private String checkOrMarkInnerFieldAccess(Expression source, FieldNode fn, boolean lhsOfAssignment, String delegationData) if (fn == null || fn.isStatic()) return delegationData;
ClassNode enclosingClassNode = typeCheckingContext.getEnclosingClassNode();
ClassNode declaringClass = fn.getDeclaringClass();
if ((fn.isPublic() || fn.isProtected()) &&
(declaringClass != enclosingClassNode || typeCheckingContext.getEnclosingClosure() != null) &&
declaringClass.getModule() == enclosingClassNode.getModule() && !lhsOfAssignment && enclosingClassNode.isDerivedFrom(declaringClass)) {
if (source instanceof PropertyExpression) {
PropertyExpression pe = (PropertyExpression) source;
if ("this".equals(pe.getPropertyAsString()) || source instanceof AttributeExpression) return delegationData;
pe.getObjectExpression().putNodeMetaData(StaticTypesMarker.IMPLICIT_RECEIVER, "owner");
}
return "owner";
}
return delegationData;

public static List<MethodNode> filterMethodsByVisibility(List<MethodNode> methodNodeList, ClassNode enclosingClassNode) if (!asBoolean(methodNodeList)) {
return StaticTypeCheckingVisitor.EMPTY_METHODNODE_LIST;
}
List<MethodNode> result = new LinkedList<>();
boolean isEnclosingInnerClass = enclosingClassNode instanceof InnerClassNode;
List<ClassNode> outerClasses = enclosingClassNode.getOuterClasses();
outer:
for (MethodNode methodNode : methodNodeList) {
if (methodNode instanceof ExtensionMethodNode) {
result.add(methodNode);
continue;
}
ClassNode declaringClass = methodNode.getDeclaringClass();
if (isEnclosingInnerClass) {
for (ClassNode outerClass : outerClasses) {
if (outerClass.isDerivedFrom(declaringClass)) {
if (outerClass.equals(declaringClass)) {
result.add(methodNode);
continue outer;
} else {
if (methodNode.isPublic() || methodNode.isProtected()) {
result.add(methodNode);
continue outer;
}
}
}
}
}
if (declaringClass instanceof InnerClassNode) {
if (declaringClass.getOuterClasses().contains(enclosingClassNode)) {
result.add(methodNode);
continue;
}
}
if (methodNode.isPrivate() && !enclosingClassNode.equals(declaringClass)) {
continue;
}
if (methodNode.isProtected()
&& !enclosingClassNode.isDerivedFrom(declaringClass)
&& !samePackageName(enclosingClassNode, declaringClass)) {
continue;
}
if (methodNode.isPackageScope() && !samePackageName(enclosingClassNode, declaringClass)) {
continue;
}
result.add(methodNode);
}
return result;

public static Expression transformInlineConstants(final Expression exp, final ClassNode attrType) if (exp instanceof PropertyExpression) {
PropertyExpression pe = (PropertyExpression) exp;
if (pe.getObjectExpression() instanceof ClassExpression) {
ClassExpression ce = (ClassExpression) pe.getObjectExpression();
ClassNode type = ce.getType();
if (type.isEnum() || !(type.isResolved() || type.isPrimaryClassNode()))
return exp;
if (type.isPrimaryClassNode()) {
FieldNode fn = type.redirect().getField(pe.getPropertyAsString());
if (fn != null && fn.isStatic() && fn.isFinal()) {
Expression ce2 = transformInlineConstants(fn.getInitialValueExpression(), attrType);
if (ce2 != null) {
return ce2;
}
}
} else {
try {
Field field = type.redirect().getTypeClass().getField(pe.getPropertyAsString());
if (field != null && Modifier.isStatic(field.getModifiers()) && Modifier.isFinal(field.getModifiers())) {
ConstantExpression ce3 = new ConstantExpression(field.get(null), true);
ce3.setSourcePosition(exp);
return ce3;
}
} catch(Exception e) {
}
}
}
} else if (exp instanceof BinaryExpression) {
ConstantExpression ce = transformBinaryConstantExpression((BinaryExpression) exp, attrType);
if (ce != null) {
return ce;
}
} else if (exp instanceof VariableExpression) {
VariableExpression ve = (VariableExpression) exp;
if (ve.getAccessedVariable() instanceof FieldNode) {
FieldNode fn = (FieldNode) ve.getAccessedVariable();
if (fn.isStatic() && fn.isFinal()) {
Expression ce = transformInlineConstants(fn.getInitialValueExpression(), attrType);
if (ce != null) {
return ce;
}
}
}
} else if (exp instanceof ListExpression) {
return transformListOfConstants((ListExpression) exp, attrType);
}
return exp;

