public static String stepDownRelativePath(String[] pathSegments) if ( !CrawlableDatasetUtils.isValidRelativePath(pathSegments))
throw new IllegalArgumentException( "Path segments not a valid relative path.");
if ( pathSegments.length < 2 )
throw new IllegalArgumentException( "Number of path segments must be > 1.");
StringBuilder sb = new StringBuilder();
for ( int i = 1; i < pathSegments.length - 1; i++ ) {
sb.append( pathSegments[i]).append("/");
}
sb.append( pathSegments[pathSegments.length - 1]);
return sb.toString();

public boolean addDimensionIfNotExists(Dimension dim) if (immutable) throw new IllegalStateException("Cant modify");
if (!dim.isShared()) {
throw new IllegalArgumentException("Dimensions added to a group must be shared.");
}
if (findDimensionLocal(dim.getShortName()) != null)
return false;
dimensions.add(dim);
dim.setGroup(this);
return true;

public void addVariable(Variable v) if (immutable) throw new IllegalStateException("Cant modify");
if (v == null) return;
if (findVariable(v.getShortName()) != null) {
throw new IllegalArgumentException("Variable name (" + v.getShortName() + ") must be unique within Group " + getShortName());
}
variables.add(v);
v.setParentGroup(this);

public Match match( String path) SortedMap<String, Match> tail = treeMap.tailMap( path);
if (tail.isEmpty()) return null;
String after = tail.firstKey();
if (path.startsWith( after))
return treeMap.get( after);
for (String key : tail.keySet()) {
if (path.startsWith(key))
return treeMap.get(key);
if (StringUtil2.match(path, key) == 0)
break;
}
return null;

RingbufferContainer getRingBufferContainer() final RingbufferService service = getService();
final ObjectNamespace ns = RingbufferService.getRingbufferNamespace(name);
RingbufferContainer ringbuffer = service.getContainerOrNull(getPartitionId(), ns);
if (ringbuffer == null) {
ringbuffer = service.getOrCreateContainer(getPartitionId(), ns, service.getRingbufferConfig(name));
}
ringbuffer.cleanup();
return ringbuffer;

@SuppressWarnings("unchecked") public void set(long sequenceId, T item) final E rbItem = convertToRingbufferFormat(item);
ringbuffer.set(sequenceId, rbItem);
if (sequenceId > tailSequence()) {
ringbuffer.setTailSequence(sequenceId);
if (ringbuffer.size() > ringbuffer.getCapacity()) {
ringbuffer.setHeadSequence(ringbuffer.tailSequence() - ringbuffer.getCapacity() + 1);
}
}
if (sequenceId < headSequence()) {
ringbuffer.setHeadSequence(sequenceId);
}
if (expirationPolicy != null) {
expirationPolicy.setExpirationAt(sequenceId);
}

private Ringbuffer<Object> merge(RingbufferContainer<Object, Object> existingContainer, RingbufferMergeTypes mergingValue) RingbufferMergeTypes existingValue = createMergingValueOrNull(existingContainer);
RingbufferMergeData resultData = mergePolicy.merge(mergingValue, existingValue);
if (resultData == null) {
ringbufferService.destroyDistributedObject(namespace.getObjectName());
return null;
} else {
if (existingContainer == null) {
RingbufferConfig config = getRingbufferConfig(ringbufferService, namespace);
existingContainer = ringbufferService.getOrCreateContainer(getPartitionId(), namespace, config);
}
setRingbufferData(resultData, existingContainer);
return existingContainer.getRingbuffer();
}

@SuppressWarnings("unchecked") void cleanup(Ringbuffer ringbuffer) if (ringbuffer.headSequence() > ringbuffer.tailSequence()) {
return;
}
long now = currentTimeMillis();
while (ringbuffer.headSequence() <= ringbuffer.tailSequence()) {
final long headSequence = ringbuffer.headSequence();
if (ringExpirationMs[toIndex(headSequence)] > now) {
return;
}
ringbuffer.set(headSequence, null);
ringbuffer.setHeadSequence(ringbuffer.headSequence() + 1);
}

private RingbufferContainer<InternalEventJournalCacheEvent, Object> getRingbufferOrFail(ObjectNamespace namespace, int partitionId) RingbufferService ringbufferService = getRingbufferService();
RingbufferContainer<InternalEventJournalCacheEvent, Object> container
= ringbufferService.getContainerOrNull(partitionId, namespace);
if (container != null) {
return container;
}
EventJournalConfig config = getEventJournalConfig(namespace);
if (config == null) {
throw new IllegalStateException(format(
"There is no event journal configured for cache %s or the journal is disabled",
namespace.getObjectName()));
}
return getOrCreateRingbufferContainer(namespace, partitionId, config);

public long add(T item) final long nextSequence = ringbuffer.peekNextTailSequence();
if (store.isEnabled()) {
try {
store.store(nextSequence, convertToData(item));
} catch (Exception e) {
throw new HazelcastException(e);
}
}
final long storedSequence = addInternal(item);
if (storedSequence != nextSequence) {
throw new IllegalStateException("Sequence we stored the item with and Ringbuffer sequence differs. Was the "
+ "Ringbuffer mutated from multiple threads?");
}
return storedSequence;

private RingbufferContainer<InternalEventJournalCacheEvent, Object> getRingbufferOrNull( EventJournalConfig journalConfig, ObjectNamespace namespace, int partitionId) RingbufferService ringbufferService = getRingbufferService();
RingbufferContainer<InternalEventJournalCacheEvent, Object> container
= ringbufferService.getContainerOrNull(partitionId, namespace);
if (container != null) {
return container;
}
return journalConfig != null ? getOrCreateRingbufferContainer(namespace, partitionId, journalConfig) : null;

public long addAll(T[] items) long firstSequence = ringbuffer.peekNextTailSequence();
long lastSequence = ringbuffer.peekNextTailSequence();
if (store.isEnabled() && items.length != 0) {
try {
store.storeAll(firstSequence, convertToData(items));
} catch (Exception e) {
throw new HazelcastException(e);
}
}
for (int i = 0; i < items.length; i++) {
lastSequence = addInternal(items[i]);
}
return lastSequence;

@Override public RingbufferConfig toRingbufferConfig(EventJournalConfig config, ObjectNamespace namespace) CacheConfig cacheConfig = getCacheService().getCacheConfig(namespace.getObjectName());
if (cacheConfig == null) {
throw new CacheNotExistsException("Cache " + namespace.getObjectName()
+ " is already destroyed or not created yet, on "
+ nodeEngine.getLocalMember());
}
int partitionCount = nodeEngine.getPartitionService().getPartitionCount();
return new RingbufferConfig()
.setAsyncBackupCount(cacheConfig.getAsyncBackupCount())
.setBackupCount(cacheConfig.getBackupCount())
.setInMemoryFormat(InMemoryFormat.OBJECT)
.setCapacity(config.getCapacity() / partitionCount)
.setTimeToLiveSeconds(config.getTimeToLiveSeconds());

public boolean couldMatchAtomType(IAtom atom, double bondOrderSum, IBond.Order maxBondOrder, IAtomType type) logger.debug("couldMatchAtomType:   ... matching atom ", atom, " vs ", type);
int hcount = atom.getImplicitHydrogenCount();
int charge = atom.getFormalCharge();
if (charge == type.getFormalCharge()) {
logger.debug("couldMatchAtomType:     formal charge matches...");
if (bondOrderSum + hcount <= type.getBondOrderSum()) {
logger.debug("couldMatchAtomType:     bond order sum is OK...");
if (!BondManipulator.isHigherOrder(maxBondOrder, type.getMaxBondOrder())) {
logger.debug("couldMatchAtomType:     max bond order is OK... We have a match!");
return true;
}
} else {
logger.debug("couldMatchAtomType:      no match", "" + (bondOrderSum + hcount), " > ",
"" + type.getBondOrderSum());
}
} else {
logger.debug("couldMatchAtomType:     formal charge does NOT match...");
}
logger.debug("couldMatchAtomType:    No Match");
return false;

@Override public IAtomType findMatchingAtomType(IAtomContainer atomContainer, IAtom atom) throws CDKException if (factory == null) {
try {
factory = AtomTypeFactory.getInstance("org/openscience/cdk/config/data/structgen_atomtypes.xml",
atom.getBuilder());
} catch (Exception ex1) {
logger.error(ex1.getMessage());
logger.debug(ex1);
throw new CDKException("Could not instantiate the AtomType list!", ex1);
}
}
double bondOrderSum = atomContainer.getBondOrderSum(atom);
IBond.Order maxBondOrder = atomContainer.getMaximumBondOrder(atom);
int charge = atom.getFormalCharge();
int hcount = atom.getImplicitHydrogenCount() == null ? 0 : atom.getImplicitHydrogenCount();
IAtomType[] types = factory.getAtomTypes(atom.getSymbol());
for (IAtomType type : types) {
logger.debug("   ... matching atom ", atom, " vs ", type);
if (bondOrderSum - charge + hcount == type.getBondOrderSum()
&& !BondManipulator.isHigherOrder(maxBondOrder, type.getMaxBondOrder())) {
return type;
}
}
logger.debug("    No Match");
return null;

public IAtom configure(IAtom atom) throws CDKException if (atom instanceof IPseudoAtom) {
return atom;
}
try {
IAtomType atomType;
String atomTypeName = atom.getAtomTypeName();
if (atomTypeName == null || atomTypeName.length() == 0) {
logger.debug("Using atom symbol because atom type name is empty...");
IAtomType[] types = getAtomTypes(atom.getSymbol());
if (types.length > 0) {
logger.warn("Taking first atom type, but other may exist");
atomType = types[0];
} else {
String message = "Could not configure atom with unknown ID: " + atom.toString() + " + (id="
+ atom.getAtomTypeName() + ")";
logger.warn(message);
throw new CDKException(message);
}
} else {
atomType = getAtomType(atom.getAtomTypeName());
}
logger.debug("Configuring with atomtype: ", atomType);
atom.setSymbol(atomType.getSymbol());
atom.setMaxBondOrder(atomType.getMaxBondOrder());
atom.setBondOrderSum(atomType.getBondOrderSum());
atom.setCovalentRadius(atomType.getCovalentRadius());
atom.setHybridization(atomType.getHybridization());
Object color = atomType.getProperty("org.openscience.cdk.renderer.color");
if (color != null) {
atom.setProperty("org.openscience.cdk.renderer.color", color);
}
atom.setAtomicNumber(atomType.getAtomicNumber());
atom.setExactMass(atomType.getExactMass());
} catch (Exception exception) {
logger.warn("Could not configure atom with unknown ID: ", atom, " + (id=", atom.getAtomTypeName(), ")");
logger.debug(exception);
throw new CDKException(exception.toString(), exception);
}
logger.debug("Configured: ", atom);
return atom;

@Override public void saturate(IAtomContainer atomContainer) throws CDKException IAtom partner = null;
IAtom atom = null;
List<IAtom> partners = null;
IAtomType[] atomTypes1 = null;
IAtomType[] atomTypes2 = null;
IBond bond = null;
for (int i = 1; i < 4; i++) {
for (int f = 0; f < atomContainer.getAtomCount(); f++) {
atom = atomContainer.getAtom(f);
logger.debug("symbol: ", atom.getSymbol());
atomTypes1 = getAtomTypeFactory(atom.getBuilder()).getAtomTypes(atom.getSymbol());
if (atomTypes1.length > 0) {
logger.debug("first atom type: ", atomTypes1[0]);
if (atomContainer.getConnectedBondsCount(atom) == i) {
Integer hcount = atom.getImplicitHydrogenCount() == CDKConstants.UNSET ? 0 : atom
.getImplicitHydrogenCount();
if (atom.getFlag(CDKConstants.ISAROMATIC)
&& atomContainer.getBondOrderSum(atom) < atomTypes1[0].getBondOrderSum() - hcount) {
partners = atomContainer.getConnectedAtomsList(atom);
for (int g = 0; g < partners.size(); g++) {
partner = partners.get(g);
logger.debug("Atom has " + partners.size() + " partners");
atomTypes2 = getAtomTypeFactory(atom.getBuilder()).getAtomTypes(partner.getSymbol());
if (atomTypes2.length == 0) return;
hcount = partner.getImplicitHydrogenCount() == CDKConstants.UNSET ? 0 : partner
.getImplicitHydrogenCount();
if (atomContainer.getBond(partner, atom).getFlag(CDKConstants.ISAROMATIC)
&& atomContainer.getBondOrderSum(partner) < atomTypes2[0].getBondOrderSum()
- hcount) {
logger.debug("Partner has " + atomContainer.getBondOrderSum(partner)
+ ", may have: " + atomTypes2[0].getBondOrderSum());
bond = atomContainer.getBond(atom, partner);
logger.debug("Bond order was " + bond.getOrder());
BondManipulator.increaseBondOrder(bond);
logger.debug("Bond order now " + bond.getOrder());
break;
}
}
}
Double bondOrderSum = atomTypes1[0].getBondOrderSum() == CDKConstants.UNSET ? 0.0
: atomTypes1[0].getBondOrderSum();
Integer hydrogenCount = atom.getImplicitHydrogenCount() == CDKConstants.UNSET ? 0 : atom
.getImplicitHydrogenCount();
Double atomContainerBondOrderSum = atomContainer.getBondOrderSum(atom);
if (atomContainerBondOrderSum == CDKConstants.UNSET) atomContainerBondOrderSum = 0.0;
if (atomContainerBondOrderSum < bondOrderSum - hydrogenCount) {
logger.debug("Atom has " + atomContainerBondOrderSum + ", may have: " + bondOrderSum);
partners = atomContainer.getConnectedAtomsList(atom);
for (int g = 0; g < partners.size(); g++) {
partner = (IAtom) partners.get(g);
logger.debug("Atom has " + partners.size() + " partners");
atomTypes2 = getAtomTypeFactory(atom.getBuilder()).getAtomTypes(partner.getSymbol());
if (atomTypes2.length == 0) return;
Double bos2 = atomTypes2[0].getBondOrderSum();
Integer hc2 = partner.getImplicitHydrogenCount();
Double acbos2 = atomContainer.getBondOrderSum(partner);
if (bos2 == CDKConstants.UNSET) bos2 = 0.0;
if (hc2 == CDKConstants.UNSET) hc2 = 0;
if (acbos2 == CDKConstants.UNSET) acbos2 = 0.0;
if (acbos2 < bos2 - hc2) {
logger.debug("Partner has " + acbos2 + ", may have: " + bos2);
bond = atomContainer.getBond(atom, partner);
logger.debug("Bond order was " + bond.getOrder());
BondManipulator.increaseBondOrder(bond);
logger.debug("Bond order now " + bond.getOrder());
break;
}
}
}
}
}
}
}

@Override public boolean isSaturated(IAtom atom, IAtomContainer ac) throws CDKException IAtomType[] atomTypes = getAtomTypeFactory(atom.getBuilder()).getAtomTypes(atom.getSymbol());
if (atomTypes.length == 0) return true;
double bondOrderSum = ac.getBondOrderSum(atom);
IBond.Order maxBondOrder = ac.getMaximumBondOrder(atom);
Integer hcount = atom.getImplicitHydrogenCount() == CDKConstants.UNSET ? 0 : atom.getImplicitHydrogenCount();
Integer charge = atom.getFormalCharge() == CDKConstants.UNSET ? 0 : atom.getFormalCharge();
try {
logger.debug("*** Checking saturation of atom ", atom.getSymbol(), "" + ac.indexOf(atom) + " ***");
logger.debug("bondOrderSum: " + bondOrderSum);
logger.debug("maxBondOrder: " + maxBondOrder);
logger.debug("hcount: " + hcount);
} catch (Exception exc) {
logger.debug(exc);
}
for (int f = 0; f < atomTypes.length; f++) {
if (bondOrderSum - charge + hcount == atomTypes[f].getBondOrderSum()
&& !BondManipulator.isHigherOrder(maxBondOrder, atomTypes[f].getMaxBondOrder())) {
logger.debug("*** Good ! ***");
return true;
}
}
logger.debug("*** Bad ! ***");
return false;

public boolean saturateByIncreasingBondOrder(IBond bond, IAtomContainer atomContainer) throws CDKException IAtom[] atoms = BondManipulator.getAtomArray(bond);
IAtom atom = atoms[0];
IAtom partner = atoms[1];
logger.debug("  saturating bond: ", atom.getSymbol(), "-", partner.getSymbol());
IAtomType[] atomTypes1 = getAtomTypeFactory(bond.getBuilder()).getAtomTypes(atom.getSymbol());
IAtomType[] atomTypes2 = getAtomTypeFactory(bond.getBuilder()).getAtomTypes(partner.getSymbol());
for (int atCounter1 = 0; atCounter1 < atomTypes1.length; atCounter1++) {
IAtomType aType1 = atomTypes1[atCounter1];
logger.debug("  condidering atom type: ", aType1);
if (couldMatchAtomType(atomContainer, atom, aType1)) {
logger.debug("  trying atom type: ", aType1);
for (int atCounter2 = 0; atCounter2 < atomTypes2.length; atCounter2++) {
IAtomType aType2 = atomTypes2[atCounter2];
logger.debug("  condidering partner type: ", aType1);
if (couldMatchAtomType(atomContainer, partner, atomTypes2[atCounter2])) {
logger.debug("    with atom type: ", aType2);
if (BondManipulator.isLowerOrder(bond.getOrder(), aType2.getMaxBondOrder())
&& BondManipulator.isLowerOrder(bond.getOrder(), aType1.getMaxBondOrder())) {
bond.setOrder(BondManipulator.increaseBondOrder(bond.getOrder()));
logger.debug("Bond order now ", bond.getOrder());
return true;
}
}
}
}
}
return false;

