public int calculateNumberOfImplicitHydrogens(IAtom atom, double bondOrderSum, IBond.Order maxBondOrder, int neighbourCount) throws CDKException int missingHydrogens = 0;
if (atom instanceof IPseudoAtom) {
logger.debug("don't figure it out... it simply does not lack H's");
return 0;
}
logger.debug("Calculating number of missing hydrogen atoms");
IAtomType[] atomTypes = getAtomTypeFactory(atom.getBuilder()).getAtomTypes(atom.getSymbol());
if (atomTypes.length == 0) {
logger.warn("Element not found in configuration file: ", atom);
return 0;
}
logger.debug("Found atomtypes: ", atomTypes.length);
for (int f = 0; f < atomTypes.length; f++) {
IAtomType type = atomTypes[f];
if (couldMatchAtomType(atom, bondOrderSum, maxBondOrder, type)) {
logger.debug("This type matches: ", type);
int formalNeighbourCount = type.getFormalNeighbourCount();
if (type.getHybridization() == CDKConstants.UNSET) {
missingHydrogens = (int) (type.getBondOrderSum() - bondOrderSum);
} else if (type.getHybridization() == Hybridization.SP3) {
missingHydrogens = formalNeighbourCount - neighbourCount;
} else if (type.getHybridization() == Hybridization.SP2) {
missingHydrogens = formalNeighbourCount - neighbourCount;
} else if (type.getHybridization() == Hybridization.SP1) {
missingHydrogens = formalNeighbourCount - neighbourCount;
} else {
missingHydrogens = (int) (type.getBondOrderSum() - bondOrderSum);
}
break;
}
}
logger.debug("missing hydrogens: ", missingHydrogens);
return missingHydrogens;

public static void configure(IAtom atom, IAtomType atomType) if (atomType == null) {
throw new IllegalArgumentException("The IAtomType was null.");
}
if ("X".equals(atomType.getAtomTypeName())) {
atom.setAtomTypeName("X");
return;
}
atom.setAtomTypeName(atomType.getAtomTypeName());
if (!(atom instanceof IPseudoAtom)) {
atom.setSymbol(atomType.getSymbol());
atom.setMaxBondOrder(atomType.getMaxBondOrder());
atom.setBondOrderSum(atomType.getBondOrderSum());
atom.setCovalentRadius(atomType.getCovalentRadius());
atom.setValency(atomType.getValency());
atom.setFormalCharge(atomType.getFormalCharge());
atom.setHybridization(atomType.getHybridization());
atom.setFormalNeighbourCount(atomType.getFormalNeighbourCount());
atom.setFlag(CDKConstants.IS_HYDROGENBOND_ACCEPTOR, atomType.getFlag(CDKConstants.IS_HYDROGENBOND_ACCEPTOR));
atom.setFlag(CDKConstants.IS_HYDROGENBOND_DONOR, atomType.getFlag(CDKConstants.IS_HYDROGENBOND_DONOR));
Object constant = atomType.getProperty(CDKConstants.CHEMICAL_GROUP_CONSTANT);
if (constant != null) {
atom.setProperty(CDKConstants.CHEMICAL_GROUP_CONSTANT, constant);
}
if (atomType.getFlag(CDKConstants.ISAROMATIC))
atom.setFlag(CDKConstants.ISAROMATIC, atomType.getFlag(CDKConstants.ISAROMATIC));
Object color = atomType.getProperty("org.openscience.cdk.renderer.color");
if (color != null) {
atom.setProperty("org.openscience.cdk.renderer.color", color);
}
if (atomType.getAtomicNumber() != CDKConstants.UNSET) atom.setAtomicNumber(atomType.getAtomicNumber());
if (atomType.getExactMass() != CDKConstants.UNSET) atom.setExactMass(atomType.getExactMass());
}

