protected String getTargetUriOutOfScope(Target target, Object[] contextSpecificObjects) List<StructuralNode> nodes = target.getStartNodes();
if (nodes != null) {
for (StructuralNode node : nodes) {
if (node == null) {
continue;
}
if (node instanceof StructuralSiteNode) {
SiteNode siteNode = ((StructuralSiteNode) node).getSiteNode();
if (!siteNode.isIncludedInScope()) {
return node.getURI().toString();
}
} else {
String uri = node.getURI().toString();
if (!isTargetUriInScope(uri)) {
return uri;
}
}
}
}
if (contextSpecificObjects != null) {
for (Object obj : contextSpecificObjects) {
if (obj instanceof URI) {
String uri = ((URI) obj).toString();
if (!isTargetUriInScope(uri)) {
return uri;
}
}
}
}
return null;

@Override public Component getTreeCellRendererComponent(JTree tree, Object value, boolean sel, boolean expanded, boolean leaf, int row, boolean hasFocus) component.removeAll();
SiteNode node = null;
if (value instanceof SiteNode) {
node = (SiteNode) value;
}
if (node != null) {
if( node.isFiltered()) {
setPreferredSize( new Dimension(0, 0) );
return this;
}
setPreferredSize(null);
super.getTreeCellRendererComponent(tree, value, sel, expanded, leaf, row, hasFocus);
if (node.isRoot()) {
component.add(wrap(ROOT_ICON));
} else {
OverlayIcon icon;
if (node.isDataDriven()) {
if (node.isIncludedInScope() && ! node.isExcludedFromScope()) {
icon = new OverlayIcon(DATA_DRIVEN_IN_SCOPE_ICON);
} else {
icon = new OverlayIcon(DATA_DRIVEN_ICON);
}
} else if (leaf) {
if (node.isIncludedInScope() && ! node.isExcludedFromScope()) {
icon = new OverlayIcon(LEAF_IN_SCOPE_ICON);
} else {
icon = new OverlayIcon(LEAF_ICON);
}
} else {
if  (expanded) {
if (node.isIncludedInScope() && ! node.isExcludedFromScope()) {
icon = new OverlayIcon(FOLDER_OPEN_IN_SCOPE_ICON);
} else {
icon = new OverlayIcon(FOLDER_OPEN_ICON);
}
} else {
