}
ch = value.charAt(idx++);
switch (ch) {
case '0':
buf.append('\u0000');
break;
case '!':
buf.append((char)RPC_SEPARATOR_CHAR);
break;
case '\\':
buf.append(ch);
break;
case 'u':
try {
if (idx + 4 < value.length()) {
ch = (char)Integer.parseInt(value.substring(idx, idx + 4), 16);
buf.append(ch);
} else {
}
} catch (NumberFormatException ex) {
}
idx += 4;
break;
default:
}
} else {
buf.append(ch);
}
}
return buf.toString();
}

private static byte[] createBlob(final byte[] clientChallenge, final byte[] targetInformation, final byte[] timestamp) final byte[] blobSignature = new byte[] { (byte) 0x01, (byte) 0x01, (byte) 0x00, (byte) 0x00 };
final byte[] reserved = new byte[] { (byte) 0x00, (byte) 0x00, (byte) 0x00, (byte) 0x00 };
final byte[] unknown1 = new byte[] { (byte) 0x00, (byte) 0x00, (byte) 0x00, (byte) 0x00 };
final byte[] unknown2 = new byte[] { (byte) 0x00, (byte) 0x00, (byte) 0x00, (byte) 0x00 };
final byte[] blob = new byte[blobSignature.length + reserved.length + timestamp.length + 8
+ unknown1.length + targetInformation.length + unknown2.length];
int offset = 0;
System.arraycopy(blobSignature, 0, blob, offset, blobSignature.length);
offset += blobSignature.length;
System.arraycopy(reserved, 0, blob, offset, reserved.length);
offset += reserved.length;
System.arraycopy(timestamp, 0, blob, offset, timestamp.length);
offset += timestamp.length;
System.arraycopy(clientChallenge, 0, blob, offset, 8);
offset += 8;
System.arraycopy(unknown1, 0, blob, offset, unknown1.length);
offset += unknown1.length;
System.arraycopy(targetInformation, 0, blob, offset, targetInformation.length);
offset += targetInformation.length;
System.arraycopy(unknown2, 0, blob, offset, unknown2.length);
offset += unknown2.length;
return blob;

public void append(byte[] contents, int length) if (contents == null || length <= 0) {
return;
}
int len = Math.min(contents.length, length);
if (pos + len > body.length) {
byte[] newBody = new byte[pos + len];
System.arraycopy(body, 0, newBody, 0, pos);
body = newBody;
}
System.arraycopy(contents, 0, body, pos, len);
pos += len;
cachedString = null;

public void setBody(byte[] contents) if (contents == null) {
return;
}
cachedString = null;
body = new byte[contents.length];
System.arraycopy(contents, 0, body, 0, contents.length);
pos = body.length;

private static byte[] lmHash(final String password) throws AuthenticationException try {
final byte[] oemPassword = password.toUpperCase(Locale.ROOT).getBytes(StandardCharsets.US_ASCII);
final int length = Math.min(oemPassword.length, 14);
final byte[] keyBytes = new byte[14];
System.arraycopy(oemPassword, 0, keyBytes, 0, length);
final Key lowKey = createDESKey(keyBytes, 0);
final Key highKey = createDESKey(keyBytes, 7);
final byte[] magicConstant = "KGS!@#$%".getBytes(StandardCharsets.US_ASCII);
final Cipher des = Cipher.getInstance("DES/ECB/NoPadding");
des.init(Cipher.ENCRYPT_MODE, lowKey);
final byte[] lowHash = des.doFinal(magicConstant);
des.init(Cipher.ENCRYPT_MODE, highKey);
final byte[] highHash = des.doFinal(magicConstant);
final byte[] lmHash = new byte[16];
System.arraycopy(lowHash, 0, lmHash, 0, 8);
System.arraycopy(highHash, 0, lmHash, 8, 8);
return lmHash;
} catch (final Exception e) {
throw new AuthenticationException(e.getMessage(), e);
}

private static byte[] lmv2Response(final byte[] hash, final byte[] challenge, final byte[] clientData) throws AuthenticationException final HMACMD5 hmacMD5 = new HMACMD5(hash);
hmacMD5.update(challenge);
hmacMD5.update(clientData);
final byte[] mac = hmacMD5.getOutput();
final byte[] lmv2Response = new byte[mac.length + clientData.length];
System.arraycopy(mac, 0, lmv2Response, 0, mac.length);
System.arraycopy(clientData, 0, lmv2Response, mac.length, clientData.length);
return lmv2Response;

public double dot(MAVector v) if (nelems != v.getNelems())
throw new IllegalArgumentException("MAVector.dot "+nelems+" != "+ v.getNelems());
double sum = 0.0;
for (int k=0; k<nelems; k++)
sum += getDouble(k) * v.getDouble(k);
return sum;

static public MAMatrix multiply(MAMatrix m1, MAMatrix m2) if (m1.getNcols() != m2.getNrows())
throw new IllegalArgumentException("MAMatrix.multiply "+m1.getNcols()+" != "+ m2.getNrows());
int kdims = m1.getNcols();
ArrayDouble.D2 result = new ArrayDouble.D2(m1.getNrows(), m2.getNcols());
Index imr = result.getIndex();
for (int i=0; i<m1.getNrows(); i++) {
for (int j=0; j<m2.getNcols(); j++) {
double sum = 0.0;
for (int k=0; k<kdims; k++)
sum += m1.getDouble(i, k) * m2.getDouble(k, j);
result.setDouble( imr.set(i,j), sum);
}
}
return new MAMatrix( result);

public void postMultiplyDiagonal(MAVector diag) if (ncols != diag.getNelems())
throw new IllegalArgumentException("MAMatrix.postMultiplyDiagonal "+ncols+" != "+ diag.getNelems());
for (int i=0; i<nrows; i++) {
for (int j=0; j<ncols; j++) {
double val = a.getDouble( ima.set(i,j)) * diag.getDouble(j);
a.setDouble( ima, val);
}
}

public double cos(MAVector v) if (nelems != v.getNelems())
throw new IllegalArgumentException("MAVector.cos "+nelems+" != "+ v.getNelems());
double norm = norm();
double normV = v.norm();
if ((norm == 0.0) || (normV == 0.0))
return 0.0;
else
return dot(v)/(norm*normV);

public ArrayDouble.D3 getCoordinateArray(int timeIndex) throws IOException ArrayDouble.D3 array;
Array pertArray = getTimeSlice(pertVar, timeIndex);
Array baseArray = getTimeSlice(baseVar, timeIndex);
int[] shape = pertArray.getShape();
int ni = shape[0];
int nj = shape[1];
int nk = shape[2];
array = new ArrayDouble.D3(ni, nj, nk);
Index index = array.getIndex();
for (int i = 0; i < ni; i++) {
for (int j = 0; j < nj; j++) {
for (int k = 0; k < nk; k++) {
index.set(i, j, k);
double d = pertArray.getDouble(index) + baseArray.getDouble(index);
if (isZStag) {
d = d / 9.81;
}
array.setDouble(index, d);
}
}
}
if (isXStag) {
array = addStagger(array, 2);
}
if (isYStag) {
array = addStagger(array, 1);
}
return array;

public double norm() double sum = 0.0;
for (int k=0; k<nelems; k++) {
double val = getDouble(k);
sum += val * val;
}
return Math.sqrt(sum);

public D1 getCoordinateArray1D(int timeIndex, int xIndex, int yIndex) throws IOException, InvalidRangeException Array ps = readArray(psVar, timeIndex);
Index psIndex = ps.getIndex();
int nz = sigma.length;
ArrayDouble.D1 result = new ArrayDouble.D1(nz);
double psVal = ps.getDouble(psIndex.set(yIndex, xIndex));
for (int z = 0; z < nz; z++) {
result.set(z,  ptop + sigma[z] * (psVal - ptop));
}
return result;

public void normalize() double norm = norm();
if (norm <= 0.0)
return;
for (int k=0; k<nelems; k++) {
double val = getDouble(k);
setDouble(k, val/norm);
}

protected void writeData( Array values, Layout index, DataType dataType) throws java.io.IOException if ((dataType == DataType.BYTE) || (dataType == DataType.CHAR)) {
IndexIterator ii = values.getIndexIterator();
while (index.hasNext()) {
Layout.Chunk chunk = index.next();
raf.seek ( chunk.getSrcPos());
for (int k=0; k<chunk.getNelems(); k++)
raf.write( ii.getByteNext());
}
return;
} else if (dataType == DataType.STRING) {
IndexIterator ii = values.getIndexIterator();
while (index.hasNext()) {
Layout.Chunk chunk = index.next();
raf.seek ( chunk.getSrcPos());
for (int k=0; k<chunk.getNelems(); k++) {
String val = (String) ii.getObjectNext();
if (val != null) raf.write( val.getBytes(CDM.utf8Charset));
}
}
return;
} else if (dataType == DataType.SHORT) {
IndexIterator ii = values.getIndexIterator();
while (index.hasNext()) {
Layout.Chunk chunk = index.next();
raf.seek ( chunk.getSrcPos());
for (int k=0; k<chunk.getNelems(); k++)
raf.writeShort( ii.getShortNext());
}
return;
} else if (dataType == DataType.INT) {
IndexIterator ii = values.getIndexIterator();
while (index.hasNext()) {
Layout.Chunk chunk = index.next();
raf.seek ( chunk.getSrcPos());
for (int k=0; k<chunk.getNelems(); k++)
raf.writeInt( ii.getIntNext());
}
return;
} else if (dataType == DataType.FLOAT) {
IndexIterator ii = values.getIndexIterator();
while (index.hasNext()) {
Layout.Chunk chunk = index.next();
raf.seek ( chunk.getSrcPos());
for (int k=0; k<chunk.getNelems(); k++)
raf.writeFloat( ii.getFloatNext());
}
return;
} else if (dataType == DataType.DOUBLE) {
IndexIterator ii = values.getIndexIterator();
while (index.hasNext()) {
Layout.Chunk chunk = index.next();
raf.seek ( chunk.getSrcPos());
for (int k=0; k<chunk.getNelems(); k++)
raf.writeDouble( ii.getDoubleNext());
}
return;
}
throw new IllegalStateException("dataType= "+dataType);

private ArrayDouble.D3 addStagger(ArrayDouble.D3 array, int dimIndex) int[] shape = array.getShape();
int[] newShape = new int[3];
System.arraycopy(shape, 0, newShape, 0, 3);
newShape[dimIndex]++;
int ni = newShape[0];
int nj = newShape[1];
int nk = newShape[2];
ArrayDouble.D3 newArray = new ArrayDouble.D3(ni, nj, nk);
int n = shape[dimIndex];
double[] d = new double[n];
int[] eshape = new int[3];
int[] neweshape = new int[3];
for (int i = 0; i < 3; i++) {
eshape[i] = (i == dimIndex)
? n
: 1;
neweshape[i] = (i == dimIndex)
? n + 1
: 1;
}
int[] origin = new int[3];
try {
for (int i = 0; i < ((dimIndex == 0)
? 1
: ni); i++) {
for (int j = 0; j < ((dimIndex == 1)
? 1
: nj); j++) {
for (int k = 0; k < ((dimIndex == 2)
? 1
: nk); k++) {
origin[0] = i;
origin[1] = j;
origin[2] = k;
IndexIterator it = array.section(origin,
eshape).getIndexIterator();
for (int l = 0; l < n; l++) {
d[l] = it.getDoubleNext();
}
double[] d2 = extrapinterpolate(d);
IndexIterator newit =
newArray.section(origin,
neweshape).getIndexIterator();
for (int l = 0; l < n + 1; l++) {
newit.setDoubleNext(d2[l]);
}
}
}
}
} catch (InvalidRangeException e) {
return null;
}
return newArray;

public void setValueFor(Field target, Object value) if(value == null && target.getType().isPrimitive()) {
throw new ND4JIllegalStateException("Unable to set primitive field " + target + " of type " + target.getClass()
+ " using null value!");
}
if(value != null) {
value = ensureProperType(target, value);
}
if(isConfigProperties()){
String propertyName = configFieldName();
if(propertyName == null)
propertyName = "config";
Field f = null;
Class<?> currClass = getClass();
try{
f = currClass.getDeclaredField(propertyName);
} catch (NoSuchFieldException e){
}
while(f == null && currClass.getSuperclass() != null){
currClass = currClass.getSuperclass();
try{
f = currClass.getDeclaredField(propertyName);
} catch (NoSuchFieldException e){
}
}
if(f == null){
throw new IllegalStateException("Could not find field \"" + propertyName + "\" for class " + getClass().getName());
}
try {
f.setAccessible(true);
Object o = f.get(this);
if(o == null){
Class<?> c = f.getType();
try {
o = c.newInstance();
} catch (InstantiationException e){
throw new RuntimeException("Error creating new instance of configuration object type " + c.getName(), e);
}
f.set(this, o);
}
target.set(o, value);
} catch (IllegalAccessException e){
throw new RuntimeException("Error setting configuration field \"" + propertyName + "\" for config field \"" + propertyName
+ "\" on class " + getClass().getName());
}
} else {
try {
target.set(this,value);
} catch (IllegalAccessException e) {
throw new RuntimeException("Error setting property for function " + getClass().getName(), e);
}
}

