private void compactPartition(final int partitionNumber) throws IOException if (this.closed || partitionNumber >= this.partitions.size() || this.partitions.get(partitionNumber).isCompacted()) {
return;
}
this.compactionMemory.clearAllMemory(availableMemory);
this.compactionMemory.allocateSegments(1);
this.compactionMemory.pushDownPages();
T tempHolder = this.buildSideSerializer.createInstance();
final int numPartitions = this.partitions.size();
InMemoryPartition<T> partition = this.partitions.remove(partitionNumber);
MemorySegment[] overflowSegments = partition.overflowSegments;
long pointer;
int pointerOffset;
int bucketOffset;
final int bucketsPerSegment = this.bucketsPerSegmentMask + 1;
for (int i = 0, bucket = partitionNumber; i < this.buckets.length && bucket < this.numBuckets; i++) {
MemorySegment segment = this.buckets[i];
for (int k = bucket % bucketsPerSegment; k < bucketsPerSegment && bucket < this.numBuckets; k += numPartitions, bucket += numPartitions) {
bucketOffset = k * HASH_BUCKET_SIZE;
if((int)segment.get(bucketOffset + HEADER_PARTITION_OFFSET) != partitionNumber) {
throw new IOException("Accessed wrong bucket! wanted: " + partitionNumber + " got: " + segment.get(bucketOffset + HEADER_PARTITION_OFFSET));
}
int countInSegment = segment.getInt(bucketOffset + HEADER_COUNT_OFFSET);
int numInSegment = 0;
pointerOffset = bucketOffset + BUCKET_POINTER_START_OFFSET;
while (true) {
while (numInSegment < countInSegment) {
pointer = segment.getLong(pointerOffset);
tempHolder = partition.readRecordAt(pointer, tempHolder);
pointer = this.compactionMemory.appendRecord(tempHolder);
segment.putLong(pointerOffset, pointer);
pointerOffset += POINTER_LEN;
numInSegment++;
}
final long forwardPointer = segment.getLong(bucketOffset + HEADER_FORWARD_OFFSET);
if (forwardPointer == BUCKET_FORWARD_POINTER_NOT_SET) {
break;
}
final int overflowSegNum = (int) (forwardPointer >>> 32);
segment = overflowSegments[overflowSegNum];
bucketOffset = (int) forwardPointer;
countInSegment = segment.getInt(bucketOffset + HEADER_COUNT_OFFSET);
pointerOffset = bucketOffset + BUCKET_POINTER_START_OFFSET;
numInSegment = 0;
}
segment = this.buckets[i];
}
}
this.compactionMemory.setPartitionNumber(partitionNumber);
this.partitions.add(partitionNumber, compactionMemory);
this.partitions.get(partitionNumber).overflowSegments = partition.overflowSegments;
this.partitions.get(partitionNumber).numOverflowSegments = partition.numOverflowSegments;
this.partitions.get(partitionNumber).nextOverflowBucket = partition.nextOverflowBucket;
this.partitions.get(partitionNumber).setIsCompacted(true);
this.compactionMemory = partition;
this.compactionMemory.resetRecordCounter();
this.compactionMemory.setPartitionNumber(-1);
this.compactionMemory.overflowSegments = null;
this.compactionMemory.numOverflowSegments = 0;
this.compactionMemory.nextOverflowBucket = 0;
this.compactionMemory.clearAllMemory(this.availableMemory);
int maxSegmentNumber = this.getMaxPartition();
this.compactionMemory.allocateSegments(maxSegmentNumber);
this.compactionMemory.resetRWViews();
this.compactionMemory.pushDownPages();

public void insertOrReplaceRecord(T record) throws IOException if (this.closed) {
return;
}
final int searchHashCode = MathUtils.jenkinsHash(this.buildSideComparator.hash(record));
final int posHashCode = searchHashCode % this.numBuckets;
final MemorySegment originalBucket = this.buckets[posHashCode >> this.bucketsPerSegmentBits];
final int originalBucketOffset = (posHashCode & this.bucketsPerSegmentMask) << NUM_INTRA_BUCKET_BITS;
MemorySegment bucket = originalBucket;
int bucketInSegmentOffset = originalBucketOffset;
final int partitionNumber = bucket.get(bucketInSegmentOffset + HEADER_PARTITION_OFFSET);
final InMemoryPartition<T> partition = this.partitions.get(partitionNumber);
final MemorySegment[] overflowSegments = partition.overflowSegments;
this.buildSideComparator.setReference(record);
int countInSegment = bucket.getInt(bucketInSegmentOffset + HEADER_COUNT_OFFSET);
int numInSegment = 0;
int posInSegment = bucketInSegmentOffset + BUCKET_HEADER_LENGTH;
while (true) {
while (numInSegment < countInSegment) {
final int thisCode = bucket.getInt(posInSegment);
posInSegment += HASH_CODE_LEN;
if (thisCode == searchHashCode) {
final int pointerOffset = bucketInSegmentOffset + BUCKET_POINTER_START_OFFSET + (numInSegment * POINTER_LEN);
final long pointer = bucket.getLong(pointerOffset);
T valueAtPosition = partition.readRecordAt(pointer);
if (this.buildSideComparator.equalToReference(valueAtPosition)) {
long newPointer = insertRecordIntoPartition(record, partition, true);
bucket.putLong(pointerOffset, newPointer);
return;
}
}
numInSegment++;
}
long newForwardPointer = bucket.getLong(bucketInSegmentOffset + HEADER_FORWARD_OFFSET);
if (newForwardPointer == BUCKET_FORWARD_POINTER_NOT_SET) {
long pointer = insertRecordIntoPartition(record, partition, false);
if (countInSegment < NUM_ENTRIES_PER_BUCKET) {
bucket.putInt(bucketInSegmentOffset + BUCKET_HEADER_LENGTH + (countInSegment * HASH_CODE_LEN), searchHashCode);
bucket.putLong(bucketInSegmentOffset + BUCKET_POINTER_START_OFFSET + (countInSegment * POINTER_LEN), pointer);
bucket.putInt(bucketInSegmentOffset + HEADER_COUNT_OFFSET, countInSegment + 1);
}
else {
insertBucketEntryFromStart(originalBucket, originalBucketOffset, searchHashCode, pointer, partitionNumber);
}
return;
}
final int overflowSegNum = (int) (newForwardPointer >>> 32);
bucket = overflowSegments[overflowSegNum];
bucketInSegmentOffset = (int) newForwardPointer;
countInSegment = bucket.getInt(bucketInSegmentOffset + HEADER_COUNT_OFFSET);
posInSegment = bucketInSegmentOffset + BUCKET_HEADER_LENGTH;
numInSegment = 0;
}

final int insertIntoBuildBuffer(BinaryRow record) throws IOException this.buildSideRecordCounter++;
if (isInMemory()) {
final long pointer = this.buildSideWriteBuffer.getCurrentPointer();
int skip = this.buildSideSerializer.serializeToPages(record, this.buildSideWriteBuffer);
if (isInMemory()) {
long ret = pointer + skip;
if (ret > Integer.MAX_VALUE) {
throw new RuntimeException("Too more data in this partition: " + ret);
}
return (int) ret;
} else {
return -1;
}
} else {
this.buildSideSerializer.serializeToPages(record, this.buildSideWriteBuffer);
return -1;
}

@Override public boolean write(T record) throws IOException if (this.currentSortIndexOffset > this.lastIndexEntryOffset) {
if (memoryAvailable()) {
this.currentSortIndexSegment = nextMemorySegment();
this.sortIndex.add(this.currentSortIndexSegment);
this.currentSortIndexOffset = 0;
this.sortIndexBytes += this.segmentSize;
} else {
return false;
}
}
try {
this.serializer.serialize(record, this.recordCollector);
}
catch (EOFException e) {
return false;
}
final long newOffset = this.recordCollector.getCurrentOffset();
final boolean shortRecord = newOffset - this.currentDataBufferOffset < LARGE_RECORD_THRESHOLD;
if (!shortRecord && LOG.isDebugEnabled()) {
LOG.debug("Put a large record ( >" + LARGE_RECORD_THRESHOLD + " into the sort buffer");
}
this.currentSortIndexSegment.putLong(this.currentSortIndexOffset, shortRecord ?
this.currentDataBufferOffset : (this.currentDataBufferOffset | LARGE_RECORD_TAG));
if (this.numKeyBytes != 0) {
this.comparator.putNormalizedKey(record, this.currentSortIndexSegment, this.currentSortIndexOffset + OFFSET_LEN, this.numKeyBytes);
}
this.currentSortIndexOffset += this.indexEntrySize;
this.currentDataBufferOffset = newOffset;
this.numRecords++;
return true;

public final long getLong(int index) final long pos = address + index;
if (index >= 0 && pos <= addressLimit - 8) {
return UNSAFE.getLong(heapMemory, pos);
}
else if (address > addressLimit) {
throw new IllegalStateException("segment has been freed");
}
else {
throw new IndexOutOfBoundsException();
}

protected void writeIndexAndNormalizedKey(BaseRow record, long currOffset) this.currentSortIndexSegment.putLong(this.currentSortIndexOffset, currOffset);
if (this.numKeyBytes != 0) {
normalizedKeyComputer.putKey(record, this.currentSortIndexSegment, this.currentSortIndexOffset + OFFSET_LEN);
}
this.currentSortIndexOffset += this.indexEntrySize;
this.numRecords++;

public static String toUnicodeLiteral(String s) StringBuffer result = new StringBuffer();
char[] carr = s.toCharArray();
String unicode;
for (int i = 0; i < carr.length; i++) {
result.append("\\u");
unicode = Integer.toHexString(carr[i]).toUpperCase();
for (int j = 4 - unicode.length(); j > 0; j--) {
result.append("0");
}
result.append(unicode);
}
return result.toString();

public static List<String> splitAsList(String source, String[] delimiters, boolean trim, boolean includeDelimiters) List<String> result = new ArrayList<String>();
String delimiter = "";
int i = 0;
int l = source.length();
int n = -1;
int max = Integer.MAX_VALUE;
for (int j = 0; j < delimiters.length; j++) {
int delimPos = source.indexOf(delimiters[j]);
if (delimPos > -1) {
if (delimPos < max) {
max = delimPos;
n = delimPos;
delimiter = delimiters[j];
}
}
}
while (n != -1) {
if ((i < n) || ((i > 0) && (i < l))) {
result.add(trim ? source.substring(i, n).trim() : source.substring(i, n));
if (includeDelimiters && ((n + delimiter.length()) <= l)) {
result.add(source.substring(n, n + delimiter.length()));
}
} else {
if (includeDelimiters && source.startsWith(delimiter)) {
result.add(delimiter);
}
}
i = n + delimiter.length();
max = Integer.MAX_VALUE;
n = -1;
for (int j = 0; j < delimiters.length; j++) {
int delimPos = source.indexOf(delimiters[j], i);
if (delimPos > -1) {
if (delimPos < max) {
max = delimPos;
n = delimPos;
delimiter = delimiters[j];
}
}
}
}
if (n < 0) {
n = source.length();
}
if (i < n) {
result.add(trim ? source.substring(i).trim() : source.substring(i));
}
return result;

public static String formatResourceName(String name, int maxLength) if (name == null) {
return null;
}
if (name.length() <= maxLength) {
return name;
}
int total = name.length();
String[] names = CmsStringUtil.splitAsArray(name, "/");
if (name.endsWith("/")) {
names[names.length - 1] = names[names.length - 1] + "/";
}
for (int i = 1; (total > maxLength) && (i < (names.length - 1)); i++) {
if (i > 1) {
names[i - 1] = "";
}
names[i] = "...";
total = 0;
for (int j = 0; j < names.length; j++) {
int l = names[j].length();
total += l + ((l > 0) ? 1 : 0);
}
}
if (total > maxLength) {
names[0] = (names.length > 2) ? "" : (names.length > 1) ? "..." : names[0];
}
StringBuffer result = new StringBuffer();
for (int i = 0; i < names.length; i++) {
if (names[i].length() > 0) {
result.append("/");
result.append(names[i]);
}
}
return result.toString();

public static String[] getNames(JSONObject jo) int length = jo.length();
if (length == 0) {
return null;
}
Iterator<String> i = jo.keys();
String[] names = new String[length];
int j = 0;
while (i.hasNext()) {
names[j] = i.next();
j += 1;
}
return names;

public static String encodeParams(HttpServletRequest req) StringBuffer result = new StringBuffer(512);
Map<String, String[]> params = CmsCollectionsGenericWrapper.map(req.getParameterMap());
Iterator<Map.Entry<String, String[]>> i = params.entrySet().iterator();
while (i.hasNext()) {
Map.Entry<String, String[]> entry = i.next();
String param = entry.getKey();
String[] values = entry.getValue();
for (int j = 0; j < values.length; j++) {
result.append(param);
result.append("=");
result.append(CmsEncoder.encode(values[j]));
if ((j + 1) < values.length) {
result.append("&");
}
}
if (i.hasNext()) {
result.append("&");
}
}
return CmsEncoder.encode(result.toString());

public static String getRelativeUri(String fromUri, String toUri) StringBuffer result = new StringBuffer();
int pos = 0;
while (true) {
int i = fromUri.indexOf('/', pos);
int j = toUri.indexOf('/', pos);
if ((i == -1) || (i != j) || !fromUri.regionMatches(pos, toUri, pos, i - pos)) {
break;
}
pos = i + 1;
}
for (int i = fromUri.indexOf('/', pos); i > 0; i = fromUri.indexOf('/', i + 1)) {
result.append("../");
}
result.append(toUri.substring(pos));
if (result.length() == 0) {
result.append("./");
}
return result.toString();

public static String appendParameters(String url, Map<String, String[]> params, boolean encode) if (CmsStringUtil.isEmpty(url)) {
return null;
}
if ((params == null) || params.isEmpty()) {
return url;
}
int pos = url.indexOf(URL_DELIMITER);
StringBuffer result = new StringBuffer(256);
result.append(url);
if (pos >= 0) {
result.append(PARAMETER_DELIMITER);
} else {
result.append(URL_DELIMITER);
}
Iterator<Map.Entry<String, String[]>> i = params.entrySet().iterator();
while (i.hasNext()) {
Map.Entry<String, String[]> entry = i.next();
String key = entry.getKey();
Object value = entry.getValue();
String[] values = value instanceof String[] ? (String[])value : new String[] {value.toString()};
for (int j = 0; j < values.length; j++) {
String strValue = values[j];
if (encode) {
strValue = CmsEncoder.encode(strValue);
}
result.append(key);
result.append(PARAMETER_ASSIGNMENT);
result.append(strValue);
if ((j + 1) < values.length) {
result.append(PARAMETER_DELIMITER);
}
}
if (i.hasNext()) {
result.append(PARAMETER_DELIMITER);
}
}
return result.toString();

public void setCategories(List<CmsCategory> categories) for (int i = 0; i < categories.size(); i++) {
CmsCategory cat = categories.get(i);
m_container.addItem(cat);
m_checkboxes.put(cat, new CheckBox());
String parentPath = CmsResource.getParentFolder(cat.getPath());
if (parentPath.length() > 1) {
for (int j = i - 1; j >= 0; j--) {
if (categories.get(j).getPath().equals(parentPath)) {
m_container.setParent(cat, categories.get(j));
break;
}
}
}
}
for (CmsCategory cat : categories) {
if ((m_container.getChildren(cat) == null) || (m_container.getChildren(cat).size() == 0)) {
m_container.setChildrenAllowed(cat, false);
}
}

protected List<String> optimizeSourceList(List<String> sourceListInVfs) List<String> input = new ArrayList<String>(sourceListInVfs);
Collections.sort(input);
List<String> result = new ArrayList<String>();
Iterator<String> i = input.iterator();
while (i.hasNext()) {
String sourceInVfs = i.next();
if (CmsStringUtil.isEmpty(sourceInVfs)) {
continue;
}
boolean found = false;
for (int j = (result.size() - 1); j >= 0; j--) {
String check = result.get(j);
if (sourceInVfs.startsWith(check)) {
found = true;
break;
}
}
if (!found) {
result.add(sourceInVfs);
}
}
return result;

public static void processHeaders(Map<String, List<String>> headers, HttpServletResponse res) if (headers != null) {
Iterator<Map.Entry<String, List<String>>> i = headers.entrySet().iterator();
while (i.hasNext()) {
Map.Entry<String, List<String>> entry = i.next();
String key = entry.getKey();
List<String> l = entry.getValue();
for (int j = 0; j < l.size(); j++) {
if ((j == 0) && ((l.get(0)).startsWith(SET_HEADER))) {
String s = l.get(0);
res.setHeader(key, s.substring(SET_HEADER.length()));
} else {
res.addHeader(key, l.get(j));
}
}
}
}

public <R> JoinOperatorSetsBase<T, R> rightOuterJoin(DataSet<R> other, JoinHint strategy) switch(strategy) {
case OPTIMIZER_CHOOSES:
case REPARTITION_SORT_MERGE:
case REPARTITION_HASH_FIRST:
case REPARTITION_HASH_SECOND:
case BROADCAST_HASH_FIRST:
return new JoinOperatorSetsBase<>(this, other, strategy, JoinType.RIGHT_OUTER);
default:
throw new InvalidProgramException("Invalid JoinHint for RightOuterJoin: " + strategy);
}

public <R> JoinOperatorSetsBase<T, R> fullOuterJoin(DataSet<R> other, JoinHint strategy) switch(strategy) {
case OPTIMIZER_CHOOSES:
case REPARTITION_SORT_MERGE:
case REPARTITION_HASH_FIRST:
case REPARTITION_HASH_SECOND:
return new JoinOperatorSetsBase<>(this, other, strategy, JoinType.FULL_OUTER);
default:
throw new InvalidProgramException("Invalid JoinHint for FullOuterJoin: " + strategy);
}

public static FailoverStrategy.Factory loadFailoverStrategy(Configuration config, @Nullable Logger logger) final String strategyParam = config.getString(JobManagerOptions.EXECUTION_FAILOVER_STRATEGY);
if (StringUtils.isNullOrWhitespaceOnly(strategyParam)) {
if (logger != null) {
logger.warn("Null config value for {} ; using default failover strategy (full restarts).",
JobManagerOptions.EXECUTION_FAILOVER_STRATEGY.key());
}
return new RestartAllStrategy.Factory();
}
else {
switch (strategyParam.toLowerCase()) {
case FULL_RESTART_STRATEGY_NAME:
return new RestartAllStrategy.Factory();
case PIPELINED_REGION_RESTART_STRATEGY_NAME:
return new RestartPipelinedRegionStrategy.Factory();
case INDIVIDUAL_RESTART_STRATEGY_NAME:
return new RestartIndividualStrategy.Factory();
default:
throw new IllegalConfigurationException("Unknown failover strategy: " + strategyParam);
}
}

