protected void connectInner(GrayS32 input, GrayS32 output) int startX = connectRule == ConnectRule.EIGHT ? 1 : 0;
for( int y = 0; y < input.height-1; y++ ) {
int indexIn = input.startIndex + y*input.stride + startX;
int indexOut = output.startIndex + y*output.stride + startX;
for( int x = startX; x < input.width-1; x++ , indexIn++, indexOut++) {
int inputLabel = input.data[indexIn];
int outputLabel = output.data[indexOut];
if( outputLabel == -1 ) {
output.data[indexOut] = outputLabel = regionMemberCount.size;
regionMemberCount.add(1);
mergeList.add(outputLabel);
}
for( int i = 0; i < edgesIn.length; i++ ) {
if( inputLabel == input.data[indexIn+edgesIn[i]] ) {
int outputAdj = output.data[indexOut+edgesOut[i]];
if( outputAdj == -1 ) {
regionMemberCount.data[outputLabel]++;
output.data[indexOut+edgesOut[i]] = outputLabel;
} else if( outputLabel != outputAdj ) {
markMerge(outputLabel,outputAdj);
}
}
}
}
}

public static void equalizeLocalRow( GrayU16 input , int radius , int startY , GrayU16 output , IWorkArrays workArrays ) int width = 2*radius+1;
int area = width*width;
int maxValue = workArrays.length()-1;
int[] histogram = workArrays.pop();
int[] transform = workArrays.pop();
int hist0 = startY;
int hist1 = startY+width;
if( hist1 > input.height ) {
hist1 = input.height;
hist0 = hist1 - width;
}
int region0 = startY;
int region1 = startY+radius;
localHistogram(input,0,hist0,width,hist1,histogram);
int sum = 0;
for( int i = 0; i < histogram.length; i++ ) {
transform[i] = sum += histogram[i];
}
for( int y = region0; y < region1; y++ ) {
int indexIn = input.startIndex + y*input.stride;
int indexOut = output.startIndex + y*output.stride;
for( int x = 0; x <= radius; x++ ) {
int inputValue =  input.data[indexIn++] & 0xff;
output.data[indexOut++] = (short)((transform[ inputValue ]*maxValue)/area);
}
}
for( int x = radius+1; x < input.width-radius-1; x++ ) {
int indexIn = input.startIndex + x-radius-1;
for( int y = hist0; y < hist1; y++ ) {
histogram[input.data[indexIn + y*input.stride] & 0xFFFF]--;
}
indexIn += width;
for( int y = hist0; y < hist1; y++ ) {
histogram[input.data[indexIn + y*input.stride] & 0xFFFF]++;
}
sum = 0;
for( int i = 0; i < histogram.length; i++ ) {
transform[i] = sum += histogram[i];
}
indexIn = input.startIndex + region0*input.stride + x;
int indexOut = output.startIndex + region0*output.stride + x;
for( int y = 0; y < radius; y++ ) {
int inputValue =  input.data[indexIn] & 0xff;
output.data[indexOut] = (short)((transform[ inputValue ]*maxValue)/area);
indexIn += input.stride;
indexOut += output.stride;
}
}
localHistogram(input,input.width-width,hist0,input.width,hist1,histogram);
sum = 0;
for( int i = 0; i < histogram.length; i++ ) {
transform[i] = sum += histogram[i];
}
for( int y = region0; y < region1; y++ ) {
int x = input.width-radius-1;
int indexIn = input.startIndex + y*input.stride + x;
int indexOut = output.startIndex + y*output.stride + x;
for( ; x < input.width; x++ ) {
int inputValue =  input.data[indexIn++] & 0xff;
output.data[indexOut++] = (short)((transform[ inputValue ]*maxValue)/area);
}
}
workArrays.recycle(histogram);
workArrays.recycle(transform);

public static void savePPM(Planar<GrayU8> rgb , String fileName , GrowQueue_I8 temp ) throws IOException File out = new File(fileName);
DataOutputStream os = new DataOutputStream(new FileOutputStream(out));
