PixelMath.pow2(input, inputPow2);
BlurImageOps.mean(inputPow2,inputPow2Mean,radius,tmp, work);
PixelMath.pow2(inputMean,inputMeanPow2);
PixelMath.subtract(inputPow2Mean, inputMeanPow2, stdev);
PixelMath.sqrt(stdev, stdev);
float R = ImageStatistics.max(stdev);
if( down ) {
BoofConcurrency.loopFor(0, input.height, y -> {
int i = y * stdev.width;
int indexIn = input.startIndex + y * input.stride;
int indexOut = output.startIndex + y * output.stride;
for (int x = 0; x < input.width; x++, i++) {
float threshold = inputMean.data[i] * (1.0f + k * (stdev.data[i] / R - 1.0f));
output.data[indexOut++] = (byte) (input.data[indexIn++] <= threshold ? 1 : 0);
}
});
} else {
BoofConcurrency.loopFor(0, input.height, y -> {
int i = y * stdev.width;
int indexIn = input.startIndex + y * input.stride;
int indexOut = output.startIndex + y * output.stride;
for (int x = 0; x < input.width; x++, i++) {
float threshold = inputMean.data[i] * (1.0f + k * (stdev.data[i] / R - 1.0f));
output.data[indexOut++] = (byte) (input.data[indexIn++] >= threshold ? 1 : 0);
}
});
}

public static void equalizeLocalCol( GrayU16 input , int radius , int startX , GrayU16 output , IWorkArrays workArrays) int width = 2*radius+1;
int area = width*width;
int maxValue = workArrays.length()-1;
int[] histogram = workArrays.pop();
int[] transform = workArrays.pop();
int hist0 = startX;
int hist1 = startX+width;
if( hist1 > input.width ) {
hist1 = input.width;
hist0 = hist1 - width;
}
localHistogram(input,hist0,0,hist1,width,histogram);
int sum = 0;
for( int i = 0; i < histogram.length; i++ ) {
transform[i] = sum += histogram[i];
}
int indexIn = input.startIndex + radius*input.stride + startX;
int indexOut = output.startIndex + radius*output.stride + startX;
for( int x = 0; x < radius; x++ ) {
int inputValue =  input.data[indexIn++] & 0xff;
output.data[indexOut++] = (short)((transform[ inputValue ]*maxValue)/area);
}
for( int y = radius+1; y < input.height-radius; y++ ) {
indexIn = input.startIndex + (y-radius-1)*input.stride;
for( int x = hist0; x < hist1; x++ ) {
histogram[input.data[indexIn + x] & 0xFFFF]--;
}
indexIn += width*input.stride;
for( int x = hist0; x < hist1; x++ ) {
histogram[input.data[indexIn + x] & 0xFFFF]++;
}
sum = 0;
for( int i = 0; i < histogram.length; i++ ) {
transform[i] = sum += histogram[i];
}
indexIn = input.startIndex + y*input.stride + startX;
indexOut = output.startIndex + y*output.stride + startX;
for( int x = 0; x < radius; x++ ) {
int inputValue =  input.data[indexIn++] & 0xff;
output.data[indexOut++] = (short)((transform[ inputValue ]*maxValue)/area);
}
}
workArrays.recycle(histogram);
workArrays.recycle(transform);

private static byte[] read(InputStream source, int initialSize) throws IOException int capacity = initialSize;
byte[] buf = new byte[capacity];
int nread = 0;
int n;
for (; ;) {
while ((n = source.read(buf, nread, Math.min(capacity - nread, BUFFER_SIZE))) > 0) {
nread += n;
}
if (n < 0 || (n = source.read()) < 0) {
break;
}
if (capacity <= MAX_BUFFER_SIZE - capacity) {
capacity = Math.max(capacity << 1, BUFFER_SIZE);
} else {
if (capacity == MAX_BUFFER_SIZE) {
throw new OutOfMemoryError("Required array size too large");
}
capacity = MAX_BUFFER_SIZE;
}
buf = Arrays.copyOf(buf, capacity);
buf[nread++] = (byte) n;
}
return (capacity == nread) ? buf : Arrays.copyOf(buf, nread);

public boolean isMatching(ResourceProfile required) if (required == UNKNOWN) {
return true;
}
if (cpuCores >= required.getCpuCores() &&
heapMemoryInMB >= required.getHeapMemoryInMB() &&
directMemoryInMB >= required.getDirectMemoryInMB() &&
nativeMemoryInMB >= required.getNativeMemoryInMB() &&
networkMemoryInMB >= required.getNetworkMemoryInMB()) {
for (Map.Entry<String, Resource> resource : required.extendedResources.entrySet()) {
if (!extendedResources.containsKey(resource.getKey()) ||
!extendedResources.get(resource.getKey()).getResourceAggregateType().equals(resource.getValue().getResourceAggregateType()) ||
extendedResources.get(resource.getKey()).getValue() < resource.getValue().getValue()) {
return false;
}
}
return true;
}
return false;

public static void copyBytes(final InputStream in, final OutputStream out, final int buffSize, final boolean close) throws IOException @SuppressWarnings("resource")
final PrintStream ps = out instanceof PrintStream ? (PrintStream) out : null;
final byte[] buf = new byte[buffSize];
try {
int bytesRead = in.read(buf);
while (bytesRead >= 0) {
out.write(buf, 0, bytesRead);
if ((ps != null) && ps.checkError()) {
throw new IOException("Unable to write to output stream.");
}
bytesRead = in.read(buf);
}
} finally {
if (close) {
out.close();
in.close();
}
}

