private boolean tryDropSpare(WorkQueue w) if (w != null && w.isEmpty()) {
long c; int sp, wl; WorkQueue[] ws; WorkQueue v;
while ((short)((c = ctl) >> TC_SHIFT) > 0 &&
((sp = (int)c) != 0 || (int)(c >> AC_SHIFT) > 0) &&
(ws = workQueues) != null && (wl = ws.length) > 0) {
boolean dropped, canDrop;
if (sp == 0) {
long nc = ((AC_MASK & (c - AC_UNIT)) |
(TC_MASK & (c - TC_UNIT)) | (SP_MASK & c));
dropped = U.compareAndSwapLong(this, CTL, c, nc);
}
else if (
(v = ws[(wl - 1) & sp]) == null || v.scanState != sp)
dropped = false;
else {
long nc = v.stackPred & SP_MASK;
if (w == v || w.scanState >= 0) {
canDrop = true;
nc |= ((AC_MASK & c) |
(TC_MASK & (c - TC_UNIT)));
}
else {
canDrop = false;
nc |= ((AC_MASK & (c + AC_UNIT)) |
(TC_MASK & c));
}
if (U.compareAndSwapLong(this, CTL, c, nc)) {
v.scanState = sp & ~UNSIGNALLED;
LockSupport.unpark(v.parker);
dropped = canDrop;
}
else
dropped = false;
}
if (dropped) {
int cfg = w.config, idx = cfg & SMASK;
if (idx >= 0 && idx < ws.length && ws[idx] == w)
ws[idx] = null;
w.config = cfg | UNREGISTERED;
w.qlock = -1;
return true;
}
}
}
return false;

final void deregisterWorker(ForkJoinWorkerThread wt, Throwable ex) WorkQueue w = null;
if (wt != null && (w = wt.workQueue) != null) {
AuxState aux; WorkQueue[] ws;
int idx = w.config & SMASK;
int ns = w.nsteals;
if ((aux = auxState) != null) {
aux.lock();
try {
if ((ws = workQueues) != null && ws.length > idx &&
ws[idx] == w)
ws[idx] = null;
aux.stealCount += ns;
} finally {
aux.unlock();
}
}
}
if (w == null || (w.config & UNREGISTERED) == 0) {
long c;
do {} while (!U.compareAndSwapLong
(this, CTL, c = ctl, ((AC_MASK & (c - AC_UNIT)) |
(TC_MASK & (c - TC_UNIT)) |
(SP_MASK & c))));
}
if (w != null) {
w.currentSteal = null;
w.qlock = -1;
w.cancelAll();
}
while (tryTerminate(false, false) >= 0) {
WorkQueue[] ws; int wl, sp; long c;
if (w == null || w.array == null ||
(ws = workQueues) == null || (wl = ws.length) <= 0)
break;
else if ((sp = (int)(c = ctl)) != 0) {
if (tryRelease(c, ws[(wl - 1) & sp], AC_UNIT))
break;
}
else if (ex != null && (c & ADD_WORKER) != 0L) {
tryAddWorker(c);
break;
}
else
break;
}
if (ex == null)
ForkJoinTask.helpExpungeStaleExceptions();
else
ForkJoinTask.rethrow(ex);

