}
}

final void signalWork() for (;;) {
long c; int sp, i; WorkQueue v; WorkQueue[] ws;
if ((c = ctl) >= 0L)
break;
else if ((sp = (int)c) == 0) {
if ((c & ADD_WORKER) != 0L)
