break;
}
else if ((ws = workQueues) == null)
break;
else if (ws.length <= (i = sp & SMASK))
break;
else if ((v = ws[i]) == null)
break;
else {
int ns = sp & ~UNSIGNALLED;
int vs = v.scanState;
long nc = (v.stackPred & SP_MASK) | (UC_MASK & (c + AC_UNIT));
if (sp == vs && U.compareAndSwapLong(this, CTL, c, nc)) {
