private void tryAddWorker(long c) do {
long nc = ((AC_MASK & (c + AC_UNIT)) |
(TC_MASK & (c + TC_UNIT)));
if (ctl == c && U.compareAndSwapLong(this, CTL, c, nc)) {
createWorker(false);
break;
}
} while (((c = ctl) & ADD_WORKER) != 0L && (int)c == 0);

final void helpQuiescePool(WorkQueue w) ForkJoinTask<?> ps = w.currentSteal;
int wc = w.config;
for (boolean active = true;;) {
long c; WorkQueue q; ForkJoinTask<?> t;
if (wc >= 0 && (t = w.pop()) != null) {
(w.currentSteal = t).doExec();
w.currentSteal = ps;
}
else if ((q = findNonEmptyStealQueue()) != null) {
if (!active) {
active = true;
U.getAndAddLong(this, CTL, AC_UNIT);
}
if ((t = q.pollAt(q.base)) != null) {
(w.currentSteal = t).doExec();
w.currentSteal = ps;
if (++w.nsteals < 0)
w.transferStealCount(this);
}
}
else if (active) {
long nc = (AC_MASK & ((c = ctl) - AC_UNIT)) | (~AC_MASK & c);
if (U.compareAndSwapLong(this, CTL, c, nc))
active = false;
}
else if ((int)((c = ctl) >> AC_SHIFT) + (config & SMASK) <= 0 &&
U.compareAndSwapLong(this, CTL, c, c + AC_UNIT))
break;
}

private int timedAwaitWork(WorkQueue w, long c) int stat = 0;
int scale = 1 - (short)(c >>> TC_SHIFT);
long deadline = (((scale <= 0) ? 1 : scale) * IDLE_TIMEOUT_MS +
System.currentTimeMillis());
if ((runState >= 0 || (stat = tryTerminate(false, false)) > 0) &&
w != null && w.scanState < 0) {
int ss; AuxState aux;
w.parker = Thread.currentThread();
if (w.scanState < 0)
LockSupport.parkUntil(this, deadline);
w.parker = null;
if ((runState & STOP) != 0)
stat = w.qlock = -1;
else if ((ss = w.scanState) < 0 && !Thread.interrupted() &&
(int)c == ss && (aux = auxState) != null && ctl == c &&
deadline - System.currentTimeMillis() <= TIMEOUT_SLOP_MS) {
aux.lock();
try {
WorkQueue[] ws;
int cfg = w.config, idx = cfg & SMASK;
long nc = ((UC_MASK & (c - TC_UNIT)) |
(SP_MASK & w.stackPred));
if ((runState & STOP) == 0 &&
(ws = workQueues) != null &&
idx < ws.length && idx >= 0 && ws[idx] == w &&
U.compareAndSwapLong(this, CTL, c, nc)) {
ws[idx] = null;
w.config = cfg | UNREGISTERED;
stat = w.qlock = -1;
}
} finally {
aux.unlock();
}
}
}
return stat;

private void inactivate(WorkQueue w, int ss) int ns = (ss + SS_SEQ) | UNSIGNALLED;
long lc = ns & SP_MASK, nc, c;
if (w != null) {
w.scanState = ns;
do {
nc = lc | (UC_MASK & ((c = ctl) - AC_UNIT));
w.stackPred = (int)c;
} while (!U.compareAndSwapLong(this, CTL, c, nc));
}

private boolean tryRelease(long c, WorkQueue v, long inc) int sp = (int)c, ns = sp & ~UNSIGNALLED;
if (v != null) {
int vs = v.scanState;
long nc = (v.stackPred & SP_MASK) | (UC_MASK & (c + inc));
if (sp == vs && U.compareAndSwapLong(this, CTL, c, nc)) {
v.scanState = ns;
LockSupport.unpark(v.parker);
return true;
}
}
return false;

private int tryTerminate(boolean now, boolean enable) int rs;
while ((rs = runState) >= 0) {
if (!enable || this == common)
return 1;
else if (rs == 0)
tryInitialize(false);
else
U.compareAndSwapInt(this, RUNSTATE, rs, rs | SHUTDOWN);
}
if ((rs & STOP) == 0) {
if (!now) {
for (long oldSum = 0L;;) {
WorkQueue[] ws; WorkQueue w; int b;
long checkSum = ctl;
if ((int)(checkSum >> AC_SHIFT) + (config & SMASK) > 0)
return 0;
if ((ws = workQueues) != null) {
for (int i = 0; i < ws.length; ++i) {
if ((w = ws[i]) != null) {
checkSum += (b = w.base);
if (w.currentSteal != null || b != w.top)
return 0;
}
}
}
if (oldSum == (oldSum = checkSum))
break;
}
}
do {} while (!U.compareAndSwapInt(this, RUNSTATE,
rs = runState, rs | STOP));
}
for (long oldSum = 0L;;) {
WorkQueue[] ws; WorkQueue w; ForkJoinWorkerThread wt;
long checkSum = ctl;
if ((ws = workQueues) != null) {
for (int i = 0; i < ws.length; ++i) {
if ((w = ws[i]) != null) {
w.cancelAll();
checkSum += w.base;
if (w.qlock >= 0) {
w.qlock = -1;
if ((wt = w.owner) != null) {
try {
wt.interrupt();
} catch (Throwable ignore) {
}
}
}
}
}
}
if (oldSum == (oldSum = checkSum))
break;
}
if ((short)(ctl >>> TC_SHIFT) + (config & SMASK) <= 0) {
runState = (STARTED | SHUTDOWN | STOP | TERMINATED);
synchronized (this) {
notifyAll();
}
}
return -1;

