private CmsLock unlockResource(String resourceName, boolean systemLocks) m_isDirty = true;
CmsLock lock = OpenCms.getMemoryMonitor().getCachedLock(resourceName);
if (lock == null) {
return CmsLock.getNullLock();
}
if (systemLocks) {
if (!lock.getSystemLock().isUnlocked()) {
OpenCms.getMemoryMonitor().uncacheLock(resourceName);
return lock;
} else {
return CmsLock.getNullLock();
}
} else {
if (lock.getSystemLock().isUnlocked()) {
OpenCms.getMemoryMonitor().uncacheLock(resourceName);
return lock;
} else {
if (!lock.getEditionLock().isUnlocked()) {
CmsLock tmp = lock.getEditionLock();
CmsLock sysLock = lock.getSystemLock();
sysLock.setRelatedLock(null);
if (!sysLock.equals(lock)) {
OpenCms.getMemoryMonitor().cacheLock(sysLock);
}
return tmp;
} else {
return CmsLock.getNullLock();
}
}
}

public static CmsListInfoBean addLockInfo(CmsObject cms, CmsResource resource, CmsListInfoBean resourceInfo) throws CmsException Locale locale = OpenCms.getWorkplaceManager().getWorkplaceLocale(cms);
CmsResourceUtil resourceUtil = new CmsResourceUtil(cms, resource);
CmsLock lock = resourceUtil.getLock();
LockIcon icon = LockIcon.NONE;
String iconTitle = null;
CmsLockType lockType = lock.getType();
if (!lock.isOwnedBy(cms.getRequestContext().getCurrentUser())) {
if ((lockType == CmsLockType.EXCLUSIVE)
|| (lockType == CmsLockType.INHERITED)
|| (lockType == CmsLockType.TEMPORARY)) {
icon = LockIcon.CLOSED;
} else if ((lockType == CmsLockType.SHARED_EXCLUSIVE) || (lockType == CmsLockType.SHARED_INHERITED)) {
icon = LockIcon.SHARED_CLOSED;
}
} else {
if ((lockType == CmsLockType.EXCLUSIVE)
|| (lockType == CmsLockType.INHERITED)
|| (lockType == CmsLockType.TEMPORARY)) {
icon = LockIcon.OPEN;
} else if ((lockType == CmsLockType.SHARED_EXCLUSIVE) || (lockType == CmsLockType.SHARED_INHERITED)) {
icon = LockIcon.SHARED_OPEN;
}
}
if ((lock.getUserId() != null) && !lock.getUserId().isNullUUID()) {
CmsUser lockOwner = cms.readUser(lock.getUserId());
iconTitle = Messages.get().getBundle(locale).key(Messages.GUI_LOCKED_BY_1, lockOwner.getFullName());
resourceInfo.addAdditionalInfo(
Messages.get().getBundle(locale).key(Messages.GUI_LOCKED_OWNER_0),
lockOwner.getFullName());
}
resourceInfo.setLockIcon(icon);
resourceInfo.setLockIconTitle(iconTitle);
if (icon != LockIcon.NONE) {
resourceInfo.setTitle(resourceInfo.getTitle() + " (" + iconTitle + ")");
}
return resourceInfo;

private void internalLockResource(CmsLock lock, Map<String, CmsLock> locks) throws CmsLockException CmsLock currentLock = null;
if (locks == null) {
currentLock = OpenCms.getMemoryMonitor().getCachedLock(lock.getResourceName());
} else {
currentLock = locks.get(lock.getResourceName());
}
if (currentLock != null) {
if (currentLock.getSystemLock().equals(lock) || currentLock.getEditionLock().equals(lock)) {
return;
}
if (!currentLock.getSystemLock().isUnlocked() && lock.getSystemLock().isUnlocked()) {
lock.setRelatedLock(currentLock);
if (locks == null) {
OpenCms.getMemoryMonitor().cacheLock(lock);
} else {
locks.put(lock.getResourceName(), lock);
}
} else if (currentLock.getSystemLock().isUnlocked() && !lock.getSystemLock().isUnlocked()) {
currentLock.setRelatedLock(lock);
} else {
throw new CmsLockException(
Messages.get().container(Messages.ERR_LOCK_ILLEGAL_STATE_2, currentLock, lock));
}
} else {
if (locks == null) {
OpenCms.getMemoryMonitor().cacheLock(lock);
} else {
locks.put(lock.getResourceName(), lock);
}
}

public CmsLock getLock(CmsDbContext dbc, CmsResource resource, boolean includeSiblings) throws CmsException if ((resource == null) || (dbc.currentProject().isOnlineProject())) {
return CmsLock.getNullLock();
}
CmsLock lock = getDirectLock(resource.getRootPath());
if ((lock == null) && includeSiblings) {
List<CmsResource> siblings = internalReadSiblings(dbc, resource);
lock = getSiblingsLock(siblings, resource.getRootPath());
}
if (lock == null) {
lock = getParentLock(resource.getRootPath());
}
if (!lock.getSystemLock().isUnlocked()) {
lock = lock.getSystemLock();
} else {
lock = lock.getEditionLock();
}
return lock;

public void addResource(CmsDbContext dbc, CmsResource resource, CmsUser user, CmsProject project, CmsLockType type) throws CmsLockException, CmsException if (!type.isSystem() && !type.isExclusive()) {
throw new CmsLockException(Messages.get().container(Messages.ERR_INVALID_LOCK_TYPE_1, type.toString()));
}
CmsLock currentLock = getLock(dbc, resource);
checkLockable(dbc, resource, user, project, type, currentLock);
boolean needNewLock = true;
if ((type.isExclusive()) && !(type.isTemporary() && currentLock.isInherited())) {
if (!currentLock.getEditionLock().isUnlocked()) {
needNewLock = false;
}
}
CmsLock newLock = CmsLock.getNullLock();
if (needNewLock) {
newLock = new CmsLock(resource.getRootPath(), user.getId(), project, type);
lockResource(newLock);
}
if (resource.isFolder() && newLock.getSystemLock().isUnlocked()) {
String resourceName = resource.getRootPath();
Iterator<CmsLock> itLocks = OpenCms.getMemoryMonitor().getAllCachedLocks().iterator();
while (itLocks.hasNext()) {
CmsLock lock = itLocks.next();
String lockedPath = lock.getResourceName();
if (lockedPath.startsWith(resourceName) && !lockedPath.equals(resourceName)) {
unlockResource(lockedPath, false);
}
}
}

private CmsLock getParentFolderLock(String resourceName) Iterator<CmsLock> itLocks = OpenCms.getMemoryMonitor().getAllCachedLocks().iterator();
while (itLocks.hasNext()) {
CmsLock lock = itLocks.next();
if (lock.getResourceName().endsWith("/")
&& resourceName.startsWith(lock.getResourceName())
&& !resourceName.equals(lock.getResourceName())) {
lock = lock.getEditionLock();
if (!lock.isUnlocked()) {
return lock;
}
}
}
return CmsLock.getNullLock();

