public static String replace(String source, int oldChar32, int newChar32) if (oldChar32 <= 0 || oldChar32 > CODEPOINT_MAX_VALUE) {
throw new IllegalArgumentException("Argument oldChar32 is not a valid codepoint");
}
if (newChar32 <= 0 || newChar32 > CODEPOINT_MAX_VALUE) {
throw new IllegalArgumentException("Argument newChar32 is not a valid codepoint");
}
int index = indexOf(source, oldChar32);
if (index == -1) {
return source;
}
String newChar32Str = toString(newChar32);
int oldChar32Size = 1;
int newChar32Size = newChar32Str.length();
StringBuffer result = new StringBuffer(source);
int resultIndex = index;
if (oldChar32 >= SUPPLEMENTARY_MIN_VALUE) {
oldChar32Size = 2;
}
while (index != -1) {
int endResultIndex = resultIndex + oldChar32Size;
result.replace(resultIndex, endResultIndex, newChar32Str);
int lastEndIndex = index + oldChar32Size;
index = indexOf(source, oldChar32, lastEndIndex);
resultIndex += newChar32Size + index - lastEndIndex;
}
return result.toString();

private void dumpCharCategories(java.io.PrintStream out) int n = fHeader.fCatCount;
String   catStrings[] = new  String[n+1];
int      rangeStart = 0;
int      rangeEnd = 0;
int      lastCat = -1;
int      char32;
int      category;
int      lastNewline[] = new int[n+1];
for (category = 0; category <= fHeader.fCatCount; category ++) {
catStrings[category] = "";
}
out.println("\nCharacter Categories");
out.println("--------------------");
for (char32 = 0; char32<=0x10ffff; char32++) {
category = fTrie.getCodePointValue(char32);
category &= ~0x4000;
if (category < 0 || category > fHeader.fCatCount) {
out.println("Error, bad category " + Integer.toHexString(category) +
" for char " + Integer.toHexString(char32));
break;
}
if (category == lastCat ) {
rangeEnd = char32;
} else {
if (lastCat >= 0) {
if (catStrings[lastCat].length() > lastNewline[lastCat] + 70) {
lastNewline[lastCat] = catStrings[lastCat].length() + 10;
catStrings[lastCat] += "\n       ";
}
catStrings[lastCat] += " " + Integer.toHexString(rangeStart);
if (rangeEnd != rangeStart) {
catStrings[lastCat] += "-" + Integer.toHexString(rangeEnd);
}
}
lastCat = category;
rangeStart = rangeEnd = char32;
}
}
catStrings[lastCat] += " " + Integer.toHexString(rangeStart);
if (rangeEnd != rangeStart) {
catStrings[lastCat] += "-" + Integer.toHexString(rangeEnd);
}
for (category = 0; category <= fHeader.fCatCount; category ++) {
out.println (intToString(category, 5) + "  " + catStrings[category]);
}
out.println();

public static VersionInfo getAge(int ch) if (ch < MIN_VALUE || ch > MAX_VALUE) {
throw new IllegalArgumentException("Codepoint out of bounds");
}
return UCharacterProperty.INSTANCE.getAge(ch);

public static void setCharAt(StringBuffer target, int offset16, int char32) int count = 1;
char single = target.charAt(offset16);
if (isSurrogate(single)) {
if (isLeadSurrogate(single) && (target.length() > offset16 + 1)
&& isTrailSurrogate(target.charAt(offset16 + 1))) {
count++;
} else {
if (isTrailSurrogate(single) && (offset16 > 0)
&& isLeadSurrogate(target.charAt(offset16 - 1))) {
offset16--;
count++;
}
}
}
target.replace(offset16, offset16 + count, valueOf(char32));

public static int digit(int codePoint, int radix) if (radix < MIN_RADIX || radix > MAX_RADIX) {
return -1;
}
if (codePoint < 128) {
int result = -1;
if ('0' <= codePoint && codePoint <= '9') {
result = codePoint - '0';
} else if ('a' <= codePoint && codePoint <= 'z') {
result = 10 + (codePoint - 'a');
} else if ('A' <= codePoint && codePoint <= 'Z') {
result = 10 + (codePoint - 'A');
}
return result < radix ? result : -1;
}
return digitImpl(codePoint, radix);

private <T extends Comparable<T>> void getInternal2(List<HttpCookie> cookies, Map<T, List<HttpCookie>> cookieIndex, T comparator) for (T index : cookieIndex.keySet()) {
if ((index == comparator) || (index != null && comparator.compareTo(index) == 0)) {
List<HttpCookie> indexedCookies = cookieIndex.get(index);
if (indexedCookies != null) {
Iterator<HttpCookie> it = indexedCookies.iterator();
while (it.hasNext()) {
HttpCookie ck = it.next();
if (!ck.hasExpired()) {
if (!cookies.contains(ck))
cookies.add(ck);
} else {
it.remove();
}
}
}
}
}

private List<String> sortByPath(List<HttpCookie> cookies) Collections.sort(cookies, new CookiePathComparator());
final StringBuilder result = new StringBuilder();
int minVersion = 1;
for (HttpCookie cookie : cookies) {
if (cookie.getVersion() < minVersion) {
minVersion = cookie.getVersion();
}
}
if (minVersion == 1) {
result.append("$Version=\"1\"; ");
}
for (int i = 0; i < cookies.size(); ++i) {
if (i != 0) {
result.append("; ");
}
result.append(cookies.get(i).toString());
}
List<String> cookieHeader = new java.util.ArrayList<String>();
cookieHeader.add(result.toString());
return cookieHeader;

public boolean remove(URI uri, HttpCookie ck) if (ck == null) {
throw new NullPointerException("cookie is null");
}
lock.lock();
try {
uri = getEffectiveURI(uri);
if (uriIndex.get(uri) == null) {
return false;
} else {
List<HttpCookie> cookies = uriIndex.get(uri);
if (cookies != null) {
return cookies.remove(ck);
} else {
return false;
}
}
} finally {
lock.unlock();
}

public List<HttpCookie> get(URI uri) if (uri == null) {
throw new NullPointerException("uri is null");
}
List<HttpCookie> cookies = new ArrayList<HttpCookie>();
lock.lock();
try {
getInternal1(cookies, uriIndex, uri.getHost());
getInternal2(cookies, uriIndex, getEffectiveURI(uri));
} finally {
lock.unlock();
}
return cookies;

public List<HttpCookie> getCookies() List<HttpCookie> rt = new ArrayList<HttpCookie>();
lock.lock();
try {
for (List<HttpCookie> list : uriIndex.values()) {
Iterator<HttpCookie> it = list.iterator();
while (it.hasNext()) {
HttpCookie cookie = it.next();
if (cookie.hasExpired()) {
it.remove();
} else if (!rt.contains(cookie)) {
rt.add(cookie);
}
}
}
} finally {
rt = Collections.unmodifiableList(rt);
lock.unlock();
}
return rt;

private void loadRequestCookies() throws IOException CookieHandler cookieHandler = CookieHandler.getDefault();
if (cookieHandler != null) {
try {
URI uri = getURL().toURI();
Map<String, List<String>> cookieHeaders =
cookieHandler.get(uri, getHeaderFieldsDoNotForceResponse());
for (Map.Entry<String, List<String>> entry : cookieHeaders.entrySet()) {
String key = entry.getKey();
if (("Cookie".equalsIgnoreCase(key)
|| "Cookie2".equalsIgnoreCase(key))
&& !entry.getValue().isEmpty()) {
List<String> cookies = entry.getValue();
StringBuilder sb = new StringBuilder();
for (int i = 0, size = cookies.size(); i < size; i++) {
if (i > 0) {
sb.append("; ");
}
sb.append(cookies.get(i));
}
setHeader(key, sb.toString());
}
}
} catch (URISyntaxException e) {
throw new IOException(e);
}
}

public void add(URI uri, HttpCookie cookie) if (cookie == null) {
throw new NullPointerException("cookie is null");
}
lock.lock();
try {
if (cookie.getMaxAge() != 0) {
addIndex(uriIndex, getEffectiveURI(uri), cookie);
}
} finally {
lock.unlock();
}

private static List<String> splitMultiCookies(String header) List<String> cookies = new java.util.ArrayList<String>();
int quoteCount = 0;
int p, q;
for (p = 0, q = 0; p < header.length(); p++) {
char c = header.charAt(p);
if (c == '"') quoteCount++;
if (c == ',' && (quoteCount % 2 == 0)) {
cookies.add(header.substring(q, p));
q = p + 1;
}
}
cookies.add(header.substring(q));
return cookies;

private static HttpCookie parseInternal(String header, boolean retainHeader) HttpCookie cookie = null;
String namevaluePair = null;
StringTokenizer tokenizer = new StringTokenizer(header, ";");
try {
namevaluePair = tokenizer.nextToken();
int index = namevaluePair.indexOf('=');
if (index != -1) {
String name = namevaluePair.substring(0, index).trim();
String value = namevaluePair.substring(index + 1).trim();
if (retainHeader)
cookie = new HttpCookie(name,
stripOffSurroundingQuote(value),
header);
else
cookie = new HttpCookie(name,
stripOffSurroundingQuote(value));
} else {
throw new IllegalArgumentException("Invalid cookie name-value pair");
}
} catch (NoSuchElementException ignored) {
throw new IllegalArgumentException("Empty cookie header string");
}
while (tokenizer.hasMoreTokens()) {
namevaluePair = tokenizer.nextToken();
int index = namevaluePair.indexOf('=');
String name, value;
if (index != -1) {
name = namevaluePair.substring(0, index).trim();
value = namevaluePair.substring(index + 1).trim();
} else {
name = namevaluePair.trim();
value = null;
}
assignAttribute(cookie, name, value);
}
return cookie;

