bounds.addAttribute(new Attribute(CDM.LONG_NAME, "bounds for " + tcName));
bounds.setSPobject(new Time2Dinfo(Time2DinfoType.boundsU, time2D, null));
}
if (runtime.getNCoords() != 1) {
