private static boolean registerClientProtocolAddress(AvatarZooKeeperClient zk, Configuration originalConf, Configuration conf, boolean toOverwrite) throws UnsupportedEncodingException, IOException LOG.info("Updating Client Address information in ZooKeeper");
InetSocketAddress addr = NameNode.getClientProtocolAddress(conf);
if (addr == null) {
LOG.error(FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY
+ " for primary service is not defined");
return true;
}
InetSocketAddress defaultAddr = NameNode.getClientProtocolAddress(originalConf);
if (defaultAddr == null) {
LOG.error(FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY
+ " for default service is not defined");
return true;
}
registerSocketAddress(zk,
originalConf.get(NameNode.DFS_NAMENODE_RPC_ADDRESS_KEY),
conf.get(NameNode.DFS_NAMENODE_RPC_ADDRESS_KEY), toOverwrite);
registerAliases(zk, conf, FSConstants.FS_NAMENODE_ALIASES,
conf.get(NameNode.DFS_NAMENODE_RPC_ADDRESS_KEY), toOverwrite);
return false;

public static List<InetSocketAddress> getClientRpcAddresses( Configuration conf, Collection<String> suffixes) throws IOException List<InetSocketAddress> addressList;
if(suffixes != null && !suffixes.isEmpty()){
addressList = new ArrayList<InetSocketAddress>();
for (String s : suffixes) {
addressList.addAll(getRPCAddresses(s, conf, getNameServiceIds(conf),
FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY));
}
} else {
String defaultAddress;
try {
defaultAddress = NameNode.getDefaultAddress(conf);
} catch (IllegalArgumentException e) {
defaultAddress = null;
}
addressList = getAddresses(conf, defaultAddress,
FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY);
}
if (addressList == null || addressList.isEmpty()) {
throw new IOException("Incorrect configuration: namenode address "
+ FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY
+ " is not configured.");
}
return addressList;

public static List<InetSocketAddress> getNNServiceRpcAddresses( Configuration conf) throws IOException String defaultAddress;
try {
defaultAddress = NameNode.getDefaultAddress(conf);
} catch (IllegalArgumentException e) {
defaultAddress = null;
}
List<InetSocketAddress> addressList = getAddresses(conf, defaultAddress,
NameNode.DATANODE_PROTOCOL_ADDRESS, FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY);
if (addressList == null) {
throw new IOException("Incorrect configuration: namenode address "
+ NameNode.DATANODE_PROTOCOL_ADDRESS + " or "
+ FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY
+ " is not configured.");
}
return addressList;

private static void registerHttpAddress(AvatarZooKeeperClient zk, Configuration originalConf, Configuration conf, boolean toOverwrite) throws UnsupportedEncodingException, IOException LOG.info("Updating Http Address information in ZooKeeper");
String addr = conf.get(FSConstants.DFS_NAMENODE_HTTP_ADDRESS_KEY);
String defaultAddr = originalConf
.get(FSConstants.DFS_NAMENODE_HTTP_ADDRESS_KEY);
registerSocketAddress(zk, defaultAddr, addr, toOverwrite);
registerAliases(zk, conf, FSConstants.DFS_HTTP_ALIASES, addr, toOverwrite);

static InetSocketAddress getRemoteNamenodeAddress(Configuration conf, InstanceId instance) throws IOException String fs = null;
if (instance == InstanceId.NODEZERO) {
fs = conf.get(DFS_NAMENODE_RPC_ADDRESS1_KEY);
if (fs == null)
fs = conf.get("fs.default.name1");
} else if (instance == InstanceId.NODEONE) {
fs = conf.get(DFS_NAMENODE_RPC_ADDRESS0_KEY);
if (fs == null)
fs = conf.get("fs.default.name0");
} else {
throw new IOException("Unknown instance " + instance);
}
if(fs != null) {
Configuration newConf = new Configuration(conf);
newConf.set(FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY, fs);
conf = newConf;
}
return NameNode.getClientProtocolAddress(conf);

private static List<InetSocketAddress> getAvatarNodeAddresses(String suffix, Configuration conf, Collection<String> serviceIds) throws IOException List<InetSocketAddress> namenodeAddresses = DFSUtil.getRPCAddresses(suffix,
conf, serviceIds, FSConstants.DFS_NAMENODE_RPC_ADDRESS_KEY);
List<InetSocketAddress> avatarnodeAddresses =
new ArrayList<InetSocketAddress>(namenodeAddresses.size());
for (InetSocketAddress namenodeAddress : namenodeAddresses) {
avatarnodeAddresses.add(
new InetSocketAddress(namenodeAddress.getAddress(), conf.getInt(
"dfs.avatarnode.port", namenodeAddress.getPort() + 1)));
}
return avatarnodeAddresses;

public static String getNameServiceIdFromAddress(Configuration conf, InetSocketAddress address, String... keys) Collection<String> nameserviceIds = getNameServiceIds(conf);
if (nameserviceIds == null || nameserviceIds.isEmpty()) {
return null;
}
for (String nameserviceId : nameserviceIds) {
for (String key : keys) {
String candidateAddress = conf.get(
getNameServiceIdKey(key, nameserviceId));
if (candidateAddress != null
&& address.equals(NetUtils.createSocketAddr(candidateAddress)))
return nameserviceId;
}
}
return null;

