"help",
Messages.get().getBundle(getLocale()).key(Messages.GUI_ADMIN_MENU_HELP_GROUP_0));
helpMenu.addMenuItem(new CmsAdminContextHelpMenuItem());
addGroup(helpMenu);
Iterator<CmsTool> itElems = getToolManager().getToolsForPath(
this,
getToolManager().getBaseToolPath(this),
false).iterator();
while (itElems.hasNext()) {
CmsTool tool = itElems.next();
String link = tool.getHandler().getLink();
if (link.indexOf("?") > 0) {
link = link.substring(0, link.indexOf("?"));
}
if (!getCms().existsResource(link) || !tool.getHandler().isVisible(this)) {
continue;
}
String path = tool.getHandler().getPath().substring(getToolManager().getBaseToolPath(this).length());
if (CmsStringUtil.isEmpty(path)) {
continue;
}
int pos = tool.getHandler().getPath().indexOf(CmsToolManager.TOOLPATH_SEPARATOR);
if (path.indexOf(CmsToolManager.TOOLPATH_SEPARATOR, pos + 1) < 0) {
addItem(
tool.getHandler().getGroup(),
tool.getHandler().getShortName(),
tool.getHandler().getSmallIconPath(),
CmsToolManager.linkForToolPath(getJsp(), tool.getHandler().getPath()),
tool.getHandler().isEnabled(this)
? tool.getHandler().getHelpText()
: tool.getHandler().getDisabledHelpText(),
tool.getHandler().isEnabled(this),
tool.getHandler().getPosition(),
CmsAdminMenu.DEFAULT_TARGET);
}
}

public void doSubstitution(long number, StringBuilder toInsertInto, int position, int recursionCount) long numberToFormat = transformNumber(number);
if (ruleSet != null) {
ruleSet.format(numberToFormat, toInsertInto, position + pos, recursionCount);
} else {
toInsertInto.insert(position + pos, numberFormat.format(numberToFormat));
}

public void doSubstitution(double number, StringBuilder toInsertInto, int position, int recursionCount) double numberToFormat = transformNumber(number);
if (withZeros && ruleSet != null) {
long nf = (long)numberToFormat;
int len = toInsertInto.length();
while ((nf *= 10) < denominator) {
toInsertInto.insert(position + pos, ' ');
ruleSet.format(0, toInsertInto, position + pos, recursionCount);
}
position += toInsertInto.length() - len;
}
if (numberToFormat == Math.floor(numberToFormat) && ruleSet != null) {
ruleSet.format((long)numberToFormat, toInsertInto, position + pos, recursionCount);
} else {
if (ruleSet != null) {
ruleSet.format(numberToFormat, toInsertInto, position + pos, recursionCount);
} else {
toInsertInto.insert(position + pos, numberFormat.format(numberToFormat));
}
}

public void doSubstitution(double number, StringBuilder toInsertInto, int position, int recursionCount) if (!byDigits) {
super.doSubstitution(number, toInsertInto, position, recursionCount);
}
else {
DigitList dl = new DigitList();
dl.set(number, 20, true);
boolean pad = false;
while (dl.count > Math.max(0, dl.decimalAt)) {
if (pad && useSpaces) {
toInsertInto.insert(position + pos, ' ');
} else {
pad = true;
}
ruleSet.format(dl.digits[--dl.count] - '0', toInsertInto, position + pos, recursionCount);
}
while (dl.decimalAt < 0) {
if (pad && useSpaces) {
toInsertInto.insert(position + pos, ' ');
} else {
pad = true;
}
ruleSet.format(0, toInsertInto, position + pos, recursionCount);
++dl.decimalAt;
}
}

public void doFormat(double number, StringBuilder toInsertInto, int pos, int recursionCount) int pluralRuleStart = ruleText.length();
int lengthOffset = 0;
if (rulePatternFormat == null) {
toInsertInto.insert(pos, ruleText);
}
else {
pluralRuleStart = ruleText.indexOf("$(");
int pluralRuleEnd = ruleText.indexOf(")$", pluralRuleStart);
int initialLength = toInsertInto.length();
if (pluralRuleEnd < ruleText.length() - 1) {
toInsertInto.insert(pos, ruleText.substring(pluralRuleEnd + 2));
}
double pluralVal = number;
if (0 <= pluralVal && pluralVal < 1) {
pluralVal = Math.round(pluralVal * power(radix, exponent));
}
else {
pluralVal = pluralVal / power(radix, exponent);
}
toInsertInto.insert(pos, rulePatternFormat.format((long)(pluralVal)));
if (pluralRuleStart > 0) {
toInsertInto.insert(pos, ruleText.substring(0, pluralRuleStart));
}
lengthOffset = ruleText.length() - (toInsertInto.length() - initialLength);
}
if (sub2 != null) {
sub2.doSubstitution(number, toInsertInto, pos - (sub2.getPos() > pluralRuleStart ? lengthOffset : 0), recursionCount);
}
if (sub1 != null) {
sub1.doSubstitution(number, toInsertInto, pos - (sub1.getPos() > pluralRuleStart ? lengthOffset : 0), recursionCount);
}

