private void primeProduct(List<InvPair> v, IAtomContainer atomContainer) Iterator<InvPair> it = v.iterator();
Iterator<IAtom> n;
InvPair inv;
IAtom a;
long summ;
while (it.hasNext()) {
inv = (InvPair) it.next();
List<IAtom> neighbour = atomContainer.getConnectedAtomsList(inv.getAtom());
n = neighbour.iterator();
summ = 1;
while (n.hasNext()) {
a = n.next();
int next = ((InvPair) a.getProperty(InvPair.INVARIANCE_PAIR)).getPrime();
summ = summ * next;
}
inv.setLast(inv.getCurr());
inv.setCurr(summ);
}

