private void search(int v, BitSet prev, BitSet curr) state[v] = curr;
curr = copy(curr);
curr.set(v);
visited.or(curr);
for (int w : g[v]) {
if (prev.get(w)) {
numCycles++;
add(xor(state[w], curr));
}
else if (!visited.get(w)) {
search(w, state[v], curr);
}
}

private void search(int v, long prev, long curr) state[v] = curr;
curr = setBit(curr, v);
visited |= curr;
for (int w : g[v]) {
if (visited(w)) {
if (isBitSet(prev, w)) {
numCycles++;
add(state[w] ^ curr);
}
} else {
search(w, state[v], curr);
}
}

