int rank(int[] currEq, int[] nextEq, int n, long[] curr, long[] prev) sortBy(currEq, 0, n, curr, prev);
int nEquivalent = 0;
int nRanks = 1 + curr.length - n;
int[] tmp = aux;
int u = currEq[0];
int labelTick = tmp[u] = (int) prev[u];
long label = labelTick;
for (int i = 1; i < n; i++) {
int v = currEq[i];
if (prev[v] != tmp[u])
labelTick = (int) prev[v];
else
labelTick++;
if (curr[v] != curr[u] || prev[v] != tmp[u]) {
tmp[v] = (int) prev[v];
prev[v] = labelTick;
label = labelTick;
nRanks++;
} else {
if (nEquivalent == 0 || nextEq[nEquivalent - 1] != u) nextEq[nEquivalent++] = u;
nextEq[nEquivalent++] = v;
tmp[v] = (int) prev[v];
prev[v] = label;
}
u = v;
}
if (nEquivalent < nextEq.length) nextEq[nEquivalent] = -1;
return nRanks;

