it1 = ii;
it2 = i;
}
}
}
}
n1 = k1[it1];
n2 = k1[it2];
int s1 = k2[it1] - k1[it1] + 1;
int s2 = k2[it2] - k1[it2] + 1;
float[] t0 = new float[s1];
float[] t00 = new float[s2];
