if ((mx0 > 330.0f & mx00 < 50.0f)) {
for (int i = 0; i < s1; i++) {
float q = r[n1 + i].getAz();
r[n1 + i].setAz(q - 360.0f);
}
}
Arrays.sort(r, new RayComparator());
for (int i = 0; i < r.length; i++) {
float a = r[i].getAz();
if (a < 0 & a > -361.0f) {
float qa = r[i].getAz();
r[i].setAz(qa + 360.0f);
}
}

