checkTimeOut();
if ((sourceBitSet.get(rNode.getRMap().getId1()) || sourceBitSet.isEmpty())
&& (targetBitSet.get(rNode.getRMap().getId2()) || targetBitSet.isEmpty())) {
bistSet.set(getGraph().indexOf(rNode));
}
}
