private void placeMultipleGroups(IAtomContainer mol) final List<Sgroup> sgroups = mol.getProperty(CDKConstants.CTAB_SGROUPS);
if (sgroups == null)
return;
final List<Sgroup> multipleGroups = new ArrayList<>();
for (Sgroup sgroup : sgroups) {
if (sgroup.getType() == SgroupType.CtabMultipleGroup)
multipleGroups.add(sgroup);
}
if (multipleGroups.isEmpty())
return;
int[][] adjlist = GraphUtil.toAdjList(mol);
Map<IAtom,Integer> idxs = new HashMap<>();
for (IAtom atom : mol.atoms())
idxs.put(atom, idxs.size());
for (Sgroup sgroup : multipleGroups) {
final int numCrossing = sgroup.getBonds().size();
if (numCrossing != 0 && numCrossing != 2)
continue;
final IAtomContainer substructure = mol.getBuilder().newInstance(IAtomContainer.class);
final Set<IAtom> visit = new HashSet<>();
final Collection<IAtom> patoms = sgroup.getValue(SgroupKey.CtabParentAtomList);
if (patoms == null)
continue;
for (IAtom atom : patoms) {
substructure.addAtom(atom);
visit.add(atom);
}
for (IBond bond : mol.bonds()) {
IAtom beg = bond.getBegin();
IAtom end = bond.getEnd();
if (visit.contains(beg) && visit.contains(end))
substructure.addBond(bond);
}
visit.addAll(sgroup.getAtoms());
Pattern ptrn = VentoFoggia.findSubstructure(substructure, new AtomMatcher() {
@Override
public boolean matches(IAtom a, IAtom b) {
if (!visit.contains(b))
return false;
final int aElem = safeUnbox(a.getAtomicNumber());
final int bElem = safeUnbox(b.getAtomicNumber());
if (aElem != bElem)
return false;
final int aChg = safeUnbox(a.getFormalCharge());
final int bChg = safeUnbox(b.getFormalCharge());
if (aChg != bChg)
return false;
final int aMass = safeUnbox(a.getMassNumber());
final int bMass = safeUnbox(b.getMassNumber());
if (aMass != bMass)
return false;
final int aHcnt = safeUnbox(a.getImplicitHydrogenCount());
final int bHcnt = safeUnbox(b.getImplicitHydrogenCount());
if (aHcnt != bHcnt)
return false;
return true;
}
}, BondMatcher.forOrder());
Set<IAtom> sgroupAtoms = sgroup.getAtoms();
List<Map.Entry<Point2d,Vector2d>> outgoing = new ArrayList<>();
List<Map.Entry<IBond,Vector2d>>   xBondVec = new ArrayList<>();
if (numCrossing == 2) {
for (IBond bond : mol.bonds()) {
IAtom beg = bond.getBegin();
IAtom end = bond.getEnd();
if (patoms.contains(beg) == patoms.contains(end))
continue;
if (patoms.contains(beg)) {
outgoing.add(new SimpleImmutableEntry<>(beg.getPoint2d(),
new Vector2d(end.getPoint2d().x - beg.getPoint2d().x,
end.getPoint2d().y - beg.getPoint2d().y)));
} else {
outgoing.add(new SimpleImmutableEntry<>(end.getPoint2d(),
new Vector2d(beg.getPoint2d().x - end.getPoint2d().x,
beg.getPoint2d().y - end.getPoint2d().y)));
}
}
for (IBond bond : sgroup.getBonds()) {
IAtom beg = bond.getBegin();
IAtom end = bond.getEnd();
if (sgroupAtoms.contains(beg)) {
xBondVec.add(new SimpleImmutableEntry<>(bond,
new Vector2d(end.getPoint2d().x - beg.getPoint2d().x,
end.getPoint2d().y - beg.getPoint2d().y)));
} else {
xBondVec.add(new SimpleImmutableEntry<>(bond,
new Vector2d(beg.getPoint2d().x - end.getPoint2d().x,
beg.getPoint2d().y - end.getPoint2d().y)));
}
}
}
visit.removeAll(patoms);
for (Map<IAtom, IAtom> atoms : ptrn.matchAll(mol).uniqueAtoms().toAtomMap()) {
for (Map.Entry<IAtom, IAtom> e : atoms.entrySet()) {
e.getValue().setPoint2d(new Point2d(e.getKey().getPoint2d()));
}
visit.removeAll(atoms.values());
}
assert xBondVec.size() == outgoing.size();
for (Map.Entry<IBond,Vector2d> e : xBondVec) {
IBond bond = e.getKey();
if (bond.isInRing())
continue;
IAtom beg  = sgroupAtoms.contains(bond.getBegin()) ? bond.getBegin() : bond.getEnd();
Map.Entry<Point2d,Vector2d> best = null;
for (Map.Entry<Point2d,Vector2d> candidate : outgoing) {
if (best == null || candidate.getKey().distance(beg.getPoint2d()) < best.getKey().distance(beg.getPoint2d()))
best = candidate;
}
outgoing.remove(best);
assert best != null;
Set<Integer> iVisit = new HashSet<>();
iVisit.add(idxs.get(beg));
visit(iVisit, adjlist, idxs.get(bond.getOther(beg)));
iVisit.remove(idxs.get(beg));
IAtomContainer frag = mol.getBuilder().newInstance(IAtomContainer.class);
for (Integer idx : iVisit)
frag.addAtom(mol.getAtom(idx));
Vector2d orgVec = e.getValue();
Vector2d newVec = best.getValue();
Point2d endP    = bond.getOther(beg).getPoint2d();
Point2d newEndP = new Point2d(beg.getPoint2d());
newEndP.add(newVec);
double pDot  = orgVec.x * newVec.y - orgVec.y * newVec.x;
double theta = Math.atan2(pDot, newVec.dot(orgVec));
GeometryUtil.translate2D(frag, newEndP.x - endP.x, newEndP.y - endP.y);
GeometryUtil.rotate(frag, new Point2d(bond.getOther(beg).getPoint2d()), theta);
}
}

public boolean awaitConnected(long timeout, TimeUnit unit) throws InterruptedException lock.lock();
try {
if (currentState.equals(CLIENT_CONNECTED)) {
return true;
}
if (currentState.equals(SHUTTING_DOWN) || currentState.equals(SHUTDOWN)) {
return false;
}
long duration = unit.toNanos(timeout);
while (duration > 0) {
duration = connectedCondition.awaitNanos(duration);
if (currentState.equals(CLIENT_CONNECTED)) {
return true;
}
}
return false;
} finally {
lock.unlock();
}

public boolean awaitDisconnected(long timeout, TimeUnit unit) throws InterruptedException lock.lock();
try {
if (currentState.equals(CLIENT_DISCONNECTED) || currentState.equals(SHUTTING_DOWN) || currentState.equals(SHUTDOWN)) {
return true;
}
long duration = unit.toNanos(timeout);
while (duration > 0) {
duration = disconnectedCondition.awaitNanos(duration);
if (currentState.equals(CLIENT_DISCONNECTED) || currentState.equals(SHUTTING_DOWN) || currentState
.equals(SHUTDOWN)) {
return true;
}
}
return false;
} finally {
lock.unlock();
}

protected boolean setResult(Object result) for (; ; ) {
Object currentState = this.state;
if (isDoneState(currentState)) {
return false;
}
if (STATE.compareAndSet(this, currentState, result)) {
done();
notifyThreadsWaitingOnGet();
runAsynchronous((ExecutionCallbackNode) currentState, result);
break;
}
}
return true;

public TransactionOptions setTimeout(long timeout, TimeUnit timeUnit) if (timeout < 0) {
throw new IllegalArgumentException("Timeout can not be negative!");
}
if (timeUnit == null) {
throw new IllegalArgumentException("timeunit can't be null");
}
if (timeout == 0) {
setDefaultTimeout();
} else {
this.timeoutMillis = timeUnit.toMillis(timeout);
}
return this;

void afterExecution() for (;;) {
State currentState = state.get();
switch (currentState) {
case REQUESTED:
state.set(State.RUNNING);
scheduleExecution();
return;
case RUNNING:
if (state.compareAndSet(State.RUNNING, State.INACTIVE)) {
return;
}
break;
default:
throw new IllegalStateException("Inactive state is illegal here.");
}
}

void requestExecution() for (;;) {
State currentState = state.get();
switch (currentState) {
case INACTIVE:
if (state.compareAndSet(State.INACTIVE, State.RUNNING)) {
scheduleExecution();
return;
}
break;
case RUNNING:
if (state.compareAndSet(State.RUNNING, State.REQUESTED)) {
return;
}
break;
default:
return;
}
}

@Override public boolean onShutdown(long timeout, TimeUnit unit) if (nodeEngine.getLocalMember().isLiteMember()) {
return true;
}
long timeoutNanos = unit.toNanos(timeout);
for (CRDTReplicationAwareService service : getReplicationServices()) {
service.prepareToSafeShutdown();
final CRDTReplicationContainer replicationOperation = service.prepareReplicationOperation(
replicationVectorClocks.getLatestReplicatedVectorClock(service.getName()), 0);
if (replicationOperation == null) {
logger.fine("Skipping replication since all CRDTs are replicated");
continue;
}
long start = System.nanoTime();
if (!tryProcessOnOtherMembers(replicationOperation.getOperation(), service.getName(), timeoutNanos)) {
logger.warning("Failed replication of CRDTs for " + service.getName() + ". CRDT state may be lost.");
}
timeoutNanos -= (System.nanoTime() - start);
if (timeoutNanos < 0) {
return false;
}
}
return true;

public StateMachine<T> next(T nextState) throws IllegalStateException Set<T> allowed = transitions.get(currentState);
checkNotNull(allowed, "No transitions from state " + currentState);
checkState(allowed.contains(nextState), "Transition not allowed from state " + currentState + " to " + nextState);
currentState = nextState;
return this;

public static String toPrettyString(long size, MemoryUnit unit) if (unit.toGigaBytes(size) >= PRETTY_FORMAT_LIMIT) {
return unit.toGigaBytes(size) + " GB";
}
if (unit.toMegaBytes(size) >= PRETTY_FORMAT_LIMIT) {
return unit.toMegaBytes(size) + " MB";
}
if (unit.toKiloBytes(size) >= PRETTY_FORMAT_LIMIT) {
return unit.toKiloBytes(size) + " KB";
}
if (size % MemoryUnit.K == 0) {
return unit.toKiloBytes(size) + " KB";
}
return size + " bytes";

boolean detectAndHandleBackupTimeout(long timeoutMillis) boolean backupsCompleted = backupsAcksExpected == backupsAcksReceived;
long responseReceivedMillis = pendingResponseReceivedMillis;
long expirationTime = responseReceivedMillis + timeoutMillis;
boolean timeout = expirationTime > 0 && expirationTime < Clock.currentTimeMillis();
boolean responseReceived = pendingResponse != VOID;
if (backupsCompleted || !responseReceived || !timeout) {
return false;
}
if (shouldFailOnIndeterminateOperationState()) {
complete(new IndeterminateOperationStateException(this + " failed because backup acks missed."));
return true;
}
boolean targetDead = context.clusterService.getMember(targetAddress) == null;
if (targetDead) {
resetAndReInvoke();
return false;
}
complete(pendingResponse);
return true;

public void addAllListeners(PropertyChangeListener listener, Object newObject, Set updateSet) addListeners(listener, newObject, updateSet);
if ((children != null) && (children.length > 0)) {
try {
Object newValue = null;
if (newObject != null) {
updateSet.add(newObject);
newValue = extractNewValue(newObject);
}
for (BindPath child : children) {
child.addAllListeners(listener, newValue, updateSet);
}
} catch (Exception e) {
e.printStackTrace(System.out);
}
}

public void addListeners(PropertyChangeListener listener, Object newObject, Set updateSet) removeListeners();
if (newObject != null) {
TriggerBinding syntheticTrigger = getSyntheticTriggerBinding(newObject);
MetaClass mc = InvokerHelper.getMetaClass(newObject);
if (syntheticTrigger != null) {
PropertyBinding psb = new PropertyBinding(newObject, propertyName);
PropertyChangeProxyTargetBinding proxytb = new PropertyChangeProxyTargetBinding(newObject, propertyName, listener);
syntheticFullBinding = syntheticTrigger.createBinding(psb, proxytb);
syntheticFullBinding.bind();
updateSet.add(newObject);
} else if (!mc.respondsTo(newObject, "addPropertyChangeListener", NAME_PARAMS).isEmpty()) {
InvokerHelper.invokeMethod(newObject, "addPropertyChangeListener", new Object[] {propertyName, listener});
localListener = listener;
updateSet.add(newObject);
} else if (!mc.respondsTo(newObject, "addPropertyChangeListener", GLOBAL_PARAMS).isEmpty()) {
InvokerHelper.invokeMethod(newObject, "addPropertyChangeListener", listener);
globalListener = listener;
updateSet.add(newObject);
}
}
currentObject = newObject;

public void removeListeners() if (globalListener != null) {
try {
InvokerHelper.invokeMethod(currentObject, "removePropertyChangeListener", globalListener);
} catch (Exception e) {
}
globalListener = null;
}
if (localListener != null) {
try {
InvokerHelper.invokeMethod(currentObject, "removePropertyChangeListener", new Object[] {propertyName, localListener});
} catch (Exception e) {
}
localListener = null;
}
if (syntheticFullBinding != null) {
syntheticFullBinding.unbind();
}

public void setProperty(final String property, final Object newValue) if (property.startsWith("@")) {
if (newValue instanceof String || newValue instanceof GString) {
final Iterator iter = iterator();
while (iter.hasNext()) {
final NodeChild child = (NodeChild) iter.next();
child.attributes().put(property.substring(1), newValue);
}
}
} else {
final GPathResult result = new NodeChildren(this, property, this.namespaceTagHints);
if (newValue instanceof Map) {
for (Object o : ((Map) newValue).entrySet()) {
final Map.Entry entry = (Map.Entry) o;
result.setProperty("@" + entry.getKey(), entry.getValue());
}
} else {
if (newValue instanceof Closure) {
result.replaceNode((Closure) newValue);
} else {
result.replaceBody(newValue);
}
}
}

public Closure getBody() return new Closure(this.parent,this) {
public void doCall(Object[] args) {
final GroovyObject delegate = (GroovyObject)getDelegate();
final GPathResult thisObject = (GPathResult)getThisObject();
Node node = (Node)thisObject.getAt(0);
List children = node.children();
for (Object child : children) {
delegate.getProperty("mkp");
if (child instanceof Node) {
delegate.invokeMethod("yield", new Object[]{new NodeChild((Node) child, thisObject, "*", null)});
} else {
delegate.invokeMethod("yield", new Object[]{child});
}
}
}
