public void visitClassExpression(ClassExpression expression) ClassNode type = expression.getType();
MethodVisitor mv = controller.getMethodVisitor();
if (BytecodeHelper.isClassLiteralPossible(type) || BytecodeHelper.isSameCompilationUnit(controller.getClassNode(), type)) {
if (controller.getClassNode().isInterface()) {
InterfaceHelperClassNode interfaceClassLoadingClass = controller.getInterfaceClassLoadingClass();
if (BytecodeHelper.isClassLiteralPossible(interfaceClassLoadingClass)) {
BytecodeHelper.visitClassLiteral(mv, interfaceClassLoadingClass);
controller.getOperandStack().push(ClassHelper.CLASS_Type);
return;
}
} else {
BytecodeHelper.visitClassLiteral(mv, type);
controller.getOperandStack().push(ClassHelper.CLASS_Type);
return;
}
}
String staticFieldName = getStaticFieldName(type);
referencedClasses.put(staticFieldName, type);
String internalClassName = controller.getInternalClassName();
if (controller.getClassNode().isInterface()) {
internalClassName = BytecodeHelper.getClassInternalName(controller.getInterfaceClassLoadingClass());
mv.visitFieldInsn(GETSTATIC, internalClassName, staticFieldName, "Ljava/lang/Class;");
} else {
mv.visitMethodInsn(INVOKESTATIC, internalClassName, "$get$" + staticFieldName, "()Ljava/lang/Class;", false);
}
controller.getOperandStack().push(ClassHelper.CLASS_Type);

public static boolean isNumberOrArrayOfNumber(ClassNode targetType, boolean recurse) if (targetType == null) return false;
return targetType.isDerivedFrom(ClassHelper.Number_TYPE) ||
(targetType.isArray() && recurse
? isNumberOrArrayOfNumber(targetType.getComponentType(), recurse)
: targetType.isArray() && targetType.getComponentType().isDerivedFrom(ClassHelper.Number_TYPE));

private boolean setField(PropertyExpression expression, Expression objectExpression, ClassNode rType, String name) if (expression.isSafe()) return false;
FieldNode fn = AsmClassGenerator.getDeclaredFieldOfCurrentClassOrAccessibleFieldOfSuper(controller.getClassNode(), rType, name, false);
if (fn==null) return false;
OperandStack stack = controller.getOperandStack();
stack.doGroovyCast(fn.getType());
MethodVisitor mv = controller.getMethodVisitor();
String ownerName = BytecodeHelper.getClassInternalName(fn.getOwner());
if (!fn.isStatic()) {
controller.getCompileStack().pushLHS(false);
objectExpression.visit(controller.getAcg());
controller.getCompileStack().popLHS();
if (!rType.equals(stack.getTopOperand())) {
BytecodeHelper.doCast(mv, rType);
stack.replace(rType);
}
stack.swap();
mv.visitFieldInsn(PUTFIELD, ownerName, name, BytecodeHelper.getTypeDescription(fn.getType()));
stack.remove(1);
} else {
mv.visitFieldInsn(PUTSTATIC, ownerName, name, BytecodeHelper.getTypeDescription(fn.getType()));
}
return true;

public static boolean implementsInterfaceOrSubclassOf(final ClassNode source, final ClassNode targetType) if (source.isDerivedFrom(targetType) || source.implementsInterface(targetType)) return true;
if (targetType instanceof WideningCategories.LowestUpperBoundClassNode) {
WideningCategories.LowestUpperBoundClassNode lub = (WideningCategories.LowestUpperBoundClassNode) targetType;
if (implementsInterfaceOrSubclassOf(source, lub.getSuperClass())) return true;
for (ClassNode classNode : lub.getInterfaces()) {
if (source.implementsInterface(classNode)) return true;
}
}
return false;

public void dup() ClassNode type = getTopOperand();
stack.add(type);
MethodVisitor mv = controller.getMethodVisitor();
if (type == ClassHelper.double_TYPE || type == ClassHelper.long_TYPE) {
mv.visitInsn(DUP2);
} else {
mv.visitInsn(DUP);
}

public static boolean isTypeOrArrayOfType(ClassNode targetType, ClassNode type, boolean recurse) if (targetType == null) return false;
return type.equals(targetType) ||
(targetType.isArray() && recurse
? isTypeOrArrayOfType(targetType.getComponentType(), type, recurse)
: type.equals(targetType.getComponentType()));

protected void loadArguments(List<Expression> argumentList, Parameter[] para) if (para.length==0) return;
ClassNode lastParaType = para[para.length - 1].getOriginType();
AsmClassGenerator acg = controller.getAcg();
OperandStack operandStack = controller.getOperandStack();
if (lastParaType.isArray()
&& (argumentList.size()>para.length || argumentList.size()==para.length-1 || !lastIsArray(argumentList, para.length-1))) {
int stackLen = operandStack.getStackLength()+argumentList.size();
MethodVisitor mv = controller.getMethodVisitor();
controller.setMethodVisitor(mv);
for (int i = 0; i < para.length-1; i++) {
argumentList.get(i).visit(acg);
operandStack.doGroovyCast(para[i].getType());
}
List<Expression> lastParams = new LinkedList<Expression>();
for (int i=para.length-1; i<argumentList.size();i++) {
lastParams.add(argumentList.get(i));
}
ArrayExpression array = new ArrayExpression(
lastParaType.getComponentType(),
lastParams
);
array.visit(acg);
while (operandStack.getStackLength()<stackLen) {
operandStack.push(ClassHelper.OBJECT_TYPE);
}
if (argumentList.size()==para.length-1) {
operandStack.remove(1);
}
} else {
for (int i = 0; i < argumentList.size(); i++) {
argumentList.get(i).visit(acg);
operandStack.doGroovyCast(para[i].getType());
}
}

public void pushConstant(ConstantExpression expression) MethodVisitor mv = controller.getMethodVisitor();
Object value = expression.getValue();
ClassNode origType = expression.getType().redirect();
ClassNode type = ClassHelper.getUnwrapper(origType);
boolean boxing = origType!=type;
boolean asPrimitive = boxing || ClassHelper.isPrimitiveType(type);
if (value == null) {
mv.visitInsn(ACONST_NULL);
} else if (boxing && value instanceof Boolean) {
Boolean bool = (Boolean) value;
String text = bool ? "TRUE" : "FALSE";
mv.visitFieldInsn(GETSTATIC, "java/lang/Boolean", text, "Ljava/lang/Boolean;");
boxing = false;
type = origType;
} else if (asPrimitive) {
pushPrimitiveConstant(mv, value, type);
} else if (value instanceof BigDecimal) {
newInstance(mv, value);
} else if (value instanceof BigInteger) {
newInstance(mv, value);
} else if (value instanceof String) {
mv.visitLdcInsn(value);
} else {
throw new ClassGeneratorException(
"Cannot generate bytecode for constant: " + value + " of type: " + type.getName());
}
push(type);
if (boxing) box();

public void swap() MethodVisitor mv = controller.getMethodVisitor();
int size = stack.size();
ClassNode b = stack.get(size-1);
ClassNode a = stack.get(size-2);
if (isTwoSlotType(a)) {
if (isTwoSlotType(b)) {
mv.visitInsn(DUP2_X2);
mv.visitInsn(POP2);
} else {
mv.visitInsn(DUP_X2);
mv.visitInsn(POP);
}
} else {
if (isTwoSlotType(b)) {
mv.visitInsn(DUP2_X1);
mv.visitInsn(POP2);
} else {
mv.visitInsn(SWAP);
}
}
stack.set(size-1,a);
stack.set(size-2,b);

public static void convertPrimitiveToBoolean(MethodVisitor mv, ClassNode type) if (type == boolean_TYPE) {
return;
}
if (type == double_TYPE) {
convertDoubleToBoolean(mv);
return;
} else if (type == float_TYPE) {
convertFloatToBoolean(mv);
return;
}
Label trueLabel = new Label();
Label falseLabel = new Label();
if (type== long_TYPE) {
mv.visitInsn(LCONST_0);
mv.visitInsn(LCMP);
}
mv.visitJumpInsn(IFEQ, falseLabel);
mv.visitInsn(ICONST_1);
mv.visitJumpInsn(GOTO, trueLabel);
mv.visitLabel(falseLabel);
mv.visitInsn(ICONST_0);
mv.visitLabel(trueLabel);

