LOG.debug("Unable to allocate socket on port", e);
} else {
LOG.info("Unable to allocate on port {}, due to error: {}", port, e.getMessage());
}
}
}
return null;

@Override public void close() throws Exception try {
if (outputStream != null) {
outputStream.flush();
outputStream.close();
}
if (client != null) {
client.close();
}
}
catch (Exception e) {
throw new IOException("Error while closing connection that streams data back to client at "
+ hostIp.toString() + ":" + port, e);
}
finally {
if (client != null) {
try {
client.close();
}
catch (Throwable t) {
}
}
}

