private ObjectNode convertRow(ObjectNode reuse, RowTypeInfo info, Row row) if (reuse == null) {
reuse = mapper.createObjectNode();
}
final String[] fieldNames = info.getFieldNames();
final TypeInformation<?>[] fieldTypes = info.getFieldTypes();
if (row.getArity() != fieldNames.length) {
throw new IllegalStateException(String.format(
"Number of elements in the row '%s' is different from number of field names: %d", row, fieldNames.length));
}
for (int i = 0; i < fieldNames.length; i++) {
final String name = fieldNames[i];
final JsonNode fieldConverted = convert(reuse, reuse.get(name), fieldTypes[i], row.getField(i));
reuse.set(name, fieldConverted);
}
return reuse;

private static <E> TypeInformation<?>[] extractTypeInfos(PojoTypeInfo<E> pojoTypeInfo, String[] fieldNames) Preconditions.checkNotNull(pojoTypeInfo);
Preconditions.checkNotNull(fieldNames);
Preconditions.checkArgument(pojoTypeInfo.getArity() >= fieldNames.length);
TypeInformation<?>[] fieldTypes = new TypeInformation<?>[fieldNames.length];
for (int i = 0; i < fieldNames.length; ++i) {
String fieldName = fieldNames[i];
Preconditions.checkNotNull(fieldName, "The field can't be null");
int fieldPos = pojoTypeInfo.getFieldIndex(fieldName);
Preconditions.checkArgument(fieldPos >= 0,
String.format("Field %s is not a member of POJO type %s",
fieldName, pojoTypeInfo.getTypeClass().getName()));
fieldTypes[i] = pojoTypeInfo.getTypeAt(fieldPos);
}
return fieldTypes;

public static CsvSchema convert(RowTypeInfo rowType) final Builder builder = new CsvSchema.Builder();
final String[] fields = rowType.getFieldNames();
final TypeInformation<?>[] types = rowType.getFieldTypes();
for (int i = 0; i < rowType.getArity(); i++) {
builder.addColumn(new Column(i, fields[i], convertType(fields[i], types[i])));
}
return builder.build();

private MessageType getReadSchema(MessageType fileSchema, Path filePath) RowTypeInfo fileTypeInfo = (RowTypeInfo) ParquetSchemaConverter.fromParquetType(fileSchema);
List<Type> types = new ArrayList<>();
for (int i = 0; i < fieldNames.length; ++i) {
String readFieldName = fieldNames[i];
TypeInformation<?> readFieldType = fieldTypes[i];
if (fileTypeInfo.getFieldIndex(readFieldName) < 0) {
if (!skipWrongSchemaFileSplit) {
throw new IllegalArgumentException("Field " + readFieldName + " cannot be found in schema of "
+ " Parquet file: " + filePath + ".");
} else {
this.skipThisSplit = true;
return fileSchema;
}
}
if (!readFieldType.equals(fileTypeInfo.getTypeAt(readFieldName))) {
if (!skipWrongSchemaFileSplit) {
throw new IllegalArgumentException("Expecting type " + readFieldType + " for field " + readFieldName
+ " but found type " + fileTypeInfo.getTypeAt(readFieldName) + " in Parquet file: "
+ filePath + ".");
} else {
this.skipThisSplit = true;
return fileSchema;
}
}
types.add(fileSchema.getType(readFieldName));
}
return new MessageType(fileSchema.getName(), types);

public static BaseRowKeySelector getBaseRowSelector(int[] keyFields, BaseRowTypeInfo rowType) if (keyFields.length > 0) {
InternalType[] inputFieldTypes = rowType.getInternalTypes();
String[] inputFieldNames = rowType.getFieldNames();
InternalType[] keyFieldTypes = new InternalType[keyFields.length];
String[] keyFieldNames = new String[keyFields.length];
for (int i = 0; i < keyFields.length; ++i) {
keyFieldTypes[i] = inputFieldTypes[keyFields[i]];
keyFieldNames[i] = inputFieldNames[keyFields[i]];
}
RowType returnType = new RowType(keyFieldTypes, keyFieldNames);
RowType inputType = new RowType(inputFieldTypes, rowType.getFieldNames());
GeneratedProjection generatedProjection = ProjectionCodeGenerator.generateProjection(
CodeGeneratorContext.apply(new TableConfig()),
"KeyProjection",
inputType,
returnType, keyFields);
BaseRowTypeInfo keyRowType = returnType.toTypeInfo();
TypeCheckUtils.validateEqualsHashCode("grouping", keyRowType);
return new BinaryRowKeySelector(keyRowType, generatedProjection);
} else {
return NullBinaryRowKeySelector.INSTANCE;
}

