public boolean equalType(HttpMessage msg) boolean result = false;
if (!this.getRequestHeader().getMethod().equalsIgnoreCase(msg.getRequestHeader().getMethod())) {
return false;
}
URI uri1 = this.getRequestHeader().getURI();
URI uri2 = msg.getRequestHeader().getURI();
try {
if (uri1.getHost() == null || uri2.getHost() == null || !uri1.getHost().equalsIgnoreCase(uri2.getHost())) {
return false;
}
if (uri1.getPort() != uri2.getPort()) {
return false;
}
String path1 = uri1.getPath();
String path2 = uri2.getPath();
if (path1 == null && path2 == null) {
return true;
}
if (path1 != null && path2 != null && !path1.equalsIgnoreCase(path2)) {
return false;
} else {
if (path1 == null || path2 == null) {
return false;
}
}
if (!queryEquals(msg)) {
return false;
}
result = true;
} catch (URIException e) {
log.error(e.getMessage(), e);
}
return result;

public double computeFirstCover(boolean leaf) double max = 0.;
for(DistanceEntry<E> e : firstAssignments) {
double cover = leaf ? e.getDistance() : (e.getEntry().getCoveringRadius() + e.getDistance());
max = cover > max ? cover : max;
}
return max;

public double coveringRadiusFromEntries(DBID routingObjectID, AbstractMTree<O, N, E, ?> mTree) double coveringRadius = 0.;
for(int i = 0; i < getNumEntries(); i++) {
E entry = getEntry(i);
final double cover = entry.getParentDistance() + entry.getCoveringRadius();
coveringRadius = coveringRadius < cover ? cover : coveringRadius;
}
return coveringRadius;

@Override public Assignments<E> split(AbstractMTree<?, N, E, ?> tree, N node) final int n = node.getNumEntries();
double[][] distanceMatrix = computeDistanceMatrix(tree, node);
double miSumCR = Double.POSITIVE_INFINITY;
boolean leaf = node.isLeaf();
Assignments<E> bestAssignment = null;
for(int i = 0; i < n; i++) {
for(int j = i + 1; j < n; j++) {
Assignments<E> currentAssignments = distributor.distribute(node, i, distanceMatrix[i], j, distanceMatrix[j]);
double maxCR = Math.max(currentAssignments.computeFirstCover(leaf), currentAssignments.computeSecondCover(leaf));
if(maxCR < miSumCR) {
miSumCR = maxCR;
bestAssignment = currentAssignments;
}
}
}
return bestAssignment;

private void adjustTree(IndexTreePath<E> subtree) final Logging log = getLogger();
if(log.isDebugging()) {
log.debugFine("Adjust tree " + subtree + "\n");
}
int nodeIndex = subtree.getIndex();
N node = getNode(subtree.getEntry());
if(hasOverflow(node)) {
Assignments<E> assignments = settings.splitStrategy.split(this, node);
final N newNode = node.isLeaf() ? createNewLeafNode() : createNewDirectoryNode();
List<E> entries1 = new ArrayList<>(assignments.getFirstAssignments().size());
List<E> entries2 = new ArrayList<>(assignments.getSecondAssignments().size());
for(DistanceEntry<E> ent : assignments.getFirstAssignments()) {
final E e = ent.getEntry();
e.setParentDistance(ent.getDistance());
entries1.add(e);
}
for(DistanceEntry<E> ent : assignments.getSecondAssignments()) {
final E e = ent.getEntry();
e.setParentDistance(ent.getDistance());
entries2.add(e);
}
node.splitTo(newNode, entries1, entries2);
writeNode(node);
writeNode(newNode);
if(log.isDebuggingFine()) {
log.debugFine(new StringBuilder(1000)
.append("Split Node ").append(node.getPageID()).append(" (").append(this.getClass()).append(')').append(FormatUtil.NEWLINE)
.append("      newNode ").append(newNode.getPageID()).append(FormatUtil.NEWLINE)
.append("      firstPromoted ").append(assignments.getFirstRoutingObject()).append(FormatUtil.NEWLINE)
.append("      firstAssignments(").append(node.getPageID()).append(") ").append(assignments.getFirstAssignments()).append(FormatUtil.NEWLINE)
.append("      firstCR ").append(assignments.computeFirstCover(node.isLeaf())).append(FormatUtil.NEWLINE)
.append("      secondPromoted ").append(assignments.getSecondRoutingObject()).append(FormatUtil.NEWLINE)
.append("      secondAssignments(").append(newNode.getPageID()).append(") ").append(assignments.getSecondAssignments()).append(FormatUtil.NEWLINE)
.append("      secondCR ").append(assignments.computeSecondCover(node.isLeaf())).append(FormatUtil.NEWLINE));
}
if(isRoot(node)) {
IndexTreePath<E> newRootPath = createNewRoot(node, newNode, assignments.getFirstRoutingObject(), assignments.getSecondRoutingObject());
adjustTree(newRootPath);
}
else {
E parentEntry = subtree.getParentPath().getEntry();
N parent = getNode(parentEntry);
if(log.isDebugging()) {
log.debugFine("parent " + parent);
}
double parentDistance2 = distance(parentEntry.getRoutingObjectID(), assignments.getSecondRoutingObject());
parent.addDirectoryEntry(createNewDirectoryEntry(newNode, assignments.getSecondRoutingObject(), parentDistance2));
double parentDistance1 = distance(parentEntry.getRoutingObjectID(), assignments.getFirstRoutingObject());
node.adjustEntry(parent.getEntry(nodeIndex), assignments.getFirstRoutingObject(), parentDistance1, this);
writeNode(parent);
adjustTree(subtree.getParentPath());
}
}
else {
if(!isRoot(node)) {
E parentEntry = subtree.getParentPath().getEntry();
N parent = getNode(parentEntry);
E entry = parent.getEntry(subtree.getIndex());
boolean changed = node.adjustEntry(entry, entry.getRoutingObjectID(), entry.getParentDistance(), this);
if(changed) {
writeNode(parent);
adjustTree(subtree.getParentPath());
}
}
else {
E rootEntry = getRootEntry();
node.adjustEntry(rootEntry, rootEntry.getRoutingObjectID(), rootEntry.getParentDistance(), this);
}
}

protected ApproximationLine progressiveKnnDistanceApproximation(int k_max) if(!isLeaf()) {
throw new UnsupportedOperationException("Progressive KNN-distance approximation " + "is only vailable in leaf nodes!");
}
int k_0 = 0;
double y_1 = Double.POSITIVE_INFINITY;
double y_kmax = Double.POSITIVE_INFINITY;
for(int i = 0; i < getNumEntries(); i++) {
MkCoPLeafEntry entry = (MkCoPLeafEntry) getEntry(i);
ApproximationLine approx = entry.getProgressiveKnnDistanceApproximation();
k_0 = Math.max(approx.getK_0(), k_0);
}
for(int i = 0; i < getNumEntries(); i++) {
MkCoPLeafEntry entry = (MkCoPLeafEntry) getEntry(i);
ApproximationLine approx = entry.getProgressiveKnnDistanceApproximation();
y_1 = Math.min(approx.getValueAt(k_0), y_1);
y_kmax = Math.min(approx.getValueAt(k_max), y_kmax);
}
double m = (y_kmax - y_1) / (FastMath.log(k_max) - FastMath.log(k_0));
double t = y_1 - m * FastMath.log(k_0);
return new ApproximationLine(k_0, m, t);

@SuppressWarnings("unchecked") public final void integrityCheck(AbstractMTree<O, N, E, ?> mTree, E entry) if(isLeaf()) {
for(int i = 0; i < getCapacity(); i++) {
E e = getEntry(i);
if(i < getNumEntries() && e == null) {
throw new InconsistentDataException("i < numEntries && entry == null");
}
if(i >= getNumEntries() && e != null) {
throw new InconsistentDataException("i >= numEntries && entry != null");
}
}
}
else {
N tmp = mTree.getNode(getEntry(0));
boolean childIsLeaf = tmp.isLeaf();
for(int i = 0; i < getCapacity(); i++) {
E e = getEntry(i);
if(i < getNumEntries() && e == null) {
throw new InconsistentDataException("i < numEntries && entry == null");
}
if(i >= getNumEntries() && e != null) {
throw new InconsistentDataException("i >= numEntries && entry != null");
}
if(e != null) {
N node = mTree.getNode(e);
if(childIsLeaf && !node.isLeaf()) {
for(int k = 0; k < getNumEntries(); k++) {
mTree.getNode(getEntry(k));
}
throw new InconsistentDataException("Wrong Child in " + this + " at " + i);
}
if(!childIsLeaf && node.isLeaf()) {
throw new InconsistentDataException("Wrong Child: child id no leaf, but node is leaf!");
}
node.integrityCheckParameters(entry, (N) this, i, mTree);
node.integrityCheck(mTree, e);
}
}
if(LoggingConfiguration.DEBUG) {
Logger.getLogger(this.getClass().getName()).fine("DirNode " + getPageID() + " ok!");
}
}

@SuppressWarnings("unchecked") public final void integrityCheck(AbstractRStarTree<N, E, ?> tree) if(isLeaf()) {
for(int i = 0; i < getCapacity(); i++) {
E e = getEntry(i);
if(i < getNumEntries() && e == null) {
throw new RuntimeException("i < numEntries && entry == null");
}
if(i >= getNumEntries() && e != null) {
throw new RuntimeException("i >= numEntries && entry != null");
}
}
}
else {
N tmp = tree.getNode(getEntry(0));
boolean childIsLeaf = tmp.isLeaf();
for(int i = 0; i < getCapacity(); i++) {
E e = getEntry(i);
if(i < getNumEntries() && e == null) {
throw new RuntimeException("i < numEntries && entry == null");
}
if(i >= getNumEntries() && e != null) {
throw new RuntimeException("i >= numEntries && entry != null");
}
if(e != null) {
N node = tree.getNode(e);
if(childIsLeaf && !node.isLeaf()) {
for(int k = 0; k < getNumEntries(); k++) {
tree.getNode(getEntry(k));
}
throw new RuntimeException("Wrong Child in " + this + " at " + i);
}
if(!childIsLeaf && node.isLeaf()) {
throw new RuntimeException("Wrong Child: child id no leaf, but node is leaf!");
}
node.integrityCheckParameters((N) this, i);
node.integrityCheck(tree);
}
}
if(LoggingConfiguration.DEBUG) {
Logger.getLogger(this.getClass().getName()).fine("DirNode " + getPageID() + " ok!");
}
}

private void tql2() System.arraycopy(e, 1, e, 0, n - 1);
e[n - 1] = 0.;
double f = 0., tst1 = 0.;
for(int l = 0; l < n; l++) {
tst1 = max(tst1, abs(d[l]) + abs(e[l]));
int m = l;
for(; m < n; ++m) {
if(abs(e[m]) <= 0x1P-52 * tst1) {
break;
}
}
if(m > l) {
do {
f += tql2ComputeImplicitShift(l);
tql2ImplicitQL(l, m, d[l + 1]);
}
while(abs(e[l]) > 0x1P-52 * tst1);
}
d[l] += f;
e[l] = 0.;
}

protected void deletePath(IndexTreePath<E> deletionPath) N leaf = getNode(deletionPath.getParentPath().getEntry());
int index = deletionPath.getIndex();
E entry = leaf.getEntry(index);
leaf.deleteEntry(index);
writeNode(leaf);
Stack<N> stack = new Stack<>();
condenseTree(deletionPath.getParentPath(), stack);
while(!stack.empty()) {
N node = stack.pop();
if(node.isLeaf()) {
for(int i = 0; i < node.getNumEntries(); i++) {
settings.getOverflowTreatment().reinitialize();
this.insertLeafEntry(node.getEntry(i));
}
}
else {
for(int i = 0; i < node.getNumEntries(); i++) {
stack.push(getNode(node.getEntry(i)));
}
}
deleteNode(node);
}
postDelete(entry);
doExtraIntegrityChecks();

