public static Point3d[] zmatrixToCartesian(double[] distances, int[] first_atoms, double[] angles, int[] second_atoms, double[] dihedrals, int[] third_atoms) Point3d[] cartesianCoords = new Point3d[distances.length];
for (int index = 0; index < distances.length; index++) {
if (index == 0) {
cartesianCoords[index] = new Point3d(0d, 0d, 0d);
} else if (index == 1) {
cartesianCoords[index] = new Point3d(distances[1], 0d, 0d);
} else if (index == 2) {
cartesianCoords[index] = new Point3d(-Math.cos((angles[2] / 180) * Math.PI) * distances[2]
+ distances[1], Math.sin((angles[2] / 180) * Math.PI) * distances[2], 0d);
if (first_atoms[index] == 0) cartesianCoords[index].x = (cartesianCoords[index].x - distances[1]) * -1;
} else {
Vector3d cd = new Vector3d();
cd.sub(cartesianCoords[third_atoms[index]], cartesianCoords[second_atoms[index]]);
Vector3d bc = new Vector3d();
bc.sub(cartesianCoords[second_atoms[index]], cartesianCoords[first_atoms[index]]);
Vector3d n1 = new Vector3d();
n1.cross(cd, bc);
Vector3d n2 = rotate(n1, bc, -dihedrals[index]);
Vector3d ba = rotate(bc, n2, -angles[index]);
ba.normalize();
ba.scale(distances[index]);
Point3d result = new Point3d();
result.add(cartesianCoords[first_atoms[index]], ba);
cartesianCoords[index] = result;
}
}
return cartesianCoords;

@Override public Color getAtomColor(IAtom atom, Color defaultColor) Color color = defaultColor;
if (atom.getCharge() == null) return defaultColor;
double charge = atom.getCharge();
if (charge > 0.0) {
if (charge < 1.0) {
int index = 255 - (int) (charge * 255.0);
color = new Color(index, index, 255);
} else {
color = Color.blue;
}
} else if (charge < 0.0) {
if (charge > -1.0) {
int index = 255 + (int) (charge * 255.0);
color = new Color(255, index, index);
} else {
color = Color.red;
}
}
return color;

@Override public ICountFingerprint getCountFingerprint(IAtomContainer atomContainer) throws CDKException if (keys.isEmpty()) {
throw new CDKException("No substructures were defined");
}
SmartsPattern.prepare(atomContainer);
final Map<Integer, Integer> map = new TreeMap<Integer, Integer>();
for (int i = 0; i < keys.size(); i++) {
Pattern ptrn = keys.get(i).pattern;
map.put(i,
ptrn.matchAll(atomContainer)
.countUnique());
}
final int length = keys.size();
final int size = map.size();
final int[] hash = new int[size], count = new int[size];
int n = 0;
for (int h : map.keySet()) {
hash[n] = h;
count[n++] = map.get(h);
}
return new ICountFingerprint() {
@Override
public long size() { return length; }
@Override
public int numOfPopulatedbins() { return size; }
@Override
public int getCount(int index) { return count[index]; }
@Override
public int getHash(int index) { return hash[index]; }
@Override
public void merge(ICountFingerprint fp) {}
@Override
public void setBehaveAsBitFingerprint(boolean behaveAsBitFingerprint) {}
@Override
public boolean hasHash(int hash) { return map.containsKey(hash); }
@Override
public int getCountForHash(int hash) { return map.get(hash); }
};

