public MigrationInfo setActiveMigration(MigrationInfo migrationInfo) partitionServiceLock.lock();
try {
if (activeMigrationInfo == null) {
activeMigrationInfo = migrationInfo;
return null;
}
if (!activeMigrationInfo.equals(migrationInfo)) {
if (logger.isFineEnabled()) {
logger.fine("Active migration is not set: " + migrationInfo
+ ". Existing active migration: " + activeMigrationInfo);
}
}
return activeMigrationInfo;
} finally {
partitionServiceLock.unlock();
}

void finalizeMigration(MigrationInfo migrationInfo) try {
PartitionReplica localReplica = PartitionReplica.from(node.getLocalMember());
int partitionId = migrationInfo.getPartitionId();
boolean source = localReplica.equals(migrationInfo.getSource());
boolean destination = localReplica.equals(migrationInfo.getDestination());
assert migrationInfo.getStatus() == MigrationStatus.SUCCESS
|| migrationInfo.getStatus() == MigrationStatus.FAILED : "Invalid migration: " + migrationInfo;
if (source || destination) {
boolean success = migrationInfo.getStatus() == MigrationStatus.SUCCESS;
MigrationParticipant participant = source ? MigrationParticipant.SOURCE : MigrationParticipant.DESTINATION;
if (success) {
internalMigrationListener.onMigrationCommit(participant, migrationInfo);
} else {
internalMigrationListener.onMigrationRollback(participant, migrationInfo);
}
MigrationEndpoint endpoint = source ? MigrationEndpoint.SOURCE : MigrationEndpoint.DESTINATION;
FinalizeMigrationOperation op = new FinalizeMigrationOperation(migrationInfo, endpoint, success);
op.setPartitionId(partitionId).setNodeEngine(nodeEngine).setValidateTarget(false)
.setService(partitionService);
InternalOperationService operationService = nodeEngine.getOperationService();
if (operationService.isRunAllowed(op)) {
operationService.run(op);
} else {
operationService.execute(op);
}
removeActiveMigration(partitionId);
} else {
PartitionReplica partitionOwner = partitionStateManager.getPartitionImpl(partitionId).getOwnerReplicaOrNull();
if (localReplica.equals(partitionOwner)) {
removeActiveMigration(partitionId);
partitionStateManager.clearMigratingFlag(partitionId);
} else {
logger.severe("Failed to finalize migration because " + localReplica
+ " is not a participant of the migration: " + migrationInfo);
}
}
} catch (Exception e) {
logger.warning(e);
} finally {
migrationInfo.doneProcessing();
}

private void verifyMigrationParticipant() Member localMember = getNodeEngine().getLocalMember();
if (getMigrationParticipantType() == MigrationParticipant.SOURCE) {
if (migrationInfo.getSourceCurrentReplicaIndex() == 0
&& !migrationInfo.getSource().isIdentical(localMember)) {
throw new IllegalStateException(localMember
+ " is the migration source but has a different identity! Migration: " + migrationInfo);
}
verifyPartitionOwner();
verifyExistingDestination();
} else if (getMigrationParticipantType() == MigrationParticipant.DESTINATION) {
if (!migrationInfo.getDestination().isIdentical(localMember)) {
throw new IllegalStateException(localMember
+ " is the migration destination but has a different identity! Migration: " + migrationInfo);
}
}

boolean addCompletedMigration(MigrationInfo migrationInfo) if (migrationInfo.getStatus() != MigrationStatus.SUCCESS
&& migrationInfo.getStatus() != MigrationStatus.FAILED) {
throw new IllegalArgumentException("Migration doesn't seem completed: " + migrationInfo);
}
if (migrationInfo.getInitialPartitionVersion() <= 0 || migrationInfo.getPartitionVersionIncrement() <= 0) {
throw new IllegalArgumentException("Partition state versions are not set: " + migrationInfo);
}
partitionServiceLock.lock();
try {
boolean added = completedMigrations.add(migrationInfo);
if (added) {
stats.incrementCompletedMigrations();
}
return added;
} finally {
partitionServiceLock.unlock();
}

public void onPartitionMigrate(MigrationInfo migrationInfo) if (migrationInfo.getSource() == null || !migrationInfo.getSource().isIdentical(nodeEngine.getLocalMember())) {
return;
}
for (WaitSet waitSet : waitSetMap.values()) {
waitSet.onPartitionMigrate(migrationInfo);
}

void applyMigration(InternalPartitionImpl partition, MigrationInfo migrationInfo) final PartitionReplica[] members = Arrays.copyOf(partition.getReplicas(), InternalPartition.MAX_REPLICA_COUNT);
if (migrationInfo.getSourceCurrentReplicaIndex() > -1) {
members[migrationInfo.getSourceCurrentReplicaIndex()] = null;
}
if (migrationInfo.getDestinationCurrentReplicaIndex() > -1) {
members[migrationInfo.getDestinationCurrentReplicaIndex()] = null;
}
members[migrationInfo.getDestinationNewReplicaIndex()] = migrationInfo.getDestination();
if (migrationInfo.getSourceNewReplicaIndex() > -1) {
members[migrationInfo.getSourceNewReplicaIndex()] = migrationInfo.getSource();
}
partition.setReplicas(members);

private boolean removeActiveMigration(int partitionId) partitionServiceLock.lock();
try {
if (activeMigrationInfo != null) {
if (activeMigrationInfo.getPartitionId() == partitionId) {
activeMigrationInfo = null;
return true;
}
if (logger.isFineEnabled()) {
logger.fine("Active migration is not removed, because it has different partitionId! "
+ "partitionId=" + partitionId + ", active migration=" + activeMigrationInfo);
}
}
} finally {
partitionServiceLock.unlock();
}
return false;

PartitionRuntimeState createMigrationCommitPartitionState(MigrationInfo migrationInfo) lock.lock();
try {
if (!partitionStateManager.isInitialized()) {
return null;
}
List<MigrationInfo> completedMigrations = migrationManager.getCompletedMigrationsCopy();
InternalPartition[] partitions = partitionStateManager.getPartitionsCopy();
int partitionId = migrationInfo.getPartitionId();
InternalPartitionImpl partition = (InternalPartitionImpl) partitions[partitionId];
migrationManager.applyMigration(partition, migrationInfo);
migrationInfo.setStatus(MigrationStatus.SUCCESS);
completedMigrations.add(migrationInfo);
int committedVersion = getPartitionStateVersion() + 1;
return new PartitionRuntimeState(partitions, completedMigrations, committedVersion);
} finally {
lock.unlock();
}

void setActiveMigration() InternalPartitionServiceImpl partitionService = getService();
MigrationManager migrationManager = partitionService.getMigrationManager();
MigrationInfo currentActiveMigration = migrationManager.setActiveMigration(migrationInfo);
if (currentActiveMigration != null) {
if (migrationInfo.equals(currentActiveMigration)) {
migrationInfo = currentActiveMigration;
return;
}
throw new RetryableHazelcastException("Cannot set active migration to " + migrationInfo
+ ". Current active migration is " + currentActiveMigration);
}
PartitionStateManager partitionStateManager = partitionService.getPartitionStateManager();
if (!partitionStateManager.trySetMigratingFlag(migrationInfo.getPartitionId())) {
throw new RetryableHazelcastException("Cannot set migrating flag, "
+ "probably previous migration's finalization is not completed yet.");
}

void retainCompletedMigrations(Collection<MigrationInfo> migrations) partitionServiceLock.lock();
try {
completedMigrations.retainAll(migrations);
} finally {
partitionServiceLock.unlock();
}

int addLineToGrid(SquareNode a, SquareNode b, List<SquareNode> list) int total = 2;
while( true ) {
boolean matched = false;
int side;
for( side = 0; side < 4; side++ ) {
if( b.edges[side] != null && b.edges[side].destination(b) == a ) {
matched = true;
break;
}
}
if(!matched) {
throw new RuntimeException("BUG!");
}
side = (side+2)%4;
if( b.edges[side] == null )
break;
SquareNode c = b.edges[side].destination(b);
if (c.graph == SEARCHED )
break;
total++;
c.graph = SEARCHED;
list.add(c);
a = b;
b = c;
}
return total;

