lineCenters.b = node.center;
for (int i = 0; i < 4; i++) {
int j = (i+1)%4;
lineSide.a = target.square.get(i);
lineSide.b = target.square.get(j);
if(Intersection2D_F64.intersection(lineCenters,lineSide,dummy) != null ) {
return i;
}
}
return -1;

boolean addToRow( SquareNode n , int corner , int sign , boolean skip , List<SquareNode> row ) SquareEdge e;
while( (e = n.edges[corner]) != null ) {
if( e.a == n ) {
n = e.b;
corner = e.sideB;
} else {
n = e.a;
corner = e.sideA;
}
if( !skip ) {
if( n.graph != SquareNode.RESET_GRAPH) {
invalid = true;
return false;
}
n.graph = 0;
row.add(n);
}
skip = !skip;
sign *= -1;
corner = addOffset(corner,sign,n.square.size());
}
return true;

protected boolean checkPreconditions(List<SquareNode> cluster) for( int i = 0; i < cluster.size(); i++ ) {
SquareNode n = cluster.get(i);
for (int j = 0; j < n.square.size(); j++) {
SquareEdge e0 = n.edges[j];
if( e0 == null)
continue;
for (int k = j+1; k < n.square.size(); k++) {
SquareEdge e1 = n.edges[k];
if( e1 == null)
continue;
if( e0.destination(n) == e1.destination(n) ) {
return false;
}
}
}
}
return true;

protected static NodeInfo findClosestEdge( NodeInfo n , Point2D_F64 p ) double bestDistance = Double.MAX_VALUE;
NodeInfo best = null;
for (int i = 0; i < n.edges.size(); i++) {
Edge e = n.edges.get(i);
if( e.target.marked )
continue;
double d = e.target.ellipse.center.distance2(p);
if( d < bestDistance ) {
bestDistance = d;
best = e.target;
}
}
return best;

boolean determinePose(View target ) List<Point2D3D> list = new ArrayList<>();
List<Feature3D> features = new ArrayList<>();
GrowQueue_I32 featureIndexes = new GrowQueue_I32();
for( Motion c : target.connections ) {
boolean isSrc = c.viewSrc == target;
View other = c.destination(target);
if( other.state != ViewState.PROCESSED )
continue;
for (int i = 0; i < c.associated.size(); i++) {
AssociatedIndex a = c.associated.get(i);
Feature3D f = other.features3D[isSrc?a.dst:a.src];
if( f == null || f.mark == target.index)
continue;
f.mark = target.index;
features.add(f);
featureIndexes.add( isSrc?a.src:a.dst);
Point2D_F64 norm = target.observationNorm.get( isSrc?a.src:a.dst);
Point2D3D p = new Point2D3D();
p.location.set(f.worldPt);
p.observation.set(norm);
list.add(p);
}
}
ransacPnP.setIntrinsic(0,target.camera.pinhole);
if( list.size() < 20 || !ransacPnP.process(list) ) {
if( verbose != null )
verbose.println("   View="+target.index+" RANSAC failed. list.size="+list.size());
return false;
}
target.state = ViewState.PROCESSED;
int N = ransacPnP.getMatchSet().size();
if( verbose != null )
verbose.println("   View="+target.index+" PNP RANSAC "+N+"/"+list.size());
for (int i = 0; i < N; i++) {
int which = ransacPnP.getInputIndex(i);
Feature3D f = features.get(which);
if( f.views.contains(target))
continue;
f.views.add(target);
f.obsIdx.add(featureIndexes.get(which));
target.features3D[featureIndexes.get(which)] = f;
if( f.views.size() != f.obsIdx.size )
throw new RuntimeException("BUG!");
}
Se3_F64 worldToView = ransacPnP.getModelParameters();
target.viewToWorld.set( worldToView.invert(null) );
return true;

void addToCluster(SquareNode seed, List<SquareNode> graph) open.clear();
open.add(seed);
while( !open.isEmpty() ) {
SquareNode n = open.remove( open.size() - 1 );
for (int i = 0; i < n.square.size(); i++) {
SquareEdge edge = n.edges[i];
if( edge == null )
continue;
SquareNode other;
if( edge.a == n )
other = edge.b;
else if( edge.b == n )
other = edge.a;
else
throw new RuntimeException("BUG!");
if( other.graph == SquareNode.RESET_GRAPH) {
other.graph = n.graph;
graph.add(other);
open.add(other);
} else if( other.graph != n.graph ) {
throw new RuntimeException("BUG! "+other.graph+" "+n.graph);
}
}
}

List<SquareNode> firstRow1( SquareNode seed ) for (int i = 0; i < seed.square.size(); i++) {
if( isOpenEdge(seed,i) ) {
List<SquareNode> list = new ArrayList<>();
seed.graph = 0;
int corner = seed.edges[i].destinationSide(seed);
SquareNode dst = seed.edges[i].destination(seed);
int l = addOffset(corner,-1,dst.square.size());
int u = addOffset(corner, 1,dst.square.size());
if( dst.edges[u] != null ) {
list.add(seed);
if( !addToRow(seed,i,-1,true,list) ) return null;
} else if( dst.edges[l] != null ){
List<SquareNode> tmp = new ArrayList<>();
if( !addToRow(seed,i, 1,true,tmp) ) return null;
flipAdd(tmp, list);
list.add(seed);
} else {
list.add(seed);
}
return list;
}
}
