static QrCodeMaskPattern selectMask( QrCode qr ) int N = qr.getNumberOfModules();
int totalBytes = QrCode.VERSION_INFO[qr.version].codewords;
List<Point2D_I32> locations = QrCode.LOCATION_BITS[qr.version];
QrCodeMaskPattern bestMask = null;
double bestScore = Double.MAX_VALUE;
PackedBits8 bits = new PackedBits8();
bits.size = totalBytes * 8;
bits.data = qr.rawbits;
if (bits.size > locations.size())
throw new RuntimeException("BUG in code");
QrCodeCodeWordLocations matrix = new QrCodeCodeWordLocations(qr.version);
for (QrCodeMaskPattern mask : QrCodeMaskPattern.values()) {
double score = scoreMask(N, locations, bits, matrix, mask);
if (score < bestScore) {
bestScore = score;
bestMask = mask;
}
}
return bestMask;

private boolean readRawData( QrCode qr) QrCode.VersionInfo info = QrCode.VERSION_INFO[qr.version];
qr.rawbits = new byte[info.codewords];
bits.resize(info.codewords*8);
List<Point2D_I32> locationBits =  QrCode.LOCATION_BITS[qr.version];
for (int i = 0; i < bits.size; i++ ) {
Point2D_I32 b = locationBits.get(i);
readDataMatrix(i,b.y,b.x, qr.mask);
}
System.arraycopy(bits.data,0,qr.rawbits,0,qr.rawbits.length);
return true;

public void render( QrCode qr ) initialize(qr);
render.init();
positionPattern(0,0, qr.ppCorner);
positionPattern((numModules-7)*moduleWidth,0, qr.ppRight);
positionPattern(0,(numModules-7)*moduleWidth, qr.ppDown);
timingPattern(7*moduleWidth,6*moduleWidth,moduleWidth,0);
timingPattern(6*moduleWidth,7*moduleWidth,0,moduleWidth);
formatInformation();
if( qr.version >= QrCode.VERSION_ENCODED_AT)
versionInformation();
int alignment[] = QrCode.VERSION_INFO[qr.version].alignment;
for (int i = 0; i < alignment.length; i++) {
int row = alignment[i];
for (int j = 0; j < alignment.length; j++) {
if( i == 0 & j == 0 )
continue;
if( i == alignment.length-1 & j == 0)
continue;
if( i == 0 & j == alignment.length-1)
continue;
int col = alignment[j];
alignmentPattern(col,row);
}
}
if( renderData ) {
if( qr.rawbits.length != QrCode.VERSION_INFO[qr.version].codewords )
throw new RuntimeException("Unexpected length of raw data.");
bitLocations = new QrCodeCodeWordLocations(qr.version).bits;
int numBytes = bitLocations.size() / 8;
if (numBytes != qr.rawbits.length)
throw new RuntimeException("Egads. unexpected length of qrcode raw data");
renderData();
}
qr.bounds.set(0,0,0);
qr.bounds.set(1,markerWidth,0);
qr.bounds.set(2,markerWidth,markerWidth);
qr.bounds.set(3,0,markerWidth);

public static void computeNormalizationLL(List<List<Point2D_F64>> points, NormalizationPoint2D normalize ) double meanX = 0;
double meanY = 0;
int count = 0;
for (int i = 0; i < points.size(); i++) {
List<Point2D_F64> l = points.get(i);
for (int j = 0; j < l.size(); j++) {
Point2D_F64 p = l.get(j);
meanX += p.x;
meanY += p.y;
}
count += l.size();
}
meanX /= count;
meanY /= count;
double stdX = 0;
double stdY = 0;
for (int i = 0; i < points.size(); i++) {
List<Point2D_F64> l = points.get(i);
for (int j = 0; j < l.size(); j++) {
Point2D_F64 p = l.get(j);
double dx = p.x - meanX;
double dy = p.y - meanY;
stdX += dx*dx;
stdY += dy*dy;
}
}
normalize.meanX = meanX;
normalize.meanY = meanY;
normalize.stdX = Math.sqrt(stdX/count);
normalize.stdY = Math.sqrt(stdY/count);

protected double computeFractionBoundary( float pixelThreshold ) final int w = square.width;
int radius = (int) (w * borderWidthFraction);
int innerWidth = w-2*radius;
int total = w*w - innerWidth*innerWidth;
int count = 0;
for (int y = 0; y < radius; y++) {
int indexTop = y*w;
int indexBottom = (w - radius + y)*w;
for (int x = 0; x < w; x++) {
if( square.data[indexTop++] < pixelThreshold )
count++;
if( square.data[indexBottom++] < pixelThreshold )
count++;
}
}
for (int y = radius; y < w-radius; y++) {
int indexLeft = y*w;
int indexRight = y*w + w - radius;
for (int x = 0; x < radius; x++) {
if( square.data[indexLeft++] < pixelThreshold )
count++;
if( square.data[indexRight++] < pixelThreshold )
count++;
}
}
return count/(double)total;

