public void mapTemplates(IAtomContainer mol, int numberOfRingAtoms) throws CDKException, CloneNotSupportedException if (templates.isEmpty())
loadTemplates();
IAtomContainer                best          = null;
Map<IChemObject, IChemObject> bestMap       = null;
IAtomContainer                secondBest    = null;
Map<IChemObject, IChemObject> secondBestMap = null;
for (int i = 0; i < templates.size(); i++) {
IAtomContainer query = queries.get(i);
if (query.getAtomCount() != mol.getAtomCount()) {
continue;
}
Mappings mappings = patterns.get(i).matchAll(mol);
for (Map<IChemObject, IChemObject> map : mappings.toAtomBondMap()) {
if (isExactMatch(query, map)) {
assignCoords(query, map);
return;
} else if (query.getBondCount() == mol.getBondCount()) {
best = query;
bestMap = new HashMap<>(map);
} else {
secondBest = query;
secondBestMap = new HashMap<>(map);
}
}
}
if (best != null) {
assignCoords(best, bestMap);
} else if (secondBest != null) {
assignCoords(secondBest, secondBestMap);
} else {
logger.warn("Maybe RingTemplateError!");
}

public IAtomContainer fixAromaticBondOrders(IAtomContainer atomContainer) throws CDKException for (IBond bond : atomContainer.bonds()) {
if (bond.isAromatic() && bond.getOrder() == IBond.Order.UNSET)
bond.setOrder(IBond.Order.SINGLE);
}
IRingSet rs = allRingsFinder.findAllRings(atomContainer, 7);
storeRingSystem(atomContainer, rs);
IRingSet ringSet;
ringSet = removeExtraRings(atomContainer);
if (ringSet == null) throw new CDKException("failure in AllRingsFinder.findAllRings");
List<List<List<String>>> MasterList = new ArrayList<List<List<String>>>();
this.FixPyridineNOxides(atomContainer, ringSet);
for (int i = 0; i <= ringSet.getAtomContainerCount() - 1; i++) {
IRing ring = (IRing) ringSet.getAtomContainer(i);
if (ring.getAtomCount() == 5) {
fiveMemberedRingPossibilities(atomContainer, ring, MasterList);
} else if (ring.getAtomCount() == 6) {
sixMemberedRingPossibilities(atomContainer, ring, MasterList);
} else if (ring.getAtomCount() == 7) {
sevenMemberedRingPossibilities(atomContainer, ring, MasterList);
} else {
logger.debug("Found ring of size: " + ring.getAtomCount());
}
}
IAtomContainerSet som = atomContainer.getBuilder().newInstance(IAtomContainerSet.class);
int[] choices;
choices = new int[MasterList.size()];
if (MasterList.size() > 0) {
IAtomContainer iAtomContainer = loop(System.currentTimeMillis(), atomContainer, 0, MasterList, choices, som);
if (iAtomContainer != null) return iAtomContainer;
}
int mincount = 99999999;
int best = -1;
for (int i = 0; i <= som.getAtomContainerCount() - 1; i++) {
IAtomContainer mol = som.getAtomContainer(i);
ringSet = removeExtraRings(mol);
if (ringSet == null) continue;
int count = getBadCount(mol, ringSet);
if (count < mincount) {
mincount = count;
best = i;
}
}
if (som.getAtomContainerCount() > 0) return som.getAtomContainer(best);
return atomContainer;

@Override public int indexOf(Object o) IAtomContainer atomContainer = (IAtomContainer) o;
if (!atomContainer.getTitle().equals(title)) return -1;
if (atomContainer.getAtomCount() != this.atomContainer.getAtomCount()) return -1;
boolean coordsMatch;
int index = 0;
for (Point3d[] coords : coordinates) {
coordsMatch = true;
for (int i = 0; i < atomContainer.getAtomCount(); i++) {
Point3d p = atomContainer.getAtom(i).getPoint3d();
if (!(p.x == coords[i].x && p.y == coords[i].y && p.z == coords[i].z)) {
coordsMatch = false;
break;
}
}
if (coordsMatch) return index;
index++;
}
return -1;

@Override public IBitFingerprint getBitFingerprint(IAtomContainer atomContainer) throws CDKException if (keys.isEmpty()) {
throw new CDKException("No substructures were defined");
}
SmartsPattern.prepare(atomContainer);
BitSet fingerPrint = new BitSet(keys.size());
for (int i = 0; i < keys.size(); i++) {
if (keys.get(i).pattern.matches(atomContainer))
fingerPrint.set(i, true);
}
return new BitSetFingerprint(fingerPrint);

public static List<List<Integer>> getFragments(IAtomContainer atomContainer, QueryAtomContainer[] queries) UniversalIsomorphismTester universalIsomorphismTester = new UniversalIsomorphismTester();
List<List<Integer>> uniqueSubgraphs = new ArrayList<List<Integer>>();
for (QueryAtomContainer query : queries) {
List<List<RMap>> subgraphMaps = null;
try {
subgraphMaps = universalIsomorphismTester.getSubgraphMaps(atomContainer, query);
} catch (CDKException e) {
e.printStackTrace();
}
if (subgraphMaps == null) continue;
if (subgraphMaps.size() == 0) continue;
uniqueSubgraphs.addAll(getUniqueBondSubgraphs(subgraphMaps, atomContainer));
}
List<List<Integer>> retValue = new ArrayList<List<Integer>>();
for (List<Integer> fragment : uniqueSubgraphs) {
for (QueryAtomContainer query : queries) {
if (fragment.size() == query.getAtomCount()) {
retValue.add(fragment);
break;
}
}
}
return retValue;

