}
return new BitSetFingerprint(fingerPrint);

public double calculateGHEffectiveAtomPolarizability(IAtomContainer atomContainer, IAtom atom, int influenceSphereCutOff, boolean addExplicitH) double polarizabilitiy = 0;
IAtomContainer acH;
if (addExplicitH) {
acH = atomContainer.getBuilder().newInstance(IAtomContainer.class, atomContainer);
addExplicitHydrogens(acH);
} else {
acH = atomContainer;
}
List<IAtom> startAtom = new ArrayList<>(1);
startAtom.add(0, atom);
double bond;
polarizabilitiy += getKJPolarizabilityFactor(acH, atom);
for (int i = 0; i < acH.getAtomCount(); i++) {
if (!acH.getAtom(i).equals(atom)) {
bond = PathTools.breadthFirstTargetSearch(acH, startAtom, acH.getAtom(i), 0, influenceSphereCutOff);
if (bond == 1) {
polarizabilitiy += getKJPolarizabilityFactor(acH, acH.getAtom(i));
} else {
polarizabilitiy += (Math.pow(0.5, bond - 1) * getKJPolarizabilityFactor(acH, acH.getAtom(i)));
}
}
}
return polarizabilitiy;

private Statement transformExtendedTryWithResourcesStatement(TryCatchStatement tryCatchStatement) TryCatchStatement newTryWithResourcesStatement =
new TryCatchStatement(
tryCatchStatement.getTryStatement(),
EmptyStatement.INSTANCE);
tryCatchStatement.getResourceStatements().forEach(newTryWithResourcesStatement::addResource);
TryCatchStatement newTryCatchStatement =
new TryCatchStatement(
astBuilder.createBlockStatement(this.transform(newTryWithResourcesStatement)),
tryCatchStatement.getFinallyStatement());
tryCatchStatement.getCatchStatements().forEach(newTryCatchStatement::addCatch);
return newTryCatchStatement;

private Statement transformBasicTryWithResourcesStatement(TryCatchStatement tryCatchStatement) BlockStatement blockStatement = new BlockStatement();
ExpressionStatement firstResourceStatement =
this.makeVariableDeclarationFinal(
tryCatchStatement.getResourceStatement(0));
astBuilder.appendStatementsToBlockStatement(blockStatement, firstResourceStatement);
String primaryExcName = this.genPrimaryExcName();
VariableExpression primaryExcX = localVarX(primaryExcName, ClassHelper.make(Throwable.class));
ExpressionStatement primaryExcDeclarationStatement =
new ExpressionStatement(
new DeclarationExpression(
primaryExcX,
newSymbol(Types.ASSIGN, -1, -1),
new ConstantExpression(null)
)
);
astBuilder.appendStatementsToBlockStatement(blockStatement, primaryExcDeclarationStatement);
String firstResourceIdentifierName =
((DeclarationExpression) tryCatchStatement.getResourceStatement(0).getExpression()).getLeftExpression().getText();
TryCatchStatement newTryCatchStatement =
new TryCatchStatement(
tryCatchStatement.getTryStatement(),
this.createFinallyBlockForNewTryCatchStatement(primaryExcName, firstResourceIdentifierName));
List<ExpressionStatement> resourceStatements = tryCatchStatement.getResourceStatements();
List<ExpressionStatement> tailResourceStatements = resourceStatements.subList(1, resourceStatements.size());
tailResourceStatements.stream().forEach(newTryCatchStatement::addResource);
newTryCatchStatement.addCatch(this.createCatchBlockForOuterNewTryCatchStatement(primaryExcName));
astBuilder.appendStatementsToBlockStatement(blockStatement, this.transform(newTryCatchStatement));
return blockStatement;

private BlockStatement createFinallyBlockForNewTryCatchStatement(String primaryExcName, String firstResourceIdentifierName) BlockStatement finallyBlock = new BlockStatement();
BooleanExpression conditionExpression =
new BooleanExpression(
new BinaryExpression(
new VariableExpression(primaryExcName),
newSymbol(Types.COMPARE_NOT_EQUAL, -1, -1),
new ConstantExpression(null)));
TryCatchStatement newTryCatchStatement =
new TryCatchStatement(
astBuilder.createBlockStatement(this.createCloseResourceStatement(firstResourceIdentifierName)),
EmptyStatement.INSTANCE);
String suppressedExcName = this.genSuppressedExcName();
newTryCatchStatement.addCatch(
new CatchStatement(
new Parameter(ClassHelper.make(Throwable.class), suppressedExcName),
astBuilder.createBlockStatement(this.createAddSuppressedStatement(primaryExcName, suppressedExcName))
)
);
IfStatement ifStatement =
new IfStatement(
conditionExpression,
newTryCatchStatement,
this.createCloseResourceStatement(firstResourceIdentifierName)
);
astBuilder.appendStatementsToBlockStatement(finallyBlock, ifStatement);
return astBuilder.createBlockStatement(finallyBlock);

public void handle(ASTNode node, GroovyParser.GroovyParserRuleContext ctx) if (!(groovydocEnabled || runtimeGroovydocEnabled)) {
return;
}
if (!asBoolean(node) || !asBoolean(ctx)) {
return;
}
String docCommentNodeText = this.findDocCommentByNode(ctx);
if (null == docCommentNodeText) {
return;
}
attachDocCommentAsMetaData(node, docCommentNodeText);
attachGroovydocAnnotation(node, docCommentNodeText);

@Override public ClassNode visitType(TypeContext ctx) if (!asBoolean(ctx)) {
return ClassHelper.OBJECT_TYPE;
}
ClassNode classNode = null;
if (asBoolean(ctx.classOrInterfaceType())) {
ctx.classOrInterfaceType().putNodeMetaData(IS_INSIDE_INSTANCEOF_EXPR, ctx.getNodeMetaData(IS_INSIDE_INSTANCEOF_EXPR));
classNode = this.visitClassOrInterfaceType(ctx.classOrInterfaceType());
} else if (asBoolean(ctx.primitiveType())) {
classNode = this.visitPrimitiveType(ctx.primitiveType());
}
if (!asBoolean(classNode)) {
if (VOID_STR.equals(ctx.getText())) {
throw createParsingFailedException("void is not allowed here", ctx);
}
throw createParsingFailedException("Unsupported type: " + ctx.getText(), ctx);
}
classNode.addAnnotations(this.visitAnnotationsOpt(ctx.annotationsOpt()));
List<List<AnnotationNode>> dimList = this.visitDimsOpt(ctx.dimsOpt());
if (asBoolean(dimList)) {
classNode.setGenericsTypes(null);
classNode.setUsingGenerics(false);
classNode = this.createArrayType(classNode, dimList);
}
return configureAST(classNode, ctx);

public Object getProperty(final String property) if ("..".equals(property)) {
return parent();
} else if ("*".equals(property)) {
return children();
} else if ("**".equals(property)) {
return depthFirst();
} else if (property.startsWith("@")) {
if (property.contains(":") && !this.namespaceTagHints.isEmpty()) {
final int i = property.indexOf(":");
return new Attributes(this, "@" + property.substring(i + 1), property.substring(1, i), this.namespaceTagHints);
} else {
return new Attributes(this, property, this.namespaceTagHints);
}
} else {
if (property.contains(":") && !this.namespaceTagHints.isEmpty()) {
final int i = property.indexOf(":");
return new NodeChildren(this, property.substring(i + 1), property.substring(0, i), this.namespaceTagHints);
} else {
return new NodeChildren(this, property, this.namespaceTagHints);
}
}

public Object getProperty(String property) if (isValidExpandoProperty(property)) {
if (property.equals(STATIC_QUALIFIER)) {
return new ExpandoMetaProperty(property, true);
} else if (property.equals(CONSTRUCTOR)) {
return new ExpandoMetaConstructor();
} else {
if (myMetaClass.hasProperty(this, property) == null)
return new ExpandoMetaProperty(property);
else
return myMetaClass.getProperty(this, property);
}
} else {
return myMetaClass.getProperty(this, property);
}

@Override public Expression visitIdentifierPrmrAlt(IdentifierPrmrAltContext ctx) if (asBoolean(ctx.typeArguments())) {
ClassNode classNode = ClassHelper.make(ctx.identifier().getText());
classNode.setGenericsTypes(
this.visitTypeArguments(ctx.typeArguments()));
return configureAST(new ClassExpression(classNode), ctx);
}
return configureAST(new VariableExpression(this.visitIdentifier(ctx.identifier())), ctx);

@Override public AssertStatement visitAssertStatement(AssertStatementContext ctx) visitingAssertStatementCnt++;
Expression conditionExpression = (Expression) this.visit(ctx.ce);
if (conditionExpression instanceof BinaryExpression) {
BinaryExpression binaryExpression = (BinaryExpression) conditionExpression;
if (binaryExpression.getOperation().getType() == Types.ASSIGN) {
throw createParsingFailedException("Assignment expression is not allowed in the assert statement", conditionExpression);
}
}
BooleanExpression booleanExpression =
configureAST(
new BooleanExpression(conditionExpression), conditionExpression);
if (!asBoolean(ctx.me)) {
return configureAST(
new AssertStatement(booleanExpression), ctx);
}
AssertStatement result = configureAST(new AssertStatement(booleanExpression,
(Expression) this.visit(ctx.me)),
ctx);
visitingAssertStatementCnt--;
return result;

public Writer writeTo(final Writer out) throws IOException if (this.out!=null) {
return NullWriter.DEFAULT;
}
try {
this.out = createWriter(out);
run();
return out;
} finally {
if (this.out!=null) {
this.out.flush();
}
this.out = null;
}

public static SVGPath drawVoronoi(Projection2D proj, List<SweepHullDelaunay2D.Triangle> delaunay, List<double[]> means) final SVGPath path = new SVGPath();
CanvasSize viewport = proj.estimateViewport();
for(int i = 0; i < delaunay.size(); i++) {
SweepHullDelaunay2D.Triangle del = delaunay.get(i);
final double[] projcx = proj.fastProjectDataToRenderSpace(del.m);
if(del.ab > i) {
Triangle oth = delaunay.get(del.ab);
double[] p1 = projcx.clone(), p2 = proj.fastProjectDataToRenderSpace(oth.m);
if (viewport.clipToMargin(p1, p2)) {
path.moveTo(p1);
path.drawTo(p2);
}
}
else if(del.ab < 0) {
double[] dirv = VMath.minus(means.get(del.a), means.get(del.b));
VMath.rotate90Equals(dirv);
double[] dir = proj.fastProjectRelativeDataToRenderSpace(dirv);
final double factor = viewport.continueToMargin(projcx, dir);
if(factor > 0) {
path.moveTo(projcx);
path.relativeLineTo(factor * dir[0], factor * dir[1]);
}
}
if(del.bc > i) {
Triangle oth = delaunay.get(del.bc);
double[] p1 = projcx.clone(), p2 = proj.fastProjectDataToRenderSpace(oth.m);
if (viewport.clipToMargin(p1, p2)) {
path.moveTo(p1);
path.drawTo(p2);
}
}
else if(del.bc < 0) {
double[] dirv = VMath.minus(means.get(del.b), means.get(del.c));
VMath.rotate90Equals(dirv);
double[] dir = proj.fastProjectRelativeDataToRenderSpace(dirv);
final double factor = viewport.continueToMargin(projcx, dir);
if(factor > 0) {
path.moveTo(projcx);
path.relativeLineTo(factor * dir[0], factor * dir[1]);
}
}
if(del.ca > i) {
Triangle oth = delaunay.get(del.ca);
double[] projca = proj.fastProjectDataToRenderSpace(oth.m);
if (viewport.clipToMargin(projcx, projca)) {
path.moveTo(projcx);
path.drawTo(projca);
}
}
else if(del.ca < 0) {
double[] dirv = VMath.minus(means.get(del.c), means.get(del.a));
VMath.rotate90Equals(dirv);
double[] dir = proj.fastProjectRelativeDataToRenderSpace(dirv);
final double factor = viewport.continueToMargin(projcx, dir);
if(factor > 0) {
path.moveTo(projcx);
path.relativeLineTo(factor * dir[0], factor * dir[1]);
}
}
}
return path;

void run(boolean hullonly) if(points.size() < 3) {
throw new UnsupportedOperationException("There is no delaunay triangulation for less than three objects!");
}
int len = points.size() - 1;
hull = new LinkedList<>();
tris = hullonly ? null : new ArrayList<Triangle>(len);
final double[] seed;
final int seedid = 0;
final double[] sortd = new double[len];
final int[] sorti = new int[len];
Arrays.fill(sorti, -42);
{
Iterator<double[]> iter = points.iterator();
seed = iter.next();
for(int i = 0, j = 1; iter.hasNext(); j++, i++) {
double dist = quadraticEuclidean(seed, iter.next());
if(dist <= 0.) {
--len;
--i;
continue;
}
sortd[i] = dist;
sorti[i] = j;
}
DoubleIntegerArrayQuickSort.sort(sortd, sorti, len);
}
if(len < 2) {
hull.add(new IntIntPair(seedid, -1));
if(len == 1) {
hull.add(new IntIntPair(sorti[0], -1));
}
return;
}
assert (sortd[0] > 0);
final int seed2id = sorti[0];
Triangle besttri = findSmallest(seedid, seed2id, sortd, sorti, len);
if(besttri == null) {
hull.add(new IntIntPair(seedid, -1));
hull.add(new IntIntPair(seed2id, -1));
return;
}
int start = 2;
besttri.makeClockwise(points);
if(!hullonly) {
tris.add(besttri);
}
hull.add(new IntIntPair(besttri.a, 0));
hull.add(new IntIntPair(besttri.b, 0));
hull.add(new IntIntPair(besttri.c, 0));
if(LOG.isDebuggingFinest()) {
debugHull();
}
double[] center = besttri.m;
for(int i = start; i < len; i++) {
sortd[i] = quadraticEuclidean(center, points.get(sorti[i]));
}
DoubleIntegerArrayQuickSort.sort(sortd, sorti, start, len);
for(int i = start; i < len; i++) {
final int pointId = sorti[i];
final double[] newpoint = points.get(pointId);
LinkedList<Triangle> newtris = hullonly ? null : new LinkedList<Triangle>();
int hstart = -1, hend = -1;
{
Iterator<IntIntPair> iter = hull.descendingIterator();
IntIntPair next = hull.getFirst();
double[] nextV = points.get(next.first);
for(int pos = hull.size() - 1; iter.hasNext(); pos--) {
IntIntPair prev = iter.next();
double[] prevV = points.get(prev.first);
if(hend < 0) {
if(leftOf(prevV, nextV, newpoint)) {
hstart = hend = pos;
if(!hullonly) {
Triangle tri = new Triangle(pointId, next.first, prev.first);
assert (tri.isClockwise(points));
assert (prev.second >= 0);
tri.updateCircumcircle(points);
tri.bc = prev.second;
newtris.addFirst(tri);
}
}
}
else {
if(leftOf(prevV, nextV, newpoint)) {
hstart = pos;
if(!hullonly) {
Triangle tri = new Triangle(pointId, next.first, prev.first);
assert (tri.isClockwise(points));
assert (prev.second >= 0);
tri.updateCircumcircle(points);
tri.bc = prev.second;
newtris.addFirst(tri);
}
}
else {
break;
}
}
next = prev;
nextV = prevV;
}
}
if(hend == hull.size() - 1) {
Iterator<IntIntPair> iter = hull.iterator();
IntIntPair prev = iter.next();
double[] prevV = points.get(prev.first);
while(iter.hasNext()) {
IntIntPair next = iter.next();
double[] nextV = points.get(next.first);
if(leftOf(prevV, nextV, newpoint)) {
hend++;
if(!hullonly) {
Triangle tri = new Triangle(pointId, next.first, prev.first);
assert (tri.isClockwise(points));
assert (prev.second >= 0);
tri.updateCircumcircle(points);
tri.bc = prev.second;
newtris.addLast(tri);
}
}
else {
break;
}
prev = next;
prevV = nextV;
}
}
assert (hstart >= 0 && hend >= hstart);
final int firsttri, lasttri;
if(hullonly) {
firsttri = lasttri = -1;
}
else {
final int tristart = tris.size();
firsttri = tristart;
lasttri = tristart + newtris.size() - 1;
}
final int hullsize = hull.size();
if(LOG.isDebuggingFinest()) {
LOG.debugFinest("Size: " + hullsize + " start: " + hstart + " end: " + hend);
}
if(hend < hullsize) {
ListIterator<IntIntPair> iter = hull.listIterator();
int p = 0;
for(; p <= hstart; p++) {
iter.next();
}
for(; p <= hend; p++) {
iter.next();
iter.remove();
}
iter.add(new IntIntPair(pointId, lasttri));
iter.previous();
if(!hullonly) {
(iter.hasPrevious() ? iter.previous() : hull.getLast()).second = firsttri;
}
}
else {
ListIterator<IntIntPair> iter = hull.listIterator();
int p = hullsize;
for(; p <= hend; p++) {
iter.next();
iter.remove();
}
iter.add(new IntIntPair(pointId, lasttri));
p -= hullsize;
IntIntPair pre = null;
for(; p <= hstart; p++) {
pre = iter.next();
}
assert (pre != null);
pre.second = firsttri;
while(iter.hasNext()) {
iter.next();
iter.remove();
}
}
if(LOG.isDebuggingFinest()) {
debugHull();
}
if(!hullonly) {
final int tristart = tris.size();
Iterator<Triangle> iter = newtris.iterator();
for(int o = 0; iter.hasNext(); o++) {
Triangle cur = iter.next();
cur.ca = o > 0 ? tristart + o - 1 : -1;
cur.ab = iter.hasNext() ? tristart + o + 1 : -1;
assert (cur.bc >= 0);
Triangle other = tris.get(cur.bc);
Orientation orient = cur.findOrientation(other);
assert (orient != null) : "Inconsistent triangles: " + cur + " " + other;
switch(orient){
case ORIENT_BC_BA:
assert (other.ab == -1) : "Inconsistent triangles: " + cur + " " + other;
other.ab = tristart + o;
break;
case ORIENT_BC_CB:
assert (other.bc == -1) : "Inconsistent triangles: " + cur + " " + other;
other.bc = tristart + o;
break;
case ORIENT_BC_AC:
assert (other.ca == -1) : "Inconsistent triangles: " + cur + " " + other;
other.ca = tristart + o;
break;
default:
assert (cur.isClockwise(points));
assert (other.isClockwise(points));
throw new RuntimeException("Inconsistent triangles: " + cur + " " + other + " size:" + tris.size());
}
tris.add(cur);
}
assert (tris.size() == lasttri + 1);
}
}
if(!hullonly) {
final int size = tris.size();
long[] flippedA = BitsUtil.zero(size), flippedB = BitsUtil.zero(size);
if(flipTriangles(flippedA) > 0) {
for(int iterations = 1; iterations < 1000; iterations += 2) {
if(LOG.isDebuggingFinest()) {
debugHull();
}
if(flipTriangles(flippedA, flippedB) == 0) {
break;
}
if(LOG.isDebuggingFinest()) {
debugHull();
}
if(flipTriangles(flippedB, flippedA) == 0) {
break;
}
}
}
}

protected double computeDensity(DoubleDBIDList referenceDists, DoubleDBIDListIter iter, int index) final int size = referenceDists.size();
final double xDist = iter.seek(index).doubleValue();
int lef = index, rig = index;
double sum = 0.;
double lef_d = (--lef >= 0) ? xDist - iter.seek(lef).doubleValue() : Double.POSITIVE_INFINITY;
double rig_d = (++rig < size) ? iter.seek(rig).doubleValue() - xDist : Double.POSITIVE_INFINITY;
for(int i = 0; i < k; ++i) {
if(lef >= 0 && rig < size) {
if(lef_d < rig_d) {
sum += lef_d;
lef_d = (--lef >= 0) ? xDist - iter.seek(lef).doubleValue() : Double.POSITIVE_INFINITY;
}
else {
sum += rig_d;
rig_d = (++rig < size) ? iter.seek(rig).doubleValue() - xDist : Double.POSITIVE_INFINITY;
}
}
else if(lef >= 0) {
sum += lef_d;
lef_d = (--lef >= 0) ? xDist - iter.seek(lef).doubleValue() : Double.POSITIVE_INFINITY;
}
else if(rig < size) {
sum += rig_d;
rig_d = (++rig < size) ? iter.seek(rig).doubleValue() - xDist : Double.POSITIVE_INFINITY;
}
else {
throw new IndexOutOfBoundsException("Less than k objects?");
}
}
return k / sum;

protected N buildTree(int[] msg, int cur, int parent, ArrayList<N> nodes) int c = 0;
for(int i = 1; i < msg.length; i += 2) {
if((msg[i - 1] == cur && msg[i] != parent) || (msg[i] == cur && msg[i - 1] != parent)) {
c++;
}
}
List<N> children = Collections.emptyList();
if(c > 0) {
children = new ArrayList<>(c);
for(int i = 1; i < msg.length; i += 2) {
if(msg[i - 1] == cur && msg[i] != parent) {
children.add(buildTree(msg, msg[i], cur, nodes));
}
else if(msg[i] == cur && msg[i - 1] != parent) {
children.add(buildTree(msg, msg[i - 1], cur, nodes));
}
}
}
N node = makeNode(cur, children);
nodes.set(cur, node);
return node;

public static double parseDouble(final byte[] str, final int start, final int end) if(start >= end) {
throw EMPTY_STRING;
}
int pos = start;
byte cur = str[pos];
if(matchNaN(str, cur, pos, end)) {
return Double.NaN;
}
boolean isNegative = (cur == '-');
if((isNegative || (cur == '+')) && (++pos < end)) {
cur = str[pos];
}
if(matchInf(str, cur, pos, end)) {
return isNegative ? Double.NEGATIVE_INFINITY : Double.POSITIVE_INFINITY;
}
if(((cur < '0') || (cur > '9')) && (cur != '.')) {
throw NOT_A_NUMBER;
}
long decimal = 0;
int decimalPoint = -1;
while(true) {
final int digit = cur - '0';
if((digit >= 0) && (digit <= 9)) {
final long tmp = (decimal << 3) + (decimal << 1) + digit;
if(tmp >= decimal) {
decimal = tmp;
}
else if(++decimalPoint == 0) {
throw PRECISION_OVERFLOW;
}
}
else if((cur == '.') && (decimalPoint < 0)) {
decimalPoint = pos;
}
else {
break;
}
if(++pos >= end) {
break;
}
cur = str[pos];
}
decimalPoint = (decimalPoint >= 0) ? pos - decimalPoint - 1 : 0;
int exp = 0;
if((pos + 1 < end) && ((cur == 'E') || (cur == 'e'))) {
cur = str[++pos];
final boolean isNegativeExp = (cur == '-');
if((isNegativeExp || (cur == '+')) && (++pos < end)) {
cur = str[pos];
}
if((cur < '0') || (cur > '9')) {
throw INVALID_EXPONENT;
}
while(true) {
final int digit = cur - '0';
if(digit < 0 || digit > 9) {
break;
}
exp = (exp << 3) + (exp << 1) + digit;
if(exp > Double.MAX_EXPONENT) {
throw EXPONENT_OVERFLOW;
}
if(++pos >= end) {
break;
}
cur = str[pos];
}
exp = isNegativeExp ? -exp : exp;
}
exp = decimalPoint > 0 ? (exp - decimalPoint) : exp;
if(pos != end) {
throw TRAILING_CHARACTERS;
}
return BitsUtil.lpow10(isNegative ? -decimal : decimal, exp);

public static long parseLongBase10(final CharSequence str, final int start, final int end) int pos = start;
char cur = str.charAt(pos);
boolean isNegative = (cur == '-');
if((isNegative || (cur == '+')) && (++pos < end)) {
cur = str.charAt(pos);
}
if((cur < '0') || (cur > '9')) {
throw NOT_A_NUMBER;
}
long decimal = 0;
while(true) {
final int digit = cur - '0';
if((digit >= 0) && (digit <= 9)) {
final long tmp = (decimal << 3) + (decimal << 1) + digit;
if(tmp < decimal) {
throw PRECISION_OVERFLOW;
}
decimal = tmp;
}
else {
break;
}
if(++pos < end) {
cur = str.charAt(pos);
}
else {
break;
}
}
if(pos != end) {
throw TRAILING_CHARACTERS;
}
return isNegative ? -decimal : decimal;

public boolean containsPoint2D(double[] v) assert (v.length == 2);
final double testx = v[0];
final double testy = v[1];
boolean c = false;
Iterator<double[]> it = points.iterator();
double[] pre = points.get(points.size() - 1);
while(it.hasNext()) {
final double[] cur = it.next();
final double curx = cur[0], cury = cur[1];
final double prex = pre[0], prey = pre[1];
if(((cury > testy) != (prey > testy))) {
if((testx < (prex - curx) * (testy - cury) / (prey - cury) + curx)) {
c = !c;
}
}
pre = cur;
}
return c;

public static double regularizedGammaQ(final double a, final double x) if(Double.isNaN(a) || Double.isNaN(x) || (a <= 0.0) || (x < 0.0)) {
return Double.NaN;
}
if(x == 0.0) {
return 1.0;
}
if(x < a + 1.0) {
return 1.0 - regularizedGammaP(a, x);
}
final double FPMIN = Double.MIN_VALUE / NUM_PRECISION;
double b = x + 1 - a;
double c = 1.0 / FPMIN;
double d = 1.0 / b;
double fac = d;
for(int i = 1; i < MAX_ITERATIONS; i++) {
double an = i * (a - i);
b += 2;
d = an * d + b;
if(Math.abs(d) < FPMIN) {
d = FPMIN;
}
c = b + an / c;
if(Math.abs(c) < FPMIN) {
c = FPMIN;
}
d = 1 / d;
double del = d * c;
fac *= del;
if(Math.abs(del - 1.0) <= NUM_PRECISION) {
break;
}
}
return fac * FastMath.exp(-x + a * FastMath.log(x) - logGamma(a));

private static MutableTreeNode simplifyTree(MutableTreeNode cur, String prefix) if(cur instanceof PackageNode) {
PackageNode node = (PackageNode) cur;
if(node.getChildCount() == 1) {
String newprefix = (prefix != null) ? prefix + "." + (String) node.getUserObject() : (String) node.getUserObject();
cur = simplifyTree((MutableTreeNode) node.getChildAt(0), newprefix);
}
else {
if(prefix != null) {
node.setUserObject(prefix + "." + (String) node.getUserObject());
}
for(int i = 0; i < node.getChildCount(); i++) {
MutableTreeNode c = (MutableTreeNode) node.getChildAt(i);
MutableTreeNode c2 = simplifyTree(c, null);
if(c != c2) {
node.remove(i);
node.insert(c2, i);
}
}
}
}
else if(cur instanceof ClassNode) {
ClassNode node = (ClassNode) cur;
if(prefix != null) {
node.setUserObject(prefix + "." + (String) node.getUserObject());
}
}
return cur;

private void nnChainCore(MatrixParadigm mat, DBIDArrayMIter prots, DistanceQuery<O> dq, PointerHierarchyRepresentationBuilder builder, Int2ObjectOpenHashMap<ModifiableDBIDs> clusters) final DBIDArrayIter ix = mat.ix;
final double[] distances = mat.matrix;
final int size = mat.size;
IntegerArray chain = new IntegerArray(size + 1);
FiniteProgress progress = LOG.isVerbose() ? new FiniteProgress("Running MiniMax-NNChain", size - 1, LOG) : null;
for(int k = 1, end = size; k < size; k++) {
int a = -1, b = -1;
if(chain.size() <= 3) {
a = NNChain.findUnlinked(0, end, ix, builder);
b = NNChain.findUnlinked(a + 1, end, ix, builder);
chain.clear();
chain.add(a);
}
else {
int lastIndex = chain.size;
int c = chain.get(lastIndex - 2);
b = chain.get(lastIndex - 3);
a = chain.get(lastIndex - 4);
assert (chain.get(lastIndex - 1) == c || chain.get(lastIndex - 1) == b);
b = c < b ? c : b;
chain.size -= 3;
}
double minDist = mat.get(a, b);
do {
int c = b;
final int ta = MatrixParadigm.triangleSize(a);
for(int i = 0; i < a; i++) {
if(i != b && !builder.isLinked(ix.seek(i))) {
double dist = distances[ta + i];
if(dist < minDist) {
minDist = dist;
c = i;
}
}
}
for(int i = a + 1; i < size; i++) {
if(i != b && !builder.isLinked(ix.seek(i))) {
double dist = distances[MatrixParadigm.triangleSize(i) + a];
if(dist < minDist) {
minDist = dist;
c = i;
}
}
}
b = a;
a = c;
chain.add(a);
}
while(chain.size() < 3 || a != chain.get(chain.size - 1 - 2));
if(a < b) {
int tmp = a;
a = b;
b = tmp;
}
assert (minDist == mat.get(a, b));
assert (b < a);
MiniMax.merge(size, mat, prots, builder, clusters, dq, a, b);
end = AGNES.shrinkActiveSet(ix, builder, end, a);
LOG.incrementProcessed(progress);
}
LOG.ensureCompleted(progress);

