public static <T> Collection<T> addAll(Collection<T> collection, Object value, Type elementType) {
if (null == collection || null == value) {
return collection;
}
if (TypeUtil.isUnknow(elementType)) {
elementType = Object.class;
} else {
final Class<?> elementRowType = TypeUtil.getClass(elementType);
if (null != elementRowType && (elementRowType.isInstance(value) && false == Iterable.class.isAssignableFrom(elementRowType))) {
collection.add((T) value);
return collection;
}
}
Iterator iter;
if (value instanceof Iterator) {
iter = (Iterator) value;
} else if (value instanceof Iterable) {
iter = ((Iterable) value).iterator();
} else if (value instanceof Enumeration) {
iter = new EnumerationIter<>((Enumeration) value);
} else if (ArrayUtil.isArray(value)) {
iter = new ArrayIter<>(value);
} else if (value instanceof CharSequence) {
iter = StrUtil.splitTrim((CharSequence) value, CharUtil.COMMA).iterator();
} else {
iter = CollUtil.newArrayList(value).iterator();
}
final ConverterRegistry convert = ConverterRegistry.getInstance();
while (iter.hasNext()) {
collection.add((T) convert.convert(elementType, iter.next()));
}
return collection;

private Object convertObjectToArray(Object value) if (value instanceof CharSequence) {
if (targetComponentType == char.class || targetComponentType == Character.class) {
return convertArrayToArray(value.toString().toCharArray());
}
final String[] strings = StrUtil.split(value.toString(), StrUtil.COMMA);
return convertArrayToArray(strings);
}
final ConverterRegistry converter = ConverterRegistry.getInstance();
Object result = null;
if (value instanceof List) {
final List<?> list = (List<?>) value;
result = Array.newInstance(targetComponentType, list.size());
for (int i = 0; i < list.size(); i++) {
Array.set(result, i, converter.convert(targetComponentType, list.get(i)));
}
} else if (value instanceof Collection) {
final Collection<?> collection = (Collection<?>) value;
result = Array.newInstance(targetComponentType, collection.size());
int i = 0;
for (Object element : collection) {
Array.set(result, i, converter.convert(targetComponentType, element));
i++;
}
} else if (value instanceof Iterable) {
final List<?> list = IterUtil.toList((Iterable<?>) value);
result = Array.newInstance(targetComponentType, list.size());
for (int i = 0; i < list.size(); i++) {
Array.set(result, i, converter.convert(targetComponentType, list.get(i)));
}
} else if (value instanceof Iterator) {
final List<?> list = IterUtil.toList((Iterator<?>) value);
result = Array.newInstance(targetComponentType, list.size());
for (int i = 0; i < list.size(); i++) {
Array.set(result, i, converter.convert(targetComponentType, list.get(i)));
}
} else {
result = convertToSingleElementArray(value);
}
return result;

