public BaseType getVariable(String name) throws NoSuchVariableException Stack s = new Stack();
s = search(name, s);
return (BaseType) s.pop();

Stack collect(Stack components) throws DAP2ServerSideException, DAP2Exception, NoSuchFunctionException, NoSuchVariableException BaseType bt = null;
ServerArrayMethods sam = null;
components = getSdds().search(name, components);
if(slices != null && slices.size() > 0) {
try {
bt = (BaseType) components.peek();
} catch (ClassCastException cce) {
String msg = "Attempt to treat the variable `" + name
+ "' as if it is an array.";
throw new DAP2Exception(DAP2Exception.MALFORMED_EXPR, msg);
}
if(bt instanceof DGrid) {
DGrid grid = ((DGrid) bt);
bt = grid.getArray();
sam = (ServerArrayMethods) bt;
for(int i = 0;i < slices.size();i++) {
ASTslice slice = slices.get(i);
slice.walk(sam, i);
}
for(int i = 0;i < slices.size();i++) {
ASTslice slice = slices.get(i);
bt = grid.getVar(i + 1);
sam = (ServerArrayMethods) bt;
slice.walk(sam, 0);
}
} else if(bt instanceof ServerArrayMethods) {
sam = (ServerArrayMethods) bt;
for(int i = 0;i < slices.size();i++) {
ASTslice slice = slices.get(i);
slice.walk(sam, i);
}
}
}
return components;

void walk(CEEvaluator ceEval) throws DAP2ServerSideException, DAP2Exception, NoSuchFunctionException, NoSuchVariableException if(fcn != null) {
SubClause subclause = fcn.translate();
getCeEval().appendClause(subclause);
} else {
Stack components = new Stack();
components = var.collect(components);
markStackedVariables(components);
}

SubClause translate() throws DAP2ServerSideException, DAP2Exception, NoSuchFunctionException, NoSuchVariableException SubClause subclause = null;
if(constant != null) {
subclause = constant.translate();
} else if(var != null) {
Stack components = new Stack();
components = var.collect(components);
subclause = getClauseFactory().newValueClause((BaseType) components.pop(), false);
} else if(fcn != null) {
subclause = fcn.translate();
} else
assert (false);
return subclause;

Stack collect(Stack components) throws DAP2ServerSideException, DAP2Exception, NoSuchFunctionException, NoSuchVariableException for(ASTsegment segment : segments) {
components = segment.collect(components);
}
return components;

private void resolveAlias(Alias alias) throws MalformedAliasException, UnresolvedAliasException String name = alias.getEncodedName();
String attribute = alias.getAliasedToAttributeFieldAsClearString();
if (Debug.isSet("DDS.resolveAliases")) {
DAPNode.log.debug("\n\nFound: Alias " + name +
"  " + attribute);
}
if (attribute.equals("")) {
throw new MalformedAliasException("The attribute 'attribute' in the Alias " +
"element (name: '" + name + "') must have a value other than an empty string.");
}
if (Debug.isSet("DDS.resolveAliases")) {
DAPNode.log.debug("Attribute: `" + attribute + "'");
}
Vector aNames = tokenizeAliasField(attribute);
if (Debug.isSet("DDS.resolveAliases")) {
DAPNode.log.debug("Attribute name tokenized to " + aNames.size() + " elements");
Enumeration e = aNames.elements();
while (e.hasMoreElements()) {
String aname = (String) e.nextElement();
DAPNode.log.debug("name: " + aname);
}
}
BaseType targetBT = null;
boolean isAbsolutePath = aNames.get(0).equals(".");
if (!isAbsolutePath) {
throw new MalformedAliasException("In the Alias '" + name + "'" +
" the value of the attribute 'attribute' does not begin with the character dot (.). " +
"The value of the 'attribute' field must always be an absolute path name from the " +
"top level of the variable reference, and thus must always begin with the dot (.) character.");
}
if (aNames.size() == 1) {
throw new MalformedAliasException("In the Alias '" + name + "'" +
" the value of the attribute 'attribute' contains only the character dot (.). " +
"The value of the 'attribute' field must always reference an Attribute using an absolute path name from the " +
"top level of the DAS, and must reference an attribute within the DAS. A simple dot is not allowed.");
}
aNames.remove(0);
targetBT = getDeepestMatchingVariable(this, aNames);
if (targetBT == null) {
targetBT = this;
}
Attribute targetAT = null;
if (aNames.size() == 0) {
targetAT = targetBT.getAttribute();
} else {
targetAT = getAttribute(targetBT.getAttributeTable(), aNames);
}
alias.setMyVariable(targetBT);
alias.setMyAttribute(targetAT);

