public String solutionToString(int fractionDigits) if(!isSolvable()) {
throw new IllegalStateException("System is not solvable!");
}
DecimalFormat nf = new DecimalFormat();
nf.setMinimumFractionDigits(fractionDigits);
nf.setMaximumFractionDigits(fractionDigits);
nf.setDecimalFormatSymbols(new DecimalFormatSymbols(Locale.US));
nf.setNegativePrefix("");
nf.setPositivePrefix("");
int row = coeff[0].length >> 1;
int params = u.length;
int paramsDigits = integerDigits(params);
int x0Digits = maxIntegerDigits(x_0);
int[] uDigits = maxIntegerDigits(u);
StringBuilder buffer = new StringBuilder();
for(int i = 0; i < x_0.length; i++) {
double value = x_0[i];
format(nf, buffer, value, x0Digits);
for(int j = 0; j < u[0].length; j++) {
if(i == row) {
buffer.append("  +  a_").append(j).append(" * ");
}
else {
buffer.append("          ");
for(int d = 0; d < paramsDigits; d++) {
buffer.append(' ');
}
}
format(nf, buffer, u[i][j], uDigits[j]);
}
buffer.append('\n');
}
return buffer.toString();

private void solve(int method) throws NullPointerException if(solved) {
return;
}
if(!reducedRowEchelonForm) {
reducedRowEchelonForm(method);
}
if(!isSolvable(method)) {
if(LOG.isDebugging()) {
LOG.debugFine("Equation system is not solvable!");
}
return;
}
final int cols = coeff[0].length;
int numbound = 0, numfree = 0;
int[] boundIndices = new int[cols], freeIndices = new int[cols];
x_0 = new double[cols];
outer: for(int i = 0; i < coeff.length; i++) {
for(int j = i; j < coeff[row[i]].length; j++) {
if(coeff[row[i]][col[j]] == 1) {
x_0[col[i]] = rhs[row[i]];
boundIndices[numbound++] = col[i];
continue outer;
}
}
freeIndices[numfree++] = i;
}
StringBuilder msg = new StringBuilder();
if(LOG.isDebugging()) {
msg.append("\nSpecial solution x_0 = [").append(FormatUtil.format(x_0, ",", FormatUtil.NF4)).append(']')
.append("\nbound Indices ").append(FormatUtil.format(boundIndices, ","))
.append("\nfree Indices ").append(FormatUtil.format(freeIndices, ","));
}
Arrays.sort(boundIndices, 0, numbound);
int freeIndex = 0;
int boundIndex = 0;
u = new double[cols][numfree];
for(int j = 0; j < u[0].length; j++) {
for(int i = 0; i < u.length; i++) {
if(freeIndex < numfree && i == freeIndices[freeIndex]) {
u[i][j] = 1;
}
else if(boundIndex < numbound && i == boundIndices[boundIndex]) {
u[i][j] = -coeff[row[boundIndex]][freeIndices[freeIndex]];
boundIndex++;
}
}
freeIndex++;
boundIndex = 0;
}
if(LOG.isDebugging()) {
msg.append("\nU");
for(double[] anU : u) {
msg.append('\n').append(FormatUtil.format(anU, ",", FormatUtil.NF4));
}
LOG.debugFine(msg.toString());
}
solved = true;

public static double[][] orthonormalize(final double[][] m1) final int columndimension = getColumnDimensionality(m1);
final double[][] v = copy(m1);
for(int i = 1; i < columndimension; i++) {
final double[] u_i = getCol(m1, i);
final double[] sum = new double[m1.length];
for(int j = 0; j < i; j++) {
final double[] v_j = getCol(v, j);
final double scalar = scalarProduct(u_i, v_j) / scalarProduct(v_j, v_j);
plusEquals(sum, times(v_j, scalar));
}
final double[] v_i = minus(u_i, sum);
setCol(v, i, v_i);
}
normalizeColumns(v);
return v;

private double[][] solveInplace(double[][] B) int mx = B.length;
if(mx != m) {
throw new IllegalArgumentException(ERR_MATRIX_DIMENSIONS);
}
if(!this.isNonsingular()) {
throw new ArithmeticException(ERR_SINGULAR);
}
for(int k = 0; k < n; k++) {
final double[] Bk = B[k];
for(int i = k + 1; i < n; i++) {
minusTimesEquals(B[i], Bk, LU[i][k]);
}
}
for(int k = n - 1; k >= 0; k--) {
final double[] Bk = B[k];
timesEquals(Bk, 1. / LU[k][k]);
for(int i = 0; i < k; i++) {
minusTimesEquals(B[i], Bk, LU[i][k]);
}
}
return B;

protected double computeNNForUniformData(final KNNQuery<NumberVector> knnQuery, final double[] min, final double[] extend) final Random rand = random.getSingleThreadedRandom();
final int dim = min.length;
double[] buf = new double[dim];
double u = 0.;
for(int i = 0; i < sampleSize; i++) {
for(int d = 0; d < buf.length; d++) {
buf[d] = min[d] + (rand.nextDouble() * extend[d]);
}
double kdist = knnQuery.getKNNForObject(DoubleVector.wrap(buf), k).getKNNDistance();
u += MathUtil.powi(kdist, dim);
}
return u;

private static int[] mstPartition(double[][] matrix) final int n = matrix.length;
int[] edges = PrimsMinimumSpanningTree.processDense(matrix);
double meanlength = thresholdLength(matrix, edges);
int[] idx = new int[n], best = new int[n], sizes = new int[n];
int bestsize = -1;
double bestlen = 0;
for(int omit = n - 2; omit > 0; --omit) {
final double len = edgelength(matrix, edges, omit);
if(len < meanlength) {
continue;
}
omitEdge(edges, idx, sizes, omit);
int minsize = n;
for(int i = 0; i < n; i++) {
int j = idx[i] = follow(i, idx);
if(j == i && sizes[i] < minsize) {
minsize = sizes[i];
}
}
if(minsize > bestsize || (minsize == bestsize && len > bestlen)) {
bestsize = minsize;
bestlen = len;
System.arraycopy(idx, 0, best, 0, n);
}
}
return best;

