private boolean migrate(CRDTReplicationAwareService service, Member target, int maxConfiguredReplicaCount) if (Thread.currentThread().isInterrupted()) {
return false;
}
final OperationService operationService = nodeEngine.getOperationService();
final CRDTReplicationContainer migrationOperation = service.prepareMigrationOperation(maxConfiguredReplicaCount);
if (migrationOperation == null) {
logger.finest("Skipping migration of " + service.getName() + " for target " + target);
return true;
}
try {
logger.finest("Migrating " + service.getName() + " to " + target);
operationService.invokeOnTarget(null, migrationOperation.getOperation(), target.getAddress()).join();
final boolean allMigrated = service.clearCRDTState(migrationOperation.getVectorClocks());
if (!allMigrated) {
logger.fine(service.getName() + " CRDTs have been mutated since migrated to target " + target
+ ". Rescheduling migration in " + MIGRATION_RETRY_DELAY_SECONDS + " second(s).");
}
return allMigrated;
} catch (Exception e) {
if (logger.isFineEnabled()) {
logger.fine("Failed migration of " + service.getName() + " for target " + target
+ ". Rescheduling migration in " + MIGRATION_RETRY_DELAY_SECONDS + " second(s).", e);
} else {
logger.info("Failed migration of " + service.getName() + " for target " + target
+ ". Rescheduling migration in " + MIGRATION_RETRY_DELAY_SECONDS + " second(s).");
}
return false;
}

private void rollbackDestination() int partitionId = getPartitionId();
InternalPartitionServiceImpl partitionService = getService();
PartitionReplicaManager replicaManager = partitionService.getReplicaManager();
ILogger logger = getLogger();
int destinationCurrentReplicaIndex = migrationInfo.getDestinationCurrentReplicaIndex();
if (destinationCurrentReplicaIndex == -1) {
clearPartitionReplicaVersions(partitionId);
if (logger.isFinestEnabled()) {
logger.finest("Replica versions are cleared in destination after failed migration. partitionId="
+ partitionId);
}
} else {
int replicaOffset = migrationInfo.getDestinationCurrentReplicaIndex() <= 1 ? 1 : migrationInfo
.getDestinationCurrentReplicaIndex();
for (ServiceNamespace namespace : replicaManager.getNamespaces(partitionId)) {
long[] versions = updatePartitionReplicaVersions(replicaManager, partitionId, namespace, replicaOffset - 1);
if (logger.isFinestEnabled()) {
logger.finest("Replica versions are rolled back in destination after failed migration. partitionId="
+ partitionId + " namespace: " + namespace + " replica versions=" + Arrays.toString(versions));
}
}
}

private void sendEvent(Address subscriber, EventEnvelope eventEnvelope, int orderKey) String serviceName = eventEnvelope.getServiceName();
EventServiceSegment segment = getSegment(serviceName, true);
boolean sync = segment.incrementPublish() % eventSyncFrequency == 0;
if (sync) {
SendEventOperation op = new SendEventOperation(eventEnvelope, orderKey);
Future f = nodeEngine.getOperationService()
.createInvocationBuilder(serviceName, op, subscriber)
.setTryCount(SEND_RETRY_COUNT).invoke();
try {
f.get(sendEventSyncTimeoutMillis, MILLISECONDS);
} catch (Exception e) {
syncDeliveryFailureCount.inc();
if (logger.isFinestEnabled()) {
logger.finest("Sync event delivery failed. Event: " + eventEnvelope, e);
}
}
} else {
Packet packet = new Packet(serializationService.toBytes(eventEnvelope), orderKey)
.setPacketType(Packet.Type.EVENT);
EndpointManager em = nodeEngine.getNode().getNetworkingService().getEndpointManager(MEMBER);
if (!em.transmit(packet, subscriber)) {
if (nodeEngine.isRunning()) {
logFailure("Failed to send event packet to: %s, connection might not be alive.", subscriber);
}
}
}

