public static void depthTo3D(CameraPinholeBrown param , GrayU16 depth , FastQueue<Point3D_F64> cloud ) cloud.reset();
Point2Transform2_F64 p2n = LensDistortionFactory.narrow(param).undistort_F64(true,false);
Point2D_F64 n = new Point2D_F64();
for( int y = 0; y < depth.height; y++ ) {
int index = depth.startIndex + y*depth.stride;
for( int x = 0; x < depth.width; x++ ) {
int mm = depth.data[index++] & 0xFFFF;
if( mm == 0 )
continue;
p2n.compute(x,y,n);
Point3D_F64 p = cloud.grow();
p.z = mm;
p.x = n.x*p.z;
p.y = n.y*p.z;
}
}

public void assignValuesToA( DMatrixRMaj A ) for (int viewIdx = 0; viewIdx < depths.numRows; viewIdx++) {
int rowA = viewIdx*3;
int rowPixels = viewIdx*2;
for (int pointIdx = 0; pointIdx < depths.numCols; pointIdx++) {
double depth = depths.get(viewIdx,pointIdx);
A.set(rowA,pointIdx, depth*pixels.get(rowPixels,pointIdx)/pixelScale);
A.set(rowA+1,pointIdx, depth*pixels.get(rowPixels+1,pointIdx)/pixelScale);
A.set(rowA+2,pointIdx, depth);
}
}

