final IAtom atom2 = bond.getEnd();
if (atom1.getPoint2d() == null || atom2.getPoint2d() == null)
throw new IllegalArgumentException("An atom has no 2D coordinates.");
lengths[i] = getLength2D(bond);
}
Arrays.sort(lengths);
return lengths[lengths.length / 2];

