private List<Integer> tryDoubleBondCombinations(IAtomContainer container, int dblBondsAdded, int bondOffSet, int doubleBondMax, List<IAtom> atomsInNeedOfFix) int offSet = bondOffSet;
List<Integer> dblBondPositions = null;
while (offSet < container.getBondCount() && dblBondPositions == null) {
IBond bond = container.getBond(offSet);
if (atomsInNeedOfFix.contains(bond.getBegin()) && atomsInNeedOfFix.contains(bond.getEnd())) {
bond.setOrder(IBond.Order.DOUBLE);
dblBondsAdded = dblBondsAdded + 1;
if (dblBondsAdded == doubleBondMax) {
boolean validDoubleBondConfig = true;
CHECK: for (IAtom atom : container.atoms()) {
if (atom.getValency() != atom.getImplicitHydrogenCount() + getConnectivity(atom, container)) {
validDoubleBondConfig = false;
break CHECK;
}
}
if (validDoubleBondConfig) {
dblBondPositions = new ArrayList<Integer>();
for (int idx = 0; idx < container.getBondCount(); idx++) {
if (container.getBond(idx).getOrder().equals(IBond.Order.DOUBLE))
dblBondPositions.add(idx);
}
return dblBondPositions;
}
} else {
dblBondPositions = tryDoubleBondCombinations(container, dblBondsAdded, offSet + 1, doubleBondMax,
atomsInNeedOfFix);
}
bond.setOrder(IBond.Order.SINGLE);
dblBondsAdded = dblBondsAdded - 1;
}
offSet++;
}
return dblBondPositions;

public IAtomContainer ringFragments() int[] vertices = cyclic();
int n = vertices.length;
IAtom[] atoms = new IAtom[n];
List<IBond> bonds = new ArrayList<IBond>();
for (int i = 0; i < vertices.length; i++) {
atoms[i] = container.getAtom(vertices[i]);
}
for (IBond bond : container.bonds()) {
IAtom either = bond.getBegin();
IAtom other = bond.getEnd();
int u = container.indexOf(either);
int v = container.indexOf(other);
if (searcher.cyclic(u, v)) bonds.add(bond);
}
IChemObjectBuilder builder = container.getBuilder();
IAtomContainer fragment = builder.newInstance(IAtomContainer.class, 0, 0, 0, 0);
fragment.setAtoms(atoms);
fragment.setBonds(bonds.toArray(new IBond[bonds.size()]));
return fragment;

private IAtom getNextAtomWithAliphaticUnplacedNeigbors() IBond bond;
for (int f = 0; f < molecule.getBondCount(); f++) {
bond = molecule.getBond(f);
if (bond.getEnd().getFlag(CDKConstants.ISPLACED) && !bond.getBegin().getFlag(CDKConstants.ISPLACED)) {
return bond.getEnd();
}
if (bond.getBegin().getFlag(CDKConstants.ISPLACED) && !bond.getEnd().getFlag(CDKConstants.ISPLACED)) {
return bond.getBegin();
}
}
return null;

public static double getBondLengthMedian(final IAtomContainer container) if (container.getBondCount() == 0) throw new IllegalArgumentException("Container has no bonds.");
int nBonds = 0;
double[] lengths = new double[container.getBondCount()];
for (int i = 0; i < container.getBondCount(); i++) {
final IBond bond = container.getBond(i);
final IAtom atom1 = bond.getBegin();
final IAtom atom2 = bond.getEnd();
Point2d p1 = atom1.getPoint2d();
Point2d p2 = atom2.getPoint2d();
if (p1 == null || p2 == null)
throw new IllegalArgumentException("An atom has no 2D coordinates.");
if (p1.x != p2.x || p1.y != p2.y)
lengths[nBonds++] = p1.distance(p2);
}
Arrays.sort(lengths, 0, nBonds);
return lengths[nBonds / 2];

