private boolean lookupRingSystem(IRingSet rs, IAtomContainer molecule, boolean anon) if (!useIdentTemplates) return false;
final IChemObjectBuilder bldr = molecule.getBuilder();
final IAtomContainer ringSystem = bldr.newInstance(IAtomContainer.class);
for (IAtomContainer container : rs.atomContainers())
ringSystem.add(container);
final Set<IAtom> ringAtoms = new HashSet<>();
for (IAtom atom : ringSystem.atoms())
ringAtoms.add(atom);
final IAtomContainer ringWithStubs = bldr.newInstance(IAtomContainer.class);
ringWithStubs.add(ringSystem);
for (IBond bond : molecule.bonds()) {
IAtom atom1 = bond.getBegin();
IAtom atom2 = bond.getEnd();
if (isHydrogen(atom1) || isHydrogen(atom2)) continue;
if (ringAtoms.contains(atom1) ^ ringAtoms.contains(atom2)) {
ringWithStubs.addAtom(atom1);
ringWithStubs.addAtom(atom2);
ringWithStubs.addBond(bond);
}
}
final IAtomContainer skeletonStub = clearHydrogenCounts(AtomContainerManipulator.skeleton(ringWithStubs));
final IAtomContainer skeleton = clearHydrogenCounts(AtomContainerManipulator.skeleton(ringSystem));
final IAtomContainer anonymous = clearHydrogenCounts(AtomContainerManipulator.anonymise(ringSystem));
for (IAtomContainer container : Arrays.asList(skeletonStub, skeleton, anonymous)) {
if (!anon && container == anonymous)
continue;
if (identityLibrary.assignLayout(container)) {
for (int i = 0; i < ringSystem.getAtomCount(); i++) {
IAtom atom = ringSystem.getAtom(i);
atom.setPoint2d(container.getAtom(i).getPoint2d());
atom.setFlag(CDKConstants.ISPLACED, true);
}
return true;
}
}
return false;

public static int globalCentroid(Centroid overallCentroid, Relation<? extends NumberVector> rel, List<? extends Cluster<?>> clusters, NumberVector[] centroids, NoiseHandling noiseOption) int clustercount = 0;
Iterator<? extends Cluster<?>> ci = clusters.iterator();
for(int i = 0; ci.hasNext(); i++) {
Cluster<?> cluster = ci.next();
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
continue;
case TREAT_NOISE_AS_SINGLETONS:
clustercount += cluster.size();
for(DBIDIter it = cluster.getIDs().iter(); it.valid(); it.advance()) {
overallCentroid.put(rel.get(it));
}
continue;
case MERGE_NOISE:
break;
}
}
assert (centroids[i] != null);
overallCentroid.put(centroids[i], cluster.size());
++clustercount;
}
return clustercount;

public int getHighestClusterCount() int maxClusters = 0;
for(int i = 0; i < numclusters.length; i++) {
maxClusters = Math.max(maxClusters, numclusters[i]);
}
return maxClusters;

public double evaluateClustering(Database db, Relation<? extends NumberVector> rel, Clustering<?> c) final SquaredEuclideanDistanceFunction df = SquaredEuclideanDistanceFunction.STATIC;
List<? extends Cluster<?>> clusters = c.getAllClusters();
double vrc = 0.;
int ignorednoise = 0;
if(clusters.size() > 1) {
NumberVector[] centroids = new NumberVector[clusters.size()];
ignorednoise = EvaluateSimplifiedSilhouette.centroids(rel, clusters, centroids, noiseOption);
final int dim = RelationUtil.dimensionality(rel);
Centroid overallCentroid = new Centroid(dim);
int clustercount = globalCentroid(overallCentroid, rel, clusters, centroids, noiseOption);
double a = 0, b = 0;
Iterator<? extends Cluster<?>> ci = clusters.iterator();
for(int i = 0; ci.hasNext(); i++) {
Cluster<?> cluster = ci.next();
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
continue;
case TREAT_NOISE_AS_SINGLETONS:
for(DBIDIter it = cluster.getIDs().iter(); it.valid(); it.advance()) {
b += df.distance(overallCentroid, rel.get(it));
}
continue;
case MERGE_NOISE:
break;
}
}
for(DBIDIter it = cluster.getIDs().iter(); it.valid(); it.advance()) {
NumberVector vec = rel.get(it);
a += df.distance(centroids[i], vec);
b += df.distance(overallCentroid, vec);
}
}
vrc = ((b - a) / a) * ((rel.size() - clustercount) / (clustercount - 1.));
if(penalize && ignorednoise > 0) {
vrc *= (rel.size() - ignorednoise) / (double) rel.size();
}
}
if(LOG.isStatistics()) {
LOG.statistics(new StringStatistic(key + ".vrc.noise-handling", noiseOption.toString()));
if(ignorednoise > 0) {
LOG.statistics(new LongStatistic(key + ".vrc.ignored", ignorednoise));
}
LOG.statistics(new DoubleStatistic(key + ".vrc", vrc));
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), c, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Distance-based Evaluation");
g.addMeasure("Variance Ratio Criteria", vrc, 0., 1., 0., false);
return vrc;

