@Override public Socket createSocket(final String host, final int port, final InetAddress localAddress, final int localPort, final HttpConnectionParams params) throws IOException, UnknownHostException, ConnectTimeoutException if (params == null) {
throw new IllegalArgumentException("Parameters may not be null");
}
int timeout = params.getConnectionTimeout();
if (timeout == 0) {
InetAddress hostAddress = getCachedMisconfiguredHost(host, port);
if (hostAddress != null) {
return clientSSLSockFactory.createSocket(hostAddress, port, localAddress, localPort);
}
try {
SSLSocket sslSocket = (SSLSocket) clientSSLSockFactory.createSocket(host, port, localAddress, localPort);
sslSocket.startHandshake();
return sslSocket;
} catch (SSLException e) {
if (!e.getMessage().contains(CONTENTS_UNRECOGNIZED_NAME_EXCEPTION)) {
throw e;
}
hostAddress = InetAddress.getByName(host);
cacheMisconfiguredHost(host, port, hostAddress);
return clientSSLSockFactory.createSocket(hostAddress, port, localAddress, localPort);
}
}
Socket socket = clientSSLSockFactory.createSocket();
SocketAddress localAddr = new InetSocketAddress(localAddress, localPort);
socket.bind(localAddr);
SocketAddress remoteAddr = new InetSocketAddress(host, port);
socket.connect(remoteAddr, timeout);
return socket;

private KeyStore convertPemFileToKeyStore(Path pemFile) String pem;
try {
pem = FileUtils.readFileToString(pemFile.toFile(), StandardCharsets.US_ASCII);
} catch (IOException e) {
logger.warn("Failed to read .pem file:", e);
JOptionPane.showMessageDialog(
this,
Constant.messages.getString("dynssl.importpem.failedreadfile", e.getLocalizedMessage()),
Constant.messages.getString("dynssl.importpem.failed.title"),
JOptionPane.ERROR_MESSAGE);
return null;
}
byte[] cert;
try {
cert = SslCertificateUtils.extractCertificate(pem);
if (cert.length == 0) {
JOptionPane.showMessageDialog(
this,
Constant.messages.getString(
"dynssl.importpem.nocertsection",
SslCertificateUtils.BEGIN_CERTIFICATE_TOKEN,
SslCertificateUtils.END_CERTIFICATE_TOKEN),
Constant.messages.getString("dynssl.importpem.failed.title"),
JOptionPane.ERROR_MESSAGE);
return null;
}
} catch (IllegalArgumentException e) {
logger.warn("Failed to base64 decode the certificate from .pem file:", e);
JOptionPane.showMessageDialog(
this,
Constant.messages.getString("dynssl.importpem.certnobase64"),
Constant.messages.getString("dynssl.importpem.failed.title"),
JOptionPane.ERROR_MESSAGE);
return null;
}
byte[] key;
try {
key = SslCertificateUtils.extractPrivateKey(pem);
if (key.length == 0) {
JOptionPane.showMessageDialog(
this,
Constant.messages.getString(
"dynssl.importpem.noprivkeysection",
SslCertificateUtils.BEGIN_PRIVATE_KEY_TOKEN,
SslCertificateUtils.END_PRIVATE_KEY_TOKEN),
Constant.messages.getString("dynssl.importpem.failed.title"),
JOptionPane.ERROR_MESSAGE);
return null;
}
} catch (IllegalArgumentException e) {
logger.warn("Failed to base64 decode the private key from .pem file:", e);
JOptionPane.showMessageDialog(
this,
Constant.messages.getString("dynssl.importpem.privkeynobase64"),
Constant.messages.getString("dynssl.importpem.failed.title"),
JOptionPane.ERROR_MESSAGE);
return null;
}
try {
return SslCertificateUtils.pem2KeyStore(cert, key);
} catch (Exception e) {
