public static double pdf(double x, double k, double theta, double shift) if(x == Double.POSITIVE_INFINITY || x == Double.NEGATIVE_INFINITY) {
return 0.;
}
if(x != x) {
return Double.NaN;
}
x = (x - shift) * theta;
final double ex = FastMath.exp(x);
return ex < Double.POSITIVE_INFINITY ? FastMath.exp(k * x - ex - GammaDistribution.logGamma(k)) * theta : 0.;

public static double logpdf(double x, double k, double theta) if(x < 0) {
return Double.NEGATIVE_INFINITY;
}
if(x == 0) {
return (k == 1.0) ? FastMath.log(theta) : Double.NEGATIVE_INFINITY;
}
if(k == 1.0) {
return FastMath.log(theta) - x * theta;
}
final double xt = x * theta;
return (xt == Double.POSITIVE_INFINITY) ? Double.NEGATIVE_INFINITY :
FastMath.log(theta) + (k - 1.0) * FastMath.log(xt) - xt - logGamma(k);

public static double cdf(double x, double k, double theta, double shift) if(x == Double.NEGATIVE_INFINITY) {
return 0.;
}
if(x == Double.POSITIVE_INFINITY) {
return 1.;
}
if(x != x) {
return Double.NaN;
}
final double e = FastMath.exp((x - shift) * theta);
return e < Double.POSITIVE_INFINITY ? GammaDistribution.regularizedGammaP(k, e) : 1.;

public static double logpdf(double x, double k, double lambda, double theta) if(x <= theta || x == Double.POSITIVE_INFINITY) {
return Double.NEGATIVE_INFINITY;
}
double xl = (x - theta) / lambda;
return FastMath.log(k / lambda) + (k - 1) * FastMath.log(xl) - FastMath.pow(xl, k);

public static double pdf(double x, double k, double theta) if(x < 0) {
return 0.;
}
if(x == 0) {
return (k == 1.) ? theta : 0;
}
if(k == 1.) {
return FastMath.exp(-x * theta) * theta;
}
final double xt = x * theta;
return (xt == Double.POSITIVE_INFINITY) ? 0. :
FastMath.exp((k - 1.0) * FastMath.log(xt) - xt - logGamma(k)) * theta;

public static double pdf(double x, double k, double lambda, double theta) if(x <= theta || x == Double.POSITIVE_INFINITY) {
return 0.;
}
double xl = (x - theta) / lambda;
double p = FastMath.pow(xl, k - 1), p2 = p * -xl;
return p2 != Double.NEGATIVE_INFINITY ? k / lambda * p * FastMath.exp(p2) : 0.;

public void startTimerService( TypeSerializer<K> keySerializer, TypeSerializer<N> namespaceSerializer, Triggerable<K, N> triggerTarget) if (!isInitialized) {
if (keySerializer == null || namespaceSerializer == null) {
throw new IllegalArgumentException("The TimersService serializers cannot be null.");
}
if (this.keySerializer != null || this.namespaceSerializer != null || this.triggerTarget != null) {
throw new IllegalStateException("The TimerService has already been initialized.");
}
if (restoredTimersSnapshot != null) {
TypeSerializerSchemaCompatibility<K> keySerializerCompatibility =
restoredTimersSnapshot.getKeySerializerSnapshot().resolveSchemaCompatibility(keySerializer);
if (keySerializerCompatibility.isIncompatible() || keySerializerCompatibility.isCompatibleAfterMigration()) {
throw new IllegalStateException(
"Tried to initialize restored TimerService with new key serializer that requires migration or is incompatible.");
}
TypeSerializerSchemaCompatibility<N> namespaceSerializerCompatibility =
restoredTimersSnapshot.getNamespaceSerializerSnapshot().resolveSchemaCompatibility(namespaceSerializer);
if (namespaceSerializerCompatibility.isIncompatible() || namespaceSerializerCompatibility.isCompatibleAfterMigration()) {
throw new IllegalStateException(
"Tried to initialize restored TimerService with new namespace serializer that requires migration or is incompatible.");
}
this.keySerializer = keySerializerCompatibility.isCompatibleAsIs()
? keySerializer : keySerializerCompatibility.getReconfiguredSerializer();
this.namespaceSerializer = namespaceSerializerCompatibility.isCompatibleAsIs()
? namespaceSerializer : namespaceSerializerCompatibility.getReconfiguredSerializer();
} else {
this.keySerializer = keySerializer;
this.namespaceSerializer = namespaceSerializer;
}
this.keyDeserializer = null;
this.namespaceDeserializer = null;
this.triggerTarget = Preconditions.checkNotNull(triggerTarget);
final InternalTimer<K, N> headTimer = processingTimeTimersQueue.peek();
if (headTimer != null) {
nextTimer = processingTimeService.registerTimer(headTimer.getTimestamp(), this);
}
this.isInitialized = true;
} else {
if (!(this.keySerializer.equals(keySerializer) && this.namespaceSerializer.equals(namespaceSerializer))) {
throw new IllegalArgumentException("Already initialized Timer Service " +
"tried to be initialized with different key and namespace serializers.");
}
}

public static <K, N> Tuple2<K, N> deserializeKeyAndNamespace( byte[] serializedKeyAndNamespace, TypeSerializer<K> keySerializer, TypeSerializer<N> namespaceSerializer) throws IOException DataInputDeserializer dis = new DataInputDeserializer(
serializedKeyAndNamespace,
0,
serializedKeyAndNamespace.length);
try {
K key = keySerializer.deserialize(dis);
byte magicNumber = dis.readByte();
if (magicNumber != MAGIC_NUMBER) {
throw new IOException("Unexpected magic number " + magicNumber + ".");
}
N namespace = namespaceSerializer.deserialize(dis);
if (dis.available() > 0) {
throw new IOException("Unconsumed bytes in the serialized key and namespace.");
}
return new Tuple2<>(key, namespace);
} catch (IOException e) {
throw new IOException("Unable to deserialize key " +
"and namespace. This indicates a mismatch in the key/namespace " +
"serializers used by the KvState instance and this access.", e);
}

@Override public final TypeSerializer<T> restoreSerializer() if (serializer == null) {
throw new IllegalStateException(
"Trying to restore the prior serializer via TypeSerializerConfigSnapshot, " +
"but the prior serializer has not been set.");
}
else if (serializer instanceof UnloadableDummyTypeSerializer) {
Throwable originalError = ((UnloadableDummyTypeSerializer<?>) serializer).getOriginalError();
throw new IllegalStateException(
"Could not Java-deserialize TypeSerializer while restoring checkpoint metadata for serializer " +
"snapshot '" + getClass().getName() + "'. " +
"Please update to the TypeSerializerSnapshot interface that removes Java Serialization to avoid " +
"this problem in the future.", originalError);
} else {
return this.serializer;
}

public void addVirtualSideOutputNode(Integer originalId, Integer virtualId, OutputTag outputTag) if (virtualSideOutputNodes.containsKey(virtualId)) {
throw new IllegalStateException("Already has virtual output node with id " + virtualId);
}
for (Tuple2<Integer, OutputTag> tag : virtualSideOutputNodes.values()) {
if (!tag.f0.equals(originalId)) {
continue;
}
if (tag.f1.getId().equals(outputTag.getId()) &&
!tag.f1.getTypeInfo().equals(outputTag.getTypeInfo())) {
throw new IllegalArgumentException("Trying to add a side output for the same " +
"side-output id with a different type. This is not allowed. Side-output ID: " +
tag.f1.getId());
}
}
virtualSideOutputNodes.put(virtualId, new Tuple2<>(originalId, outputTag));

