public InternalQueryCache<K, V> tryCreateQueryCache(String mapName, String cacheName, ConstructorFunction<String, InternalQueryCache<K, V>> constructor) ContextMutexFactory.Mutex mutex = lifecycleMutexFactory.mutexFor(mapName);
try {
synchronized (mutex) {
ConcurrentMap<String, InternalQueryCache<K, V>> queryCacheRegistry
= getOrPutIfAbsent(queryCacheRegistryPerMap, mapName, queryCacheRegistryConstructor);
InternalQueryCache<K, V> queryCache = queryCacheRegistry.get(cacheName);
String cacheId = queryCache == null
? UuidUtil.newUnsecureUuidString() : queryCache.getCacheId();
queryCache = constructor.createNew(cacheId);
if (queryCache != NULL_QUERY_CACHE) {
queryCacheRegistry.put(cacheName, queryCache);
return queryCache;
}
return null;
}
} finally {
closeResource(mutex);
}

@Override public final InternalQueryCache createNew(String cacheId) try {
QueryCacheConfig queryCacheConfig = initQueryCacheConfig(request, cacheId);
if (queryCacheConfig == null) {
return NULL_QUERY_CACHE;
}
queryCache = createUnderlyingQueryCache(queryCacheConfig, request, cacheId);
AccumulatorInfo info = toAccumulatorInfo(queryCacheConfig, mapName, cacheId, predicate);
addInfoToSubscriberContext(info);
info.setPublishable(true);
String publisherListenerId = queryCache.getPublisherListenerId();
if (publisherListenerId == null) {
createSubscriberAccumulator(info);
}
createPublisherAccumulator(info);
queryCache.setPublisherListenerId(this.publisherListenerId);
} catch (Throwable throwable) {
removeQueryCacheConfig(mapName, request.getCacheName());
throw rethrow(throwable);
}
return queryCache;

