public static byte[] decode(final String base32) int i, index, lookup, offset, digit;
byte[] bytes = new byte[base32.length() * 5 / 8];
for (i = 0, index = 0, offset = 0; i < base32.length(); i++) {
lookup = base32.charAt(i) - '0';
if (lookup < 0 || lookup >= base32Lookup.length) {
continue;
}
digit = base32Lookup[lookup];
if (digit == 0xFF) {
continue;
}
if (index <= 3) {
index = (index + 5) % 8;
if (index == 0) {
bytes[offset] |= digit;
offset++;
if (offset >= bytes.length) {
break;
}
} else {
bytes[offset] |= digit << (8 - index);
}
} else {
index = (index + 5) % 8;
bytes[offset] |= (digit >>> index);
offset++;
if (offset >= bytes.length) {
break;
}
bytes[offset] |= digit << (8 - index);
}
}
return bytes;

private static int getChsAscii(String chs) int asc = 0;
byte[] bytes = chs.getBytes(CharsetUtil.CHARSET_GBK);
switch (bytes.length) {
case 1:
asc = bytes[0];
break;
case 2:
int hightByte = 256 + bytes[0];
int lowByte = 256 + bytes[1];
asc = (256 * hightByte + lowByte) - 256 * 256;
break;
default:
throw new UtilException("Illegal resource string");
}
return asc;

public static String bcdToStr(byte[] bytes) char temp[] = new char[bytes.length * 2], val;
