@Reference(authors = "Erich Schubert, Arthur Zimek, Hans-Peter Kriegel", title = "Geodetic Distance Queries on R-Trees for Indexing Geographic Data", booktitle = "Int. Symp. Advances in Spatial and Temporal Databases (SSTD'2013)", url = "https: bibkey = "DBLP:conf/ssd/SchubertZK13") public static double latlngMinDistRadFull(double plat, double plng, double rminlat, double rminlng, double rmaxlat, double rmaxlng) if((rminlat >= rmaxlat) && (rminlng >= rmaxlng)) {
