protected final void resize(int requiredSize) int newCapacity = ((queue.length < 64) ? ((queue.length + 1) << 1) : ((queue.length >> 1) + queue.length));
if(newCapacity < 0) {
throw new OutOfMemoryError();
}
if(requiredSize > newCapacity) {
newCapacity = requiredSize;
}
queue = Arrays.copyOf(queue, newCapacity);

public int shrinkSuperNode(int dirCapacity) if(!isSuperNode()) {
throw new IllegalStateException("Cannot shrink a non-super node");
}
int newCapacity = getCapacity() / 2 + 1;
if(numEntries >= newCapacity) {
throw new IllegalStateException("This node is not yet underflowing and cannot be shrunken yet.");
}
Entry[] new_entries = java.util.Arrays.copyOfRange(super.entries, 0, newCapacity);
assert new_entries[newCapacity - 1] == null;
super.entries = new_entries;
if(dirCapacity == getCapacity()) {
supernode = false;
}
return getCapacity();

protected double assignToNearestCluster(DBIDArrayIter miter, double[] dsum, List<? extends ModifiableDBIDs> clusters, DistanceQuery<V> distQ) double cost = 0;
double[] dists = new double[k];
for(DBIDIter iditer = distQ.getRelation().iterDBIDs(); iditer.valid(); iditer.advance()) {
final int current = currentCluster(clusters, iditer);
int minindex = -1;
double mindist = Double.POSITIVE_INFINITY;
if(current >= 0) {
minindex = current;
mindist = dists[current] = distQ.distance(iditer, miter.seek(current));
}
for(miter.seek(0); miter.valid(); miter.advance()) {
if(miter.getOffset() == current) {
continue;
}
double d = dists[miter.getOffset()] = distQ.distance(iditer, miter);
if(d < mindist) {
minindex = miter.getOffset();
mindist = d;
}
}
cost += mindist;
if(minindex == current) {
continue;
}
if(!clusters.get(minindex).add(iditer)) {
throw new IllegalStateException("Reassigning to the same cluster. " + current + " -> " + minindex);
}
dsum[minindex] += mindist;
if(current >= 0) {
if(!clusters.get(current).remove(iditer)) {
throw new IllegalStateException("Removing from the wrong cluster.");
}
dsum[current] -= dists[current];
}
}
return cost;

private long inverse(double current) short[] digits = new short[maxi];
for(int j = 0; j < maxi; j++) {
current *= base;
digits[j] = (short) current;
current -= digits[j];
if(current <= 1e-10) {
break;
}
}
long inv = 0;
for(int j = maxi - 1; j >= 0; j--) {
inv = inv * base + digits[j];
}
return inv;

@Override protected boolean hasUnderflow(N node) if(node.isLeaf()) {
return node.getNumEntries() < leafMinimum;
}
else {
if(node.isSuperNode()) {
if(node.getCapacity() - node.getNumEntries() >= dirCapacity) {
int newCapacity = node.shrinkSuperNode(dirCapacity);
if(newCapacity == dirCapacity) {
assert !node.isSuperNode();
if(node.isSuperNode()) {
throw new IllegalStateException("This node should not be a supernode anymore");
}
N n = supernodes.remove(Long.valueOf(node.getPageID()));
assert (n != null);
writeNode(node);
}
}
return false;
}
return node.getNumEntries() < dirMinimum;
}

public static <T> void processDense(T data, Adapter<T> adapter, Collector collector) final int n = adapter.size(data);
double[] best = new double[n];
Arrays.fill(best, Double.POSITIVE_INFINITY);
int[] src = new int[n];
byte[] connected = new byte[n];
int current = 0;
connected[current] = 1;
best[current] = 0;
for(int i = n - 2; i >= 0; i--) {
int newbesti = -1;
double newbestd = Double.POSITIVE_INFINITY;
for(int j = 0; j < n; ++j) {
if(connected[j] == 1) {
continue;
}
final double dist = adapter.distance(data, current, j);
if(dist < best[j]) {
best[j] = dist;
src[j] = current;
}
if(best[j] < newbestd || newbesti == -1) {
newbestd = best[j];
newbesti = j;
}
}
assert (newbesti >= 0);
connected[newbesti] = 1;
collector.addEdge(newbestd, src[newbesti], newbesti);
current = newbesti;
}

private void process(double[] data, double min, double max, KernelDensityFunction kernel, int window, double epsilon) dens = new double[data.length];
var = new double[data.length];
double halfwidth = ((max - min) / window) * .5;
for (int current = 0; current < data.length; current++) {
double value = 0.0;
for (int i = current; i >= 0; i--) {
double delta = Math.abs(data[i] - data[current]) / halfwidth;
final double contrib = kernel.density(delta);
value += contrib;
if (contrib < epsilon) {
break;
}
}
for (int i = current + 1; i < data.length; i++) {
double delta = Math.abs(data[i] - data[current]) / halfwidth;
final double contrib = kernel.density(delta);
value += contrib;
if (contrib < epsilon) {
break;
}
}
double realwidth = (Math.min(data[current] + halfwidth, max) - Math.max(min, data[current] - halfwidth));
double weight = realwidth / (2 * halfwidth);
dens[current] = value / (data.length * realwidth * .5);
var[current] = 1 / weight;
}

private void fireResultChanged(Result current) if(LOG.isDebugging()) {
LOG.debug("Result changed: " + current);
}
for(int i = listenerList.size(); --i >= 0;) {
