}

private double nextRadicalInverse() counter++;
if(counter >= MAXFAST) {
counter = 0;
inverse += MAXFAST;
current = radicalInverse(inverse);
return current;
}
double nextInverse = current + invbase;
if(nextInverse < ALMOST_ONE) {
current = nextInverse;
return current;
}
else {
double digit1 = invbase, digit2 = invbase * invbase;
while(current + digit2 >= ALMOST_ONE) {
digit1 = digit2;
digit2 *= invbase;
}
current += (digit1 - 1.0) + digit2;
return current;
}

public Clustering<Model> run(Database database, Relation<NumberVector> relation) Clustering<Model> ret = new Clustering<>("LMCLUS Clustering", "lmclus-clustering");
FiniteProgress progress = LOG.isVerbose() ? new FiniteProgress("Clustered objects", relation.size(), LOG) : null;
IndefiniteProgress cprogress = LOG.isVerbose() ? new IndefiniteProgress("Clusters found", LOG) : null;
ModifiableDBIDs unclustered = DBIDUtil.newHashSet(relation.getDBIDs());
Random r = rnd.getSingleThreadedRandom();
final int maxdim = Math.min(maxLMDim, RelationUtil.dimensionality(relation));
int cnum = 0;
while(unclustered.size() > minsize) {
DBIDs current = unclustered;
int lmDim = 1;
for(int k = 1; k <= maxdim; k++) {
while(true) {
Separation separation = findSeparation(relation, current, k, r);
if(separation.goodness <= sensitivityThreshold) {
break;
}
ModifiableDBIDs subset = DBIDUtil.newArray(current.size());
for(DBIDIter iter = current.iter(); iter.valid(); iter.advance()) {
if(deviation(minusEquals(relation.get(iter).toArray(), separation.originV), separation.basis) < separation.threshold) {
subset.add(iter);
}
}
if(subset.size() < minsize) {
break;
}
current = subset;
lmDim = k;
}
}
if(current.size() < minsize || current == unclustered) {
break;
}
final Cluster<Model> cluster = new Cluster<>(current);
cluster.setName("Cluster_" + lmDim + "d_" + cnum);
cnum++;
ret.addToplevelCluster(cluster);
unclustered.removeDBIDs(current);
if(progress != null) {
progress.setProcessed(relation.size() - unclustered.size(), LOG);
}
if(cprogress != null) {
cprogress.setProcessed(cnum, LOG);
}
}
if(unclustered.size() > 0) {
ret.addToplevelCluster(new Cluster<>(unclustered, true));
}
if(progress != null) {
progress.setProcessed(relation.size(), LOG);
progress.ensureCompleted(LOG);
}
LOG.setCompleted(cprogress);
return ret;

static boolean urlMatch(URL pattern, URL url) int relation;
if (pattern == null)
return (url == null);
if (!(url.getHost().endsWith(pattern.getHost())))
return false;
if (!(url.getPath().startsWith(pattern.getPath())))
return false;
if (pattern.getPort() > 0 && pattern.getPort() != url.getPort())
return false;
return true;

static private ServiceType searchFragment(String fragment) if (fragment.length() == 0)
return null;
Map<String, String> map = parseFragment(fragment);
if (map == null) return null;
String protocol = map.get("protocol");
if(protocol == null) {
for(String p: FRAGPROTOCOLS) {
if(map.get(p) != null) {protocol = p; break;}
}
}
if (protocol != null) {
if (protocol.equalsIgnoreCase("dap") || protocol.equalsIgnoreCase("dods"))
return ServiceType.OPENDAP;
if (protocol.equalsIgnoreCase("dap4"))
return ServiceType.DAP4;
if (protocol.equalsIgnoreCase("cdmremote"))
return ServiceType.CdmRemote;
if (protocol.equalsIgnoreCase("thredds"))
return ServiceType.THREDDS;
if (protocol.equalsIgnoreCase("ncml"))
return ServiceType.NCML;
}
return null;

