private static int nStereoBonds(List<IBond> bonds) int count = 0;
for (IBond bond : bonds) {
IBond.Stereo stereo = bond.getStereo();
switch (stereo) {
case E_OR_Z:
case UP_OR_DOWN:
case UP_OR_DOWN_INVERTED:
return -1;
case UP:
case DOWN:
case UP_INVERTED:
case DOWN_INVERTED:
count++;
break;
}
}
return count;

public static int convertBondOrder(IBond bond) int value = 0;
switch (bond.getOrder()) {
case QUADRUPLE:
value = 4;
break;
case TRIPLE:
value = 3;
break;
case DOUBLE:
value = 2;
break;
case SINGLE:
value = 1;
break;
default:
value = 0;
}
return value;

private static void makeElevationMap(IAtom atom, List<IBond> bonds, Map<IAtom, Integer> map) map.clear();
for (IBond bond : bonds) {
int elevation = 0;
switch (bond.getStereo()) {
case UP:
case DOWN_INVERTED:
elevation = +1;
break;
case DOWN:
case UP_INVERTED:
elevation = -1;
break;
}
if (bond.getBegin().equals(atom)) {
map.put(bond.getEnd(), elevation);
} else {
map.put(bond.getBegin(), -1 * elevation);
}
}

static int elevation(IBond bond) IBond.Stereo stereo = bond.getStereo();
if (stereo == null) return 0;
switch (stereo) {
case UP:
case DOWN_INVERTED:
return +1;
case DOWN:
case UP_INVERTED:
return -1;
default:
return 0;
}

private boolean matches(Type type, IAtom atom, int stereo) switch (type) {
case TRUE:
return true;
case FALSE:
return false;
case IS_AROMATIC:
return atom.isAromatic();
case IS_ALIPHATIC:
return !atom.isAromatic();
case IS_IN_RING:
return atom.isInRing();
case IS_IN_CHAIN:
return !atom.isInRing();
case IS_HETERO:
return !eq(atom.getAtomicNumber(), 6) &&
!eq(atom.getAtomicNumber(), 1);
case HAS_IMPLICIT_HYDROGEN:
return atom.getImplicitHydrogenCount() != null &&
atom.getImplicitHydrogenCount() > 0;
case HAS_ISOTOPE:
return atom.getMassNumber() != null;
case HAS_UNSPEC_ISOTOPE:
return atom.getMassNumber() == null;
case UNSATURATED:
for (IBond bond : atom.bonds())
if (bond.getOrder() == IBond.Order.DOUBLE)
return true;
return false;
case ELEMENT:
return eq(atom.getAtomicNumber(), value);
case ALIPHATIC_ELEMENT:
return !atom.isAromatic() &&
eq(atom.getAtomicNumber(), value);
case AROMATIC_ELEMENT:
return atom.isAromatic() &&
eq(atom.getAtomicNumber(), value);
case IMPL_H_COUNT:
return eq(atom.getImplicitHydrogenCount(), value);
case TOTAL_H_COUNT:
if (atom.getImplicitHydrogenCount() != null
&& atom.getImplicitHydrogenCount() > value)
return false;
return getTotalHCount(atom) == value;
case DEGREE:
return atom.getBondCount() == value;
case HEAVY_DEGREE:
return atom.getBondCount() - (getTotalHCount(atom) - atom.getImplicitHydrogenCount()) == value;
case TOTAL_DEGREE:
int x = atom.getBondCount() + unbox(atom.getImplicitHydrogenCount());
return x == value;
case VALENCE:
int v = unbox(atom.getImplicitHydrogenCount());
if (v > value)
return false;
for (IBond bond : atom.bonds()) {
if (bond.getOrder() != null)
v += bond.getOrder().numeric();
}
return v == value;
case ISOTOPE:
return eq(atom.getMassNumber(), value);
case FORMAL_CHARGE:
return eq(atom.getFormalCharge(), value);
case RING_BOND_COUNT:
if (!atom.isInRing() || atom.getBondCount() < value)
return false;
int rbonds = 0;
for (IBond bond : atom.bonds())
rbonds += bond.isInRing() ? 1 : 0;
return rbonds == value;
case RING_COUNT:
return atom.isInRing() && getRingCount(atom) == value;
case RING_SMALLEST:
return atom.isInRing() && isInSmallRingSize(atom, value);
case RING_SIZE:
return atom.isInRing() && isInRingSize(atom, value);
case HETERO_SUBSTITUENT_COUNT:
if (atom.getBondCount() < value)
return false;
int q = 0;
for (IBond bond : atom.bonds())
q += matches(Type.IS_HETERO, bond.getOther(atom), stereo) ? 1 : 0;
return q == value;
case INSATURATION:
int db = 0;
for (IBond bond : atom.bonds())
if (bond.getOrder() == IBond.Order.DOUBLE)
db++;
return db == value;
case HYBRIDISATION_NUMBER:
IAtomType.Hybridization hyb = atom.getHybridization();
if (hyb == null)
return false;
switch (value) {
case 1:
return hyb == IAtomType.Hybridization.SP1;
case 2:
return hyb == IAtomType.Hybridization.SP2;
case 3:
return hyb == IAtomType.Hybridization.SP3;
case 4:
return hyb == IAtomType.Hybridization.SP3D1;
case 5:
return hyb == IAtomType.Hybridization.SP3D2;
case 6:
return hyb == IAtomType.Hybridization.SP3D3;
case 7:
return hyb == IAtomType.Hybridization.SP3D4;
case 8:
return hyb == IAtomType.Hybridization.SP3D5;
default:
return false;
}
case PERIODIC_GROUP:
return atom.getAtomicNumber() != null &&
Elements.ofNumber(atom.getAtomicNumber()).group() == value;
case STEREOCHEMISTRY:
return stereo == UNKNOWN_STEREO || stereo == value;
case REACTION_ROLE:
ReactionRole role = atom.getProperty(CDKConstants.REACTION_ROLE);
return role != null && role.ordinal() == value;
case AND:
return left.matches(left.type, atom, stereo) &&
right.matches(right.type, atom, stereo);
case OR:
return left.matches(left.type, atom, stereo) ||
right.matches(right.type, atom, stereo);
case NOT:
return !left.matches(left.type, atom, stereo) ||
(stereo == UNKNOWN_STEREO &&
(left.type == STEREOCHEMISTRY ||
left.type == OR && left.left.type == STEREOCHEMISTRY));
case RECURSIVE:
if (ptrn == null)
ptrn = DfPattern.findSubstructure(query);
return ptrn.matchesRoot(atom);
default:
throw new IllegalArgumentException("Cannot match AtomExpr, type=" + type);
}

public void writeMolecule(IAtomContainer container) throws Exception final int dim = getNumberOfDimensions(container);
StringBuilder line = new StringBuilder();
Map<Integer, Integer> rgroups = null;
Map<Integer, String> aliases = null;
String title = container.getTitle();
if (title == null) title = "";
if (title.length() > 80) title = title.substring(0, 80);
writer.write(title);
writer.write('\n');
writer.write("  ");
writer.write(getProgName());
writer.write(new SimpleDateFormat("MMddyyHHmm").format(System.currentTimeMillis()));
if (dim != 0) {
writer.write(Integer.toString(dim));
writer.write('D');
}
writer.write('\n');
String comment = (String) container.getProperty(CDKConstants.REMARK);
if (comment == null) comment = "";
if (comment.length() > 80) comment = comment.substring(0, 80);
writer.write(comment);
writer.write('\n');
Map<IAtom,ITetrahedralChirality> atomstereo = new HashMap<>();
Map<IAtom,Integer> atomindex = new HashMap<>();
for (IStereoElement element : container.stereoElements())
if (element instanceof ITetrahedralChirality)
atomstereo.put(((ITetrahedralChirality) element).getChiralAtom(), (ITetrahedralChirality) element);
for (IAtom atom : container.atoms())
atomindex.put(atom, atomindex.size());
line.append(formatMDLInt(container.getAtomCount(), 3));
line.append(formatMDLInt(container.getBondCount(), 3));
line.append("  0  0");
line.append(atomstereo.isEmpty() ? "  0" : "  1");
line.append("  0  0  0  0  0999 V2000");
writer.write(line.toString());
writer.write('\n');
for (int f = 0; f < container.getAtomCount(); f++) {
IAtom atom = container.getAtom(f);
line.setLength(0);
switch (dim) {
case 0:
line.append("    0.0000    0.0000    0.0000 ");
break;
case 2:
if (atom.getPoint2d() != null) {
line.append(formatMDLFloat((float) atom.getPoint2d().x));
line.append(formatMDLFloat((float) atom.getPoint2d().y));
line.append("    0.0000 ");
} else {
line.append("    0.0000    0.0000    0.0000 ");
}
break;
case 3:
if (atom.getPoint3d() != null) {
line.append(formatMDLFloat((float) atom.getPoint3d().x));
line.append(formatMDLFloat((float) atom.getPoint3d().y));
line.append(formatMDLFloat((float) atom.getPoint3d().z)).append(" ");
} else {
line.append("    0.0000    0.0000    0.0000 ");
}
break;
}
if (container.getAtom(f) instanceof IPseudoAtom) {
IPseudoAtom pseudoAtom = (IPseudoAtom) container.getAtom(f);
String label = pseudoAtom.getLabel();
if (label == null)
label = "";
Matcher matcher = NUMERED_R_GROUP.matcher(label);
if (pseudoAtom.getSymbol().equals("R") && !label.isEmpty() && matcher.matches()) {
line.append("R# ");
if (rgroups == null) {
rgroups = new TreeMap<Integer, Integer>();
}
rgroups.put(f + 1, Integer.parseInt(matcher.group(1)));
}
else {
if (label.length() > 3) {
if (aliases == null) aliases = new TreeMap<Integer, String>();
aliases.put(f + 1, label);
line.append(formatMDLString(atom.getSymbol(), 3));
} else {
if (!label.isEmpty())
line.append(formatMDLString(label, 3));
else
line.append(formatMDLString(atom.getSymbol(), 3));
}
}
} else {
line.append(formatMDLString(container.getAtom(f).getSymbol(), 3));
}
int[] atomprops = new int[12];
atomprops[0] = determineIsotope(atom);
atomprops[1] = determineCharge(container, atom);
atomprops[2] = determineStereoParity(container, atomstereo, atomindex, atom);
atomprops[5] = determineValence(container, atom);
atomprops[9] = determineAtomMap(atom);
line.append(formatMDLInt(atomprops[0], 2));
line.append(formatMDLInt(atomprops[1], 3));
int last = atomprops.length-1;
if (!writeDefaultProps.isSet())
{
while (last >= 0) {
if (atomprops[last] != 0)
break;
last--;
}
if (last >= 2 && last < 5)
last = 5;
}
for (int i = 2; i <= last; i++)
line.append(formatMDLInt(atomprops[i], 3));
line.append('\n');
writer.write(line.toString());
}
for (IBond bond : container.bonds()) {
line.setLength(0);
if (bond.getAtomCount() != 2) {
logger.warn("Skipping bond with more/less than two atoms: " + bond);
} else {
if (bond.getStereo() == IBond.Stereo.UP_INVERTED || bond.getStereo() == IBond.Stereo.DOWN_INVERTED
|| bond.getStereo() == IBond.Stereo.UP_OR_DOWN_INVERTED) {
line.append(formatMDLInt(atomindex.get(bond.getEnd()) + 1, 3));
line.append(formatMDLInt(atomindex.get(bond.getBegin()) + 1, 3));
} else {
line.append(formatMDLInt(atomindex.get(bond.getBegin()) + 1, 3));
line.append(formatMDLInt(atomindex.get(bond.getEnd()) + 1, 3));
}
int bondType = 0;
if (bond instanceof QueryBond) {
QueryBond qbond = ((QueryBond)bond);
Expr e = qbond.getExpression();
switch (e.type()) {
case ALIPHATIC_ORDER:
case ORDER:
bondType = e.value();
break;
case IS_AROMATIC:
bondType = 4;
break;
case SINGLE_OR_DOUBLE:
bondType = 5;
break;
case SINGLE_OR_AROMATIC:
bondType = 6;
break;
case DOUBLE_OR_AROMATIC:
bondType = 7;
break;
case TRUE:
bondType = 8;
break;
case OR:
if (e.equals(new Expr(Expr.Type.ALIPHATIC_ORDER, 1).or(new Expr(Expr.Type.ALIPHATIC_ORDER, 2))) ||
e.equals(new Expr(Expr.Type.ALIPHATIC_ORDER, 2).or(new Expr(Expr.Type.ALIPHATIC_ORDER, 1))))
bondType = 5;
else if (e.equals(new Expr(Expr.Type.ALIPHATIC_ORDER, 1).or(new Expr(Expr.Type.IS_AROMATIC))) ||
e.equals(new Expr(Expr.Type.IS_AROMATIC).or(new Expr(Expr.Type.ALIPHATIC_ORDER, 1))))
bondType = 6;
else if (e.equals(new Expr(Expr.Type.ALIPHATIC_ORDER, 2).or(new Expr(Expr.Type.IS_AROMATIC))) ||
e.equals(new Expr(Expr.Type.IS_AROMATIC).or(new Expr(Expr.Type.ALIPHATIC_ORDER, 2))))
bondType = 6;
break;
default:
throw new IllegalArgumentException("Unsupported bond type!");
}
} else {
if (bond.getOrder() != null) {
switch (bond.getOrder()) {
case SINGLE:
case DOUBLE:
case TRIPLE:
if (writeAromaticBondTypes.isSet() && bond.isAromatic())
bondType = 4;
else
bondType = bond.getOrder().numeric();
break;
case UNSET:
if (bond.isAromatic()) {
if (!writeAromaticBondTypes.isSet())
throw new CDKException("Bond at idx " + container.indexOf(bond) + " was an unspecific aromatic bond which should only be used for querie in Molfiles. These can be written if desired by enabling the option 'WriteAromaticBondTypes'.");
bondType = 4;
}
break;
}
}
}
if (bondType == 0)
throw new CDKException("Bond at idx=" + container.indexOf(bond) + " is not supported by Molfile, bond=" + bond.getOrder());
line.append(formatMDLInt(bondType, 3));
line.append("  ");
switch (bond.getStereo()) {
case UP:
line.append("1");
break;
case UP_INVERTED:
line.append("1");
break;
case DOWN:
line.append("6");
break;
case DOWN_INVERTED:
line.append("6");
break;
case UP_OR_DOWN:
line.append("4");
break;
case UP_OR_DOWN_INVERTED:
line.append("4");
break;
case E_OR_Z:
line.append("3");
break;
default:
line.append("0");
}
if (writeDefaultProps.isSet())
line.append("  0  0  0 ");
line.append('\n');
writer.write(line.toString());
}
}
for (int i = 0; i < container.getAtomCount(); i++) {
IAtom atom = container.getAtom(i);
if (atom.getProperty(CDKConstants.COMMENT) != null
&& atom.getProperty(CDKConstants.COMMENT) instanceof String
&& !((String) atom.getProperty(CDKConstants.COMMENT)).trim().equals("")) {
writer.write("V  ");
writer.write(formatMDLInt(i + 1, 3));
writer.write(" ");
writer.write((String) atom.getProperty(CDKConstants.COMMENT));
writer.write('\n');
}
}
for (int i = 0; i < container.getAtomCount(); i++) {
IAtom atom = container.getAtom(i);
Integer charge = atom.getFormalCharge();
if (charge != null && charge != 0) {
writer.write("M  CHG  1 ");
writer.write(formatMDLInt(i + 1, 3));
writer.write(" ");
writer.write(formatMDLInt(charge, 3));
writer.write('\n');
}
}
if (container.getSingleElectronCount() > 0) {
Map<Integer, SPIN_MULTIPLICITY> atomIndexSpinMap = new LinkedHashMap<Integer, SPIN_MULTIPLICITY>();
for (int i = 0; i < container.getAtomCount(); i++) {
int eCount = container.getConnectedSingleElectronsCount(container.getAtom(i));
switch (eCount) {
case 0:
continue;
case 1:
atomIndexSpinMap.put(i, SPIN_MULTIPLICITY.Monovalent);
break;
case 2:
atomIndexSpinMap.put(i, SPIN_MULTIPLICITY.DivalentSinglet);
break;
default:
logger.debug("Invalid number of radicals found: " + eCount);
break;
}
}
Iterator<Map.Entry<Integer, SPIN_MULTIPLICITY>> iterator = atomIndexSpinMap.entrySet().iterator();
for (int i = 0; i < atomIndexSpinMap.size(); i += NN8) {
if (atomIndexSpinMap.size() - i <= NN8) {
writer.write("M  RAD" + formatMDLInt(atomIndexSpinMap.size() - i, WIDTH));
writeRadicalPattern(iterator, 0);
} else {
writer.write("M  RAD" + formatMDLInt(NN8, WIDTH));
writeRadicalPattern(iterator, 0);
}
writer.write('\n');
}
}
for (int i = 0; i < container.getAtomCount(); i++) {
IAtom atom = container.getAtom(i);
if (!(atom instanceof IPseudoAtom)) {
Integer atomicMass = atom.getMassNumber();
if (!writeMajorIsotopes.isSet() &&
isMajorIsotope(atom))
atomicMass = null;
if (atomicMass != null) {
writer.write("M  ISO  1 ");
writer.write(formatMDLInt(i + 1, 3));
writer.write(" ");
writer.write(formatMDLInt(atomicMass, 3));
writer.write('\n');
}
}
}
if (rgroups != null) {
StringBuilder rgpLine = new StringBuilder();
int cnt = 0;
for (Map.Entry<Integer, Integer> e : rgroups.entrySet()) {
rgpLine.append(formatMDLInt(e.getKey(), 4));
rgpLine.append(formatMDLInt(e.getValue(), 4));
cnt++;
if (cnt == 8) {
rgpLine.insert(0, "M  RGP" + formatMDLInt(cnt, 3));
writer.write(rgpLine.toString());
writer.write('\n');
rgpLine = new StringBuilder();
cnt = 0;
}
}
if (cnt != 0) {
rgpLine.insert(0, "M  RGP" + formatMDLInt(cnt, 3));
writer.write(rgpLine.toString());
writer.write('\n');
}
}
if (aliases != null) {
for (Map.Entry<Integer, String> e : aliases.entrySet()) {
writer.write("A" + formatMDLInt(e.getKey(), 5));
writer.write('\n');
String label = e.getValue();
if (label.length() > 70) label = label.substring(0, 70);
writer.write(label);
writer.write('\n');
}
}
writeSgroups(container, writer, atomindex);
writer.write("M  END");
writer.write('\n');
writer.flush();

public static CTFileQueryBond ofType(IBond bond, int type) CTFileQueryBond queryBond = new CTFileQueryBond(bond.getBuilder());
queryBond.setOrder(Order.UNSET);
queryBond.setAtoms(new IAtom[]{bond.getBegin(), bond.getEnd()});
switch (type) {
case 1:
queryBond.setType(Type.SINGLE);
break;
case 2:
queryBond.setType(Type.DOUBLE);
break;
case 3:
queryBond.setType(Type.TRIPLE);
break;
case 4:
queryBond.setType(Type.AROMATIC);
break;
case 5:
queryBond.setType(Type.SINGLE_OR_DOUBLE);
break;
case 6:
queryBond.setType(Type.SINGLE_OR_AROMATIC);
break;
case 7:
queryBond.setType(Type.DOUBLE_OR_AROMATIC);
break;
case 8:
queryBond.setType(Type.ANY);
break;
default:
throw new IllegalArgumentException("Unknown bond type: " + type);
}
return queryBond;

public void setLogical(Type type, Expr left, Expr right) switch (type) {
case AND:
case OR:
this.type = type;
this.value = 0;
this.left = left;
this.right = right;
this.query = null;
break;
case NOT:
this.type = type;
if (left != null && right == null)
this.left = left;
else if (left == null && right != null)
this.left = right;
else if (left != null)
throw new IllegalArgumentException("Only one sub-expression"
+ " should be provided"
+ " for NOT expressions!");
this.query = null;
this.value = 0;
break;
default:
throw new IllegalArgumentException("Left/Right sub expressions "
+ "supplied for "
+ " non-logical operator!");
}

private void labelUnspecified(IBond doubleBond) final IAtom aBeg = doubleBond.getBegin();
final IAtom aEnd = doubleBond.getEnd();
final int beg = atomToIndex.get(aBeg);
final int end = atomToIndex.get(aEnd);
int nAdj = 0;
final IAtom[] focus = new IAtom[4];
final IAtom[] adj = new IAtom[4];
for (int neighbor : graph[beg]) {
IBond bond = edgeToBond.get(beg, neighbor);
if (bond.getOrder() == SINGLE) {
if (nAdj == 4) return;
focus[nAdj] = aBeg;
adj[nAdj++] = container.getAtom(neighbor);
}
if (bond.getStereo() == UP_OR_DOWN || bond.getStereo() == UP_OR_DOWN_INVERTED) {
return;
}
}
for (int neighbor : graph[end]) {
IBond bond = edgeToBond.get(end, neighbor);
if (bond.getOrder() == SINGLE) {
if (nAdj == 4) return;
focus[nAdj] = aEnd;
adj[nAdj++] = container.getAtom(neighbor);
}
if (bond.getStereo() == UP_OR_DOWN || bond.getStereo() == UP_OR_DOWN_INVERTED) {
return;
}
}
int[] rank = priority(-1, adj, nAdj);
for (int i = 0; i < nAdj; i++) {
if (doubleBondElements[atomToIndex.get(adj[rank[i]])] == null &&
tetrahedralElements[atomToIndex.get(adj[rank[i]])] == null) {
edgeToBond.get(atomToIndex.get(focus[rank[i]]),
atomToIndex.get(adj[rank[i]])).setStereo(UP_OR_DOWN);
return;
}
}
doubleBond.setStereo(E_OR_Z);

