protected void checkResourceRequestLimit( List<ResourceRequest> requestList, String handle) throws InvalidSessionHandle ConfigManager configManager = getScheduler().getConfigManager();
Session session = sessionManager.getSession(handle);
PoolInfo poolInfo = session.getPoolInfo();
if (!configManager.useRequestMax(poolInfo)) {
return;
}
ResourceTypeCounter resourceTypeCounter = new ResourceTypeCounter();
for (ResourceRequest req : requestList) {
resourceTypeCounter.incr(req.type);
}
for (ResourceType resourceType : ResourceType.values()) {
if (configManager.getPoolMaximum(poolInfo, resourceType) <
resourceTypeCounter.getCount(resourceType)) {
String failureMessage =
"Session " + handle + " requested " +
resourceTypeCounter.getCount(resourceType) +
" resources for resource type " +
resourceType + " but was only allowed " +
configManager.getPoolMaximum(poolInfo, resourceType) + ", " +
"so failing the job";
LOG.error(failureMessage);
throw new InvalidSessionHandle(failureMessage);
}
}

public PoolSchedulable getPool(PoolInfo poolInfo) PoolSchedulable pool = nameToMap.get(poolInfo);
if (pool == null) {
pool = new PoolSchedulable(poolInfo, getType(), configManager);
PoolSchedulable prevPool = nameToMap.putIfAbsent(poolInfo, pool);
if (prevPool != null) {
pool = prevPool;
}
}
return pool;

public Queue<SessionSchedulable> getScheduleQueue() if (scheduleQueue == null) {
scheduleQueue =
createSessionQueue(configManager.getPoolComparator(poolInfo));
}
return scheduleQueue;

private PoolSchedulable getPoolSchedulable(PoolInfo poolInfo) PoolGroupSchedulable poolGroup =
nameToPoolGroup.get(poolInfo.getPoolGroupName());
if (poolGroup == null) {
poolGroup = new PoolGroupSchedulable(
poolInfo.getPoolGroupName(), type, configManager);
PoolGroupSchedulable prevPoolGroup =
nameToPoolGroup.putIfAbsent(poolInfo.getPoolGroupName(), poolGroup);
if (prevPoolGroup != null) {
poolGroup = prevPoolGroup;
}
}
return poolGroup.getPool(poolInfo);

public void snapshot() snapshotPoolGroups =
new ArrayList<PoolGroupSchedulable>(nameToPoolGroup.values());
for (PoolGroupSchedulable poolGroup : snapshotPoolGroups) {
poolGroup.snapshot();
}
scheduleQueue = null;
preemptQueue = null;
Collection<PoolInfo> configuredPoolInfos =
configManager.getConfiguredPoolInfos();
if (configuredPoolInfos != null) {
for (PoolInfo poolInfo : configuredPoolInfos) {
getPoolSchedulable(poolInfo);
}
}

