}
if (poolInfo == null) {
throw new InvalidSessionHandle("This cluster is operating in " +
"configured pools only mode.  The pool group " +
"and pool was not specified.  Please use the Corona parameter " +
CoronaConf.EXPLICIT_POOL_PROPERTY + " to set a valid poolgroup and " +
"pool in the format '<poolgroup>.<pool>'");
}
if (!configManager.isConfiguredPoolInfo(poolInfo)) {
throw new InvalidSessionHandle("This cluster is operating in " +
"configured pools only mode.  The pool group " +
"and pool was specified as '" + poolInfo.getPoolGroupName() +
"." + poolInfo.getPoolName() +
"' and is not part of this cluster.  " +
"Please use the Corona parameter " +
CoronaConf.EXPLICIT_POOL_PROPERTY + " to set a valid pool " +
"group and pool in the format <poolgroup>.<pool>");
}
if (!PoolInfo.isLegalPoolInfo(poolInfo)) {
throw new InvalidSessionHandle("This cluster is operating in " +
"configured pools only mode.  The pool group " +
"and pool was specified as '" + poolInfo.getPoolGroupName() +
"." + poolInfo.getPoolName() +
"' and has illegal characters (Something not in " +
PoolInfo.INVALID_REGEX + ").  Please use the Corona parameter " +
CoronaConf.EXPLICIT_POOL_PROPERTY + " to set a valid pool " +
"group and pool in the format <poolgroup>.<pool>");
}

private void preemptTasks(int tasksToPreempt) LOG.info("Start preempt " + tasksToPreempt + " for type " + type);
long maxRunningTime = configManager.getPreemptedTaskMaxRunningTime();
int rounds = configManager.getPreemptionRounds();
while (tasksToPreempt > 0) {
int preempted = preemptOneSession(tasksToPreempt, maxRunningTime);
if (preempted == 0) {
maxRunningTime *= 2;
if (--rounds <= 0 || maxRunningTime <= 0) {
LOG.warn("Cannot preempt enough " + type + " tasks " +
" rounds " + configManager.getPreemptionRounds() +
" maxRunningTime " + maxRunningTime +
" tasks not preempted:" + tasksToPreempt);
return;
}
}
tasksToPreempt -= preempted;
}

public Queue<SessionSchedulable> getPreemptQueue() if (preemptQueue == null) {
ScheduleComparator comparator = null;
switch (configManager.getPoolComparator(poolInfo)) {
case FIFO:
comparator = ScheduleComparator.FIFO_PREEMPT;
break;
case FAIR:
comparator = ScheduleComparator.FAIR_PREEMPT;
break;
case DEADLINE:
comparator = ScheduleComparator.DEADLINE_PREEMPT;
break;
default:
throw new IllegalArgumentException("Unknown comparator");
}
preemptQueue = createSessionQueue(comparator);
}
return preemptQueue;

