public double evaluateClustering(Database db, Relation<? extends NumberVector> rel, Clustering<?> c) List<? extends Cluster<?>> clusters = c.getAllClusters();
NumberVector[] centroids = new NumberVector[clusters.size()];
int ignorednoise = EvaluateSimplifiedSilhouette.centroids(rel, clusters, centroids, noiseHandling);
final int dim = RelationUtil.dimensionality(rel);
Centroid overallCentroid = new Centroid(dim);
EvaluateVarianceRatioCriteria.globalCentroid(overallCentroid, rel, clusters, centroids, noiseHandling);
double max = 0;
for(int i = 0; i < centroids.length; i++) {
if(centroids[i] == null && noiseHandling != NoiseHandling.TREAT_NOISE_AS_SINGLETONS) {
continue;
}
for(int j = i + 1; j < centroids.length; j++) {
if(centroids[j] == null && noiseHandling != NoiseHandling.TREAT_NOISE_AS_SINGLETONS) {
continue;
}
if(centroids[i] == null && centroids[j] == null) {
for(DBIDIter iti = clusters.get(i).getIDs().iter(); iti.valid(); iti.advance()) {
for(DBIDIter itj = clusters.get(j).getIDs().iter(); itj.valid(); itj.advance()) {
double dist = distanceFunction.distance(rel.get(iti), rel.get(itj));
max = dist > max ? dist : max;
}
}
}
else if(centroids[i] == null) {
for(DBIDIter iti = clusters.get(i).getIDs().iter(); iti.valid(); iti.advance()) {
double dist = distanceFunction.distance(rel.get(iti), centroids[j]);
max = dist > max ? dist : max;
}
}
else if(centroids[j] == null) {
for(DBIDIter itj = clusters.get(j).getIDs().iter(); itj.valid(); itj.advance()) {
double dist = distanceFunction.distance(centroids[i], rel.get(itj));
max = dist > max ? dist : max;
}
}
else {
double dist = distanceFunction.distance(centroids[i], centroids[j]);
max = dist > max ? dist : max;
}
}
}
double a = 0, b = 0;
Iterator<? extends Cluster<?>> ci = clusters.iterator();
for(int i = 0; ci.hasNext(); i++) {
Cluster<?> cluster = ci.next();
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseHandling){
case IGNORE_NOISE:
continue;
case TREAT_NOISE_AS_SINGLETONS:
for(DBIDIter it = cluster.getIDs().iter(); it.valid(); it.advance()) {
b += SquaredEuclideanDistanceFunction.STATIC.distance(overallCentroid, rel.get(it));
}
continue;
case MERGE_NOISE:
break;
}
}
for(DBIDIter it = cluster.getIDs().iter(); it.valid(); it.advance()) {
NumberVector obj = rel.get(it);
a += distanceFunction.distance(centroids[i], obj);
b += distanceFunction.distance(overallCentroid, obj);
}
}
final double pbm = FastMath.pow((1. / centroids.length) * (b / a) * max, 2.);
if(LOG.isStatistics()) {
LOG.statistics(new StringStatistic(key + ".pbm.noise-handling", noiseHandling.toString()));
if(ignorednoise > 0) {
LOG.statistics(new LongStatistic(key + ".pbm.ignored", ignorednoise));
}
LOG.statistics(new DoubleStatistic(key + ".pbm", pbm));
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), c, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Distance-based Evaluation");
g.addMeasure("PBM-Index", pbm, 0., Double.POSITIVE_INFINITY, 0., false);
db.getHierarchy().resultChanged(ev);
return pbm;

public double evaluateClustering(Database db, Relation<? extends NumberVector> rel, Clustering<?> c) List<? extends Cluster<?>> clusters = c.getAllClusters();
NumberVector[] centroids = new NumberVector[clusters.size()];
int ignorednoise = centroids(rel, clusters, centroids, noiseOption);
MeanVariance mssil = new MeanVariance();
Iterator<? extends Cluster<?>> ci = clusters.iterator();
for(int i = 0; ci.hasNext(); i++) {
Cluster<?> cluster = ci.next();
if(cluster.size() <= 1) {
mssil.put(0., cluster.size());
continue;
}
if(cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
continue;
case TREAT_NOISE_AS_SINGLETONS:
mssil.put(0., cluster.size());
continue;
case MERGE_NOISE:
break;
}
}
final NumberVector center = centroids[i];
assert (center != null);
for(DBIDIter it = cluster.getIDs().iter(); it.valid(); it.advance()) {
NumberVector obj = rel.get(it);
double a = distance.distance(center, obj);
double min = Double.POSITIVE_INFINITY;
Iterator<? extends Cluster<?>> cj = clusters.iterator();
for(int j = 0; cj.hasNext(); j++) {
Cluster<?> ocluster = cj.next();
if(i == j) {
continue;
}
NumberVector other = centroids[j];
if(other == null) {
switch(noiseOption){
case IGNORE_NOISE:
continue;
case TREAT_NOISE_AS_SINGLETONS:
for(DBIDIter it2 = ocluster.getIDs().iter(); it2.valid(); it2.advance()) {
double dist = distance.distance(rel.get(it2), obj);
min = dist < min ? dist : min;
}
continue;
case MERGE_NOISE:
break;
}
}
double dist = distance.distance(other, obj);
min = dist < min ? dist : min;
}
min = min < Double.POSITIVE_INFINITY ? min : a;
mssil.put((min - a) / (min > a ? min : a));
}
}
double penalty = 1.;
if(penalize && ignorednoise > 0) {
penalty = (rel.size() - ignorednoise) / (double) rel.size();
}
final double meanssil = penalty * mssil.getMean();
final double stdssil = penalty * mssil.getSampleStddev();
if(LOG.isStatistics()) {
LOG.statistics(new StringStatistic(key + ".simplified-silhouette.noise-handling", noiseOption.toString()));
if(ignorednoise > 0) {
LOG.statistics(new LongStatistic(key + ".simplified-silhouette.ignored", ignorednoise));
}
LOG.statistics(new DoubleStatistic(key + ".simplified-silhouette.mean", meanssil));
LOG.statistics(new DoubleStatistic(key + ".simplified-silhouette.stddev", stdssil));
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), c, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Distance-based Evaluation");
g.addMeasure("Simp. Silhouette +-" + FormatUtil.NF2.format(stdssil), meanssil, -1., 1., 0., false);
db.getHierarchy().resultChanged(ev);
return meanssil;

public static int globalCentroid(Centroid overallCentroid, Relation<? extends NumberVector> rel, List<? extends Cluster<?>> clusters, NumberVector[] centroids, NoiseHandling noiseOption) int clustercount = 0;
Iterator<? extends Cluster<?>> ci = clusters.iterator();
for(int i = 0; ci.hasNext(); i++) {
Cluster<?> cluster = ci.next();
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
continue;
case TREAT_NOISE_AS_SINGLETONS:
clustercount += cluster.size();
for(DBIDIter it = cluster.getIDs().iter(); it.valid(); it.advance()) {
overallCentroid.put(rel.get(it));
}
continue;
case MERGE_NOISE:
break;
}
}
assert (centroids[i] != null);
overallCentroid.put(centroids[i], cluster.size());
++clustercount;
}
return clustercount;

public double evaluateClustering(Database db, Relation<? extends O> rel, DistanceQuery<O> dq, Clustering<?> c) List<? extends Cluster<?>> clusters = c.getAllClusters();
int ignorednoise = 0, w = 0;
for(Cluster<?> cluster : clusters) {
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
ignorednoise += cluster.size();
continue;
case TREAT_NOISE_AS_SINGLETONS:
continue;
case MERGE_NOISE:
break;
default:
LOG.warning("Unknown noise handling option: " + noiseOption);
}
}
w += (cluster.size() * (cluster.size() - 1)) >>> 1;
}
DoubleHeap maxDists = new DoubleMinHeap(w);
DoubleHeap minDists = new DoubleMaxHeap(w);
double theta = 0.;
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Processing clusters for C-Index", clusters.size(), LOG) : null;
for(int i = 0; i < clusters.size(); i++) {
Cluster<?> cluster = clusters.get(i);
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
LOG.incrementProcessed(prog);
continue;
case TREAT_NOISE_AS_SINGLETONS:
processSingleton(cluster, rel, dq, maxDists, minDists, w);
LOG.incrementProcessed(prog);
continue;
case MERGE_NOISE:
break;
}
}
theta += processCluster(cluster, clusters, i, dq, maxDists, minDists, w);
LOG.incrementProcessed(prog);
}
LOG.ensureCompleted(prog);
double min = 0, max = 0;
assert (minDists.size() == w);
assert (maxDists.size() == w);
for(DoubleHeap.UnsortedIter it = minDists.unsortedIter(); it.valid(); it.advance()) {
min += it.get();
}
for(DoubleHeap.UnsortedIter it = maxDists.unsortedIter(); it.valid(); it.advance()) {
max += it.get();
}
assert (max >= min);
double cIndex = (max > min) ? (theta - min) / (max - min) : 1.;
if(LOG.isStatistics()) {
LOG.statistics(new StringStatistic(key + ".c-index.noise-handling", noiseOption.toString()));
if(ignorednoise > 0) {
LOG.statistics(new LongStatistic(key + ".c-index.ignored", ignorednoise));
}
LOG.statistics(new DoubleStatistic(key + ".c-index", cIndex));
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), c, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Distance-based Evaluation");
g.addMeasure("C-Index", cIndex, 0., 1., 0., true);
db.getHierarchy().resultChanged(ev);
return cIndex;

public double evaluateClustering(Database db, Relation<? extends NumberVector> rel, Clustering<?> c) boolean square = !distance.isSquared();
int ignorednoise = 0;
List<? extends Cluster<?>> clusters = c.getAllClusters();
double ssq = 0, sum = 0;
for(Cluster<?> cluster : clusters) {
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
ignorednoise += cluster.size();
continue;
case TREAT_NOISE_AS_SINGLETONS:
continue;
case MERGE_NOISE:
break;
}
}
NumberVector center = ModelUtil.getPrototypeOrCentroid(cluster.getModel(), rel, cluster.getIDs());
for(DBIDIter it1 = cluster.getIDs().iter(); it1.valid(); it1.advance()) {
final double d = distance.distance(center, rel.get(it1));
sum += d;
ssq += square ? d * d : d;
}
}
final int div = Math.max(1, rel.size() - ignorednoise);
if(LOG.isStatistics()) {
LOG.statistics(new DoubleStatistic(key + ".mean", sum / div));
LOG.statistics(new DoubleStatistic(key + ".ssq", ssq));
LOG.statistics(new DoubleStatistic(key + ".rmsd", FastMath.sqrt(ssq / div)));
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), c, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Distance-based Evaluation");
g.addMeasure("Mean distance", sum / div, 0., Double.POSITIVE_INFINITY, true);
g.addMeasure("Sum of Squares", ssq, 0., Double.POSITIVE_INFINITY, true);
g.addMeasure("RMSD", FastMath.sqrt(ssq / div), 0., Double.POSITIVE_INFINITY, true);
db.getHierarchy().add(c, ev);
return ssq;

public double evaluateClustering(Database db, Relation<O> rel, DistanceQuery<O> dq, Clustering<?> c) List<? extends Cluster<?>> clusters = c.getAllClusters();
MeanVariance msil = new MeanVariance();
int ignorednoise = 0;
for(Cluster<?> cluster : clusters) {
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
ignorednoise += cluster.size();
continue;
case TREAT_NOISE_AS_SINGLETONS:
msil.put(0., cluster.size());
continue;
case MERGE_NOISE:
break;
}
}
ArrayDBIDs ids = DBIDUtil.ensureArray(cluster.getIDs());
double[] as = new double[ids.size()];
DBIDArrayIter it1 = ids.iter(), it2 = ids.iter();
for(it1.seek(0); it1.valid(); it1.advance()) {
double a = as[it1.getOffset()];
for(it2.seek(it1.getOffset() + 1); it2.valid(); it2.advance()) {
final double dist = dq.distance(it1, it2);
a += dist;
as[it2.getOffset()] += dist;
}
a /= (ids.size() - 1);
double b = Double.POSITIVE_INFINITY;
for(Cluster<?> ocluster : clusters) {
if(ocluster == cluster) {
continue;
}
if(ocluster.size() <= 1 || ocluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
continue;
case TREAT_NOISE_AS_SINGLETONS:
for(DBIDIter it3 = ocluster.getIDs().iter(); it3.valid(); it3.advance()) {
final double dist = dq.distance(it1, it3);
b = dist < b ? dist : b;
}
continue;
case MERGE_NOISE:
break;
}
}
final DBIDs oids = ocluster.getIDs();
double btmp = 0.;
for(DBIDIter it3 = oids.iter(); it3.valid(); it3.advance()) {
btmp += dq.distance(it1, it3);
}
btmp /= oids.size();
b = btmp < b ? btmp : b;
}
b = b < Double.POSITIVE_INFINITY ? b : a;
msil.put((b - a) / (b > a ? b : a));
}
}
double penalty = 1.;
if(penalize && ignorednoise > 0) {
penalty = (rel.size() - ignorednoise) / (double) rel.size();
}
final double meansil = penalty * msil.getMean();
final double stdsil = penalty * msil.getSampleStddev();
if(LOG.isStatistics()) {
LOG.statistics(new StringStatistic(key + ".silhouette.noise-handling", noiseOption.toString()));
if(ignorednoise > 0) {
LOG.statistics(new LongStatistic(key + ".silhouette.noise", ignorednoise));
}
LOG.statistics(new DoubleStatistic(key + ".silhouette.mean", meansil));
LOG.statistics(new DoubleStatistic(key + ".silhouette.stddev", stdsil));
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), c, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Distance-based Evaluation");
g.addMeasure("Silhouette +-" + FormatUtil.NF2.format(stdsil), meansil, -1., 1., 0., false);
db.getHierarchy().resultChanged(ev);
return meansil;

public static int centroids(Relation<? extends NumberVector> rel, List<? extends Cluster<?>> clusters, NumberVector[] centroids, NoiseHandling noiseOption) assert (centroids.length == clusters.size());
int ignorednoise = 0;
Iterator<? extends Cluster<?>> ci = clusters.iterator();
for(int i = 0; ci.hasNext(); i++) {
Cluster<?> cluster = ci.next();
if(cluster.size() <= 1 || cluster.isNoise()) {
switch(noiseOption){
case IGNORE_NOISE:
ignorednoise += cluster.size();
case TREAT_NOISE_AS_SINGLETONS:
centroids[i] = null;
continue;
case MERGE_NOISE:
break;
}
}
centroids[i] = ModelUtil.getPrototypeOrCentroid(cluster.getModel(), rel, cluster.getIDs());
}
return ignorednoise;

public double evaluateClustering(Database db, Relation<? extends NumberVector> rel, Clustering<?> c) List<? extends Cluster<?>> clusters = c.getAllClusters();
NumberVector[] centroids = new NumberVector[clusters.size()];
int noisecount = EvaluateSimplifiedSilhouette.centroids(rel, clusters, centroids, noiseOption);
double[] withinGroupDistance = withinGroupDistances(rel, clusters, centroids);
Mean daviesBouldin = new Mean();
for(int i = 0; i < clusters.size(); i++) {
final NumberVector centroid = centroids[i];
final double withinGroupDistancei = withinGroupDistance[i];
double max = 0;
for(int j = 0; j < clusters.size(); j++) {
NumberVector ocentroid = centroids[j];
if(ocentroid == centroid) {
continue;
}
if(centroid != null && ocentroid != null) {
double bD = distanceFunction.distance(centroid, ocentroid);
double d = (withinGroupDistancei + withinGroupDistance[j]) / bD;
max = d > max ? d : max;
}
else if(noiseOption != NoiseHandling.IGNORE_NOISE) {
if(centroid != null) {
double d = Double.POSITIVE_INFINITY;
for(DBIDIter it = clusters.get(j).getIDs().iter(); it.valid(); it.advance()) {
double d2 = distanceFunction.distance(centroid, rel.get(it));
d = d2 < d ? d2 : d;
}
d = withinGroupDistancei / d;
max = d > max ? d : max;
}
else if(ocentroid != null) {
double d = Double.POSITIVE_INFINITY;
for(DBIDIter it = clusters.get(i).getIDs().iter(); it.valid(); it.advance()) {
double d2 = distanceFunction.distance(rel.get(it), ocentroid);
d = d2 < d ? d2 : d;
}
d = withinGroupDistance[j] / d;
max = d > max ? d : max;
}
}
}
daviesBouldin.put(max);
}
final double daviesBouldinMean = daviesBouldin.getCount() > 1 ? daviesBouldin.getMean() : 2.;
if(LOG.isStatistics()) {
LOG.statistics(new StringStatistic(key + ".db-index.noise-handling", noiseOption.toString()));
if(noisecount > 0) {
LOG.statistics(new LongStatistic(key + ".db-index.ignored", noisecount));
}
LOG.statistics(new DoubleStatistic(key + ".db-index", daviesBouldinMean));
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), c, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Distance-based Evaluation");
g.addMeasure("Davies Bouldin Index", daviesBouldinMean, 0., Double.POSITIVE_INFINITY, 0., true);
db.getHierarchy().resultChanged(ev);
return daviesBouldinMean;

public double evaluateClustering(Database db, Relation<? extends NumberVector> rel, Clustering<?> c) List<? extends Cluster<?>> clusters = c.getAllClusters();
int ignorednoise = 0, withinPairs = 0;
for(Cluster<?> cluster : clusters) {
if((cluster.size() <= 1 || cluster.isNoise())) {
switch(noiseHandling){
case IGNORE_NOISE:
ignorednoise += cluster.size();
continue;
case TREAT_NOISE_AS_SINGLETONS:
continue;
case MERGE_NOISE:
break;
}
}
withinPairs += (cluster.size() * (cluster.size() - 1)) >>> 1;
if(withinPairs < 0) {
throw new AbortException("Integer overflow - clusters too large to compute pairwise distances.");
}
}
double[] withinDistances = computeWithinDistances(rel, clusters, withinPairs);
int[] withinTies = new int[withinDistances.length];
countTies(withinDistances, withinTies);
long concordantPairs = 0, discordantPairs = 0, betweenPairs = 0;
for(int i = 0; i < clusters.size(); i++) {
Cluster<?> ocluster1 = clusters.get(i);
if((ocluster1.size() <= 1 || ocluster1.isNoise())
&& noiseHandling.equals(NoiseHandling.IGNORE_NOISE)) {
continue;
}
for(int j = i + 1; j < clusters.size(); j++) {
Cluster<?> ocluster2 = clusters.get(j);
if((ocluster2.size() <= 1 || ocluster2.isNoise())
&& noiseHandling.equals(NoiseHandling.IGNORE_NOISE)) {
continue;
}
betweenPairs += ocluster1.size() * (long) ocluster2.size();
for(DBIDIter oit1 = ocluster1.getIDs().iter(); oit1.valid(); oit1.advance()) {
NumberVector obj = rel.get(oit1);
for(DBIDIter oit2 = ocluster2.getIDs().iter(); oit2.valid(); oit2.advance()) {
double dist = distanceFunction.distance(obj, rel.get(oit2));
int p = Arrays.binarySearch(withinDistances, dist);
if(p >= 0) {
while(p > 0 && withinDistances[p - 1] >= dist) {
--p;
}
concordantPairs += p;
discordantPairs += withinDistances.length - p - withinTies[p];
continue;
}
p = -p - 1;
concordantPairs += p;
discordantPairs += withinDistances.length - p;
}
}
}
}
final long t = ((rel.size() - ignorednoise) * (long) (rel.size() - ignorednoise - 1)) >>> 1;
final long tt = (t * (t - 1)) >>> 1;
double gamma = (concordantPairs - discordantPairs) / (double) (concordantPairs + discordantPairs);
double tau = computeTau(concordantPairs, discordantPairs, tt, withinDistances.length, betweenPairs);
gamma = gamma > 0. ? gamma : 0.;
tau = tau > 0. ? tau : 0.;
if(LOG.isStatistics()) {
LOG.statistics(new StringStatistic(key + ".noise-handling", noiseHandling.toString()));
if(ignorednoise > 0) {
LOG.statistics(new LongStatistic(key + ".ignored", ignorednoise));
}
LOG.statistics(new DoubleStatistic(key + ".gamma", gamma));
LOG.statistics(new DoubleStatistic(key + ".tau", tau));
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), c, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Concordance-based Evaluation");
g.addMeasure("Gamma", gamma, -1., 1., 0., false);
g.addMeasure("Tau", tau, -1., +1., 0., false);
db.getHierarchy().resultChanged(ev);
return gamma;

public double evaluateClustering(Database db, Relation<O> rel, Clustering<?> cl) final DistanceQuery<O> dq = rel.getDistanceQuery(distanceFunction);
List<? extends Cluster<?>> clusters = cl.getAllClusters();
final int numc = clusters.size();
@SuppressWarnings("unchecked")
final Relation<? extends SpatialComparable> vrel = (Relation<? extends SpatialComparable>) rel;
final int dim = RelationUtil.dimensionality(vrel);
ArrayDBIDs[] cids = new ArrayDBIDs[numc];
double[][] coreDists = new double[numc][];
for(int c = 0; c < numc; c++) {
Cluster<?> cluster = clusters.get(c);
if(cluster.isNoise() || cluster.size() < 2) {
coreDists[c] = null;
continue;
}
ArrayDBIDs ids = cids[c] = DBIDUtil.ensureArray(cluster.getIDs());
double[] clusterCoreDists = coreDists[c] = new double[ids.size()];
for(DBIDArrayIter it = ids.iter(), it2 = ids.iter(); it.valid(); it.advance()) {
double currentCoreDist = 0;
int neighbors = 0;
for(it2.seek(0); it2.valid(); it2.advance()) {
if(DBIDUtil.equal(it, it2)) {
continue;
}
double dist = dq.distance(it, it2);
if(dist > 0) {
currentCoreDist += MathUtil.powi(1. / dist, dim);
++neighbors;
}
}
clusterCoreDists[it.getOffset()] = FastMath.pow(currentCoreDist / neighbors, -1. / dim);
}
}
int[][] clusterDegrees = new int[numc][];
double[] clusterDscMax = new double[numc];
boolean[] internalEdges = new boolean[numc];
for(int c = 0; c < numc; c++) {
Cluster<?> cluster = clusters.get(c);
if(cluster.isNoise() || cluster.size() < 2) {
clusterDegrees[c] = null;
clusterDscMax[c] = Double.NaN;
continue;
}
double[] clusterCoreDists = coreDists[c];
ArrayDBIDs ids = cids[c];
double dscMax = 0;
double[][] distances = new double[cluster.size()][cluster.size()];
for(DBIDArrayIter it = ids.iter(), it2 = ids.iter(); it.valid(); it.advance()) {
double currentCoreDist = clusterCoreDists[it.getOffset()];
for(it2.seek(it.getOffset() + 1); it2.valid(); it2.advance()) {
double mutualReachDist = MathUtil.max(currentCoreDist, clusterCoreDists[it2.getOffset()], dq.distance(it, it2));
distances[it.getOffset()][it2.getOffset()] = mutualReachDist;
distances[it2.getOffset()][it.getOffset()] = mutualReachDist;
}
}
int[] nodes = PrimsMinimumSpanningTree.processDense(distances);
int[] degree = new int[cluster.size()];
for(int i = 0; i < nodes.length; i++) {
degree[nodes[i]]++;
}
for(int i = 0, e = nodes.length - 1; i < e; i += 2) {
if(degree[nodes[i]] > 1 && degree[nodes[i + 1]] > 1) {
internalEdges[c] = true;
}
}
clusterDegrees[c] = degree;
for(int i = 0, e = nodes.length - 1; i < e; i += 2) {
final int n1 = nodes[i], n2 = nodes[i + 1];
if(distances[n1][n2] > dscMax && (!internalEdges[c] || (degree[n1] > 1 && degree[n2] > 1))) {
dscMax = distances[n1][n2];
}
}
clusterDscMax[c] = dscMax;
}
double dbcv = 0;
for(int c = 0; c < numc; c++) {
Cluster<?> cluster = clusters.get(c);
if(cluster.isNoise() || cluster.size() < 2) {
continue;
}
double currentDscMax = clusterDscMax[c];
double[] clusterCoreDists = coreDists[c];
int[] currentDegree = clusterDegrees[c];
double dspcMin = Double.POSITIVE_INFINITY;
for(DBIDArrayIter it = cids[c].iter(); it.valid(); it.advance()) {
if(currentDegree[it.getOffset()] < 2 && internalEdges[c]) {
continue;
}
double currentCoreDist = clusterCoreDists[it.getOffset()];
for(int oc = 0; oc < numc; oc++) {
Cluster<?> ocluster = clusters.get(oc);
if(ocluster.isNoise() || ocluster.size() < 2 || cluster == ocluster) {
continue;
}
int[] oDegree = clusterDegrees[oc];
double[] oclusterCoreDists = coreDists[oc];
for(DBIDArrayIter it2 = cids[oc].iter(); it2.valid(); it2.advance()) {
if(oDegree[it2.getOffset()] < 2 && internalEdges[oc]) {
continue;
}
double mutualReachDist = MathUtil.max(currentCoreDist, oclusterCoreDists[it2.getOffset()], dq.distance(it, it2));
dspcMin = mutualReachDist < dspcMin ? mutualReachDist : dspcMin;
}
}
}
double vc = (dspcMin - currentDscMax) / MathUtil.max(dspcMin, currentDscMax);
double weight = cluster.size() / (double) rel.size();
dbcv += weight * vc;
}
EvaluationResult ev = EvaluationResult.findOrCreate(db.getHierarchy(), cl, "Internal Clustering Evaluation", "internal evaluation");
MeasurementGroup g = ev.findOrCreateGroup("Distance-based Evaluation");
g.addMeasure("Density Based Clustering Validation", dbcv, 0., Double.POSITIVE_INFINITY, 0., true);
db.getHierarchy().resultChanged(ev);
return dbcv;

private SkeletonAndItsBestMatch genIntervalPattern( int field, String skeleton, String bestSkeleton, int differenceInfo, Map<String, PatternInfo> intervalPatterns) SkeletonAndItsBestMatch retValue = null;
PatternInfo pattern = fInfo.getIntervalPattern(
bestSkeleton, field);
