private boolean diffCalFieldValue(Calendar fromCalendar, Calendar toCalendar, Object[] items, int i) throws IllegalArgumentException if ( items[i] instanceof String) {
return false;
}
PatternItem item = (PatternItem)items[i];
char ch = item.type;
int patternCharIndex = getIndexFromChar(ch);
