}
}
return false;

static boolean isFieldUnitIgnored(String pattern, int field) int fieldLevel = CALENDAR_FIELD_TO_LEVEL[field];
int level;
char ch;
boolean inQuote = false;
char prevCh = 0;
int count = 0;
for (int i = 0; i < pattern.length(); ++i) {
ch = pattern.charAt(i);
if (ch != prevCh && count > 0) {
level = getLevelFromChar(prevCh);
if (fieldLevel <= level) {
return false;
}
count = 0;
}
if (ch == '\'') {
if ((i+1) < pattern.length() && pattern.charAt(i+1) == '\'') {
++i;
} else {
inQuote = ! inQuote;
}
} else if (!inQuote && isSyntaxChar(ch)) {
prevCh = ch;
++count;
}
}
if (count > 0) {
level = getLevelFromChar(prevCh);
if (fieldLevel <= level) {
return false;
}
}
return true;

private boolean genSeparateDateTimePtn(String dateSkeleton, String timeSkeleton, Map<String, PatternInfo> intervalPatterns, DateTimePatternGenerator dtpng) String skeleton;
if ( timeSkeleton.length() != 0  ) {
skeleton = timeSkeleton;
} else {
skeleton = dateSkeleton;
}
BestMatchInfo retValue = fInfo.getBestSkeleton(skeleton);
String bestSkeleton = retValue.bestMatchSkeleton;
int differenceInfo =  retValue.bestMatchDistanceInfo;
if (dateSkeleton.length() != 0  ) {
fDatePattern = dtpng.getBestPattern(dateSkeleton);
}
if (timeSkeleton.length() != 0  ) {
fTimePattern = dtpng.getBestPattern(timeSkeleton);
}
if ( differenceInfo == -1 ) {
return false;
}
if ( timeSkeleton.length() == 0 ) {
genIntervalPattern(Calendar.DATE, skeleton, bestSkeleton, differenceInfo, intervalPatterns);
SkeletonAndItsBestMatch skeletons = genIntervalPattern(
Calendar.MONTH, skeleton,
bestSkeleton, differenceInfo,
intervalPatterns);
if ( skeletons != null ) {
bestSkeleton = skeletons.skeleton;
skeleton = skeletons.bestMatchSkeleton;
}
genIntervalPattern(Calendar.YEAR, skeleton, bestSkeleton, differenceInfo, intervalPatterns);
} else {
genIntervalPattern(Calendar.MINUTE, skeleton, bestSkeleton, differenceInfo, intervalPatterns);
genIntervalPattern(Calendar.HOUR, skeleton, bestSkeleton, differenceInfo, intervalPatterns);
genIntervalPattern(Calendar.AM_PM, skeleton, bestSkeleton, differenceInfo, intervalPatterns);
}
return true;

private void subFormat(int patternCharIndex, int count, FieldDelegate delegate, StringBuffer buffer, boolean useDateFormatSymbols) int     maxIntCount = Integer.MAX_VALUE;
String  current = null;
int     beginOffset = buffer.length();
int field = PATTERN_INDEX_TO_CALENDAR_FIELD[patternCharIndex];
int value;
if (field == CalendarBuilder.WEEK_YEAR) {
if (calendar.isWeekDateSupported()) {
value = calendar.getWeekYear();
} else {
patternCharIndex = PATTERN_YEAR;
field = PATTERN_INDEX_TO_CALENDAR_FIELD[patternCharIndex];
value = calendar.get(field);
}
} else if (field == CalendarBuilder.ISO_DAY_OF_WEEK) {
value = CalendarBuilder.toISODayOfWeek(calendar.get(Calendar.DAY_OF_WEEK));
} else {
value = calendar.get(field);
}
int style = (count >= 4) ? Calendar.LONG : Calendar.SHORT;
if (!useDateFormatSymbols && field != CalendarBuilder.ISO_DAY_OF_WEEK) {
current = calendar.getDisplayName(field, style, locale);
}
switch (patternCharIndex) {
case PATTERN_ERA:
if (useDateFormatSymbols) {
String[] eras = formatData.getEras();
if (value < eras.length)
current = eras[value];
}
if (current == null)
current = "";
break;
case PATTERN_WEEK_YEAR:
case PATTERN_YEAR:
if (calendar instanceof GregorianCalendar) {
if (count != 2)
zeroPaddingNumber(value, count, maxIntCount, buffer);
else
zeroPaddingNumber(value, 2, 2, buffer);
} else {
if (current == null) {
zeroPaddingNumber(value, style == Calendar.LONG ? 1 : count,
maxIntCount, buffer);
}
}
break;
case PATTERN_STANDALONE_MONTH:
{
current = formatMonth(count, value, maxIntCount, buffer, useDateFormatSymbols,
true );
break;
}
case PATTERN_MONTH:
{
current = formatMonth(count, value, maxIntCount, buffer, useDateFormatSymbols,
false );
break;
}
case PATTERN_HOUR_OF_DAY1:
if (current == null) {
if (value == 0)
zeroPaddingNumber(calendar.getMaximum(Calendar.HOUR_OF_DAY)+1,
count, maxIntCount, buffer);
else
zeroPaddingNumber(value, count, maxIntCount, buffer);
}
break;
case PATTERN_STANDALONE_DAY_OF_WEEK:
{
current = formatWeekday(count, value, useDateFormatSymbols, true );
break;
}
case PATTERN_DAY_OF_WEEK:
{
current = formatWeekday(count, value, useDateFormatSymbols, false );
break;
}
case PATTERN_AM_PM:
if (useDateFormatSymbols) {
String[] ampm = formatData.getAmPmStrings();
current = ampm[value];
}
break;
case PATTERN_DAY_PERIOD:
case PATTERN_FLEXIBLE_DAY_PERIOD:
current = "";
break;
case PATTERN_HOUR1:
if (current == null) {
if (value == 0)
zeroPaddingNumber(calendar.getLeastMaximum(Calendar.HOUR)+1,
count, maxIntCount, buffer);
else
zeroPaddingNumber(value, count, maxIntCount, buffer);
}
break;
case PATTERN_ZONE_NAME:
if (current == null) {
TimeZone tz = calendar.getTimeZone();
boolean daylight = (calendar.get(Calendar.DST_OFFSET) != 0);
int tzstyle = count < 4 ? TimeZone.SHORT : TimeZone.LONG;
String zoneString = tz.getDisplayName(daylight, tzstyle, formatData.locale);
if (zoneString != null) {
buffer.append(zoneString);
} else {
int offsetMillis = calendar.get(Calendar.ZONE_OFFSET) +
calendar.get(Calendar.DST_OFFSET);
buffer.append(TimeZone.createGmtOffsetString(true, true, offsetMillis));
}
}
break;
case PATTERN_ZONE_VALUE:
{
value = calendar.get(Calendar.ZONE_OFFSET) + calendar.get(Calendar.DST_OFFSET);
final boolean includeSeparator = (count >= 4);
final boolean includeGmt = (count == 4);
buffer.append(TimeZone.createGmtOffsetString(includeGmt, includeSeparator, value));
break;
}
case PATTERN_ISO_ZONE:
value = calendar.get(Calendar.ZONE_OFFSET)
+ calendar.get(Calendar.DST_OFFSET);
if (value == 0) {
buffer.append('Z');
break;
}
value /=  60000;
if (value >= 0) {
buffer.append('+');
} else {
buffer.append('-');
value = -value;
}
CalendarUtils.sprintf0d(buffer, value / 60, 2);
if (count == 1) {
break;
}
if (count == 3) {
buffer.append(':');
}
CalendarUtils.sprintf0d(buffer, value % 60, 2);
break;
case PATTERN_MILLISECOND:
if (current == null) {
value = (int) (((double) value / 1000) * Math.pow(10, count));
zeroPaddingNumber(value, count, count, buffer);
}
break;
default:
if (current == null) {
zeroPaddingNumber(value, count, maxIntCount, buffer);
}
break;
}
if (current != null) {
buffer.append(current);
}
int fieldID = PATTERN_INDEX_TO_DATE_FORMAT_FIELD[patternCharIndex];
Field f = PATTERN_INDEX_TO_DATE_FORMAT_FIELD_ID[patternCharIndex];
delegate.formatted(fieldID, f, f, beginOffset, buffer.length(), buffer);

DateIntervalFormat.BestMatchInfo getBestSkeleton(String inputSkeleton) String bestSkeleton = inputSkeleton;
int[] inputSkeletonFieldWidth = new int[58];
int[] skeletonFieldWidth = new int[58];
final int DIFFERENT_FIELD = 0x1000;
final int STRING_NUMERIC_DIFFERENCE = 0x100;
final int BASE = 0x41;
boolean replaceZWithV = false;
if ( inputSkeleton.indexOf('z') != -1 ) {
inputSkeleton = inputSkeleton.replace('z', 'v');
replaceZWithV = true;
}
parseSkeleton(inputSkeleton, inputSkeletonFieldWidth);
int bestDistance = Integer.MAX_VALUE;
int bestFieldDifference = 0;
for (String skeleton : fIntervalPatterns.keySet()) {
for ( int i = 0; i < skeletonFieldWidth.length; ++i ) {
skeletonFieldWidth[i] = 0;
}
parseSkeleton(skeleton, skeletonFieldWidth);
int distance = 0;
int fieldDifference = 1;
for ( int i = 0; i < inputSkeletonFieldWidth.length; ++i ) {
int inputFieldWidth = inputSkeletonFieldWidth[i];
int fieldWidth = skeletonFieldWidth[i];
if ( inputFieldWidth == fieldWidth ) {
continue;
}
if ( inputFieldWidth == 0 ) {
fieldDifference = -1;
distance += DIFFERENT_FIELD;
} else if ( fieldWidth == 0 ) {
fieldDifference = -1;
distance += DIFFERENT_FIELD;
} else if (stringNumeric(inputFieldWidth, fieldWidth,
(char)(i+BASE) ) ) {
distance += STRING_NUMERIC_DIFFERENCE;
} else {
distance += Math.abs(inputFieldWidth - fieldWidth);
}
}
if ( distance < bestDistance ) {
bestSkeleton = skeleton;
bestDistance = distance;
bestFieldDifference = fieldDifference;
}
if ( distance == 0 ) {
bestFieldDifference = 0;
break;
}
}
if ( replaceZWithV && bestFieldDifference != -1 ) {
bestFieldDifference = 2;
}
return new DateIntervalFormat.BestMatchInfo(bestSkeleton, bestFieldDifference);

