public void showRecord(int recnum, Formatter f) if ((recnum < 0) || (recnum > recordTracker.length - 1)) {
f.format("%d out of range [0,%d]%n", recnum, recordTracker.length - 1);
return;
}
GridRecord gr = recordTracker[recnum];
if (hasEnsemble()) {
int ens = recnum / (nlevels * ntimes);
int tmp = recnum - ens *(nlevels * ntimes);
int time = tmp / nlevels;
int level = tmp % nlevels;
f.format("recnum=%d (record hash=%d) ens=%d time=%s(%d) level=%f(%d)%n", recnum, gr.hashCode(), ens, tcs.getCoord(time), time, vc.getCoord(level), level);
}  else {
int time = recnum / nlevels;
int level = recnum % nlevels;
f.format("recnum=%d (record hash=%d) time=%s(%d) level=%f(%d)%n", recnum, gr.hashCode(), tcs.getCoord(time), time, vc.getCoord(level), level);
}

Variable makeVariable(NetcdfFile ncfile, Group g, String useName, RandomAccessFile raf) assert records.size() > 0 : "no records for this variable";
this.nlevels = getVertNlevels();
this.ntimes = tcs.getNTimes();
if (vname == null) {
useName = StringUtil2.replace(useName, ' ', "_");
this.vname = useName;
}
Variable v = new Variable(ncfile, g, null, vname);
v.setDataType(DataType.FLOAT);
Formatter dims = new Formatter();
if (hasEnsemble()) {
dims.format("ens ");
}
dims.format("%s ", tcs.getName());
if (getVertIsUsed()) {
dims.format("%s ",  getVertName());
hasVert = true;
}
if (hcs.isLatLon()) {
dims.format("lat lon");
} else {
dims.format("y x");
}
v.setDimensions(dims.toString());
GridParameter param = lookup.getParameter(firstRecord);
if (param == null) return null;
String unit = param.getUnit();
if (unit == null) unit = "";
v.addAttribute(new Attribute("units", unit));
v.addAttribute(new Attribute("long_name", makeLongName()));
v.addAttribute(new Attribute("missing_value", lookup.getFirstMissingValue()));
if (!hcs.isLatLon()) {
if (GridServiceProvider.addLatLon)
v.addAttribute(new Attribute("coordinates", "lat lon"));
v.addAttribute(new Attribute("grid_mapping", hcs.getGridName()));
}
addExtraAttributes(param, v);
v.setSPobject(this);
int nrecs = ntimes * nlevels;
if (hasEnsemble()) nrecs *= ecs.getNEnsembles();
recordTracker = new GridRecord[nrecs];
if (log.isDebugEnabled()) log.debug("Record Assignment for Variable " + getName());
boolean oneSent = false;
for (GridRecord p : records) {
int level = getVertIndex(p);
if (!getVertIsUsed() && (level > 0)) {
log.warn("inconsistent level encoding=" + level);
level = 0;
}
int time = tcs.findIndex(p);
if (level < 0) {
log.warn("LEVEL NOT FOUND record; level=" + level + " time= "
+ time + " for " + getName() + " file="
+ ncfile.getLocation() + "\n" + "   "
+ getVertLevelName() + " (type=" + p.getLevelType1()
+ "," + p.getLevelType2() + ")  value="
+ p.getLevel1() + "," + p.getLevel2() + "\n");
getVertIndex(p);
continue;
}
if (time < 0) {
log.warn("TIME NOT FOUND record; level=" + level + " time= "
+ time + " for " + getName() + " file="
+ ncfile.getLocation() + "\n" + " validTime= "
+ p.getValidTime() + "\n");
tcs.findIndex(p);
continue;
}
oneSent = trackRecords(time, level, p, raf, oneSent);
}
records.clear();
return v;

public void showMissing(Formatter f) int count = 0, total = 0;
f.format("  %s%n", name);
for (int j = 0; j < nlevels; j++) {
f.format("   ");
for (int i = 0; i < ntimes; i++) {
boolean missing = recordTracker[i * nlevels + j] == null;
f.format("%s", missing ? "-" : "X");
if (missing) count++;
total++;
}
f.format("%n");
}
f.format("  MISSING= %d / %d for %s%n",count,total, name);

private GeoReferencedArray readHSlice(int level, int time, int ensemble, int runtime) if (dataState.grid.equals(lastGrid) && (time == lastTime) && (level == lastLevel) && (horizStride == lastStride)
&& (ensemble == lastEnsemble) && (runtime == lastRunTime))
return dataH;
SubsetParams subset = new SubsetParams();
if (level >= 0 && dataState.zaxis != null) {
double levelVal = dataState.zaxis.getCoordMidpoint(level);
subset.set(SubsetParams.vertCoord, levelVal);
}
if (time >= 0 && dataState.taxis != null) {
double timeVal = dataState.taxis.getCoordMidpoint(time);
CalendarDate date = dataState.taxis.makeDate(timeVal);
subset.set(SubsetParams.time, date);
}
if (runtime >= 0 && dataState.rtaxis != null) {
double rtimeVal = dataState.rtaxis.getCoordMidpoint(runtime);
CalendarDate date = dataState.rtaxis.makeDate(rtimeVal);
subset.set(SubsetParams.runtime, date);
}
if (ensemble >= 0 && dataState.ensaxis != null) {
double ensVal = dataState.ensaxis.getCoordMidpoint(ensemble);
subset.set(SubsetParams.ensCoord, ensVal);
}
if (horizStride != 1)
subset.setHorizStride( horizStride);
try {
dataH = dataState.grid.readData(subset);
geodata = dataH.getData().reduce();
} catch (IOException | InvalidRangeException e) {
e.printStackTrace();
}
lastGrid = dataState.grid;
lastTime = time;
lastLevel = level;
lastEnsemble = ensemble;
lastRunTime = runtime;
lastStride = horizStride;
return dataH;

private List<String> getFileNames() throws IOException if (fileNames == null) {
fileNames = new ArrayList<>();
timeStepsPerFile = tDim.getSize();
if (!isTemplate()) {
fileNames.add(getFullPath(getDataFile()));
} else {
long start = System.currentTimeMillis();
List<String> fileSet = new ArrayList<>();
String template = getDataFile();
if (GradsTimeDimension.hasTimeTemplate(template)) {
if (template.contains(GradsEnsembleDimension.ENS_TEMPLATE_ID)) {
templateType = ENS_TIME_TEMPLATE;
} else {
templateType = TIME_TEMPLATE;
}
} else {
if (template.contains(GradsEnsembleDimension.ENS_TEMPLATE_ID)) {
templateType = ENS_TEMPLATE;
} else {
templateType = TIME_TEMPLATE;
}
}
if (templateType == ENS_TEMPLATE) {
for (int e = 0; e < eDim.getSize(); e++) {
fileSet.add(
getFullPath(
eDim.replaceFileTemplate(template, e)));
}
} else if ((templateType == TIME_TEMPLATE)
|| (templateType == ENS_TIME_TEMPLATE)) {
int numens = (templateType == TIME_TEMPLATE)
? 1
: eDim.getSize();
for (int t = 0; t < tDim.getSize(); t++) {
for (int e = 0; e < numens; e++) {
String file = getFileName(e, t);
if (!fileSet.contains(file)) {
fileSet.add(file);
}
}
}
timeStepsPerFile = tDim.getSize()
/ (fileSet.size() / numens);
}
fileNames.addAll(fileSet);
}
for (String file : fileNames) {
File f = new File(file);
if (!f.exists()) {
log.error("File: " + f + " does not exist");
throw new IOException("File: " + f + " does not exist");
}
}
}
return fileNames;

