private boolean containsKey(K key, int keyGroupIndex, N namespace) checkKeyNamespacePreconditions(key, namespace);
Map<N, Map<K, S>> namespaceMap = getMapForKeyGroup(keyGroupIndex);
if (namespaceMap == null) {
return false;
}
Map<K, S> keyedMap = namespaceMap.get(namespace);
return keyedMap != null && keyedMap.containsKey(key);

@SuppressWarnings("unchecked") @Override public <N, S extends State> S getPartitionedState( final N namespace, final TypeSerializer<N> namespaceSerializer, final StateDescriptor<S, ?> stateDescriptor) throws Exception checkNotNull(namespace, "Namespace");
if (lastName != null && lastName.equals(stateDescriptor.getName())) {
lastState.setCurrentNamespace(namespace);
return (S) lastState;
}
InternalKvState<K, ?, ?> previous = keyValueStatesByName.get(stateDescriptor.getName());
if (previous != null) {
lastState = previous;
lastState.setCurrentNamespace(namespace);
lastName = stateDescriptor.getName();
return (S) previous;
}
final S state = getOrCreateKeyedState(namespaceSerializer, stateDescriptor);
final InternalKvState<K, N, ?> kvState = (InternalKvState<K, N, ?>) state;
lastName = stateDescriptor.getName();
lastState = kvState;
kvState.setCurrentNamespace(namespace);
return state;

private void setMapForKeyGroup(int keyGroupId, Map<N, Map<K, S>> map) try {
state[indexToOffset(keyGroupId)] = map;
} catch (ArrayIndexOutOfBoundsException e) {
throw new IllegalArgumentException("Key group index " + keyGroupId + " is out of range of key group " +
"range [" + keyGroupOffset + ", " + (keyGroupOffset + state.length) + ").");
}

@Override public boolean validate(Graph<K, VV, EV> graph) throws Exception DataSet<Tuple1<K>> edgeIds = graph.getEdges()
.flatMap(new MapEdgeIds<>()).distinct();
DataSet<K> invalidIds = graph.getVertices().coGroup(edgeIds).where(0)
.equalTo(0).with(new GroupInvalidIds<>()).first(1);
return invalidIds.map(new KToTupleMap<>()).count() == 0;

float refreshAndGetAvg() long total = 0;
int count = 0;
for (InputChannel channel : inputGate.getInputChannels().values()) {
if (channel instanceof RemoteInputChannel) {
RemoteInputChannel rc = (RemoteInputChannel) channel;
int size = rc.unsynchronizedGetNumberOfQueuedBuffers();
total += size;
++count;
}
}
return count == 0 ? 0 : total / (float) count;

private static <T> T filterBySupportedProperties( Class<T> factoryClass, Map<String, String> properties, List<TableFactory> foundFactories, List<TableFactory> classFactories) final List<String> plainGivenKeys = new LinkedList<>();
properties.keySet().forEach(k -> {
String key = k.replaceAll(".\\d+", ".#");
if (!plainGivenKeys.contains(key)) {
plainGivenKeys.add(key);
}
});
Optional<String> lastKey = Optional.empty();
List<TableFactory> supportedFactories = new LinkedList<>();
for (TableFactory factory: classFactories) {
Set<String> requiredContextKeys = normalizeContext(factory).keySet();
Tuple2<List<String>, List<String>> tuple2 = normalizeSupportedProperties(factory);
List<String> givenContextFreeKeys = plainGivenKeys.stream()
.filter(p -> !requiredContextKeys.contains(p))
.collect(Collectors.toList());
List<String> givenFilteredKeys = filterSupportedPropertiesFactorySpecific(
factory,
givenContextFreeKeys);
Boolean allTrue = true;
for (String k: givenFilteredKeys) {
lastKey = Optional.of(k);
if (!(tuple2.f0.contains(k) || tuple2.f1.stream().anyMatch(p -> k.startsWith(p)))) {
allTrue = false;
break;
}
}
if (allTrue) {
supportedFactories.add(factory);
}
}
if (supportedFactories.isEmpty() && classFactories.size() == 1 && lastKey.isPresent()) {
TableFactory factory = classFactories.get(0);
Tuple2<List<String>, List<String>> tuple2 = normalizeSupportedProperties(factory);
String errorMessage = String.format(
"The matching factory '%s' doesn't support '%s'.\n\nSupported properties of " +
"this factory are:\n%s",
factory.getClass().getName(),
lastKey.get(),
String.join("\n", tuple2.f0));
throw new NoMatchingTableFactoryException(
errorMessage,
factoryClass,
foundFactories,
properties);
} else if (supportedFactories.isEmpty()) {
throw new NoMatchingTableFactoryException(
"No factory supports all properties.",
factoryClass,
foundFactories,
properties);
} else if (supportedFactories.size() > 1) {
throw new AmbiguousTableFactoryException(
supportedFactories,
factoryClass,
foundFactories,
properties);
}
return (T) supportedFactories.get(0);

