readResponseHeaders(state, conn);
processResponseHeaders(state, conn);
int status = this.statusLine.getStatusCode();
if ((status >= 100) && (status < 200)) {
if (LOG.isInfoEnabled()) {
LOG.info("Discarding unexpected response: " + this.statusLine.toString());
}
this.statusLine = null;
}
}
readResponseBody(state, conn);
processResponseBody(state, conn);

protected void readStatusLine(HttpState state, HttpConnection conn) throws IOException, HttpException LOG.trace("enter HttpMethodBase.readStatusLine(HttpState, HttpConnection)");
final int maxGarbageLines = getParams().
getIntParameter(HttpMethodParams.STATUS_LINE_GARBAGE_LIMIT, Integer.MAX_VALUE);
int count = 0;
String s;
do {
s = conn.readLine(getParams().getHttpElementCharset());
if (s == null && count == 0) {
throw new NoHttpResponseException("The server " + conn.getHost() +
" failed to respond");
}
if (s != null && StatusLine.startsWithHTTP(s)) {
break;
} else if (s == null || count >= maxGarbageLines) {
throw new ProtocolException("The server " + conn.getHost() +
" failed to respond with a valid HTTP response");
}
count++;
} while(true);
statusLine = new StatusLine(s);
String versionStr = statusLine.getHttpVersion();
if (getParams().isParameterFalse(HttpMethodParams.UNAMBIGUOUS_STATUS_LINE)
&& versionStr.equals("HTTP")) {
getParams().setVersion(HttpVersion.HTTP_1_0);
if (LOG.isWarnEnabled()) {
LOG.warn("Ambiguous status line (HTTP protocol version missing):" +
statusLine.toString());
}
} else {
this.effectiveVersion = HttpVersion.parse(versionStr);
}

void pluginCompleted(Plugin plugin) PluginStats pluginStats = mapPluginStats.get(plugin.getId());
if (pluginStats == null) {
return;
}
StringBuilder sb = new StringBuilder();
if (isStop()) {
sb.append("stopped host/plugin ");
} else if (pluginStats.isSkipped()) {
sb.append("skipped plugin ");
String reason = pluginStats.getSkippedReason();
if (reason != null) {
sb.append('[').append(reason).append("] ");
}
} else {
sb.append("completed host/plugin ");
}
sb.append(hostAndPort).append(" | ").append(plugin.getCodeName());
long startTimeMillis = pluginStats.getStartTime();
long diffTimeMillis = System.currentTimeMillis() - startTimeMillis;
String diffTimeString = decimalFormat.format(diffTimeMillis / 1000.0);
sb.append(" in ").append(diffTimeString).append('s');
sb.append(" with ").append(pluginStats.getMessageCount()).append(" message(s) sent");
sb.append(" and ").append(pluginStats.getAlertCount()).append(" alert(s) raised.");
log.info(sb.toString());
pluginFactory.setRunningPluginCompleted(plugin);
notifyHostProgress(null);
pluginStats.setProgress(nodeInScopeCount);

public boolean isSkipped(Plugin plugin) PluginStats pluginStats = mapPluginStats.get(plugin.getId());
if (pluginStats != null && pluginStats.isSkipped()) {
return true;
}
if (plugin.getTimeFinished() == null && stopReason != null) {
this.pluginSkipped(plugin, stopReason);
return true;
} else if (this.scannerParam.getMaxRuleDurationInMins() > 0 && plugin.getTimeStarted() != null) {
long endtime = System.currentTimeMillis();
if (plugin.getTimeFinished() != null) {
endtime = plugin.getTimeFinished().getTime();
}
if (endtime - plugin.getTimeStarted().getTime() >
TimeUnit.MINUTES.toMillis(this.scannerParam.getMaxRuleDurationInMins())) {
this.pluginSkipped(plugin,
Constant.messages.getString("ascan.progress.label.skipped.reason.maxRule"));
return true;
}
}
return false;

