@Override public <T extends IChemObject> T read(T object) throws CDKException @inheritDoc} */
public <T extends IChemObject> T read(T object) throws CDKException {
final String[] expected_columns = {"NO.", "ATOM", "X", "Y", "Z"};
StringBuffer eigenvalues = new StringBuffer();
if (object instanceof IAtomContainer) {
IAtomContainer container = (IAtomContainer) object;
try {
String line = input.readLine();
while (line != null) {
if (line.indexOf("****  MAX. NUMBER OF ATOMS ALLOWED") > -1) throw new CDKException(line);
if (line.indexOf("TO CONTINUE CALCULATION SPECIFY \"GEO-OK\"") > -1) throw new CDKException(line);
if ("CARTESIAN COORDINATES".equals(line.trim())) {
IAtomContainer atomcontainer = ((IAtomContainer) object);
input.readLine();
line = input.readLine();
String[] columns = line.trim().split(" +");
int okCols = 0;
if (columns.length == expected_columns.length)
for (int i = 0; i < expected_columns.length; i++)
okCols += (columns[i].equals(expected_columns[i])) ? 1 : 0;
if (okCols < expected_columns.length) continue;
input.readLine();
int atomIndex = 0;
while (!line.trim().isEmpty()) {
line = input.readLine();
StringTokenizer tokenizer = new StringTokenizer(line);
int token = 0;
IAtom atom = null;
double[] point3d = new double[3];
while (tokenizer.hasMoreTokens()) {
String tokenStr = tokenizer.nextToken();
switch (token) {
case 0: {
atomIndex = Integer.parseInt(tokenStr) - 1;
if (atomIndex < atomcontainer.getAtomCount()) {
atom = atomcontainer.getAtom(atomIndex);
} else
atom = null;
break;
}
case 1: {
if ((atom != null) && (!tokenStr.equals(atom.getSymbol()))) atom = null;
break;
}
case 2: {
point3d[0] = Double.parseDouble(tokenStr);
break;
}
case 3: {
point3d[1] = Double.parseDouble(tokenStr);
break;
}
case 4: {
point3d[2] = Double.parseDouble(tokenStr);
if (atom != null) atom.setPoint3d(new Point3d(point3d));
break;
}
}
token++;
if (atom == null) break;
}
if ((atom == null) || ((atomIndex + 1) >= atomcontainer.getAtomCount())) break;
}
} else if (line.indexOf(Mopac7Reader.eigenvalues) >= 0) {
line = input.readLine();
line = input.readLine();
while (!line.trim().equals("")) {
eigenvalues.append(line);
line = input.readLine();
}
container.setProperty(Mopac7Reader.eigenvalues, eigenvalues.toString());
} else
for (int i = 0; i < parameters.length; i++)
if (line.indexOf(parameters[i]) >= 0) {
String value = line.substring(line.lastIndexOf('=') + 1).trim();
value = value.replaceAll(Mopac7Reader.units[i], "").trim();
int pos = value.indexOf(' ');
if (pos >= 0) value = value.substring(0, pos - 1);
container.setProperty(parameters[i], value.trim());
break;
}
line = input.readLine();
}
calcHomoLumo(container);
return (T) container;
} catch (IOException exception) {
throw new CDKException(exception.getMessage());
}
} else
return null;

public void process(IAtomContainer molecule) throws CDKException if (descriptors == null || speclist == null) throw new CDKException("Descriptors have not been instantiated");
if (speclist.size() != descriptors.size())
throw new CDKException("Number of specs and descriptors do not match");
for (int i = 0; i < descriptors.size(); i++) {
IDescriptor descriptor = descriptors.get(i);
if (descriptor instanceof IMolecularDescriptor) {
DescriptorValue value = ((IMolecularDescriptor) descriptor).calculate(molecule);
if (value.getException() == null)
molecule.setProperty(speclist.get(i), value);
else {
logger.error("Could not calculate descriptor value for: ", descriptor.getClass().getName());
logger.debug(value.getException());
}
logger.debug("Calculated molecular descriptors...");
} else if (descriptor instanceof IAtomicDescriptor) {
Iterator atoms = molecule.atoms().iterator();
while (atoms.hasNext()) {
IAtom atom = (IAtom) atoms.next();
DescriptorValue value = ((IAtomicDescriptor) descriptor).calculate(atom, molecule);
if (value.getException() == null)
atom.setProperty(speclist.get(i), value);
else {
logger.error("Could not calculate descriptor value for: ", descriptor.getClass().getName());
logger.debug(value.getException());
}
}
logger.debug("Calculated atomic descriptors...");
} else if (descriptor instanceof IBondDescriptor) {
Iterator bonds = molecule.bonds().iterator();
while (bonds.hasNext()) {
IBond bond = (IBond) bonds.next();
DescriptorValue value = ((IBondDescriptor) descriptor).calculate(bond, molecule);
if (value.getException() == null)
bond.setProperty(speclist.get(i), value);
else {
logger.error("Could not calculate descriptor value for: ", descriptor.getClass().getName());
logger.debug(value.getException());
}
}
logger.debug("Calculated bond descriptors...");
} else {
logger.debug("Unknown descriptor type for: ", descriptor.getClass().getName());
}
}

@Override public void set(int index, boolean value) int i = Arrays.binarySearch(trueBits, index);
if (i >= 0 && !value) {
int[] tmp = new int[trueBits.length - 1];
System.arraycopy(trueBits, 0, tmp, 0, i);
System.arraycopy(trueBits, i + 1, tmp, i, trueBits.length - i - 1);
trueBits = tmp;
}
else if (i < 0 && value) {
int[] tmp = new int[trueBits.length + 1];
System.arraycopy(trueBits, 0, tmp, 0, trueBits.length);
tmp[tmp.length - 1] = index;
trueBits = tmp;
Arrays.sort(trueBits);
}

public List<Double> getRDBEValue(IMolecularFormula formula) List<Double> RDBEList = new ArrayList<Double>();
int nE = 0;
List<Integer> nV = new ArrayList<Integer>();
for (Iterator<IIsotope> it = formula.isotopes().iterator(); it.hasNext();) {
IIsotope isotope = it.next();
int[] valence = getOxidationState(formula.getBuilder().newInstance(IAtom.class, isotope.getSymbol()));
if (valence.length != 1) {
for (int i = 0; i < valence.length; i++) {
nV.add(valence[i]);
}
nE += MolecularFormulaManipulator.getElementCount(formula,
formula.getBuilder().newInstance(IElement.class, isotope.getSymbol()));
}
}
double RDBE = 0;
if (nE == 0) {
for (Iterator<IIsotope> it = formula.isotopes().iterator(); it.hasNext();) {
IIsotope isotope = it.next();
int[] valence = getOxidationState(formula.getBuilder().newInstance(IAtom.class, isotope.getSymbol()));
double value = (valence[0] - 2) * formula.getIsotopeCount(isotope) / 2.0;
RDBE += value;
}
RDBE += 1;
RDBEList.add(RDBE);
} else {
double RDBE_1 = 0;
for (Iterator<IIsotope> it = formula.isotopes().iterator(); it.hasNext();) {
IIsotope isotope = it.next();
int[] valence = getOxidationState(formula.getBuilder().newInstance(IAtom.class, isotope.getSymbol()));
double value = (valence[0] - 2) * formula.getIsotopeCount(isotope) * 0.5;
RDBE_1 += value;
}
String[] valences = new String[nV.size()];
for (int i = 0; i < valences.length; i++)
valences[i] = Integer.toString(nV.get(i));
Combinations c = new Combinations(valences, nE);
while (c.hasMoreElements()) {
double RDBE_int = 0.0;
Object[] combo = (Object[]) c.nextElement();
for (int i = 0; i < combo.length; i++) {
int value = (Integer.parseInt((String) combo[i]) - 2) / 2;
RDBE_int += value;
}
RDBE = 1 + RDBE_1 + RDBE_int;
RDBEList.add(RDBE);
}
}
return RDBEList;

private DoubleArrayResult arrangingEnergy(ArrayList<Double> array) DoubleArrayResult results = new DoubleArrayResult();
int count = array.size();
for (int i = 0; i < count; i++) {
double min = array.get(0);
int pos = 0;
for (int j = 0; j < array.size(); j++) {
double value = array.get(j);
if (value < min) {
min = value;
pos = j;
}
}
array.remove(pos);
results.add(min);
}
return results;

public IMolecularFormulaSet generate(double mass) if (mass <= 0.0) {
logger.error("Proposed mass is not valid: ", mass);
return null;
}
IMolecularFormula minimalMF = MolecularFormulaRangeManipulator.getMinimalFormula(mfRange, builder);
IMolecularFormula maximalMF = MolecularFormulaRangeManipulator.getMaximalFormula(mfRange, builder);
double massMim = MolecularFormulaManipulator.getTotalExactMass(minimalMF) - tolerance;
double massMap = MolecularFormulaManipulator.getTotalExactMass(maximalMF) + tolerance;
if (massMim > mass || massMap < mass) {
logger.error("Proposed mass is out of the range: ", mass);
return null;
}
IMolecularFormulaSet molecularFormulaSet = builder.newInstance(IMolecularFormulaSet.class);
int[][] matrix = this.matrix_Base;
int numberElements = mfRange.getIsotopeCount();
List<IIsotope> isotopes_TO = new ArrayList<IIsotope>();
Iterator<IIsotope> isIt = mfRange.isotopes().iterator();
while (isIt.hasNext())
isotopes_TO.add(isIt.next());
isotopes_TO = orderList(isotopes_TO);
for (int i = 0; i < matrix.length; i++) {
int[] value_In = new int[numberElements];
for (int j = 0; j < numberElements; j++) {
if (matrix[i][j] == 0)
value_In[j] = 0;
else
value_In[j] = 1;
}
int count_E = 0;
ArrayList<Integer> elem_Pos = new ArrayList<Integer>();
for (int j = 0; j < matrix[1].length; j++)
if (value_In[j] != 0) {
count_E++;
elem_Pos.add(j);
}
boolean flag = true;
int possChan = 0;
String lastMFString = "";
while (flag) {
boolean flagBreak = false;
for (int j = 0; j < matrix[1].length; j++) {
int min = mfRange.getIsotopeCountMin(isotopes_TO.get(j));
if (value_In[j] == 0) if (min != 0) flagBreak = true;
}
if (flagBreak) break;
int occurence = getMaxOccurence(mass, elem_Pos.get(possChan).intValue(), value_In, isotopes_TO);
if (occurence == 0) break;
int maxx = mfRange.getIsotopeCountMax(isotopes_TO.get(elem_Pos.get(possChan).intValue()));
int minn = mfRange.getIsotopeCountMin(isotopes_TO.get(elem_Pos.get(possChan).intValue()));
if (occurence < minn | maxx < occurence) {
if (possChan < elem_Pos.size() - 1) {
if (maxx < occurence) value_In[elem_Pos.get(possChan).intValue()] = maxx;
possChan++;
} else {
boolean foundZ = false;
for (int z = possChan - 1; z >= 0; z--) {
if (value_In[elem_Pos.get(z).intValue()] != 1) {
possChan = z;
foundZ = true;
int newValue = value_In[elem_Pos.get(possChan).intValue()] - 1;
value_In[elem_Pos.get(possChan).intValue()] = newValue;
for (int j = possChan + 1; j < elem_Pos.size(); j++) {
int p = elem_Pos.get(j).intValue();
value_In[p] = 1;
}
possChan++;
break;
}
}
if (!foundZ) break;
}
continue;
}
value_In[elem_Pos.get(possChan).intValue()] = occurence;
double massT = calculateMassT(isotopes_TO, value_In);
double diff_new = Math.abs(mass - (massT));
if (diff_new < tolerance) {
IMolecularFormula myMF = getFormula(isotopes_TO, value_In);
String newMFString = MolecularFormulaManipulator.getString(myMF);
if (!newMFString.equals(lastMFString)) {
molecularFormulaSet.addMolecularFormula(myMF);
lastMFString = newMFString;
}
}
if (count_E == 1)
break;
if (possChan < elem_Pos.size() - 1) {
possChan++;
} else {
boolean foundZ = false;
for (int z = possChan - 1; z >= 0; z--) {
if (value_In[elem_Pos.get(z).intValue()] != 1) {
possChan = z;
foundZ = true;
int newValue = value_In[elem_Pos.get(possChan).intValue()] - 1;
value_In[elem_Pos.get(possChan).intValue()] = newValue;
for (int j = possChan + 1; j < elem_Pos.size(); j++) {
int p = elem_Pos.get(j).intValue();
value_In[p] = 1;
}
possChan++;
break;
}
}
if (!foundZ) break;
}
}
}
return returnOrdered(mass, molecularFormulaSet);

