public Clustering<PrototypeModel<O>> run(Relation<O> relation) RangeQuery<O> rq = relation.getRangeQuery(getDistanceFunction(), threshold);
ModifiableDBIDs seen = DBIDUtil.newHashSet(relation.size());
Clustering<PrototypeModel<O>> clustering = new Clustering<>("Prototype clustering", "prototype-clustering");
int queries = 0;
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Leader clustering", relation.size(), LOG) : null;
for(DBIDIter it = relation.iterDBIDs(); it.valid() && seen.size() < relation.size(); it.advance()) {
if(seen.contains(it)) {
continue;
}
DoubleDBIDList res = rq.getRangeForDBID(it, threshold);
++queries;
ModifiableDBIDs ids = DBIDUtil.newArray(res.size());
for(DBIDIter cand = res.iter(); cand.valid(); cand.advance()) {
if(seen.add(cand)) {
LOG.incrementProcessed(prog);
ids.add(cand);
}
}
assert (ids.size() > 0 && ids.contains(it));
PrototypeModel<O> mod = new SimplePrototypeModel<>(relation.get(it));
clustering.addToplevelCluster(new Cluster<>(ids, mod));
}
LOG.statistics(new LongStatistic(this.getClass().getName() + ".queries", queries));
LOG.ensureCompleted(prog);
return clustering;

public ArrayDBIDs topologicalSort() ArrayModifiableDBIDs ids = DBIDUtil.newArray(this.ids);
if(mergeOrder != null) {
ids.sort(new DataStoreUtil.AscendingByIntegerDataStore(mergeOrder));
WritableDoubleDataStore maxheight = computeMaxHeight();
ids.sort(new Sorter(maxheight));
maxheight.destroy();
}
else {
ids.sort(new DataStoreUtil.DescendingByDoubleDataStoreAndId(parentDistance));
}
final int size = ids.size();
ModifiableDBIDs seen = DBIDUtil.newHashSet(size);
ArrayModifiableDBIDs order = DBIDUtil.newArray(size);
DBIDVar v1 = DBIDUtil.newVar(), prev = DBIDUtil.newVar();
for(DBIDIter it = ids.iter(); it.valid(); it.advance()) {
if(!seen.add(it)) {
continue;
}
final int begin = order.size();
order.add(it);
prev.set(it);
while(!DBIDUtil.equal(prev, parent.assignVar(prev, v1))) {
if(!seen.add(v1)) {
break;
}
order.add(v1);
prev.set(v1);
}
for(int i = begin, j = order.size() - 1; i < j; i++, j--) {
order.swap(i, j);
}
}
for(int i = 0, j = size - 1; i < j; i++, j--) {
order.swap(i, j);
}
return order;

