private void insertNode(PatriciaNode<V> node) PatriciaNode<V> current = root.getLeft();
PatriciaNode<V> parent = root;
while (parent.getBit() < current.getBit() && current.getBit() < node.getBit()) {
parent = current;
if (!keyMapper.isSet(current.getBit(), node.getKey())) {
current = current.getLeft();
} else {
current = current.getRight();
}
}
if (!keyMapper.isSet(node.getBit(), node.getKey())) {
node.setLeft(node);
node.setRight(current);
} else {
node.setLeft(current);
node.setRight(node);
}
if (!keyMapper.isSet(parent.getBit(), node.getKey())) {
parent.setLeft(node);
} else {
parent.setRight(node);
}

@Override public V put(String key, V value) if (key == null) {
throw new NullPointerException("Key can not be null");
}
if (key.equals("")) {
PatriciaNode<V> node = new PatriciaNode<>(key, value, -1);
node.setValue(value);
root.setRight(node);
entries++;
return value;
}
PatriciaNode<V> nearest = findNearestNode(key);
if (key.equals(nearest.getKey())) {
nearest.setValue(value);
return value;
}
int bit = findFirstDifferingBit(key, nearest.getKey());
PatriciaNode<V> node = new PatriciaNode<>(key, value, bit);
insertNode(node);
entries++;
return value;

@Override public Set<Entry<String, V>> entrySet() HashMap<String, V> entries = new HashMap<>();
entriesR(root.getLeft(), -1, entries);
return entries.entrySet();

@Override public V get(Object key) if (key == null) {
throw new NullPointerException("Key can not be null");
}
if (!(key instanceof String)) {
throw new ClassCastException("Only String keys are supported -- got " + key.getClass());
}
if (key.equals("")) {
if (root.getRight() == null) {
return null;
} else {
return root.getRight().getValue();
}
}
PatriciaNode<V> nearest = findNearestNode((String) key);
if (key.equals(nearest.getKey())) {
return nearest.getValue();
} else {
return null;
}

public Tree ancestor(int height, Tree root) if (height < 0) {
throw new IllegalArgumentException("ancestor: height cannot be negative");
}
if (height == 0) {
return this;
}
Tree par = parent(root);
if (par == null) {
return null;
}
return par.ancestor(height - 1, root);

private PatriciaNode<V> findNearestNode(String key) PatriciaNode<V> current = root.getLeft();
PatriciaNode<V> parent = root;
while (parent.getBit() < current.getBit()) {
parent = current;
if (!keyMapper.isSet(current.getBit(), key)) {
current = current.getLeft();
} else {
current = current.getRight();
}
}
return current;

public void insert(INDArray point) if (!point.isVector() || point.length() != dims)
throw new IllegalArgumentException("Point must be a vector of length " + dims);
if (root == null) {
root = new KDNode(point);
rect = new HyperRect(HyperRect.point(point));
} else {
int disc = 0;
KDNode node = root;
KDNode insert = new KDNode(point);
int successor;
while (true) {
INDArray pt = node.getPoint();
INDArray countEq = Nd4j.getExecutioner().execAndReturn(new Any(pt.neq(point))).z();
if (countEq.getInt(0) == 0) {
return;
} else {
successor = successor(node, point, disc);
KDNode child;
if (successor < 1)
child = node.getLeft();
else
child = node.getRight();
if (child == null)
break;
disc = (disc + 1) % dims;
node = child;
}
}
if (successor < 1)
node.setLeft(insert);
else
node.setRight(insert);
rect.enlargeTo(point);
insert.setParent(node);
}
size++;

