Symbol findImmediateMemberType(Env<AttrContext> env, Type site, Name name, TypeSymbol c) for (Symbol sym : c.members().getSymbolsByName(name)) {
if (sym.kind == TYP) {
return isAccessible(env, site, sym)
? sym
: new AccessError(env, site, sym);
}
}
return typeNotFound;

Symbol findInheritedMemberType(Env<AttrContext> env, Type site, Name name, TypeSymbol c) Symbol bestSoFar = typeNotFound;
Symbol sym;
Type st = types.supertype(c.type);
if (st != null && st.hasTag(CLASS)) {
sym = findMemberType(env, site, name, st.tsym);
bestSoFar = bestOf(bestSoFar, sym);
}
for (List<Type> l = types.interfaces(c.type);
bestSoFar.kind != AMBIGUOUS && l.nonEmpty();
l = l.tail) {
sym = findMemberType(env, site, name, l.head.tsym);
if (!bestSoFar.kind.isResolutionError() &&
!sym.kind.isResolutionError() &&
sym.owner != bestSoFar.owner)
bestSoFar = new AmbiguityError(bestSoFar, sym);
else
bestSoFar = bestOf(bestSoFar, sym);
}
return bestSoFar;

Symbol findIdentInType(Env<AttrContext> env, Type site, Name name, KindSelector kind) Symbol bestSoFar = typeNotFound;
Symbol sym;
if (kind.contains(KindSelector.VAL)) {
sym = findField(env, site, name, site.tsym);
if (sym.exists()) return sym;
else bestSoFar = bestOf(bestSoFar, sym);
}
if (kind.contains(KindSelector.TYP)) {
sym = findMemberType(env, site, name, site.tsym);
if (sym.exists()) return sym;
else bestSoFar = bestOf(bestSoFar, sym);
}
return bestSoFar;

Symbol findField(Env<AttrContext> env, Type site, Name name, TypeSymbol c) while (c.type.hasTag(TYPEVAR))
c = c.type.getUpperBound().tsym;
Symbol bestSoFar = varNotFound;
Symbol sym;
for (Symbol s : c.members().getSymbolsByName(name)) {
if (s.kind == VAR && (s.flags_field & SYNTHETIC) == 0) {
return isAccessible(env, site, s)
? s : new AccessError(env, site, s);
}
}
Type st = types.supertype(c.type);
if (st != null && (st.hasTag(CLASS) || st.hasTag(TYPEVAR))) {
sym = findField(env, site, name, st.tsym);
bestSoFar = bestOf(bestSoFar, sym);
}
for (List<Type> l = types.interfaces(c.type);
bestSoFar.kind != AMBIGUOUS && l.nonEmpty();
l = l.tail) {
sym = findField(env, site, name, l.head.tsym);
if (bestSoFar.exists() && sym.exists() &&
sym.owner != bestSoFar.owner)
bestSoFar = new AmbiguityError(bestSoFar, sym);
else
bestSoFar = bestOf(bestSoFar, sym);
}
return bestSoFar;

public VarSymbol resolveInternalField(DiagnosticPosition pos, Env<AttrContext> env, Type site, Name name) Symbol sym = findField(env, site, name, site.tsym);
if (sym.kind == VAR) return (VarSymbol)sym;
else throw new FatalError(
diags.fragment("fatal.err.cant.locate.field",
name));

Symbol resolveSelf(DiagnosticPosition pos, Env<AttrContext> env, TypeSymbol c, Name name) Env<AttrContext> env1 = env;
boolean staticOnly = false;
while (env1.outer != null) {
if (isStatic(env1)) staticOnly = true;
if (env1.enclClass.sym == c) {
Symbol sym = env1.info.scope.findFirst(name);
if (sym != null) {
if (staticOnly) sym = new StaticError(sym);
return accessBase(sym, pos, env.enclClass.sym.type,
name, true);
}
}
if ((env1.enclClass.sym.flags() & STATIC) != 0) staticOnly = true;
env1 = env1.outer;
}
if (c.isInterface() &&
name == names._super && !isStatic(env) &&
types.isDirectSuperInterface(c, env.enclClass.sym)) {
for (Type t : pruneInterfaces(env.enclClass.type)) {
if (t.tsym == c) {
env.info.defaultSuperCallSite = t;
return new VarSymbol(0, names._super,
types.asSuper(env.enclClass.type, c), env.enclClass.sym);
}
}
for (Type i : types.directSupertypes(env.enclClass.type)) {
if (i.tsym.isSubClass(c, types) && i.tsym != c) {
log.error(pos, "illegal.default.super.call", c,
diags.fragment("redundant.supertype", c, i));
return syms.errSymbol;
}
}
Assert.error();
}
log.error(pos, "not.encl.class", c);
return syms.errSymbol;

public MethodSymbol resolveInternalMethod(DiagnosticPosition pos, Env<AttrContext> env, Type site, Name name, List<Type> argtypes, List<Type> typeargtypes) MethodResolutionContext resolveContext = new MethodResolutionContext();
resolveContext.internalResolution = true;
Symbol sym = resolveQualifiedMethod(resolveContext, pos, env, site.tsym,
site, name, argtypes, typeargtypes);
if (sym.kind == MTH) return (MethodSymbol)sym;
else throw new FatalError(
diags.fragment("fatal.err.cant.locate.meth",
name));

Symbol findType(Env<AttrContext> env, Name name) if (name == names.empty)
return typeNotFound;
Symbol bestSoFar = typeNotFound;
Symbol sym;
boolean staticOnly = false;
for (Env<AttrContext> env1 = env; env1.outer != null; env1 = env1.outer) {
if (isStatic(env1)) staticOnly = true;
final Symbol tyvar = findTypeVar(env1, name, staticOnly);
sym = findImmediateMemberType(env1, env1.enclClass.sym.type,
name, env1.enclClass.sym);
if (tyvar != typeNotFound) {
if (env.baseClause || sym == typeNotFound ||
(tyvar.kind == TYP && tyvar.exists() &&
tyvar.owner.kind == MTH)) {
return tyvar;
}
}
if (sym == typeNotFound)
sym = findInheritedMemberType(env1, env1.enclClass.sym.type,
name, env1.enclClass.sym);
if (staticOnly && sym.kind == TYP &&
sym.type.hasTag(CLASS) &&
sym.type.getEnclosingType().hasTag(CLASS) &&
env1.enclClass.sym.type.isParameterized() &&
sym.type.getEnclosingType().isParameterized())
return new StaticError(sym);
else if (sym.exists()) return sym;
else bestSoFar = bestOf(bestSoFar, sym);
JCClassDecl encl = env1.baseClause ? (JCClassDecl)env1.tree : env1.enclClass;
if ((encl.sym.flags() & STATIC) != 0)
staticOnly = true;
}
if (!env.tree.hasTag(IMPORT)) {
sym = findGlobalType(env, env.toplevel.namedImportScope, name, namedImportScopeRecovery);
if (sym.exists()) return sym;
else bestSoFar = bestOf(bestSoFar, sym);
sym = findGlobalType(env, env.toplevel.packge.members(), name, noRecovery);
if (sym.exists()) return sym;
else bestSoFar = bestOf(bestSoFar, sym);
sym = findGlobalType(env, env.toplevel.starImportScope, name, starImportScopeRecovery);
if (sym.exists()) return sym;
else bestSoFar = bestOf(bestSoFar, sym);
}
return bestSoFar;

Symbol resolveDiamond(DiagnosticPosition pos, Env<AttrContext> env, Type site, List<Type> argtypes, List<Type> typeargtypes) return lookupMethod(env, pos, site.tsym, resolveMethodCheck,
new BasicLookupHelper(names.init, site, argtypes, typeargtypes) {
@Override
Symbol doLookup(Env<AttrContext> env, MethodResolutionPhase phase) {
return findDiamond(env, site, argtypes, typeargtypes,
phase.isBoxingRequired(),
phase.isVarargsRequired());
}
@Override
Symbol access(Env<AttrContext> env, DiagnosticPosition pos, Symbol location, Symbol sym) {
if (sym.kind.isResolutionError()) {
if (sym.kind != WRONG_MTH &&
sym.kind != WRONG_MTHS) {
sym = super.access(env, pos, location, sym);
} else {
final JCDiagnostic details = sym.kind == WRONG_MTH ?
((InapplicableSymbolError)sym.baseSymbol()).errCandidate().snd :
null;
sym = new DiamondError(sym, currentResolutionContext);
sym = accessMethod(sym, pos, site, names.init, true, argtypes, typeargtypes);
env.info.pendingResolutionPhase = currentResolutionContext.step;
}
}
return sym;
}});

Symbol findIdentInPackage(Env<AttrContext> env, TypeSymbol pck, Name name, KindSelector kind) Name fullname = TypeSymbol.formFullName(name, pck);
Symbol bestSoFar = typeNotFound;
if (kind.contains(KindSelector.TYP)) {
RecoveryLoadClass recoveryLoadClass =
allowModules && !kind.contains(KindSelector.PCK) &&
!pck.exists() && !env.info.isSpeculative ?
doRecoveryLoadClass : noRecovery;
Symbol sym = loadClass(env, fullname, recoveryLoadClass);
if (sym.exists()) {
if (name == sym.name) return sym;
}
else bestSoFar = bestOf(bestSoFar, sym);
}
if (kind.contains(KindSelector.PCK)) {
return lookupPackage(env, fullname);
}
return bestSoFar;

private IChemFile readChemFile(IChemFile file) IChemSequence chemSequence = file.getBuilder().newInstance(IChemSequence.class);
int number_of_atoms = 0;
StringTokenizer tokenizer;
try {
String line = input.readLine();
while (input.ready() && line != null) {
tokenizer = new StringTokenizer(line, "\t ,;");
String token = tokenizer.nextToken();
number_of_atoms = Integer.parseInt(token);
String info = input.readLine();
IChemModel chemModel = file.getBuilder().newInstance(IChemModel.class);
IAtomContainerSet setOfMolecules = file.getBuilder().newInstance(IAtomContainerSet.class);
IAtomContainer m = file.getBuilder().newInstance(IAtomContainer.class);
m.setTitle(info);
for (int i = 0; i < number_of_atoms; i++) {
line = input.readLine();
if (line == null) break;
if (line.startsWith("#") && line.length() > 1) {
Object comment = m.getProperty(CDKConstants.COMMENT);
if (comment == null) {
comment = "";
}
comment = comment.toString() + line.substring(1).trim();
m.setProperty(CDKConstants.COMMENT, comment);
logger.debug("Found and set comment: ", comment);
i--;
} else {
double x = 0.0f, y = 0.0f, z = 0.0f;
double charge = 0.0f;
tokenizer = new StringTokenizer(line, "\t ,;");
int fields = tokenizer.countTokens();
if (fields < 4) {
} else {
String atomtype = tokenizer.nextToken();
x = (new Double(tokenizer.nextToken())).doubleValue();
y = (new Double(tokenizer.nextToken())).doubleValue();
z = (new Double(tokenizer.nextToken())).doubleValue();
if (fields == 8) charge = (new Double(tokenizer.nextToken())).doubleValue();
IAtom atom = file.getBuilder().newInstance(IAtom.class, atomtype, new Point3d(x, y, z));
atom.setCharge(charge);
m.addAtom(atom);
}
}
}
setOfMolecules.addAtomContainer(m);
chemModel.setMoleculeSet(setOfMolecules);
chemSequence.addChemModel(chemModel);
line = input.readLine();
}
file.addChemSequence(chemSequence);
} catch (IOException e) {
file = null;
logger.error("Error while reading file: ", e.getMessage());
logger.debug(e);
}
return file;

private void readPartialCharges(IChemModel model) throws CDKException, IOException logger.info("Reading partial atomic charges");
IAtomContainerSet moleculeSet = model.getMoleculeSet();
IAtomContainer molecule = moleculeSet.getAtomContainer(0);
String line = input.readLine();
while (input.ready()) {
line = input.readLine();
logger.debug("Read charge block line: " + line);
if ((line == null) || (line.indexOf("Sum of Mulliken charges") >= 0)) {
logger.debug("End of charge block found");
break;
}
StringReader sr = new StringReader(line);
StreamTokenizer tokenizer = new StreamTokenizer(sr);
if (tokenizer.nextToken() == StreamTokenizer.TT_NUMBER) {
int atomCounter = (int) tokenizer.nval;
tokenizer.nextToken();
double charge = 0.0;
if (tokenizer.nextToken() == StreamTokenizer.TT_NUMBER) {
charge = (double) tokenizer.nval;
logger.debug("Found charge for atom " + atomCounter + ": " + charge);
} else {
throw new CDKException("Error while reading charge: expected double.");
}
IAtom atom = molecule.getAtom(atomCounter - 1);
atom.setCharge(charge);
}
}

public void readBondBlock(IAtomContainer readData) throws CDKException logger.info("Reading BOND block");
boolean foundEND = false;
while (isReady() && !foundEND) {
String command = readCommand(readLine());
if ("END BOND".equals(command)) {
foundEND = true;
} else {
logger.debug("Parsing bond from: " + command);
StringTokenizer tokenizer = new StringTokenizer(command);
IBond bond = readData.getBuilder().newBond();
try {
String indexString = tokenizer.nextToken();
bond.setID(indexString);
} catch (Exception exception) {
String error = "Error while parsing bond index";
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
try {
String orderString = tokenizer.nextToken();
int order = Integer.parseInt(orderString);
if (order >= 4) {
logger.warn("Query order types are not supported (yet). File a bug if you need it");
} else {
bond.setOrder(BondManipulator.createBondOrder((double) order));
}
} catch (Exception exception) {
String error = "Error while parsing bond index";
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
try {
String indexAtom1String = tokenizer.nextToken();
int indexAtom1 = Integer.parseInt(indexAtom1String);
IAtom atom1 = readData.getAtom(indexAtom1 - 1);
bond.setAtom(atom1, 0);
} catch (Exception exception) {
String error = "Error while parsing index atom 1 in bond";
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
try {
String indexAtom2String = tokenizer.nextToken();
int indexAtom2 = Integer.parseInt(indexAtom2String);
IAtom atom2 = readData.getAtom(indexAtom2 - 1);
bond.setAtom(atom2, 1);
} catch (Exception exception) {
String error = "Error while parsing index atom 2 in bond";
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
List<IAtom> endpts = new ArrayList<>();
String attach = null;
if (command.indexOf('=') != -1) {
Map<String, String> options = parseOptions(exhaustStringTokenizer(tokenizer));
for (String key : options.keySet()) {
String value = options.get(key);
try {
switch (key) {
case "CFG":
int configuration = Integer.parseInt(value);
if (configuration == 0) {
bond.setStereo(IBond.Stereo.NONE);
} else if (configuration == 1) {
bond.setStereo(IBond.Stereo.UP);
} else if (configuration == 2) {
bond.setStereo((IBond.Stereo) CDKConstants.UNSET);
} else if (configuration == 3) {
bond.setStereo(IBond.Stereo.DOWN);
}
break;
case "ENDPTS":
String[] endptStr = value.split(" ");
for (int i = 1; i < endptStr.length; i++) {
endpts.add(readData.getAtom(Integer.parseInt(endptStr[i]) - 1));
}
break;
case "ATTACH":
attach = value;
break;
default:
logger.warn("Not parsing key: " + key);
break;
}
} catch (Exception exception) {
String error = "Error while parsing key/value " + key + "=" + value + ": "
+ exception.getMessage();
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
}
}
readData.addBond(bond);
if ("ANY".equals(attach)) {
Sgroup sgroup = new Sgroup();
sgroup.setType(SgroupType.ExtMulticenter);
sgroup.addAtom(bond.getBegin());
sgroup.addBond(bond);
for (IAtom endpt : endpts)
sgroup.addAtom(endpt);
List<Sgroup> sgroups = readData.getProperty(CDKConstants.CTAB_SGROUPS);
if (sgroups == null)
readData.setProperty(CDKConstants.CTAB_SGROUPS, sgroups = new ArrayList<>(4));
sgroups.add(sgroup);
}
logger.debug("Added bond: " + bond);
}
}

private IAtomContainer readMolecule(IAtomContainer molecule) throws CDKException logger.debug("Reading new molecule");
int linecount = 0;
int atoms = 0;
int bonds = 0;
int atom1 = 0;
int atom2 = 0;
int order = 0;
IBond.Stereo stereo = (IBond.Stereo) CDKConstants.UNSET;
int RGroupCounter = 1;
int Rnumber = 0;
String[] rGroup = null;
double x = 0.0;
double y = 0.0;
double z = 0.0;
double totalX = 0.0;
double totalY = 0.0;
double totalZ = 0.0;
IAtom atom;
String line = "";
try {
IsotopeFactory isotopeFactory = Isotopes.getInstance();
logger.info("Reading header");
line = input.readLine();
linecount++;
if (line == null) {
return null;
}
logger.debug("Line " + linecount + ": " + line);
if (line.startsWith("$$$$")) {
logger.debug("File is empty, returning empty molecule");
return molecule;
}
if (line.length() > 0) {
molecule.setTitle(line);
}
line = input.readLine();
linecount++;
logger.debug("Line " + linecount + ": " + line);
line = input.readLine();
linecount++;
logger.debug("Line " + linecount + ": " + line);
if (line.length() > 0) {
molecule.setProperty(CDKConstants.REMARK, line);
}
logger.info("Reading rest of file");
line = input.readLine();
linecount++;
logger.debug("Line " + linecount + ": " + line);
if (mode == Mode.STRICT) {
if (line.contains("V2000") || line.contains("v2000")) {
throw new CDKException("This file must be read with the MDLV2000Reader.");
}
if (line.contains("V3000") || line.contains("v3000")) {
throw new CDKException("This file must be read with the MDLV3000Reader.");
}
}
atoms = Integer.valueOf(line.substring(0, 3).trim()).intValue();
logger.debug("Atomcount: " + atoms);
bonds = Integer.valueOf(line.substring(3, 6).trim()).intValue();
logger.debug("Bondcount: " + bonds);
logger.info("Reading atom block");
for (int f = 0; f < atoms; f++) {
line = input.readLine();
linecount++;
Matcher trailingSpaceMatcher = TRAILING_SPACE.matcher(line);
if (trailingSpaceMatcher.find()) {
handleError("Trailing space found", linecount, trailingSpaceMatcher.start(),
trailingSpaceMatcher.end());
line = trailingSpaceMatcher.replaceAll("");
}
x = new Double(line.substring(0, 10).trim()).doubleValue();
y = new Double(line.substring(10, 20).trim()).doubleValue();
z = new Double(line.substring(20, 30).trim()).doubleValue();
totalX += Math.abs(x);
totalY += Math.abs(y);
totalZ += Math.abs(z);
logger.debug("Coordinates: " + x + "; " + y + "; " + z);
String element = line.substring(31, Math.min(34, line.length())).trim();
if (line.length() < 34) {
handleError("Element atom type does not follow V2000 format type should of length three"
+ " and padded with space if required", linecount, 31, 34);
}
logger.debug("Atom type: ", element);
if (isotopeFactory.isElement(element)) {
atom = isotopeFactory.configure(molecule.getBuilder().newInstance(IAtom.class, element));
} else if ("A".equals(element)) {
atom = molecule.getBuilder().newInstance(IPseudoAtom.class, element);
} else if ("Q".equals(element)) {
atom = molecule.getBuilder().newInstance(IPseudoAtom.class, element);
} else if ("*".equals(element)) {
atom = molecule.getBuilder().newInstance(IPseudoAtom.class, element);
} else if ("LP".equals(element)) {
atom = molecule.getBuilder().newInstance(IPseudoAtom.class, element);
} else if ("L".equals(element)) {
atom = molecule.getBuilder().newInstance(IPseudoAtom.class, element);
} else if (element.length() > 0 && element.charAt(0) == 'R') {
logger.debug("Atom ", element, " is not an regular element. Creating a PseudoAtom.");
rGroup = element.split("^R");
if (rGroup.length > 1) {
try {
Rnumber = Integer.parseInt(rGroup[(rGroup.length - 1)]);
RGroupCounter = Rnumber;
} catch (Exception ex) {
Rnumber = RGroupCounter;
RGroupCounter++;
}
element = "R" + Rnumber;
}
atom = molecule.getBuilder().newInstance(IPseudoAtom.class, element);
} else {
if (mode == ISimpleChemObjectReader.Mode.STRICT) {
throw new CDKException(
"Invalid element type. Must be an existing element, or one in: A, Q, L, LP, *.");
}
atom = molecule.getBuilder().newInstance(IPseudoAtom.class, element);
}
atom.setPoint3d(new Point3d(x, y, z));
if (line.length() >= 36) {
String massDiffString = line.substring(34, 36).trim();
logger.debug("Mass difference: ", massDiffString);
if (!(atom instanceof IPseudoAtom)) {
try {
int massDiff = Integer.parseInt(massDiffString);
if (massDiff != 0) {
IIsotope major = Isotopes.getInstance().getMajorIsotope(element);
atom.setMassNumber(major.getMassNumber() + massDiff);
}
} catch (NumberFormatException | IOException exception) {
logger.error("Could not parse mass difference field");
}
} else {
logger.error("Cannot set mass difference for a non-element!");
}
} else {
handleError("Mass difference is missing", linecount, 34, 36);
}
if (line.length() >= 39) {
String chargeCodeString = line.substring(36, 39).trim();
logger.debug("Atom charge code: ", chargeCodeString);
int chargeCode = Integer.parseInt(chargeCodeString);
if (chargeCode == 0) {
} else if (chargeCode == 1) {
atom.setFormalCharge(+3);
} else if (chargeCode == 2) {
atom.setFormalCharge(+2);
} else if (chargeCode == 3) {
atom.setFormalCharge(+1);
} else if (chargeCode == 4) {
} else if (chargeCode == 5) {
atom.setFormalCharge(-1);
} else if (chargeCode == 6) {
atom.setFormalCharge(-2);
} else if (chargeCode == 7) {
atom.setFormalCharge(-3);
}
} else {
handleError("Atom charge count is empty", linecount, 35, 39);
}
if (line.length() >= 64) {
String reactionAtomIDString = line.substring(60, 63).trim();
logger.debug("Parsing mapping id: ", reactionAtomIDString);
try {
int reactionAtomID = Integer.parseInt(reactionAtomIDString);
if (reactionAtomID != 0) {
atom.setProperty(CDKConstants.ATOM_ATOM_MAPPING, reactionAtomID);
}
} catch (Exception exception) {
logger.error("Mapping number ", reactionAtomIDString, " is not an integer.");
logger.debug(exception);
}
}
if (line.length() >= 78) {
double shift = Double.parseDouble(line.substring(69, 80).trim());
atom.setProperty("first shift", new Double(shift));
}
if (line.length() >= 87) {
double shift = Double.parseDouble(line.substring(79, 87).trim());
atom.setProperty("second shift", new Double(shift));
}
molecule.addAtom(atom);
}
if (totalX == 0.0 && totalY == 0.0 && totalZ == 0.0) {
logger.info("All coordinates are 0.0");
for (IAtom atomToUpdate : molecule.atoms()) {
atomToUpdate.setPoint3d(null);
}
} else if (totalZ == 0.0 && !forceReadAs3DCoords.isSet()) {
logger.info("Total 3D Z is 0.0, interpreting it as a 2D structure");
Iterator<IAtom> atomsToUpdate = molecule.atoms().iterator();
while (atomsToUpdate.hasNext()) {
IAtom atomToUpdate = (IAtom) atomsToUpdate.next();
Point3d p3d = atomToUpdate.getPoint3d();
atomToUpdate.setPoint2d(new Point2d(p3d.x, p3d.y));
atomToUpdate.setPoint3d(null);
}
}
logger.info("Reading bond block");
for (int f = 0; f < bonds; f++) {
line = input.readLine();
linecount++;
atom1 = java.lang.Integer.valueOf(line.substring(0, 3).trim()).intValue();
atom2 = java.lang.Integer.valueOf(line.substring(3, 6).trim()).intValue();
order = java.lang.Integer.valueOf(line.substring(6, 9).trim()).intValue();
if (line.length() > 12) {
int mdlStereo = Integer.valueOf(line.substring(9, 12).trim());
if (mdlStereo == 1) {
stereo = IBond.Stereo.UP;
} else if (mdlStereo == 6) {
stereo = IBond.Stereo.DOWN;
} else if (mdlStereo == 0) {
stereo = IBond.Stereo.NONE;
} else if (mdlStereo == 4) {
stereo = IBond.Stereo.UP_OR_DOWN;
} else if (mdlStereo == 3) {
stereo = IBond.Stereo.E_OR_Z;
}
} else {
logger.warn("Missing expected stereo field at line: " + line);
}
if (logger.isDebugEnabled()) {
logger.debug("Bond: " + atom1 + " - " + atom2 + "; order " + order);
}
IAtom a1 = molecule.getAtom(atom1 - 1);
IAtom a2 = molecule.getAtom(atom2 - 1);
IBond newBond = null;
if (order >= 1 && order <= 3) {
IBond.Order cdkOrder = IBond.Order.SINGLE;
if (order == 2) cdkOrder = IBond.Order.DOUBLE;
if (order == 3) cdkOrder = IBond.Order.TRIPLE;
if (stereo != null) {
newBond = molecule.getBuilder().newInstance(IBond.class, a1, a2, cdkOrder, stereo);
} else {
newBond = molecule.getBuilder().newInstance(IBond.class, a1, a2, cdkOrder);
}
} else if (order == 4) {
if (stereo != null) {
newBond = molecule.getBuilder().newInstance(IBond.class, a1, a2, IBond.Order.SINGLE, stereo);
} else {
newBond = molecule.getBuilder().newInstance(IBond.class, a1, a2, IBond.Order.SINGLE);
}
newBond.setFlag(CDKConstants.ISAROMATIC, true);
a1.setFlag(CDKConstants.ISAROMATIC, true);
a2.setFlag(CDKConstants.ISAROMATIC, true);
}
molecule.addBond(newBond);
}
} catch (IOException | CDKException | IllegalArgumentException exception) {
String error = "Error while parsing line " + linecount + ": " + line + " -> " + exception.getMessage();
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
return molecule;

public void readAtomBlock(IAtomContainer readData) throws CDKException logger.info("Reading ATOM block");
IsotopeFactory isotopeFactory;
try {
isotopeFactory = Isotopes.getInstance();
} catch (IOException exception) {
throw new CDKException("Could not initiate the IsotopeFactory.", exception);
}
int RGroupCounter = 1;
int Rnumber = 0;
String[] rGroup = null;
boolean foundEND = false;
while (isReady() && !foundEND) {
String command = readCommand(readLine());
if ("END ATOM".equals(command)) {
foundEND = true;
} else {
logger.debug("Parsing atom from: " + command);
IAtom atom = readData.getBuilder().newAtom();
StringTokenizer tokenizer = new StringTokenizer(command);
try {
atom.setID(tokenizer.nextToken());
} catch (Exception exception) {
String error = "Error while parsing atom index";
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
String element = tokenizer.nextToken();
if (isotopeFactory.isElement(element)) {
atom.setSymbol(element);
isotopeFactory.configure(atom);
} else if ("A".equals(element)) {
atom = readData.getBuilder().newInstance(IPseudoAtom.class, element);
} else if ("Q".equals(element)) {
atom = readData.getBuilder().newInstance(IPseudoAtom.class, element);
} else if ("*".equals(element)) {
atom = readData.getBuilder().newInstance(IPseudoAtom.class, element);
} else if ("LP".equals(element)) {
atom = readData.getBuilder().newInstance(IPseudoAtom.class, element);
} else if ("L".equals(element)) {
atom = readData.getBuilder().newInstance(IPseudoAtom.class, element);
} else if (element.length() > 0 && element.charAt(0) == 'R') {
logger.debug("Atom ", element, " is not an regular element. Creating a PseudoAtom.");
rGroup = element.split("^R");
if (rGroup.length > 1) {
try {
Rnumber = Integer.valueOf(rGroup[(rGroup.length - 1)]).intValue();
RGroupCounter = Rnumber;
} catch (Exception ex) {
Rnumber = RGroupCounter;
RGroupCounter++;
}
element = "R" + Rnumber;
}
atom = readData.getBuilder().newInstance(IPseudoAtom.class, element);
} else {
if (mode == ISimpleChemObjectReader.Mode.STRICT) {
throw new CDKException(
"Invalid element type. Must be an existing element, or one in: A, Q, L, LP, *.");
}
atom = readData.getBuilder().newInstance(IPseudoAtom.class, element);
atom.setSymbol(element);
}
try {
String xString = tokenizer.nextToken();
String yString = tokenizer.nextToken();
String zString = tokenizer.nextToken();
double x = Double.parseDouble(xString);
double y = Double.parseDouble(yString);
double z = Double.parseDouble(zString);
atom.setPoint3d(new Point3d(x, y, z));
atom.setPoint2d(new Point2d(x, y));
} catch (Exception exception) {
String error = "Error while parsing atom coordinates";
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
String mapping = tokenizer.nextToken();
if (!mapping.equals("0")) {
logger.warn("Skipping atom-atom mapping: " + mapping);
}
if (command.indexOf('=') != -1) {
Map<String, String> options = parseOptions(exhaustStringTokenizer(tokenizer));
Iterator<String> keys = options.keySet().iterator();
while (keys.hasNext()) {
String key = keys.next();
String value = options.get(key);
try {
switch (key) {
case "CHG":
int charge = Integer.parseInt(value);
if (charge != 0) {
atom.setFormalCharge(charge);
}
break;
case "RAD":
int numElectons = MDLV2000Writer.SPIN_MULTIPLICITY.ofValue(Integer.parseInt(value))
.getSingleElectrons();
while (numElectons-- > 0) {
readData.addSingleElectron(readData.getBuilder().newInstance(ISingleElectron.class, atom));
}
break;
case "VAL":
if (!(atom instanceof IPseudoAtom)) {
try {
int valence = Integer.parseInt(value);
if (valence != 0) {
if (valence == 15)
atom.setValency(0);
else
atom.setValency(valence);
}
} catch (Exception exception) {
handleError("Could not parse valence information field", lineNumber, 0, 0, exception);
}
} else {
logger.error("Cannot set valence information for a non-element!");
}
break;
default:
logger.warn("Not parsing key: " + key);
break;
}
} catch (Exception exception) {
String error = "Error while parsing key/value " + key + "=" + value + ": "
+ exception.getMessage();
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
}
}
readData.addAtom(atom);
logger.debug("Added atom: " + atom);
}
}

private IChemFile readChemFile(IChemFile chemFile) IChemSequence chemSequence;
IChemModel chemModel;
ICrystal crystal;
try {
String line = readLine();
while (input.ready() && line != null) {
if (line.startsWith("%%Header Start")) {
while (input.ready() && line != null && !(line.startsWith("%%Header End"))) {
if (line.startsWith("%%Version Number")) {
String version = readLine().trim();
if (!version.equals("3.00")) {
logger.error("The PMPReader only supports PMP files with version 3.00");
return null;
}
}
line = readLine();
}
} else if (line.startsWith("%%Model Start")) {
modelStructure = chemFile.getBuilder().newInstance(IAtomContainer.class);
while (input.ready() && line != null && !(line.startsWith("%%Model End"))) {
Matcher objHeaderMatcher = objHeader.matcher(line);
if (objHeaderMatcher.matches()) {
String object = objHeaderMatcher.group(2);
constructObject(chemFile.getBuilder(), object);
int id = Integer.parseInt(objHeaderMatcher.group(1));
line = readLine();
while (input.ready() && line != null && !(line.trim().equals(")"))) {
Matcher objCommandMatcher = objCommand.matcher(line);
objHeaderMatcher = objHeader.matcher(line);
if (objHeaderMatcher.matches()) {
object = objHeaderMatcher.group(2);
id = Integer.parseInt(objHeaderMatcher.group(1));
constructObject(chemFile.getBuilder(), object);
} else if (objCommandMatcher.matches()) {
String format = objCommandMatcher.group(1);
String command = objCommandMatcher.group(2);
String field = objCommandMatcher.group(3);
processModelCommand(object, command, format, field);
} else {
logger.warn("Skipping line: " + line);
}
line = readLine();
}
if (chemObject instanceof IAtom) {
atomids.put(id, modelStructure.getAtomCount());
atomGivenIds.put(Integer.valueOf((String) chemObject.getProperty(PMP_ID)),
id);
modelStructure.addAtom((IAtom) chemObject);
} else if (chemObject instanceof IBond) {
} else {
logger.error("chemObject is not initialized or of bad class type");
}
}
line = readLine();
}
assert line != null;
if (line.startsWith("%%Model End")) {
int bondsFound = bondids.size();
logger.debug("Found #bonds: ", bondsFound);
logger.debug("#atom ones: ", bondAtomOnes.size());
logger.debug("#atom twos: ", bondAtomTwos.size());
logger.debug("#orders: ", bondOrders.size());
for (Integer index : bondids.keySet()) {
double order = (bondOrders.get(index) != null ? bondOrders.get(index) : 1.0);
logger.debug("index: ", index);
logger.debug("ones: ", bondAtomOnes.get(index));
IAtom atom1 = modelStructure.getAtom(atomids.get(bondAtomOnes.get(index)));
IAtom atom2 = modelStructure.getAtom(atomids.get(bondAtomTwos.get(index)));
IBond bond = modelStructure.getBuilder().newInstance(IBond.class, atom1, atom2);
if (order == 1.0) {
bond.setOrder(IBond.Order.SINGLE);
} else if (order == 2.0) {
bond.setOrder(IBond.Order.DOUBLE);
} else if (order == 3.0) {
bond.setOrder(IBond.Order.TRIPLE);
} else if (order == 4.0) {
bond.setOrder(IBond.Order.QUADRUPLE);
}
modelStructure.addBond(bond);
}
}
} else if (line.startsWith("%%Traj Start")) {
chemSequence = chemFile.getBuilder().newInstance(IChemSequence.class);
double energyFragment = 0.0;
double energyTotal = 0.0;
int Z = 1;
while (input.ready() && line != null && !(line.startsWith("%%Traj End"))) {
if (line.startsWith("%%Start Frame")) {
chemModel = chemFile.getBuilder().newInstance(IChemModel.class);
crystal = chemFile.getBuilder().newInstance(ICrystal.class);
while (input.ready() && line != null && !(line.startsWith("%%End Frame"))) {
if (line.startsWith("%%Atom Coords")) {
if (energyFragment != 0.0 && energyTotal != 0.0) {
Z = (int) Math.round(energyTotal / energyFragment);
logger.debug("Z derived from energies: ", Z);
}
int expatoms = modelStructure.getAtomCount();
for (int molCount = 1; molCount <= Z; molCount++) {
IAtomContainer clone = modelStructure.getBuilder().newInstance(
IAtomContainer.class);
for (int i = 0; i < expatoms; i++) {
line = readLine();
IAtom a = clone.getBuilder().newInstance(IAtom.class);
StringTokenizer st = new StringTokenizer(line, " ");
a.setPoint3d(new Point3d(Double.parseDouble(st.nextToken()), Double
.parseDouble(st.nextToken()), Double.parseDouble(st.nextToken())));
a.setCovalentRadius(0.6);
IAtom modelAtom = modelStructure.getAtom(atomids.get(atomGivenIds
.get(i + 1)));
a.setSymbol(modelAtom.getSymbol());
clone.addAtom(a);
}
rebonder.rebond(clone);
crystal.add(clone);
}
} else if (line.startsWith("%%E/Frag")) {
line = readLine().trim();
energyFragment = Double.parseDouble(line);
} else if (line.startsWith("%%Tot E")) {
line = readLine().trim();
energyTotal = Double.parseDouble(line);
} else if (line.startsWith("%%Lat Vects")) {
StringTokenizer st;
line = readLine();
st = new StringTokenizer(line, " ");
crystal.setA(new Vector3d(Double.parseDouble(st.nextToken()), Double.parseDouble(st
.nextToken()), Double.parseDouble(st.nextToken())));
line = readLine();
st = new StringTokenizer(line, " ");
crystal.setB(new Vector3d(Double.parseDouble(st.nextToken()), Double.parseDouble(st
.nextToken()), Double.parseDouble(st.nextToken())));
line = readLine();
st = new StringTokenizer(line, " ");
crystal.setC(new Vector3d(Double.parseDouble(st.nextToken()), Double.parseDouble(st
.nextToken()), Double.parseDouble(st.nextToken())));
} else if (line.startsWith("%%Space Group")) {
line = readLine().trim();
if ("P 21 21 21 (1)".equals(line)) {
crystal.setSpaceGroup("P 2_1 2_1 2_1");
} else {
crystal.setSpaceGroup("P1");
}
}
line = readLine();
}
chemModel.setCrystal(crystal);
chemSequence.addChemModel(chemModel);
}
line = readLine();
}
chemFile.addChemSequence(chemSequence);
}
line = readLine();
}
} catch (IOException e) {
logger.error("An IOException happened: ", e.getMessage());
logger.debug(e);
chemFile = null;
} catch (CDKException e) {
logger.error("An CDKException happened: ", e.getMessage());
logger.debug(e);
chemFile = null;
}
return chemFile;

private RGroupQuery parseRGFile(RGroupQuery rGroupQuery) throws CDKException IChemObjectBuilder defaultChemObjectBuilder = rGroupQuery.getBuilder();
String line = "";
int lineCount = 0;
String eol = "\n";
StringTokenizer strTk = null;
Map<Integer, RGroupLogic> logicDefinitions = new HashMap<Integer, RGroupLogic>();
Map<IAtom, Map<Integer, IBond>> attachmentPoints = new HashMap<IAtom, Map<Integer, IBond>>();
try {
logger.info("Process the Header block");
checkLineBeginsWith(input.readLine(), "$MDL", ++lineCount);
checkLineBeginsWith(input.readLine(), "$MOL", ++lineCount);
checkLineBeginsWith(input.readLine(), "$HDR", ++lineCount);
for (int i = 1; i <= 3; i++) {
lineCount++;
if (input.readLine() == null) {
throw new CDKException("RGFile invalid, empty/null header line at #" + lineCount);
}
}
checkLineBeginsWith(input.readLine(), "$END HDR", ++lineCount);
logger.info("Process the root structure (scaffold)");
checkLineBeginsWith(input.readLine(), "$CTAB", ++lineCount);
StringBuilder sb = new StringBuilder(RGroup.ROOT_LABEL + "\n\n\n");
line = input.readLine();
++lineCount;
while (line != null && !line.equals("$END CTAB")) {
sb.append(line + eol);
if (line.startsWith("M  LOG")) {
strTk = new StringTokenizer(line);
strTk.nextToken();
strTk.nextToken();
strTk.nextToken();
RGroupLogic log = null;
log = new RGroupLogic();
int rgroupNumber = Integer.valueOf(strTk.nextToken());
String tok = strTk.nextToken();
log.rgoupNumberRequired = tok.equals("0") ? 0 : Integer.valueOf(tok);
log.restH = strTk.nextToken().equals("1") ? true : false;
tok = "";
while (strTk.hasMoreTokens()) {
tok += strTk.nextToken();
}
log.occurence = tok;
logicDefinitions.put(rgroupNumber, log);
}
line = input.readLine();
++lineCount;
}
String rootStr = sb.toString();
MDLV2000Reader reader = new MDLV2000Reader(new StringReader(rootStr), ISimpleChemObjectReader.Mode.STRICT);
IAtomContainer root = reader.read(defaultChemObjectBuilder.newInstance(IAtomContainer.class));
rGroupQuery.setRootStructure(root);
strTk = new StringTokenizer(rootStr, eol);
while (strTk.hasMoreTokens()) {
line = strTk.nextToken();
if (line.startsWith("M  AAL")) {
StringTokenizer stAAL = new StringTokenizer(line);
stAAL.nextToken();
stAAL.nextToken();
int pos = Integer.valueOf(stAAL.nextToken());
IAtom rGroup = root.getAtom(pos - 1);
stAAL.nextToken();
Map<Integer, IBond> bondMap = new HashMap<Integer, IBond>();
while (stAAL.hasMoreTokens()) {
pos = Integer.valueOf(stAAL.nextToken());
IAtom partner = root.getAtom(pos - 1);
IBond bond = root.getBond(rGroup, partner);
int order = Integer.valueOf(stAAL.nextToken());
bondMap.put(order, bond);
logger.info("AAL " + order + " " + ((IPseudoAtom) rGroup).getLabel() + "-"
+ partner.getSymbol());
}
if (bondMap.size() != 0) {
attachmentPoints.put(rGroup, bondMap);
}
}
}
for (IAtom atom : root.atoms()) {
if (atom instanceof IPseudoAtom) {
IPseudoAtom rGroup = (IPseudoAtom) atom;
if (rGroup.getLabel().startsWith("R") && !rGroup.getLabel().equals("R") &&
!attachmentPoints.containsKey(rGroup)) {
int order = 0;
Map<Integer, IBond> bondMap = new HashMap<Integer, IBond>();
for (IAtom atom2 : root.atoms()) {
if (!atom.equals(atom2)) {
for (IBond bond : root.bonds()) {
if (bond.contains(atom) && bond.contains(atom2)) {
bondMap.put(++order, bond);
logger.info("Def " + order + " " + rGroup.getLabel() + "-" + atom2.getSymbol());
break;
}
}
}
}
if (bondMap.size() != 0) {
attachmentPoints.put(rGroup, bondMap);
}
}
}
}
rGroupQuery.setRootAttachmentPoints(attachmentPoints);
logger.info("Attachm.points defined for " + attachmentPoints.size() + " R# atoms");
Map<Integer, RGroupList> rGroupDefinitions = new HashMap<Integer, RGroupList>();
for (IAtom atom : root.atoms()) {
if (atom instanceof IPseudoAtom) {
IPseudoAtom rGroup = (IPseudoAtom) atom;
if (RGroupQuery.isValidRgroupQueryLabel(rGroup.getLabel())) {
int rgroupNum = Integer.valueOf(rGroup.getLabel().substring(1));
RGroupList rgroupList = new RGroupList(rgroupNum);
if (!rGroupDefinitions.containsKey(rgroupNum)) {
logger.info("Define Rgroup R" + rgroupNum);
RGroupLogic logic = logicDefinitions.get(rgroupNum);
if (logic != null) {
rgroupList.setRestH(logic.restH);
rgroupList.setOccurrence(logic.occurence);
rgroupList.setRequiredRGroupNumber(logic.rgoupNumberRequired);
} else {
rgroupList.setRestH(false);
rgroupList.setOccurrence(">0");
rgroupList.setRequiredRGroupNumber(0);
}
rgroupList.setRGroups(new ArrayList<RGroup>());
rGroupDefinitions.put(rgroupNum, rgroupList);
}
}
}
}
line = input.readLine();
++lineCount;
boolean hasMoreRGP = true;
while (hasMoreRGP) {
checkLineBeginsWith(line, "$RGP", lineCount);
line = input.readLine();
++lineCount;
logger.info("line for num is " + line);
int rgroupNum = Integer.valueOf(line.trim());
line = input.readLine();
++lineCount;
boolean hasMoreCTAB = true;
while (hasMoreCTAB) {
checkLineBeginsWith(line, "$CTAB", lineCount);
sb = new StringBuilder(RGroup.makeLabel(rgroupNum) + "\n\n\n");
line = input.readLine();
while (line != null && !line.startsWith("$END CTAB")) {
sb.append(line + eol);
line = input.readLine();
++lineCount;
}
String groupStr = sb.toString();
reader = new MDLV2000Reader(new StringReader(groupStr), ISimpleChemObjectReader.Mode.STRICT);
IAtomContainer group = reader.read(defaultChemObjectBuilder.newInstance(IAtomContainer.class));
RGroup rGroup = new RGroup();
rGroup.setGroup(group);
strTk = new StringTokenizer(groupStr, eol);
while (strTk.hasMoreTokens()) {
line = strTk.nextToken();
if (line.startsWith("M  APO")) {
StringTokenizer stAPO = new StringTokenizer(line);
stAPO.nextToken();
stAPO.nextToken();
stAPO.nextToken();
while (stAPO.hasMoreTokens()) {
int pos = Integer.valueOf(stAPO.nextToken());
int apo = Integer.valueOf(stAPO.nextToken());
IAtom at = group.getAtom(pos - 1);
switch (apo) {
case 1:
rGroup.setFirstAttachmentPoint(at);
break;
case 2:
rGroup.setSecondAttachmentPoint(at);
break;
case 3: {
rGroup.setFirstAttachmentPoint(at);
rGroup.setSecondAttachmentPoint(at);
}
break;
}
}
}
}
RGroupList rList = rGroupDefinitions.get(rgroupNum);
if (rList == null) {
throw new CDKException("R" + rgroupNum + " not defined but referenced in $RGP.");
} else {
rList.getRGroups().add(rGroup);
}
line = input.readLine();
++lineCount;
if (line.startsWith("$END RGP")) {
logger.info("end of RGP block");
hasMoreCTAB = false;
}
}
line = input.readLine();
++lineCount;
if (line.startsWith("$END MOL")) {
hasMoreRGP = false;
}
}
rGroupQuery.setRGroupDefinitions(rGroupDefinitions);
logger.info("Number of lines was " + lineCount);
return rGroupQuery;
} catch (CDKException exception) {
String error = "CDK Error while parsing line " + lineCount + ": " + line + " -> " + exception.getMessage();
logger.error(error);
logger.debug(exception);
throw exception;
} catch (IOException | IllegalArgumentException exception) {
exception.printStackTrace();
String error = exception.getClass() + "Error while parsing line " + lineCount + ": " + line + " -> "
+ exception.getMessage();
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}

private IReactionSet readReactionSet(IReactionSet setOfReactions) throws CDKException IReaction r = readReaction(setOfReactions.getBuilder());
if (r != null) {
setOfReactions.addReaction(r);
}
try {
String line;
while ((line = input.readLine()) != null) {
logger.debug("line: ", line);
if (line.equals("$$$$")) {
r = readReaction(setOfReactions.getBuilder());
if (r != null) {
setOfReactions.addReaction(r);
}
} else {
if (r != null) {
String fieldName = null;
if (line.startsWith("> ")) {
int index = line.indexOf('<');
if (index != -1) {
int index2 = line.substring(index).indexOf('>');
if (index2 != -1) {
fieldName = line.substring(index + 1, index + index2);
}
}
while ((line = input.readLine()) != null && line.startsWith(">")) {
logger.debug("data header line: ", line);
}
}
if (line == null) {
throw new CDKException("Expecting data line here, but found null!");
}
String data = line;
while ((line = input.readLine()) != null && line.trim().length() > 0) {
if (line.equals("$$$$")) {
logger.error("Expecting data line here, but found end of molecule: ", line);
break;
}
logger.debug("data line: ", line);
data += line;
if (line.length() < 80) data += "\n";
}
if (fieldName != null) {
logger.info("fieldName, data: ", fieldName, ", ", data);
r.setProperty(fieldName, data);
}
}
}
}
} catch (CDKException cdkexc) {
throw cdkexc;
} catch (IOException exception) {
String error = "Error while parsing SDF";
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
return setOfReactions;

public void readSGroup(IAtomContainer readData) throws CDKException boolean foundEND = false;
while (isReady() && !foundEND) {
String command = readCommand(readLine());
if ("END SGROUP".equals(command)) {
foundEND = true;
} else {
logger.debug("Parsing Sgroup line: " + command);
StringTokenizer tokenizer = new StringTokenizer(command);
String indexString = tokenizer.nextToken();
logger.warn("Skipping external index: " + indexString);
String type = tokenizer.nextToken();
String externalIndexString = tokenizer.nextToken();
logger.warn("Skipping external index: " + externalIndexString);
Map<String, String> options = new Hashtable<String, String>();
if (command.indexOf('=') != -1) {
options = parseOptions(exhaustStringTokenizer(tokenizer));
}
if (type.startsWith("SUP")) {
Iterator<String> keys = options.keySet().iterator();
int atomID = -1;
String label = "";
while (keys.hasNext()) {
String key = keys.next();
String value = options.get(key);
try {
if (key.equals("ATOMS")) {
StringTokenizer atomsTokenizer = new StringTokenizer(value);
Integer.parseInt(atomsTokenizer.nextToken());
atomID = Integer.parseInt(atomsTokenizer.nextToken());
} else if (key.equals("LABEL")) {
label = value;
} else {
logger.warn("Not parsing key: " + key);
}
} catch (Exception exception) {
String error = "Error while parsing key/value " + key + "=" + value + ": "
+ exception.getMessage();
logger.error(error);
logger.debug(exception);
throw new CDKException(error, exception);
}
if (atomID != -1 && label.length() > 0) {
IAtom original = readData.getAtom(atomID - 1);
IAtom replacement = original;
if (!(original instanceof IPseudoAtom)) {
replacement = readData.getBuilder().newInstance(IPseudoAtom.class,
original);
}
((IPseudoAtom) replacement).setLabel(label);
if (!replacement.equals(original))
AtomContainerManipulator.replaceAtomByAtom(readData, original, replacement);
}
}
} else {
logger.warn("Skipping unrecognized SGROUP type: " + type);
}
}
}

private IReaction readReaction(IChemObjectBuilder builder) throws CDKException logger.debug("Reading new reaction");
int linecount = 0;
IReaction reaction = builder.newInstance(IReaction.class);
try {
input.readLine();
input.readLine();
input.readLine();
input.readLine();
} catch (IOException exception) {
logger.debug(exception);
throw new CDKException("Error while reading header of RXN file", exception);
}
int reactantCount = 0;
int productCount = 0;
try {
String countsLine = input.readLine();
linecount++;
if (countsLine == null) {
return null;
}
logger.debug("Line " + linecount + ": " + countsLine);
if (countsLine.startsWith("$$$$")) {
logger.debug("File is empty, returning empty reaction");
return reaction;
}
StringTokenizer tokenizer = new StringTokenizer(countsLine);
reactantCount = Integer.valueOf(tokenizer.nextToken()).intValue();
logger.info("Expecting " + reactantCount + " reactants in file");
productCount = Integer.valueOf(tokenizer.nextToken()).intValue();
logger.info("Expecting " + productCount + " products in file");
} catch (IOException | NumberFormatException exception) {
logger.debug(exception);
throw new CDKException("Error while counts line of RXN file", exception);
}
try {
for (int i = 1; i <= reactantCount; i++) {
StringBuffer molFile = new StringBuffer();
input.readLine();
String molFileLine = "";
do {
molFileLine = input.readLine();
molFile.append(molFileLine);
molFile.append('\n');
} while (!molFileLine.equals("M  END"));
MDLReader reader = new MDLReader(new StringReader(molFile.toString()));
IAtomContainer reactant = (IAtomContainer) reader.read(builder.newInstance(IAtomContainer.class));
reader.close();
reaction.addReactant(reactant);
}
} catch (CDKException exception) {
throw exception;
} catch (IOException | IllegalArgumentException exception) {
logger.debug(exception);
throw new CDKException("Error while reading reactant", exception);
}
try {
for (int i = 1; i <= productCount; i++) {
StringBuffer molFile = new StringBuffer();
input.readLine();
String molFileLine = "";
do {
molFileLine = input.readLine();
molFile.append(molFileLine);
molFile.append('\n');
} while (!molFileLine.equals("M  END"));
MDLReader reader = new MDLReader(new StringReader(molFile.toString()), super.mode);
IAtomContainer product = (IAtomContainer) reader.read(builder.newInstance(IAtomContainer.class));
reader.close();
reaction.addProduct(product);
}
} catch (CDKException exception) {
throw exception;
} catch (IOException | IllegalArgumentException exception) {
logger.debug(exception);
throw new CDKException("Error while reading products", exception);
}
logger.info("Reading atom-atom mapping from file");
IAtomContainer reactingSide = builder.newInstance(IAtomContainer.class);
Iterator<IAtomContainer> molecules = reaction.getReactants().atomContainers().iterator();
while (molecules.hasNext()) {
reactingSide.add(molecules.next());
}
IAtomContainer producedSide = builder.newInstance(IAtomContainer.class);
molecules = reaction.getProducts().atomContainers().iterator();
while (molecules.hasNext()) {
producedSide.add(molecules.next());
}
int mappingCount = 0;
for (int i = 0; i < reactingSide.getAtomCount(); i++) {
for (int j = 0; j < producedSide.getAtomCount(); j++) {
IAtom eductAtom = reactingSide.getAtom(i);
IAtom productAtom = producedSide.getAtom(j);
if (eductAtom.getProperty(CDKConstants.ATOM_ATOM_MAPPING) != null
&& eductAtom.getProperty(CDKConstants.ATOM_ATOM_MAPPING).equals(
productAtom.getProperty(CDKConstants.ATOM_ATOM_MAPPING))) {
reaction.addMapping(builder.newInstance(IMapping.class, eductAtom, productAtom));
mappingCount++;
break;
}
}
}
logger.info("Mapped atom pairs: " + mappingCount);
return reaction;

public int parseParameters(String[] args) if (args.length < 1) {
CliFrontendParser.printHelp(customCommandLines);
System.out.println("Please specify an action.");
return 1;
}
String action = args[0];
final String[] params = Arrays.copyOfRange(args, 1, args.length);
try {
switch (action) {
case ACTION_RUN:
run(params);
return 0;
case ACTION_LIST:
list(params);
return 0;
case ACTION_INFO:
info(params);
return 0;
case ACTION_CANCEL:
cancel(params);
return 0;
case ACTION_STOP:
stop(params);
return 0;
case ACTION_SAVEPOINT:
savepoint(params);
return 0;
case "-h":
case "--help":
CliFrontendParser.printHelp(customCommandLines);
return 0;
case "-v":
case "--version":
String version = EnvironmentInformation.getVersion();
String commitID = EnvironmentInformation.getRevisionInformation().commitId;
System.out.print("Version: " + version);
System.out.println(commitID.equals(EnvironmentInformation.UNKNOWN) ? "" : ", Commit ID: " + commitID);
return 0;
default:
System.out.printf("\"%s\" is not a valid action.\n", action);
System.out.println();
System.out.println("Valid actions are \"run\", \"list\", \"info\", \"savepoint\", \"stop\", or \"cancel\".");
System.out.println();
System.out.println("Specify the version option (-v or --version) to print Flink version.");
System.out.println();
System.out.println("Specify the help option (-h or --help) to get help on the command.");
return 1;
}
} catch (CliArgsException ce) {
return handleArgException(ce);
} catch (ProgramParametrizationException ppe) {
return handleParametrizationException(ppe);
} catch (ProgramMissingJobException pmje) {
return handleMissingJobException();
} catch (Exception e) {
return handleError(e);
}

private static int handleError(Throwable t) LOG.error("Error while running the command.", t);
System.err.println();
System.err.println("------------------------------------------------------------");
System.err.println(" The program finished with the following exception:");
System.err.println();
if (t.getCause() instanceof InvalidProgramException) {
System.err.println(t.getCause().getMessage());
StackTraceElement[] trace = t.getCause().getStackTrace();
for (StackTraceElement ele: trace) {
System.err.println("\t" + ele);
if (ele.getMethodName().equals("main")) {
break;
}
}
} else {
t.printStackTrace();
}
return 1;

