protected void heapifyUp(int pos, E elem) assert (pos < size && pos >= 0);
while(pos > 0) {
final int parent = (pos - 1) >>> 1;
Object par = queue[parent];
if(comparator.compare(elem, par) >= 0) {
break;
}
queue[pos] = par;
pos = parent;
}
queue[pos] = elem;

protected void offerAt(final int pos, O e) if(pos == NO_VALUE) {
if(size + 1 > queue.length) {
resize(size + 1);
}
index.put(e, size);
size++;
heapifyUp(size - 1, e);
heapModified();
return;
}
assert (pos >= 0) : "Unexpected negative position.";
assert (queue[pos].equals(e));
if(comparator.compare(e, queue[pos]) >= 0) {
return;
}
heapifyUp(pos, e);
heapModified();
return;

public static double parseDouble(final byte[] str, final int start, final int end) if(start >= end) {
throw EMPTY_STRING;
}
int pos = start;
byte cur = str[pos];
if(matchNaN(str, cur, pos, end)) {
return Double.NaN;
}
boolean isNegative = (cur == '-');
if((isNegative || (cur == '+')) && (++pos < end)) {
cur = str[pos];
}
if(matchInf(str, cur, pos, end)) {
return isNegative ? Double.NEGATIVE_INFINITY : Double.POSITIVE_INFINITY;
}
if(((cur < '0') || (cur > '9')) && (cur != '.')) {
throw NOT_A_NUMBER;
}
long decimal = 0;
int decimalPoint = -1;
while(true) {
final int digit = cur - '0';
if((digit >= 0) && (digit <= 9)) {
final long tmp = (decimal << 3) + (decimal << 1) + digit;
if(tmp >= decimal) {
decimal = tmp;
}
else if(++decimalPoint == 0) {
throw PRECISION_OVERFLOW;
}
}
else if((cur == '.') && (decimalPoint < 0)) {
decimalPoint = pos;
}
else {
break;
}
if(++pos >= end) {
break;
}
cur = str[pos];
}
decimalPoint = (decimalPoint >= 0) ? pos - decimalPoint - 1 : 0;
int exp = 0;
if((pos + 1 < end) && ((cur == 'E') || (cur == 'e'))) {
cur = str[++pos];
final boolean isNegativeExp = (cur == '-');
if((isNegativeExp || (cur == '+')) && (++pos < end)) {
cur = str[pos];
}
if((cur < '0') || (cur > '9')) {
throw INVALID_EXPONENT;
}
while(true) {
final int digit = cur - '0';
if(digit < 0 || digit > 9) {
break;
}
exp = (exp << 3) + (exp << 1) + digit;
if(exp > Double.MAX_EXPONENT) {
throw EXPONENT_OVERFLOW;
}
if(++pos >= end) {
break;
}
cur = str[pos];
}
exp = isNegativeExp ? -exp : exp;
}
exp = decimalPoint > 0 ? (exp - decimalPoint) : exp;
if(pos != end) {
throw TRAILING_CHARACTERS;
}
return BitsUtil.lpow10(isNegative ? -decimal : decimal, exp);

@SuppressWarnings("unchecked") protected E removeAt(int pos) if(pos < 0 || pos >= size) {
return null;
}
final E ret = (E) queue[pos];
final Object reinsert = queue[size - 1];
queue[size - 1] = null;
size--;
heapifyDown(pos, reinsert);
heapModified();
return ret;

public static long parseLongBase10(final CharSequence str, final int start, final int end) int pos = start;
char cur = str.charAt(pos);
boolean isNegative = (cur == '-');
if((isNegative || (cur == '+')) && (++pos < end)) {
cur = str.charAt(pos);
}
if((cur < '0') || (cur > '9')) {
throw NOT_A_NUMBER;
}
long decimal = 0;
while(true) {
final int digit = cur - '0';
if((digit >= 0) && (digit <= 9)) {
final long tmp = (decimal << 3) + (decimal << 1) + digit;
if(tmp < decimal) {
throw PRECISION_OVERFLOW;
}
decimal = tmp;
}
else {
break;
}
if(++pos < end) {
cur = str.charAt(pos);
}
else {
break;
}
}
if(pos != end) {
throw TRAILING_CHARACTERS;
}
return isNegative ? -decimal : decimal;

