@Override public Object map(Object input) List<Long> list = (List<Long>) input;
switch (mathOp) {
case Add:
long sum = 0;
for (Long w : list)
sum += w;
return new LongWritable(sum);
case Subtract:
return list.get(0) - list.get(1);
case Multiply:
long product = 1;
for (Long w : list)
product *= w;
return product;
case Divide:
return list.get(0) / list.get(1);
case Modulus:
return list.get(0) % list.get(1);
case ReverseSubtract:
case ReverseDivide:
case ScalarMin:
case ScalarMax:
default:
throw new RuntimeException("Invalid mathOp: " + mathOp);
}

public static List<Writable> rowToWritables(Schema schema, Row row) List<Writable> ret = new ArrayList<>();
for (int i = 0; i < row.size(); i++) {
switch (schema.getType(i)) {
case Double:
ret.add(new DoubleWritable(row.getDouble(i)));
break;
case Float:
ret.add(new FloatWritable(row.getFloat(i)));
break;
case Integer:
ret.add(new IntWritable(row.getInt(i)));
break;
case Long:
ret.add(new LongWritable(row.getLong(i)));
break;
case String:
ret.add(new Text(row.getString(i)));
break;
default:
throw new IllegalStateException("Illegal type");
}
}
return ret;

public static void setValue(ColumnType columnType,FieldVector fieldVector,Object value,int row) if(value instanceof NullWritable) {
return;
}
try {
switch (columnType) {
case Integer:
if (fieldVector instanceof IntVector) {
IntVector intVector = (IntVector) fieldVector;
int set = TypeConversion.getInstance().convertInt(value);
intVector.set(row, set);
} else if (fieldVector instanceof UInt4Vector) {
UInt4Vector uInt4Vector = (UInt4Vector) fieldVector;
int set = TypeConversion.getInstance().convertInt(value);
uInt4Vector.set(row, set);
} else {
throw new UnsupportedOperationException("Illegal type " + fieldVector.getClass() + " for int type");
}
break;
case Float:
Float4Vector float4Vector = (Float4Vector) fieldVector;
float set2 = TypeConversion.getInstance().convertFloat(value);
float4Vector.set(row, set2);
break;
case Double:
double set3 = TypeConversion.getInstance().convertDouble(value);
Float8Vector float8Vector = (Float8Vector) fieldVector;
float8Vector.set(row, set3);
break;
case Long:
if (fieldVector instanceof BigIntVector) {
BigIntVector largeIntVector = (BigIntVector) fieldVector;
largeIntVector.set(row, TypeConversion.getInstance().convertLong(value));
} else if (fieldVector instanceof UInt8Vector) {
UInt8Vector uInt8Vector = (UInt8Vector) fieldVector;
uInt8Vector.set(row, TypeConversion.getInstance().convertLong(value));
} else {
throw new UnsupportedOperationException("Illegal type " + fieldVector.getClass() + " for long type");
}
break;
case Categorical:
case String:
String stringSet = TypeConversion.getInstance().convertString(value);
VarCharVector textVector = (VarCharVector) fieldVector;
textVector.setSafe(row, stringSet.getBytes());
break;
case Time:
long timeSet = TypeConversion.getInstance().convertLong(value);
setLongInTime(fieldVector, row, timeSet);
break;
case NDArray:
NDArrayWritable arr = (NDArrayWritable) value;
VarBinaryVector nd4jArrayVector = (VarBinaryVector) fieldVector;
ByteBuffer byteBuffer = BinarySerde.toByteBuffer(arr.get());
nd4jArrayVector.setSafe(row,byteBuffer,0,byteBuffer.capacity());
break;
}
}catch(Exception e) {
log.warn("Unable to set value at row " + row);
}

public float distance(INDArray arr1, INDArray arr2) if (scalars == null)
scalars = new ThreadLocal<>();
if (Nd4j.scalar(0.0f).equals(scalars.get()))
scalars.set(Nd4j.scalar(0.0));
switch (similarityFunction) {
case "jaccard":
float ret7 = Nd4j.getExecutioner()
.execAndReturn(new JaccardDistance(arr1, arr2, scalars.get()))
.getFinalResult().floatValue();
return invert ? -ret7 : ret7;
case "hamming":
float ret8 = Nd4j.getExecutioner()
.execAndReturn(new HammingDistance(arr1, arr2, scalars.get()))
.getFinalResult().floatValue();
return invert ? -ret8 : ret8;
case "euclidean":
float ret = Nd4j.getExecutioner()
.execAndReturn(new EuclideanDistance(arr1, arr2, scalars.get()))
.getFinalResult().floatValue();
return invert ? -ret : ret;
case "cosinesimilarity":
float ret2 = Nd4j.getExecutioner()
.execAndReturn(new CosineSimilarity(arr1, arr2, scalars.get()))
.getFinalResult().floatValue();
return invert ? -ret2 : ret2;
case "cosinedistance":
float ret6 = Nd4j.getExecutioner()
.execAndReturn(new CosineDistance(arr1, arr2, scalars.get()))
.getFinalResult().floatValue();
return invert ? -ret6 : ret6;
case "manhattan":
float ret3 = Nd4j.getExecutioner()
.execAndReturn(new ManhattanDistance(arr1, arr2, scalars.get()))
.getFinalResult().floatValue();
return invert ? -ret3 : ret3;
case "dot":
float dotRet = (float) Nd4j.getBlasWrapper().dot(arr1, arr2);
return invert ? -dotRet : dotRet;
default:
float ret4 = Nd4j.getExecutioner()
.execAndReturn(new EuclideanDistance(arr1, arr2, scalars.get()))
.getFinalResult().floatValue();
return invert ? -ret4 : ret4;
}

