private TreeNode split(TreeNode node, ClusteringFeature newchild) final int capacity = node.children.length;
assert (node.children[capacity - 1] != null) : "Node to split is not empty!";
TreeNode newn = new TreeNode(node.getDimensionality(), capacity);
final int size = capacity + 1;
int m1 = -1, m2 = -1;
double maxd = Double.NEGATIVE_INFINITY;
double[][] dists = new double[size][size];
for(int i = 0; i < capacity; i++) {
ClusteringFeature ci = node.children[i];
for(int j = i + 1; j < capacity; j++) {
double d = dists[i][j] = dists[j][i] = distance.squaredDistance(ci, node.children[j]);
if(d > maxd) {
maxd = d;
m1 = i;
m2 = j;
}
}
double d = dists[i][capacity] = dists[capacity][i] = distance.squaredDistance(ci, newchild);
if(d > maxd) {
maxd = d;
m1 = i;
m2 = capacity;
}
}
node.resetStatistics();
newn.resetStatistics();
int si = 0, sj = 0;
double[] d1s = dists[m1], d2s = dists[m2];
for(int i = 0; i < capacity; i++) {
double d1 = d1s[i], d2 = d2s[i];
if(i == m1 || i != m2 && (d1 < d2 || (d1 == d2 && si <= sj))) {
node.addToStatistics(node.children[si++] = node.children[i]);
}
else {
newn.addToStatistics(newn.children[sj++] = node.children[i]);
}
}
{
double d1 = d1s[capacity], d2 = d2s[capacity];
if(capacity != m2 && (d1 < d2 || (d1 == d2 && si <= sj))) {
node.addToStatistics(node.children[si++] = newchild);
}
else {
newn.addToStatistics(newn.children[sj++] = newchild);
}
}
for(int j = si; j < capacity; j++) {
node.children[j] = null;
}
for(int j = sj; j < capacity; j++) {
assert (newn.children[j] == null);
}
return newn;

public int correlationDistance(PCAFilteredResult pca1, PCAFilteredResult pca2, int dimensionality) double[][] v1t = copy(pca1.getEigenvectors());
double[][] v1t_strong = pca1.getStrongEigenvectors();
int lambda1 = pca1.getCorrelationDimension();
double[][] v2t = copy(pca2.getEigenvectors());
double[][] v2t_strong = pca2.getStrongEigenvectors();
int lambda2 = pca2.getCorrelationDimension();
double[][] m1_czech = pca1.dissimilarityMatrix();
for(int i = 0; i < v2t_strong.length; i++) {
double[] v2_i = v2t_strong[i];
double distsq = squareSum(v2_i) - transposeTimesTimes(v2_i, m1_czech, v2_i);
if(lambda1 < dimensionality && distsq > deltasq) {
adjust(v1t, v2_i, lambda1++);
double[] e1_czech_d = new double[v1t.length];
Arrays.fill(e1_czech_d, 0, lambda1, 1);
m1_czech = transposeDiagonalTimes(v1t, e1_czech_d, v1t);
}
}
double[][] m2_czech = pca2.dissimilarityMatrix();
for(int i = 0; i < v1t_strong.length; i++) {
double[] v1_i = v1t_strong[i];
double distsq = squareSum(v1_i) - transposeTimesTimes(v1_i, m2_czech, v1_i);
if(lambda2 < dimensionality && distsq > deltasq) {
adjust(v2t, v1_i, lambda2++);
double[] e2_czech_d = new double[v1t.length];
Arrays.fill(e2_czech_d, 0, lambda2, 1);
m2_czech = transposeDiagonalTimes(v2t, e2_czech_d, v2t);
}
}
return Math.max(lambda1, lambda2);

