protected void computeGradient(AffinityMatrix pij, double[][] qij, double qij_isum, double[][] sol, double[] meta) final int dim3 = dim * 3;
int size = pij.size();
for(int i = 0, off = 0; i < size; i++, off += dim3) {
final double[] sol_i = sol[i], qij_i = qij[i];
Arrays.fill(meta, off, off + dim, 0.);
for(int j = 0; j < size; j++) {
if(i == j) {
continue;
}
final double[] sol_j = sol[j];
final double qij_ij = qij_i[j];
final double q = MathUtil.max(qij_ij * qij_isum, MIN_QIJ);
double a = 4 * (pij.get(i, j) - q);
for(int k = 0; k < dim; k++) {
meta[off + k] += a * (sol_i[k] - sol_j[k]);
}
}
}

protected void updateSolution(double[][] sol, double[] meta, int it) final double mom = (it < momentumSwitch && initialMomentum < finalMomentum) ? initialMomentum : finalMomentum;
final int dim3 = dim * 3;
for(int i = 0, off = 0; i < sol.length; i++, off += dim3) {
final double[] sol_i = sol[i];
for(int k = 0; k < dim; k++) {
final int gradk = off + k, movk = gradk + dim, gaink = movk + dim;
meta[gaink] = MathUtil.max(((meta[gradk] > 0) != (meta[movk] > 0)) ? (meta[gaink] + 0.2) : (meta[gaink] * 0.8), MIN_GAIN);
meta[movk] *= mom;
meta[movk] -= learningRate * meta[gradk] * meta[gaink];
sol_i[k] += meta[movk];
}
}

protected static double[][] computePij(double[][] dist, double sigma, double initialScale) final int size = dist.length;
final double msigmasq = -.5 / (sigma * sigma);
double[][] pij = new double[size][size];
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Computing affinities", size, LOG) : null;
Duration timer = LOG.isStatistics() ? LOG.newDuration(GaussianAffinityMatrixBuilder.class.getName() + ".runtime.pijmatrix").begin() : null;
MeanVariance mv = LOG.isStatistics() ? new MeanVariance() : null;
for(int i = 0; i < size; i++) {
double logP = computeH(i, dist[i], pij[i], msigmasq);
if(mv != null) {
mv.put(FastMath.exp(logP));
}
LOG.incrementProcessed(prog);
}
LOG.ensureCompleted(prog);
if(LOG.isStatistics()) {
LOG.statistics(timer.end());
LOG.statistics(new DoubleStatistic(GaussianAffinityMatrixBuilder.class.getName() + ".perplexity.average", mv.getMean()));
LOG.statistics(new DoubleStatistic(GaussianAffinityMatrixBuilder.class.getName() + ".perplexity.stddev", mv.getSampleStddev()));
}
double sum = 0.;
for(int i = 1; i < size; i++) {
final double[] pij_i = pij[i];
for(int j = 0; j < i; j++) {
sum += (pij_i[j] += pij[j][i]);
}
}
final double scale = initialScale / (2. * sum);
for(int i = 1; i < size; i++) {
final double[] pij_i = pij[i];
for(int j = 0; j < i; j++) {
pij_i[j] = pij[j][i] = MathUtil.max(pij_i[j] * scale, MIN_PIJ);
}
}
return pij;

protected static double[][] computePij(double[][] dist, double perplexity, double initialScale) final int size = dist.length;
final double logPerp = FastMath.log(perplexity);
double[][] pij = new double[size][size];
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Optimizing perplexities", size, LOG) : null;
Duration timer = LOG.isStatistics() ? LOG.newDuration(PerplexityAffinityMatrixBuilder.class.getName() + ".runtime.pijmatrix").begin() : null;
MeanVariance mv = LOG.isStatistics() ? new MeanVariance() : null;
for(int i = 0; i < size; i++) {
double beta = computePi(i, dist[i], pij[i], perplexity, logPerp);
if(mv != null) {
mv.put(beta > 0 ? FastMath.sqrt(.5 / beta) : 0.);
}
LOG.incrementProcessed(prog);
}
LOG.ensureCompleted(prog);
if(LOG.isStatistics()) {
LOG.statistics(timer.end());
LOG.statistics(new DoubleStatistic(PerplexityAffinityMatrixBuilder.class.getName() + ".sigma.average", mv.getMean()));
LOG.statistics(new DoubleStatistic(PerplexityAffinityMatrixBuilder.class.getName() + ".sigma.stddev", mv.getSampleStddev()));
}
double sum = 0.;
for(int i = 1; i < size; i++) {
final double[] pij_i = pij[i];
for(int j = 0; j < i; j++) {
sum += (pij_i[j] += pij[j][i]);
}
}
final double scale = initialScale / (2. * sum);
for(int i = 1; i < size; i++) {
final double[] pij_i = pij[i];
for(int j = 0; j < i; j++) {
pij_i[j] = pij[j][i] = MathUtil.max(pij_i[j] * scale, MIN_PIJ);
}
}
return pij;

protected void computePij(DBIDRange ids, KNNQuery<?> knnq, boolean square, int numberOfNeighbours, double[][] pij, int[][] indices, double initialScale) Duration timer = LOG.isStatistics() ? LOG.newDuration(this.getClass().getName() + ".runtime.neighborspijmatrix").begin() : null;
final double logPerp = FastMath.log(perplexity);
DoubleArray dists = new DoubleArray(numberOfNeighbours + 10);
IntegerArray inds = new IntegerArray(numberOfNeighbours + 10);
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Finding neighbors and optimizing perplexity", ids.size(), LOG) : null;
MeanVariance mv = LOG.isStatistics() ? new MeanVariance() : null;
Mean mid = LOG.isStatistics() ? new Mean() : null;
for(DBIDArrayIter ix = ids.iter(); ix.valid(); ix.advance()) {
dists.clear();
inds.clear();
KNNList neighbours = knnq.getKNNForDBID(ix, numberOfNeighbours + 1);
convertNeighbors(ids, ix, square, neighbours, dists, inds, mid);
double beta = computeSigma(ix.getOffset(), dists, perplexity, logPerp,
pij[ix.getOffset()] = new double[dists.size()]);
if(mv != null) {
mv.put(beta > 0 ? FastMath.sqrt(.5 / beta) : 0.);
}
indices[ix.getOffset()] = inds.toArray();
LOG.incrementProcessed(prog);
}
LOG.ensureCompleted(prog);
if(mid != null) {
LOG.statistics(new DoubleStatistic(getClass() + ".average-original-id", mid.getMean()));
}
double sum = 0.;
for(int i = 0; i < pij.length; i++) {
final double[] pij_i = pij[i];
for(int offi = 0; offi < pij_i.length; offi++) {
int j = indices[i][offi];
if(j > i) {
continue;
}
assert (i != j);
int offj = containsIndex(indices[j], i);
if(offj >= 0) {
sum += FastMath.sqrt(pij_i[offi] * pij[j][offj]);
}
}
}
final double scale = initialScale / (2 * sum);
for(int i = 0; i < pij.length; i++) {
final double[] pij_i = pij[i];
for(int offi = 0; offi < pij_i.length; offi++) {
int j = indices[i][offi];
assert (i != j);
int offj = containsIndex(indices[j], i);
if(offj >= 0) {
assert (indices[j][offj] == i);
if(i < j) {
final double val = FastMath.sqrt(pij_i[offi] * pij[j][offj]);
pij_i[offi] = pij[j][offj] = MathUtil.max(val * scale, MIN_PIJ);
}
}
else {
pij_i[offi] = 0;
}
}
}
if(LOG.isStatistics()) {
LOG.statistics(timer.end());
LOG.statistics(new DoubleStatistic(NearestNeighborAffinityMatrixBuilder.class.getName() + ".sigma.average", mv.getMean()));
LOG.statistics(new DoubleStatistic(NearestNeighborAffinityMatrixBuilder.class.getName() + ".sigma.stddev", mv.getSampleStddev()));
}

protected double[][] buildDistanceMatrix(ArrayDBIDs ids, DistanceQuery<?> dq) final int size = ids.size();
double[][] dmat = new double[size][size];
final boolean square = !dq.getDistanceFunction().isSquared();
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Computing distance matrix", (size * (size - 1)) >>> 1, LOG) : null;
Duration timer = LOG.isStatistics() ? LOG.newDuration(this.getClass().getName() + ".runtime.distancematrix").begin() : null;
DBIDArrayIter ix = ids.iter(), iy = ids.iter();
for(ix.seek(0); ix.valid(); ix.advance()) {
double[] dmat_x = dmat[ix.getOffset()];
for(iy.seek(ix.getOffset() + 1); iy.valid(); iy.advance()) {
final double dist = dq.distance(ix, iy);
dmat[iy.getOffset()][ix.getOffset()] = dmat_x[iy.getOffset()] = square ? (dist * dist) : dist;
}
if(prog != null) {
int row = ix.getOffset() + 1;
prog.setProcessed(row * size - ((row * (row + 1)) >>> 1), LOG);
}
}
LOG.ensureCompleted(prog);
if(timer != null) {
LOG.statistics(timer.end());
}
return dmat;

public FrequentItemsetsResult run(Database db, final Relation<BitVector> relation) final int dim = RelationUtil.dimensionality(relation);
