detector.setMaxDistanceFromEllipse(config.maxDistanceFromEllipse);
detector.setMaximumContour(config.maximumContour);
detector.setMinimumContour(config.minimumContour);
detector.setMinimumMinorAxis(config.minimumMinorAxis);
detector.setInternalContour(config.processInternal);
detector.setMaxMajorToMinorRatio(config.maxMajorToMinorRatio);
SnapToEllipseEdge<T> refine = new SnapToEllipseEdge<>(config.numSampleContour, config.refineRadialSamples, imageType);
refine.setConvergenceTol(config.convergenceTol);
refine.setMaxIterations(config.maxIterations);
if( config.maxIterations <= 0 || config.numSampleContour <= 0 ) {
refine = null;
}
EdgeIntensityEllipse<T> check = new EdgeIntensityEllipse<>(
config.checkRadialDistance,
config.numSampleContour,
config.minimumEdgeIntensity, imageType);
return new BinaryEllipseDetector<>(detector, refine, check, imageType);

public static NonMaxSuppression nonmax( @Nullable ConfigExtract config ) if( config == null )
config = new ConfigExtract();
config.checkValidity();
if( BOverrideFactoryFeatureExtractor.nonmax != null ) {
return BOverrideFactoryFeatureExtractor.nonmax.process(config);
}
NonMaxBlock.Search search;
if (config.useStrictRule) {
if( config.detectMaximums)
if( config.detectMinimums )
search = new NonMaxBlockSearchStrict.MinMax();
else
search = new NonMaxBlockSearchStrict.Max();
else
search = new NonMaxBlockSearchStrict.Min();
} else {
if( config.detectMaximums)
if( config.detectMinimums )
search = new NonMaxBlockSearchRelaxed.MinMax();
else
search = new NonMaxBlockSearchRelaxed.Max();
else
search = new NonMaxBlockSearchRelaxed.Min();
}
NonMaxBlock alg = BoofConcurrency.USE_CONCURRENT ?
new NonMaxBlock_MT(search) : new NonMaxBlock(search);
alg.setSearchRadius(config.radius);
alg.setThresholdMax(config.threshold);
alg.setThresholdMin(-config.threshold);
alg.setBorder(config.ignoreBorder);
return new WrapperNonMaximumBlock(alg);

public static <T extends ImageGray<T>> DescribeRegionPoint<T,TupleDesc_B> brief( @Nullable ConfigBrief config , Class<T> imageType) if( config == null )
