}
List<String> profiles = new ArrayList<String>();
IRingSet rs;
try {
rs = (new AllRingsFinder()).findAllRings(ac);
} catch (CDKException e) {
return getDummyDescriptorValue(e);
}
if (checkAromaticity) {
