protected static <A> double[] computeNormalizedRanks(final NumberArrayAdapter<?, A> adapter, final A data, int len) int[] s1 = sortedIndex(adapter, data, len);
final double norm = .5 / (len - 1);
double[] ret = new double[len];
for(int i = 0; i < len;) {
final int start = i++;
final double val = adapter.getDouble(data, s1[start]);
while(i < len && adapter.getDouble(data, s1[i]) <= val) {
i++;
}
final double score = (start + i - 1) * norm;
for(int j = start; j < i; j++) {
ret[s1[j]] = score;
}
}
return ret;

private void divide(int[] idx, double[] data, ArrayList<int[]> ret, int start, int end, int depth) if(depth == 0) {
int[] a = Arrays.copyOfRange(idx, start, end);
Arrays.sort(a);
ret.add(a);
return;
}
final int count = end - start;
if(count == 0) {
for(int j = 1 << depth; j > 0; --j) {
ret.add(new int[0]);
}
return;
}
double m = 0.;
for(int i = start; i < end; i++) {
m += data[i];
}
m /= count;
int pos = Arrays.binarySearch(data, start, end, m);
if(pos >= 0) {
final int opt = (start + end) >> 1;
while(data[pos] == m) {
if(pos < opt) {
pos++;
}
else if(pos > opt) {
pos--;
}
else {
break;
}
}
}
else {
pos = (-pos - 1);
}
divide(idx, data, ret, start, pos, depth - 1);
divide(idx, data, ret, pos, end, depth - 1);

private <A> ArrayList<int[]> buildPartitions(NumberArrayAdapter<?, A> adapter1, A data1, int len, int depth) final int[] idx = new int[len];
final double[] tmp = new double[len];
for(int i = 0; i < len; ++i) {
idx[i] = i;
tmp[i] = adapter1.getDouble(data1, i);
}
IntegerArrayQuickSort.sort(idx, (x, y) -> Double.compare(tmp[x], tmp[y]));
Arrays.sort(tmp);
ArrayList<int[]> ret = new ArrayList<>(1 << depth);
divide(idx, tmp, ret, 0, tmp.length, depth);
return ret;

public static <A> double[] toPrimitiveDoubleArray(A data, NumberArrayAdapter<?, A> adapter) if(adapter == DoubleArrayAdapter.STATIC) {
return ((double[]) data).clone();
}
final int len = adapter.size(data);
double[] x = new double[len];
for(int i = 0; i < len; i++) {
x[i] = adapter.getDouble(data, i);
}
return x;

protected static <A, B> double[] computeBivariateRanks(NumberArrayAdapter<?, A> adapter1, A data1, NumberArrayAdapter<?, B> adapter2, B data2, int len) double[] ret = new double[len];
for(int i = 0; i < len; i++) {
for(int j = i + 1; j < len; j++) {
double xi = adapter1.getDouble(data1, i),
xj = adapter1.getDouble(data1, j);
double yi = adapter2.getDouble(data2, i),
yj = adapter2.getDouble(data2, j);
if(xi < xj) {
ret[j] += (yi < yj) ? 1 : (yi == yj) ? .5 : 0;
}
else if(xj < xi) {
ret[i] += (yj < yi) ? 1 : (yj == yi) ? .5 : 0;
}
else {
if(yi < yj) {
ret[j] += .5;
}
else if(yj < yi) {
ret[i] += .5;
}
else {
ret[i] += .25;
ret[j] += .25;
}
}
}
}
return ret;

protected static <A> int[] discretize(NumberArrayAdapter<?, A> adapter, A data, final int len, final int bins) double min = adapter.getDouble(data, 0), max = min;
for(int i = 1; i < len; i++) {
double v = adapter.getDouble(data, i);
if(v < min) {
min = v;
}
else if(v > max) {
max = v;
}
}
final double scale = (max > min) ? bins / (max - min) : 1;
int[] discData = new int[len];
for(int i = 0; i < len; i++) {
int bin = (int) Math.floor((adapter.getDouble(data, i) - min) * scale);
discData[i] = bin < 0 ? 0 : bin >= bins ? bins - 1 : bin;
}
return discData;

public static <A> double[] alphaPWM(A data, NumberArrayAdapter<?, A> adapter, final int nmom) final int n = adapter.size(data);
final double[] xmom = new double[nmom];
double weight = 1. / n;
for(int i = 0; i < n; i++) {
final double val = adapter.getDouble(data, i);
xmom[0] += weight * val;
for(int j = 1; j < nmom; j++) {
weight *= (n - i - j + 1) / (n - j + 1);
xmom[j] += weight * val;
}
}
return xmom;

protected static <A> double[] computeDistances(NumberArrayAdapter<?, A> adapter, A data) final int size = adapter.size(data);
double[] dMatrix = new double[(size * (size + 1)) >> 1];
for(int i = 0, c = 0; i < size; i++) {
for(int j = 0; j < i; j++) {
double dx = adapter.getDouble(data, i) - adapter.getDouble(data, j);
dMatrix[c++] = (dx < 0) ? -dx : dx;
}
c++;
}
doubleCenterMatrix(dMatrix, size);
return dMatrix;

public static <A> double[] alphaBetaPWM(A data, NumberArrayAdapter<?, A> adapter, final int nmom) final int n = adapter.size(data);
final double[] xmom = new double[nmom << 1];
double aweight = 1. / n, bweight = aweight;
for(int i = 0; i < n; i++) {
final double val = adapter.getDouble(data, i);
xmom[0] += aweight * val;
xmom[1] += bweight * val;
for(int j = 1, k = 2; j < nmom; j++, k += 2) {
aweight *= (n - i - j + 1) / (n - j + 1);
bweight *= (i - j + 1) / (n - j + 1);
xmom[k + 1] += aweight * val;
xmom[k + 1] += bweight * val;
}
}
return xmom;

protected static <A> int[] sortedIndex(final NumberArrayAdapter<?, A> adapter, final A data, int len) int[] s1 = MathUtil.sequence(0, len);
IntegerArrayQuickSort.sort(s1, (x, y) -> Double.compare(adapter.getDouble(data, x), adapter.getDouble(data, y)));
return s1;

public boolean awaitDisconnected(long timeout, TimeUnit unit) throws InterruptedException lock.lock();
try {
if (currentState.equals(CLIENT_DISCONNECTED) || currentState.equals(SHUTTING_DOWN) || currentState.equals(SHUTDOWN)) {
return true;
}
long duration = unit.toNanos(timeout);
while (duration > 0) {
duration = disconnectedCondition.awaitNanos(duration);
if (currentState.equals(CLIENT_DISCONNECTED) || currentState.equals(SHUTTING_DOWN) || currentState
.equals(SHUTDOWN)) {
return true;
}
}
return false;
} finally {
lock.unlock();
}

@Override public V get(long timeout, TimeUnit unit) throws ExecutionException, InterruptedException, TimeoutException final long deadlineTimeMillis = System.currentTimeMillis() + unit.toMillis(timeout);
long millisToWait;
for (; ; ) {
Object currentState = this.state;
if (isCancelledState(currentState)) {
throw new CancellationException();
}
if (isDoneState(currentState)) {
return getResult(currentState);
}
if (Thread.interrupted()) {
throw new InterruptedException();
}
millisToWait = deadlineTimeMillis - System.currentTimeMillis();
if (millisToWait <= 0) {
throw new TimeoutException();
}
synchronized (this) {
if (!isDoneState(this.state)) {
wait(millisToWait);
}
}
}

protected boolean setResult(Object result) for (; ; ) {
Object currentState = this.state;
if (isDoneState(currentState)) {
return false;
}
if (STATE.compareAndSet(this, currentState, result)) {
done();
notifyThreadsWaitingOnGet();
runAsynchronous((ExecutionCallbackNode) currentState, result);
break;
}
}
return true;

