@Override public boolean onShutdown(long timeout, TimeUnit unit) if (nodeEngine.getLocalMember().isLiteMember()) {
return true;
}
long timeoutNanos = unit.toNanos(timeout);
for (CRDTReplicationAwareService service : getReplicationServices()) {
service.prepareToSafeShutdown();
final CRDTReplicationContainer replicationOperation = service.prepareReplicationOperation(
replicationVectorClocks.getLatestReplicatedVectorClock(service.getName()), 0);
if (replicationOperation == null) {
logger.fine("Skipping replication since all CRDTs are replicated");
continue;
}
long start = System.nanoTime();
if (!tryProcessOnOtherMembers(replicationOperation.getOperation(), service.getName(), timeoutNanos)) {
logger.warning("Failed replication of CRDTs for " + service.getName() + ". CRDT state may be lost.");
}
timeoutNanos -= (System.nanoTime() - start);
if (timeoutNanos < 0) {
return false;
}
}
return true;

private boolean applyNewPartitionTable(PartitionReplica[][] partitionTable, int newVersion, Collection<MigrationInfo> completedMigrations, Address sender) try {
if (!lock.tryLock(PTABLE_SYNC_TIMEOUT_SECONDS, SECONDS)) {
return false;
}
} catch (InterruptedException e) {
Thread.currentThread().interrupt();
return false;
}
try {
int currentVersion = partitionStateManager.getVersion();
if (newVersion < currentVersion) {
if (logger.isFineEnabled()) {
logger.fine("Already applied partition state change. Local version: " + currentVersion
+ ", Master version: " + newVersion + " Master: " + sender);
}
return false;
} else if (newVersion == currentVersion) {
if (logger.isFineEnabled()) {
logger.fine("Already applied partition state change. Version: " + currentVersion + ", Master: " + sender);
}
return true;
}
requestMemberListUpdateIfUnknownMembersFound(sender, partitionTable);
updatePartitionsAndFinalizeMigrations(partitionTable, newVersion, completedMigrations);
return true;
} finally {
lock.unlock();
}

