private Registration getRegistration(EventEnvelope eventEnvelope, String serviceName) EventServiceSegment segment = eventService.getSegment(serviceName, false);
if (segment == null) {
if (eventService.nodeEngine.isRunning()) {
eventService.logger.warning("No service registration found for " + serviceName);
}
return null;
}
String id = eventEnvelope.getEventId();
Registration registration = (Registration) segment.getRegistrationIdMap().get(id);
if (registration == null) {
if (eventService.nodeEngine.isRunning()) {
if (eventService.logger.isFinestEnabled()) {
eventService.logger.finest("No registration found for " + serviceName + " / " + id);
}
}
return null;
}
if (!eventService.isLocal(registration)) {
eventService.logger.severe("Invalid target for  " + registration);
return null;
}
if (registration.getListener() == null) {
eventService.logger.warning("Something seems wrong! Subscriber is local but listener instance is null! -> "
+ registration);
return null;
}
return registration;

void process(EventEnvelope envelope) Object event = getEvent(envelope);
String serviceName = envelope.getServiceName();
EventPublishingService<Object, Object> service = eventService.nodeEngine.getService(serviceName);
Registration registration = getRegistration(envelope, serviceName);
if (registration == null) {
return;
}
service.dispatchEvent(event, registration.getListener());

private void publishLocalEvent(String cacheId, Object eventData, Extractors extractors) Collection<EventRegistration> eventRegistrations = getRegistrations(cacheId);
if (eventRegistrations.isEmpty()) {
return;
}
for (EventRegistration eventRegistration : eventRegistrations) {
Registration registration = (Registration) eventRegistration;
Object listener = registration.getListener();
if (!(listener instanceof QueryCacheListenerAdapter)) {
continue;
}
Object eventDataToPublish = eventData;
int orderKey = -1;
if (eventDataToPublish instanceof LocalCacheWideEventData) {
orderKey = cacheId.hashCode();
} else if (eventDataToPublish instanceof LocalEntryEventData) {
LocalEntryEventData localEntryEventData = (LocalEntryEventData) eventDataToPublish;
if (localEntryEventData.getEventType() != EventLostEvent.EVENT_TYPE) {
EventFilter filter = registration.getFilter();
if (!canPassFilter(localEntryEventData, filter, extractors)) {
continue;
} else {
boolean includeValue = isIncludeValue(filter);
eventDataToPublish = includeValue
? localEntryEventData : localEntryEventData.cloneWithoutValue();
Data keyData = localEntryEventData.getKeyData();
orderKey = keyData == null ? -1 : keyData.hashCode();
}
}
}
publishEventInternal(registration, eventDataToPublish, orderKey);
}

private void sendEvent(Address subscriber, EventEnvelope eventEnvelope, int orderKey) String serviceName = eventEnvelope.getServiceName();
EventServiceSegment segment = getSegment(serviceName, true);
boolean sync = segment.incrementPublish() % eventSyncFrequency == 0;
if (sync) {
SendEventOperation op = new SendEventOperation(eventEnvelope, orderKey);
Future f = nodeEngine.getOperationService()
.createInvocationBuilder(serviceName, op, subscriber)
.setTryCount(SEND_RETRY_COUNT).invoke();
try {
f.get(sendEventSyncTimeoutMillis, MILLISECONDS);
} catch (Exception e) {
syncDeliveryFailureCount.inc();
if (logger.isFinestEnabled()) {
logger.finest("Sync event delivery failed. Event: " + eventEnvelope, e);
}
}
} else {
Packet packet = new Packet(serializationService.toBytes(eventEnvelope), orderKey)
.setPacketType(Packet.Type.EVENT);
EndpointManager em = nodeEngine.getNode().getNetworkingService().getEndpointManager(MEMBER);
if (!em.transmit(packet, subscriber)) {
if (nodeEngine.isRunning()) {
logFailure("Failed to send event packet to: %s, connection might not be alive.", subscriber);
}
}
}

private void pingNotifiableEventListener(String topic, Registration registration, boolean register) Object listener = registration.getListener();
if (!(listener instanceof NotifiableEventListener)) {
EventFilter filter = registration.getFilter();
if (filter instanceof ListenerWrapperEventFilter) {
listener = ((ListenerWrapperEventFilter) filter).getListener();
}
}
pingNotifiableEventListenerInternal(listener, topic, registration, register);
pingNotifiableEventListenerInternal(service, topic, registration, register);

private void pingNotifiableEventListenerInternal(Object object, String topic, Registration registration, boolean register) if (!(object instanceof NotifiableEventListener)) {
return;
}
NotifiableEventListener listener = ((NotifiableEventListener) object);
if (register) {
listener.onRegister(service, serviceName, topic, registration);
} else {
listener.onDeregister(service, serviceName, topic, registration);
}

@Deprecated public <T> TypeSerializerSchemaCompatibility<T> resolveCompatibilityWithNested( TypeSerializerSchemaCompatibility<?> outerCompatibility, TypeSerializer<?>... newNestedSerializers) checkArgument(newNestedSerializers.length == nestedSnapshots.length,
"Different number of new serializers and existing serializer configuration snapshots");
if (outerCompatibility.isIncompatible()) {
return TypeSerializerSchemaCompatibility.incompatible();
}
boolean nestedSerializerRequiresMigration = false;
for (int i = 0; i < nestedSnapshots.length; i++) {
TypeSerializerSchemaCompatibility<?> compatibility =
resolveCompatibility(newNestedSerializers[i], nestedSnapshots[i]);
if (compatibility.isIncompatible()) {
return TypeSerializerSchemaCompatibility.incompatible();
}
if (compatibility.isCompatibleAfterMigration()) {
nestedSerializerRequiresMigration = true;
}
}
return (nestedSerializerRequiresMigration || !outerCompatibility.isCompatibleAsIs()) ?
TypeSerializerSchemaCompatibility.compatibleAfterMigration() :
TypeSerializerSchemaCompatibility.compatibleAsIs();

public static <T> IntermediateCompatibilityResult<T> constructIntermediateCompatibilityResult( TypeSerializer<?>[] newNestedSerializers, TypeSerializerSnapshot<?>[] nestedSerializerSnapshots) Preconditions.checkArgument(newNestedSerializers.length == nestedSerializerSnapshots.length,
"Different number of new serializers and existing serializer snapshots.");
TypeSerializer<?>[] nestedSerializers = new TypeSerializer[newNestedSerializers.length];
boolean nestedSerializerRequiresMigration = false;
boolean hasReconfiguredNestedSerializers = false;
for (int i = 0; i < nestedSerializerSnapshots.length; i++) {
TypeSerializerSchemaCompatibility<?> compatibility =
resolveCompatibility(newNestedSerializers[i], nestedSerializerSnapshots[i]);
if (compatibility.isIncompatible()) {
return IntermediateCompatibilityResult.definedIncompatibleResult();
}
if (compatibility.isCompatibleAfterMigration()) {
nestedSerializerRequiresMigration = true;
} else if (compatibility.isCompatibleWithReconfiguredSerializer()) {
hasReconfiguredNestedSerializers = true;
nestedSerializers[i] = compatibility.getReconfiguredSerializer();
} else if (compatibility.isCompatibleAsIs()) {
nestedSerializers[i] = newNestedSerializers[i];
} else {
throw new IllegalStateException("Undefined compatibility type.");
}
}
if (nestedSerializerRequiresMigration) {
return IntermediateCompatibilityResult.definedCompatibleAfterMigrationResult();
}
if (hasReconfiguredNestedSerializers) {
return IntermediateCompatibilityResult.undefinedReconfigureResult(nestedSerializers);
}
return IntermediateCompatibilityResult.definedCompatibleAsIsResult(nestedSerializers);

@Override public TypeSerializerSchemaCompatibility<ArrayList<T>> resolveSchemaCompatibilityViaRedirectingToNewSnapshotClass( TypeSerializerConfigSnapshot<ArrayList<T>> deprecatedConfigSnapshot) if (deprecatedConfigSnapshot instanceof CollectionSerializerConfigSnapshot) {
CollectionSerializerConfigSnapshot<ArrayList<T>, T> castedLegacySnapshot =
(CollectionSerializerConfigSnapshot<ArrayList<T>, T>) deprecatedConfigSnapshot;
ArrayListSerializerSnapshot<T> newSnapshot = new ArrayListSerializerSnapshot<>();
return CompositeTypeSerializerUtil.delegateCompatibilityCheckToNewSnapshot(
this,
newSnapshot,
castedLegacySnapshot.getNestedSerializerSnapshots());
}
return TypeSerializerSchemaCompatibility.incompatible();

@SuppressWarnings("unchecked") private static <E> TypeSerializerSchemaCompatibility<E> resolveCompatibility( TypeSerializer<?> serializer, TypeSerializerSnapshot<?> snapshot) TypeSerializer<E> typedSerializer = (TypeSerializer<E>) serializer;
TypeSerializerSnapshot<E> typedSnapshot = (TypeSerializerSnapshot<E>) snapshot;
return typedSnapshot.resolveSchemaCompatibility(typedSerializer);

