private boolean checkSync() boolean sync = false;
long last = lastSubmitTime;
long now = Clock.currentTimeMillis();
if (last + SYNC_DELAY_MS < now) {
CONSECUTIVE_SUBMITS.set(this, 0);
} else if (CONSECUTIVE_SUBMITS.incrementAndGet(this) % SYNC_FREQUENCY == 0) {
sync = true;
}
lastSubmitTime = now;
return sync;

static int findRelativeSecond(long delayMillis) long now = Clock.currentTimeMillis();
long d = (now + delayMillis - INITIAL_TIME_MILLIS);
return ceilToSecond(d);

private void startJoinRequest(MemberInfo memberInfo) long now = Clock.currentTimeMillis();
if (logger.isFineEnabled()) {
String timeToStart = (timeToStartJoin > 0 ? ", timeToStart: " + (timeToStartJoin - now) : "");
logger.fine(format("Handling join from %s, joinInProgress: %b%s", memberInfo.getAddress(),
joinInProgress, timeToStart));
}
if (firstJoinRequest == 0) {
firstJoinRequest = now;
}
final MemberInfo existing = joiningMembers.put(memberInfo.getAddress(), memberInfo);
if (existing == null) {
sendMasterAnswer(memberInfo.getAddress());
if (now - firstJoinRequest < maxWaitMillisBeforeJoin) {
timeToStartJoin = now + waitMillisBeforeJoin;
}
} else if (!existing.getUuid().equals(memberInfo.getUuid())) {
logger.warning("Received a new join request from " + memberInfo.getAddress()
+ " with a new UUID " + memberInfo.getUuid()
+ ". Previous UUID was " + existing.getUuid());
}
if (now >= timeToStartJoin) {
startJoin();
}

private void checkClockDrift(long intervalMillis) long now = Clock.currentTimeMillis();
if (lastHeartbeat != 0L) {
long clockJump = now - lastHeartbeat - intervalMillis;
long absoluteClockJump = Math.abs(clockJump);
if (absoluteClockJump > CLOCK_JUMP_THRESHOLD) {
logger.info(format("System clock apparently jumped from %s to %s since last heartbeat (%+d ms)",
timeToString(lastHeartbeat), timeToString(now), clockJump));
long currentClusterTimeDiff = clusterClock.getClusterTimeDiff();
if (Math.abs(lastClusterTimeDiff - currentClusterTimeDiff) < CLOCK_JUMP_THRESHOLD) {
clusterClock.setClusterTimeDiff(currentClusterTimeDiff - clockJump);
}
}
if (absoluteClockJump >= maxNoHeartbeatMillis / 2) {
logger.warning(format("Resetting heartbeat timestamps because of huge system clock jump!"
+ " Clock-Jump: %d ms, Heartbeat-Timeout: %d ms", clockJump, maxNoHeartbeatMillis));
resetHeartbeats();
}
}
lastClusterTimeDiff = clusterClock.getClusterTimeDiff();
lastHeartbeat = now;

Collection<Tuple2<Long, Long>> getSessionsToExpire() List<Tuple2<Long, Long>> expired = new ArrayList<Tuple2<Long, Long>>();
long now = Clock.currentTimeMillis();
for (CPSessionInfo session : sessions.values()) {
if (session.isExpired(now)) {
expired.add(Tuple2.of(session.id(), session.version()));
}
}
return expired;

private void heartbeatWhenMaster(long now) Collection<MemberImpl> members = clusterService.getMemberImpls();
for (MemberImpl member : members) {
if (!member.localMember()) {
try {
logIfConnectionToEndpointIsMissing(now, member);
if (suspectMemberIfNotHeartBeating(now, member)) {
continue;
}
pingMemberIfRequired(now, member);
sendHeartbeat(member);
} catch (Throwable e) {
logger.severe(e);
}
}
}

public <C extends EvictionCandidate<A, E>> C evaluate(Iterable<C> evictionCandidates) C selectedEvictionCandidate = null;
long now = Clock.currentTimeMillis();
for (C currentEvictionCandidate : evictionCandidates) {
if (selectedEvictionCandidate == null) {
selectedEvictionCandidate = currentEvictionCandidate;
} else {
E evictable = currentEvictionCandidate.getEvictable();
if (isExpired(now, evictable)) {
return currentEvictionCandidate;
}
int comparisonResult = evictionPolicyComparator.compare(selectedEvictionCandidate, currentEvictionCandidate);
if (comparisonResult == EvictionPolicyComparator.SECOND_ENTRY_HAS_HIGHER_PRIORITY_TO_BE_EVICTED) {
selectedEvictionCandidate = currentEvictionCandidate;
}
}
}
return selectedEvictionCandidate;

private void pingMemberIfRequired(long now, Member member) if (!icmpEnabled || icmpParallelMode) {
return;
}
long lastHeartbeat = heartbeatFailureDetector.lastHeartbeat(member);
if ((now - lastHeartbeat) >= legacyIcmpCheckThresholdMillis) {
runPingTask(member);
}

@SuppressWarnings("unchecked") void cleanup(Ringbuffer ringbuffer) if (ringbuffer.headSequence() > ringbuffer.tailSequence()) {
return;
}
long now = currentTimeMillis();
while (ringbuffer.headSequence() <= ringbuffer.tailSequence()) {
final long headSequence = ringbuffer.headSequence();
if (ringExpirationMs[toIndex(headSequence)] > now) {
return;
}
ringbuffer.set(headSequence, null);
ringbuffer.setHeadSequence(ringbuffer.headSequence() + 1);
}

private void heartbeatWhenSlave(long now) MembershipManager membershipManager = clusterService.getMembershipManager();
Collection<Member> members = clusterService.getMembers(MemberSelectors.NON_LOCAL_MEMBER_SELECTOR);
for (Member member : members) {
try {
logIfConnectionToEndpointIsMissing(now, member);
if (suspectMemberIfNotHeartBeating(now, member)) {
continue;
}
if (membershipManager.isMemberSuspected(member.getAddress())) {
continue;
}
pingMemberIfRequired(now, member);
sendHeartbeat(member);
} catch (Throwable e) {
logger.severe(e);
}
}

