public static <V extends NumberVector> V project(V v, long[] selectedAttributes, NumberVector.Factory<V> factory) int card = BitsUtil.cardinality(selectedAttributes);
if(factory instanceof SparseNumberVector.Factory) {
final SparseNumberVector.Factory<?> sfactory = (SparseNumberVector.Factory<?>) factory;
Int2DoubleOpenHashMap values = new Int2DoubleOpenHashMap(card, .8f);
for(int d = BitsUtil.nextSetBit(selectedAttributes, 0); d >= 0; d = BitsUtil.nextSetBit(selectedAttributes, d + 1)) {
if(v.doubleValue(d) != 0.0) {
values.put(d, v.doubleValue(d));
}
}
@SuppressWarnings("unchecked")
V projectedVector = (V) sfactory.newNumberVector(values, card);
return projectedVector;
}
else {
double[] newAttributes = new double[card];
int i = 0;
for(int d = BitsUtil.nextSetBit(selectedAttributes, 0); d >= 0; d = BitsUtil.nextSetBit(selectedAttributes, d + 1)) {
newAttributes[i] = v.doubleValue(d);
i++;
}
return factory.newNumberVector(newAttributes);
}

@Override protected Cluster<SubspaceModel> runDOC(Database database, Relation<V> relation, ArrayModifiableDBIDs S, int d, int n, int m, int r, int minClusterSize) long[] D = null;
DBIDVar dV = DBIDUtil.newVar();
FiniteProgress iprogress = LOG.isVerbose() ? new FiniteProgress("Iteration progress for current cluster", m * n, LOG) : null;
Random random = rnd.getSingleThreadedRandom();
DBIDArrayIter iter = S.iter();
outer: for(int i = 0; i < n; ++i) {
iter.seek(random.nextInt(S.size()));
for(int j = 0; j < m; ++j) {
DBIDs randomSet = DBIDUtil.randomSample(S, r, random);
long[] nD = BitsUtil.zero(d);
for(int k = 0; k < d; ++k) {
if(dimensionIsRelevant(k, relation, randomSet)) {
BitsUtil.setI(nD, k);
}
}
if(D == null || BitsUtil.cardinality(nD) > BitsUtil.cardinality(D)) {
D = nD;
dV.set(iter);
if(BitsUtil.cardinality(D) >= d_zero) {
if(iprogress != null) {
iprogress.setProcessed(iprogress.getTotal(), LOG);
}
break outer;
}
}
LOG.incrementProcessed(iprogress);
}
}
LOG.ensureCompleted(iprogress);
if(D == null || BitsUtil.cardinality(D) == 0) {
return null;
}
DBIDs C = findNeighbors(dV, D, S, relation);
return (C.size() >= minClusterSize) ? makeCluster(relation, C, D) : null;

protected Cluster<SubspaceModel> runDOC(Database database, Relation<V> relation, ArrayModifiableDBIDs S, final int d, int n, int m, int r, int minClusterSize) DBIDs C = null;
long[] D = null;
double quality = Double.NEGATIVE_INFINITY;
FiniteProgress iprogress = LOG.isVerbose() ? new FiniteProgress("Iteration progress for current cluster", m * n, LOG) : null;
Random random = rnd.getSingleThreadedRandom();
DBIDArrayIter iter = S.iter();
for(int i = 0; i < n; ++i) {
iter.seek(random.nextInt(S.size()));
for(int j = 0; j < m; ++j) {
DBIDs randomSet = DBIDUtil.randomSample(S, r, random);
long[] nD = BitsUtil.zero(d);
for(int k = 0; k < d; ++k) {
if(dimensionIsRelevant(k, relation, randomSet)) {
BitsUtil.setI(nD, k);
}
}
if(BitsUtil.cardinality(nD) > 0) {
DBIDs nC = findNeighbors(iter, nD, S, relation);
if(LOG.isDebuggingFiner()) {
LOG.finer("Testing a cluster candidate, |C| = " + nC.size() + ", |D| = " + BitsUtil.cardinality(nD));
}
if(nC.size() < minClusterSize) {
if(LOG.isDebuggingFiner()) {
LOG.finer("... but it's too small.");
}
continue;
}
double nQuality = computeClusterQuality(nC.size(), BitsUtil.cardinality(nD));
if(nQuality > quality) {
if(LOG.isDebuggingFiner()) {
LOG.finer("... and it's the best so far: " + nQuality + " vs. " + quality);
}
C = nC;
D = nD;
quality = nQuality;
}
else {
if(LOG.isDebuggingFiner()) {
LOG.finer("... but we already have a better one.");
}
}
}
LOG.incrementProcessed(iprogress);
}
}
LOG.ensureCompleted(iprogress);
return (C != null) ? makeCluster(relation, C, D) : null;

protected double[][] splitCentroid(Cluster<? extends MeanModel> parentCluster, Relation<V> relation) double[] parentCentroid = parentCluster.getModel().getMean();
double radius = 0.;
for(DBIDIter it = parentCluster.getIDs().iter(); it.valid(); it.advance()) {
double d = getDistanceFunction().distance(relation.get(it), DoubleVector.wrap(parentCentroid));
radius = (d > radius) ? d : radius;
}
Random random = rnd.getSingleThreadedRandom();
final int dim = RelationUtil.dimensionality(relation);
double[] randomVector = normalize(MathUtil.randomDoubleArray(dim, random));
timesEquals(randomVector, (.4 + random.nextDouble() * .5) * radius);
for(int d = 0; d < dim; d++) {
double a = parentCentroid[d], b = randomVector[d];
parentCentroid[d] = a - b;
randomVector[d] = a + b;
}
return new double[][] { parentCentroid, randomVector };

private void updateMinMax(NumberVector featureVector, double[] minima, double[] maxima) assert (minima.length == featureVector.getDimensionality());
for(int d = 0; d < featureVector.getDimensionality(); d++) {
double v = featureVector.doubleValue(d);
if(v == v) {
maxima[d] = MathUtil.max(v, maxima[d]);
minima[d] = MathUtil.min(v, minima[d]);
}
}

protected void findEigenVectors(double[][] imat, double[][] evs, double[] lambda) final int size = imat.length;
Random rnd = random.getSingleThreadedRandom();
double[] tmp = new double[size];
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Learning projections", tdim, LOG) : null;
for(int d = 0; d < tdim;) {
final double[] cur = evs[d];
randomInitialization(cur, rnd);
double l = multiply(imat, cur, tmp);
for(int iter = 0; iter < 100; iter++) {
double delta = updateEigenvector(tmp, cur, l);
if(delta < 1e-10) {
break;
}
l = multiply(imat, cur, tmp);
}
lambda[d++] = l = estimateEigenvalue(imat, cur);
LOG.incrementProcessed(prog);
if(d == tdim) {
break;
}
updateMatrix(imat, cur, l);
}
LOG.ensureCompleted(prog);

protected void addToStatistics(NumberVector nv) final int d = nv.getDimensionality();
assert (d == ls.length);
this.n++;
for(int i = 0; i < d; i++) {
double v = nv.doubleValue(i);
ls[i] += v;
ss += v * v;
}

protected void randomInitialization(double[] out, Random rnd) double l2 = 0.;
while(!(l2 > 0)) {
for(int d = 0; d < out.length; d++) {
final double val = rnd.nextDouble();
out[d] = val;
l2 += val * val;
}
}
final double s = 1. / FastMath.sqrt(l2);
for(int d = 0; d < out.length; d++) {
out[d] *= s;
}

