public SubGraph getSubGraph(SameDiff sd, DifferentialFunction rootFn) Preconditions.checkState(matches(sd, rootFn), "Root function does not match predicate");
List<DifferentialFunction> childNodes = new ArrayList<>();
if(!opInputSubgraphPredicates.isEmpty()){
for(Map.Entry<Integer,OpPredicate> entry : opInputSubgraphPredicates.entrySet()){
OpPredicate p2 = entry.getValue();
SDVariable arg = rootFn.arg(entry.getKey());
DifferentialFunction df = sd.getVariableOutputFunction(arg.getVarName());
if(df != null){
childNodes.add(df);
if(p2 instanceof SubGraphPredicate){
SubGraph sg = ((SubGraphPredicate) p2).getSubGraph(sd, df);
childNodes.addAll(sg.childNodes);
}
}
}
}
SubGraph sg = SubGraph.builder()
.sameDiff(sd)
.rootNode(rootFn)
.childNodes(childNodes)
.build();
return sg;

public List<Prediction> getPredictionErrors() if (this.confusionMatrixMetaData == null)
return null;
List<Prediction> list = new ArrayList<>();
List<Map.Entry<Pair<Integer, Integer>, List<Object>>> sorted =
new ArrayList<>(confusionMatrixMetaData.entrySet());
Collections.sort(sorted, new Comparator<Map.Entry<Pair<Integer, Integer>, List<Object>>>() {
@Override
public int compare(Map.Entry<Pair<Integer, Integer>, List<Object>> o1,
Map.Entry<Pair<Integer, Integer>, List<Object>> o2) {
Pair<Integer, Integer> p1 = o1.getKey();
Pair<Integer, Integer> p2 = o2.getKey();
int order = Integer.compare(p1.getFirst(), p2.getFirst());
if (order != 0)
return order;
order = Integer.compare(p1.getSecond(), p2.getSecond());
return order;
}
});
for (Map.Entry<Pair<Integer, Integer>, List<Object>> entry : sorted) {
Pair<Integer, Integer> p = entry.getKey();
if (p.getFirst().equals(p.getSecond())) {
continue;
}
for (Object m : entry.getValue()) {
list.add(new Prediction(p.getFirst(), p.getSecond(), m));
}
}
return list;

