}
}
return map;

public static <K, V> List<Map<K, V>> toMapList(Map<K, ? extends Iterable<V>> listMap) final List<Map<K, V>> resultList = new ArrayList<>();
if (isEmpty(listMap)) {
return resultList;
}
boolean isEnd = true;
int index = 0;
Map<K, V> map;
do {
isEnd = true;
map = new HashMap<>();
List<V> vList;
int vListSize;
for (Entry<K, ? extends Iterable<V>> entry : listMap.entrySet()) {
vList = CollectionUtil.newArrayList(entry.getValue());
vListSize = vList.size();
if (index < vListSize) {
map.put(entry.getKey(), vList.get(index));
if (index != vListSize - 1) {
isEnd = false;
}
}
}
if (false == map.isEmpty()) {
resultList.add(map);
}
index++;
} while (false == isEnd);
return resultList;

