static boolean isFieldUnitIgnored(String pattern, int field) int fieldLevel = CALENDAR_FIELD_TO_LEVEL[field];
int level;
char ch;
boolean inQuote = false;
char prevCh = 0;
int count = 0;
for (int i = 0; i < pattern.length(); ++i) {
ch = pattern.charAt(i);
if (ch != prevCh && count > 0) {
level = getLevelFromChar(prevCh);
if (fieldLevel <= level) {
return false;
}
count = 0;
}
if (ch == '\'') {
if ((i+1) < pattern.length() && pattern.charAt(i+1) == '\'') {
++i;
} else {
inQuote = ! inQuote;
}
} else if (!inQuote && isSyntaxChar(ch)) {
prevCh = ch;
++count;
}
}
if (count > 0) {
level = getLevelFromChar(prevCh);
if (fieldLevel <= level) {
return false;
}
}
return true;

private void shapeNonContextually(char[] text, int start, int count) int base;
char minDigit = '0';
if (shapingRange != null) {
base = shapingRange.getDigitBase();
minDigit += shapingRange.getNumericBase();
} else {
base = bases[key];
if (key == ETHIOPIC_KEY) {
minDigit++;
}
}
for (int i = start, e = start + count; i < e; ++i) {
