for (GridEnsembleCoord gec : ensembleCoords) {
gec.setSequence(seqno++);
gec.addDimensionsToNetcdfFile(ncfile, hcs.getGroup());
}
hcs.addDimensionsToNetcdfFile(ncfile);
Collections.sort(vertCoords);
int vcIndex = 0;
