if(x == 0.0) {
return Double.NEGATIVE_INFINITY;
}
if(x >= a + 1) {
return FastMath.log(1.0 - regularizedGammaQ(a, x));
}
double del = 1.0 / a;
double sum = del;
for(int n = 1; n < Integer.MAX_VALUE; n++) {
del *= x / (a + n);
sum = sum + del;
if(Math.abs(del / sum) < NUM_PRECISION || sum >= Double.POSITIVE_INFINITY) {
break;
}
}
if(Double.isInfinite(sum)) {
return 0;
}
return -x + (a * FastMath.log(x)) - logGamma(a) + FastMath.log(sum);

public static double regularizedGammaP(final double a, final double x) if(Double.isInfinite(a) || Double.isInfinite(x) || !(a > 0.0) || !(x >= 0.0)) {
return Double.NaN;
}
if(x == 0.0) {
return 0.0;
}
if(x >= a + 1) {
return 1.0 - regularizedGammaQ(a, x);
}
double term = 1.0 / a;
double sum = term;
for(int n = 1; n < MAX_ITERATIONS; n++) {
term = x / (a + n) * term;
sum = sum + term;
if(sum == Double.POSITIVE_INFINITY) {
return 1.0;
}
if(Math.abs(term / sum) < NUM_PRECISION) {
break;
}
}
return FastMath.exp(-x + (a * FastMath.log(x)) - logGamma(a)) * sum;

