pkt.putInt(packetLen);
if (pktIncludeVersion) {
pkt.putInt(packetVersion);
}
pkt.putLong(offset);
pkt.putLong(seqno);
pkt.put((byte)((offset + len >= endOffset) ? 1 : 0));
pkt.putInt(len);
int checksumOff = pkt.position();
byte[] buf = pkt.array();
blockReader.sendChunks(out, buf, offset, checksumOff,
numChunks, len, crcUpdater, packetVersion);
if (throttler != null) {
throttler.throttle(packetLen);
}
return len;

private int readNextPacket() throws IOException long startTime = System.currentTimeMillis();;
if (buf == null) {
int chunkSize = bytesPerChecksum + checksumSize;
int chunksPerPacket = (datanode.writePacketSize - getPacketHeaderLen() -
SIZE_OF_INTEGER + chunkSize - 1)/chunkSize;
buf = ByteBuffer.allocate(getPacketHeaderLen() + SIZE_OF_INTEGER +
Math.max(chunksPerPacket, 1) * chunkSize);
buf.limit(0);
}
if (bufRead > buf.limit()) {
buf.limit(bufRead);
}
while (buf.remaining() < SIZE_OF_INTEGER) {
if (buf.position() > 0) {
shiftBufData();
}
readToBuf(-1);
}
buf.mark();
int payloadLen = buf.getInt();
buf.reset();
if (payloadLen == 0) {
buf.limit(buf.position() + SIZE_OF_INTEGER);
return 0;
}
if (payloadLen < 0 || payloadLen > (100*1024*1024)) {
throw new IOException("Incorrect value for packet payload : " +
payloadLen);
}
int pktSize = payloadLen + getPacketHeaderLen();
if (buf.remaining() < pktSize) {
int toRead = pktSize - buf.remaining();
int spaceLeft = buf.capacity() - buf.limit();
if (toRead > spaceLeft && buf.position() > 0) {
shiftBufData();
spaceLeft = buf.capacity() - buf.limit();
}
if (toRead > spaceLeft) {
byte oldBuf[] = buf.array();
int toCopy = buf.limit();
buf = ByteBuffer.allocate(toCopy + toRead);
System.arraycopy(oldBuf, 0, buf.array(), 0, toCopy);
buf.limit(toCopy);
}
while (toRead > 0) {
toRead -= readToBuf(toRead);
}
}
if (buf.remaining() > pktSize) {
buf.limit(buf.position() + pktSize);
}
if (pktSize > maxPacketReadLen) {
maxPacketReadLen = pktSize;
}
long readPacketDuration = System.currentTimeMillis() - startTime;
datanode.myMetrics.readPacketLatency.inc(readPacketDuration);
return payloadLen;

protected static int readFully(InputStream stm, byte[] buf, int offset, int len) throws IOException int n = 0;
for (;;) {
int nread = stm.read(buf, offset + n, len - n);
if (nread <= 0)
return (n == 0) ? nread : n;
n += nread;
if (n >= len)
return n;
}

public List<ByteBuffer> readFullyScatterGather(long position, int length) throws IOException byte[] buf = new byte[length];
readFully(position, buf, 0, length);
LinkedList<ByteBuffer> results = new LinkedList<ByteBuffer>();
results.add(ByteBuffer.wrap(buf, 0, length));
return results;

private int readToBuf(int toRead) throws IOException long startTime = System.currentTimeMillis();
if (toRead < 0) {
toRead = (maxPacketReadLen > 0 ? maxPacketReadLen : buf.capacity())
- buf.limit();
}
int nRead = in.read(buf.array(), buf.limit(), toRead);
if (nRead < 0) {
throw new EOFException("while trying to read " + toRead + " bytes");
}
bufRead = buf.limit() + nRead;
buf.limit(bufRead);
long readToBufDuration = System.currentTimeMillis() - startTime;
if (nRead > KB_RIGHT_SHIFT_MIN) {
datanode.myMetrics.largeReadsToBufRate.inc(
(int) (nRead >> KB_RIGHT_SHIFT_BITS),
readToBufDuration);
} else {
datanode.myMetrics.smallReadsToBufRate.inc(nRead, readToBufDuration);
}
datanode.myMetrics.readToBufBytesRead.inc(nRead);
return nRead;

private int read1(byte b[], int off, int len) throws IOException int avail = count-pos;
if( avail <= 0 ) {
if(len>=buf.length) {
int nread = readChecksumChunk(b, off, len);
return nread;
} else {
fill();
if( count <= 0 ) {
return -1;
} else {
avail = count;
}
}
}
int cnt = (avail < len) ? avail : len;
System.arraycopy(buf, pos, b, off, cnt);
pos += cnt;
return cnt;

public synchronized int read(byte[] b, int off, int len) throws IOException if ((off | len | (off + len) | (b.length - (off + len))) < 0) {
throw new IndexOutOfBoundsException();
}
int n = 0;
for (;;) {
int nread = read1(b, off + n, len - n);
if (nread <= 0)
return (n == 0) ? nread : n;
n += nread;
if (n >= len)
return n;
}

private int write1(byte b[], int off, int len) throws IOException eventStartWrite();
try {
if(count==0 && bytesSentInChunk + len>=buf.length) {
final int length = buf.length - bytesSentInChunk;
sum.update(b, off, length);
writeChecksumChunk(b, off, length, false);
bytesSentInChunk = 0;
return length;
}
int bytesToCopy = buf.length - bytesSentInChunk - count;
bytesToCopy = (len<bytesToCopy) ? len : bytesToCopy;
sum.update(b, off, bytesToCopy);
System.arraycopy(b, off, buf, count, bytesToCopy);
count += bytesToCopy;
if (count + bytesSentInChunk == buf.length) {
flushBuffer(true, shouldKeepPartialChunkData());
}
return bytesToCopy;
} finally {
eventEndWrite();
}

