private MultiResult getMultiValue(JsonParser parser, JsonPathCursor cursor) throws IOException cursor.getNext();
MultiResult<Object> multiResult = new MultiResult<Object>();
JsonToken currentToken = parser.currentToken();
if (currentToken != JsonToken.START_ARRAY) {
return null;
}
while (true) {
currentToken = parser.nextToken();
if (currentToken == JsonToken.END_ARRAY) {
break;
}
if (cursor.getCurrent() == null) {
if (currentToken.isScalarValue()) {
multiResult.add(convertJsonTokenToValue(parser));
} else {
parser.skipChildren();
}
} else {
if (currentToken == JsonToken.START_OBJECT && findAttribute(parser, cursor)) {
multiResult.add(convertJsonTokenToValue(parser));
while (parser.getCurrentToken() != JsonToken.END_OBJECT) {
if (parser.currentToken().isStructStart()) {
parser.skipChildren();
}
parser.nextToken();
}
} else if (currentToken == JsonToken.START_ARRAY) {
parser.skipChildren();
}
}
}
return multiResult;

