public IAtomContainer generate(IAtomContainerSet atomContainers) throws CDKException int iteration = 0;
boolean structureFound = false;
do {
iteration++;
boolean bondFormed;
do {
bondFormed = false;
for (IAtomContainer ac : atomContainers.atomContainers()) {
for (IAtom atom : AtomContainerManipulator.getAtomArray(ac)) {
if (!satCheck.isSaturated(atom, ac)) {
IAtom partner = getAnotherUnsaturatedNode(atom, ac, atomContainers);
if (partner != null) {
IAtomContainer toadd = AtomContainerSetManipulator.getRelevantAtomContainer(
atomContainers, partner);
double cmax1 = satCheck.getCurrentMaxBondOrder(atom, ac);
double cmax2 = satCheck.getCurrentMaxBondOrder(partner, toadd);
double max = Math.min(cmax1, cmax2);
double order = Math.min(Math.max(1.0, max), 3.0);
logger.debug("cmax1, cmax2, max, order: " + cmax1 + ", " + cmax2 + ", " + max + ", "
+ order);
if (toadd != ac) {
atomContainers.removeAtomContainer(toadd);
ac.add(toadd);
}
ac.addBond(ac.getBuilder().newInstance(IBond.class, atom, partner,
BondManipulator.createBondOrder(order)));
bondFormed = true;
}
}
}
}
} while (bondFormed);
if (atomContainers.getAtomContainerCount() == 1
&& satCheck.allSaturated(atomContainers.getAtomContainer(0))) {
structureFound = true;
}
} while (!structureFound && iteration < 5);
if (atomContainers.getAtomContainerCount() == 1 && satCheck.allSaturated(atomContainers.getAtomContainer(0))) {
structureFound = true;
}
if (!structureFound)
throw new CDKException("Could not combine the fragments to combine a valid, satured structure");
return atomContainers.getAtomContainer(0);

private IAtomContainerSet readAtomContainerSet(IAtomContainerSet molSet) throws IOException SmilesParser parser = new SmilesParser(molSet.getBuilder());
parser.kekulise(false);
String line = input.readLine();
line = input.readLine();
while (line != null) {
String[] cols = line.split(",");
try {
IAtomContainer mol = parser.parseSmiles(cols[1]);
mol.setProperty("focusSupport", cols[5]);
mol.setProperty("complementSupport", cols[7]);
mol.setProperty("atomCount", cols[2]);
mol.setProperty("bondCount", cols[3]);
molSet.addAtomContainer(mol);
} catch (InvalidSmilesException exception) {
logger.error("Skipping invalid SMILES: " + cols[1]);
logger.debug(exception);
}
line = input.readLine();
}
return molSet;

private IAtomContainerSet getHyperconjugationInteractions(IAtomContainer ac, IAtomContainerSet iSet) throws IOException, ClassNotFoundException, CDKException IAtomContainerSet set = ac.getBuilder().newInstance(IAtomContainerSet.class);
IReactionProcess type = new HeterolyticCleavageSBReaction();
cleanFlagReactiveCenter(ac);
boolean found = false;
IAtomContainerSet setOfReactants = ac.getBuilder().newInstance(IAtomContainerSet.class);
out: for (int i = 0; i < ac.getBondCount(); i++) {
if (ac.getBond(i).getOrder() != IBond.Order.SINGLE) {
for (int j = 0; j < iSet.getAtomContainerCount(); j++) {
IAtomContainer ati = iSet.getAtomContainer(j);
if (!ati.equals(ac))
for (int k = 0; k < ati.getBondCount(); k++) {
IAtom a0 = ati.getBond(k).getBegin();
IAtom a1 = ati.getBond(k).getEnd();
if (!a0.getSymbol().equals("H") || !a1.getSymbol().equals("H"))
if ((a0.getID().equals(ac.getBond(i).getBegin().getID()) && a1.getID().equals(
ac.getBond(i).getEnd().getID()))
|| (a1.getID().equals(ac.getBond(i).getBegin().getID()) && a0.getID().equals(
ac.getBond(i).getEnd().getID()))) {
if (a0.getFormalCharge() != 0 || a1.getFormalCharge() != 0) continue out;
}
}
}
ac.getBond(i).getBegin().setFlag(CDKConstants.REACTIVE_CENTER, true);
ac.getBond(i).getEnd().setFlag(CDKConstants.REACTIVE_CENTER, true);
ac.getBond(i).setFlag(CDKConstants.REACTIVE_CENTER, true);
found = true;
}
}
if (!found) return null;
setOfReactants.addAtomContainer(ac);
List<IParameterReact> paramList = new ArrayList<IParameterReact>();
IParameterReact param = new SetReactionCenter();
param.setParameter(Boolean.TRUE);
paramList.add(param);
type.setParameterList(paramList);
IReactionSet setOfReactions = type.initiate(setOfReactants, null);
for (int i = 0; i < setOfReactions.getReactionCount(); i++) {
type = new HyperconjugationReaction();
IAtomContainerSet setOfM2 = ac.getBuilder().newInstance(IAtomContainerSet.class);
IAtomContainer mol = setOfReactions.getReaction(i).getProducts().getAtomContainer(0);
for (int k = 0; k < mol.getBondCount(); k++) {
mol.getBond(k).setFlag(CDKConstants.REACTIVE_CENTER, false);
mol.getBond(k).getBegin().setFlag(CDKConstants.REACTIVE_CENTER, false);
mol.getBond(k).getEnd().setFlag(CDKConstants.REACTIVE_CENTER, false);
}
setOfM2.addAtomContainer(mol);
List<IParameterReact> paramList2 = new ArrayList<IParameterReact>();
IParameterReact param2 = new SetReactionCenter();
param2.setParameter(Boolean.FALSE);
paramList2.add(param);
type.setParameterList(paramList2);
IReactionSet setOfReactions2 = type.initiate(setOfM2, null);
if (setOfReactions2.getReactionCount() > 0) {
IAtomContainer react = setOfReactions2.getReaction(0).getReactants().getAtomContainer(0);
set.addAtomContainer(react);
}
}
return set;

