public boolean reserveAllocationIfPossible(Long threadId, Integer deviceId, long memorySize) ensureThreadRegistered(threadId, deviceId);
try {
deviceLocks.get(deviceId).writeLock().lock();
addToReservedSpace(deviceId, memorySize);
return true;
} finally {
deviceLocks.get(deviceId).writeLock().unlock();
}

@Override public PointersPair malloc(AllocationShape shape, AllocationPoint point, AllocationStatus location) val reqMemory = AllocationUtils.getRequiredMemory(shape);
