}

@Override public int[][] isolated() List<int[]> isolated = new ArrayList<int[]>(cycles.size());
for (int i = 0; i < cycles.size(); i++) {
if (!fused.get(i)) isolated.add(toArray(cycles.get(i)));
}
return isolated.toArray(new int[isolated.size()][]);

private void addFused(long cycle) int i = indexOfFused(0, cycle);
if (i != -1) {
cycles.set(i, cycle | cycles.get(i));
fused.set(i, Boolean.TRUE);
int j = i;
while ((j = indexOfFused(j + 1, cycles.get(i))) != -1) {
cycles.set(i, cycles.remove(j) | cycles.get(i));
fused.remove(j);
j--;
}
} else {
addIsolated(cycle);
}

private void addFused(BitSet cycle) int i = indexOfFused(0, cycle);
if (i != -1) {
cycles.get(i).or(cycle);
fused.set(i, true);
int j = i;
while ((j = indexOfFused(j + 1, cycle)) != -1) {
cycles.get(i).or(cycles.remove(j));
fused.remove(j);
j--;
}
} else {
addIsolated(cycle);
}

public IRingSet findAllRings(IAtomContainer container, int maxRingSize) throws CDKException final EdgeToBondMap edges = EdgeToBondMap.withSpaceFor(container);
final int[][] graph = GraphUtil.toAdjList(container, edges);
RingSearch rs = new RingSearch(container, graph);
IRingSet ringSet = container.getBuilder().newInstance(IRingSet.class);
for (int[] isolated : rs.isolated()) {
if (isolated.length <= maxRingSize) {
IRing ring = toRing(container, edges, GraphUtil.cycle(graph, isolated));
ringSet.addAtomContainer(ring);
}
}
for (int[] fused : rs.fused()) {
AllCycles ac = new AllCycles(GraphUtil.subgraph(graph, fused), Math.min(maxRingSize, fused.length),
threshold.value);
if (!ac.completed()) throw new CDKException("Threshold exceeded for AllRingsFinder");
for (int[] path : ac.paths()) {
IRing ring = toRing(container, edges, path, fused);
ringSet.addAtomContainer(ring);
}
}
return ringSet;

public int[][] paths() int[][] paths = new int[cycles.size()][];
for (int i = 0; i < cycles.size(); i++)
paths[i] = cycles.get(i).clone();
return paths;

private static int[][] findAromaticRings(int[][] cycles, int[] contribution, int[] dbs) boolean found;
boolean[] checked = new boolean[cycles.length];
final boolean[] aromaticAtoms = new boolean[contribution.length];
final List<int[]> ringsOfSize6 = new ArrayList<int[]>();
final List<int[]> ringsOfSize5 = new ArrayList<int[]>();
do {
found = false;
for (int i = 0; i < cycles.length; i++) {
int[] cycle = cycles[i];
int len = cycle.length - 1;
if (checked[i]) continue;
if (isAromaticRing(cycle, contribution, dbs, aromaticAtoms)) {
checked[i] = true;
found |= true;
for (int j = 0; j < len; j++) {
aromaticAtoms[cycle[j]] = true;
}
if (len == 6)
ringsOfSize6.add(cycle);
else if (len == 5) ringsOfSize5.add(cycle);
}
}
} while (found);
List<int[]> rings = new ArrayList<int[]>();
rings.addAll(ringsOfSize6);
rings.addAll(ringsOfSize5);
return rings.toArray(new int[rings.size()][]);

private int indexOfFused(int start, long cycle) for (int i = start; i < cycles.size(); i++) {
long intersect = cycles.get(i) & cycle;
if (intersect != 0 && Long.bitCount(intersect) > 1) {
return i;
}
}
return -1;

private int indexOfFused(int start, BitSet cycle) for (int i = start; i < cycles.size(); i++) {
if (and(cycles.get(i), cycle).cardinality() > 1) {
return i;
}
}
return -1;

private List<List<Integer>> assignRingGroups(List<Integer[]> rBondsArray) List<List<Integer>> ringGroups;
ringGroups = new ArrayList<List<Integer>>();
for (int i = 0; i < rBondsArray.size() - 1; i++) {
for (int j = 0; j < rBondsArray.get(i).length; j++) {
for (int k = i + 1; k < rBondsArray.size(); k++) {
for (int l = 0; l < rBondsArray.get(k).length; l++) {
if (Objects.equals(rBondsArray.get(i)[j], rBondsArray.get(k)[l])) {
if (i != k) {
ringGroups.add(new ArrayList<Integer>());
ringGroups.get(ringGroups.size() - 1).add(i);
ringGroups.get(ringGroups.size() - 1).add(k);
}
}
}
}
}
}
while (combineGroups(ringGroups));
for (int i = 0; i < rBondsArray.size(); i++) {
boolean found = false;
for (int j = 0; j < ringGroups.size(); j++) {
if (ringGroups.get(j).contains(i)) {
found = true;
break;
}
}
if (!found) {
ringGroups.add(new ArrayList<Integer>());
ringGroups.get(ringGroups.size() - 1).add(i);
}
}
return ringGroups;

private void minimize(int startIndex) if (isMinimized) return;
boolean[][] a = getCycleEdgeIncidenceMatrix();
for (int i = startIndex; i < cycles.size(); i++) {
boolean[] u = constructKernelVector(edgeList.size(), a, i);
AuxiliaryGraph gu = new AuxiliaryGraph(graph, u);
SimpleCycle shortestCycle = cycles.get(i);
Iterator vertexIterator = graph.vertexSet().iterator();
while (vertexIterator.hasNext()) {
Object vertex = vertexIterator.next();
boolean shouldSearchCycle = false;
Collection incidentEdges = graph.edgesOf(vertex);
Iterator edgeIterator = incidentEdges.iterator();
while (edgeIterator.hasNext()) {
Edge edge = (Edge) edgeIterator.next();
int index = getEdgeIndex(edge);
if (u[index]) {
shouldSearchCycle = true;
break;
}
}
if (shouldSearchCycle) {
Object auxVertex0 = gu.auxVertex0(vertex);
Object auxVertex1 = gu.auxVertex1(vertex);
List auxPath = BFSShortestPath.findPathBetween(gu, auxVertex0, auxVertex1);
List edgesOfNewCycle = new Vector();
Object v = vertex;
edgeIterator = auxPath.iterator();
while (edgeIterator.hasNext()) {
Edge auxEdge = (Edge) edgeIterator.next();
Edge e = (Edge) gu.edge(auxEdge);
if (edgesOfNewCycle.contains(e)) {
edgesOfNewCycle.remove(e);
} else {
edgesOfNewCycle.add(e);
}
v = e.oppositeVertex(v);
}
SimpleCycle newCycle = new SimpleCycle(graph, edgesOfNewCycle);
if (newCycle.weight() < shortestCycle.weight()) {
shortestCycle = newCycle;
}
}
}
cycles.set(i, shortestCycle);
for (int j = 0; j < edgeList.size(); j++) {
a[i][j] = shortestCycle.containsEdge((Edge) edgeList.get(j));
}
for (int j = 0; j < i; j++) {
if (a[i][j]) {
for (int k = 0; k < edgeList.size(); k++) {
a[i][k] = (a[i][k] != a[j][k]);
}
}
}
}
isMinimized = true;

Symbol findMemberType(Env<AttrContext> env, Type site, Name name, TypeSymbol c) Symbol sym = findImmediateMemberType(env, site, name, c);
if (sym != typeNotFound)
return sym;
return findInheritedMemberType(env, site, name, c);

Symbol findField(Env<AttrContext> env, Type site, Name name, TypeSymbol c) while (c.type.hasTag(TYPEVAR))
c = c.type.getUpperBound().tsym;
Symbol bestSoFar = varNotFound;
Symbol sym;
for (Symbol s : c.members().getSymbolsByName(name)) {
if (s.kind == VAR && (s.flags_field & SYNTHETIC) == 0) {
return isAccessible(env, site, s)
? s : new AccessError(env, site, s);
}
}
Type st = types.supertype(c.type);
if (st != null && (st.hasTag(CLASS) || st.hasTag(TYPEVAR))) {
sym = findField(env, site, name, st.tsym);
bestSoFar = bestOf(bestSoFar, sym);
}
for (List<Type> l = types.interfaces(c.type);
bestSoFar.kind != AMBIGUOUS && l.nonEmpty();
l = l.tail) {
sym = findField(env, site, name, l.head.tsym);
if (bestSoFar.exists() && sym.exists() &&
sym.owner != bestSoFar.owner)
bestSoFar = new AmbiguityError(bestSoFar, sym);
else
bestSoFar = bestOf(bestSoFar, sym);
}
return bestSoFar;

Symbol findIdentInType(Env<AttrContext> env, Type site, Name name, KindSelector kind) Symbol bestSoFar = typeNotFound;
Symbol sym;
if (kind.contains(KindSelector.VAL)) {
sym = findField(env, site, name, site.tsym);
if (sym.exists()) return sym;
else bestSoFar = bestOf(bestSoFar, sym);
}
if (kind.contains(KindSelector.TYP)) {
sym = findMemberType(env, site, name, site.tsym);
if (sym.exists()) return sym;
else bestSoFar = bestOf(bestSoFar, sym);
}
return bestSoFar;

Symbol findInheritedMemberType(Env<AttrContext> env, Type site, Name name, TypeSymbol c) Symbol bestSoFar = typeNotFound;
Symbol sym;
Type st = types.supertype(c.type);
if (st != null && st.hasTag(CLASS)) {
sym = findMemberType(env, site, name, st.tsym);
bestSoFar = bestOf(bestSoFar, sym);
}
for (List<Type> l = types.interfaces(c.type);
bestSoFar.kind != AMBIGUOUS && l.nonEmpty();
l = l.tail) {
sym = findMemberType(env, site, name, l.head.tsym);
if (!bestSoFar.kind.isResolutionError() &&
!sym.kind.isResolutionError() &&
sym.owner != bestSoFar.owner)
bestSoFar = new AmbiguityError(bestSoFar, sym);
else
bestSoFar = bestOf(bestSoFar, sym);
}
return bestSoFar;

