void placeConnectedRings(IRingSet rs, IRing ring, int handleType, double bondLength) final IRingSet connectedRings = rs.getConnectedRings(ring);
for (IAtomContainer container : connectedRings.atomContainers()) {
final IRing connectedRing = (IRing) container;
if (!connectedRing.getFlag(CDKConstants.ISPLACED)) {
final IAtomContainer sharedAtoms = AtomContainerManipulator.getIntersection(ring, connectedRing);
final int numSharedAtoms = sharedAtoms.getAtomCount();
logger.debug("placeConnectedRings-> connectedRing: " + (ring.toString()));
if ((numSharedAtoms == 2 && handleType == FUSED) ||
(numSharedAtoms == 1 && handleType == SPIRO) ||
(numSharedAtoms > 2  && handleType == BRIDGED)) {
final Point2d sharedAtomsCenter = GeometryUtil.get2DCenter(sharedAtoms);
final Point2d oldRingCenter = GeometryUtil.get2DCenter(ring);
final Vector2d tempVector = (new Vector2d(sharedAtomsCenter));
final Vector2d newRingCenterVector = new Vector2d(tempVector);
newRingCenterVector.sub(new Vector2d(oldRingCenter));
if (Math.abs(newRingCenterVector.x) < 0.001 && Math.abs(newRingCenterVector.y) < 0.001) {
IAtomContainer terminalOnly = molecule.getBuilder().newInstance(IAtomContainer.class);
for (IAtom atom : ring.atoms()) {
if (ring.getConnectedBondsCount(atom) == 1)
terminalOnly.addAtom(atom);
}
if (terminalOnly.getAtomCount() == 2) {
newRingCenterVector.set(GeometryUtil.get2DCenter(terminalOnly));
newRingCenterVector.sub(oldRingCenter);
connectedRing.setProperty(RingPlacer.SNAP_HINT, true);
}
else {
Vector2d vec = new Vector2d(0, 1);
double   bestLen = -Double.MAX_VALUE;
for (int i = 0; i < 12; i++) {
Vector2d orth = new Vector2d(-vec.y, vec.x);
orth.normalize();
double min = Double.MAX_VALUE, max = -Double.MAX_VALUE;
for (IAtom atom : sharedAtoms.atoms()) {
double s = orth.dot(new Vector2d(atom.getPoint2d()));
if (s < min)
min = s;
if (s > max)
max = s;
}
double len = max - min;
if (len > bestLen) {
bestLen = len;
newRingCenterVector.set(vec);
}
rotate(vec, RAD_30);
}
}
}
final Vector2d oldRingCenterVector = new Vector2d(newRingCenterVector);
logger.debug("placeConnectedRing -> tempVector: " + tempVector + ", tempVector.length: "
+ tempVector.length());
logger.debug("placeConnectedRing -> bondCenter: " + sharedAtomsCenter);
logger.debug("placeConnectedRing -> oldRingCenterVector.length(): " + oldRingCenterVector.length());
logger.debug("placeConnectedRing -> newRingCenterVector.length(): " + newRingCenterVector.length());
final Point2d tempPoint = new Point2d(sharedAtomsCenter);
tempPoint.add(newRingCenterVector);
placeRing(connectedRing, sharedAtoms, sharedAtomsCenter, newRingCenterVector, bondLength);
connectedRing.setFlag(CDKConstants.ISPLACED, true);
placeConnectedRings(rs, connectedRing, handleType, bondLength);
}
}
}

public static double[] getMinMax(IAtomContainer container) double maxX = -Double.MAX_VALUE;
double maxY = -Double.MAX_VALUE;
double minX = Double.MAX_VALUE;
double minY = Double.MAX_VALUE;
for (int i = 0; i < container.getAtomCount(); i++) {
IAtom atom = container.getAtom(i);
if (atom.getPoint2d() != null) {
if (atom.getPoint2d().x > maxX) {
maxX = atom.getPoint2d().x;
}
if (atom.getPoint2d().x < minX) {
minX = atom.getPoint2d().x;
}
if (atom.getPoint2d().y > maxY) {
maxY = atom.getPoint2d().y;
}
if (atom.getPoint2d().y < minY) {
minY = atom.getPoint2d().y;
}
}
}
double[] minmax = new double[4];
minmax[0] = minX;
minmax[1] = minY;
minmax[2] = maxX;
minmax[3] = maxY;
return minmax;

private static void validateFormatForViewAction(Format format) throws ApiException switch (format) {
case JSON:
case JSONP:
case XML:
case HTML:
return;
default:
throw new ApiException(ApiException.Type.BAD_FORMAT, "The format OTHER should not be used with views and actions.");
}

public HttpMessage handleApiRequest (HttpRequestHeader requestHeader, HttpInputStream httpIn, HttpOutputStream httpOut, boolean force) throws IOException String url = requestHeader.getURI().toString();
Format format = Format.OTHER;
ApiImplementor callbackImpl = null;
ApiImplementor shortcutImpl = null;
if (url.contains(CALL_BACK_URL)) {
logger.debug("handleApiRequest Callback: " + url);
for (Entry<String, ApiImplementor> callback : callBacks.entrySet()) {
if (url.startsWith(callback.getKey())) {
callbackImpl = callback.getValue();
break;
}
}
if (callbackImpl == null) {
logger.warn("Request to callback URL " + requestHeader.getURI().toString() + " from " +
requestHeader.getSenderAddress().getHostAddress() +
" not found - this could be a callback url from a previous session or possibly an attempt to attack ZAP");
return new HttpMessage();
}
}
String path = requestHeader.getURI().getPath();
if (path != null) {
for (Entry<String, ApiImplementor> shortcut : shortcuts.entrySet()) {
if (path.startsWith(shortcut.getKey())) {
shortcutImpl = shortcut.getValue();
break;
}
}
}
if (shortcutImpl == null && callbackImpl == null && ! url.startsWith(API_URL) && ! url.startsWith(API_URL_S) && ! force) {
return null;
}
if (callbackImpl == null && ! isPermittedAddr(requestHeader)) {
return new HttpMessage();
}
if (getOptionsParamApi().isSecureOnly() && ! requestHeader.isSecure()) {
logger.debug("handleApiRequest rejecting insecure request");
return new HttpMessage();
}
logger.debug("handleApiRequest " + url);
HttpMessage msg = new HttpMessage();
msg.setRequestHeader(requestHeader);
if (requestHeader.getContentLength() > 0) {
msg.setRequestBody(httpIn.readRequestBody(requestHeader));
}
String component = null;
ApiImplementor impl = null;
RequestType reqType = null;
String contentType = "text/plain; charset=UTF-8";
String response = "";
String name = null;
boolean error = false;
try {
if (shortcutImpl != null) {
if (!getOptionsParamApi().isDisableKey() && !getOptionsParamApi().isNoKeyForSafeOps()) {
if ( ! this.hasValidKey(requestHeader, getParams(requestHeader))) {
throw new ApiException(ApiException.Type.BAD_API_KEY);
}
}
msg = shortcutImpl.handleShortcut(msg);
impl = shortcutImpl;
} else if (callbackImpl != null) {
response = callbackImpl.handleCallBack(msg);
impl = callbackImpl;
} else {
JSONObject params = getParams(requestHeader);
String[] elements = url.split("/");
if (elements.length > 3 && elements[3].equalsIgnoreCase("favicon.ico")) {
if (!getOptionsParamApi().isUiEnabled()) {
throw new ApiException(ApiException.Type.DISABLED);
}
InputStream is = API.class.getResourceAsStream("/resource/zap.ico");
byte[] icon = new byte[is.available()];
is.read(icon);
is.close();
msg.setResponseHeader(getDefaultResponseHeader(contentType));
msg.getResponseHeader().setContentLength(icon.length);
httpOut.write(msg.getResponseHeader());
httpOut.write(icon);
httpOut.flush();
httpOut.close();
httpIn.close();
return msg;
} else if (elements.length > 3) {
try {
format = Format.valueOf(elements[3].toUpperCase());
switch (format) {
case JSONP: contentType = "application/javascript; charset=UTF-8";
break;
case XML:	contentType = "text/xml; charset=UTF-8";
break;
case HTML:	contentType = "text/html; charset=UTF-8";
break;
case UI:	contentType = "text/html; charset=UTF-8";
break;
case JSON:
default:
contentType = "application/json; charset=UTF-8";
break;
}
} catch (IllegalArgumentException e) {
format = Format.HTML;
throw new ApiException(ApiException.Type.BAD_FORMAT, e);
}
}
if (elements.length > 4) {
component = elements[4];
impl = implementors.get(component);
if (impl == null) {
throw new ApiException(ApiException.Type.NO_IMPLEMENTOR);
}
}
if (elements.length > 5) {
try {
reqType = RequestType.valueOf(elements[5]);
} catch (IllegalArgumentException e) {
throw new ApiException(ApiException.Type.BAD_TYPE, e);
}
}
if (elements.length > 6) {
name = elements[6];
if (name != null && name.indexOf("?") > 0) {
name = name.substring(0, name.indexOf("?"));
}
}
if (format.equals(Format.UI)) {
if ( ! isEnabled() || !getOptionsParamApi().isUiEnabled()) {
throw new ApiException(ApiException.Type.DISABLED);
}
response = webUI.handleRequest(component, impl, reqType, name);
contentType = "text/html; charset=UTF-8";
} else if (name != null) {
if ( ! isEnabled()) {
throw new ApiException(ApiException.Type.DISABLED);
}
if (requestHeader.getMethod().equalsIgnoreCase(HttpRequestHeader.POST)) {
String contentTypeHeader = requestHeader.getHeader(HttpHeader.CONTENT_TYPE);
if (contentTypeHeader != null
&& contentTypeHeader.equals(HttpHeader.FORM_URLENCODED_CONTENT_TYPE)) {
params = getParams(msg.getRequestBody().toString());
} else {
throw new ApiException(ApiException.Type.CONTENT_TYPE_NOT_SUPPORTED);
}
}
if (format.equals(Format.JSONP)) {
if (!getOptionsParamApi().isEnableJSONP()) {
throw new ApiException(ApiException.Type.DISABLED);
}
if (! this.hasValidKey(requestHeader, params)) {
throw new ApiException(ApiException.Type.BAD_API_KEY);
}
}
ApiResponse res;
switch (reqType) {
case action:
if (!getOptionsParamApi().isDisableKey()) {
if ( ! this.hasValidKey(requestHeader, params)) {
throw new ApiException(ApiException.Type.BAD_API_KEY);
}
}
validateFormatForViewAction(format);
ApiAction action = impl.getApiAction(name);
validateMandatoryParams(params, action);
res = impl.handleApiOptionAction(name, params);
if (res == null) {
res = impl.handleApiAction(name, params);
}
response = convertViewActionApiResponse(format, name, res);
break;
case view:
if (!getOptionsParamApi().isDisableKey() && !getOptionsParamApi().isNoKeyForSafeOps()) {
if ( ! this.hasValidKey(requestHeader, params)) {
throw new ApiException(ApiException.Type.BAD_API_KEY);
}
}
validateFormatForViewAction(format);
ApiView view = impl.getApiView(name);
validateMandatoryParams(params, view);
res = impl.handleApiOptionView(name, params);
if (res == null) {
res = impl.handleApiView(name, params);
}
response = convertViewActionApiResponse(format, name, res);
break;
case other:
ApiOther other = impl.getApiOther(name);
if (other != null) {
if (!getOptionsParamApi().isDisableKey() &&
(!getOptionsParamApi().isNoKeyForSafeOps() ||
other.isRequiresApiKey())) {
if ( ! this.hasValidKey(requestHeader, params)) {
throw new ApiException(ApiException.Type.BAD_API_KEY);
}
}
validateMandatoryParams(params, other);
}
msg = impl.handleApiOther(msg, name, params);
break;
case pconn:
if (impl != null) {
ApiPersistentConnection pconn = impl.getApiPersistentConnection(name);
