else if("ps".equals(format)) {
plot.saveAsPS(file);
}
else if("eps".equals(format)) {
plot.saveAsEPS(file);
}
else if("pdf".equals(format)) {
plot.saveAsPDF(file);
}
else if("svg".equals(format)) {
plot.saveAsSVG(file);
}
else {
