}
List<IAtom> atoms = container.getConnectedAtomsList(a);
IAtom one = null;
IAtom two = null;
boolean doubleBond = false;
IAtom nextAtom = null;
for (IAtom atom : atoms) {
if (!atom.equals(parent) && container.getBond(atom, a).getOrder() == Order.DOUBLE
&& isEndOfDoubleBond(container, atom, a, doubleBondConfiguration)) {
doubleBond = true;
nextAtom = atom;
}
if (!atom.equals(nextAtom) && one == null) {
one = atom;
} else if (!atom.equals(nextAtom) && one != null) {
two = atom;
}
}
String[] morgannumbers = MorganNumbersTools.getMorganNumbersWithElementSymbol(container);
if (one != null
&& ((!a.getSymbol().equals("N")
&& two != null
&& !morgannumbers[container.indexOf(one)].equals(morgannumbers[container
.indexOf(two)]) && doubleBond && doubleBondConfiguration[container.indexOf(container.getBond(
a, nextAtom))]) || (doubleBond && a.getSymbol().equals("N") && Math.abs(giveAngleBothMethods(
nextAtom, a, parent, true)) > Math.PI / 10))) {
return (true);
} else {
return (false);
}

private static boolean suppressibleHydrogen(final IAtomContainer container, final IAtom atom) if (!"H".equals(atom.getSymbol())) return false;
if (atom.getFormalCharge() != null && atom.getFormalCharge() != 0) return false;
if (atom.getMassNumber() != null) return false;
if (atom.getImplicitHydrogenCount() != null && atom.getImplicitHydrogenCount() != 0) return false;
List<IAtom> neighbors = container.getConnectedAtomsList(atom);
if (neighbors.size() == 1 && (neighbors.get(0).getSymbol().equals("H") ||
neighbors.get(0) instanceof IPseudoAtom)) return false;
return true;

public static CoordinateCoverage get3DCoordinateCoverage(IAtomContainer container) if (container == null || container.getAtomCount() == 0) return CoordinateCoverage.NONE;
int count = 0;
for (IAtom atom : container.atoms()) {
count += atom != null && atom.getPoint3d() != null ? 1 : 0;
