private void addSeed(SiteNode node) try {
if (!node.isRoot() && node.getHistoryReference() != null) {
HttpMessage msg = node.getHistoryReference().getHttpMessage();
if (!msg.getResponseHeader().isImage()) {
spider.addSeed(msg);
}
}
} catch (Exception e) {
log.error("Error while adding seed for Spider scan: " + e.getMessage(), e);
}

private void addStartSeeds() if (scanContext != null) {
if (startNode != null && scanContext.isInContext(startNode)) {
addSeed(startNode);
}
if (startURI != null && scanContext.isInContext(startURI.toString())) {
spider.addSeed(startURI);
}
return;
}
if (justScanInScope) {
if (startNode != null && Model.getSingleton().getSession().isInScope(startNode)) {
addSeed(startNode);
}
if (startURI != null && Model.getSingleton().getSession().isInScope(startURI.toString())) {
spider.addSeed(startURI);
}
return;
}
if (startNode != null) {
addSeeds(startNode);
}
if (startURI != null) {
spider.addSeed(startURI);
}

public void start() log.info("Starting spider...");
this.timeStarted = System.currentTimeMillis();
fetchFilterSeeds();
if (seedList == null || seedList.isEmpty()) {
log.warn("No seeds available for the Spider. Cancelling scan...");
notifyListenersSpiderComplete(false);
notifyListenersSpiderProgress(100, 0, 0);
return;
}
if (scanUser != null)
log.info("Scan will be performed from the point of view of User: " + scanUser.getName());
this.controller.init();
this.stopped = false;
this.paused = false;
this.initialized = false;
this.threadPool = Executors.newFixedThreadPool(spiderParam.getThreadCount(),
new SpiderThreadFactory("ZAP-SpiderThreadPool-" + id + "-thread-"));
httpSender = new HttpSender(
connectionParam,
connectionParam.isHttpStateEnabled() ? true : !spiderParam.isAcceptCookies(),
HttpSender.SPIDER_INITIATOR);
httpSender.setFollowRedirect(false);
for (URI uri : seedList) {
if (log.isDebugEnabled()) {
log.debug("Adding seed for spider: " + uri);
}
controller.addSeed(uri, HttpRequestHeader.GET);
}
initialized = true;

