private static ModifiableDBIDs internalIntersection(DBIDs first, DBIDs second) second = second.size() > 16 && !(second instanceof SetDBIDs) ? newHashSet(second) : second;
ModifiableDBIDs inter = newHashSet(first.size());
for(DBIDIter it = first.iter(); it.valid(); it.advance()) {
if(second.contains(it)) {
inter.add(it);
}
}
return inter;

private static int internalIntersectionSize(DBIDs first, DBIDs second) second = second.size() > 16 && !(second instanceof SetDBIDs) ? newHashSet(second) : second;
int c = 0;
for(DBIDIter it = first.iter(); it.valid(); it.advance()) {
if(second.contains(it)) {
c++;
}
}
return c;

public static ModifiableDBIDs intersection(DBIDs first, DBIDs second) if(second instanceof SetDBIDs) {
if(!(first instanceof SetDBIDs)) {
return internalIntersection(first, second);
}
}
else if(first instanceof SetDBIDs) {
return internalIntersection(second, first);
}
return first.size() <= second.size() ? internalIntersection(first, second) : internalIntersection(second, first);

public void bulkLoad(DBIDs ids) if(ids.size() == 0) {
return;
}
assert (root == null) : "Tree already initialized.";
DBIDIter it = ids.iter();
DBID first = DBIDUtil.deref(it);
ModifiableDoubleDBIDList candidates = DBIDUtil.newDistanceDBIDList(ids.size() - 1);
for(it.advance(); it.valid(); it.advance()) {
candidates.add(distance(first, it), it);
}
root = bulkConstruct(first, Integer.MAX_VALUE, candidates);

protected static <T> double initialWeights(WritableDoubleDataStore weights, Relation<? extends T> relation, DBIDs ids, T first, T second, DistanceQuery<? super T> distQ) double weightsum = 0.;
for(DBIDIter it = ids.iter(); it.valid(); it.advance()) {
T v = relation.get(it);
double weight = Math.min(distQ.distance(first, v), distQ.distance(second, v));
weights.putDouble(it, weight);
weightsum += weight;
}
return weightsum;

public static int intersectionSize(DBIDs first, DBIDs second) if(second instanceof SetDBIDs) {
if(!(first instanceof SetDBIDs)) {
return internalIntersectionSize(first, second);
}
}
else if(first instanceof SetDBIDs) {
return internalIntersectionSize(second, first);
}
return first.size() <= second.size() ? internalIntersectionSize(first, second) : internalIntersectionSize(second, first);

private List<PROCLUSCluster> finalAssignment(List<Pair<double[], long[]>> dimensions, Relation<V> database) Map<Integer, ModifiableDBIDs> clusterIDs = new HashMap<>();
for(int i = 0; i < dimensions.size(); i++) {
clusterIDs.put(i, DBIDUtil.newHashSet());
}
for(DBIDIter it = database.iterDBIDs(); it.valid(); it.advance()) {
V p = database.get(it);
double minDist = Double.POSITIVE_INFINITY;
int best = -1;
for(int i = 0; i < dimensions.size(); i++) {
Pair<double[], long[]> pair_i = dimensions.get(i);
double currentDist = manhattanSegmentalDistance(p, pair_i.first, pair_i.second);
if(best < 0 || currentDist < minDist) {
minDist = currentDist;
best = i;
}
}
assert minDist >= 0.;
clusterIDs.get(best).add(it);
}
List<PROCLUSCluster> clusters = new ArrayList<>();
for(int i = 0; i < dimensions.size(); i++) {
ModifiableDBIDs objectIDs = clusterIDs.get(i);
if(!objectIDs.isEmpty()) {
long[] clusterDimensions = dimensions.get(i).second;
double[] centroid = Centroid.make(database, objectIDs).getArrayRef();
clusters.add(new PROCLUSCluster(objectIDs, clusterDimensions, centroid));
}
}
if(LOG.isDebugging()) {
LOG.debugFine(new StringBuilder().append("clusters ").append(clusters).toString());
}
return clusters;

private int maxIntersection(Map<Integer, ModifiableDBIDs> candidates, ModifiableDBIDs set) int maxDim = -1;
ModifiableDBIDs maxIntersection = null;
for(Integer nextDim : candidates.keySet()) {
DBIDs nextSet = candidates.get(nextDim);
ModifiableDBIDs nextIntersection = DBIDUtil.intersection(set, nextSet);
if(maxDim < 0 || maxIntersection.size() < nextIntersection.size()) {
maxIntersection = nextIntersection;
maxDim = nextDim;
}
}
if(maxDim >= 0) {
set.clear();
set.addDBIDs(maxIntersection);
}
return maxDim;

protected void collectByCover(DBIDRef cur, ModifiableDoubleDBIDList candidates, double fmax, ModifiableDoubleDBIDList collect) assert (collect.size() == 0) : "Not empty";
DoubleDBIDListIter it = candidates.iter().advance();
while(it.valid()) {
assert (!DBIDUtil.equal(cur, it));
final double dist = distance(cur, it);
if(dist <= fmax) {
collect.add(dist, it);
candidates.removeSwap(it.getOffset());
}
else {
it.advance();
}
}

static double initialWeights(WritableDoubleDataStore weights, DBIDs ids, NumberVector first, DistanceQuery<? super NumberVector> distQ) double weightsum = 0.;
for(DBIDIter it = ids.iter(); it.valid(); it.advance()) {
double weight = distQ.distance(first, it);
weights.putDouble(it, weight);
weightsum += weight;
}
return weightsum;

