}
m_message = null;
if (cms.getRequestContext().getCurrentUser().isGuestUser()) {
m_action = ACTION_DISPLAY;
m_username = CmsRequestUtil.getNotEmptyParameter(getRequest(), PARAM_USERNAME);
if (m_username != null) {
