private float[] getData40(RandomAccessFile raf, Grib2Drs.Type40 gdrs) throws IOException int nb = gdrs.numberOfBits;
int D = gdrs.decimalScaleFactor;
float DD = (float) java.lang.Math.pow((double) 10, (double) D);
float R = gdrs.referenceValue;
int E = gdrs.binaryScaleFactor;
float EE = (float) java.lang.Math.pow(2.0, (double) E);
float ref_val = R / DD;
Grib2JpegDecoder g2j = null;
if (nb != 0) {
g2j = new Grib2JpegDecoder(nb, false);
byte[] buf = new byte[dataLength - 5];
raf.readFully(buf);
g2j.decode(buf);
gdrs.hasSignedProblem = g2j.hasSignedProblem();
}
float[] result = new float[totalNPoints];
if (nb == 0) {
for (int i = 0; i < dataNPoints; i++) {
result[i] = ref_val;
}
return result;
}
int[] idata = g2j.getGdata();
if (bitmap == null) {
if (idata.length != dataNPoints) {
logger.debug("Number of points in the data record {} != {} expected from GDS", idata.length,
dataNPoints);
throw new IllegalStateException(
"Number of points in the data record {} != expected from GDS");
}
for (int i = 0; i < dataNPoints; i++) {
result[i] = (R + idata[i] * EE) / DD;
}
return result;
} else {
for (int i = 0, j = 0; i < totalNPoints; i++) {
if (GribNumbers.testBitIsSet(bitmap[i / 8], i % 8)) {
if (j >= idata.length) {
logger.warn("HEY jj2000 data count %d < bitmask count %d, i=%d, totalNPoints=%d%n",
idata.length, j, i, totalNPoints);
break;
}
int indata = idata[j];
result[i] = (R + indata * EE) / DD;
j++;
} else {
result[i] = staticMissingValue;
}
}
}
return result;

static public List<String> collectValues(String text) throws ParseException List<String> values = new ArrayList<String>();
StringBuffer buf = new StringBuffer();
text = text.trim() + '\0';
int i = 0;
for(; ; ) {
char c = text.charAt(i++);
if(c == '\0') break;
if(c <= ' ' || c == 127)
continue;
if(c == '\'') {
c = text.charAt(i++);
if(c == '\0')
throw new ParseException("Malformed char constant: no final '''");
else if(i >= 128)
throw new ParseException("Illegal char constant: " + (int) c);
buf.append(c);
values.add(buf.toString());
buf.setLength(0);
} else if(c == '"') {
for(; ; ) {
c = text.charAt(i++);
if(c == '\0') {
i--;
break;
}
if(c == '\\') {
c = text.charAt(i++);
} else if(c == '"') break;
buf.append(c);
}
if(c == '\0')
throw new ParseException("Malformed string: no final '\"'");
values.add(buf.toString());
buf.setLength(0);
} else {
do {
if(c == '\\') {
c = text.charAt(i++);
}
buf.append(c);
c = text.charAt(i++);
} while(c > ' ' && c != 127);
values.add(buf.toString());
buf.setLength(0);
if(c == 0) i--;
}
}
return values;

