public double[] getDoublesByName(String Name) DbaseData d;
if ((d = getField(Name)) == null) return null;
if (d.getType() == DbaseData.TYPE_CHAR) {
String[] s = d.getStrings();
double[] dd = new double[s.length];
for (int i = 0; i < s.length; i++) {
dd[i] = Double.valueOf(s[i]);
}
return dd;
}
if (d.getType() == DbaseData.TYPE_BOOLEAN) {
boolean[] b = d.getBooleans();
double[] dd = new double[b.length];
for (int i = 0; i < b.length; i++) {
if (b[i]) {
dd[i] = 1;
} else {
dd[i] = 0;
}
}
return dd;
}
return d.getDoubles();

static public List<String> backslashsplit(String s, char sep) List<String> path = new ArrayList<String>();
int len = s.length();
StringBuilder piece = new StringBuilder();
int i = 0;
for(; i <= len - 1; i++) {
char c = s.charAt(i);
if(c == '\\' && i < (len - 1)) {
piece.append(c);
piece.append(s.charAt(++i));
} else if(c == sep) {
path.add(piece.toString());
piece.setLength(0);
} else
piece.append(c);
}
path.add(piece.toString());
return path;

