public static int[] toRational(double d) if (d == 0)
return new int[]{0, 0};
if (!ErddapMath2.isFinite(d))
return new int[]{1, Integer.MAX_VALUE};
String s = "" + d;
int ten = 0;
int epo = s.indexOf('E');
if (epo > 0) {
ten = parseInt(s.substring(epo + 1));
s = s.substring(0, epo);
}
if (s.endsWith(".0"))
s = s.substring(0, s.length() - 2);
int dpo = s.indexOf('.');
if (dpo > 0) {
ten -= s.length() - dpo - 1;
s = s.substring(0, dpo) + s.substring(dpo + 1);
}
long tl = parseLong(s);
while (Math.abs(tl) > 1000000000) {
tl = Math.round(tl / 10.0);
ten++;
}
while (tl != 0 && tl / 10 == tl / 10.0) {
tl /= 10;
ten++;
}
if (tl < 100000 && ten >= 1 && ten <= 3) {
while (ten > 0) {
tl *= 10;
ten--;
}
}
return new int[]{(int)tl, ten};

