public static int asIntExactly(Number number) Class clazz = number.getClass();
if (isLongRepresentableExceptLong(clazz)) {
return number.intValue();
} else if (clazz == Long.class) {
int intValue = number.intValue();
if (number.longValue() == (long) intValue) {
return intValue;
}
} else if (isDoubleRepresentable(clazz)) {
int intValue = number.intValue();
if (equalDoubles(number.doubleValue(), (double) intValue)) {
return intValue;
}
}
throw new IllegalArgumentException("Can't represent " + number + " as int exactly");

public static Comparable canonicalizeForHashLookup(Comparable value) Class clazz = value.getClass();
assert value instanceof Number;
Number number = (Number) value;
if (isDoubleRepresentable(clazz)) {
double doubleValue = number.doubleValue();
long longValue = number.longValue();
if (equalDoubles(doubleValue, (double) longValue)) {
return longValue;
} else if (clazz == Float.class) {
return doubleValue;
}
} else if (isLongRepresentableExceptLong(clazz)) {
return number.longValue();
}
return value;

public static String resolve(String baseUri, String relativeUri) if ((baseUri == null) || (relativeUri == null))
return relativeUri;
if (relativeUri.startsWith("file:"))
return relativeUri;
if (baseUri.startsWith("file:")) {
try {
URI uriRelative = URI.create(relativeUri);
if (uriRelative.isAbsolute())
return relativeUri;
} catch (Exception e) {
}
if ((relativeUri.length() > 0) && (relativeUri.charAt(0) == '#'))
return baseUri + relativeUri;
if ((relativeUri.length() > 0) && (relativeUri.charAt(0) == '/'))
return relativeUri;
baseUri = StringUtil2.substitute(baseUri, "\\", "/");
int pos = baseUri.lastIndexOf('/');
if (pos > 0) {
String baseDir = baseUri.substring(0, pos + 1);
if (relativeUri.equals(".")) {
return baseDir;
} else {
return baseDir + relativeUri;
}
}
}
try {
URI relativeURI = URI.create(relativeUri);
if (relativeURI.isAbsolute())
return relativeUri;
URI baseURI = URI.create(baseUri);
URI resolvedURI = baseURI.resolve(relativeURI);
return resolvedURI.toASCIIString();
} catch (IllegalArgumentException e) {
return  relativeUri;
}

