public void emitRecord(String contextName, String recordName, OutputRecord outRec) throws IOException Calendar currentDate = Calendar.getInstance();
if (fileName != null) {
if (currentDate.get(Calendar.DAY_OF_MONTH) != lastRecordDate.get(Calendar.DAY_OF_MONTH)) {
file = new File(getFullFileName(currentDate));
if (writer != null)
writer.close();
writer = new PrintWriter(new FileWriter(file, true));
}
}
writer.print(recordDateFormat.format(currentDate.getTime()));
writer.print(" ");
writer.print(contextName);
writer.print(".");
writer.print(recordName);
String separator = ": ";
for (String tagName : outRec.getTagNames()) {
writer.print(separator);
separator = ", ";
writer.print(tagName);
writer.print("=");
writer.print(outRec.getTag(tagName));
}
for (String metricName : outRec.getMetricNames()) {
writer.print(separator);
separator = ", ";
writer.print(metricName);
writer.print("=");
writer.print(outRec.getMetric(metricName));
}
writer.println();
lastRecordDate = currentDate;

public List<ResourceReport> getResourceReportList(String resourceType) Map<Integer, ResourceReport> resourceReportMap =
new TreeMap<Integer, ResourceReport>();
synchronized (lockObject) {
for (Map.Entry<TaskAttemptID, Integer> entry :
taskLookupTable.taskIdToGrantMap.entrySet()) {
if (ResourceTracker.isNoneGrantId(entry.getValue())) {
continue;
}
if ((resourceType.equals("map") && entry.getKey().isMap()) ||
(resourceType.equals("reduce") && !entry.getKey().isMap())) {
resourceReportMap.put(entry.getValue(),
new ResourceReport(entry.getValue(), entry.getKey().toString()));
}
}
for (Integer grantId : resourceTracker.availableResources) {
if (!resourceReportMap.containsKey(grantId)) {
resourceReportMap.put(grantId,
new ResourceReport(grantId, "Available (currently not in use)"));
}
}
}
return new ArrayList<ResourceReport>(resourceReportMap.values());

public List<String> getFreeNodesForType(ResourceType type) ArrayList<String> freeNodes = new ArrayList<String>();
for (Map.Entry<String, ClusterNode> entry: nameToNode.entrySet()) {
ClusterNode node = entry.getValue();
synchronized (node) {
if (!node.deleted &&
node.getMaxCpuForType(type) > node.getAllocatedCpuForType(type)) {
freeNodes.add(entry.getKey() + ": " + node.getFree().toString());
}
}
}
return freeNodes;

