private void buildTree(int left, int right, int axis, DoubleDBIDListMIter iter) assert (left < right);
for(iter.seek(left); iter.getOffset() < right; iter.advance()) {
iter.setDouble(relation.get(iter).doubleValue(axis));
countObjectAccess();
}
if(right - left <= leafsize) {
return;
}
int middle = (left + right) >>> 1;
QuickSelectDBIDs.quickSelect(sorted, left, right, middle);
final int next = (axis + 1) % dims;
if(left < middle) {
buildTree(left, middle, next, iter);
}
++middle;
if(middle < right) {
buildTree(middle, right, next, iter);
}

private static void quickSortReverse(double[] keys, int[] vals, final int start, final int end) final int len = end - start;
if(len < INSERTION_THRESHOLD) {
insertionSortReverse(keys, vals, start, end);
return;
}
final int last = end - 1;
final int seventh = (len >> 3) + (len >> 6) + 1;
final int m3 = (start + end) >> 1;
final int m2 = m3 - seventh;
final int m1 = m2 - seventh;
final int m4 = m3 + seventh;
final int m5 = m4 + seventh;
sortReverse5(keys, vals, m1, m2, m3, m4, m5);
double pivotkey = keys[m3];
int pivotval = vals[m3];
keys[m3] = keys[start];
vals[m3] = vals[start];
int left = start + 1;
int right = last;
while(true) {
while(left <= right && keys[left] > pivotkey) {
left++;
}
while(left <= right && pivotkey >= keys[right]) {
right--;
}
if(right <= left) {
break;
}
swap(keys, vals, left, right);
left++;
right--;
}
keys[start] = keys[right];
vals[start] = vals[right];
keys[right] = pivotkey;
vals[right] = pivotval;
if(start + 1 < right) {
quickSortReverse(keys, vals, start, right);
}
int rstart = right + 1;
while(rstart < last && keys[rstart] >= keys[right]) {
rstart++;
}
if(rstart < last) {
quickSortReverse(keys, vals, rstart, end);
}

private static void quickSort(double[] keys, int[] vals, final int start, final int end) final int len = end - start;
if(len < INSERTION_THRESHOLD) {
insertionSort(keys, vals, start, end);
return;
}
final int last = end - 1;
final int seventh = (len >> 3) + (len >> 6) + 1;
final int m3 = (start + end) >> 1;
final int m2 = m3 - seventh;
final int m1 = m2 - seventh;
final int m4 = m3 + seventh;
final int m5 = m4 + seventh;
sort5(keys, vals, m1, m2, m3, m4, m5);
double pivotkey = keys[m3];
int pivotval = vals[m3];
keys[m3] = keys[start];
vals[m3] = vals[start];
int left = start + 1;
int right = last;
while(true) {
while(left <= right && keys[left] < pivotkey) {
left++;
}
while(left <= right && pivotkey <= keys[right]) {
right--;
}
if(right <= left) {
break;
}
swap(keys, vals, left, right);
left++;
right--;
}
keys[start] = keys[right];
vals[start] = vals[right];
keys[right] = pivotkey;
vals[right] = pivotval;
if(start + 1 < right) {
quickSort(keys, vals, start, right);
}
int rstart = right + 1;
while(rstart < last && keys[rstart] <= keys[right]) {
rstart++;
}
if(rstart < last) {
quickSort(keys, vals, rstart, end);
}

private static void quickSort(int[] data, final int start, final int end, IntComparator comp) final int len = end - start;
final int last = end - 1;
if(len < INSERTION_THRESHOLD) {
insertionSort(data, start, end, comp);
return;
}
final int seventh = (len >> 3) + (len >> 6) + 1;
final int m3 = (start + end) >> 1;
final int m2 = m3 - seventh;
final int m1 = m2 - seventh;
final int m4 = m3 + seventh;
final int m5 = m4 + seventh;
sort5(data, m1, m2, m3, m4, m5, comp);
final int lpivot = data[m2];
final int rpivot = data[m4];
data[m2] = data[start];
data[m4] = data[last];
final boolean tied = comp.compare(lpivot, rpivot) == 0;
int left = start + 1;
int right = last - 1;
for(int k = left; k <= right; k++) {
final int tmp = data[k];
final int c = comp.compare(tmp, lpivot);
if(c == 0) {
continue;
}
else if(c < 0) {
data[k] = data[left];
data[left] = tmp;
left++;
}
else if(tied || comp.compare(tmp, rpivot) > 0) {
while(true) {
final int tmp2 = data[right];
if(comp.compare(tmp2, rpivot) > 0 && k < right) {
right--;
}
else {
break;
}
}
data[k] = data[right];
data[right] = tmp;
right--;
if(comp.compare(data[k], lpivot) < 0) {
final int tmp2 = data[k];
data[k] = data[left];
data[left] = tmp2;
left++;
}
}
}
data[start] = data[left - 1];
data[left - 1] = lpivot;
data[last] = data[right + 1];
data[right + 1] = rpivot;
quickSort(data, start, left - 1, comp);
if(!tied) {
quickSort(data, left, right + 1, comp);
}
quickSort(data, right + 2, end, comp);

private void buildTree(int left, int right, int axis, SortDBIDsBySingleDimension comp) int middle = (left + right) >>> 1;
comp.setDimension(axis);
QuickSelectDBIDs.quickSelect(sorted, comp, left, right, middle);
final int next = (axis + 1) % dims;
if(left + leafsize < middle) {
buildTree(left, middle, next, comp);
}
++middle;
if(middle + leafsize < right) {
buildTree(middle, right, next, comp);
}

public void dfs(CLIQUEUnit unit, ModifiableDBIDs cluster, CLIQUESubspace model) cluster.addDBIDs(unit.getIds());
unit.markAsAssigned();
model.addDenseUnit(unit);
final long[] dims = getDimensions();
for(int dim = BitsUtil.nextSetBit(dims, 0); dim >= 0; dim = BitsUtil.nextSetBit(dims, dim + 1)) {
CLIQUEUnit left = leftNeighbor(unit, dim);
if(left != null && !left.isAssigned()) {
dfs(left, cluster, model);
}
CLIQUEUnit right = rightNeighbor(unit, dim);
if(right != null && !right.isAssigned()) {
dfs(right, cluster, model);
}
}

private static void quickSort(int[] data, final int start, final int end, Comparator<? super DBIDRef> comp, IntegerDBIDVar vl, IntegerDBIDVar vk, IntegerDBIDVar vr) final int len = end - start;
if(len < INSERTION_THRESHOLD) {
for(int i = start + 1; i <= end; i++) {
for(int j = i; j > start; j--) {
vl.internalSetIndex(data[j]);
vr.internalSetIndex(data[j - 1]);
if(comp.compare(vl, vr) < 0) {
int tmp = data[j - 1];
data[j - 1] = data[j];
data[j] = tmp;
}
else {
break;
}
}
}
return;
}
final int seventh = (len >> 3) + (len >> 6) + 1;
final int m3 = (start + end) >> 1;
final int m2 = m3 - seventh;
final int m1 = m2 - seventh;
final int m4 = m3 + seventh;
final int m5 = m4 + seventh;
if(compare(vl, data[m1], vk, data[m2], comp) > 0) {
int tmp = data[m2];
data[m2] = data[m1];
data[m1] = tmp;
}
if(compare(vl, data[m1], vk, data[m3], comp) > 0) {
int tmp = data[m3];
data[m3] = data[m1];
data[m1] = tmp;
}
if(compare(vl, data[m2], vk, data[m3], comp) > 0) {
int tmp = data[m3];
data[m3] = data[m2];
data[m2] = tmp;
}
if(compare(vl, data[m4], vk, data[m5], comp) > 0) {
int tmp = data[m5];
data[m5] = data[m4];
data[m4] = tmp;
}
if(compare(vl, data[m1], vk, data[m4], comp) > 0) {
int tmp = data[m4];
data[m4] = data[m1];
data[m1] = tmp;
}
if(compare(vl, data[m3], vk, data[m4], comp) > 0) {
int tmp = data[m4];
data[m4] = data[m3];
data[m3] = tmp;
}
if(compare(vl, data[m2], vk, data[m5], comp) > 0) {
int tmp = data[m5];
data[m5] = data[m2];
data[m2] = tmp;
}
if(compare(vl, data[m2], vk, data[m3], comp) > 0) {
int tmp = data[m3];
data[m3] = data[m2];
data[m2] = tmp;
}
if(compare(vl, data[m4], vk, data[m5], comp) > 0) {
int tmp = data[m5];
data[m5] = data[m4];
data[m4] = tmp;
}
vl.internalSetIndex(data[m2]);
vr.internalSetIndex(data[m4]);
data[m2] = data[start];
data[m4] = data[end];
final boolean tied = comp.compare(vl, vr) == 0;
int left = start + 1;
int right = end - 1;
for(int k = left; k <= right; k++) {
int tmp = data[k];
vk.internalSetIndex(tmp);
final int c = comp.compare(vk, vl);
if(c == 0) {
continue;
}
else if(c < 0) {
data[k] = data[left];
data[left] = tmp;
left++;
}
else if(tied || comp.compare(vk, vr) > 0) {
while(true) {
vk.internalSetIndex(data[right]);
if(comp.compare(vk, vr) > 0 && k < right) {
right--;
}
else {
break;
}
}
data[k] = data[right];
data[right] = tmp;
right--;
vk.internalSetIndex(data[k]);
if(comp.compare(vk, vl) < 0) {
tmp = data[k];
data[k] = data[left];
data[left] = tmp;
left++;
}
}
}
data[start] = data[left - 1];
data[left - 1] = vl.internalGetIndex();
data[end] = data[right + 1];
data[right + 1] = vr.internalGetIndex();
quickSort(data, start, left - 2, comp, vl, vk, vr);
if(!tied) {
quickSort(data, left, right, comp, vl, vk, vr);
}
quickSort(data, right + 2, end, comp, vl, vk, vr);

public static double median(double[] data, int begin, int end) final int length = end - begin;
assert (length > 0);
final int left = begin + ((length - 1) >> 1);
quickSelect(data, begin, end, left);
if(length % 2 == 1) {
return data[left];
}
else {
quickSelect(data, left + 1, end, left + 1);
return data[left] + .5 * (data[left + 1] - data[left]);
}

private int binarySearch(List<SparseItemset> candidates, SparseItemset scratch, int begin, int end) --end;
while(begin < end) {
final int mid = (begin + end) >>> 1;
SparseItemset midVal = candidates.get(mid);
int cmp = midVal.compareTo(scratch);
if(cmp < 0) {
begin = mid + 1;
}
else if(cmp > 0) {
end = mid - 1;
}
else {
return mid;
}
}
return -(begin + 1);

public static int median(ArrayModifiableDBIDs data, Comparator<? super DBIDRef> comparator, int begin, int end) final int length = end - begin;
assert (length > 0);
final int left = begin + ((length - 1) >> 1);
quickSelect(data, comparator, begin, end, left);
return left;

