private CatchStatement createCatchBlockForOuterNewTryCatchStatement(String primaryExcName) BlockStatement blockStatement = new BlockStatement();
String tExcName = this.genTExcName();
ExpressionStatement primaryExcAssignStatement =
new ExpressionStatement(
new BinaryExpression(
new VariableExpression(primaryExcName),
