public Clustering<M> run(Database database, Relation<V> relation) if(relation.size() == 0) {
throw new IllegalArgumentException("database empty: must contain elements");
}
List<? extends EMClusterModel<M>> models = mfactory.buildInitialModels(database, relation, k, SquaredEuclideanDistanceFunction.STATIC);
WritableDataStore<double[]> probClusterIGivenX = DataStoreUtil.makeStorage(relation.getDBIDs(), DataStoreFactory.HINT_HOT | DataStoreFactory.HINT_SORTED, double[].class);
double loglikelihood = assignProbabilitiesToInstances(relation, models, probClusterIGivenX);
DoubleStatistic likestat = LOG.isStatistics() ? new DoubleStatistic(this.getClass().getName() + ".loglikelihood") : null;
if(LOG.isStatistics()) {
LOG.statistics(likestat.setDouble(loglikelihood));
}
int it = 0, lastimprovement = 0;
double bestloglikelihood = loglikelihood;
for(++it; it < maxiter || maxiter < 0; it++) {
final double oldloglikelihood = loglikelihood;
recomputeCovarianceMatrices(relation, probClusterIGivenX, models, prior);
loglikelihood = assignProbabilitiesToInstances(relation, models, probClusterIGivenX);
if(LOG.isStatistics()) {
LOG.statistics(likestat.setDouble(loglikelihood));
}
if(loglikelihood - bestloglikelihood > delta) {
lastimprovement = it;
bestloglikelihood = loglikelihood;
}
if(Math.abs(loglikelihood - oldloglikelihood) <= delta || lastimprovement < it >> 1) {
break;
}
}
if(LOG.isStatistics()) {
LOG.statistics(new LongStatistic(KEY + ".iterations", it));
}
List<ModifiableDBIDs> hardClusters = new ArrayList<>(k);
for(int i = 0; i < k; i++) {
hardClusters.add(DBIDUtil.newArray());
}
for(DBIDIter iditer = relation.iterDBIDs(); iditer.valid(); iditer.advance()) {
hardClusters.get(argmax(probClusterIGivenX.get(iditer))).add(iditer);
}
Clustering<M> result = new Clustering<>("EM Clustering", "em-clustering");
for(int i = 0; i < k; i++) {
result.addToplevelCluster(new Cluster<>(hardClusters.get(i), models.get(i).finalizeCluster()));
}
if(isSoft()) {
result.addChildResult(new MaterializedRelation<>("cluster assignments", "em-soft-score", SOFT_TYPE, probClusterIGivenX, relation.getDBIDs()));
}
else {
probClusterIGivenX.destroy();
}
return result;

public static <V extends NumberVector> double logLikelihoodZhao(Relation<V> relation, Clustering<? extends MeanModel> clustering, NumberVectorDistanceFunction<? super V> distanceFunction) List<? extends Cluster<? extends MeanModel>> clusters = clustering.getAllClusters();
final int m = clusters.size();
int n = 0;
int[] n_i = new int[m];
double[] d_i = new double[m];
Iterator<? extends Cluster<? extends MeanModel>> it = clusters.iterator();
for(int i = 0; it.hasNext(); ++i) {
Cluster<? extends MeanModel> cluster = it.next();
n += n_i[i] = cluster.size();
d_i[i] = varianceOfCluster(cluster, distanceFunction, relation) / (double) n_i[i];
}
final int dim = RelationUtil.dimensionality(relation);
double logLikelihood = 0.;
for(int i = 0; i < m; i++) {
logLikelihood += n_i[i] * FastMath.log(n_i[i] / (double) n)
- n_i[i] * dim * .5 * MathUtil.LOGTWOPI
- n_i[i] * .5 * FastMath.log(d_i[i])
- (n_i[i] - m) * .5;
}
return logLikelihood;

@Reference(authors = "D. Pelleg, A. Moore", title = "X-means: Extending K-means with Efficient Estimation on the Number of Clusters", booktitle = "Proc. 17th Int. Conf. on Machine Learning (ICML 2000)", url = "http: bibkey = "DBLP:conf/icml/PellegM00") public static <V extends NumberVector> double logLikelihood(Relation<V> relation, Clustering<? extends MeanModel> clustering, NumberVectorDistanceFunction<? super V> distanceFunction) List<? extends Cluster<? extends MeanModel>> clusters = clustering.getAllClusters();
final int m = clusters.size();
int n = 0;
int[] n_i = new int[m];
double d = 0.;
double[] d_i = new double[m];
Iterator<? extends Cluster<? extends MeanModel>> it = clusters.iterator();
for(int i = 0; it.hasNext(); ++i) {
Cluster<? extends MeanModel> cluster = it.next();
n += n_i[i] = cluster.size();
d += d_i[i] = varianceOfCluster(cluster, distanceFunction, relation);
}
if(n <= m) {
return Double.NEGATIVE_INFINITY;
}
final double logv = FastMath.log(d / (n - m));
final int dim = RelationUtil.dimensionality(relation);
double logLikelihood = 0.;
for(int i = 0; i < m; i++) {
logLikelihood += n_i[i] * FastMath.log(n_i[i])
- n_i[i] * .5 * MathUtil.LOGTWOPI
- n_i[i] * dim * .5 * logv
- (d_i[i] - m) * .5;
}
logLikelihood -= n * FastMath.log(n);
return logLikelihood;

protected Cluster<SubspaceModel> runDOC(Database database, Relation<V> relation, ArrayModifiableDBIDs S, final int d, int n, int m, int r, int minClusterSize) DBIDs C = null;
long[] D = null;
double quality = Double.NEGATIVE_INFINITY;
FiniteProgress iprogress = LOG.isVerbose() ? new FiniteProgress("Iteration progress for current cluster", m * n, LOG) : null;
Random random = rnd.getSingleThreadedRandom();
DBIDArrayIter iter = S.iter();
for(int i = 0; i < n; ++i) {
iter.seek(random.nextInt(S.size()));
for(int j = 0; j < m; ++j) {
DBIDs randomSet = DBIDUtil.randomSample(S, r, random);
long[] nD = BitsUtil.zero(d);
for(int k = 0; k < d; ++k) {
if(dimensionIsRelevant(k, relation, randomSet)) {
BitsUtil.setI(nD, k);
}
}
if(BitsUtil.cardinality(nD) > 0) {
DBIDs nC = findNeighbors(iter, nD, S, relation);
if(LOG.isDebuggingFiner()) {
LOG.finer("Testing a cluster candidate, |C| = " + nC.size() + ", |D| = " + BitsUtil.cardinality(nD));
}
if(nC.size() < minClusterSize) {
if(LOG.isDebuggingFiner()) {
LOG.finer("... but it's too small.");
}
continue;
}
double nQuality = computeClusterQuality(nC.size(), BitsUtil.cardinality(nD));
if(nQuality > quality) {
if(LOG.isDebuggingFiner()) {
LOG.finer("... and it's the best so far: " + nQuality + " vs. " + quality);
}
C = nC;
D = nD;
quality = nQuality;
}
else {
if(LOG.isDebuggingFiner()) {
LOG.finer("... but we already have a better one.");
}
}
}
LOG.incrementProcessed(iprogress);
}
}
LOG.ensureCompleted(iprogress);
return (C != null) ? makeCluster(relation, C, D) : null;

