protected void inferClosureParameterTypes(final ClassNode receiver, final Expression arguments, final ClosureExpression expression, final Parameter param, final MethodNode selectedMethod) List<AnnotationNode> annotations = param.getAnnotations(CLOSUREPARAMS_CLASSNODE);
if (annotations != null && !annotations.isEmpty()) {
for (AnnotationNode annotation : annotations) {
Expression hintClass = annotation.getMember("value");
Expression options = annotation.getMember("options");
Expression resolverClass = annotation.getMember("conflictResolutionStrategy");
if (hintClass instanceof ClassExpression) {
doInferClosureParameterTypes(receiver, arguments, expression, selectedMethod, hintClass, resolverClass, options);
}
}
} else if (isSAMType(param.getOriginType())) {
inferSAMType(param, receiver, selectedMethod, InvocationWriter.makeArgumentList(arguments), expression);
}

public boolean lookupFernPN( TldRegionFernInfo info ) ImageRectangle r = info.r;
float rectWidth = r.getWidth();
float rectHeight = r.getHeight();
float c_x = r.x0+(rectWidth-1)/2.0f;
float c_y = r.y0+(rectHeight-1)/2.0f;
int sumP = 0;
int sumN = 0;
for( int i = 0; i < ferns.length; i++ ) {
TldFernDescription fern = ferns[i];
int value = computeFernValue(c_x, c_y, rectWidth, rectHeight, fern);
TldFernFeature f = managers[i].table[value];
if( f != null ) {
sumP += f.numP;
sumN += f.numN;
}
}
info.sumP = sumP;
info.sumN = sumN;
return sumN != 0 || sumP != 0;

double scoreResults() double totalScore = 0;
for (int i = 0; i < normalizedP.size; i++) {
DMatrixRMaj P = normalizedP.get(i);
MultiViewOps.intrinsicFromAbsoluteQuadratic(Q,P,intrinsic);
double score = 0;
score += w_sk*Math.abs(intrinsic.skew);
score += w_ar*(Math.max(intrinsic.fx,intrinsic.fy)/Math.min(intrinsic.fx,intrinsic.fy) - 1);
score += w_uo*(Math.abs(intrinsic.cx) + Math.abs(intrinsic.cy));
totalScore += score;
}
return totalScore;

public static RectangleLength2D_F32 boundBoxInside(int srcWidth, int srcHeight, PixelTransform<Point2D_F32> transform, Point2D_F32 work ) List<Point2D_F32> points = computeBoundingPoints(srcWidth, srcHeight, transform, work);
Point2D_F32 center = new Point2D_F32();
UtilPoint2D_F32.mean(points,center);
float x0,x1,y0,y1;
x0 = y0 = Float.MAX_VALUE;
x1 = y1 = -Float.MAX_VALUE;
for (int i = 0; i < points.size(); i++) {
Point2D_F32 p = points.get(i);
if( p.x < x0 )
x0 = p.x;
if( p.x > x1 )
x1 = p.x;
if( p.y < y0 )
y0 = p.y;
if( p.y > y1 )
y1 = p.y;
}
x0 -= center.x;
x1 -= center.x;
y0 -= center.y;
y1 -= center.y;
float ox0 = x0;
float oy0 = y0;
float ox1 = x1;
float oy1 = y1;
for (int i = 0; i < points.size(); i++) {
Point2D_F32 p = points.get(i);
float dx = p.x-center.x;
float dy = p.y-center.y;
if( dx > x0 && dy > y0 && dx < x1 && dy < y1 ) {
float d0 = (float) (float)Math.abs(dx - x0) + x0 - ox0;
float d1 = (float) (float)Math.abs(dx - x1) + ox1 - x1;
float d2 = (float) (float)Math.abs(dy - y0) + y0 - oy0;
float d3 = (float) (float)Math.abs(dy - y1) + oy1 - y1;
if ( d0 <= d1 && d0 <= d2 && d0 <= d3) {
x0 = dx;
} else if (d1 <= d2 && d1 <= d3) {
x1 = dx;
} else if (d2 <= d3) {
y0 = dy;
} else {
y1 = dy;
}
}
}
return new RectangleLength2D_F32(x0+center.x,y0+center.y,x1-x0,y1-y0);

private void detectCandidateFeatures(T image, double sigma ) float scaleThreshold = (float) (baseThreshold / Math.pow(sigma, scalePower));
detector.setThreshold(scaleThreshold);
computeDerivative.setInput(image);
D derivX = null, derivY = null;
D derivXX = null, derivYY = null, derivXY = null;
if (detector.getRequiresGradient()) {
derivX = computeDerivative.getDerivative(true);
derivY = computeDerivative.getDerivative(false);
}
if (detector.getRequiresHessian()) {
derivXX = computeDerivative.getDerivative(true, true);
derivYY = computeDerivative.getDerivative(false, false);
derivXY = computeDerivative.getDerivative(true, false);
}
detector.process(image, derivX, derivY, derivXX, derivYY, derivXY);
List<Point2D_I16> m = maximums;
m.clear();
if( detector.isDetectMaximums() ) {
QueueCorner q = detector.getMaximums();
for (int i = 0; i < q.size; i++) {
m.add(q.get(i).copy());
}
}
if( detector.isDetectMinimums() ) {
QueueCorner q = detector.getMinimums();
for (int i = 0; i < q.size; i++) {
m.add(q.get(i).copy());
}
}

protected void updateLocation( T image , RectangleRotate_F32 region ) double bestHistScore = Double.MAX_VALUE;
float bestX = -1, bestY = -1;
for( int i = 0; i < maxIterations; i++ ) {
calcHistogram.computeHistogram(image,region);
float histogram[] = calcHistogram.getHistogram();
updateWeights(histogram);
double histScore = distanceHistogram(keyHistogram, histogram);
if( histScore < bestHistScore ) {
bestHistScore = histScore;
bestX = region.cx;
bestY = region.cy;
}
List<Point2D_F32> samples = calcHistogram.getSamplePts();
int sampleHistIndex[] = calcHistogram.getSampleHistIndex();
float meanX = 0;
float meanY = 0;
float totalWeight = 0;
for( int j = 0; j < samples.size(); j++ ) {
Point2D_F32 samplePt = samples.get(j);
int histIndex = sampleHistIndex[j];
if( histIndex < 0 )
continue;
float w = weightHistogram[histIndex];
meanX += w*samplePt.x;
meanY += w*samplePt.y;
totalWeight += w;
}
meanX /= totalWeight;
meanY /= totalWeight;
calcHistogram.squareToImageSample(meanX, meanY, region);
meanX = calcHistogram.imageX;
meanY = calcHistogram.imageY;
boolean done = Math.abs(meanX-region.cx ) <= minimumChange && Math.abs(meanY-region.cy ) <= minimumChange;
region.cx = meanX;
region.cy = meanY;
if( done ) {
break;
}
}
region.cx = bestX;
region.cy = bestY;

protected void trilinearInterpolation( float weight , float sampleX , float sampleY , double angle , TupleDesc_F64 descriptor ) for (int i = 0; i < widthGrid; i++) {
double weightGridY = 1.0 - Math.abs(sampleY-i);
if( weightGridY <= 0) continue;
for (int j = 0; j < widthGrid; j++) {
double weightGridX = 1.0 - Math.abs(sampleX-j);
if( weightGridX <= 0 ) continue;
for (int k = 0; k < numHistogramBins; k++) {
double angleBin = k*histogramBinWidth;
double weightHistogram = 1.0 - UtilAngle.dist(angle,angleBin)/histogramBinWidth;
if( weightHistogram <= 0 ) continue;
int descriptorIndex = (i*widthGrid + j)*numHistogramBins + k;
descriptor.value[descriptorIndex] += weight*weightGridX*weightGridY*weightHistogram;
}
}
}

protected int computeFernValue(float c_x, float c_y, float rectWidth , float rectHeight , TldFernDescription fern ) rectWidth -= 1;
rectHeight -= 1;
int desc = 0;
for( int i = 0; i < fern.pairs.length; i++ ) {
Point2D_F32 p_a = fern.pairs[i].a;
Point2D_F32 p_b = fern.pairs[i].b;
float valA = interpolate.get_fast(c_x + p_a.x * rectWidth, c_y + p_a.y * rectHeight);
float valB = interpolate.get_fast(c_x + p_b.x * rectWidth, c_y + p_b.y * rectHeight);
desc *= 2;
if( valA < valB ) {
desc += 1;
}
}
return desc;

void computeAverageQ(Cache cache) float[] weights = cache.weights.data;
cache.aveQ.set(0,0);
for (int i = 0; i < controls.size(); i++) {
Control c = controls.get(i);
float w = weights[i];
cache.aveQ.x += c.q.x * w;
cache.aveQ.y += c.q.y * w;
}
cache.aveQ.x /= cache.totalWeight;
cache.aveQ.y /= cache.totalWeight;

protected void selectBestRegionsFern(double totalP, double totalN) for( int i = 0; i < fernInfo.size; i++ ) {
TldRegionFernInfo info = fernInfo.get(i);
double probP = info.sumP/totalP;
double probN = info.sumN/totalN;
if( probP > probN ) {
storageMetric.add(-(probP-probN));
storageRect.add( info.r );
}
}
if( config.maximumCascadeConsider < storageMetric.size ) {
int N = Math.min(config.maximumCascadeConsider, storageMetric.size);
storageIndexes.resize(storageMetric.size);
QuickSelect.selectIndex(storageMetric.data, N - 1, storageMetric.size, storageIndexes.data);
for( int i = 0; i < N; i++ ) {
fernRegions.add(storageRect.get(storageIndexes.get(i)));
}
} else {
fernRegions.addAll(storageRect);
}

private void computeSpan( List<AssociatedPair> points ) Q.reshape(points.size(), 9);
int index = 0;
for( int i = 0; i < points.size(); i++ ) {
AssociatedPair p = points.get(i);
Point2D_F64 a = p.p2;
Point2D_F64 b = p.p1;
Q.data[index++] =  a.x*b.x;
Q.data[index++] =  a.x*b.y;
Q.data[index++] =  a.x;
Q.data[index++] =  a.y*b.x;
Q.data[index++] =  a.y*b.y;
Q.data[index++] =  a.y;
Q.data[index++] =      b.x;
Q.data[index++] =      b.y;
Q.data[index++] =  1;
}
if( !solverNull.process(Q,4,nullspace) )
throw new RuntimeException("Nullspace solver should never fail, probably bad input");
for( int i = 0; i < 9; i++ ) {
X[i] = nullspace.unsafe_get(i,0);
Y[i] = nullspace.unsafe_get(i,1);
Z[i] = nullspace.unsafe_get(i,2);
W[i] = nullspace.unsafe_get(i,3);
}

