int horzPerRev = (int)(((256 - new Float(x).floatValue()) / 256) * 100);
int vertPerRev = (int)(((256 - new Float(y).floatValue()) / 256) * 100);
if (vertPerRev > horzPerRev) {
m_sliderbar.setLayerOpacity(horzPerRev, CmsSliderBar.COLORBAR_D);
} else {
m_sliderbar.setLayerOpacity(vertPerRev, CmsSliderBar.COLORBAR_D);
}
if (vertPerRev > horzPer) {
m_sliderbar.setLayerOpacity(horzPer, CmsSliderBar.COLORBAR_C);
} else {
m_sliderbar.setLayerOpacity(vertPerRev, CmsSliderBar.COLORBAR_C);
}
if (vertPer > horzPer) {
m_sliderbar.setLayerOpacity(horzPer, CmsSliderBar.COLORBAR_B);
} else {
m_sliderbar.setLayerOpacity(vertPer, CmsSliderBar.COLORBAR_B);
}
if (vertPer > horzPerRev) {
m_sliderbar.setLayerOpacity(horzPerRev, CmsSliderBar.COLORBAR_A);
} else {
m_sliderbar.setLayerOpacity(vertPer, CmsSliderBar.COLORBAR_A);
}
}

private static double findPrototypeSingleton(DistanceQuery<?> dq, DBIDs cx, DBIDRef cy, DBIDVar prototype) double maxDisty = 0., minMaxDist = Double.POSITIVE_INFINITY;
for(DBIDIter i = cx.iter(); i.valid(); i.advance()) {
double maxDist = dq.distance(i, cy);
maxDisty = (maxDist > maxDisty) ? maxDist : maxDisty;
if(maxDist >= minMaxDist) {
continue;
}
maxDist = findMax(dq, i, cx, maxDist, minMaxDist);
if(maxDist < minMaxDist) {
minMaxDist = maxDist;
prototype.set(i);
}
}
if(maxDisty < minMaxDist) {
minMaxDist = maxDisty;
prototype.set(cy);
}
return minMaxDist;

private static double findMax(DistanceQuery<?> dq, DBIDIter i, DBIDs cy, double maxDist, double minMaxDist) for(DBIDIter j = cy.iter(); j.valid(); j.advance()) {
double dist = dq.distance(i, j);
if(dist > maxDist) {
if(dist >= minMaxDist) {
return dist;
}
maxDist = dist;
}
}
return maxDist;

protected static void updateEntry(MatrixParadigm mat, DBIDArrayMIter prots, Int2ObjectOpenHashMap<ModifiableDBIDs> clusters, DistanceQuery<?> dq, int x, int y) assert (y < x);
final DBIDArrayIter ix = mat.ix, iy = mat.iy;
final double[] distances = mat.matrix;
ModifiableDBIDs cx = clusters.get(x), cy = clusters.get(y);
DBIDVar prototype = DBIDUtil.newVar(ix.seek(x));
double minMaxDist;
if(cx != null && cy != null) {
minMaxDist = findPrototype(dq, cx, cy, prototype, Double.POSITIVE_INFINITY);
minMaxDist = findPrototype(dq, cy, cx, prototype, minMaxDist);
}
else if(cx != null) {
minMaxDist = findPrototypeSingleton(dq, cx, iy.seek(y), prototype);
}
else if(cy != null) {
minMaxDist = findPrototypeSingleton(dq, cy, ix.seek(x), prototype);
}
else {
minMaxDist = dq.distance(ix.seek(x), iy.seek(y));
prototype.set(ix);
}
final int offset = MatrixParadigm.triangleSize(x) + y;
distances[offset] = minMaxDist;
prots.seek(offset).setDBID(prototype);

@Override public double[][] processIds(DBIDs ids, Relation<? extends NumberVector> relation) final int dim = RelationUtil.dimensionality(relation);
final CovarianceMatrix cmat = new CovarianceMatrix(dim);
final Centroid centroid = Centroid.make(relation, ids);
double maxdist = 0.0, stddev = 0.0;
{
for(DBIDIter iter = ids.iter(); iter.valid(); iter.advance()) {
double distance = weightDistance.distance(centroid, relation.get(iter));
stddev += distance * distance;
if(distance > maxdist) {
maxdist = distance;
}
}
if(maxdist == 0.0) {
maxdist = 1.0;
}
stddev = FastMath.sqrt(stddev / ids.size());
}
for(DBIDIter iter = ids.iter(); iter.valid(); iter.advance()) {
NumberVector obj = relation.get(iter);
double distance = weightDistance.distance(centroid, obj);
double weight = weightfunction.getWeight(distance, maxdist, stddev);
cmat.put(obj, weight);
}
return cmat.destroyToPopulationMatrix();

@Override public double[][] processQueryResults(DoubleDBIDList results, Relation<? extends NumberVector> database, int k) final int dim = RelationUtil.dimensionality(database);
final CovarianceMatrix cmat = new CovarianceMatrix(dim);
k = k <= results.size() ? k : results.size();
double maxdist = 0.0, stddev = 0.0;
{
int i = 0;
for(DoubleDBIDListIter it = results.iter(); it.valid() && i < k; it.advance(), k++) {
final double dist = it.doubleValue();
stddev += dist * dist;
if(dist > maxdist) {
maxdist = dist;
}
}
if(maxdist == 0.0) {
maxdist = 1.0;
}
stddev = FastMath.sqrt(stddev / k);
}
int i = 0;
for(DoubleDBIDListIter it = results.iter(); it.valid() && i < k; it.advance(), k++) {
final double dist = it.doubleValue();
NumberVector obj = database.get(it);
double weight = weightfunction.getWeight(dist, maxdist, stddev);
cmat.put(obj, weight);
}
return cmat.destroyToPopulationMatrix();

public double getMaxDist(VectorApproximation vec) final int dim = lookup.length;
double maxDist = 0;
for(int d = 0; d < dim; d++) {
final int vp = vec.getApproximation(d);
maxDist += getPartialMaxDist(d, vp);
}
return FastMath.pow(maxDist, onebyp);

protected int findMerge(int size, MatrixParadigm mat, double[] bestd, int[] besti, PointerHierarchyRepresentationBuilder builder) double mindist = Double.POSITIVE_INFINITY;
int x = -1, y = -1;
for(int cx = 0; cx < size; cx++) {
final int cy = besti[cx];
if(cy < 0) {
continue;
}
final double dist = bestd[cx];
if(dist <= mindist) {
mindist = dist;
x = cx;
y = cy;
}
}
assert (x >= 0 && y >= 0);
assert (y < x);
merge(size, mat, bestd, besti, builder, mindist, x, y);
return x;

protected static void merge(int size, MatrixParadigm mat, DBIDArrayMIter prots, PointerHierarchyRepresentationBuilder builder, Int2ObjectOpenHashMap<ModifiableDBIDs> clusters, DistanceQuery<?> dq, int x, int y) assert (y < x);
final DBIDArrayIter ix = mat.ix.seek(x), iy = mat.iy.seek(y);
final double[] distances = mat.matrix;
int offset = MatrixParadigm.triangleSize(x) + y;
if(LOG.isDebuggingFine()) {
LOG.debugFine("Merging: " + DBIDUtil.toString(ix) + " -> " + DBIDUtil.toString(iy) + " " + distances[offset]);
}
ModifiableDBIDs cx = clusters.get(x), cy = clusters.get(y);
if(cy == null) {
cy = DBIDUtil.newHashSet();
cy.add(iy);
}
if(cx == null) {
cy.add(ix);
}
else {
cy.addDBIDs(cx);
clusters.remove(x);
}
clusters.put(y, cy);
builder.add(ix, distances[offset], iy, prots.seek(offset));
updateMatrices(size, mat, prots, builder, clusters, dq, y);

protected void batchNN(AbstractRStarTreeNode<?, ?> node, Map<DBID, KNNHeap> knnLists) if(node.isLeaf()) {
for(int i = 0; i < node.getNumEntries(); i++) {
SpatialEntry p = node.getEntry(i);
for(Entry<DBID, KNNHeap> ent : knnLists.entrySet()) {
final DBID q = ent.getKey();
final KNNHeap knns_q = ent.getValue();
double knn_q_maxDist = knns_q.getKNNDistance();
DBID pid = ((LeafEntry) p).getDBID();
double dist_pq = distanceFunction.distance(relation.get(pid), relation.get(q));
tree.statistics.countDistanceCalculation();
if(dist_pq <= knn_q_maxDist) {
knns_q.insert(dist_pq, pid);
}
}
}
}
else {
ModifiableDBIDs ids = DBIDUtil.newArray(knnLists.size());
for(DBID id : knnLists.keySet()) {
ids.add(id);
}
List<DoubleDistanceEntry> entries = getSortedEntries(node, ids);
for(DoubleDistanceEntry distEntry : entries) {
double minDist = distEntry.distance;
for(Entry<DBID, KNNHeap> ent : knnLists.entrySet()) {
final KNNHeap knns_q = ent.getValue();
double knn_q_maxDist = knns_q.getKNNDistance();
if(minDist <= knn_q_maxDist) {
SpatialEntry entry = distEntry.entry;
AbstractRStarTreeNode<?, ?> child = tree.getNode(((DirectoryEntry) entry).getPageID());
batchNN(child, knnLists);
break;
}
}
}
}

public Result run(Database db, Relation<O> relation) DistanceQuery<O> dq = db.getDistanceQuery(relation, getDistanceFunction());
ArrayDBIDs ids = DBIDUtil.ensureArray(relation.getDBIDs());
final int size = ids.size();
if(size > 0x10000) {
throw new AbortException("This implementation does not scale to data sets larger than " + 0x10000 + " instances (~17 GB RAM), which results in an integer overflow.");
}
if(Linkage.SINGLE.equals(linkage)) {
LOG.verbose("Notice: SLINK is a much faster algorithm for single-linkage clustering!");
}
double[] scratch = new double[triangleSize(size)];
DBIDArrayIter ix = ids.iter(), iy = ids.iter();
int pos = 0;
boolean square = Linkage.WARD.equals(linkage) && !getDistanceFunction().isSquared();
for(int x = 0; ix.valid(); x++, ix.advance()) {
iy.seek(0);
for(int y = 0; y < x; y++, iy.advance()) {
scratch[pos] = dq.distance(ix, iy);
if(square) {
scratch[pos] *= scratch[pos];
}
pos++;
}
}
double[] height = new double[size];
Arrays.fill(height, Double.POSITIVE_INFINITY);
ArrayModifiableDBIDs parent = DBIDUtil.newArray(ids);
Int2ReferenceMap<ModifiableDBIDs> clusters = new Int2ReferenceOpenHashMap<>();
final int stop = size - numclusters;
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Agglomerative clustering", stop, LOG) : null;
for(int i = 0; i < stop; i++) {
double min = Double.POSITIVE_INFINITY;
int minx = -1, miny = -1;
for(int x = 0; x < size; x++) {
if(height[x] < Double.POSITIVE_INFINITY) {
continue;
}
final int xbase = triangleSize(x);
for(int y = 0; y < x; y++) {
if(height[y] < Double.POSITIVE_INFINITY) {
continue;
}
final int idx = xbase + y;
if(scratch[idx] < min) {
min = scratch[idx];
minx = x;
miny = y;
}
}
}
assert (minx >= 0 && miny >= 0);
ix.seek(minx);
iy.seek(miny);
height[minx] = min;
parent.set(minx, iy);
ModifiableDBIDs cx = clusters.get(minx);
ModifiableDBIDs cy = clusters.get(miny);
int sizex = 1, sizey = 1;
if(cy == null) {
cy = DBIDUtil.newHashSet();
cy.add(iy);
}
else {
sizey = cy.size();
}
if(cx == null) {
cy.add(ix);
}
else {
sizex = cx.size();
cy.addDBIDs(cx);
clusters.remove(minx);
}
clusters.put(miny, cy);
final int xbase = triangleSize(minx), ybase = triangleSize(miny);
for(int j = 0; j < miny; j++) {
if(height[j] < Double.POSITIVE_INFINITY) {
continue;
}
final DBIDs idsj = clusters.get(j);
final int sizej = (idsj == null) ? 1 : idsj.size();
scratch[ybase + j] = linkage.combine(sizex, scratch[xbase + j], sizey, scratch[ybase + j], sizej, min);
}
for(int j = miny + 1; j < minx; j++) {
if(height[j] < Double.POSITIVE_INFINITY) {
continue;
}
final int jbase = triangleSize(j);
final DBIDs idsj = clusters.get(j);
final int sizej = (idsj == null) ? 1 : idsj.size();
scratch[jbase + miny] = linkage.combine(sizex, scratch[xbase + j], sizey, scratch[jbase + miny], sizej, min);
}
for(int j = minx + 1; j < size; j++) {
if(height[j] < Double.POSITIVE_INFINITY) {
continue;
}
final DBIDs idsj = clusters.get(j);
final int sizej = (idsj == null) ? 1 : idsj.size();
final int jbase = triangleSize(j);
scratch[jbase + miny] = linkage.combine(sizex, scratch[jbase + minx], sizey, scratch[jbase + miny], sizej, min);
}
LOG.incrementProcessed(prog);
}
LOG.ensureCompleted(prog);
final Clustering<Model> dendrogram = new Clustering<>("Hierarchical-Clustering", "hierarchical-clustering");
for(int x = 0; x < size; x++) {
if(height[x] < Double.POSITIVE_INFINITY) {
DBIDs cids = clusters.get(x);
if(cids == null) {
ix.seek(x);
cids = DBIDUtil.deref(ix);
}
Cluster<Model> cluster = new Cluster<>("Cluster", cids);
dendrogram.addToplevelCluster(cluster);
}
}
return dendrogram;

public boolean shouldShowType(String contextKey, String typeName) Map<String, CmsDefaultSet<String>> allowedContextMap = safeGetAllowedContextMap();
CmsDefaultSet<String> allowedContexts = allowedContextMap.get(typeName);
if (allowedContexts == null) {
