}
return allowedContexts.contains(contextKey);

public boolean isShowInContext(String currentContext) if ((m_settings == null)
|| !m_settings.containsKey(CmsTemplateContextInfo.SETTING)
|| CmsStringUtil.isEmptyOrWhitespaceOnly(m_settings.get(CmsTemplateContextInfo.SETTING))) {
return true;
}
return CmsStringUtil.splitAsList(m_settings.get(CmsTemplateContextInfo.SETTING), "|").contains(currentContext);

protected CmsContainerElementBean transformContainerElement( CmsObject cms, CmsTemplateMapperConfiguration config, CmsContainerElementBean element) if (m_forSave) {
try {
element.initResource(cms);
} catch (Exception e) {
LOG.error(e.getLocalizedMessage(), e);
return null;
}
}
Map<String, String> settings = element.getIndividualSettings();
if (settings == null) {
settings = new HashMap<>();
}
Map<String, String> newSettings = new HashMap<>();
for (Map.Entry<String, String> entry : settings.entrySet()) {
String key = entry.getKey();
if (CmsTemplateContextInfo.SETTING.equals(key)) {
continue;
}
String value = entry.getValue();
if (value == null) {
continue;
}
String newValue = value;
if (key.startsWith(CmsFormatterConfig.FORMATTER_SETTINGS_KEY)) {
if (CmsUUID.isValidUUID(value)) {
String newId = config.getMappedFormatterConfiguration(value);
if (newId != null) {
newValue = newId;
}
} else if (value.startsWith(CmsFormatterConfig.SCHEMA_FORMATTER_ID)) {
String schemaFormatterIdStr = value.substring(CmsFormatterConfig.SCHEMA_FORMATTER_ID.length());
if (CmsUUID.isValidUUID(schemaFormatterIdStr)) {
CmsUUID schemaFormatterId = new CmsUUID(schemaFormatterIdStr);
CmsUUID mappedFormatterId = config.getMappedFormatterJspId(schemaFormatterId);
if (mappedFormatterId != null) {
newValue = CmsFormatterConfig.SCHEMA_FORMATTER_ID + mappedFormatterId;
}
}
}
}
newSettings.put(key, newValue);
}
CmsContainerElementBean newElement = element.clone();
newElement.updateIndividualSettings(newSettings);
CmsUUID formatterId = element.getFormatterId();
if ((formatterId == null) && m_forSave) {
try {
if (element.isGroupContainer(cms)) {
formatterId = new CmsUUID("e7029fa2-761e-11e0-bd7f-9ffeadaf4d46");
newElement.setFormatterId(formatterId);
} else if (OpenCms.getResourceManager().matchResourceType(
"function",
element.getResource().getTypeId())) {
formatterId = new CmsUUID("087ba7c9-e7fc-4336-acb8-d3416a4eb1fd");
newElement.setFormatterId(formatterId);
}
} catch (CmsException e) {
LOG.warn(e.getLocalizedMessage(), e);
}
}
CmsUUID mappedFormatterJspId = config.getMappedFormatterJspId(formatterId);
if (mappedFormatterJspId != null) {
newElement.setFormatterId(mappedFormatterJspId);
}
return newElement;

private CmsContainerElementBean getModelReplacementElement( CmsContainerElementBean element, CmsContainerElementBean baseElement, boolean allowCopyModel) boolean resetSettings = false;
if (!baseElement.isCopyModel() && !baseElement.getFormatterId().equals(element.getFormatterId())) {
I_CmsFormatterBean formatter = m_configData.getCachedFormatters().getFormatters().get(
element.getFormatterId());
resetSettings = (formatter == null)
|| !formatter.getResourceTypeNames().contains(
OpenCms.getResourceManager().getResourceType(baseElement.getResource()).getTypeName());
}
Map<String, String> settings;
if (resetSettings) {
settings = new HashMap<String, String>();
for (String id : KEEP_SETTING_IDS) {
if (element.getIndividualSettings().containsKey(id)) {
settings.put(id, element.getIndividualSettings().get(id));
}
}
settings.put(CmsContainerElement.MODEL_GROUP_ID, element.getId().toString());
for (Entry<String, String> settingEntry : baseElement.getIndividualSettings().entrySet()) {
if (!settings.containsKey(settingEntry.getKey())) {
settings.put(settingEntry.getKey(), settingEntry.getValue());
}
}
} else {
settings = new HashMap<String, String>(element.getIndividualSettings());
if (!(baseElement.isCopyModel() && allowCopyModel)) {
settings.put(CmsContainerElement.MODEL_GROUP_ID, element.getId().toString());
if (allowCopyModel) {
for (Entry<String, String> settingEntry : baseElement.getIndividualSettings().entrySet()) {
if (!settings.containsKey(settingEntry.getKey())) {
settings.put(settingEntry.getKey(), settingEntry.getValue());
}
}
}
} else if (baseElement.isCopyModel()) {
settings.put(CmsContainerElement.MODEL_GROUP_STATE, ModelGroupState.wasModelGroup.name());
}
}
return CmsContainerElementBean.cloneWithSettings(baseElement, settings);

private boolean renderContainerElement( HttpServletRequest request, CmsObject cms, CmsJspStandardContextBean standardContext, CmsContainerElementBean element, Locale locale, boolean alreadyFull) throws Exception CmsTemplateContext context = (CmsTemplateContext)(request.getAttribute(
CmsTemplateContextManager.ATTR_TEMPLATE_CONTEXT));
if ((context == null) && alreadyFull) {
return false;
}
String contextKey = null;
if (context != null) {
contextKey = context.getKey();
} else {
String rpcContextOverride = (String)request.getAttribute(
CmsTemplateContextManager.ATTR_RPC_CONTEXT_OVERRIDE);
contextKey = rpcContextOverride;
}
boolean showInContext = shouldShowInContext(element, context != null ? context.getKey() : null);
boolean isOnline = cms.getRequestContext().getCurrentProject().isOnlineProject();
if (!m_editableRequest && !showInContext) {
return false;
}
element.initResource(cms);
if (!m_editableRequest && !element.isReleasedAndNotExpired()) {
return false;
}
ServletRequest req = pageContext.getRequest();
ServletResponse res = pageContext.getResponse();
String containerType = getType();
int containerWidth = getContainerWidth();
CmsADEConfigData adeConfig = OpenCms.getADEManager().lookupConfiguration(
cms,
cms.getRequestContext().getRootUri());
boolean isGroupContainer = element.isGroupContainer(cms);
boolean isInheritedContainer = element.isInheritedContainer(cms);
I_CmsFormatterBean formatterConfig = null;
if (!isGroupContainer && !isInheritedContainer) {
formatterConfig = ensureValidFormatterSettings(
cms,
element,
adeConfig,
getName(),
containerType,
containerWidth);
element.initSettings(cms, formatterConfig, locale, request, m_settingPresets);
}
if (m_editableRequest) {
getSessionCache(cms).setCacheContainerElement(element.editorHash(), element);
}
if (isGroupContainer || isInheritedContainer) {
if (alreadyFull) {
return false;
}
List<CmsContainerElementBean> subElements;
if (isGroupContainer) {
subElements = getGroupContainerElements(cms, element, req, containerType);
} else {
subElements = getInheritedContainerElements(cms, element);
}
printElementWrapperTagStart(cms, element, standardContext.getPage(), true);
for (CmsContainerElementBean subelement : subElements) {
try {
subelement.initResource(cms);
boolean shouldShowSubElementInContext = shouldShowInContext(subelement, contextKey);
if (!m_editableRequest
&& (!shouldShowSubElementInContext || !subelement.isReleasedAndNotExpired())) {
continue;
}
I_CmsFormatterBean subElementFormatterConfig = ensureValidFormatterSettings(
cms,
subelement,
adeConfig,
getName(),
containerType,
containerWidth);
subelement.initSettings(cms, subElementFormatterConfig, locale, request, m_settingPresets);
if (m_editableRequest) {
getSessionCache(cms).setCacheContainerElement(subelement.editorHash(), subelement);
}
if (subElementFormatterConfig == null) {
if (LOG.isErrorEnabled()) {
LOG.error(
new CmsIllegalStateException(
Messages.get().container(
Messages.ERR_XSD_NO_TEMPLATE_FORMATTER_3,
subelement.getSitePath(),
OpenCms.getResourceManager().getResourceType(
subelement.getResource()).getTypeName(),
containerType)));
}
continue;
}
printElementWrapperTagStart(cms, subelement, standardContext.getPage(), false);
standardContext.setElement(subelement);
try {
String formatterSitePath;
try {
CmsResource formatterResource = cms.readResource(
subElementFormatterConfig.getJspStructureId());
formatterSitePath = cms.getSitePath(formatterResource);
} catch (CmsVfsResourceNotFoundException ex) {
LOG.debug("Formatter JSP not found by id, try using path.", ex);
formatterSitePath = cms.getRequestContext().removeSiteRoot(
subElementFormatterConfig.getJspRootPath());
}
if (shouldShowSubElementInContext) {
CmsJspTagInclude.includeTagAction(
pageContext,
formatterSitePath,
null,
locale,
false,
isOnline,
null,
CmsRequestUtil.getAttributeMap(req),
req,
res);
} else {
pageContext.getOut().print(DUMMY_ELEMENT);
}
} catch (Exception e) {
if (LOG.isErrorEnabled()) {
LOG.error(
Messages.get().getBundle().key(
Messages.ERR_CONTAINER_PAGE_ELEMENT_RENDER_ERROR_2,
subelement.getSitePath(),
subElementFormatterConfig),
e);
}
printElementErrorTag(subelement.getSitePath(), subElementFormatterConfig.getJspRootPath(), e);
}
printElementWrapperTagEnd(false);
} catch (Exception e) {
if (LOG.isErrorEnabled()) {
LOG.error(e);
}
}
}
printElementWrapperTagEnd(true);
return true;
} else {
boolean result = true;
if (alreadyFull) {
result = false;
if (!showInContext) {
printElementWrapperTagStart(cms, element, standardContext.getPage(), false);
pageContext.getOut().print(DUMMY_ELEMENT);
printElementWrapperTagEnd(false);
}
} else {
String formatter = null;
try {
if (formatterConfig != null) {
try {
CmsResource formatterResource = cms.readResource(formatterConfig.getJspStructureId());
formatter = cms.getSitePath(formatterResource);
} catch (CmsVfsResourceNotFoundException ex) {
LOG.debug("Formatter JSP not found by id, try using path.", ex);
if (cms.existsResource(
cms.getRequestContext().removeSiteRoot(formatterConfig.getJspRootPath()))) {
formatter = cms.getRequestContext().removeSiteRoot(formatterConfig.getJspRootPath());
}
}
} else {
formatter = cms.getSitePath(cms.readResource(element.getFormatterId()));
}
} catch (CmsException e) {
LOG.debug("Formatter resource can not be found, try reading it from the configuration.", e);
CmsFormatterConfiguration elementFormatters = adeConfig.getFormatters(cms, element.getResource());
I_CmsFormatterBean elementFormatterBean = elementFormatters.getDefaultFormatter(
containerType,
containerWidth);
if (elementFormatterBean == null) {
if (LOG.isErrorEnabled()) {
LOG.error(
new CmsIllegalStateException(
Messages.get().container(
Messages.ERR_XSD_NO_TEMPLATE_FORMATTER_3,
element.getSitePath(),
OpenCms.getResourceManager().getResourceType(
element.getResource()).getTypeName(),
containerType)));
}
return false;
}
try {
CmsResource formatterResource = cms.readResource(elementFormatterBean.getJspStructureId());
formatter = cms.getSitePath(formatterResource);
} catch (CmsVfsResourceNotFoundException ex) {
LOG.debug("Formatter JSP not found by id, try using path.", ex);
formatter = cms.getRequestContext().removeSiteRoot(elementFormatterBean.getJspRootPath());
}
}
printElementWrapperTagStart(cms, element, standardContext.getPage(), false);
standardContext.setElement(element);
try {
if (!showInContext) {
pageContext.getOut().print(DUMMY_ELEMENT);
result = false;
} else {
CmsJspTagInclude.includeTagAction(
pageContext,
formatter,
null,
locale,
false,
isOnline,
null,
CmsRequestUtil.getAtrributeMap(req),
req,
res);
}
} catch (Exception e) {
if (LOG.isErrorEnabled()) {
LOG.error(
Messages.get().getBundle().key(
Messages.ERR_CONTAINER_PAGE_ELEMENT_RENDER_ERROR_2,
element.getSitePath(),
formatter),
e);
}
printElementErrorTag(element.getSitePath(), formatter, e);
}
printElementWrapperTagEnd(false);
}
return result;
}

public CmsContainerPageBean prepareforModelGroupContent( Map<String, CmsContainerElementBean> elements, List<String> foundGroups, CmsContainerPageBean page, boolean alwaysCopy, Locale locale) throws CmsException for (Entry<String, CmsContainerElementBean> entry : elements.entrySet()) {
CmsContainerElementBean element = entry.getValue();
CmsContainerPageBean modelPage = null;
String modelInstanceId = null;
boolean foundInstance = false;
if (CmsModelGroupHelper.isModelGroupResource(element.getResource())) {
modelPage = getContainerPageBean(element.getResource());
CmsContainerElementBean baseElement = getModelBaseElement(modelPage, element.getResource());
if (baseElement == null) {
break;
}
String baseInstanceId = baseElement.getInstanceId();
String originalInstanceId = element.getInstanceId();
element = getModelReplacementElement(element, baseElement, true);
List<CmsContainerBean> modelContainers = readModelContainers(
baseInstanceId,
originalInstanceId,
modelPage,
baseElement.isCopyModel());
if (!m_isEditingModelGroups && baseElement.isCopyModel()) {
modelContainers = createNewElementsForModelGroup(m_cms, modelContainers, locale);
}
modelContainers.addAll(page.getContainers().values());
page = new CmsContainerPageBean(modelContainers);
entry.setValue(element);
if (m_sessionCache != null) {
m_sessionCache.setCacheContainerElement(element.editorHash(), element);
}
} else {
Map<String, String> settings = new HashMap<String, String>(element.getIndividualSettings());
String source = settings.get(CmsContainerpageService.SOURCE_CONTAINERPAGE_ID_SETTING);
settings.remove(CmsContainerpageService.SOURCE_CONTAINERPAGE_ID_SETTING);
if (CmsStringUtil.isNotEmptyOrWhitespaceOnly(source)) {
try {
CmsUUID sourceId = new CmsUUID(source);
CmsResource sourcePage = m_cms.readResource(sourceId);
if (CmsResourceTypeXmlContainerPage.isContainerPage(sourcePage)) {
CmsXmlContainerPage xmlCnt = CmsXmlContainerPageFactory.unmarshal(
m_cms,
m_cms.readFile(sourcePage));
modelPage = xmlCnt.getContainerPage(m_cms);
modelInstanceId = element.getInstanceId();
}
settings.remove(CmsContainerElement.ELEMENT_INSTANCE_ID);
boolean copyRoot = false;
if (alwaysCopy && (modelInstanceId != null) && (modelPage != null)) {
for (CmsContainerElementBean el : modelPage.getElements()) {
if (modelInstanceId.equals(el.getInstanceId())) {
copyRoot = el.isCreateNew();
break;
}
}
}
if (copyRoot) {
CmsObject cloneCms = OpenCms.initCmsObject(m_cms);
cloneCms.getRequestContext().setLocale(locale);
String typeName = OpenCms.getResourceManager().getResourceType(
element.getResource()).getTypeName();
CmsResourceTypeConfig typeConfig = m_configData.getResourceType(typeName);
if (typeConfig == null) {
throw new IllegalArgumentException(
"Can not copy template model element '"
+ element.getResource().getRootPath()
+ "' because the resource type '"
+ typeName
+ "' is not available in this sitemap.");
}
CmsResource newResource = typeConfig.createNewElement(
cloneCms,
element.getResource(),
m_configData.getBasePath());
element = new CmsContainerElementBean(
newResource.getStructureId(),
element.getFormatterId(),
settings,
false);
} else {
element = CmsContainerElementBean.cloneWithSettings(element, settings);
}
if (modelPage != null) {
Map<String, List<CmsContainerBean>> containerByParent = new HashMap<String, List<CmsContainerBean>>();
for (CmsContainerBean container : modelPage.getContainers().values()) {
if (container.getParentInstanceId() != null) {
if (!containerByParent.containsKey(container.getParentInstanceId())) {
containerByParent.put(
container.getParentInstanceId(),
new ArrayList<CmsContainerBean>());
}
containerByParent.get(container.getParentInstanceId()).add(container);
}
if (!foundInstance) {
for (CmsContainerElementBean child : container.getElements()) {
if (modelInstanceId == null) {
if (child.getId().equals(element.getId())) {
modelInstanceId = child.getInstanceId();
foundInstance = true;
Map<String, String> setting = new HashMap<String, String>(
child.getIndividualSettings());
setting.remove(CmsContainerElement.ELEMENT_INSTANCE_ID);
element = CmsContainerElementBean.cloneWithSettings(element, setting);
break;
}
} else {
if (modelInstanceId.equals(child.getInstanceId())) {
foundInstance = true;
break;
}
}
}
}
}
if (foundInstance && containerByParent.containsKey(modelInstanceId)) {
List<CmsContainerBean> modelContainers = collectModelStructure(
modelInstanceId,
element.getInstanceId(),
containerByParent,
true);
if (alwaysCopy) {
modelContainers = createNewElementsForModelGroup(m_cms, modelContainers, locale);
}
foundGroups.add(element.editorHash());
modelContainers.addAll(page.getContainers().values());
page = new CmsContainerPageBean(modelContainers);
}
}
entry.setValue(element);
if (m_sessionCache != null) {
m_sessionCache.setCacheContainerElement(element.editorHash(), element);
}
} catch (Exception e) {
LOG.info(e.getLocalizedMessage(), e);
}
}
}
}
return page;

