private void triggerMasterToAssignPartitions() if (!shouldTriggerMasterToAssignPartitions()) {
return;
}
ClusterServiceImpl clusterService = node.getClusterService();
ClusterState clusterState = clusterService.getClusterState();
if (!clusterState.isMigrationAllowed()) {
logger.warning("Partitions can't be assigned since cluster-state=" + clusterState);
return;
}
final Address masterAddress = clusterService.getMasterAddress();
if (masterAddress == null || masterAddress.equals(node.getThisAddress())) {
return;
}
if (masterTriggered.compareAndSet(false, true)) {
InternalOperationService operationService = nodeEngine.getOperationService();
ICompletableFuture<PartitionRuntimeState> future =
operationService.invokeOnTarget(SERVICE_NAME, new AssignPartitions(), masterAddress);
future.andThen(new ExecutionCallback<PartitionRuntimeState>() {
@Override
public void onResponse(PartitionRuntimeState partitionState) {
resetMasterTriggeredFlag();
if (partitionState != null) {
partitionState.setMaster(masterAddress);
processPartitionRuntimeState(partitionState);
}
}
@Override
public void onFailure(Throwable t) {
resetMasterTriggeredFlag();
logger.severe(t);
}
});
masterTrigger.executeWithDelay();
}

public void handleJoinRequest(JoinRequest joinRequest, Connection connection) if (!ensureNodeIsReady()) {
return;
}
if (!ensureValidConfiguration(joinRequest)) {
return;
}
Address target = joinRequest.getAddress();
boolean isRequestFromCurrentMaster = target.equals(clusterService.getMasterAddress());
if (!clusterService.isMaster() && !isRequestFromCurrentMaster) {
sendMasterAnswer(target);
return;
}
if (joinInProgress) {
if (logger.isFineEnabled()) {
logger.fine(format("Join or membership claim is in progress, cannot handle join request from %s at the moment",
target));
}
return;
}
executeJoinRequest(joinRequest, connection);

private void sendMemberListToOthers() if (!clusterService.isMaster() || !clusterService.isJoined()
|| clusterService.getClusterJoinManager().isMastershipClaimInProgress()) {
if (logger.isFineEnabled()) {
logger.fine("Cannot publish member list to cluster. Is-master: "
+ clusterService.isMaster() + ", joined: " + clusterService.isJoined()
+ " , mastership claim in progress: " + clusterService.getClusterJoinManager()
.isMastershipClaimInProgress());
}
return;
}
MemberMap memberMap = getMemberMap();
MembersView membersView = memberMap.toMembersView();
if (logger.isFineEnabled()) {
logger.fine("Sending member list to the non-master nodes: " + memberListString());
}
for (MemberImpl member : memberMap.getMembers()) {
if (member.localMember()) {
continue;
}
MembersUpdateOp op = new MembersUpdateOp(member.getUuid(), membersView,
clusterService.getClusterTime(), null, false);
op.setCallerUuid(clusterService.getThisUuid());
nodeEngine.getOperationService().send(op, member.getAddress());
}

public void answerWhoisMasterQuestion(JoinMessage joinMessage, Connection connection) if (!ensureValidConfiguration(joinMessage)) {
return;
}
if (clusterService.isJoined()) {
if (!checkIfJoinRequestFromAnExistingMember(joinMessage, connection)) {
sendMasterAnswer(joinMessage.getAddress());
}
} else {
if (logger.isFineEnabled()) {
logger.fine(format("Received a master question from %s,"
+ " but this node is not master itself or doesn't have a master yet!", joinMessage.getAddress()));
}
}

