private void changePoseToReference() Se3_F64 keyToCurr = currToKey.invert(null);
List<PointTrack> all = trackerLeft.getAllTracks(null);
for( PointTrack t : all ) {
LeftTrackInfo p = t.getCookie();
SePointOps_F64.transform(keyToCurr, p.location.location, p.location.location);
}
concatMotion();

private void addNewTracks() tracker.spawnTracks();
List<PointTrack> spawned = tracker.getNewTracks(null);
for (PointTrack t : spawned) {
VoTrack p = t.getCookie();
if (p == null) {
t.cookie = p = new VoTrack();
}
pixelToNorm.compute(t.x, t.y, n);
if (planeProjection.normalToPlane(n.x, n.y, p.ground)) {
p.onPlane = true;
} else {
pointing.set(n.x, n.y, 1);
GeometryMath_F64.mult(cameraToPlane.getR(), pointing, pointing);
pointing.normalize();
double normXZ = Math.sqrt(pointing.x * pointing.x + pointing.z * pointing.z);
p.pointingY = pointing.y / normXZ;
p.ground.x = pointing.z;
p.ground.y = -pointing.x;
p.ground.x /= normXZ;
p.ground.y /= normXZ;
p.onPlane = false;
}
p.lastInlier = tick;
}

private boolean estimateMotion() List<PointTrack> active = tracker.getActiveTracks(null);
List<Point2D3D> obs = new ArrayList<>();
for( PointTrack t : active ) {
Point2D3D p = t.getCookie();
pixelToNorm.compute( t.x , t.y , p.observation );
obs.add( p );
}
if( !motionEstimator.process( obs ) )
return false;
if( doublePass ) {
if (!performSecondPass(active, obs))
return false;
}
tracker.finishTracking();
Se3_F64 keyToCurr;
if( refine != null ) {
keyToCurr = new Se3_F64();
refine.fitModel(motionEstimator.getMatchSet(), motionEstimator.getModelParameters(), keyToCurr);
} else {
keyToCurr = motionEstimator.getModelParameters();
}
keyToCurr.invert(currToKey);
int N = motionEstimator.getMatchSet().size();
for( int i = 0; i < N; i++ ) {
int index = motionEstimator.getInputIndex(i);
Point2D3DTrack t = active.get(index).getCookie();
t.lastInlier = tick;
inlierTracks.add( t );
}
return true;

private void computeAngleOfRotation(PointTrack t, Vector3D_F64 pointingPlane) VoTrack p = t.getCookie();
groundCurr.x = pointingPlane.z;
groundCurr.y = -pointingPlane.x;
double norm = groundCurr.norm();
groundCurr.x /= norm;
groundCurr.y /= norm;
double dot = groundCurr.x * p.ground.x + groundCurr.y * p.ground.y;
if (dot > 1.0)
dot = 1.0;
double angle = Math.acos(dot);
if (groundCurr.x * p.ground.y - groundCurr.y * p.ground.x > 0)
angle = -angle;
farAngles.add(angle);

private int dropUnusedTracks() List<PointTrack> all = tracker.getAllTracks(null);
int num = 0;
for (PointTrack t : all) {
VoTrack p = t.getCookie();
if (tick - p.lastInlier > thresholdRetire) {
tracker.dropTrack(t);
num++;
}
}
return num;

private void sortTracksForEstimation() planeSamples.reset();
farAngles.reset();
tracksOnPlane.clear();
tracksFar.clear();
List<PointTrack> active = tracker.getActiveTracks(null);
for (PointTrack t : active) {
VoTrack p = t.getCookie();
pixelToNorm.compute(t.x, t.y, n);
pointing.set(n.x, n.y, 1);
GeometryMath_F64.mult(cameraToPlane.getR(), pointing, pointing);
pointing.normalize();
if (p.onPlane) {
if (pointing.y > 0) {
PlanePtPixel ppp = planeSamples.grow();
ppp.normalizedCurr.set(n);
ppp.planeKey.set(p.ground);
tracksOnPlane.add(t);
}
} else {
boolean allGood = pointing.y < 0;
if (strictFar) {
allGood = isRotationFromAxisY(t, pointing);
}
if (allGood) {
computeAngleOfRotation(t, pointing);
tracksFar.add(t);
}
}
}

public void changeKeyFrame() List<PointTrack> inactive = tracker.getInactiveTracks(null);
for( PointTrack l : inactive ) {
tracker.dropTrack(l);
}
List<PointTrack> active = tracker.getActiveTracks(null);
for( PointTrack l : active ) {
AssociatedPairTrack p = l.getCookie();
p.p1.set(l);
p.lastUsed = totalFramesProcessed;
}
tracker.spawnTracks();
List<PointTrack> spawned = tracker.getNewTracks(null);
for( PointTrack l : spawned ) {
AssociatedPairTrack p = l.getCookie();
if( p == null ) {
l.cookie = p = new AssociatedPairTrack();
p.p2 = l;
}
p.p1.set(l);
p.lastUsed = totalFramesProcessed;
}
worldToKey.set(worldToCurr);
keyToCurr.reset();
keyFrame = true;

public boolean process( I frame ) keyFrame = false;
tracker.process(frame);
totalFramesProcessed++;
List<PointTrack> tracks = tracker.getActiveTracks(null);
if( tracks.size() == 0 )
return false;
List<AssociatedPair> pairs = new ArrayList<>();
for( PointTrack t : tracks ) {
pairs.add((AssociatedPair)t.getCookie());
}
if( !modelMatcher.process((List)pairs) ) {
return false;
}
if( modelRefiner != null ) {
if( !modelRefiner.fitModel(modelMatcher.getMatchSet(),modelMatcher.getModelParameters(),keyToCurr) )
return false;
} else {
keyToCurr.set(modelMatcher.getModelParameters());
}
for( AssociatedPair p : modelMatcher.getMatchSet() ) {
((AssociatedPairTrack)p).lastUsed = totalFramesProcessed;
}
pruneUnusedTracks();
worldToKey.concat(keyToCurr, worldToCurr);
return true;

@Override public double computeDistance(AssociatedPair obs) triangulate.triangulate(obs.p1,obs.p2,keyToCurr,p);
if( p.z < 0 )
return Double.MAX_VALUE;
double error = errorCam1.errorSq(obs.p1.x,obs.p1.y,p.x/p.z,p.y/p.z);
SePointOps_F64.transform(keyToCurr,p,p);
if( p.z < 0 )
return Double.MAX_VALUE;
error += errorCam2.errorSq(obs.p2.x,obs.p2.y, p.x/p.z , p.y/p.z);
return error;

private void refineMotionEstimate() List<Stereo2D3D> data = new ArrayList<>();
int N = matcher.getMatchSet().size();
for( int i = 0; i < N; i++ ) {
int index = matcher.getInputIndex(i);
PointTrack l = candidates.get(index);
LeftTrackInfo info = l.getCookie();
PointTrack r = info.right;
Stereo2D3D stereo = info.location;
leftImageToNorm.compute(l.x,l.y,info.location.leftObs);
rightImageToNorm.compute(r.x,r.y,info.location.rightObs);
data.add(stereo);
}
Se3_F64 keyToCurr = currToKey.invert(null);
Se3_F64 found = new Se3_F64();
if( modelRefiner.fitModel(data,keyToCurr,found) ) {
found.invert(currToKey);
}

