public static JavaRDD<List<List<Writable>>> zeroMeanUnitVarianceSequence(Schema schema, JavaRDD<List<List<Writable>>> sequence, List<String> excludeColumns) DataRowsFacade frame = DataFrames.toDataFrameSequence(schema, sequence);
