&& !validate(escapedPath, 1, -1, uric)) {
throw new URIException(URIException.ESCAPING,
"escaped opaque part not valid");
}
_opaque = escapedPath;
} else {
throw new URIException(URIException.PARSING, "incorrect path");
}
