public boolean tryProbe(BaseRow record) throws IOException if (!this.probeIterator.hasSource()) {
this.probeIterator.setInstance(record);
}
BinaryRow probeKey = probeSideProjection.apply(record);
final int hash = hash(probeKey.hashCode(), this.currentRecursionDepth);
BinaryHashPartition p = this.partitionsBeingBuilt.get(hash % partitionsBeingBuilt.size());
if (p.isInMemory()) {
this.probeKey = probeKey;
this.probeRow = record;
p.bucketArea.startLookup(hash);
return true;
} else {
if (p.testHashBloomFilter(hash)) {
BinaryRow row = originProbeSideSerializer.baseRowToBinary(record);
p.insertIntoProbeBuffer(row);
}
return false;
}

@Override public BinaryRow baseRowToBinary(BaseRow row) if (row instanceof BinaryRow) {
return (BinaryRow) row;
}
BinaryRow binaryRow = new BinaryRow(types.length);
BinaryRowWriter writer = new BinaryRowWriter(binaryRow);
writer.writeHeader(row.getHeader());
for (int i = 0; i < types.length; i++) {
if (row.isNullAt(i)) {
writer.setNullAt(i);
} else {
BinaryWriter.write(writer, i, TypeGetterSetters.get(row, i, types[i]), types[i]);
}
}
writer.complete();
return binaryRow;

public static int hash(int hashCode, int level) final int rotation = level * 11;
int code = Integer.rotateLeft(hashCode, rotation);
return code >= 0 ? code : -(code + 1);

public static Row copy(Row row) final Row newRow = new Row(row.fields.length);
System.arraycopy(row.fields, 0, newRow.fields, 0, row.fields.length);
return newRow;

@Override public Row nextRecord(Row row) throws IOException try {
if (!hasNext) {
return null;
}
for (int pos = 0; pos < row.getArity(); pos++) {
row.setField(pos, resultSet.getObject(pos + 1));
}
hasNext = resultSet.next();
return row;
} catch (SQLException se) {
throw new IOException("Couldn't read data - " + se.getMessage(), se);
} catch (NullPointerException npe) {
throw new IOException("Couldn't access resultSet", npe);
}

protected void buildInitialTable(final MutableObjectIterator<BT> input) throws IOException final int partitionFanOut = getPartitioningFanOutNoEstimates(this.availableMemory.size());
if (partitionFanOut > MAX_NUM_PARTITIONS) {
throw new RuntimeException("Hash join partitions estimate exeeds maximum number of partitions.");
}
createPartitions(partitionFanOut, 0);
final int numBuckets = getInitialTableSize(this.availableMemory.size(), this.segmentSize,
partitionFanOut, this.avgRecordLen);
initTable(numBuckets, (byte) partitionFanOut);
final TypeComparator<BT> buildTypeComparator = this.buildSideComparator;
BT record = this.buildSideSerializer.createInstance();
while (this.running && ((record = input.next(record)) != null)) {
final int hashCode = hash(buildTypeComparator.hash(record), 0);
insertIntoTable(record, hashCode);
}
if (!this.running) {
return;
}
for (int i = 0; i < this.partitionsBeingBuilt.size(); i++) {
HashPartition<BT, PT> p = this.partitionsBeingBuilt.get(i);
p.finalizeBuildPhase(this.ioManager, this.currentEnumerator, this.writeBehindBuffers);
}

