for (int i = 0; i < fields.length; i++) {
newRow.fields[i] = row.fields[fields[i]];
}
return newRow;

protected long initRankEnd(BaseRow row) throws Exception if (isConstantRankEnd) {
return rankEnd;
} else {
Long rankEndValue = rankEndState.value();
long curRankEnd = rankEndFetcher.apply(row);
if (rankEndValue == null) {
rankEnd = curRankEnd;
rankEndState.update(rankEnd);
return rankEnd;
} else {
rankEnd = rankEndValue;
if (rankEnd != curRankEnd) {
invalidCounter.inc();
}
return rankEnd;
}
}

