BaseBondRef bondRef = newBondRef(newbonds[i]);
bondRef.setIndex(i);
addToEndpoints(bondRef);
bonds[i] = bondRef;
}
if (newbonds.length < numBonds) {
Arrays.fill(this.bonds, newbonds.length, numBonds, null);
}
numBonds = newbonds.length;
