protected String matchAxisTypeAndDimension(NetcdfDataset ds, AxisType type, final Dimension outer) Variable var = CoordSysEvaluator.findCoordByType(ds, type, new CoordSysEvaluator.Predicate() {
public boolean match(CoordinateAxis axis) {
if ((outer == null) && (axis.getRank() == 0))
return true;
if ((outer != null) && (axis.getRank() == 1) && (outer.equals(axis.getDimension(0))))
return true;
if (axis.getParentStructure() != null) {
Structure parent = axis.getParentStructure();
if ((outer != null) && (parent.getRank() == 1) && (outer.equals(parent.getDimension(0))))
return true;
}
return false;
}
});
if (var == null) return null;
return var.getFullName();

private void takeSnapshotIfCommitIndexAdvanced() long commitIndex = state.commitIndex();
if ((commitIndex - state.log().snapshotIndex()) < commitIndexAdvanceCountToSnapshot) {
return;
}
if (isTerminatedOrSteppedDown()) {
return;
}
RaftLog log = state.log();
Object snapshot = raftIntegration.takeSnapshot(commitIndex);
if (snapshot instanceof Throwable) {
Throwable t = (Throwable) snapshot;
logger.severe("Could not take snapshot at commit index: " + commitIndex, t);
return;
}
int snapshotTerm = log.getLogEntry(commitIndex).term();
RaftGroupMembers members = state.committedGroupMembers();
SnapshotEntry snapshotEntry = new SnapshotEntry(snapshotTerm, commitIndex, snapshot, members.index(), members.members());
long minMatchIndex = 0L;
LeaderState leaderState = state.leaderState();
if (leaderState != null) {
long[] indices = leaderState.matchIndices();
Arrays.sort(indices, 0, indices.length - 1);
minMatchIndex = indices[0];
}
long truncateLogsUpToIndex = max(commitIndex - maxNumberOfLogsToKeepAfterSnapshot, minMatchIndex);
int truncated = log.setSnapshot(snapshotEntry, truncateLogsUpToIndex);
if (logger.isFineEnabled()) {
logger.fine(snapshotEntry + " is taken, " + truncated + " entries are truncated.");
}

@SuppressWarnings( "checkstyle:npathcomplexity", "checkstyle:cyclomaticcomplexity", "checkstyle:methodlength"})
public void sendAppendRequest(Endpoint follower) {
if (!raftIntegration.isReachable(follower)) {
return;
}
RaftLog raftLog = state.log();
LeaderState leaderState = state.leaderState();
FollowerState followerState = leaderState.getFollowerState(follower);
if (followerState.isAppendRequestBackoffSet()) {
return;
}
long nextIndex = followerState.nextIndex();
if (nextIndex <= raftLog.snapshotIndex()
&& (!raftLog.containsLogEntry(nextIndex) || (nextIndex > 1 && !raftLog.containsLogEntry(nextIndex - 1)))) {
InstallSnapshot installSnapshot = new InstallSnapshot(localMember, state.term(), raftLog.snapshot());
if (logger.isFineEnabled()) {
logger.fine("Sending " + installSnapshot + " to " + follower + " since next index: " + nextIndex
+ " <= snapshot index: " + raftLog.snapshotIndex());
}
followerState.setMaxAppendRequestBackoff();
scheduleAppendAckResetTask();
raftIntegration.send(installSnapshot, follower);
return;
}
int prevEntryTerm = 0;
long prevEntryIndex = 0;
LogEntry[] entries;
boolean setAppendRequestBackoff = true;
if (nextIndex > 1) {
prevEntryIndex = nextIndex - 1;
LogEntry prevEntry = (raftLog.snapshotIndex() == prevEntryIndex)
? raftLog.snapshot() : raftLog.getLogEntry(prevEntryIndex);
assert prevEntry != null : "Prev entry index: " + prevEntryIndex + ", snapshot: " + raftLog.snapshotIndex();
prevEntryTerm = prevEntry.term();
long matchIndex = followerState.matchIndex();
if (matchIndex == 0) {
entries = new LogEntry[0];
} else if (nextIndex <= raftLog.lastLogOrSnapshotIndex()) {
long end = min(nextIndex + appendRequestMaxEntryCount, raftLog.lastLogOrSnapshotIndex());
entries = raftLog.getEntriesBetween(nextIndex, end);
} else {
entries = new LogEntry[0];
setAppendRequestBackoff = false;
}
} else if (nextIndex == 1 && raftLog.lastLogOrSnapshotIndex() > 0) {
long end = min(nextIndex + appendRequestMaxEntryCount, raftLog.lastLogOrSnapshotIndex());
entries = raftLog.getEntriesBetween(nextIndex, end);
} else {
entries = new LogEntry[0];
setAppendRequestBackoff = false;
}
AppendRequest request = new AppendRequest(getLocalMember(), state.term(), prevEntryTerm, prevEntryIndex,
state.commitIndex(), entries);
if (logger.isFineEnabled()) {
logger.fine("Sending " + request + " to " + follower + " with next index: " + nextIndex);
}
if (setAppendRequestBackoff) {
followerState.setAppendRequestBackoff();
scheduleAppendAckResetTask();
}
send(request, follower);

public boolean canReplicateNewEntry(Object operation) if (isTerminatedOrSteppedDown()) {
return false;
}
RaftLog log = state.log();
long lastLogIndex = log.lastLogOrSnapshotIndex();
long commitIndex = state.commitIndex();
if (lastLogIndex - commitIndex >= maxUncommittedEntryCount) {
return false;
}
if (status == TERMINATING) {
return false;
} else if (status == UPDATING_GROUP_MEMBER_LIST) {
return state.lastGroupMembers().isKnownMember(getLocalMember()) && !(operation instanceof RaftGroupCmd);
}
if (operation instanceof UpdateRaftGroupMembersCmd) {
LogEntry lastCommittedEntry = commitIndex == log.snapshotIndex() ? log.snapshot() : log.getLogEntry(commitIndex);
assert lastCommittedEntry != null;
return lastCommittedEntry.term() == state.term();
}
return true;

public void applyLogEntries() long commitIndex = state.commitIndex();
long lastApplied = state.lastApplied();
if (commitIndex == lastApplied) {
return;
}
assert commitIndex > lastApplied
: "commit index: " + commitIndex + " cannot be smaller than last applied: " + lastApplied;
RaftLog raftLog = state.log();
for (long idx = state.lastApplied() + 1; idx <= commitIndex; idx++) {
LogEntry entry = raftLog.getLogEntry(idx);
if (entry == null) {
String msg = "Failed to get log entry at index: " + idx;
logger.severe(msg);
throw new AssertionError(msg);
}
applyLogEntry(entry);
state.lastApplied(idx);
}
assert status != TERMINATED || commitIndex == raftLog.lastLogOrSnapshotIndex()
: "commit index: " + commitIndex + " must be equal to " + raftLog.lastLogOrSnapshotIndex() + " on termination.";
if (state.role() == LEADER || state.role() == FOLLOWER) {
takeSnapshotIfCommitIndexAdvanced();
}

public List<LogEntry> truncateEntriesFrom(long entryIndex) if (entryIndex <= snapshotIndex()) {
throw new IllegalArgumentException("Illegal index: " + entryIndex + ", snapshot index: " + snapshotIndex());
}
if (entryIndex > lastLogOrSnapshotIndex()) {
throw new IllegalArgumentException("Illegal index: " + entryIndex + ", last log index: " + lastLogOrSnapshotIndex());
}
long startSequence = toSequence(entryIndex);
assert startSequence >= logs.headSequence() : "Entry index: " + entryIndex + ", Head Seq: " + logs.headSequence();
List<LogEntry> truncated = new ArrayList<LogEntry>();
for (long ix = startSequence; ix <= logs.tailSequence(); ix++) {
truncated.add(logs.read(ix));
}
logs.setTailSequence(startSequence - 1);
return truncated;

private void applyLogEntry(LogEntry entry) if (logger.isFineEnabled()) {
logger.fine("Processing " + entry);
}
Object response = null;
Object operation = entry.operation();
if (operation instanceof RaftGroupCmd) {
if (operation instanceof DestroyRaftGroupCmd) {
setStatus(TERMINATED);
} else if (operation instanceof UpdateRaftGroupMembersCmd) {
if (state.lastGroupMembers().index() < entry.index()) {
setStatus(UPDATING_GROUP_MEMBER_LIST);
UpdateRaftGroupMembersCmd op = (UpdateRaftGroupMembersCmd) operation;
updateGroupMembers(entry.index(), op.getMembers());
}
assert status == UPDATING_GROUP_MEMBER_LIST : "STATUS: " + status;
assert state.lastGroupMembers().index() == entry.index();
state.commitGroupMembers();
UpdateRaftGroupMembersCmd cmd = (UpdateRaftGroupMembersCmd) operation;
if (cmd.getMember().equals(localMember) && cmd.getMode() == MembershipChangeMode.REMOVE) {
setStatus(STEPPED_DOWN);
invalidateFuturesUntil(entry.index() - 1, new LeaderDemotedException(localMember, null));
} else {
setStatus(ACTIVE);
}
response = entry.index();
} else {
response = new IllegalArgumentException("Invalid command: " + operation);
}
} else {
response = raftIntegration.runOperation(operation, entry.index());
}
if (response == PostponedResponse.INSTANCE) {
return;
}
completeFuture(entry.index(), response);

public void runQueryOperation(Object operation, SimpleCompletableFuture resultFuture) long commitIndex = state.commitIndex();
Object result = raftIntegration.runOperation(operation, commitIndex);
resultFuture.setResult(result);

public boolean addMember(long commitIndex, CPMemberInfo member) checkNotNull(member);
checkMetadataGroupInitSuccessful();
for (CPMemberInfo existingMember : activeMembers) {
if (existingMember.getAddress().equals(member.getAddress())) {
if (existingMember.getUuid().equals(member.getUuid())) {
if (logger.isFineEnabled()) {
logger.fine(member + " already exists.");
}
if (membershipChangeSchedule != null && member.equals(membershipChangeSchedule.getAddedMember())) {
membershipChangeSchedule = membershipChangeSchedule.addRetriedCommitIndex(commitIndex);
logger.info("CP groups are already being rebalanced for " + member);
return false;
}
return true;
}
throw new IllegalStateException(member + " cannot be added to the CP subsystem because another " + existingMember
+ " exists with the same address!");
}
}
checkState(membershipChangeSchedule == null,
"Cannot rebalance CP groups because there is ongoing " + membershipChangeSchedule);
Collection<CPMemberInfo> newMembers = new LinkedHashSet<>(activeMembers);
newMembers.add(member);
doSetActiveMembers(commitIndex, newMembers);
logger.info("Added new " + member + ". New active CP members list: " + newMembers);
List<CPGroupMembershipChange> changes = getGroupMembershipChangesForNewMember(member);
if (changes.size() > 0) {
membershipChangeSchedule = MembershipChangeSchedule.forJoiningMember(singletonList(commitIndex), member, changes);
if (logger.isFineEnabled()) {
logger.fine("CP group rebalancing is triggered for " + member + ", changes: " + membershipChangeSchedule);
}
return false;
}
return true;

public boolean removeMember(long commitIndex, CPMemberInfo leavingMember) checkNotNull(leavingMember);
checkMetadataGroupInitSuccessful();
if (!activeMembers.contains(leavingMember)) {
logger.fine("Not removing " + leavingMember + " since it is not an active CP member");
return true;
}
if (membershipChangeSchedule != null) {
if (leavingMember.equals(membershipChangeSchedule.getLeavingMember())) {
membershipChangeSchedule = membershipChangeSchedule.addRetriedCommitIndex(commitIndex);
if (logger.isFineEnabled()) {
logger.fine(leavingMember + " is already marked as leaving.");
}
return false;
}
String msg = "There is already an ongoing CP membership change process. " + "Cannot process remove request of "
+ leavingMember;
if (logger.isFineEnabled()) {
logger.fine(msg);
}
throw new CannotRemoveCPMemberException(msg);
}
if (activeMembers.size() == 2) {
logger.warning(leavingMember + " is directly removed as there are only " + activeMembers.size() + " CP members.");
removeActiveMember(commitIndex, leavingMember);
throw new RetryableHazelcastException();
} else if (activeMembers.size() == 1) {
logger.fine("Not removing the last active CP member: " + leavingMember + " to help it complete its shutdown");
return true;
}
return initMembershipChangeScheduleForLeavingMember(commitIndex, leavingMember);

public void invalidateFuturesFrom(long entryIndex) int count = 0;
Iterator<Entry<Long, SimpleCompletableFuture>> iterator = futures.entrySet().iterator();
while (iterator.hasNext()) {
Entry<Long, SimpleCompletableFuture> entry = iterator.next();
long index = entry.getKey();
if (index >= entryIndex) {
entry.getValue().setResult(new LeaderDemotedException(localMember, state.leader()));
iterator.remove();
count++;
}
}
if (count > 0) {
logger.warning("Invalidated " + count + " futures from log index: " + entryIndex);
}

protected double multiply(double[][] mat, double[] in, double[] out) double l = 0.;
for(int d1 = 0; d1 < in.length; d1++) {
final double[] row = mat[d1];
double t = 0.;
for(int d2 = 0; d2 < in.length; d2++) {
t += row[d2] * in[d2];
}
out[d1] = t;
l += t * t;
}
return l > 0 ? FastMath.sqrt(l) : 0.;

protected void randomInitialization(double[] out, Random rnd) double l2 = 0.;
while(!(l2 > 0)) {
for(int d = 0; d < out.length; d++) {
final double val = rnd.nextDouble();
out[d] = val;
l2 += val * val;
}
}
final double s = 1. / FastMath.sqrt(l2);
for(int d = 0; d < out.length; d++) {
out[d] *= s;
}

protected void findEigenVectors(double[][] imat, double[][] evs, double[] lambda) final int size = imat.length;
Random rnd = random.getSingleThreadedRandom();
double[] tmp = new double[size];
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Learning projections", tdim, LOG) : null;
for(int d = 0; d < tdim;) {
final double[] cur = evs[d];
randomInitialization(cur, rnd);
double l = multiply(imat, cur, tmp);
for(int iter = 0; iter < 100; iter++) {
double delta = updateEigenvector(tmp, cur, l);
if(delta < 1e-10) {
break;
}
l = multiply(imat, cur, tmp);
}
lambda[d++] = l = estimateEigenvalue(imat, cur);
LOG.incrementProcessed(prog);
if(d == tdim) {
break;
}
updateMatrix(imat, cur, l);
}
LOG.ensureCompleted(prog);

protected double estimateEigenvalue(double[][] mat, double[] in) double de = 0., di = 0.;
for(int d1 = 0; d1 < in.length; d1++) {
final double[] row = mat[d1];
double t = 0.;
for(int d2 = 0; d2 < in.length; d2++) {
t += row[d2] * in[d2];
}
final double s = in[d1];
de += t * s;
di += s * s;
}
return de / di;

private void hqr2() final int nn = this.n, low = 0, high = nn - 1;
double norm = 0.;
for(int i = 0; i < nn; i++) {
for(int j = (i > 0 ? i - 1 : 0); j < nn; j++) {
norm += abs(H[i][j]);
}
}
{
double exshift = 0.0;
int iter = 0;
for(int n = nn - 1; n >= low;) {
int l = n;
for(; l > low; --l) {
double s = abs(H[l - 1][l - 1]) + abs(H[l][l]);
if(abs(H[l][l - 1]) < 0x1P-52 * (s == 0. ? norm : s)) {
break;
}
}
if(l == n) {
d[n] = (H[n][n] += exshift);
e[n] = 0.;
n--;
iter = 0;
continue;
}
final double[] Hn = H[n], Hnm1 = H[n - 1];
if(l == n - 1) {
double w = Hn[n - 1] * Hnm1[n];
double p = (Hnm1[n - 1] - Hn[n]) * 0.5, q = p * p + w;
double x = (Hn[n] += exshift), z = FastMath.sqrt(abs(q));
Hnm1[n - 1] += exshift;
if(q >= 0) {
z = (p >= 0) ? p + z : p - z;
d[n - 1] = x + z;
d[n] = (z != 0.) ? x - w / z : d[n - 1];
e[n] = e[n - 1] = 0.;
x = Hn[n - 1];
double s = abs(x) + abs(z);
p = x / s;
q = z / s;
double r = FastMath.hypot(p, q);
p /= r;
q /= r;
for(int j = n - 1; j < nn; j++) {
double tmp = Hnm1[j];
Hnm1[j] = q * tmp + p * Hn[j];
Hn[j] = q * Hn[j] - p * tmp;
}
for(int i = 0; i <= n; i++) {
modifyQP(H[i], n, p, q);
}
for(int i = low; i <= high; i++) {
modifyQP(V[i], n, p, q);
}
}
else {
d[n] = d[n - 1] = x + p;
e[n] = -(e[n - 1] = z);
}
n -= 2;
iter = 0;
continue;
}
double x = Hn[n], y = 0., w = 0.;
y = Hnm1[n - 1];
w = Hn[n - 1] * Hnm1[n];
if(iter == 10) {
exshift += x;
for(int i = low; i <= n; i++) {
H[i][i] -= x;
}
double s = abs(Hn[n - 1]) + abs(Hnm1[n - 2]);
x = y = 0.75 * s;
w = -0.4375 * s * s;
}
if(iter == 30) {
double s = (y - x) * 0.5;
s = s * s + w;
if(s > 0) {
s = FastMath.sqrt(s);
s = (y < x) ? -s : s;
s = x - w / ((y - x) * 0.5 + s);
for(int i = low; i <= n; i++) {
H[i][i] -= s;
}
exshift += s;
x = y = w = 0.964;
}
}
++iter;
double p = 0., q = 0., r = 0.;
int m = n - 2;
for(; m >= l; m--) {
final double[] Hm = H[m], Hmp1 = H[m + 1];
final double z = Hm[m], xz = x - z;
p = (xz * (y - z) - w) / Hmp1[m] + Hm[m + 1];
q = Hmp1[m + 1] - xz - y;
r = H[m + 2][m + 1];
double tmp = abs(p) + abs(q) + abs(r);
p /= tmp;
q /= tmp;
r /= tmp;
if(m == l || abs(Hm[m - 1]) * (abs(q) + abs(r)) < 0x1P-52 * (abs(p) * (abs(H[m - 1][m - 1]) + abs(z) + abs(Hmp1[m + 1])))) {
break;
}
}
for(int i = m + 2; i <= n; i++) {
final double[] Hi = H[i];
Hi[i - 2] = 0.;
if(i > m + 2) {
Hi[i - 3] = 0.;
}
}
for(int k = m, last = n - 1; k <= last; k++) {
boolean notlast = (k != last);
final double[] Hk = H[k], Hkp1 = H[k + 1],
Hkp2 = notlast ? H[k + 2] : null;
if(k != m) {
p = Hk[k - 1];
q = Hkp1[k - 1];
r = notlast ? Hkp2[k - 1] : 0.;
x = abs(p) + abs(q) + abs(r);
if(x == 0.0) {
continue;
}
p /= x;
q /= x;
r /= x;
}
double s = FastMath.hypot(p, q, r);
s = (p < 0) ? -s : s;
if(s != 0) {
if(k != m) {
Hk[k - 1] = -s * x;
}
else if(l != m) {
Hk[k - 1] = -Hk[k - 1];
}
p += s;
x = p / s;
y = q / s;
double z = r / s;
q /= p;
r /= p;
for(int j = k; j < nn; j++) {
double tmp = Hk[j] + q * Hkp1[j];
if(notlast) {
tmp += r * Hkp2[j];
Hkp2[j] -= tmp * z;
}
Hk[j] -= tmp * x;
Hkp1[j] -= tmp * y;
}
for(int i = 0; i <= Math.min(n, k + 3); i++) {
modifyQR(H[i], k, notlast, q, r, x, y, z);
}
for(int i = low; i <= high; i++) {
modifyQR(V[i], k, notlast, q, r, x, y, z);
}
}
}
}
}
if(norm == 0.0) {
return;
}
for(int n = nn - 1; n >= 0; n--) {
double p = d[n], q = e[n];
if(q == 0) {
hqr2BacksubstituteReal(n, p, norm);
}
else if(q < 0) {
hqr2BacksubstituteComplex(n, p, q, norm);
}
}
hqr2BackTransformation(nn, low, high);

private ScalesResult run(Relation<? extends NumberVector> rel) double[][] mms = RelationUtil.computeMinMax(rel);
int dim = mms[0].length;
double delta = 0.;
for(int d = 0; d < dim; d++) {
double del = mms[1][d] - mms[0][d];
delta = del > delta ? del : delta;
}
if(delta < Double.MIN_NORMAL) {
delta = 1.;
}
int log10res = (int) Math.ceil(Math.log10(delta / (LinearScale.MAXTICKS - 1)));
double res = MathUtil.powi(10, log10res);
double target = Math.ceil(delta / res) * res;
LinearScale[] scales = new LinearScale[dim];
for(int d = 0; d < dim; d++) {
double mid = (mms[0][d] + mms[1][d] - target) * .5;
double min = Math.floor(mid / res) * res;
double max = Math.ceil((mid + target) / res) * res;
scales[d] = new LinearScale(min, max);
}
return new ScalesResult(scales);

private double preNormMBR(SpatialComparable mbr, final int start, final int end) double agg = 0.;
for(int d = start; d < end; d++) {
double delta = mbr.getMin(d);
delta = delta >= 0 ? delta : -mbr.getMax(d);
if(delta > 0.) {
agg += MathUtil.powi(delta, intp);
}
}
return agg;

private double preNormMBR(SpatialComparable mbr, final int start, final int end) double agg = 0.;
for(int d = start; d < end; d++) {
double delta = mbr.getMin(d);
delta = delta >= 0 ? delta : -mbr.getMax(d);
if(delta > 0.) {
agg += FastMath.pow(delta, p);
}
}
return agg;

private double preDistanceMBR(SpatialComparable mbr1, SpatialComparable mbr2, final int start, final int end) double agg = 0.;
for(int d = start; d < end; d++) {
double delta = mbr2.getMin(d) - mbr1.getMax(d);
delta = delta >= 0 ? delta : mbr1.getMin(d) - mbr2.getMax(d);
if(delta > 0.) {
agg += MathUtil.powi(delta, intp);
}
}
return agg;

