@Override public DescriptorValue calculate(IAtom atom, IAtomContainer ac) if (factory == null)
try {
factory = AtomTypeFactory.getInstance("org/openscience/cdk/config/data/jmol_atomtypes.txt",
ac.getBuilder());
} catch (Exception exception) {
return getDummyDescriptorValue(exception);
}
Iterator<IAtom> allAtoms = ac.atoms().iterator();
double atomicSoftness;
double radiusTarget;
atomicSoftness = 0;
double partial;
double radius;
String symbol;
IAtomType type;
try {
symbol = atom.getSymbol();
type = factory.getAtomType(symbol);
radiusTarget = type.getCovalentRadius();
} catch (Exception execption) {
logger.debug(execption);
return getDummyDescriptorValue(execption);
}
while (allAtoms.hasNext()) {
IAtom curAtom = (IAtom) allAtoms.next();
if (atom.getPoint3d() == null || curAtom.getPoint3d() == null) {
return getDummyDescriptorValue(new CDKException(
"The target atom or current atom had no 3D coordinates. These are required"));
}
if (!atom.equals(curAtom)) {
partial = 0;
symbol = curAtom.getSymbol();
try {
type = factory.getAtomType(symbol);
} catch (Exception exception) {
logger.debug(exception);
return getDummyDescriptorValue(exception);
}
radius = type.getCovalentRadius();
partial += radius * radius;
partial += (radiusTarget * radiusTarget);
partial = partial / (calculateSquareDistanceBetweenTwoAtoms(curAtom, atom));
atomicSoftness += partial;
}
}
atomicSoftness = 2 * atomicSoftness;
atomicSoftness = atomicSoftness * 0.172;
return new DescriptorValue(getSpecification(), getParameterNames(), getParameters(), new DoubleResult(
atomicSoftness), NAMES);

public static double calculate(IAtomContainer molecule) throws CDKException if (atomTypeList == null) {
atomTypeList = AtomTypeFactory.getInstance("org/openscience/cdk/dict/data/cdk-atom-types.owl",
molecule.getBuilder()
);
}
double sum = 0.0;
int totalHCount = 0;
for (IAtom atom : molecule.atoms()) {
Double bondiiVolume = bondiiVolumes.get(atom.getSymbol());
if (bondiiVolume == null) throw new CDKException("Unsupported element.");
sum += bondiiVolume;
IAtomType type = atomTypeList.getAtomType(atom.getAtomTypeName());
if (type == null) throw new CDKException("Unknown atom type for atom: " + atom.getSymbol());
if (type.getFormalNeighbourCount() == null)
throw new CDKException("Formal neighbor count not given for : " + type.getAtomTypeName());
int hCount = type.getFormalNeighbourCount() - molecule.getConnectedBondsCount(atom);
sum += (hCount * bondiiVolumes.get("H"));
totalHCount += hCount;
}
sum -= 5.92 * (molecule.getBondCount() + totalHCount);
boolean[] originalFlags = molecule.getFlags();
Aromaticity.cdkLegacy().apply(molecule);
IRingSet ringSet = Cycles.sssr(molecule).toRingSet();
if (ringSet.getAtomContainerCount() > 0) {
int aromRingCount = 0;
int nonAromRingCount = 0;
for (IAtomContainer ring : ringSet.atomContainers()) {
if (ringIsAromatic(ring)) {
aromRingCount++;
} else {
nonAromRingCount++;
}
}
molecule.setFlags(originalFlags);
sum -= 14.7 * aromRingCount;
sum -= 3.8 * nonAromRingCount;
}
return sum;

private void searchAndPlaceBranches(IAtomContainer molecule, IAtomContainer chain, AtomPlacer3D ap3d, AtomTetrahedralLigandPlacer3D atlp3d, AtomPlacer atomPlacer) throws CDKException List atoms = null;
IAtomContainer branchAtoms = molecule.getBuilder().newInstance(IAtomContainer.class);
IAtomContainer connectedAtoms = molecule.getBuilder().newInstance(IAtomContainer.class);
for (int i = 0; i < chain.getAtomCount(); i++) {
atoms = molecule.getConnectedAtomsList(chain.getAtom(i));
for (int j = 0; j < atoms.size(); j++) {
IAtom atom = (IAtom) atoms.get(j);
if (!(atom.getSymbol()).equals("H") & !(atom.getFlag(CDKConstants.ISPLACED))
& !(atom.getFlag(CDKConstants.ISINRING))) {
connectedAtoms.add(ap3d.getPlacedHeavyAtoms(molecule, chain.getAtom(i)));
try {
setBranchAtom(molecule, atom, chain.getAtom(i), connectedAtoms, ap3d, atlp3d);
} catch (CDKException ex2) {
logger.error("SearchAndPlaceBranchERROR: Cannot find enough neighbour atoms due to"
+ ex2.toString());
throw new CDKException("SearchAndPlaceBranchERROR: Cannot find enough neighbour atoms: "
+ ex2.getMessage(), ex2);
}
branchAtoms.addAtom(atom);
connectedAtoms.removeAllElements();
}
}
}
placeLinearChains3D(molecule, branchAtoms, ap3d, atlp3d, atomPlacer);

@Override public DescriptorValue calculate(IAtomContainer container) IAtomContainer molecule;
try {
molecule = (IAtomContainer) container.clone();
} catch (CloneNotSupportedException e) {
return getDummyDescriptorValue(new CDKException("Error occurred during clone " + e));
}
try {
CDKAtomTypeMatcher matcher = CDKAtomTypeMatcher.getInstance(molecule.getBuilder());
Iterator<IAtom> atoms = molecule.atoms().iterator();
while (atoms.hasNext()) {
IAtom atom = atoms.next();
IAtomType type = matcher.findMatchingAtomType(molecule, atom);
AtomTypeManipulator.configure(atom, type);
}
CDKHydrogenAdder hAdder = CDKHydrogenAdder.getInstance(molecule.getBuilder());
hAdder.addImplicitHydrogens(molecule);
AtomContainerManipulator.convertImplicitToExplicitHydrogens(molecule);
} catch (Exception e) {
return getDummyDescriptorValue(new CDKException("Could not add hydrogens: " + e.getMessage(), e));
}
try {
AtomContainerManipulator.percieveAtomTypesAndConfigureAtoms(molecule);
} catch (CDKException e) {
return getDummyDescriptorValue(new CDKException("Could not percieve atom types: " + e.getMessage(), e));
}
try {
Aromaticity.cdkLegacy().apply(molecule);
} catch (CDKException e) {
return getDummyDescriptorValue(new CDKException("Could not percieve aromaticity: " + e.getMessage(), e));
}
int[][] distancematrix = PathTools.computeFloydAPSP(AdjacencyMatrix.getMatrix(molecule));
try {
double[] w = listpolarizability(molecule, distancematrix);
int natom = molecule.getAtomCount();
double[] polarizabilitySum = new double[5];
for (int k = 0; k < 5; k++) {
for (int i = 0; i < natom; i++) {
if (molecule.getAtom(i).getSymbol().equals("H")) continue;
for (int j = 0; j < natom; j++) {
if (molecule.getAtom(j).getSymbol().equals("H")) continue;
if (distancematrix[i][j] == k) {
polarizabilitySum[k] += w[i] * w[j];
} else
polarizabilitySum[k] += 0.0;
}
}
if (k > 0) polarizabilitySum[k] = polarizabilitySum[k] / 2;
}
DoubleArrayResult result = new DoubleArrayResult(5);
for (double aPolarizabilitySum : polarizabilitySum) {
result.add(aPolarizabilitySum);
}
return new DescriptorValue(getSpecification(), getParameterNames(), getParameters(), result,
getDescriptorNames());
} catch (Exception ex) {
return getDummyDescriptorValue(new CDKException("Error while calculating the ATSpolarizabilty descriptor: "
+ ex.getMessage(), ex));
}

private int layoutRingSet(Vector2d firstBondVector, IRingSet rs) RingSetManipulator.sort(rs);
final IRing first = RingSetManipulator.getMostComplexRing(rs);
final boolean macro         = isMacroCycle(first, rs);
final boolean macroDbStereo = macro && first.stereoElements().iterator().hasNext();
int result = 0;
if (!macroDbStereo) {
if (lookupRingSystem(rs, molecule, rs.getAtomContainerCount() > 1)) {
for (IAtomContainer container : rs.atomContainers())
container.setFlag(CDKConstants.ISPLACED, true);
rs.setFlag(CDKConstants.ISPLACED, true);
return macro ? 2 : 1;
} else {
final IRingSet core = getRingSetCore(rs);
if (core.getAtomContainerCount() > 0 &&
core.getAtomContainerCount() < rs.getAtomContainerCount() &&
lookupRingSystem(core, molecule, !macro || rs.getAtomContainerCount() > 1)) {
for (IAtomContainer container : core.atomContainers())
container.setFlag(CDKConstants.ISPLACED, true);
}
}
}
if (!first.getFlag(CDKConstants.ISPLACED)) {
IAtomContainer sharedAtoms = placeFirstBond(first.getBond(0), firstBondVector);
if (!macro || !macroPlacer.layout(first, rs)) {
Vector2d ringCenterVector = ringPlacer.getRingCenterOfFirstRing(first, firstBondVector, bondLength);
ringPlacer.placeRing(first, sharedAtoms, GeometryUtil.get2DCenter(sharedAtoms), ringCenterVector, bondLength);
} else {
result = 2;
}
first.setFlag(CDKConstants.ISPLACED, true);
}
if (macro) {
for (IAtomContainer ring : rs.atomContainers())
ring.setProperty(RingPlacer.SNAP_HINT, true);
}
int thisRing = 0;
IRing ring = first;
do {
if (ring.getFlag(CDKConstants.ISPLACED)) {
ringPlacer.placeConnectedRings(rs, ring, RingPlacer.FUSED, bondLength);
ringPlacer.placeConnectedRings(rs, ring, RingPlacer.BRIDGED, bondLength);
ringPlacer.placeConnectedRings(rs, ring, RingPlacer.SPIRO, bondLength);
}
thisRing++;
if (thisRing == rs.getAtomContainerCount()) {
thisRing = 0;
}
ring = (IRing) rs.getAtomContainer(thisRing);
} while (!allPlaced(rs));
return result;

@Override public IRingSet getRingSet(IAtomContainer molecule) throws CDKException Collection<List<IAtom>> cycles = findRings(molecule);
IRingSet ringSet = molecule.getBuilder().newInstance(IRingSet.class);
for (List<IAtom> ringAtoms : cycles) {
IRing ring = molecule.getBuilder().newInstance(IRing.class);
for (IAtom atom : ringAtoms) {
atom.setFlag(CDKConstants.ISINRING, true);
ring.addAtom(atom);
for (IAtom atomNext : ringAtoms) {
if (!atom.equals(atomNext)) {
IBond bond = molecule.getBond(atom, atomNext);
if (bond != null) {
bond.setFlag(CDKConstants.ISINRING, true);
ring.addElectronContainer(bond);
}
}
}
}
ringSet.addAtomContainer(ring);
}
return ringSet;

@Override public IReaction initiate(IAtomContainerSet atomContainerSet, ArrayList<IAtom> atomList, ArrayList<IBond> bondList) throws CDKException CDKAtomTypeMatcher atMatcher = CDKAtomTypeMatcher.getInstance(atomContainerSet.getBuilder());
if (atomContainerSet.getAtomContainerCount() != 1) {
throw new CDKException("TautomerizationMechanism only expects one IAtomContainer");
}
if (atomList.size() != 4) {
throw new CDKException("TautomerizationMechanism expects four atoms in the ArrayList");
}
if (bondList.size() != 3) {
throw new CDKException("TautomerizationMechanism expects three bonds in the ArrayList");
}
IAtomContainer molecule = atomContainerSet.getAtomContainer(0);
IAtomContainer reactantCloned;
try {
reactantCloned = (IAtomContainer) molecule.clone();
} catch (CloneNotSupportedException e) {
throw new CDKException("Could not clone IAtomContainer!", e);
}
IAtom atom1 = atomList.get(0);
IAtom atom1C = reactantCloned.getAtom(molecule.indexOf(atom1));
IAtom atom2 = atomList.get(1);
IAtom atom2C = reactantCloned.getAtom(molecule.indexOf(atom2));
IAtom atom3 = atomList.get(2);
IAtom atom3C = reactantCloned.getAtom(molecule.indexOf(atom3));
IAtom atom4 = atomList.get(3);
IAtom atom4C = reactantCloned.getAtom(molecule.indexOf(atom4));
IBond bond1 = bondList.get(0);
int posBond1 = molecule.indexOf(bond1);
IBond bond2 = bondList.get(1);
int posBond2 = molecule.indexOf(bond2);
IBond bond3 = bondList.get(2);
int posBond3 = molecule.indexOf(bond3);
BondManipulator.decreaseBondOrder(reactantCloned.getBond(posBond1));
BondManipulator.increaseBondOrder(reactantCloned.getBond(posBond2));
reactantCloned.removeBond(reactantCloned.getBond(posBond3));
IBond newBond = molecule.getBuilder().newInstance(IBond.class, atom1C, atom4C, IBond.Order.SINGLE);
reactantCloned.addBond(newBond);
atom1C.setHybridization(null);
AtomContainerManipulator.percieveAtomTypesAndConfigureAtoms(reactantCloned);
IAtomType type = atMatcher.findMatchingAtomType(reactantCloned, atom1C);
if (type == null || type.getAtomTypeName().equals("X")) return null;
atom3C.setHybridization(null);
AtomContainerManipulator.percieveAtomTypesAndConfigureAtoms(reactantCloned);
type = atMatcher.findMatchingAtomType(reactantCloned, atom3C);
if (type == null || type.getAtomTypeName().equals("X")) return null;
IReaction reaction = atom2C.getBuilder().newInstance(IReaction.class);
reaction.addReactant(molecule);
for (IAtom atom : molecule.atoms()) {
IMapping mapping = atom2C.getBuilder().newInstance(IMapping.class, atom,
reactantCloned.getAtom(molecule.indexOf(atom)));
reaction.addMapping(mapping);
}
reaction.addProduct(reactantCloned);
return reaction;

