public static <T extends ImageGray<T>> InputToBinary<T> threshold( ConfigThreshold config, Class<T> inputType) switch( config.type ) {
case FIXED:
return globalFixed(config.fixedThreshold, config.down, inputType);
case GLOBAL_OTSU:
return globalOtsu(config.minPixelValue, config.maxPixelValue, config.scale, config.down, inputType);
case GLOBAL_ENTROPY:
return globalEntropy(config.minPixelValue, config.maxPixelValue, config.scale, config.down, inputType);
case GLOBAL_LI:
return globalLi(config.minPixelValue, config.maxPixelValue, config.scale, config.down, inputType);
case GLOBAL_HUANG:
return globalHuang(config.minPixelValue, config.maxPixelValue, config.scale, config.down, inputType);
case LOCAL_GAUSSIAN:
return localGaussian(config.width, config.scale, config.down, inputType);
case LOCAL_SAVOLA:
return localSauvola(config.width, config.down, config.savolaK, inputType);
case LOCAL_NICK:
return localNick(config.width, config.down, config.nickK, inputType);
case LOCAL_MEAN:
return localMean(config.width, config.scale, config.down, inputType);
case LOCAL_OTSU: {
ConfigThresholdLocalOtsu c = (ConfigThresholdLocalOtsu) config;
return localOtsu(config.width, config.scale, config.down, c.useOtsu2, c.tuning, inputType);
}
case BLOCK_MIN_MAX: {
ConfigThresholdBlockMinMax c = (ConfigThresholdBlockMinMax) config;
return blockMinMax(c.width, c.scale , c.down, c.thresholdFromLocalBlocks, c.minimumSpread,
inputType);
}
case BLOCK_MEAN:
return blockMean(config.width, config.scale , config.down,
config.thresholdFromLocalBlocks, inputType);
case BLOCK_OTSU: {
ConfigThresholdLocalOtsu c = (ConfigThresholdLocalOtsu) config;
return blockOtsu(c.width, c.scale, c.down, c.thresholdFromLocalBlocks, c.useOtsu2, c.tuning,
inputType);
}
}
throw new IllegalArgumentException("Unknown type "+config.type);

private Object getMethods(Class sender, String name, boolean isCallToSuper) Object answer;
final MetaMethodIndex.Entry entry = metaMethodIndex.getMethods(sender, name);
if (entry == null)
answer = FastArray.EMPTY_LIST;
else
if (isCallToSuper) {
answer = entry.methodsForSuper;
} else {
answer = entry.methods;
}
if (answer == null) answer = FastArray.EMPTY_LIST;
if (!isCallToSuper) {
List used = GroovyCategorySupport.getCategoryMethods(name);
if (used != null) {
FastArray arr;
if (answer instanceof MetaMethod) {
arr = new FastArray();
arr.add(answer);
}
else
arr = ((FastArray) answer).copy();
for (Iterator iter = used.iterator(); iter.hasNext();) {
MetaMethod element = (MetaMethod) iter.next();
if (!element.getDeclaringClass().getTheClass().isAssignableFrom(sender))
continue;
filterMatchingMethodForCategory(arr, element);
}
answer = arr;
}
}
return answer;

public List<MetaProperty> getProperties() checkInitalised();
SingleKeyHashMap propertyMap = classPropertyIndex.getNullable(theCachedClass);
if (propertyMap==null) {
propertyMap = new SingleKeyHashMap();
}
List ret = new ArrayList(propertyMap.size());
for (ComplexKeyHashMap.EntryIterator iter = propertyMap.getEntrySetIterator(); iter.hasNext();) {
MetaProperty element = (MetaProperty) ((SingleKeyHashMap.Entry) iter.next()).value;
if (element instanceof CachedField) continue;
if (element instanceof MetaBeanProperty) {
MetaBeanProperty mp = (MetaBeanProperty) element;
boolean setter = true;
boolean getter = true;
if (mp.getGetter() == null || mp.getGetter() instanceof GeneratedMetaMethod || mp.getGetter() instanceof NewInstanceMetaMethod) {
getter = false;
}
if (mp.getSetter() == null || mp.getSetter() instanceof GeneratedMetaMethod || mp.getSetter() instanceof NewInstanceMetaMethod) {
setter = false;
}
if (!setter && !getter) continue;
}
ret.add(element);
}
return ret;

private static MethodHandle createSAMTransform(Object arg, Class parameter) Method method = CachedSAMClass.getSAMMethod(parameter);
if (method == null) return null;
if (parameter.isInterface()) {
if (Traits.isTrait(parameter)) {
MethodHandle ret = TO_SAMTRAIT_PROXY;
ret = MethodHandles.insertArguments(ret, 2, ProxyGenerator.INSTANCE, Collections.singletonList(parameter));
ret = MethodHandles.insertArguments(ret, 0, method.getName());
return ret;
}
MethodHandle ret = TO_REFLECTIVE_PROXY;
ret = MethodHandles.insertArguments(ret, 1,
method.getName(),
arg.getClass().getClassLoader(),
new Class[]{parameter});
return ret;
} else {
MethodHandle ret = TO_GENERATED_PROXY;
ret = MethodHandles.insertArguments(ret, 2, ProxyGenerator.INSTANCE, parameter);
ret = MethodHandles.insertArguments(ret, 0, method.getName());
return ret;
}

