@Override @DefinedBy(Api.COMPILER_TREE) @SuppressWarnings("fallthrough") public Void visitAttribute(AttributeTree tree, Void ignore) HtmlTag currTag = tagStack.peek().tag;
if (currTag != null) {
Name name = tree.getName();
HtmlTag.Attr attr = currTag.getAttr(name);
if (attr != null) {
if (env.htmlVersion == HtmlVersion.HTML4 && attr.name().contains("-")) {
env.messages.error(HTML, tree, "dc.attr.not.supported.html4", name);
}
boolean first = tagStack.peek().attrs.add(attr);
if (!first)
env.messages.error(HTML, tree, "dc.attr.repeated", name);
}
if (!name.toString().startsWith("on")) {
AttrKind k = currTag.getAttrKind(name);
switch (env.htmlVersion) {
case HTML4:
validateHtml4Attrs(tree, name, k);
break;
case HTML5:
validateHtml5Attrs(tree, name, k);
break;
}
}
if (attr != null) {
switch (attr) {
case NAME:
if (currTag != HtmlTag.A) {
break;
}
case ID:
String value = getAttrValue(tree);
if (value == null) {
env.messages.error(HTML, tree, "dc.anchor.value.missing");
} else {
if (!validName.matcher(value).matches()) {
env.messages.error(HTML, tree, "dc.invalid.anchor", value);
}
if (!checkAnchor(value)) {
env.messages.error(HTML, tree, "dc.anchor.already.defined", value);
}
}
break;
case HREF:
if (currTag == HtmlTag.A) {
String v = getAttrValue(tree);
if (v == null || v.isEmpty()) {
env.messages.error(HTML, tree, "dc.attr.lacks.value");
} else {
Matcher m = docRoot.matcher(v);
if (m.matches()) {
String rest = m.group(2);
if (!rest.isEmpty())
checkURI(tree, rest);
} else {
checkURI(tree, v);
}
}
}
break;
case VALUE:
if (currTag == HtmlTag.LI) {
String v = getAttrValue(tree);
if (v == null || v.isEmpty()) {
env.messages.error(HTML, tree, "dc.attr.lacks.value");
} else if (!validNumber.matcher(v).matches()) {
env.messages.error(HTML, tree, "dc.attr.not.number");
}
}
break;
case BORDER:
if (currTag == HtmlTag.TABLE) {
String v = getAttrValue(tree);
try {
if (env.htmlVersion == HtmlVersion.HTML5
&& (v == null || (!v.isEmpty() && Integer.parseInt(v) != 1))) {
env.messages.error(HTML, tree, "dc.attr.table.border.html5", attr);
}
} catch (NumberFormatException ex) {
env.messages.error(HTML, tree, "dc.attr.table.border.html5", attr);
}
}
break;
}
}
}
return super.visitAttribute(tree, ignore);

public static String print(DeprData dd) StringBuilder sb = new StringBuilder();
sb.append(depr(dd.since, dd.forRemoval))
.append(' ');
switch (dd.kind) {
case ANNOTATION_TYPE:
sb.append("@interface ");
sb.append(unslashify(dd.typeName));
break;
case CLASS:
sb.append("class ");
sb.append(unslashify(dd.typeName));
break;
case ENUM:
sb.append("enum ");
sb.append(unslashify(dd.typeName));
break;
case INTERFACE:
sb.append("interface ");
sb.append(unslashify(dd.typeName));
break;
case ENUM_CONSTANT:
case FIELD:
sb.append(unslashify(dd.typeName))
.append('.')
.append(dd.nameSig);
break;
case CONSTRUCTOR:
Matcher cons = DESC_PAT.matcher(dd.nameSig);
sb.append(unslashify(dd.typeName));
if (cons.matches()) {
sb.append('(')
.append(parms(cons.group("args")))
.append(')');
} else {
sb.append('.')
.append(dd.nameSig);
}
break;
case METHOD:
Matcher meth = DESC_PAT.matcher(dd.nameSig);
if (meth.matches()) {
sb.append(desc(meth.group("return")))
.append(' ')
.append(unslashify(dd.typeName))
.append('.')
.append(meth.group("name"))
.append('(')
.append(parms(meth.group("args")))
.append(')');
} else {
sb.append(unslashify(dd.typeName))
.append('.')
.append(dd.nameSig);
}
break;
}
return sb.toString();

