public static MAMath.ScaleOffset calcScaleOffsetSkipMissingData(Array a, double missingValue, int nbits) MAMath.MinMax minmax = getMinMaxSkipMissingData(a, missingValue);
if (a.isUnsigned()) {
long size = (1L << nbits) - 1;
double offset = minmax.min;
double scale =(minmax.max - minmax.min) / size;
return new ScaleOffset(scale, offset);
} else {
long size = (1L << nbits) - 2;
double offset = (minmax.max + minmax.min) / 2;
double scale =(minmax.max - minmax.min) / size;
return new ScaleOffset(scale, offset);
}

public double[] SatToFGF(double lamda, double theta, double scale_x, double offset_x, double scale_y, double offset_y) double fgf_x = (lamda - offset_x) / scale_x;
double fgf_y = (theta - offset_y) / scale_y;
return new double[]{fgf_x, fgf_y};

private Point2d horizontalOffset(Point2d[] points, Turn[] turns, Projection projection) if (projection != Projection.Chair)
return new Point2d(0, 0);
int offset = chairCenterOffset(turns);
int prev = (offset + 5) % 6;
int next = (offset + 7) % 6;
double deltaX = points[prev].x - points[next].x;
double deltaY = points[prev].y - points[next].y;
double mag = Math.sqrt(deltaX * deltaX + deltaY * deltaY);
deltaX /= mag;
deltaY /= mag;
if (deltaX < 0) {
deltaX = -deltaX;
deltaY = -deltaY;
}
return new Point2d(1 - deltaX, deltaY);

static Turn[] turns(Point2d[] points) final Turn[] turns = new Turn[points.length];
for (int i = 1; i <= points.length; i++) {
Point2d prevXy = points[i - 1];
Point2d currXy = points[i % points.length];
Point2d nextXy = points[(i + 1) % points.length];
int parity = (int) Math.signum(det(prevXy.x, prevXy.y,
currXy.x, currXy.y,
nextXy.x, nextXy.y));
if (parity == 0) return null;
turns[i % points.length] = parity < 0 ? Right : Turn.Left;
}
return turns;

static Point2d[] decodeCoordinates(String str) if (str.startsWith("|(")) {
int end = str.indexOf(')', 2);
if (end < 0)
return new Point2d[0];
String[] strs = str.substring(2, end).split(";");
Point2d[] points = new Point2d[strs.length];
for (int i = 0; i < strs.length; i++) {
String coord = strs[i];
int first  = coord.indexOf(',');
int second = coord.indexOf(',', first+1);
points[i] = new Point2d(Double.parseDouble(coord.substring(0, first)),
Double.parseDouble(coord.substring(first + 1, second)));
}
return points;
} else {
String[] strs = str.split(", ");
Point2d[] points = new Point2d[strs.length / 2];
for (int i = 0; i < strs.length; i += 2) {
points[i / 2] = new Point2d(Double.parseDouble(strs[i]), Double.parseDouble(strs[i + 1]));
}
return points;
}

private static Point2d[] coordinatesOfCycle(int[] cycle, IAtomContainer container) Point2d[] points = new Point2d[cycle.length];
for (int i = 0; i < cycle.length; i++) {
points[i] = container.getAtom(cycle[i]).getPoint2d();
}
return points;

static List<Point2D> pointsOf(final Shape shape) final List<Point2D> points = new ArrayList<Point2D>();
final double[] coordinates = new double[6];
for (PathIterator i = shape.getPathIterator(null); !i.isDone(); i.next()) {
switch (i.currentSegment(coordinates)) {
case PathIterator.SEG_CLOSE:
break;
case PathIterator.SEG_MOVETO:
case PathIterator.SEG_LINETO:
points.add(new Point2D.Double(coordinates[0], coordinates[1]));
break;
case PathIterator.SEG_QUADTO:
points.add(new Point2D.Double(coordinates[0], coordinates[1]));
points.add(new Point2D.Double(coordinates[2], coordinates[3]));
break;
case PathIterator.SEG_CUBICTO:
points.add(new Point2D.Double(coordinates[0], coordinates[1]));
points.add(new Point2D.Double(coordinates[2], coordinates[3]));
points.add(new Point2D.Double(coordinates[4], coordinates[5]));
break;
}
}
if (!points.isEmpty() && points.get(points.size() - 1).equals(points.get(0))) {
points.remove(points.size() - 1);
}
return points;

static List<Point2D> grahamScan(final List<Point2D> points) if (points.size() <= 3) return new ArrayList<Point2D>(points);
Collections.sort(points, new CompareYThenX());
Collections.sort(points, new PolarComparator(points.get(0)));
Deque<Point2D> hull = new ArrayDeque<Point2D>();
hull.push(points.get(0));
hull.push(points.get(1));
hull.push(points.get(2));
for (int i = 3; i < points.size(); i++) {
Point2D top = hull.pop();
while (!hull.isEmpty() && !isLeftTurn(hull.peek(), top, points.get(i))) {
top = hull.pop();
}
hull.push(top);
hull.push(points.get(i));
}
return new ArrayList<Point2D>(hull);

List<IStereoElement> recognise(Set<Projection> projections) if (!projections.contains(Projection.Haworth) && !projections.contains(Projection.Chair))
return Collections.emptyList();
List<IStereoElement> elements = new ArrayList<IStereoElement>();
RingSearch ringSearch = new RingSearch(container, graph);
for (int[] isolated : ringSearch.isolated()) {
if (isolated.length < 5 || isolated.length > 7)
continue;
int[] cycle = Arrays.copyOf(GraphUtil.cycle(graph, isolated),
isolated.length);
Point2d[]       points     = coordinatesOfCycle(cycle, container);
Turn[]          turns      = turns(points);
WoundProjection projection = WoundProjection.ofTurns(turns);
if (!projections.contains(projection.projection))
continue;
if (projection.projection == Projection.Haworth && !checkHaworthAlignment(points))
continue;
final Point2d horizontalXy = horizontalOffset(points, turns, projection.projection);
if (1 - Math.abs(horizontalXy.y) < QUART_CARDINALITY_THRESHOLD)
continue;
int[] above = cycle.clone();
int[] below = cycle.clone();
if (!assignSubstituents(cycle, above, below, projection, horizontalXy))
continue;
elements.addAll(newTetrahedralCenters(cycle, above, below, projection));
}
return elements;

boolean assignLayout(IAtomContainer container) try {
int n = container.getAtomCount();
int[] ordering = new int[n];
String smiles = cansmi(container, ordering);
for (Point2d[] points : templateMap.get(smiles)) {
for (int i = 0; i < n; i++) {
container.getAtom(i).setPoint2d(new Point2d(points[ordering[i]]));
}
return true;
}
} catch (CDKException e) {
}
return false;

private static Direction direction(Point2d centerXy, Point2d substituentXy, Point2d horizontalXy, boolean haworth) double deltaX = substituentXy.x - centerXy.x;
double deltaY = substituentXy.y - centerXy.y;
double mag = Math.sqrt(deltaX * deltaX + deltaY * deltaY);
deltaX /= mag;
deltaY /= mag;
if (deltaX > 0) {
deltaX -= horizontalXy.x;
deltaY -= horizontalXy.y;
} else {
deltaX += horizontalXy.x;
deltaY += horizontalXy.y;
}
mag = Math.sqrt(deltaX * deltaX + deltaY * deltaY);
deltaX /= mag;
deltaY /= mag;
if (haworth && Math.abs(deltaX) > CARDINALITY_THRESHOLD)
return Direction.Other;
return deltaY > 0 ? Direction.Up : Direction.Down;

static IBond[] cardinalBonds(IAtom focus, IBond[] bonds) final Point2d centerXy = focus.getPoint2d();
final IBond[] cardinal = new IBond[4];
for (final IBond bond : bonds) {
IAtom   other   = bond.getOther(focus);
Point2d otherXy = other.getPoint2d();
double deltaX = otherXy.x - centerXy.x;
double deltaY = otherXy.y - centerXy.y;
double mag = Math.sqrt(deltaX * deltaX + deltaY * deltaY);
deltaX /= mag;
deltaY /= mag;
double absDeltaX = Math.abs(deltaX);
double absDeltaY = Math.abs(deltaY);
if (absDeltaX < CARDINALITY_THRESHOLD
&& absDeltaY > CARDINALITY_THRESHOLD) {
cardinal[deltaY > 0 ? NORTH : SOUTH] = bond;
}
else if (absDeltaX > CARDINALITY_THRESHOLD
&& absDeltaY < CARDINALITY_THRESHOLD) {
cardinal[deltaX > 0 ? EAST : WEST] = bond;
}
else {
return null;
}
}
return cardinal;

