public static List<FileStatus> listStatusHelper(FileSystem fs, Path path, int depth, List<FileStatus> acc) throws IOException FileStatus[] fileStatusResults = fs.listStatus(path);
if (fileStatusResults == null) {
throw new IOException("Path does not exist: " + path);
}
for (FileStatus f : fileStatusResults) {
Path subPath = f.getPath();
if (!f.isDir()) {
acc.add(f);
} else {
if (depth > 1) {
listStatusHelper(fs, subPath, depth - 1, acc);
} else {
acc.add(f);
}
}
}
return acc;

public InputStream[] buildInputs( FileSystem srcFs, Path srcFile, FileStatus srcStat, FileSystem parityFs, Path parityFile, FileStatus parityStat, int stripeIdx, long offsetInBlock, List<Integer> erasedLocations, Set<Integer> locationsToNotRead, ErasureCode code) throws IOException InputStream[] inputs = new InputStream[codec.stripeLength +
codec.parityLength];
boolean redo = false;
do {
locationsToNotRead.clear();
List<Integer> locationsToRead =
code.locationsToReadForDecode(erasedLocations);
for (int i = 0; i < inputs.length; i++) {
boolean isErased = (erasedLocations.indexOf(i) != -1);
boolean shouldRead = (locationsToRead.indexOf(i) != -1);
try {
InputStream stm = null;
if (isErased || !shouldRead) {
if (isErased) {
LOG.info("Location " + i + " is erased, using zeros");
} else {
LOG.info("Location " + i + " need not be read, using zeros");
}
locationsToNotRead.add(i);
stm = new RaidUtils.ZeroInputStream(srcStat.getBlockSize() * (
(i < codec.parityLength) ?
stripeIdx * codec.parityLength + i :
stripeIdx * codec.stripeLength + i - codec.parityLength));
} else {
stm = buildOneInput(i, offsetInBlock,
srcFs, srcFile, srcStat,
parityFs, parityFile, parityStat);
}
inputs[i] = stm;
} catch (IOException e) {
if (e instanceof BlockMissingException || e instanceof ChecksumException) {
erasedLocations.add(i);
redo = true;
RaidUtils.closeStreams(inputs);
break;
} else {
throw e;
}
}
}
} while (redo);
assert(locationsToNotRead.size() == codec.parityLength);
return inputs;

