private EntryEventType getCQCEventTypeOrNull(EntryEventType eventType, EventFilter eventFilter, Data dataKey, Data dataNewValue, Data dataOldValue, String mapName) boolean newValueMatching = filteringStrategy.doFilter(eventFilter, dataKey, dataOldValue, dataNewValue,
eventType, mapName) != FilteringStrategy.FILTER_DOES_NOT_MATCH;
if (eventType == UPDATED) {
boolean oldValueMatching = filteringStrategy.doFilter(eventFilter, dataKey, null, dataOldValue,
EntryEventType.ADDED, mapName) != FilteringStrategy.FILTER_DOES_NOT_MATCH;
if (oldValueMatching) {
if (!newValueMatching) {
eventType = REMOVED;
}
} else {
if (newValueMatching) {
eventType = ADDED;
} else {
return null;
}
}
} else if (!newValueMatching) {
return null;
}
return eventType;

private boolean processQueryEventFilter(EventFilter filter, EntryEventType eventType, Data dataKey, Object oldValue, Object dataValue, String mapNameOrNull) Object testValue;
if (eventType == REMOVED || eventType == EVICTED || eventType == EXPIRED) {
testValue = oldValue;
} else {
testValue = dataValue;
}
return evaluateQueryEventFilter(filter, dataKey, testValue, mapNameOrNull);

@SuppressWarnings("checkstyle:npathcomplexity") @Override public int doFilter(EventFilter filter, Data dataKey, Object oldValue, Object dataValue, EntryEventType eventType, String mapNameOrNull) if (filter instanceof MapPartitionLostEventFilter) {
return FILTER_DOES_NOT_MATCH;
}
if (filter instanceof EventListenerFilter) {
if (!filter.eval(eventType.getType())) {
return FILTER_DOES_NOT_MATCH;
} else {
filter = ((EventListenerFilter) filter).getEventFilter();
}
}
if (filter instanceof TrueEventFilter) {
return eventType.getType();
}
if (filter instanceof QueryEventFilter) {
return processQueryEventFilter(filter, eventType, dataKey, oldValue, dataValue, mapNameOrNull)
? eventType.getType() : FILTER_DOES_NOT_MATCH;
}
if (filter instanceof EntryEventFilter) {
return processEntryEventFilter(filter, dataKey) ? eventType.getType() : FILTER_DOES_NOT_MATCH;
}
throw new IllegalArgumentException("Unknown EventFilter type = [" + filter.getClass().getCanonicalName() + "]");

