public void crawlDataset(InvDataset ds, CancelTask task, PrintWriter out, Object context, boolean release) boolean isCatRef = (ds instanceof InvCatalogRef);
if (filter != null && filter.skipAll(ds)) {
if (isCatRef && release) ((InvCatalogRef) ds).release();
