public Clustering<Model> run(Database database, Relation<V> relation) int dim_c = RelationUtil.dimensionality(relation);
if(dim_c < l) {
throw new IllegalStateException("Dimensionality of data < parameter l! " + "(" + dim_c + " < " + l + ")");
}
int k_c = Math.min(relation.size(), k_i * k);
List<ORCLUSCluster> clusters = initialSeeds(relation, k_c);
double beta = FastMath.exp(-FastMath.log(dim_c / (double) l) * FastMath.log(1 / alpha) / FastMath.log(k_c / (double) k));
IndefiniteProgress cprogress = LOG.isVerbose() ? new IndefiniteProgress("Current number of clusters:", LOG) : null;
while(k_c > k) {
assign(relation, clusters);
for(ORCLUSCluster cluster : clusters) {
if(cluster.objectIDs.size() > 0) {
cluster.basis = findBasis(relation, cluster, dim_c);
}
}
k_c = (int) Math.max(k, k_c * alpha);
dim_c = (int) Math.max(l, dim_c * beta);
merge(relation, clusters, k_c, dim_c, cprogress);
if(cprogress != null) {
cprogress.setProcessed(clusters.size(), LOG);
}
}
assign(relation, clusters);
LOG.setCompleted(cprogress);
Clustering<Model> r = new Clustering<>("ORCLUS clustering", "orclus-clustering");
for(ORCLUSCluster c : clusters) {
r.addToplevelCluster(new Cluster<Model>(c.objectIDs, ClusterModel.CLUSTER));
}
return r;

@Override protected Cluster<SubspaceModel> runDOC(Database database, Relation<V> relation, ArrayModifiableDBIDs S, int d, int n, int m, int r, int minClusterSize) long[] D = null;
DBIDVar dV = DBIDUtil.newVar();
FiniteProgress iprogress = LOG.isVerbose() ? new FiniteProgress("Iteration progress for current cluster", m * n, LOG) : null;
Random random = rnd.getSingleThreadedRandom();
DBIDArrayIter iter = S.iter();
outer: for(int i = 0; i < n; ++i) {
iter.seek(random.nextInt(S.size()));
for(int j = 0; j < m; ++j) {
DBIDs randomSet = DBIDUtil.randomSample(S, r, random);
long[] nD = BitsUtil.zero(d);
for(int k = 0; k < d; ++k) {
if(dimensionIsRelevant(k, relation, randomSet)) {
BitsUtil.setI(nD, k);
}
}
if(D == null || BitsUtil.cardinality(nD) > BitsUtil.cardinality(D)) {
D = nD;
dV.set(iter);
if(BitsUtil.cardinality(D) >= d_zero) {
if(iprogress != null) {
iprogress.setProcessed(iprogress.getTotal(), LOG);
}
break outer;
}
}
LOG.incrementProcessed(iprogress);
}
}
LOG.ensureCompleted(iprogress);
if(D == null || BitsUtil.cardinality(D) == 0) {
return null;
}
DBIDs C = findNeighbors(dV, D, S, relation);
return (C.size() >= minClusterSize) ? makeCluster(relation, C, D) : null;

public Clustering<SubspaceModel> run(Database database, Relation<V> relation) if(RelationUtil.dimensionality(relation) < l) {
throw new IllegalStateException("Dimensionality of data < parameter l! (" + RelationUtil.dimensionality(relation) + " < " + l + ")");
}
DistanceQuery<V> distFunc = database.getDistanceQuery(relation, SquaredEuclideanDistanceFunction.STATIC);
RangeQuery<V> rangeQuery = database.getRangeQuery(distFunc);
final Random random = rnd.getSingleThreadedRandom();
if(LOG.isVerbose()) {
LOG.verbose("1. Initialization phase...");
}
int sampleSize = Math.min(relation.size(), k_i * k);
DBIDs sampleSet = DBIDUtil.randomSample(relation.getDBIDs(), sampleSize, random);
int medoidSize = Math.min(relation.size(), m_i * k);
ArrayDBIDs medoids = greedy(distFunc, sampleSet, medoidSize, random);
if(LOG.isDebugging()) {
LOG.debugFine(new StringBuilder().append("sampleSize ").append(sampleSize).append('\n')
.append("sampleSet ").append(sampleSet).append('\n')
.append("medoidSize ").append(medoidSize).append('\n')
.append("m ").append(medoids).toString());
}
if(LOG.isVerbose()) {
LOG.verbose("2. Iterative phase...");
}
double bestObjective = Double.POSITIVE_INFINITY;
ArrayDBIDs m_best = null;
DBIDs m_bad = null;
ArrayDBIDs m_current = initialSet(medoids, k, random);
if(LOG.isDebugging()) {
LOG.debugFine(new StringBuilder().append("m_c ").append(m_current).toString());
}
IndefiniteProgress cprogress = LOG.isVerbose() ? new IndefiniteProgress("Current number of clusters:", LOG) : null;
ArrayList<PROCLUSCluster> clusters = null;
int loops = 0;
while(loops < 10) {
long[][] dimensions = findDimensions(m_current, relation, distFunc, rangeQuery);
clusters = assignPoints(m_current, dimensions, relation);
double objectiveFunction = evaluateClusters(clusters, dimensions, relation);
if(objectiveFunction < bestObjective) {
loops = 0;
bestObjective = objectiveFunction;
m_best = m_current;
m_bad = computeBadMedoids(m_current, clusters, (int) (relation.size() * 0.1 / k));
}
m_current = computeM_current(medoids, m_best, m_bad, random);
loops++;
if(cprogress != null) {
cprogress.setProcessed(clusters.size(), LOG);
}
}
LOG.setCompleted(cprogress);
if(LOG.isVerbose()) {
LOG.verbose("3. Refinement phase...");
}
List<Pair<double[], long[]>> dimensions = findDimensions(clusters, relation);
List<PROCLUSCluster> finalClusters = finalAssignment(dimensions, relation);
int numClusters = 1;
Clustering<SubspaceModel> result = new Clustering<>("ProClus clustering", "proclus-clustering");
for(PROCLUSCluster c : finalClusters) {
Cluster<SubspaceModel> cluster = new Cluster<>(c.objectIDs);
cluster.setModel(new SubspaceModel(new Subspace(c.getDimensions()), c.centroid));
cluster.setName("cluster_" + numClusters++);
result.addToplevelCluster(cluster);
}
return result;

protected Cluster<SubspaceModel> runDOC(Database database, Relation<V> relation, ArrayModifiableDBIDs S, final int d, int n, int m, int r, int minClusterSize) DBIDs C = null;
long[] D = null;
double quality = Double.NEGATIVE_INFINITY;
FiniteProgress iprogress = LOG.isVerbose() ? new FiniteProgress("Iteration progress for current cluster", m * n, LOG) : null;
Random random = rnd.getSingleThreadedRandom();
DBIDArrayIter iter = S.iter();
for(int i = 0; i < n; ++i) {
iter.seek(random.nextInt(S.size()));
for(int j = 0; j < m; ++j) {
DBIDs randomSet = DBIDUtil.randomSample(S, r, random);
long[] nD = BitsUtil.zero(d);
for(int k = 0; k < d; ++k) {
if(dimensionIsRelevant(k, relation, randomSet)) {
BitsUtil.setI(nD, k);
}
}
if(BitsUtil.cardinality(nD) > 0) {
DBIDs nC = findNeighbors(iter, nD, S, relation);
if(LOG.isDebuggingFiner()) {
LOG.finer("Testing a cluster candidate, |C| = " + nC.size() + ", |D| = " + BitsUtil.cardinality(nD));
}
if(nC.size() < minClusterSize) {
if(LOG.isDebuggingFiner()) {
LOG.finer("... but it's too small.");
}
continue;
}
double nQuality = computeClusterQuality(nC.size(), BitsUtil.cardinality(nD));
if(nQuality > quality) {
if(LOG.isDebuggingFiner()) {
LOG.finer("... and it's the best so far: " + nQuality + " vs. " + quality);
}
C = nC;
D = nD;
quality = nQuality;
}
else {
if(LOG.isDebuggingFiner()) {
LOG.finer("... but we already have a better one.");
}
}
}
LOG.incrementProcessed(iprogress);
}
}
LOG.ensureCompleted(iprogress);
return (C != null) ? makeCluster(relation, C, D) : null;

private void buildHierarchy(Relation<V> database, Clustering<SubspaceModel> clustering, List<Cluster<SubspaceModel>> clusters, int dimensionality) StringBuilder msg = LOG.isDebugging() ? new StringBuilder() : null;
final int db_dim = RelationUtil.dimensionality(database);
Hierarchy<Cluster<SubspaceModel>> hier = clustering.getClusterHierarchy();
for(int i = 0; i < clusters.size() - 1; i++) {
Cluster<SubspaceModel> c_i = clusters.get(i);
final Subspace s_i = c_i.getModel().getSubspace();
int subspaceDim_i = dimensionality - s_i.dimensionality();
NumberVector ci_centroid = ProjectedCentroid.make(s_i.getDimensions(), database, c_i.getIDs());
long[] pv1 = s_i.getDimensions();
for(int j = i + 1; j < clusters.size(); j++) {
Cluster<SubspaceModel> c_j = clusters.get(j);
final Subspace s_j = c_j.getModel().getSubspace();
int subspaceDim_j = dimensionality - s_j.dimensionality();
if(subspaceDim_i < subspaceDim_j) {
if(msg != null) {
msg.append("\n l_i=").append(subspaceDim_i).append(" pv_i=[").append(BitsUtil.toStringLow(s_i.getDimensions(), db_dim)).append(']')
.append("\n l_j=").append(subspaceDim_j).append(" pv_j=[").append(BitsUtil.toStringLow(s_j.getDimensions(), db_dim)).append(']');
}
if(s_j.dimensionality() == 0) {
if(hier.numParents(c_i) == 0) {
clustering.addChildCluster(c_j, c_i);
if(msg != null) {
msg.append("\n [").append(BitsUtil.toStringLow(s_j.getDimensions(), db_dim))
.append("] is parent of [").append(BitsUtil.toStringLow(s_i.getDimensions(), db_dim)).append(']');
}
}
}
else {
NumberVector cj_centroid = ProjectedCentroid.make(c_j.getModel().getDimensions(), database, c_j.getIDs());
long[] pv2 = s_j.getDimensions();
long[] commonPreferenceVector = BitsUtil.andCMin(pv1, pv2);
int subspaceDim = subspaceDimensionality(ci_centroid, cj_centroid, pv1, pv2, commonPreferenceVector);
double d = weightedDistance(ci_centroid, cj_centroid, commonPreferenceVector);
if(msg != null) {
msg.append("\n dist = ").append(subspaceDim);
}
if(subspaceDim == subspaceDim_j) {
if(msg != null) {
msg.append("\n d = ").append(d);
}
if(d <= 2 * epsilon) {
if(hier.numParents(c_i) == 0 || !isParent(database, c_j, hier.iterParents(c_i), db_dim)) {
clustering.addChildCluster(c_j, c_i);
if(msg != null) {
msg.append("\n [").append(BitsUtil.toStringLow(s_j.getDimensions(), db_dim))
.append("] is parent of [")
.append(BitsUtil.toStringLow(s_i.getDimensions(), db_dim)).append(']');
}
}
}
else {
throw new RuntimeException("Should never happen: d = " + d);
}
}
}
}
}
}
if(msg != null) {
LOG.debug(msg.toString());
}

public Clustering<Model> run(Database database, Relation<NumberVector> relation) Clustering<Model> ret = new Clustering<>("LMCLUS Clustering", "lmclus-clustering");
FiniteProgress progress = LOG.isVerbose() ? new FiniteProgress("Clustered objects", relation.size(), LOG) : null;
IndefiniteProgress cprogress = LOG.isVerbose() ? new IndefiniteProgress("Clusters found", LOG) : null;
ModifiableDBIDs unclustered = DBIDUtil.newHashSet(relation.getDBIDs());
Random r = rnd.getSingleThreadedRandom();
final int maxdim = Math.min(maxLMDim, RelationUtil.dimensionality(relation));
int cnum = 0;
while(unclustered.size() > minsize) {
DBIDs current = unclustered;
int lmDim = 1;
for(int k = 1; k <= maxdim; k++) {
while(true) {
Separation separation = findSeparation(relation, current, k, r);
if(separation.goodness <= sensitivityThreshold) {
break;
}
ModifiableDBIDs subset = DBIDUtil.newArray(current.size());
for(DBIDIter iter = current.iter(); iter.valid(); iter.advance()) {
if(deviation(minusEquals(relation.get(iter).toArray(), separation.originV), separation.basis) < separation.threshold) {
subset.add(iter);
}
}
if(subset.size() < minsize) {
break;
}
current = subset;
lmDim = k;
}
}
if(current.size() < minsize || current == unclustered) {
break;
}
final Cluster<Model> cluster = new Cluster<>(current);
cluster.setName("Cluster_" + lmDim + "d_" + cnum);
cnum++;
ret.addToplevelCluster(cluster);
unclustered.removeDBIDs(current);
if(progress != null) {
progress.setProcessed(relation.size() - unclustered.size(), LOG);
}
if(cprogress != null) {
cprogress.setProcessed(cnum, LOG);
}
}
if(unclustered.size() > 0) {
ret.addToplevelCluster(new Cluster<>(unclustered, true));
}
if(progress != null) {
progress.setProcessed(relation.size(), LOG);
progress.ensureCompleted(LOG);
}
LOG.setCompleted(cprogress);
return ret;

public Clustering<SubspaceModel> run(Relation<? extends NumberVector> relation) final int dimensionality = RelationUtil.dimensionality(relation);
StepProgress step = new StepProgress(2);
step.beginStep(1, "Identification of subspaces that contain clusters", LOG);
ArrayList<List<CLIQUESubspace>> dimensionToDenseSubspaces = new ArrayList<>(dimensionality);
List<CLIQUESubspace> denseSubspaces = findOneDimensionalDenseSubspaces(relation);
dimensionToDenseSubspaces.add(denseSubspaces);
if(LOG.isVerbose()) {
LOG.verbose("1-dimensional dense subspaces: " + denseSubspaces.size());
}
if(LOG.isDebugging()) {
for(CLIQUESubspace s : denseSubspaces) {
LOG.debug(s.toString());
}
}
for(int k = 2; k <= dimensionality && !denseSubspaces.isEmpty(); k++) {
denseSubspaces = findDenseSubspaces(relation, denseSubspaces);
assert (dimensionToDenseSubspaces.size() == k - 1);
dimensionToDenseSubspaces.add(denseSubspaces);
if(LOG.isVerbose()) {
LOG.verbose(k + "-dimensional dense subspaces: " + denseSubspaces.size());
}
if(LOG.isDebugging()) {
for(CLIQUESubspace s : denseSubspaces) {
LOG.debug(s.toString());
}
}
}
step.beginStep(2, "Identification of clusters", LOG);
Clustering<SubspaceModel> result = new Clustering<>("CLIQUE clustering", "clique-clustering");
for(int dim = 0; dim < dimensionToDenseSubspaces.size(); dim++) {
List<CLIQUESubspace> subspaces = dimensionToDenseSubspaces.get(dim);
List<Pair<Subspace, ModifiableDBIDs>> modelsAndClusters = determineClusters(subspaces);
if(LOG.isVerbose()) {
LOG.verbose((dim + 1) + "-dimensional clusters: " + modelsAndClusters.size());
}
for(Pair<Subspace, ModifiableDBIDs> modelAndCluster : modelsAndClusters) {
Cluster<SubspaceModel> newCluster = new Cluster<>(modelAndCluster.second);
newCluster.setModel(new SubspaceModel(modelAndCluster.first, Centroid.make(relation, modelAndCluster.second).getArrayRef()));
result.addToplevelCluster(newCluster);
}
}
return result;

private boolean isParent(Relation<V> relation, Cluster<SubspaceModel> parent, It<Cluster<SubspaceModel>> iter, int db_dim) Subspace s_p = parent.getModel().getSubspace();
NumberVector parent_centroid = ProjectedCentroid.make(s_p.getDimensions(), relation, parent.getIDs());
int subspaceDim_parent = db_dim - s_p.dimensionality();
for(; iter.valid(); iter.advance()) {
Cluster<SubspaceModel> child = iter.get();
Subspace s_c = child.getModel().getSubspace();
NumberVector child_centroid = ProjectedCentroid.make(s_c.getDimensions(), relation, child.getIDs());
long[] commonPreferenceVector = BitsUtil.andCMin(s_p.getDimensions(), s_c.getDimensions());
int subspaceDim = subspaceDimensionality(parent_centroid, child_centroid, s_p.getDimensions(), s_c.getDimensions(), commonPreferenceVector);
if(subspaceDim == subspaceDim_parent) {
return true;
}
}
return false;

private Clustering<SubspaceModel> computeClusters(Relation<V> database, DiSHClusterOrder clusterOrder) final int dimensionality = RelationUtil.dimensionality(database);
Object2ObjectOpenCustomHashMap<long[], List<ArrayModifiableDBIDs>> clustersMap = extractClusters(database, clusterOrder);
logClusterSizes("Step 1: extract clusters", dimensionality, clustersMap);
checkClusters(database, clustersMap);
logClusterSizes("Step 2: check clusters", dimensionality, clustersMap);
List<Cluster<SubspaceModel>> clusters = sortClusters(database, clustersMap);
if(LOG.isVerbose()) {
StringBuilder msg = new StringBuilder("Step 3: sort clusters");
for(Cluster<SubspaceModel> c : clusters) {
msg.append('\n').append(BitsUtil.toStringLow(c.getModel().getSubspace().getDimensions(), dimensionality)).append(" ids ").append(c.size());
}
LOG.verbose(msg.toString());
}
Clustering<SubspaceModel> clustering = new Clustering<>("DiSH clustering", "dish-clustering");
buildHierarchy(database, clustering, clusters, dimensionality);
if(LOG.isVerbose()) {
StringBuilder msg = new StringBuilder("Step 4: build hierarchy");
for(Cluster<SubspaceModel> c : clusters) {
msg.append('\n').append(BitsUtil.toStringLow(c.getModel().getSubspace().getDimensions(), dimensionality)).append(" ids ").append(c.size());
for(It<Cluster<SubspaceModel>> iter = clustering.getClusterHierarchy().iterParents(c); iter.valid(); iter.advance()) {
msg.append("\n   parent ").append(iter.get());
}
for(It<Cluster<SubspaceModel>> iter = clustering.getClusterHierarchy().iterChildren(c); iter.valid(); iter.advance()) {
msg.append("\n   child ").append(iter.get());
}
}
LOG.verbose(msg.toString());
}
for(Cluster<SubspaceModel> c : clusters) {
if(clustering.getClusterHierarchy().numParents(c) == 0) {
clustering.addToplevelCluster(c);
}
}
return clustering;

@Reference(authors = "D. Pelleg, A. Moore", title = "X-means: Extending K-means with Efficient Estimation on the Number of Clusters", booktitle = "Proc. 17th Int. Conf. on Machine Learning (ICML 2000)", url = "http: bibkey = "DBLP:conf/icml/PellegM00") public static <V extends NumberVector> double logLikelihood(Relation<V> relation, Clustering<? extends MeanModel> clustering, NumberVectorDistanceFunction<? super V> distanceFunction) List<? extends Cluster<? extends MeanModel>> clusters = clustering.getAllClusters();
final int m = clusters.size();
int n = 0;
int[] n_i = new int[m];
double d = 0.;
double[] d_i = new double[m];
Iterator<? extends Cluster<? extends MeanModel>> it = clusters.iterator();
for(int i = 0; it.hasNext(); ++i) {
Cluster<? extends MeanModel> cluster = it.next();
n += n_i[i] = cluster.size();
d += d_i[i] = varianceOfCluster(cluster, distanceFunction, relation);
}
if(n <= m) {
return Double.NEGATIVE_INFINITY;
}
final double logv = FastMath.log(d / (n - m));
final int dim = RelationUtil.dimensionality(relation);
double logLikelihood = 0.;
for(int i = 0; i < m; i++) {
logLikelihood += n_i[i] * FastMath.log(n_i[i])
- n_i[i] * .5 * MathUtil.LOGTWOPI
- n_i[i] * dim * .5 * logv
- (d_i[i] - m) * .5;
}
logLikelihood -= n * FastMath.log(n);
return logLikelihood;

