protected int findWhereKeyword(String sql) char[] chars = sql.toLowerCase().toCharArray();
char[] whereChars = "where".toCharArray();
int i = 0;
boolean inString = false;
int inWhere = 0;
while (i < chars.length) {
switch (chars[i]) {
case '\'':
inString = !inString;
break;
default:
if (!inString && chars[i] == whereChars[inWhere]) {
inWhere++;
if (inWhere == whereChars.length) {
return i;
}
} else {
inWhere = 0;
}
}
i++;
}
return -1;

private static String convertToValidJavaClassname(String inName) if (inName == null) return "_";
if (inName.startsWith("scriptdef_")) inName = inName.substring(10);
if (inName.equals("")) return "_";
StringBuilder output = new StringBuilder(inName.length());
boolean firstChar = true;
for (int i = 0; i < inName.length(); ++i) {
char ch = inName.charAt(i);
if (firstChar && !Character.isJavaIdentifierStart(ch)) {
ch = '_';
} else if (!firstChar
&& !(Character.isJavaIdentifierPart(ch) || ch == '.')) {
ch = '_';
}
firstChar = (ch == '.');
output.append(ch);
}
return output.toString();

private boolean isGetter(String name, CachedClass[] args) if (name == null || name.length() == 0 || args == null) return false;
if (args.length != 0) return false;
if (name.startsWith("get")) {
name = name.substring(3);
return isPropertyName(name);
} else if (name.startsWith("is")) {
name = name.substring(2);
return isPropertyName(name);
}
return false;

