private boolean isGoodBlockCandidate(Source source, BalancerDatanode target, BalancerBlock block) if (movedBlocks.contains(block)) {
return false;
}
if (block.isLocatedOnDatanode(target)) {
return false;
}
boolean goodBlock = false;
if (plan.cluster.isOnSameRack(source.getDatanode(), target.getDatanode())) {
goodBlock = true;
} else {
boolean notOnSameRack = true;
synchronized (block) {
for (BalancerDatanode loc : block.locations) {
if (plan.cluster.isOnSameRack(loc.datanode, target.datanode)) {
notOnSameRack = false;
break;
}
}
}
if (notOnSameRack) {
goodBlock = true;
} else {
for (BalancerDatanode loc : block.locations) {
if (loc != source &&
plan.cluster.isOnSameRack(loc.datanode, source.datanode)) {
goodBlock = true;
break;
}
}
}
}
return goodBlock;

public boolean moveAndDeleteRelativePath(String volume, String pathName) throws IOException volume = normalizePath(volume);
String newPathName =
format.format(new Date()) + "_" + uniqueId.getAndIncrement();
newPathName = TOBEDELETED + Path.SEPARATOR_CHAR + newPathName;
Path source = new Path(volume, pathName);
Path target = new Path(volume, newPathName);
try {
if (!localFileSystem.rename(source, target)) {
if (!localFileSystem.exists(source)) {
return false;
}
if (!localFileSystem.mkdirs(new Path(volume, TOBEDELETED))) {
throw new IOException("Cannot create " + TOBEDELETED + " under "
+ volume);
}
if (!localFileSystem.rename(source, target)) {
throw new IOException("Cannot rename " + source + " to "
+ target);
}
}
} catch (FileNotFoundException e) {
return false;
}
DeleteTask task = new DeleteTask(volume, pathName, newPathName);
execute(volume, task);
return true;

private void waitForMoveCompletion() boolean shouldWait;
int waitedIterations = 0;
do {
shouldWait = false;
for (BalancerDatanode target : plan.targets) {
if (!target.isPendingQEmpty()) {
shouldWait = true;
}
}
if (shouldWait) {
try {
if (waitedIterations > MAX_WAIT_ITERATIONS) {
for (BalancerDatanode target : plan.targets) {
target.killPending();
}
continue;
}
waitedIterations++;
Thread.sleep(blockMoveWaitTime);
} catch (InterruptedException ignored) {
}
}
} while (shouldWait);

public static void replaceFile(File src, File target) throws IOException if (!src.renameTo(target)) {
int retries = 5;
while (target.exists() && !target.delete() && retries-- >= 0) {
try {
Thread.sleep(1000);
} catch (InterruptedException e) {
throw new IOException("replaceFile interrupted.");
}
}
if (!src.renameTo(target)) {
throw new IOException("Unable to rename " + src +
" to " + target);
}
}

private long dispatchBlockMoves() throws InterruptedException long bytesLastMoved = bytesMoved.get();
Future<?>[] futures = new Future<?>[plan.sources.size()];
int i=0;
for (Source source : plan.sources) {
futures[i++] = dispatcherExecutor.submit(
source.new BlockMoveDispatcher(Util.now()));
}
for (Future<?> future : futures) {
try {
future.get();
} catch (ExecutionException e) {
LOG.warn("Dispatcher thread failed", e.getCause());
}
}
waitForMoveCompletion();
return bytesMoved.get()-bytesLastMoved;

