protected List<SparseItemset> frequentItemsetsSparse(List<SparseItemset> candidates, Relation<BitVector> relation, int needed, DBIDs ids, ArrayModifiableDBIDs survivors, int length) int begin = 0, end = candidates.size();
int[] scratchi = new int[length], iters = new int[length];
SparseItemset scratch = new SparseItemset(scratchi);
for(DBIDIter iditer = ids.iter(); iditer.valid(); iditer.advance()) {
BitVector bv = relation.get(iditer);
if(!initializeSearchItemset(bv, scratchi, iters)) {
continue;
}
int lives = 0;
while(begin < end) {
begin = binarySearch(candidates, scratch, begin, end);
if(begin > 0) {
candidates.get(begin).increaseSupport();
++lives;
}
else {
begin = (-begin) - 1;
}
if(begin >= end || !nextSearchItemset(bv, scratchi, iters)) {
break;
}
}
for(Itemset candidate : candidates) {
if(candidate.containedIn(bv)) {
candidate.increaseSupport();
++lives;
}
}
if(lives > length) {
survivors.add(iditer);
}
}
List<SparseItemset> frequent = new ArrayList<>(candidates.size());
for(Iterator<SparseItemset> iter = candidates.iterator(); iter.hasNext();) {
final SparseItemset candidate = iter.next();
if(candidate.getSupport() >= needed) {
frequent.add(candidate);
}
}
return frequent;

protected <T> List<List<T>> trivialPartition(List<T> objects, int minEntries, int maxEntries) final int size = objects.size();
final int numberPartitions = (int) Math.ceil(((double) size) / maxEntries);
List<List<T>> partitions = new ArrayList<>(numberPartitions);
int start = 0;
for(int pnum = 0; pnum < numberPartitions; pnum++) {
int end = (int) ((pnum + 1.) * size / numberPartitions);
if(pnum == numberPartitions - 1) {
end = size;
}
assert ((end - start) >= minEntries && (end - start) <= maxEntries);
partitions.add(objects.subList(start, end));
start = end;
}
return partitions;

protected DBIDs computeSubspace(int[] subspace, ArrayList<ArrayList<DBIDs>> ranges) HashSetModifiableDBIDs ids = DBIDUtil.newHashSet(ranges.get(subspace[0]).get(subspace[1]));
for(int i = 2, e = subspace.length - 1; i < e; i += 2) {
DBIDs current = ranges.get(subspace[i]).get(subspace[i + 1] - GENE_OFFSET);
ids.retainAll(current);
if(ids.isEmpty()) {
break;
}
}
return ids;

