@Override public StereoEncoder create(IAtomContainer container, int[][] graph) int n = container.getAtomCount();
BondMap map = new BondMap(n);
List<StereoEncoder> encoders = new ArrayList<StereoEncoder>(1);
for (IBond bond : container.bonds()) {
if (isDoubleBond(bond)) map.add(bond);
}
Set<IAtom> visited = new HashSet<IAtom>(n);
for (IAtom a : map.atoms()) {
List<IBond> bonds = map.bonds(a);
if (bonds.size() == 2) {
IAtom s = bonds.get(0).getOther(a);
IAtom e = bonds.get(1).getOther(a);
IAtom sParent = a;
IAtom eParent = a;
visited.add(a);
visited.add(s);
visited.add(e);
int size = 2;
while (s != null && map.cumulated(s)) {
IAtom p = map.bonds(s).get(0).getOther(s);
IAtom q = map.bonds(s).get(1).getOther(s);
sParent = s;
s = visited.add(p) ? p : visited.add(q) ? q : null;
size++;
}
while (e != null && map.cumulated(e)) {
IAtom p = map.bonds(e).get(0).getOther(e);
IAtom q = map.bonds(e).get(1).getOther(e);
eParent = e;
e = visited.add(p) ? p : visited.add(q) ? q : null;
size++;
}
if (s != null && e != null) {
if (isOdd(size)) {
StereoEncoder encoder = GeometricDoubleBondEncoderFactory.newEncoder(container, s, sParent, e,
eParent, graph);
if (encoder != null) {
encoders.add(encoder);
}
} else {
StereoEncoder encoder = axialEncoder(container, s, e);
if (encoder != null) {
encoders.add(encoder);
}
}
}
}
}
return encoders.isEmpty() ? StereoEncoder.EMPTY : new MultiStereoEncoder(encoders);

static Graph toBeamGraph(IAtomContainer ac, int flavour) throws CDKException int order = ac.getAtomCount();
GraphBuilder gb = GraphBuilder.create(order);
Map<IAtom, Integer> indices = Maps.newHashMapWithExpectedSize(order);
for (IAtom a : ac.atoms()) {
indices.put(a, indices.size());
gb.add(toBeamAtom(a, flavour));
}
for (IBond b : ac.bonds()) {
gb.add(toBeamEdge(b, flavour, indices));
}
if (SmiFlavor.isSet(flavour, SmiFlavor.Stereo)) {
for (IStereoElement se : ac.stereoElements()) {
if (SmiFlavor.isSet(flavour, SmiFlavor.StereoTetrahedral) &&
se instanceof ITetrahedralChirality) {
addTetrahedralConfiguration((ITetrahedralChirality) se, gb, indices);
} else if (SmiFlavor.isSet(flavour, SmiFlavor.StereoCisTrans) &&
se instanceof IDoubleBondStereochemistry) {
addGeometricConfiguration((IDoubleBondStereochemistry) se, flavour, gb, indices);
} else if (SmiFlavor.isSet(flavour, SmiFlavor.StereoExTetrahedral) &&
se instanceof ExtendedTetrahedral) {
addExtendedTetrahedralConfiguration((ExtendedTetrahedral) se, gb, indices);
} else if (SmiFlavor.isSet(flavour, SmiFlavor.StereoExCisTrans) &&
se instanceof ExtendedCisTrans) {
addExtendedCisTransConfig((ExtendedCisTrans) se, gb, indices, ac);
}
}
}
return gb.build();

List<IStereoElement> recognise(Set<Projection> projections) if (!projections.contains(Projection.Fischer))
return Collections.emptyList();
Map<IAtom,Integer> atomToIndex = new HashMap<IAtom, Integer>();
for (IAtom atom : container.atoms()) {
if (atom.getPoint2d() == null)
return Collections.emptyList();
atomToIndex.put(atom, atomToIndex.size());
}
RingSearch ringSearch = new RingSearch(container, graph);
final List<IStereoElement> elements = new ArrayList<IStereoElement>(5);
for (int v = 0; v < container.getAtomCount(); v++) {
IAtom    focus = container.getAtom(v);
Elements elem  = Elements.ofNumber(focus.getAtomicNumber());
if (elem != Carbon)
continue;
if (ringSearch.cyclic(v))
continue;
if (stereocenters.elementType(v) != Tetracoordinate)
continue;
if (!stereocenters.isStereocenter(v))
continue;
ITetrahedralChirality element = newTetrahedralCenter(focus,
neighbors(v, graph, bonds));
if (element == null)
continue;
IAtom east = element.getLigands()[EAST];
IAtom west = element.getLigands()[WEST];
if (!east.equals(focus) && !isTerminal(east, atomToIndex))
continue;
if (!west.equals(focus) && !isTerminal(west, atomToIndex))
continue;
elements.add(element);
}
return elements;

public AtomHashGenerator atomic() if (depth < 0) throw new IllegalArgumentException("no depth specified, use .depth(int)");
List<AtomEncoder> encoders = new ArrayList<AtomEncoder>();
for (AtomEncoder encoder : encoderSet) {
encoders.add(encoder);
}
encoders.addAll(this.customEncoders);
boolean suppress = suppression != AtomSuppression.unsuppressed();
AtomEncoder encoder = new ConjugatedAtomEncoder(encoders);
SeedGenerator seeds = new SeedGenerator(encoder, suppression);
AbstractAtomHashGenerator simple = suppress ? new SuppressedAtomHashGenerator(seeds, new Xorshift(),
makeStereoEncoderFactory(), suppression, depth) : new BasicAtomHashGenerator(seeds, new Xorshift(),
makeStereoEncoderFactory(), depth);
if (equivSetFinder != null) {
return new PerturbedAtomHashGenerator(seeds, simple, new Xorshift(), makeStereoEncoderFactory(),
equivSetFinder, suppression);
} else {
return simple;
}

private static GeometryEncoder encoder(IDoubleBondStereochemistry dbs, Map<IAtom, Integer> atomToIndex, int[][] graph) IBond db = dbs.getStereoBond();
int u = atomToIndex.get(db.getBegin());
int v = atomToIndex.get(db.getEnd());
IBond[] bs = dbs.getBonds();
int[] us = new int[2];
int[] vs = new int[2];
us[0] = atomToIndex.get(bs[0].getOther(db.getBegin()));
us[1] = graph[u].length == 2 ? u : findOther(graph[u], v, us[0]);
vs[0] = atomToIndex.get(bs[1].getOther(db.getEnd()));
vs[1] = graph[v].length == 2 ? v : findOther(graph[v], u, vs[0]);
int parity = dbs.getStereo() == OPPOSITE ? +1 : -1;
GeometricParity geomParity = GeometricParity.valueOf(parity);
PermutationParity permParity = new CombinedPermutationParity(us[1] == u ? BasicPermutationParity.IDENTITY
: new BasicPermutationParity(us), vs[1] == v ? BasicPermutationParity.IDENTITY
: new BasicPermutationParity(vs));
return new GeometryEncoder(new int[]{u, v}, permParity, geomParity);

@Override public void setAtom(int idx, IAtom atom) if (idx >= atomCount)
throw new IndexOutOfBoundsException("No atom at index: " + idx);
int aidx = indexOf(atom);
if (aidx >= 0)
throw new IllegalArgumentException("Atom already in container at index: " + idx);
final IAtom oldAtom = atoms[idx];
atoms[idx] = atom;
for (IBond bond : bonds()) {
for (int i = 0; i < bond.getAtomCount(); i++) {
if (oldAtom.equals(bond.getAtom(i))) {
bond.setAtom(atom, i);
}
}
}
for (ISingleElectron ec : singleElectrons()) {
if (oldAtom.equals(ec.getAtom()))
ec.setAtom(atom);
}
for (ILonePair lp : lonePairs()) {
if (oldAtom.equals(lp.getAtom()))
lp.setAtom(atom);
}
List<IStereoElement> oldStereo = null;
List<IStereoElement> newStereo = null;
for (IStereoElement se : stereoElements()) {
if (se.contains(oldAtom)) {
if (oldStereo == null) {
oldStereo = new ArrayList<>();
newStereo = new ArrayList<>();
}
oldStereo.add(se);
Map<IAtom, IAtom> amap = Collections.singletonMap(oldAtom, atom);
Map<IBond, IBond> bmap = Collections.emptyMap();
newStereo.add(se.map(amap, bmap));
}
}
if (oldStereo != null) {
stereoElements.removeAll(oldStereo);
stereoElements.addAll(newStereo);
}

private static int[] indexElements(Map<IAtom, Integer> map, IStereoElement[] elements, Type[] types, IAtomContainer container) int[] indices = new int[container.getAtomCount()];
int nElements = 0;
for (IStereoElement element : container.stereoElements()) {
if (element instanceof ITetrahedralChirality) {
ITetrahedralChirality tc = (ITetrahedralChirality) element;
int idx = map.get(tc.getChiralAtom());
elements[idx] = element;
types[idx] = Type.Tetrahedral;
indices[nElements++] = idx;
} else if (element instanceof IDoubleBondStereochemistry) {
IDoubleBondStereochemistry dbs = (IDoubleBondStereochemistry) element;
int idx1 = map.get(dbs.getStereoBond().getBegin());
int idx2 = map.get(dbs.getStereoBond().getEnd());
elements[idx2] = elements[idx1] = element;
types[idx1] = types[idx2] = Type.Geometric;
indices[nElements++] = idx1;
}
}
return Arrays.copyOf(indices, nElements);

static IAtomContainer apply(IAtomContainer container) int n = container.getAtomCount();
int[] valences = new int[n];
Map<IAtom, Integer> atomToIndex = Maps.newHashMapWithExpectedSize(n);
for (IAtom atom : container.atoms())
atomToIndex.put(atom, atomToIndex.size());
for (IBond bond : container.bonds()) {
int u = atomToIndex.get(bond.getBegin());
int v = atomToIndex.get(bond.getEnd());
int bondOrder = bond.getOrder().numeric();
valences[u] += bondOrder;
valences[v] += bondOrder;
}
for (int i = 0; i < n; i++) {
IAtom atom = container.getAtom(i);
Integer charge = atom.getFormalCharge();
Integer element = atom.getAtomicNumber();
if (element == null) continue;
charge = charge == null ? 0 : charge;
int explicit = valences[i];
if (atom.getValency() != null) {
atom.setImplicitHydrogenCount(atom.getValency() - explicit);
} else {
int implicit = implicitValence(element, charge, valences[i]);
atom.setImplicitHydrogenCount(implicit - explicit);
atom.setValency(implicit);
}
}
return container;

public static ModifiableHyperBoundingBox unionTolerant(SpatialComparable mbr1, SpatialComparable mbr2) if(mbr1 == null && mbr2 == null) {
return null;
}
if(mbr1 == null) {
return new ModifiableHyperBoundingBox(mbr2);
}
if(mbr2 == null) {
return new ModifiableHyperBoundingBox(mbr1);
}
return union(mbr1, mbr2);

private double preDistanceMBR(SpatialComparable mbr1, SpatialComparable mbr2, final int start, final int end) double agg = 0.;
for(int d = start; d < end; d++) {
double delta = mbr2.getMin(d) - mbr1.getMax(d);
delta = delta >= 0 ? delta : mbr1.getMin(d) - mbr2.getMax(d);
if(delta > 0.) {
agg += MathUtil.powi(delta, intp);
}
}
return agg;

public double maxDist(SpatialComparable mbr1, SpatialComparable mbr2) final int dim1 = mbr1.getDimensionality(), dim2 = mbr2.getDimensionality();
final int mindim = dim1 < dim2 ? dim1 : dim2;
double agg = 0.;
for(int d = 0; d < mindim; d++) {
double d1 = mbr1.getMax(d) - mbr2.getMin(d);
double d2 = mbr2.getMax(d) - mbr1.getMin(d);
double delta = d1 > d2 ? d1 : d2;
agg += delta * delta;
}
for(int d = mindim; d < dim1; d++) {
double d1 = Math.abs(mbr1.getMin(d)), d2 = Math.abs(mbr1.getMax(d));
double delta = d1 > d2 ? d1 : d2;
agg += delta * delta;
}
for(int d = mindim; d < dim2; d++) {
double d1 = Math.abs(mbr2.getMin(d)), d2 = Math.abs(mbr2.getMax(d));
double delta = d1 > d2 ? d1 : d2;
agg += delta * delta;
}
return FastMath.sqrt(agg);

private SplitSorting chooseMinimumOverlapSplit(int splitAxis, int minEntries, int maxEntries, boolean revert) if(splitAxis == -1) {
pastOverlap = Double.MAX_VALUE;
return null;
}
double optXVolume = Double.POSITIVE_INFINITY;
double optVolume = Double.POSITIVE_INFINITY;
SplitSorting optDistribution = null;
HyperBoundingBox[] optMBRs = null;
int[] entrySorting = new int[node.getNumEntries()];
for(int i = 0; i < entrySorting.length; i++) {
entrySorting[i] = i;
}
int[] lbSorting = Arrays.copyOf(entrySorting, entrySorting.length);
int[] ubSorting = Arrays.copyOf(entrySorting, entrySorting.length);
sortEntriesForDimension(splitAxis, entrySorting, entrySorting);
if(revert && maxEntries < node.getNumEntries() / 2) {
int[][] reverted = new int[2][node.getNumEntries()];
for(int i = 0; i < lbSorting.length; i++) {
reverted[0][reverted[0].length - 1 - i] = lbSorting[i];
reverted[1][reverted[1].length - 1 - i] = ubSorting[i];
}
for(int i = 0; i < lbSorting.length; i++) {
lbSorting[i] = reverted[0][i];
ubSorting[i] = reverted[1][i];
}
}
for(int i = 0; i < 2; i++) {
if(i == 0) {
entrySorting = lbSorting;
}
else {
entrySorting = ubSorting;
}
for(int limit = minEntries; limit <= maxEntries; limit++) {
HyperBoundingBox mbr1 = mbr(entrySorting, 0, limit);
HyperBoundingBox mbr2 = mbr(entrySorting, limit, entrySorting.length);
double xVolume = SpatialUtil.overlap(mbr1, mbr2);
if(xVolume < optXVolume) {
optXVolume = xVolume;
optDistribution = generateSplitSorting(entrySorting, limit);
optMBRs = new HyperBoundingBox[] { mbr1, mbr2 };
optVolume = Double.NaN;
}
else if(xVolume == optXVolume) {
double vol = SpatialUtil.volume(mbr1);
vol += SpatialUtil.volume(mbr2);
if(Double.isNaN(optVolume)) {
optVolume = SpatialUtil.volume(optMBRs[0]);
optVolume += SpatialUtil.volume(optMBRs[1]);
}
if(vol < optVolume) {
optXVolume = xVolume;
optVolume = vol;
optDistribution = generateSplitSorting(entrySorting, limit);
}
}
}
}
if(node.getEntry(0) instanceof LeafEntry || tree.get_max_overlap() >= 1) {
pastOverlap = Double.NaN;
return optDistribution;
}
switch(maxOverlapStrategy){
case DATA_OVERLAP:
pastOverlap = getRatioOfDataInIntersectionVolume(generateDistribution(optDistribution), optMBRs);
if(tree.get_max_overlap() < pastOverlap) {
LOG.finest(String.format(Locale.ENGLISH, "No %s split found%s; best data overlap was %.3f", (minEntries == tree.get_min_fanout() ? "minimum overlap" : "topological"), (maxEntries < node.getNumEntries() / 2 ? " in " + (revert ? "second" : "first") + " range" : ""), pastOverlap));
return null;
}
break;
case VOLUME_OVERLAP:
if(Double.isNaN(optVolume)) {
optVolume = SpatialUtil.volume(optMBRs[0]);
optVolume += SpatialUtil.volume(optMBRs[1]);
}
pastOverlap = optXVolume / optVolume;
if(tree.get_max_overlap() < pastOverlap) {
LOG.finest(String.format(Locale.ENGLISH, "No %s split found%s; best volume overlap was %.3f", (minEntries == tree.get_min_fanout() ? "minimum overlap" : "topological"), (maxEntries < node.getNumEntries() / 2 ? " in " + (revert ? "second" : "first") + " range" : ""), pastOverlap));
return null;
}
break;
}
return optDistribution;

private double getSurfaceSums4Sorting(int minEntries, int maxEntries, int[] entrySorting, int dim) double[] pqUBFirst = new double[dim];
Arrays.fill(pqUBFirst, Double.NEGATIVE_INFINITY);
List<Heap<DoubleIntPair>> pqUBSecond = new ArrayList<>(dim);
for(int i = 0; i < dim; i++) {
pqUBSecond.add(new TopBoundedHeap<DoubleIntPair>(maxEntries, Collections.reverseOrder()));
}
double[] pqLBFirst = new double[dim];
Arrays.fill(pqLBFirst, Double.POSITIVE_INFINITY);
List<Heap<DoubleIntPair>> pqLBSecond = new ArrayList<>(dim);
for(int i = 0; i < dim; i++) {
pqLBSecond.add(new TopBoundedHeap<DoubleIntPair>(maxEntries));
}
for(int index = 0; index < minEntries; index++) {
add2MBR(entrySorting, pqUBFirst, pqLBFirst, index);
}
HyperBoundingBox mbr1 = new HyperBoundingBox(pqLBFirst, pqUBFirst);
double[] minSecond = new double[dim];
double[] maxSecond = new double[dim];
Arrays.fill(maxSecond, Double.NEGATIVE_INFINITY);
Arrays.fill(minSecond, Double.POSITIVE_INFINITY);
assert entrySorting.length - maxEntries == minEntries;
for(int index = maxEntries; index < entrySorting.length; index++) {
add2MBR(entrySorting, maxSecond, minSecond, index);
}
for(int i = 0; i < dim; i++) {
pqLBSecond.get(i).add(new DoubleIntPair(minSecond[i], entrySorting.length));
pqUBSecond.get(i).add(new DoubleIntPair(maxSecond[i], entrySorting.length));
}
for(int index = minEntries; index < maxEntries; index++) {
add2MBR(entrySorting, pqUBSecond, pqLBSecond, index);
}
for(int i = 0; i < minSecond.length; i++) {
minSecond[i] = pqLBSecond.get(i).peek().first;
maxSecond[i] = pqUBSecond.get(i).peek().first;
}
ModifiableHyperBoundingBox mbr2 = new ModifiableHyperBoundingBox(minSecond, maxSecond);
double surfaceSum = SpatialUtil.perimeter(mbr1) + SpatialUtil.perimeter(mbr2);
for(int limit = minEntries; limit < maxEntries; limit++) {
add2MBR(entrySorting, pqUBFirst, pqLBFirst, limit);
removeFromMBR(pqUBSecond, pqLBSecond, limit, mbr2);
surfaceSum += SpatialUtil.perimeter(mbr1) + SpatialUtil.perimeter(mbr2);
}
return surfaceSum;

public static <E extends SpatialComparable, A> double[] unionFlatMBR(A data, ArrayAdapter<E, ? super A> getter) final int num = getter.size(data);
assert (num > 0) : "Cannot compute MBR of empty set.";
final int dim;
final double[] mbr;
{
final E first = getter.get(data, 0);
dim = first.getDimensionality();
mbr = new double[2 * dim];
for(int d = 0; d < dim; d++) {
mbr[d] = first.getMin(d);
mbr[dim + d] = first.getMax(d);
}
}
for(int i = 1; i < num; i++) {
E next = getter.get(data, i);
for(int d = 0; d < dim; d++) {
mbr[d] = Math.min(mbr[d], next.getMin(d));
mbr[dim + d] = Math.max(mbr[dim + d], next.getMax(d));
}
}
return mbr;

public ModifiableHyperBoundingBox computeMBR() E firstEntry = getEntry(0);
if(firstEntry == null) {
return null;
}
ModifiableHyperBoundingBox mbr = new ModifiableHyperBoundingBox(firstEntry);
for(int i = 1; i < numEntries; i++) {
mbr.extend(getEntry(i));
}
return mbr;

