public void checkParameterizables() LoggingConfiguration.setVerbose(Level.VERBOSE);
knownParameterizables = new ArrayList<>();
try {
Enumeration<URL> us = getClass().getClassLoader().getResources(ELKIServiceLoader.RESOURCE_PREFIX);
while(us.hasMoreElements()) {
URL u = us.nextElement();
if("file".equals(u.getProtocol())) {
for(String prop : new File(u.toURI()).list()) {
try {
knownParameterizables.add(Class.forName(prop));
}
catch(ClassNotFoundException e) {
LOG.warning("Service file name is not a class name: " + prop);
continue;
}
}
}
else if(("jar".equals(u.getProtocol()))) {
JarURLConnection con = (JarURLConnection) u.openConnection();
try (JarFile jar = con.getJarFile()) {
Enumeration<JarEntry> entries = jar.entries();
while(entries.hasMoreElements()) {
String prop = entries.nextElement().getName();
if(prop.startsWith(ELKIServiceLoader.RESOURCE_PREFIX)) {
prop = prop.substring(ELKIServiceLoader.RESOURCE_PREFIX.length());
}
else if(prop.startsWith(ELKIServiceLoader.FILENAME_PREFIX)) {
prop = prop.substring(ELKIServiceLoader.FILENAME_PREFIX.length());
}
else {
continue;
}
try {
knownParameterizables.add(Class.forName(prop));
}
catch(ClassNotFoundException e) {
LOG.warning("Service file name is not a class name: " + prop);
continue;
}
}
}
}
}
}
catch(IOException | URISyntaxException e) {
throw new AbortException("Error enumerating service folders.", e);
}
final String internal = de.lmu.ifi.dbs.elki.utilities.optionhandling.Parameterizer.class.getPackage().getName();
for(final Class<?> cls : ELKIServiceRegistry.findAllImplementations(Object.class, false, false)) {
if(cls.getName().startsWith(internal)) {
continue;
}
try {
State state = State.NO_CONSTRUCTOR;
state = checkV3Parameterization(cls, state);
if(state == State.ERROR) {
continue;
}
state = checkDefaultConstructor(cls, state);
if(state == State.ERROR) {
continue;
}
boolean expectedParameterizer = checkSupertypes(cls);
if(state == State.NO_CONSTRUCTOR && expectedParameterizer) {
LOG.verbose("Class " + cls.getName() +
" implements a parameterizable interface, but doesn't have a public and parameterless constructor!");
}
if(state == State.INSTANTIABLE && !expectedParameterizer) {
LOG.verbose("Class " + cls.getName() +
" has a parameterizer, but there is no service file for any of its interfaces.");
}
}
catch(NoClassDefFoundError e) {
LOG.verbose("Class discovered but not found: " + cls.getName() + " (missing: " + e.getMessage() + ")");
}
}

public final void splitByMask(AbstractNode<E> newNode, long[] assignment) assert (isLeaf() == newNode.isLeaf());
int dest = BitsUtil.nextSetBit(assignment, 0);
if(dest < 0) {
throw new AbortException("No bits set in splitting mask.");
}
int pos = dest;
while(pos < numEntries) {
if(BitsUtil.get(assignment, pos)) {
newNode.addEntry(getEntry(pos));
}
else {
entries[dest] = entries[pos];
dest++;
}
pos++;
}
final int rm = numEntries - dest;
while(dest < numEntries) {
entries[dest] = null;
dest++;
}
numEntries -= rm;

public static byte[] base64decode( String coded ) if ( null == coded )
return null;
byte[] src = coded.getBytes();
int len = src.length;
int dlen = len - (len/77);
dlen = (dlen >>> 2) + (dlen >>> 1);
int rem = 0;
if ( 61 == src[ len - 1 ] )
rem++;
if ( 61 == src[ len - 2 ] )
rem++;
dlen -= rem;
byte[] dst = new byte[ dlen ];
int pos = 0;
int dpos = 0;
int col = 0;
len -= 4;
while ( pos < len ) {
byte b0 = _base64de[ src[ pos++ ] ];
byte b1 = _base64de[ src[ pos++ ] ];
byte b2 = _base64de[ src[ pos++ ] ];
byte b3 = _base64de[ src[ pos++ ] ];
if ( B64INV == b0 || B64INV == b1 || B64INV == b2 || B64INV == b3 )
throw new RuntimeException( "Invalid character at or around position " + pos );
dst[ dpos++ ] = (byte) ((b0 << 2) | ((b1 >>> 4) & 0x03));
dst[ dpos++ ] = (byte) ((b1 << 4) | ((b2 >>> 2) & 0x0f));
dst[ dpos++ ] = (byte) ((b2 << 6) | (b3 & 0x3f));
col += 4;
if ( 76 == col ) {
if ( 10 != src[ pos++ ] )
throw new RuntimeException( "No linefeed found at position " + (pos - 1 ) );
col = 0;
}
}
byte b0 = _base64de[ src[ pos++ ] ];
byte b1 = _base64de[ src[ pos++ ] ];
byte b2 = _base64de[ src[ pos++ ] ];
byte b3 = _base64de[ src[ pos++ ] ];
if ( B64INV == b0 || B64INV == b1 || B64INV == b2 || B64INV == b3 )
throw new RuntimeException( "Invalid character at or around position " + pos );
dst[ dpos++ ] = (byte) ((b0 << 2) | ((b1 >>> 4) & 0x03));
if ( 2 == rem )
return dst;
dst[ dpos++ ] = (byte) ((b1 << 4) | ((b2 >>> 2) & 0x0f));
if ( 1 == rem )
return dst;
dst[ dpos++ ] = (byte) ((b2 << 6) | (b3 & 0x3f));
return dst;

public static String toHexString( byte[] b ) if ( null == b )
return null;
int len = b.length;
byte[] hex = new byte[ len << 1 ];
for ( int i = 0, j = 0; i < len; i++, j+=2 ) {
hex[ j ] = (byte) ((b[ i ] & 0xF0) >> 4);
hex[ j ] += 10 > hex[ j ] ? 48 : 87;
hex[ j + 1 ] = (byte) (b[ i ] & 0x0F);
hex[ j + 1 ] += 10 > hex[ j + 1 ] ? 48 : 87;
}
return new String( hex );

private static Key createDESKey(final byte[] bytes, final int offset) final byte[] keyBytes = new byte[7];
System.arraycopy(bytes, offset, keyBytes, 0, 7);
final byte[] material = new byte[8];
material[0] = keyBytes[0];
material[1] = (byte) (keyBytes[0] << 7 | (keyBytes[1] & 0xff) >>> 1);
material[2] = (byte) (keyBytes[1] << 6 | (keyBytes[2] & 0xff) >>> 2);
material[3] = (byte) (keyBytes[2] << 5 | (keyBytes[3] & 0xff) >>> 3);
material[4] = (byte) (keyBytes[3] << 4 | (keyBytes[4] & 0xff) >>> 4);
material[5] = (byte) (keyBytes[4] << 3 | (keyBytes[5] & 0xff) >>> 5);
material[6] = (byte) (keyBytes[5] << 2 | (keyBytes[6] & 0xff) >>> 6);
material[7] = (byte) (keyBytes[6] << 1);
oddParity(material);
return new SecretKeySpec(material, "DES");

