public static int[] getHeaderToViewPosition(JTextArea view, String header, int start, int end) validateView(view);
validateHeader(header);
validateStartEnd(start, end);
if (!isValidStartEndForLength(start, end, header.length())) {
return INVALID_POSITION;
}
int excessChars = 0;
int pos = 0;
while ((pos = header.indexOf(HttpHeader.CRLF, pos)) != -1 && pos < start) {
pos += 2;
++excessChars;
}
int len = view.getDocument().getLength();
int finalStartPos = start - excessChars;
if (finalStartPos > len) {
return INVALID_POSITION;
}
if (pos != -1) {
while ((pos = header.indexOf(HttpHeader.CRLF, pos)) != -1 && pos < end) {
pos += 2;
++excessChars;
}
}
int finalEndPos = end - excessChars;
if (finalEndPos > len) {
return INVALID_POSITION;
}
return new int[] { finalStartPos, finalEndPos };

protected char[] normalize(char[] path) throws URIException if (path == null) {
return null;
}
String normalized = new String(path);
if (normalized.startsWith("./")) {
normalized = normalized.substring(1);
} else if (normalized.startsWith("../")) {
normalized = normalized.substring(2);
} else if (normalized.startsWith("..")) {
normalized = normalized.substring(2);
}
int index = -1;
while ((index = normalized.indexOf("/./")) != -1) {
normalized = normalized.substring(0, index) + normalized.substring(index + 2);
}
if (normalized.endsWith("/.")) {
normalized = normalized.substring(0, normalized.length() - 1);
}
int startIndex = 0;
while ((index = normalized.indexOf("/../", startIndex)) != -1) {
int slashIndex = normalized.lastIndexOf('/', index - 1);
if (slashIndex >= 0) {
normalized = normalized.substring(0, slashIndex) + normalized.substring(index + 3);
} else {
startIndex = index + 3;
}
}
if (normalized.endsWith("/..")) {
int slashIndex = normalized.lastIndexOf('/', normalized.length() - 4);
if (slashIndex >= 0) {
normalized = normalized.substring(0, slashIndex + 1);
}
}
while ((index = normalized.indexOf("/../")) != -1) {
int slashIndex = normalized.lastIndexOf('/', index - 1);
if (slashIndex >= 0) {
break;
} else {
normalized = normalized.substring(index + 3);
}
}
if (normalized.endsWith("/..")) {
int slashIndex = normalized.lastIndexOf('/', normalized.length() - 4);
if (slashIndex < 0) {
normalized = "/";
}
}
return normalized.toCharArray();

