private double geoShiftGetXstart(Array lon, double inc) Index ilon = lon.getIndex();
int[] lonShape = lon.getShape();
IndexIterator lonIter = lon.getIndexIterator();
double xlon = 0.0;
LatLonPoint p0 = new LatLonPointImpl(0, lon.getFloat(ilon.set(0)));
LatLonPoint pN = new LatLonPointImpl(0, lon.getFloat(ilon.set(lonShape[0] - 1)));
xlon = p0.getLongitude();
while (lonIter.hasNext()) {
float l = lonIter.getFloatNext();
LatLonPoint pn = new LatLonPointImpl(0, l);
if (pn.getLongitude() < xlon) {
xlon = pn.getLongitude();
}
}
if (p0.getLongitude() == pN.getLongitude()) {
xlon = xlon - inc;
}
return xlon;

private float[] getData3(RandomAccessFile raf, Grib2Drs.Type3 gdrs) throws IOException int mvm = gdrs.missingValueManagement;
float mv = getMissingValue(gdrs);
float DD = (float) java.lang.Math.pow((double) 10, (double) gdrs.decimalScaleFactor);
float R = gdrs.referenceValue;
float EE = (float) java.lang.Math.pow(2.0, (double) gdrs.binaryScaleFactor);
float ref_val = R / DD;
int NG = gdrs.numberOfGroups;
if (NG == 0) {
return nGroups0(bitmapIndicator, ref_val, mv);
}
BitReader reader = new BitReader(raf, startPos + 5);
int ival1;
int ival2 = 0;
int minsd;
int os = gdrs.orderSpatial;
int nbitsd = gdrs.descriptorSpatial;
int sign;
nbitsd = nbitsd * 8;
if (nbitsd > 0) {
sign = (int) reader.bits2UInt(1);
ival1 = (int) reader.bits2UInt(nbitsd - 1);
if (sign == 1) {
ival1 = -ival1;
}
if (os == 2) {
sign = (int) reader.bits2UInt(1);
ival2 = (int) reader.bits2UInt(nbitsd - 1);
if (sign == 1) {
ival2 = -ival2;
}
}
sign = (int) reader.bits2UInt(1);
minsd = (int) reader.bits2UInt(nbitsd - 1);
if (sign == 1) {
minsd = -minsd;
}
} else {
float[] data = new float[totalNPoints];
for (int i = 0; i < totalNPoints; i++) {
data[i] = mv;
}
return data;
}
int[] X1 = new int[NG];
int nb = gdrs.numberOfBits;
if (nb != 0) {
reader.incrByte();
for (int i = 0; i < NG; i++) {
X1[i] = (int) reader.bits2UInt(nb);
}
}
int[] NB = new int[NG];
nb = gdrs.bitsGroupWidths;
if (nb != 0) {
reader.incrByte();
for (int i = 0; i < NG; i++) {
NB[i] = (int) reader.bits2UInt(nb);
}
}
int referenceGroupWidths = gdrs.referenceGroupWidths;
for (int i = 0; i < NG; i++) {
NB[i] += referenceGroupWidths;
}
int[] L = new int[NG];
int referenceGroupLength = gdrs.referenceGroupLength;
nb = gdrs.bitsScaledGroupLength;
int len_inc = gdrs.lengthIncrement;
if (nb != 0) {
reader.incrByte();
for (int i = 0; i < NG; i++) {
L[i] = (int) reader.bits2UInt(nb);
}
}
int totalL = 0;
for (int i = 0; i < NG; i++) {
L[i] = L[i] * len_inc + referenceGroupLength;
totalL += L[i];
}
totalL -= L[NG - 1];
totalL += gdrs.lengthLastGroup;
L[NG - 1] = gdrs.lengthLastGroup;
if (mvm != 0) {
if (totalL != totalNPoints) {
logger.warn("NPoints != gds.nPts: " + totalL + "!=" + totalNPoints);
float[] data = new float[totalNPoints];
for (int i = 0; i < totalNPoints; i++) {
data[i] = mv;
}
return data;
}
} else {
if (totalL != dataNPoints) {
logger.warn("NPoints != drs.nPts: " + totalL + "!=" + totalNPoints);
float[] data = new float[totalNPoints];
for (int i = 0; i < totalNPoints; i++) {
data[i] = mv;
}
return data;
}
}
float[] data = new float[totalNPoints];
int count = 0;
reader.incrByte();
int dataSize = 0;
boolean[] dataBitMap = null;
if (mvm == 0) {
for (int i = 0; i < NG; i++) {
if (NB[i] != 0) {
for (int j = 0; j < L[i]; j++) {
data[count++] = (int) reader.bits2UInt(NB[i]) + X1[i];
}
} else {
for (int j = 0; j < L[i]; j++) {
data[count++] = X1[i];
}
}
}
} else if (mvm == 1 || mvm == 2) {
dataBitMap = new boolean[totalNPoints];
dataSize = 0;
for (int i = 0; i < NG; i++) {
if (NB[i] != 0) {
int msng1 = bitsmv1[NB[i]];
int msng2 = msng1 - 1;
for (int j = 0; j < L[i]; j++) {
data[count] = (int) reader.bits2UInt(NB[i]);
if (data[count] == msng1 || mvm == 2 && data[count] == msng2) {
dataBitMap[count] = false;
} else {
dataBitMap[count] = true;
data[dataSize++] = data[count] + X1[i];
}
count++;
}
} else {
int msng1 = bitsmv1[gdrs.numberOfBits];
int msng2 = msng1 - 1;
if (X1[i] == msng1) {
for (int j = 0; j < L[i]; j++) {
dataBitMap[count++] = false;
}
} else if (mvm == 2 && X1[i] == msng2) {
for (int j = 0; j < L[i]; j++) {
dataBitMap[count++] = false;
}
} else {
for (int j = 0; j < L[i]; j++) {
dataBitMap[count] = true;
data[dataSize++] = X1[i];
count++;
}
}
}
}
}
if (os == 1) {
data[0] = ival1;
int itemp;
if (mvm == 0) {
itemp = totalNPoints;
} else {
itemp = dataSize;
}
for (int i = 1; i < itemp; i++) {
data[i] += minsd;
data[i] = data[i] + data[i - 1];
}
} else if (os == 2) {
data[0] = ival1;
data[1] = ival2;
int itemp;
if (mvm == 0) {
itemp = totalNPoints;
} else {
itemp = dataSize;
}
for (int i = 2; i < itemp; i++) {
data[i] += minsd;
data[i] = data[i] + (2 * data[i - 1]) - data[i - 2];
}
}
if (mvm == 0) {
for (int i = 0; i < data.length; i++) {
data[i] = (R + (data[i] * EE)) / DD;
}
} else if (mvm == 1 || mvm == 2) {
int count2 = 0;
float[] tmp = new float[totalNPoints];
for (int i = 0; i < data.length; i++) {
if (dataBitMap[i]) {
tmp[i] = (R + (data[count2++] * EE)) / DD;
} else {
tmp[i] = mv;
}
}
data = tmp;
}
if (bitmap != null) {
int idx = 0;
float[] tmp = new float[totalNPoints];
for (int i = 0; i < totalNPoints; i++) {
if (GribNumbers.testBitIsSet(bitmap[i / 8], i % 8)) {
tmp[i] = data[idx++];
} else {
tmp[i] = mv;
}
}
data = tmp;
}
return data;

private void updateObservedReplicaTimestamps(List<Entry<String, Long>> receivedLogicalTimestamps) final VectorClock received = toVectorClock(receivedLogicalTimestamps);
for (; ; ) {
final VectorClock currentClock = this.observedClock;
if (currentClock.isAfter(received)) {
break;
}
if (OBSERVED_TIMESTAMPS_UPDATER.compareAndSet(this, currentClock, received)) {
break;
}
}

private VectorClock toVectorClock(List<Entry<String, Long>> replicaLogicalTimestamps) final VectorClock timestamps = new VectorClock();
for (Entry<String, Long> replicaTimestamp : replicaLogicalTimestamps) {
timestamps.setReplicaTimestamp(replicaTimestamp.getKey(), replicaTimestamp.getValue());
}
return timestamps;

protected boolean setResult(Object result) for (; ; ) {
Object currentState = this.state;
if (isDoneState(currentState)) {
return false;
}
if (STATE.compareAndSet(this, currentState, result)) {
done();
notifyThreadsWaitingOnGet();
runAsynchronous((ExecutionCallbackNode) currentState, result);
break;
}
}
return true;

void requestExecution() for (;;) {
State currentState = state.get();
switch (currentState) {
case INACTIVE:
if (state.compareAndSet(State.INACTIVE, State.RUNNING)) {
scheduleExecution();
return;
}
break;
case RUNNING:
if (state.compareAndSet(State.RUNNING, State.REQUESTED)) {
return;
}
break;
default:
return;
}
}

public boolean isAfter(VectorClock other) boolean anyTimestampGreater = false;
for (Entry<String, Long> otherEntry : other.replicaTimestamps.entrySet()) {
final String replicaId = otherEntry.getKey();
final Long otherReplicaTimestamp = otherEntry.getValue();
final Long localReplicaTimestamp = this.getTimestampForReplica(replicaId);
if (localReplicaTimestamp == null || localReplicaTimestamp < otherReplicaTimestamp) {
return false;
} else if (localReplicaTimestamp > otherReplicaTimestamp) {
anyTimestampGreater = true;
}
}
return anyTimestampGreater || other.replicaTimestamps.size() < replicaTimestamps.size();

