final void addTaskAndWakeup(Runnable task) for (; ; ) {
NioThread localOwner = owner;
if (localOwner != null) {
localOwner.addTaskAndWakeup(task);
return;
}
TaskNode old = delayedTaskStack.get();
TaskNode update = new TaskNode(task, old);
if (delayedTaskStack.compareAndSet(old, update)) {
break;
}
}
NioThread localOwner = owner;
if (localOwner != null) {
restoreTasks(localOwner, delayedTaskStack.getAndSet(null), true);
}

final void setCallId(long newId) if (newId <= 0) {
throw new IllegalArgumentException(String.format("Attempted to set non-positive call ID %d on %s",
newId, this));
}
final long c = callId;
if (c > 0) {
throw new IllegalStateException(String.format(
"Attempt to overwrite the call ID of an active operation: current %d, requested %d. %s",
callId, newId, this));
}
if (!CALL_ID.compareAndSet(this, c, newId)) {
throw new IllegalStateException(String.format("Concurrent modification of call ID. Initially observed %d,"
+ " then attempted to set %d, then observed %d. %s", c, newId, callId, this));
}
onSetCallId(newId);

