boolean isCyclic(PartitionReplica[] oldReplicas, PartitionReplica[] newReplicas) for (int i = 0; i < oldReplicas.length; i++) {
final PartitionReplica oldAddress = oldReplicas[i];
final PartitionReplica newAddress = newReplicas[i];
if (oldAddress == null || newAddress == null || oldAddress.equals(newAddress)) {
continue;
}
if (isCyclic(oldReplicas, newReplicas, i)) {
return true;
}
}
return false;

private boolean authenticate(HttpPostCommand command, final String groupName, final String pass) throws UnsupportedEncodingException String decodedName = URLDecoder.decode(groupName, "UTF-8");
SecurityContext securityContext = textCommandService.getNode().getNodeExtension().getSecurityContext();
if (securityContext == null) {
final GroupConfig groupConfig = textCommandService.getNode().getConfig().getGroupConfig();
if (pass != null && !pass.isEmpty()) {
logger.fine("Password was provided but the Hazelcast Security is disabled.");
}
return groupConfig.getName().equals(decodedName);
}
if (pass == null) {
logger.fine("Empty password is not allowed when the Hazelcast Security is enabled.");
return false;
}
String decodedPass = URLDecoder.decode(pass, "UTF-8");
UsernamePasswordCredentials credentials = new UsernamePasswordCredentials(groupName, decodedPass);
try {
LoginContext lc = securityContext.createMemberLoginContext(credentials);
lc.login();
} catch (LoginException e) {
return false;
}
return true;

@Nonnull public static String escapeMetricNamePart(@Nonnull String namePart) int i = 0;
int l = namePart.length();
while (i < l) {
char ch = namePart.charAt(i);
if (ch == ',' || ch == '=' || ch == '\\') {
break;
}
i++;
}
if (i == l) {
return namePart;
}
StringBuilder sb = new StringBuilder(namePart.length() + 3);
sb.append(namePart, 0, i);
while (i < l) {
char ch = namePart.charAt(i++);
if (ch == ',' || ch == '=' || ch == '\\') {
sb.append('\\');
}
sb.append(ch);
}
return sb.toString();

