public synchronized void sendEvent(java.util.EventObject event) if (!hasListeners || !enabled)
return;
Object[] args = new Object[1];
args[0] = event;
ListIterator iter = listeners.listIterator();
while (iter.hasNext()) {
Object client = iter.next();
try {
method.invoke(client, args);
} catch (IllegalAccessException e) {
logger.error("ListenerManager IllegalAccessException", e);
iter.remove();
} catch (IllegalArgumentException e) {
logger.error("ListenerManager IllegalArgumentException", e);
iter.remove();
} catch (InvocationTargetException e) {
throw new RuntimeException(e.getCause());
}
}

public synchronized void sendEventExcludeSource(java.util.EventObject event) if (!hasListeners || !enabled)
return;
Object source = event.getSource();
Object[] args = new Object[1];
args[0] = event;
ListIterator iter = listeners.listIterator();
while (iter.hasNext()) {
Object client = iter.next();
if (client == source)
continue;
try {
method.invoke(client, args);
} catch (IllegalAccessException | InvocationTargetException | IllegalArgumentException e) {
e.printStackTrace();
if (e.getCause() != null)
e.getCause().printStackTrace();
logger.error("ListenerManager calling " + method + " threw exception ", e);
}
}

