@Override public File copy() throws IORuntimeException final File src = this.src;
final File dest = this.dest;
Assert.notNull(src, "Source File is null !");
if (false == src.exists()) {
throw new IORuntimeException("File not exist: " + src);
}
Assert.notNull(dest, "Destination File or directiory is null !");
if (FileUtil.equals(src, dest)) {
throw new IORuntimeException("Files '{}' and '{}' are equal", src, dest);
}
if (src.isDirectory()) {
if(dest.exists() && false == dest.isDirectory()) {
throw new IORuntimeException("Src is a directory but dest is a file!");
}
final File subDest = isCopyContentIfDir ? dest : FileUtil.mkdir(FileUtil.file(dest, src.getName()));
internalCopyDirContent(src, subDest);
} else {
internalCopyFile(src, dest);
}
return dest;

public static void move(File src, File dest, boolean isOverride) throws IORuntimeException if (false == src.exists()) {
throw new IORuntimeException("File not found: " + src);
}
if (src.isDirectory() && dest.isFile()) {
throw new IORuntimeException(StrUtil.format("Can not move directory [{}] to file [{}]", src, dest));
}
if (isOverride && dest.isFile()) {
dest.delete();
}
if (src.isFile() && dest.isDirectory()) {
dest = new File(dest, src.getName());
}
if (false == src.renameTo(dest)) {
try {
copy(src, dest, isOverride);
} catch (Exception e) {
throw new IORuntimeException(StrUtil.format("Move [{}] to [{}] failed!", src, dest), e);
}
del(src);
}

private void internalCopyFile(File src, File dest) throws IORuntimeException if (null != copyFilter && false == copyFilter.accept(src)) {
return;
}
if (dest.exists()) {
if(dest.isDirectory()) {
dest = new File(dest, src.getName());
}
if(dest.exists() && false == isOverride) {
return;
}
}else {
dest.getParentFile().mkdirs();
}
final ArrayList<CopyOption> optionList = new ArrayList<>(2);
if(isOverride) {
optionList.add(StandardCopyOption.REPLACE_EXISTING);
}
if(isCopyAttributes) {
optionList.add(StandardCopyOption.COPY_ATTRIBUTES);
}
try {
Files.copy(src.toPath(), dest.toPath(), optionList.toArray(new CopyOption[optionList.size()]));
} catch (IOException e) {
throw new IORuntimeException(e);
}

public File writeFromStream(InputStream in) throws IORuntimeException FileOutputStream out = null;
try {
out = new FileOutputStream(FileUtil.touch(file));
IoUtil.copy(in, out);
}catch (IOException e) {
throw new IORuntimeException(e);
} finally {
IoUtil.close(out);
}
return file;

private void internalCopyDirContent(File src, File dest) throws IORuntimeException if (null != copyFilter && false == copyFilter.accept(src)) {
return;
}
if (false == dest.exists()) {
dest.mkdirs();
} else if (false == dest.isDirectory()) {
throw new IORuntimeException(StrUtil.format("Src [{}] is a directory but dest [{}] is a file!", src.getPath(), dest.getPath()));
}
final String files[] = src.list();
File srcFile;
File destFile;
for (String file : files) {
srcFile = new File(src, file);
destFile = this.isOnlyCopyFile ? dest : new File(dest, file);
if (srcFile.isDirectory()) {
internalCopyDirContent(srcFile, destFile);
} else {
internalCopyFile(srcFile, destFile);
}
}

public static void convert(File srcImageFile, File destImageFile) Assert.notNull(srcImageFile);
Assert.notNull(destImageFile);
Assert.isFalse(srcImageFile.equals(destImageFile), "Src file is equals to dest file!");
final String srcExtName = FileUtil.extName(srcImageFile);
final String destExtName = FileUtil.extName(destImageFile);
if (StrUtil.equalsIgnoreCase(srcExtName, destExtName)) {
FileUtil.copy(srcImageFile, destImageFile, true);
}
ImageOutputStream imageOutputStream = null;
try {
imageOutputStream = getImageOutputStream(destImageFile);
convert(read(srcImageFile), destExtName, imageOutputStream, StrUtil.equalsIgnoreCase(IMAGE_TYPE_PNG, srcExtName));
} finally {
IoUtil.close(imageOutputStream);
}

