static void getRuns(Bidi bidi) if (bidi.runCount >= 0) {
return;
}
if (bidi.direction != Bidi.MIXED) {
getSingleRun(bidi, bidi.paraLevel);
} else  {
int length = bidi.length, limit;
byte[] levels = bidi.levels;
int i, runCount;
byte level = -1;
limit = bidi.trailingWSStart;
runCount = 0;
for (i = 0; i < limit; ++i) {
if (levels[i] != level) {
++runCount;
level = levels[i];
}
}
if (runCount == 1 && limit == length) {
getSingleRun(bidi, levels[0]);
} else  {
BidiRun[] runs;
int runIndex, start;
byte minLevel = Bidi.MAX_EXPLICIT_LEVEL + 1;
byte maxLevel=0;
if (limit < length) {
++runCount;
}
bidi.getRunsMemory(runCount);
runs = bidi.runsMemory;
runIndex = 0;
i = 0;
do {
start = i;
level = levels[i];
if (level < minLevel) {
minLevel = level;
}
if (level > maxLevel) {
maxLevel = level;
}
while (++i < limit && levels[i] == level) {}
runs[runIndex] = new BidiRun(start, i - start, level);
++runIndex;
} while (i < limit);
if (limit < length) {
runs[runIndex] = new BidiRun(limit, length - limit, bidi.paraLevel);
if (bidi.paraLevel < minLevel) {
minLevel = bidi.paraLevel;
}
}
bidi.runs = runs;
bidi.runCount = runCount;
reorderLine(bidi, minLevel, maxLevel);
limit = 0;
for (i = 0; i < runCount; ++i) {
runs[i].level = levels[runs[i].start];
limit = (runs[i].limit += limit);
}
if (runIndex < runCount) {
int trailingRun = ((bidi.paraLevel & 1) != 0)? 0 : runIndex;
runs[trailingRun].level = bidi.paraLevel;
}
}
}
if (bidi.insertPoints.size > 0) {
Bidi.Point point;
int runIndex, ip;
for (ip = 0; ip < bidi.insertPoints.size; ip++) {
point = bidi.insertPoints.points[ip];
runIndex = getRunFromLogicalIndex(bidi, point.pos);
bidi.runs[runIndex].insertRemove |= point.flag;
}
}
if (bidi.controlCount > 0) {
int runIndex, ic;
char c;
for (ic = 0; ic < bidi.length; ic++) {
c = bidi.text[ic];
if (Bidi.IsBidiControlChar(c)) {
runIndex = getRunFromLogicalIndex(bidi, ic);
bidi.runs[runIndex].insertRemove--;
}
}
}

static Runnable composeWithExceptions(Runnable a, Runnable b) return new Runnable() {
@Override
public void run() {
try {
a.run();
}
catch (Throwable e1) {
try {
b.run();
}
catch (Throwable e2) {
try {
e1.addSuppressed(e2);
} catch (Throwable ignore) {}
}
throw e1;
}
b.run();
}
};

private static void doSort(double[] a, int left, int right, double[] work, int workBase, int workLen) if (right - left < QUICKSORT_THRESHOLD) {
sort(a, left, right, true);
return;
}
int[] run = new int[MAX_RUN_COUNT + 1];
int count = 0; run[0] = left;
for (int k = left; k < right; run[count] = k) {
if (a[k] < a[k + 1]) {
while (++k <= right && a[k - 1] <= a[k]);
} else if (a[k] > a[k + 1]) {
while (++k <= right && a[k - 1] >= a[k]);
for (int lo = run[count] - 1, hi = k; ++lo < --hi; ) {
double t = a[lo]; a[lo] = a[hi]; a[hi] = t;
}
} else {
for (int m = MAX_RUN_LENGTH; ++k <= right && a[k - 1] == a[k]; ) {
if (--m == 0) {
sort(a, left, right, true);
return;
}
}
}
if (++count == MAX_RUN_COUNT) {
sort(a, left, right, true);
return;
}
}
if (run[count] == right++) {
run[++count] = right;
} else if (count == 1) {
return;
}
byte odd = 0;
for (int n = 1; (n <<= 1) < count; odd ^= 1);
double[] b;
int ao, bo;
int blen = right - left;
if (work == null || workLen < blen || workBase + blen > work.length) {
work = new double[blen];
workBase = 0;
}
if (odd == 0) {
System.arraycopy(a, left, work, workBase, blen);
b = a;
bo = 0;
a = work;
ao = workBase - left;
} else {
b = work;
ao = 0;
bo = workBase - left;
}
for (int last; count > 1; count = last) {
for (int k = (last = 0) + 2; k <= count; k += 2) {
int hi = run[k], mi = run[k - 1];
for (int i = run[k - 2], p = i, q = mi; i < hi; ++i) {
if (q >= hi || p < mi && a[p + ao] <= a[q + ao]) {
b[i + bo] = a[p++ + ao];
} else {
b[i + bo] = a[q++ + ao];
}
}
run[++last] = hi;
}
if ((count & 1) != 0) {
for (int i = right, lo = run[count - 1]; --i >= lo;
b[i + bo] = a[i + ao]
);
run[++last] = right;
}
double[] t = a; a = b; b = t;
int o = ao; ao = bo; bo = o;
}

