static Vector2d newAtomAnnotationVector(IAtom atom, List<IBond> bonds, List<Vector2d> auxVectors) final List<Vector2d> vectors = new ArrayList<Vector2d>(bonds.size());
for (IBond bond : bonds)
vectors.add(VecmathUtil.newUnitVector(atom, bond));
if (vectors.size() == 0) {
if (auxVectors.size() == 0) return new Vector2d(0, -1);
if (auxVectors.size() == 1) return VecmathUtil.negate(auxVectors.get(0));
return VecmathUtil.newVectorInLargestGap(auxVectors);
} else if (vectors.size() == 1) {
if (auxVectors.size() == 0) return VecmathUtil.negate(vectors.get(0));
vectors.addAll(auxVectors);
return VecmathUtil.newVectorInLargestGap(vectors);
} else if (vectors.size() == 2 && auxVectors.size() == 0) {
Vector2d combined = VecmathUtil.sum(vectors.get(0), vectors.get(1));
if (vectors.get(0).angle(vectors.get(1)) < Math.toRadians(65))
combined.negate();
else if ((!isPlainBond(bonds.get(0)) || !isPlainBond(bonds.get(1)))
&& !(isWedged(bonds.get(0)) && isWedged(bonds.get(1)))) combined.negate();
combined.normalize();
if (Double.isNaN(combined.length())) return VecmathUtil.newVectorInLargestGap(vectors);
return combined;
} else {
if (vectors.size() == 3 && auxVectors.size() == 0) {
List<Vector2d> plainVectors = new ArrayList<Vector2d>();
List<Vector2d> wedgeVectors = new ArrayList<Vector2d>();
for (IBond bond : bonds) {
if (isPlainBond(bond)) plainVectors.add(VecmathUtil.newUnitVector(atom, bond));
if (isWedged(bond)) wedgeVectors.add(VecmathUtil.newUnitVector(atom, bond));
}
if (plainVectors.size() == 2) {
return VecmathUtil.sum(plainVectors.get(0), plainVectors.get(1));
} else if (plainVectors.size() + wedgeVectors.size() == 2) {
plainVectors.addAll(wedgeVectors);
return VecmathUtil.sum(plainVectors.get(0), plainVectors.get(1));
}
}
if (auxVectors.size() > 0) vectors.addAll(auxVectors);
return VecmathUtil.newVectorInLargestGap(vectors);
}

static Vector2d getNearestVector(final Vector2d reference, final List<Vector2d> vectors) if (vectors.isEmpty()) throw new IllegalArgumentException("No vectors provided");
Vector2d closest = vectors.get(0);
double maxProd = reference.dot(closest);
for (int i = 1; i < vectors.size(); i++) {
double newProd = reference.dot(vectors.get(i));
if (newProd > maxProd) {
maxProd = newProd;
closest = vectors.get(i);
}
}
return closest;

static Vector2d average(final Collection<Vector2d> vectors) final Vector2d average = new Vector2d(0, 0);
for (final Vector2d vector : vectors) {
average.add(vector);
}
average.scale(1d / vectors.size());
return average;

void placeConnectedRings(IRingSet rs, IRing ring, int handleType, double bondLength) final IRingSet connectedRings = rs.getConnectedRings(ring);
for (IAtomContainer container : connectedRings.atomContainers()) {
final IRing connectedRing = (IRing) container;
if (!connectedRing.getFlag(CDKConstants.ISPLACED)) {
final IAtomContainer sharedAtoms = AtomContainerManipulator.getIntersection(ring, connectedRing);
final int numSharedAtoms = sharedAtoms.getAtomCount();
logger.debug("placeConnectedRings-> connectedRing: " + (ring.toString()));
if ((numSharedAtoms == 2 && handleType == FUSED) ||
(numSharedAtoms == 1 && handleType == SPIRO) ||
(numSharedAtoms > 2  && handleType == BRIDGED)) {
final Point2d sharedAtomsCenter = GeometryUtil.get2DCenter(sharedAtoms);
final Point2d oldRingCenter = GeometryUtil.get2DCenter(ring);
final Vector2d tempVector = (new Vector2d(sharedAtomsCenter));
final Vector2d newRingCenterVector = new Vector2d(tempVector);
newRingCenterVector.sub(new Vector2d(oldRingCenter));
if (Math.abs(newRingCenterVector.x) < 0.001 && Math.abs(newRingCenterVector.y) < 0.001) {
IAtomContainer terminalOnly = molecule.getBuilder().newInstance(IAtomContainer.class);
for (IAtom atom : ring.atoms()) {
if (ring.getConnectedBondsCount(atom) == 1)
terminalOnly.addAtom(atom);
}
if (terminalOnly.getAtomCount() == 2) {
newRingCenterVector.set(GeometryUtil.get2DCenter(terminalOnly));
newRingCenterVector.sub(oldRingCenter);
connectedRing.setProperty(RingPlacer.SNAP_HINT, true);
}
else {
Vector2d vec = new Vector2d(0, 1);
double   bestLen = -Double.MAX_VALUE;
for (int i = 0; i < 12; i++) {
Vector2d orth = new Vector2d(-vec.y, vec.x);
orth.normalize();
double min = Double.MAX_VALUE, max = -Double.MAX_VALUE;
for (IAtom atom : sharedAtoms.atoms()) {
double s = orth.dot(new Vector2d(atom.getPoint2d()));
if (s < min)
min = s;
if (s > max)
max = s;
}
double len = max - min;
if (len > bestLen) {
bestLen = len;
newRingCenterVector.set(vec);
}
rotate(vec, RAD_30);
}
}
}
final Vector2d oldRingCenterVector = new Vector2d(newRingCenterVector);
logger.debug("placeConnectedRing -> tempVector: " + tempVector + ", tempVector.length: "
+ tempVector.length());
logger.debug("placeConnectedRing -> bondCenter: " + sharedAtomsCenter);
logger.debug("placeConnectedRing -> oldRingCenterVector.length(): " + oldRingCenterVector.length());
logger.debug("placeConnectedRing -> newRingCenterVector.length(): " + newRingCenterVector.length());
final Point2d tempPoint = new Point2d(sharedAtomsCenter);
tempPoint.add(newRingCenterVector);
placeRing(connectedRing, sharedAtoms, sharedAtomsCenter, newRingCenterVector, bondLength);
connectedRing.setFlag(CDKConstants.ISPLACED, true);
placeConnectedRings(rs, connectedRing, handleType, bondLength);
}
}
}

DecompIterator decomposeIterator(double from, double to, MolecularFormulaRange boundaries) init();
if (to < 0d || from < 0d)
throw new IllegalArgumentException("Expect positive mass for decomposition: [" + from + ", " + to + "]");
if (to < from) throw new IllegalArgumentException("Negative range given: [" + from + ", " + to + "]");
final int[] minValues = new int[weights.size()];
final int[] boundsarray = new int[weights.size()];
double cfrom = from, cto = to;
Arrays.fill(boundsarray, Integer.MAX_VALUE);
if (boundaries != null) {
for (int i = 0; i < boundsarray.length; i++) {
IIsotope el = weights.get(i).getOwner();
int max = boundaries.getIsotopeCountMax(el);
int min = boundaries.getIsotopeCountMin(el);
if (min >= 0 || max >= 0) {
boundsarray[i] = max - min;
minValues[i] = min;
if (minValues[i] > 0) {
final double reduceWeightBy = weights.get(i).getMass() * min;
cfrom -= reduceWeightBy;
cto -= reduceWeightBy;
}
}
}
}
final int[] minmax = new int[2];
integerBound(cfrom, cto, minmax);
final int deviation = minmax[1] - minmax[0];
if ((1 << (ERTs.length - 1)) <= deviation) {
calcERT(deviation);
}
final int[][][] ERTs = this.ERTs;
int[][] currentERT;
if (deviation == 0) currentERT = ERTs[0];
else currentERT = ERTs[32 - Integer.numberOfLeadingZeros(deviation)];
return new DecompIterator(currentERT, minmax[0], minmax[1], from, to, minValues, boundsarray, weights);

public Vector getSpinVector(double theta, double phi) Vector spinvector = new Vector(3);
spinvector.vector[0] = Math.sin(theta) * Math.cos(phi);
spinvector.vector[1] = Math.sin(theta) * Math.sin(phi);
spinvector.vector[2] = Math.cos(phi);
