@Override public double getFinishedPercentage() if (done) return 1d;
final int[] lastDecomposition = this.lastDecomposition;
if (lastDecomposition == null) return 0;
double result = 0.0;
double remainingPerc = 1.0;
for (int i = lastDecomposition.length - 1; i >= 0; i--) {
double max = mfRange.getIsotopeCountMax(decomposer.weights.get(i).getOwner());
if (i > 0)
max += 1.0;
result += remainingPerc * ((double) lastDecomposition[i] / max);
remainingPerc /= max;
}
return result;

public static Point3d[] zmatrixToCartesian(double[] distances, int[] first_atoms, double[] angles, int[] second_atoms, double[] dihedrals, int[] third_atoms) Point3d[] cartesianCoords = new Point3d[distances.length];
for (int index = 0; index < distances.length; index++) {
if (index == 0) {
cartesianCoords[index] = new Point3d(0d, 0d, 0d);
} else if (index == 1) {
cartesianCoords[index] = new Point3d(distances[1], 0d, 0d);
} else if (index == 2) {
cartesianCoords[index] = new Point3d(-Math.cos((angles[2] / 180) * Math.PI) * distances[2]
+ distances[1], Math.sin((angles[2] / 180) * Math.PI) * distances[2], 0d);
if (first_atoms[index] == 0) cartesianCoords[index].x = (cartesianCoords[index].x - distances[1]) * -1;
} else {
Vector3d cd = new Vector3d();
cd.sub(cartesianCoords[third_atoms[index]], cartesianCoords[second_atoms[index]]);
Vector3d bc = new Vector3d();
bc.sub(cartesianCoords[second_atoms[index]], cartesianCoords[first_atoms[index]]);
Vector3d n1 = new Vector3d();
n1.cross(cd, bc);
Vector3d n2 = rotate(n1, bc, -dihedrals[index]);
Vector3d ba = rotate(bc, n2, -angles[index]);
ba.normalize();
ba.scale(distances[index]);
Point3d result = new Point3d();
result.add(cartesianCoords[first_atoms[index]], ba);
cartesianCoords[index] = result;
}
}
return cartesianCoords;

public CLIQUESubspace join(CLIQUESubspace other, double all, double tau) long[] dimensions = joinLastDimensions(other);
if(dimensions == null) {
return null;
}
CLIQUESubspace s = new CLIQUESubspace(dimensions);
for(CLIQUEUnit u1 : this.denseUnits) {
for(CLIQUEUnit u2 : other.denseUnits) {
CLIQUEUnit u = u1.join(u2, all, tau);
if(u != null) {
s.addDenseUnit(u);
}
}
}
if(s.denseUnits.isEmpty()) {
return null;
}
return s;

private double manhattanSegmentalDistance(NumberVector o1, double[] o2, long[] dimensions) double result = 0;
int card = 0;
for(int d = BitsUtil.nextSetBit(dimensions, 0); d >= 0; d = BitsUtil.nextSetBit(dimensions, d + 1)) {
result += Math.abs(o1.doubleValue(d) - o2[d]);
++card;
}
return result / card;

public String dimensonsToString(String sep) StringBuilder result = new StringBuilder(100).append('[');
for(int dim = BitsUtil.nextSetBit(dimensions, 0); dim >= 0; dim = BitsUtil.nextSetBit(dimensions, dim + 1)) {
result.append(dim + 1).append(sep);
}
if(result.length() > sep.length()) {
result.setLength(result.length() - sep.length());
}
return result.append(']').toString();

private double evaluateClusters(ArrayList<PROCLUSCluster> clusters, long[][] dimensions, Relation<V> database) double result = 0;
for(int i = 0; i < dimensions.length; i++) {
PROCLUSCluster c_i = clusters.get(i);
double[] centroid_i = c_i.centroid;
long[] dims_i = dimensions[i];
double w_i = 0;
for(int d = BitsUtil.nextSetBit(dims_i, 0); d >= 0; d = BitsUtil.nextSetBit(dims_i, d + 1)) {
w_i += avgDistance(centroid_i, c_i.objectIDs, database, d);
}
w_i /= dimensions.length;
result += c_i.objectIDs.size() * w_i;
}
return result / database.size();

protected CLIQUEUnit join(CLIQUEUnit other, double all, double tau) if(other.dimensionality() != this.dimensionality()) {
return null;
}
int e = dims.length - 1;
if(!checkDimensions(other, e)) {
return null;
}
if(dims[e] >= other.dims[e]) {
return null;
}
HashSetModifiableDBIDs resultIDs = DBIDUtil.newHashSet(this.ids);
resultIDs.retainAll(other.ids);
if(resultIDs.size() / all < tau) {
return null;
}
return new CLIQUEUnit(this, other.dims[e], other.bounds[e << 1], other.bounds[(e << 1) + 1], resultIDs);

@Override public double distance(NumberVector v1, NumberVector v2) if(v1.getDimensionality() != v2.getDimensionality()) {
throw new IllegalArgumentException("Different dimensionality of FeatureVectors\n  " + "first argument: " + v1 + "\n  " + "second argument: " + v2);
}
double sqrDist = 0;
for(int d = BitsUtil.nextSetBit(dimensions, 0); d >= 0; d = BitsUtil.nextSetBit(dimensions, d + 1)) {
final double delta = v1.doubleValue(d) - v2.doubleValue(d);
sqrDist += delta * delta;
}
return FastMath.sqrt(sqrDist);

