private double getCovalentRadius(String symbol, IBond.Order maxBondOrder) double radiusTarget = 0;
if (symbol.equals("F")) {
radiusTarget = 0.64;
} else if (symbol.equals("Cl")) {
radiusTarget = 0.99;
} else if (symbol.equals("Br")) {
radiusTarget = 1.14;
} else if (symbol.equals("I")) {
radiusTarget = 1.33;
} else if (symbol.equals("H")) {
radiusTarget = 0.30;
} else if (symbol.equals("C")) {
if (maxBondOrder == IBond.Order.SINGLE) {
radiusTarget = 0.77;
} else if (maxBondOrder == IBond.Order.DOUBLE) {
radiusTarget = 0.67;
} else {
radiusTarget = 0.60;
}
} else if (symbol.equals("O")) {
if (maxBondOrder == IBond.Order.SINGLE) {
radiusTarget = 0.66;
