public static BufferedImage loadPGM( InputStream inputStream , BufferedImage storage ) throws IOException DataInputStream in = new DataInputStream(inputStream);
readLine(in);
String line = readLine(in);
while( line.charAt(0) == '#')
line = readLine(in);
