for( int y = 0; y < h; y++ ) {
for( int x = 0; x < w; x++ ) {
gray[indexOut++] =  data[indexIn++];
}
}
}
if( useFailSafe ) {
int indexIn = 0;
for( int y = 0; y < h; y++ ) {
for( int x = 0; x < w; x++ ) {
int gray = data[indexIn++] & 0xFF;
storage.setRGB(x, y, gray << 16 | gray << 8 | gray );
