@Override public void process() locations.reset();
descriptions.reset();
int stepBlockPixelsX = pixelsPerCell *stepBlock;
int stepBlockPixelsY = pixelsPerCell *stepBlock;
int maxY = derivX.height - pixelsPerCell * cellsPerBlockY + 1;
int maxX = derivX.width - pixelsPerCell * cellsPerBlockX + 1;
for (int y = 0; y < maxY; y += stepBlockPixelsY ) {
for (int x = 0; x < maxX; x += stepBlockPixelsX ) {
TupleDesc_F64 d = descriptions.grow();
Arrays.fill(d.value,0);
histogram = d.value;
for (int cellRow = 0; cellRow < cellsPerBlockY; cellRow++) {
int blockPixelRow = cellRow* pixelsPerCell;
for (int cellCol = 0; cellCol < cellsPerBlockX; cellCol++) {
int blockPixelCol = cellCol* pixelsPerCell;
computeCellHistogram(x+blockPixelCol, y+blockPixelRow, cellCol, cellRow);
}
}
DescribeSiftCommon.normalizeDescriptor(d,0.2);
locations.grow().set(x,y);
}
}

void computeCellHistograms() int width = cellCols* pixelsPerCell;
int height = cellRows* pixelsPerCell;
float angleBinSize = GrlConstants.F_PI/orientationBins;
int indexCell = 0;
for (int i = 0; i < height; i += pixelsPerCell) {
for (int j = 0; j < width; j += pixelsPerCell, indexCell++ ) {
Cell c = cells[indexCell];
c.reset();
for (int k = 0; k < pixelsPerCell; k++) {
int indexPixel = (i+k)*derivX.width+j;
for (int l = 0; l < pixelsPerCell; l++, indexPixel++ ) {
float pixelDX = this.derivX.data[indexPixel];
float pixelDY = this.derivY.data[indexPixel];
float angle = UtilAngle.atanSafe(pixelDY,pixelDX) + GrlConstants.F_PId2;
float magnitude = (float)Math.sqrt(pixelDX*pixelDX + pixelDY*pixelDY);
float findex0 = angle/angleBinSize;
int index0 = (int)findex0;
float weight1 = findex0-index0;
index0 %= orientationBins;
int index1 = (index0+1)%orientationBins;
c.histogram[index0] += magnitude*(1.0f-weight1);
c.histogram[index1] += magnitude*weight1;
}
}
}
}

protected void constructE( Point3D_F64 e2 , Point3D_F64 e3 ) E.zero();
for( int i = 0; i < 3; i++ ) {
for( int j = 0; j < 3; j++ ) {
for( int k = 0; k < 3; k++ ) {
int row = 9*i + 3*j + k;
int col1 = j*3 + i;
int col2 = k*3 + i + 9;
E.data[row*18 + col1 ] = e3.getIdx(k);
E.data[row*18 + col2 ] = -e2.getIdx(j);
}
}
}

protected void computeWeightBlockPixels() int rows = cellsPerBlockY*pixelsPerCell;
int cols = cellsPerBlockX*pixelsPerCell;
weights = new double[ rows*cols ];
double offsetRow=0,offsetCol=0;
int radiusRow=rows/2,radiusCol=cols/2;
if( rows%2 == 0 ) {
offsetRow = 0.5;
}
if( cols%2 == 0 ) {
offsetCol = 0.5;
}
int index = 0;
for (int row = 0; row < rows; row++) {
double drow = row-radiusRow+offsetRow;
double pdfRow = UtilGaussian.computePDF(0, radiusRow, drow);
for (int col = 0; col < cols; col++) {
double dcol = col-radiusCol+offsetCol;
double pdfCol = UtilGaussian.computePDF(0, radiusCol, dcol);
weights[index++] = pdfCol*pdfRow;
}
}
double max = 0;
for (int i = 0; i < weights.length; i++) {
if( weights[i] > max ) {
max = weights[i];
}
}
for (int i = 0; i < weights.length; i++) {
weights[i] /= max;
}

protected static void constructM(List<Point2D_F64> obsPts, DMatrixRMaj alphas, DMatrixRMaj M) int N = obsPts.size();
M.reshape(3*alphas.numCols,2*N,false);
for( int i = 0; i < N; i++ ) {
Point2D_F64 p2 = obsPts.get(i);
int row = i*2;
for( int j = 0; j < alphas.numCols; j++ ) {
int col = j*3;
double alpha = alphas.unsafe_get(i, j);
M.unsafe_set(col, row, alpha);
M.unsafe_set(col + 1, row, 0);
M.unsafe_set(col + 2, row, -alpha * p2.x);
M.unsafe_set(col    , row + 1, 0);
M.unsafe_set(col + 1, row + 1, alpha);
M.unsafe_set(col + 2, row + 1, -alpha * p2.y);
}
}

void growCellArray(int imageWidth, int imageHeight) cellCols = imageWidth/ pixelsPerCell;
cellRows = imageHeight/ pixelsPerCell;
if( cellRows*cellCols > cells.length ) {
Cell[] a = new Cell[cellCols*cellRows];
System.arraycopy(cells,0,a,0,cells.length);
for (int i = cells.length; i < a.length; i++) {
a[i] = new Cell();
a[i].histogram = new float[ orientationBins ];
}
cells = a;
}

@Override public void process() locations.reset();
descriptions.reset();
growCellArray(derivX.width, derivX.height);
computeCellHistograms();
int cellRowMax = (cellRows - (cellsPerBlockY -1));
int cellColMax = (cellCols - (cellsPerBlockX -1));
for (int i = 0; i < cellRowMax; i += stepBlock) {
for (int j = 0; j < cellColMax; j += stepBlock) {
computeDescriptor(i,j);
}
}

protected void findBitCounts(GrayF32 gray , double threshold ) ThresholdImageOps.threshold(gray,binaryInner,(float)threshold,true);
Arrays.fill(counts, 0);
for (int row = 0; row < gridWidth; row++) {
int y0 = row * binaryInner.width / gridWidth + 2;
int y1 = (row + 1) * binaryInner.width / gridWidth - 2;
for (int col = 0; col < gridWidth; col++) {
int x0 = col * binaryInner.width / gridWidth + 2;
int x1 = (col + 1) * binaryInner.width / gridWidth - 2;
int total = 0;
for (int i = y0; i < y1; i++) {
int index = i * binaryInner.width + x0;
for (int j = x0; j < x1; j++) {
total += binaryInner.data[index++];
}
}
counts[row * gridWidth + col] = total;
}
}

public void normalizeDepths( DMatrixRMaj depths ) for (int row = 0; row < depths.numRows; row++) {
int idx = row*depths.numCols;
double sum = 0;
for (int col = 0; col < depths.numCols; col++) {
double v = depths.data[idx++];
sum += v*v;
}
double norm = Math.sqrt(sum)/depths.numCols;
idx = row*depths.numCols;
for (int j = 0; j < depths.numCols; j++) {
depths.data[idx++] /= norm;
}
}
for (int col = 0; col < depths.numCols; col++) {
double norm = 0;
for (int row = 0; row < depths.numRows; row++) {
double v = depths.get(row,col);
norm += v*v;
}
norm = Math.sqrt(norm);
for (int row = 0; row < depths.numRows; row++) {
depths.data[depths.getIndex(row,col)] /= norm;
}
}

private void computeFeatureMask(int numModules, int[] alignment, boolean hasVersion) markSquare(0,0,9);
markRectangle(numModules-8,0,9,8);
markRectangle(0,numModules-8,8,9);
markRectangle(8,6,1,numModules-8-8);
markRectangle(6,8,numModules-8-8,1);
if( hasVersion ) {
markRectangle(numModules-11,0,6,3);
markRectangle(0,numModules-11,3,6);
}
for (int i = 0; i < alignment.length; i++) {
int row = alignment[i];
for (int j = 0; j < alignment.length; j++) {
if( i == 0 & j == 0 )
continue;
if( i == alignment.length-1 & j == 0)
continue;
if( i == 0 & j == alignment.length-1)
continue;
int col = alignment[j];
markSquare(row-2,col-2,5);
}
}

