public static double pdf(double val, double loc, double scale, double shape) val = (val - loc) / scale;
if(shape != 0.) {
val = -FastMath.log(1 - shape * val) / shape;
}
double f = 1. + FastMath.exp(-val);
return FastMath.exp(-val * (1 - shape)) / (scale * f * f);

public static double pdf(double val, double loc, double scale, double shape) if(!(val < Double.POSITIVE_INFINITY && val > Double.NEGATIVE_INFINITY)) {
return val == val ? 0. : Double.NaN;
}
val = (val - loc) / scale;
double e = FastMath.exp(-val);
double f = 1. + e;
return e < Double.POSITIVE_INFINITY ? shape * e / (scale * FastMath.pow(f, shape + 1.)) : 0.;

public static double quantile(double val, double loc, double scale, double shape) if(shape == 0.) {
return loc - scale * FastMath.log((1 - val) / val);
}
return loc + scale * (1 - FastMath.pow((1 - val) / val, shape)) / shape;

public static double cdf(double val, double loc, double scale, double shape) val = (val - loc) / scale;
if(shape != 0.) {
final double tmp = 1 - shape * val;
if(tmp < 1e-15) {
return (shape < 0) ? 0 : 1;
}
val = -FastMath.log(tmp) / shape;
}
return 1. / (1. + FastMath.exp(-val));

public static double logpdf(double val, double shape, double location, double scale) if(val < location) {
return Double.NEGATIVE_INFINITY;
}
val = (val - location) / scale;
final double lval = FastMath.log(val);
if(lval == Double.POSITIVE_INFINITY) {
return Double.NEGATIVE_INFINITY;
}
return FastMath.log(shape / scale) + (shape - 1.) * lval
- 2. * FastMath.log1p(FastMath.exp(lval * shape));

public static double logpdf(double val, double loc, double scale) val = Math.abs((val - loc) / scale);
double f = 1.0 + FastMath.exp(-val);
return -val - FastMath.log(scale * f * f);

public static double pdf(double val, double shape, double location, double scale) if(val < location) {
return 0;
}
val = (val - location) / scale;
double f = shape / scale * FastMath.pow(val, shape - 1.);
if(f == Double.POSITIVE_INFINITY) {
return 0;
}
double d = 1. + FastMath.pow(val, shape);
return f / (d * d);

public static double pdf(double val, double loc, double scale) val = Math.abs((val - loc) / scale);
double e = FastMath.exp(-val);
double f = 1.0 + e;
return e / (scale * f * f);

public static long calculateExpirationWithDelay(long timeInMillis, long delayMillis, boolean backup) checkNotNegative(timeInMillis, "timeInMillis can't be negative");
if (backup) {
long delayedTime = timeInMillis + delayMillis;
if (delayedTime < 0) {
return Long.MAX_VALUE;
} else {
return delayedTime;
}
}
return timeInMillis;

