public void addDirectoryScan(String dirName, String suffix, String regexpPatternString, String subdirsS, String olderS, Object auxInfo) CompositeMFileFilter filters = new CompositeMFileFilter();
if (null != regexpPatternString)
filters.addIncludeFilter(new RegExpMatchOnName(regexpPatternString));
else if (suffix != null)
filters.addIncludeFilter(new WildcardMatchOnPath("*" + suffix + "$"));
if (olderS != null) {
try {
TimeDuration tu = new TimeDuration(olderS);
filters.addAndFilter(new LastModifiedLimit((long) (1000 * tu.getValueInSeconds())));
} catch (Exception e) {
logger.error(collectionName + ": Invalid time unit for olderThan = {}", olderS);
}
}
boolean wantSubdirs = true;
if ((subdirsS != null) && subdirsS.equalsIgnoreCase("false"))
wantSubdirs = false;
CollectionConfig mc = new CollectionConfig(dirName, dirName, wantSubdirs, filters, auxInfo);
StringBuilder sb = new StringBuilder(dirName);
if (wantSubdirs)
sb.append("**/");
if (null != regexpPatternString)
sb.append(regexpPatternString);
else if (suffix != null)
sb.append(suffix);
else
sb.append("noFilter");
collectionName = sb.toString();
scanList.add(mc);

protected Service readService(Element s) String name = s.getAttributeValue("name");
String typeS = s.getAttributeValue("serviceType");
String serviceBase = s.getAttributeValue("base");
String suffix = s.getAttributeValue("suffix");
String desc = s.getAttributeValue("desc");
String accessType = s.getAttributeValue("accessType");
ServiceType type = ServiceType.getServiceTypeIgnoreCase(typeS);
if (type == null) {
errlog.format(" non-standard service type = '%s'%n", typeS);
logger.debug(" non-standard service type = '{}'", typeS);
}
else {
if (desc == null) {
desc = type.getDescription();
}
if (accessType == null) {
accessType = type.getAccessType();
}
}
List<Property> properties = null;
List<Element> propertyList = s.getChildren("property", Catalog.defNS);
for (Element e : propertyList) {
if (properties == null) {
properties = new ArrayList<>();
}
properties.add(readProperty(e));
}
List<Service> services = null;
java.util.List<Element> serviceList = s.getChildren("service", Catalog.defNS);
for (Element e : serviceList) {
if (services == null) {
services = new ArrayList<>();
}
services.add(readService(e));
}
Service result = new Service(name, serviceBase, typeS, desc, suffix, services, properties, accessType);
serviceMap.put(name, result);
return result;

public boolean enhanceNeeded(Set<Enhance> want) throws IOException if (want == null) return false;
for (Enhance mode : want) {
if (!this.enhanceMode.contains(mode)) return true;
}
return false;

static private CoordSysBuilderIF enhance(NetcdfDataset ds, Set<Enhance> mode, CancelTask cancelTask) throws IOException if (mode == null) {
mode = EnumSet.noneOf(Enhance.class);
}
CoordSysBuilderIF builder = null;
if (mode.contains(Enhance.CoordSystems) && !ds.enhanceMode.contains(Enhance.CoordSystems)) {
builder = ucar.nc2.dataset.CoordSysBuilder.factory(ds, cancelTask);
builder.augmentDataset(ds, cancelTask);
ds.convUsed = builder.getConventionUsed();
}
if ((mode.contains(Enhance.ConvertEnums) && !ds.enhanceMode.contains(Enhance.ConvertEnums))
|| (mode.contains(Enhance.ConvertUnsigned) && !ds.enhanceMode.contains(Enhance.ConvertUnsigned))
|| (mode.contains(Enhance.ApplyScaleOffset) && !ds.enhanceMode.contains(Enhance.ApplyScaleOffset))
|| (mode.contains(Enhance.ConvertMissing) && !ds.enhanceMode.contains(Enhance.ConvertMissing))) {
for (Variable v : ds.getVariables()) {
VariableEnhanced ve = (VariableEnhanced) v;
ve.enhance(mode);
if ((cancelTask != null) && cancelTask.isCancel()) return null;
}
}
if (builder != null) {
if (mode.contains(Enhance.IncompleteCoordSystems)) {
ds.enhanceMode.add(Enhance.IncompleteCoordSystems);
builder.buildCoordinateSystems(ds);
ds.enhanceMode.remove(Enhance.IncompleteCoordSystems);
} else {
builder.buildCoordinateSystems(ds);
}
}
ds.finish();
ds.enhanceMode.addAll(mode);
return builder;

