public static List<Sgroup> copy(Collection<Sgroup> sgroups, Map<? extends IChemObject, ? extends IChemObject> replace) if (sgroups == null) return null;
Map<Sgroup, Sgroup> sgroupMap = new HashMap<>();
for (Sgroup sgroup : sgroups)
sgroupMap.put(sgroup, new Sgroup());
for (Map.Entry<Sgroup, Sgroup> e : sgroupMap.entrySet()) {
Sgroup orgSgroup = e.getKey();
Sgroup cpySgroup = e.getValue();
cpySgroup.setType(orgSgroup.getType());
for (IAtom atom : orgSgroup.getAtoms())
cpySgroup.addAtom(get(replace, atom));
for (IBond bond : orgSgroup.getBonds())
cpySgroup.addBond(get(replace, bond));
for (Sgroup parent : orgSgroup.getParents())
cpySgroup.addParent(sgroupMap.get(parent));
for (SgroupKey key : SgroupKey.values()) {
switch (key) {
case CtabParentAtomList: {
Collection<IAtom> orgVal = orgSgroup.getValue(key);
if (orgVal != null) {
List<IAtom> cpyVal = new ArrayList<>();
for (IAtom atom : orgVal)
cpyVal.add(get(replace, atom));
cpySgroup.putValue(key, cpyVal);
}
}
break;
case CtabBracket: {
Collection<SgroupBracket> orgVals = orgSgroup.getValue(key);
if (orgVals != null) {
for (SgroupBracket bracket : orgVals)
cpySgroup.addBracket(new SgroupBracket(bracket));
}
}
break;
default:
Object val = orgSgroup.getValue(key);
if (val != null)
cpySgroup.putValue(key, val);
break;
}
}
}
return new ArrayList<>(sgroupMap.values());

public List<Integer> matchOccurence(int maxAttachments) List<Integer> validValues = new ArrayList<Integer>();
for (int val = 0; val <= maxAttachments; val++) {
boolean addVal = false;
StringTokenizer st = new StringTokenizer(occurrence, ",");
while (st.hasMoreTokens() && !addVal) {
String cond = st.nextToken().trim().replaceAll(" ", "");
if (match("^\\d+$", cond)) {
if (Integer.valueOf(cond) == val) addVal = true;
}
if (match("^\\d+-\\d+$", cond)) {
int from = Integer.valueOf(cond.substring(0, cond.indexOf('-')));
int to = Integer.valueOf(cond.substring(cond.indexOf('-') + 1, cond.length()));
if (val >= from && val <= to) {
addVal = true;
}
}
if (match("^>\\d+$", cond)) {
int n = Integer.valueOf(cond.substring(cond.indexOf('>') + 1, cond.length()));
if (val > n) {
addVal = true;
}
}
if (match("^<\\d+$", cond)) {
int n = Integer.valueOf(cond.substring(cond.indexOf('<') + 1, cond.length()));
if (val < n) {
addVal = true;
}
}
if (addVal) {
validValues.add(val);
}
}
}
return validValues;

@Override public boolean matches(IAtom atom) boolean val = false;
boolean matchesLeft = left.matches(atom);
if (right != null) {
if ("and".equals(operator) && matchesLeft) {
boolean matchesRight = right.matches(atom);
val = matchesLeft && matchesRight;
} else if ("or".equals(operator)) {
boolean matchesRight = right.matches(atom);
val = matchesLeft || matchesRight;
}
} else {
if ("not".equals(operator)) {
val = (!matchesLeft);
} else {
val = matchesLeft;
}
}
return val;

@Deprecated @Override public boolean getFlag(int flagType) boolean val = false;
boolean leftFlag = left.getFlag(flagType);
if (right != null) {
if ("and".equals(operator) && leftFlag) {
boolean rightFlag = right.getFlag(flagType);
val = leftFlag && rightFlag;
} else if ("or".equals(operator)) {
boolean rightFlag = right.getFlag(flagType);
val = leftFlag || rightFlag;
}
} else {
if ("not".equals(operator)) {
val = (!leftFlag);
} else {
val = leftFlag;
}
}
return val;

private void assignCxSmilesInfo(IChemObjectBuilder bldr, IChemObject chemObj, List<IAtom> atoms, Map<IAtom, IAtomContainer> atomToMol, CxSmilesState cxstate) if (cxstate.atomLabels != null) {
for (Map.Entry<Integer, String> e : cxstate.atomLabels.entrySet()) {
if (e.getKey() >= atoms.size())
continue;
IAtom old = atoms.get(e.getKey());
IPseudoAtom pseudo = bldr.newInstance(IPseudoAtom.class);
String val = e.getValue();
if (val.endsWith("_p"))
val = val.substring(0, val.length() - 2);
else if (val.startsWith("_AP"))
pseudo.setAttachPointNum(parseIntSafe(val.substring(3)));
pseudo.setLabel(val);
pseudo.setAtomicNumber(0);
pseudo.setImplicitHydrogenCount(0);
IAtomContainer mol = atomToMol.get(old);
AtomContainerManipulator.replaceAtomByAtom(mol, old, pseudo);
atomToMol.put(pseudo, mol);
atoms.set(e.getKey(), pseudo);
}
}
if (cxstate.atomValues != null) {
for (Map.Entry<Integer, String> e : cxstate.atomValues.entrySet())
atoms.get(e.getKey()).setProperty(CDKConstants.COMMENT, e.getValue());
}
if (cxstate.atomCoords != null) {
final int numAtoms = atoms.size();
final int numCoords = cxstate.atomCoords.size();
final int lim = Math.min(numAtoms, numCoords);
if (cxstate.coordFlag) {
for (int i = 0; i < lim; i++)
atoms.get(i).setPoint3d(new Point3d(cxstate.atomCoords.get(i)));
} else {
for (int i = 0; i < lim; i++)
atoms.get(i).setPoint2d(new Point2d(cxstate.atomCoords.get(i)));
}
}
if (cxstate.atomRads != null) {
for (Map.Entry<Integer, CxSmilesState.Radical> e : cxstate.atomRads.entrySet()) {
if (e.getKey() >= atoms.size())
continue;
int count = 0;
switch (e.getValue()) {
case Monovalent:
count = 1;
break;
case Divalent:
case DivalentSinglet:
case DivalentTriplet:
count = 2;
break;
case Trivalent:
case TrivalentDoublet:
case TrivalentQuartet:
count = 3;
break;
}
IAtom atom = atoms.get(e.getKey());
IAtomContainer mol = atomToMol.get(atom);
while (count-- > 0)
mol.addSingleElectron(bldr.newInstance(ISingleElectron.class, atom));
}
}
Multimap<IAtomContainer, Sgroup> sgroupMap = HashMultimap.create();
if (cxstate.positionVar != null) {
for (Map.Entry<Integer, List<Integer>> e : cxstate.positionVar.entrySet()) {
Sgroup sgroup = new Sgroup();
sgroup.setType(SgroupType.ExtMulticenter);
IAtom beg = atoms.get(e.getKey());
IAtomContainer mol = atomToMol.get(beg);
List<IBond> bonds = mol.getConnectedBondsList(beg);
if (bonds.isEmpty())
continue;
sgroup.addAtom(beg);
sgroup.addBond(bonds.get(0));
for (Integer endpt : e.getValue())
sgroup.addAtom(atoms.get(endpt));
sgroupMap.put(mol, sgroup);
}
}
if (cxstate.dataSgroups != null) {
for (DataSgroup dsgroup : cxstate.dataSgroups) {
if (dsgroup.field != null && dsgroup.field.startsWith("cdk:")) {
chemObj.setProperty(dsgroup.field, dsgroup.value);
}
}
}
if (cxstate.sgroups != null) {
PolySgroup:
for (PolymerSgroup psgroup : cxstate.sgroups) {
Sgroup sgroup = new Sgroup();
Set<IAtom> atomset = new HashSet<>();
IAtomContainer mol = null;
for (Integer idx : psgroup.atomset) {
if (idx >= atoms.size())
continue;
IAtom atom = atoms.get(idx);
IAtomContainer amol = atomToMol.get(atom);
if (mol == null)
mol = amol;
else if (amol != mol)
continue PolySgroup;
atomset.add(atom);
}
if (mol == null)
continue;
for (IAtom atom : atomset) {
for (IBond bond : mol.getConnectedBondsList(atom)) {
if (!atomset.contains(bond.getOther(atom)))
sgroup.addBond(bond);
}
sgroup.addAtom(atom);
}
sgroup.setSubscript(psgroup.subscript);
sgroup.putValue(SgroupKey.CtabConnectivity, psgroup.supscript);
switch (psgroup.type) {
case "n":
sgroup.setType(SgroupType.CtabStructureRepeatUnit);
break;
case "mon":
sgroup.setType(SgroupType.CtabMonomer);
break;
case "mer":
sgroup.setType(SgroupType.CtabMer);
break;
case "co":
sgroup.setType(SgroupType.CtabCopolymer);
break;
case "xl":
sgroup.setType(SgroupType.CtabCrossLink);
break;
case "mod":
sgroup.setType(SgroupType.CtabModified);
break;
case "mix":
sgroup.setType(SgroupType.CtabMixture);
break;
case "f":
sgroup.setType(SgroupType.CtabFormulation);
break;
case "any":
sgroup.setType(SgroupType.CtabAnyPolymer);
break;
case "gen":
sgroup.setType(SgroupType.CtabGeneric);
break;
case "c":
sgroup.setType(SgroupType.CtabComponent);
break;
case "grf":
sgroup.setType(SgroupType.CtabGraft);
break;
case "alt":
sgroup.setType(SgroupType.CtabCopolymer);
sgroup.putValue(SgroupKey.CtabSubType, "ALT");
break;
case "ran":
sgroup.setType(SgroupType.CtabCopolymer);
sgroup.putValue(SgroupKey.CtabSubType, "RAN");
break;
case "blk":
sgroup.setType(SgroupType.CtabCopolymer);
sgroup.putValue(SgroupKey.CtabSubType, "BLO");
break;
}
sgroupMap.put(mol, sgroup);
}
}
for (Map.Entry<IAtomContainer, Collection<Sgroup>> e : sgroupMap.asMap().entrySet())
e.getKey().setProperty(CDKConstants.CTAB_SGROUPS, new ArrayList<>(e.getValue()));
}
