private static long nextLong(Random rng, long n) if (n <= 0) throw new IllegalArgumentException("n must be greater than 0");
long bits, val;
do {
bits = (rng.nextLong() << 1) >>> 1;
val = bits % n;
} while (bits - val + (n - 1) < 0L);
return val;

protected static String formatMDLInt(int x, int n) char[] buf = new char[n];
Arrays.fill(buf, ' ');
String val = Integer.toString(x);
if (val.length() > n)
val = "0";
int off = n - val.length();
for (int i = 0; i < val.length(); i++)
buf[off+i] = val.charAt(i);
return new String(buf);

private String encodeAtomExpr(int atmIdx) final IAtom atom = mol.getAtom(atmIdx);
boolean complex = mode == MODE_EXACT;
StringBuilder sb = new StringBuilder();
switch (atom.getAtomicNumber()) {
case 0:
sb.append('*');
break;
case 5:
case 6:
case 7:
case 8:
case 15:
case 16:
case 9:
case 17:
case 35:
case 53:
sb.append(atom.isAromatic() ? atom.getSymbol().toLowerCase(Locale.ROOT)
: atom.getSymbol());
break;
default:
complex = true;
sb.append(atom.isAromatic() ? atom.getSymbol().toLowerCase(Locale.ROOT)
: atom.getSymbol());
break;
}
if (mode == MODE_EXACT) {
int hcount = atom.getImplicitHydrogenCount();
int valence = hcount;
int connections = hcount;
int atmDeg = this.deg[atmIdx];
for (int i = 0; i < atmDeg; i++) {
IBond bond = mol.getBond(bondAdj[atmIdx][i]);
IAtom nbr = bond.getOther(atom);
if (nbr.getAtomicNumber() != null && nbr.getAtomicNumber() == 1)
hcount++;
int bord = bond.getOrder() != null ? bond.getOrder().numeric() : 0;
if (bord == 0)
throw new IllegalArgumentException("Molecule had unsupported zero-order or unset bonds!");
valence += bord;
connections++;
}
sb.append('H').append(hcount);
sb.append('v').append(valence);
sb.append('X').append(connections);
}
Integer chg = atom.getFormalCharge();
if (chg == null) chg = 0;
if (chg <= -1 || chg >= +1) {
if (chg >= 0) sb.append('+');
else sb.append('-');
int abs = Math.abs(chg);
if (abs > 1) sb.append(abs);
complex = true;
} else if (mode == MODE_EXACT) {
sb.append("+0");
}
return complex ? '[' + sb.toString() + ']' : sb.toString();

private boolean matches(Type type, IAtom atom, int stereo) switch (type) {
case TRUE:
return true;
case FALSE:
return false;
case IS_AROMATIC:
return atom.isAromatic();
case IS_ALIPHATIC:
return !atom.isAromatic();
case IS_IN_RING:
return atom.isInRing();
case IS_IN_CHAIN:
return !atom.isInRing();
case IS_HETERO:
return !eq(atom.getAtomicNumber(), 6) &&
!eq(atom.getAtomicNumber(), 1);
case HAS_IMPLICIT_HYDROGEN:
return atom.getImplicitHydrogenCount() != null &&
atom.getImplicitHydrogenCount() > 0;
case HAS_ISOTOPE:
return atom.getMassNumber() != null;
case HAS_UNSPEC_ISOTOPE:
return atom.getMassNumber() == null;
case UNSATURATED:
for (IBond bond : atom.bonds())
if (bond.getOrder() == IBond.Order.DOUBLE)
return true;
return false;
case ELEMENT:
return eq(atom.getAtomicNumber(), value);
case ALIPHATIC_ELEMENT:
return !atom.isAromatic() &&
eq(atom.getAtomicNumber(), value);
case AROMATIC_ELEMENT:
return atom.isAromatic() &&
eq(atom.getAtomicNumber(), value);
case IMPL_H_COUNT:
return eq(atom.getImplicitHydrogenCount(), value);
case TOTAL_H_COUNT:
if (atom.getImplicitHydrogenCount() != null
&& atom.getImplicitHydrogenCount() > value)
return false;
return getTotalHCount(atom) == value;
case DEGREE:
return atom.getBondCount() == value;
case HEAVY_DEGREE:
return atom.getBondCount() - (getTotalHCount(atom) - atom.getImplicitHydrogenCount()) == value;
case TOTAL_DEGREE:
int x = atom.getBondCount() + unbox(atom.getImplicitHydrogenCount());
return x == value;
case VALENCE:
int v = unbox(atom.getImplicitHydrogenCount());
if (v > value)
return false;
for (IBond bond : atom.bonds()) {
if (bond.getOrder() != null)
v += bond.getOrder().numeric();
}
return v == value;
case ISOTOPE:
return eq(atom.getMassNumber(), value);
case FORMAL_CHARGE:
return eq(atom.getFormalCharge(), value);
case RING_BOND_COUNT:
if (!atom.isInRing() || atom.getBondCount() < value)
return false;
int rbonds = 0;
for (IBond bond : atom.bonds())
rbonds += bond.isInRing() ? 1 : 0;
return rbonds == value;
case RING_COUNT:
return atom.isInRing() && getRingCount(atom) == value;
case RING_SMALLEST:
return atom.isInRing() && isInSmallRingSize(atom, value);
case RING_SIZE:
return atom.isInRing() && isInRingSize(atom, value);
case HETERO_SUBSTITUENT_COUNT:
if (atom.getBondCount() < value)
return false;
int q = 0;
for (IBond bond : atom.bonds())
q += matches(Type.IS_HETERO, bond.getOther(atom), stereo) ? 1 : 0;
return q == value;
case INSATURATION:
int db = 0;
for (IBond bond : atom.bonds())
if (bond.getOrder() == IBond.Order.DOUBLE)
db++;
return db == value;
case HYBRIDISATION_NUMBER:
IAtomType.Hybridization hyb = atom.getHybridization();
if (hyb == null)
return false;
switch (value) {
case 1:
return hyb == IAtomType.Hybridization.SP1;
case 2:
return hyb == IAtomType.Hybridization.SP2;
case 3:
return hyb == IAtomType.Hybridization.SP3;
case 4:
return hyb == IAtomType.Hybridization.SP3D1;
case 5:
return hyb == IAtomType.Hybridization.SP3D2;
case 6:
return hyb == IAtomType.Hybridization.SP3D3;
case 7:
return hyb == IAtomType.Hybridization.SP3D4;
case 8:
return hyb == IAtomType.Hybridization.SP3D5;
default:
return false;
}
case PERIODIC_GROUP:
return atom.getAtomicNumber() != null &&
Elements.ofNumber(atom.getAtomicNumber()).group() == value;
case STEREOCHEMISTRY:
return stereo == UNKNOWN_STEREO || stereo == value;
case REACTION_ROLE:
ReactionRole role = atom.getProperty(CDKConstants.REACTION_ROLE);
return role != null && role.ordinal() == value;
case AND:
return left.matches(left.type, atom, stereo) &&
right.matches(right.type, atom, stereo);
case OR:
return left.matches(left.type, atom, stereo) ||
right.matches(right.type, atom, stereo);
case NOT:
return !left.matches(left.type, atom, stereo) ||
(stereo == UNKNOWN_STEREO &&
(left.type == STEREOCHEMISTRY ||
left.type == OR && left.left.type == STEREOCHEMISTRY));
case RECURSIVE:
if (ptrn == null)
ptrn = DfPattern.findSubstructure(query);
return ptrn.matchesRoot(atom);
default:
throw new IllegalArgumentException("Cannot match AtomExpr, type=" + type);
}

public static double[][] computeMinMax(Relation<? extends NumberVector> relation) int dim = RelationUtil.dimensionality(relation);
double[] mins = new double[dim], maxs = new double[dim];
for(int i = 0; i < dim; i++) {
mins[i] = Double.MAX_VALUE;
maxs[i] = -Double.MAX_VALUE;
}
for(DBIDIter iditer = relation.iterDBIDs(); iditer.valid(); iditer.advance()) {
final NumberVector o = relation.get(iditer);
for(int d = 0; d < dim; d++) {
final double v = o.doubleValue(d);
mins[d] = (v < mins[d]) ? v : mins[d];
maxs[d] = (v > maxs[d]) ? v : maxs[d];
}
}
return new double[][] { mins, maxs };

public void split() if(hasChildren()) {
return;
}
final boolean issplit = (maxSplitDimension >= (getDimensionality() - 1));
final int childLevel = issplit ? level + 1 : level;
final int splitDim = issplit ? 0 : maxSplitDimension + 1;
final double splitPoint = getMin(splitDim) + (getMax(splitDim) - getMin(splitDim)) * .5;
for(int i = 0; i < 2; i++) {
double[] min = SpatialUtil.getMin(this);
double[] max = SpatialUtil.getMax(this);
if(i == 0) {
min[splitDim] = splitPoint;
}
else {
max[splitDim] = splitPoint;
}
ModifiableDBIDs childIDs = split.determineIDs(getIDs(), new HyperBoundingBox(min, max), d_min, d_max);
if(childIDs != null) {
if(i == 0) {
rightChild = new CASHInterval(min, max, split, childIDs, splitDim, childLevel, d_min, d_max);
}
else {
leftChild = new CASHInterval(min, max, split, childIDs, splitDim, childLevel, d_min, d_max);
}
}
}
if(LOG.isDebuggingFine()) {
StringBuilder msg = new StringBuilder();
msg.append("Child level ").append(childLevel).append(",  split Dim   ").append(splitDim);
if(leftChild != null) {
msg.append("\nleft   ").append(leftChild);
}
if(rightChild != null) {
msg.append("\nright   ").append(rightChild);
}
LOG.fine(msg.toString());
}

private Collection<CLIQUEUnit> initOneDimensionalUnits(Relation<? extends NumberVector> database) StringBuilder buf = LOG.isDebuggingFiner() ? new StringBuilder(1000) : null;
int dimensionality = RelationUtil.dimensionality(database);
double[] minima = new double[dimensionality];
double[] maxima = new double[dimensionality];
Arrays.fill(minima, Double.MAX_VALUE);
Arrays.fill(maxima, -Double.MAX_VALUE);
for(DBIDIter it = database.iterDBIDs(); it.valid(); it.advance()) {
updateMinMax(database.get(it), minima, maxima);
}
for(int i = 0; i < maxima.length; i++) {
maxima[i] += 0.0001;
}
double[] unit_lengths = new double[dimensionality];
for(int d = 0; d < dimensionality; d++) {
unit_lengths[d] = (maxima[d] - minima[d]) / xsi;
}
if(buf != null) {
FormatUtil.formatTo(buf.append("   minima: "), minima, ", ", FormatUtil.NF2);
FormatUtil.formatTo(buf.append("\n   maxima: "), maxima, ", ", FormatUtil.NF2);
FormatUtil.formatTo(buf.append("\n   unit lengths: "), unit_lengths, ", ", FormatUtil.NF2);
}
double[][] unit_bounds = new double[xsi + 1][dimensionality];
for(int x = 0; x <= xsi; x++) {
for(int d = 0; d < dimensionality; d++) {
unit_bounds[x][d] = (x < xsi) ? minima[d] + x * unit_lengths[d] : maxima[d];
}
}
if(buf != null) {
FormatUtil.formatTo(buf.append("   unit bounds "), unit_bounds, "    [", "]\n", ", ", FormatUtil.NF2);
}
List<CLIQUEUnit> units = new ArrayList<>(xsi * dimensionality);
for(int x = 0; x < xsi; x++) {
for(int d = 0; d < dimensionality; d++) {
units.add(new CLIQUEUnit(d, unit_bounds[x][d], unit_bounds[x + 1][d]));
}
}
if(buf != null) {
LOG.debugFiner(buf.append("   total number of 1-dim units: ").append(units.size()).toString());
}
return units;

public ModifiableDBIDs determineIDs(DBIDs superSetIDs, HyperBoundingBox interval, double d_min, double d_max) StringBuilder msg = LOG.isDebugging() ? new StringBuilder() : null;
if(msg != null) {
msg.append("interval ").append(interval);
}
ModifiableDBIDs childIDs = DBIDUtil.newHashSet(superSetIDs.size());
Map<DBID, Double> minima = f_minima.get(interval);
Map<DBID, Double> maxima = f_maxima.get(interval);
if(minima == null || maxima == null) {
minima = new HashMap<>();
f_minima.put(interval, minima);
maxima = new HashMap<>();
f_maxima.put(interval, maxima);
}
for(DBIDIter iter = superSetIDs.iter(); iter.valid(); iter.advance()) {
DBID id = DBIDUtil.deref(iter);
Double f_min = minima.get(id);
Double f_max = maxima.get(id);
if(f_min == null) {
ParameterizationFunction f = database.get(id);
HyperBoundingBox minMax = f.determineAlphaMinMax(interval);
f_min = f.function(SpatialUtil.getMin(minMax));
f_max = f.function(SpatialUtil.getMax(minMax));
minima.put(id, f_min);
maxima.put(id, f_max);
}
if(msg != null) {
msg.append("\n\nf_min ").append(f_min);
msg.append("\nf_max ").append(f_max);
msg.append("\nd_min ").append(d_min);
msg.append("\nd_max ").append(d_max);
}
if(f_min - f_max > ParameterizationFunction.DELTA) {
throw new IllegalArgumentException("Houston, we have a problem: f_min > f_max! " + "\nf_min[" + FormatUtil.format(SpatialUtil.centroid(interval)) + "] = " + f_min + "\nf_max[" + FormatUtil.format(SpatialUtil.centroid(interval)) + "] = " + f_max + "\nf " + database.get(id));
}
if(f_min <= d_max && f_max >= d_min) {
childIDs.add(id);
if(msg != null) {
msg.append("\nid ").append(id).append(" appended");
}
}
else {
if(msg != null) {
msg.append("\nid ").append(id).append(" NOT appended");
}
}
}
if(msg != null) {
msg.append("\nchildIds ").append(childIDs.size());
LOG.debugFine(msg.toString());
}
if(childIDs.size() < minPts) {
return null;
}
else {
return childIDs;
}

private double[] determineMinMaxDistance(Relation<ParameterizationFunction> relation, int dimensionality) double[] min = new double[dimensionality - 1];
double[] max = new double[dimensionality - 1];
Arrays.fill(max, Math.PI);
HyperBoundingBox box = new HyperBoundingBox(min, max);
double d_min = Double.POSITIVE_INFINITY, d_max = Double.NEGATIVE_INFINITY;
for(DBIDIter iditer = relation.iterDBIDs(); iditer.valid(); iditer.advance()) {
ParameterizationFunction f = relation.get(iditer);
HyperBoundingBox minMax = f.determineAlphaMinMax(box);
double f_min = f.function(SpatialUtil.getMin(minMax));
double f_max = f.function(SpatialUtil.getMax(minMax));
d_min = Math.min(d_min, f_min);
d_max = Math.max(d_max, f_max);
}
return new double[] { d_min, d_max };

public static StringBuilder formatTo(StringBuilder buf, double[] d, String sep) if(d == null) {
return buf.append("null");
}
if(d.length == 0) {
return buf;
}
buf.append(d[0]);
for(int i = 1; i < d.length; i++) {
buf.append(sep).append(d[i]);
}
return buf;

public HyperBoundingBox determineAlphaMinMax(HyperBoundingBox interval) final int dim = vec.getDimensionality();
if(interval.getDimensionality() != dim - 1) {
throw new IllegalArgumentException("Interval needs to have dimensionality d=" + (dim - 1) + ", read: " + interval.getDimensionality());
}
if(extremumType.equals(ExtremumType.CONSTANT)) {
double[] centroid = SpatialUtil.centroid(interval);
return new HyperBoundingBox(centroid, centroid);
}
double[] alpha_min = new double[dim - 1];
double[] alpha_max = new double[dim - 1];
if(SpatialUtil.contains(interval, alphaExtremum)) {
if(extremumType.equals(ExtremumType.MINIMUM)) {
alpha_min = alphaExtremum;
for(int d = dim - 2; d >= 0; d--) {
alpha_max[d] = determineAlphaMax(d, alpha_max, interval);
}
}
else {
alpha_max = alphaExtremum;
for(int d = dim - 2; d >= 0; d--) {
alpha_min[d] = determineAlphaMin(d, alpha_min, interval);
}
}
}
else {
for(int d = dim - 2; d >= 0; d--) {
alpha_min[d] = determineAlphaMin(d, alpha_min, interval);
alpha_max[d] = determineAlphaMax(d, alpha_max, interval);
}
}
return new HyperBoundingBox(alpha_min, alpha_max);

protected static HyperBoundingBox computeBounds(NumberVector[] samples) assert(samples.length > 0) : "Cannot compute bounding box of empty set.";
final int dimensions = samples[0].getDimensionality();
final double[] min = new double[dimensions];
final double[] max = new double[dimensions];
NumberVector first = samples[0];
for(int d = 0; d < dimensions; d++) {
min[d] = max[d] = first.doubleValue(d);
}
for(int i = 1; i < samples.length; i++) {
NumberVector v = samples[i];
for(int d = 0; d < dimensions; d++) {
final double c = v.doubleValue(d);
min[d] = c < min[d] ? c : min[d];
max[d] = c > max[d] ? c : max[d];
}
}
return new HyperBoundingBox(min, max);

protected void initializeDataExtends(Relation<NumberVector> relation, int dim, double[] min, double[] extend) assert (min.length == dim && extend.length == dim);
if(minima == null || maxima == null || minima.length == 0 || maxima.length == 0) {
double[][] minmax = RelationUtil.computeMinMax(relation);
final double[] dmin = minmax[0], dmax = minmax[1];
for(int d = 0; d < dim; d++) {
min[d] = dmin[d];
extend[d] = dmax[d] - dmin[d];
}
return;
}
if(minima.length == dim) {
System.arraycopy(minima, 0, min, 0, dim);
}
else if(minima.length == 1) {
Arrays.fill(min, minima[0]);
}
else {
throw new AbortException("Invalid minima specified: expected " + dim + " got minima dimensionality: " + minima.length);
}
if(maxima.length == dim) {
for(int d = 0; d < dim; d++) {
extend[d] = maxima[d] - min[d];
}
return;
}
else if(maxima.length == 1) {
for(int d = 0; d < dim; d++) {
extend[d] = maxima[0] - min[d];
}
return;
}
else {
throw new AbortException("Invalid maxima specified: expected " + dim + " got maxima dimensionality: " + maxima.length);
}

private ScalesResult run(Relation<? extends NumberVector> rel) double[][] mms = RelationUtil.computeMinMax(rel);
int dim = mms[0].length;
double delta = 0.;
for(int d = 0; d < dim; d++) {
double del = mms[1][d] - mms[0][d];
delta = del > delta ? del : delta;
}
if(delta < Double.MIN_NORMAL) {
delta = 1.;
}
int log10res = (int) Math.ceil(Math.log10(delta / (LinearScale.MAXTICKS - 1)));
double res = MathUtil.powi(10, log10res);
double target = Math.ceil(delta / res) * res;
LinearScale[] scales = new LinearScale[dim];
for(int d = 0; d < dim; d++) {
double mid = (mms[0][d] + mms[1][d] - target) * .5;
double min = Math.floor(mid / res) * res;
double max = Math.ceil((mid + target) / res) * res;
scales[d] = new LinearScale(min, max);
}
return new ScalesResult(scales);

public void readParameterSets(IChemObjectBuilder builder) throws Exception if (ins == null) {
