public static INDArray cnn2dMaskReduction(INDArray inMask, int[] kernel, int[] stride, int[] padding, int[] dilation, ConvolutionMode convolutionMode ) if(inMask.rank() != 4){
throw new IllegalStateException("Expected rank 4 mask array for 2D CNN layers. Mask arrays for 2D CNN layers " +
"must have shape [batchSize,channels,X,Y] where X = (1 or activationsHeight) and Y = (1 or activationsWidth): " +
"Got rank " + inMask.rank() + " array with shape " + Arrays.toString(inMask.shape()));
}
if(convolutionMode == ConvolutionMode.Same && stride[0] == 1 && stride[1] == 1){
return inMask;
}
if(inMask.size(2) == 1 && inMask.size(3) == 1){
return inMask;
}
int[] k;
int[] s;
int[] p;
int[] d;
if(inMask.size(3) == 1){
k = new int[]{kernel[0],1};
s = new int[]{stride[0], 1};
p = new int[]{padding[0], 0};
d = new int[]{dilation[0], 1};
} else if(inMask.size(2) == 1){
k = new int[]{1, kernel[1]};
s = new int[]{1, stride[1]};
p = new int[]{0, padding[1]};
d = new int[]{1, dilation[1]};
} else {
k = kernel;
s = stride;
p = padding;
d = dilation;
}
int[] outSize = ConvolutionUtils.getOutputSize(inMask, k, s, p, convolutionMode, d);
boolean allEq = true;
for( int i=0; i<outSize.length; i++ ){
if(outSize[i] != inMask.size(i)){
allEq = false;
break;
}
}
if(allEq){
return inMask;
}
long[] outArraySize = new long[]{inMask.size(0), inMask.size(1), outSize[0], outSize[1]};
INDArray outMask = Nd4j.createUninitialized(outArraySize);
Op op = new LegacyPooling2D(inMask, kernel[0], kernel[1], stride[0], stride[1], padding[0], padding[1], dilation[0], dilation[1],
convolutionMode == ConvolutionMode.Same, LegacyPooling2D.Pooling2DType.MAX, 0.0, outMask);
Nd4j.getExecutioner().exec(op);
return outMask;

protected Pair<INDArray, INDArray> preOutput(boolean training, boolean forBackprop, LayerWorkspaceMgr workspaceMgr) assertInputSet(false);
INDArray bias = getParamWithNoise(ConvolutionParamInitializer.BIAS_KEY, training, workspaceMgr);
INDArray weights = getParamWithNoise(ConvolutionParamInitializer.WEIGHT_KEY, training, workspaceMgr);
validateInputRank();
INDArray input = this.input.castTo(dataType);
int miniBatch = (int) input.size(0);
int outDepth = (int) weights.size(0);
int inDepth = (int) weights.size(1);
validateInputDepth(inDepth);
int kH = (int) weights.size(2);
int kW = (int) weights.size(3);
int[] dilation = layerConf().getDilation();
int[] kernel = layerConf().getKernelSize();
int[] strides = layerConf().getStride();
int[] pad;
int[] outSize;
if (convolutionMode == ConvolutionMode.Same) {
outSize = ConvolutionUtils.getOutputSize(input, kernel, strides, null, convolutionMode, dilation);
pad = ConvolutionUtils.getSameModeTopLeftPadding(outSize, new int[] {(int) input.size(2), (int) input.size(3)}, kernel,
strides, dilation );
} else {
pad = layerConf().getPadding();
outSize = ConvolutionUtils.getOutputSize(input, kernel, strides, pad, convolutionMode, dilation);
}
int outH = outSize[0];
int outW = outSize[1];
if (helper != null && (helperCountFail == 0 || !layerConf().isCudnnAllowFallback())) {
if (preOutput != null && forBackprop) {
return new Pair<>(preOutput, null);
}
if(!hasBias()){
if(dummyBias == null){
try (MemoryWorkspace wsO = Nd4j.getMemoryManager().scopeOutOfWorkspaces()) {
dummyBias = Nd4j.create(1, layerConf().getNOut());
}
}
bias = dummyBias;
}
INDArray ret = null;
try {
ret = helper.preOutput(input, weights, bias, kernel, strides, pad, layerConf().getCudnnAlgoMode(),
layerConf().getCudnnFwdAlgo(), convolutionMode, dilation, workspaceMgr);
} catch (Exception e){
if(e.getMessage() != null && e.getMessage().contains("Failed to allocate")){
throw e;
}
if(layerConf().isCudnnAllowFallback()){
helperCountFail++;
if(helper instanceof MKLDNNConvHelper){
log.warn("MKL-DNN execution failed - falling back on built-in implementation",e);
} else {
log.warn("CuDNN execution failed - falling back on built-in implementation",e);
}
} else {
throw new RuntimeException(e);
}
}
if (ret != null) {
return new Pair<>(ret, null);
}
}
if (preOutput != null && i2d != null && forBackprop) {
return new Pair<>(preOutput, i2d);
}
INDArray col = Nd4j.createUninitialized(weights.dataType(), new long[] {miniBatch, outH, outW, inDepth, kH, kW}, 'c');
INDArray col2 = col.permute(0, 3, 4, 5, 1, 2);
INDArray im2ColIn = input.castTo(col2.dataType());
Convolution.im2col(im2ColIn, kH, kW, strides[0], strides[1], pad[0], pad[1], dilation[0], dilation[1],
convolutionMode == ConvolutionMode.Same, col2);
INDArray im2col2d = Shape.newShapeNoCopy(col, new int[] {miniBatch * outH * outW, inDepth * kH * kW}, false);
INDArray permutedW = weights.permute(3, 2, 1, 0);
INDArray reshapedW = permutedW.reshape('f', kW * kH * inDepth, outDepth);
INDArray z = workspaceMgr.createUninitialized(ArrayType.ACTIVATIONS, weights.dataType(), new long[]{im2col2d.size(0), reshapedW.size(1)}, 'f');
im2col2d.mmuli(reshapedW, z);
if(layerConf().hasBias()){
z.addiRowVector(bias);
}
z = Shape.newShapeNoCopy(z, new int[] {outW, outH, miniBatch, outDepth}, true);
z = z.permute(2, 3, 1, 0);
if (training && cacheMode != CacheMode.NONE && workspaceMgr.hasConfiguration(ArrayType.FF_CACHE) && workspaceMgr.isWorkspaceOpen(ArrayType.FF_CACHE)) {
try (MemoryWorkspace wsB = workspaceMgr.notifyScopeBorrowed(ArrayType.FF_CACHE)) {
i2d = im2col2d.unsafeDuplication();
}
}
return new Pair<>(z, forBackprop ? im2col2d : null);

public static int[] getOutputSize(INDArray inputData, int[] kernel, int[] strides, int[] padding, ConvolutionMode convolutionMode, int[] dilation) int inH = (int) inputData.size(2);
int inW = (int) inputData.size(3);
int[] eKernel = effectiveKernelSize(kernel, dilation);
boolean atrous = (eKernel == kernel);
int[] inShape = new int[]{inH, inW};
validateShapes(inputData, eKernel, strides, padding, convolutionMode, dilation, inShape, atrous);
if (convolutionMode == ConvolutionMode.Same) {
int outH = (int) Math.ceil(inH / ((double) strides[0]));
int outW = (int) Math.ceil(inW / ((double) strides[1]));
return new int[]{outH, outW};
}
int hOut = (inH - eKernel[0] + 2 * padding[0]) / strides[0] + 1;
int wOut = (inW - eKernel[1] + 2 * padding[1]) / strides[1] + 1;
return new int[]{hOut, wOut};

public static int[] get3DOutputSize(INDArray inputData, int[] kernel, int[] strides, int[] padding, ConvolutionMode convolutionMode, int[] dilation, boolean isNCDHW) int inD = (int) (isNCDHW ? inputData.size(2) : inputData.size(1));
int inH = (int) (isNCDHW ? inputData.size(3) : inputData.size(2));
int inW = (int) (isNCDHW ? inputData.size(4) : inputData.size(3));
int[] eKernel = effectiveKernelSize(kernel, dilation);
boolean atrous = (eKernel == kernel);
val inShape = new int[]{inD, inH, inW};
validateShapes(ArrayUtil.toInts(inputData.shape()), eKernel, strides, padding, convolutionMode, dilation, inShape, atrous);
if (convolutionMode == ConvolutionMode.Same) {
int outD = (int) Math.ceil(inD / ((double) strides[0]));
int outH = (int) Math.ceil(inH / ((double) strides[1]));
int outW = (int) Math.ceil(inW / ((double) strides[2]));
return new int[]{outD, outH, outW};
}
int outD = (inD - eKernel[0] + 2 * padding[0]) / strides[0] + 1;
int outH = (inH - eKernel[1] + 2 * padding[1]) / strides[1] + 1;
int outW = (inW - eKernel[2] + 2 * padding[2]) / strides[2] + 1;
return new int[]{outD, outH, outW};

public static int[] getDeconvolutionOutputSize(INDArray inputData, int[] kernel, int[] strides, int[] padding, ConvolutionMode convolutionMode, int[] dilation) int hIn = (int) inputData.size(2);
int wIn = (int) inputData.size(3);
int[] eKernel = effectiveKernelSize(kernel, dilation);
if (convolutionMode == ConvolutionMode.Same) {
int hOut = strides[0] * hIn;
int wOut = strides[1] * wIn;
return new int[]{hOut, wOut};
}
int hOut = strides[0] * (hIn - 1) + eKernel[0] - 2 * padding[0];
int wOut = strides[1] * (wIn - 1) + eKernel[1] - 2 * padding[1];
return new int[]{hOut, wOut};

public static int getOutputSize(int inH, int kernel, int strides, int padding, ConvolutionMode convolutionMode, int dilation) int eKernel = effectiveKernelSize(kernel, dilation);
if (convolutionMode == ConvolutionMode.Same) {
return (int) Math.ceil(inH / ((double) strides));
}
return (inH - eKernel + 2 * padding) / strides + 1;

public static int getSameModeTopLeftPadding(int outSize, int inSize, int kernel, int strides, int dilation) int eKernel = effectiveKernelSize(kernel, dilation);
int outPad = ((outSize - 1) * strides + eKernel - inSize) / 2;
Preconditions.checkState(outPad >= 0, "Invalid padding values calculated: %s - " +
"layer configuration is invalid? Input size %s, output size %s, kernel %s, " +
"strides %s, dilation %s", outPad, inSize, outSize, kernel, strides, dilation);
return outPad;

public static INDArray reverseTimeSeries(INDArray in) if(in == null){
return null;
}
if(in.ordering() != 'f' || in.isView() || !Shape.strideDescendingCAscendingF(in)){
in = in.dup('f');
}
int[] idxs = new int[(int) in.size(2)];
int j=0;
for( int i=idxs.length-1; i>=0; i--){
idxs[j++] = i;
}
INDArray inReshape = in.reshape('f', in.size(0)*in.size(1), in.size(2));
INDArray outReshape = Nd4j.pullRows(inReshape, 0, idxs, 'f');
return outReshape.reshape('f', in.size(0), in.size(1), in.size(2));

public static boolean isContiguousInBuffer(INDArray in) long length = in.length();
long dLength = in.data().length();
if (length == dLength)
return true;
char order = in.ordering();
long[] shape = in.shape();
long[] stridesIfContiguous;
if (order == 'f') {
stridesIfContiguous = ArrayUtil.calcStridesFortran(shape);
} else if (order == 'c') {
stridesIfContiguous = ArrayUtil.calcStrides(shape);
} else if (order == 'a') {
stridesIfContiguous = new long[] {1, 1};
} else {
throw new RuntimeException("Invalid order: not c or f (is: " + order + ")");
}
return Arrays.equals(in.stride(), stridesIfContiguous);

