public void copyFile(File src, File dst, boolean hardlink) throws IOException if (src == null || dst == null) {
throw new IOException("src/dst file is null");
}
try {
if (hardlink && shouldHardLinkBlockCopy) {
if (dst.exists()) {
if(!dst.delete()) {
throw new IOException("Deletion of file : " + dst + " failed");
}
}
NativeIO.link(src, dst);
DataNode.LOG.info("Hard Link Created from : " + src + " to " + dst);
return;
}
} catch (IOException e) {
DataNode.LOG.warn("Hard link failed from : " + src + " to " + dst
+ " continuing with regular file copy");
}
FileChannel input = null;
FileChannel output = null;
try {
input = new FileInputStream(src).getChannel();
output = new FileOutputStream(dst).getChannel();
if (input == null || output == null)  {
throw new IOException("Could not create file channels for src : " + src
+ " dst : " + dst);
}
long bytesLeft = input.size();
long position = 0;
while (bytesLeft > 0) {
long bytesWritten = output.transferFrom(input, position, bytesLeft);
bytesLeft -= bytesWritten;
position += bytesWritten;
}
if (datanode.syncOnClose) {
output.force(true);
}
} finally {
if (input != null) {
input.close();
}
if (output != null) {
output.close();
}
}

@Override public List<ByteBuffer> readFullyScatterGather(long position, int length) throws IOException if (dfsClient.dataTransferVersion < DataTransferProtocol.SCATTERGATHER_VERSION) {
return super.readFullyScatterGather(position, length);
}
dfsClient.checkOpen();
if (closed) {
throw new IOException("Stream closed");
}
DFSClient.dfsInputStreamfailures.set(0);
long start = System.currentTimeMillis();
long filelen = getFileLength();
if ((position < 0) || (position > filelen)) {
String msg = " Invalid position " + position +
". File " + src + " is of size " + filelen;
DFSClient.LOG.warn(msg);
throw new IOException(msg);
}
List<ByteBuffer> results = new LinkedList<ByteBuffer>();
int realLen = length;
if ((position + length) > filelen) {
realLen = (int)(filelen - position);
}
List<LocatedBlock> blockRange = getBlockRange(position, realLen);
int remaining = realLen;
for (LocatedBlock blk : blockRange) {
long targetStart = position - blk.getStartOffset();
long bytesToRead = Math.min(remaining, blk.getBlockSize() - targetStart);
ByteBuffer bb = fetchBlockByteRangeScatterGather(blk, targetStart,
bytesToRead);
results.add(bb);
remaining -= bytesToRead;
position += bytesToRead;
}
assert remaining == 0 : "Wrong number of bytes read.";
if (dfsClient.stats != null) {
dfsClient.stats.incrementBytesRead(realLen);
}
long timeval = System.currentTimeMillis() - start;
dfsClient.metrics.incPreadTime(timeval);
dfsClient.metrics.incPreadSize(realLen);
dfsClient.metrics.incPreadOps();
return results;

public void position(long position) throws IOException if (position == 0) {
currentStreamState.setNextLedgerEntryId(firstLedgerEntryId);
currentStreamState.setOffsetInEntry(0);
entryStream = null;
} else if (savedStreamState == null ||
position != savedStreamState.getReaderPosition()) {
if (position > Integer.MAX_VALUE) {
throw new IllegalArgumentException("Asked to position to " + position +
", but can only \"brute-force\" skip up" + Integer.MAX_VALUE);
}
position(0);
skip(position, (int) position);
} else {
int bytesToSkip = 0;
if (savedStreamState.getOffsetInLedger() > position) {
long entryStartPosition = savedStreamState.getOffsetInLedger() -
savedStreamState.getOffsetInEntry();
bytesToSkip = (int) (position - entryStartPosition);
} else if (savedStreamState.getOffsetInLedger() < position) {
throw new IllegalArgumentException("Saved offset in ledger (" +
savedStreamState.getOffsetInLedger() + ") < position(" + position
+ ")");
}
long nextLedgerEntryId = savedStreamState.getNextLedgerEntryId() == firstLedgerEntryId ?
firstLedgerEntryId : (savedStreamState.getNextLedgerEntryId() - 1);
currentStreamState.setNextLedgerEntryId(nextLedgerEntryId);
if (bytesToSkip > 0) {
entryStream = null;
skip(position, bytesToSkip);
} else {
if (currentStreamState.getNextLedgerEntryId() > 0) {
currentStreamState.setNextLedgerEntryId(currentStreamState.getNextLedgerEntryId() - 1);
}
entryStream = nextEntryStream();
}
}
currentStreamState.setOffsetInLedger(position);

int doIO(ByteBuffer buf, int ops) throws IOException if (!buf.hasRemaining()) {
throw new IllegalArgumentException("Buffer has no data left.");
}
while (buf.hasRemaining()) {
if (closed) {
return -1;
}
try {
int n = performIO(buf);
if (n != 0) {
return n;
}
} catch (IOException e) {
if (!channel.isOpen()) {
closed = true;
}
throw e;
}
int count = 0;
try {
count = selector.select(channel, ops, timeout);
} catch (IOException e) {
closed = true;
throw e;
}
if (count == 0) {
throw new SocketTimeoutException(timeoutExceptionString(channel,
timeout, ops));
}
}
return 0;

DatanodeDescriptor[] getValidTargets() if (targetGSs == null) {
return null;
}
int count = 0;
long lastBlockGS = this.getLastBlock().getGenerationStamp();
for (long targetGS : targetGSs) {
if (lastBlockGS == targetGS) {
count++;
}
}
if (count == 0) {
return null;
} if (count == targets.length) {
return targets;
} else {
DatanodeDescriptor[] validTargets = new DatanodeDescriptor[count];
for (int i=0, numOfValidTargets=0; i<targets.length; i++) {
if (lastBlockGS == targetGSs[i]) {
validTargets[numOfValidTargets++] = targets[i];
if (numOfValidTargets == count) {
return validTargets;
}
}
}
return validTargets;
}

private void preallocate() throws IOException long position = fc.position();
long triggerSize = Math.max(FSEditLog.preallocateSize / 100, 4096);
if (position + triggerSize >= fc.size()) {
if(FSNamesystem.LOG.isDebugEnabled()) {
FSNamesystem.LOG.debug("Preallocating Edit log, current size "
+ fc.size());
}
fill.position(0);
int written = fc.write(fill, position);
if(FSNamesystem.LOG.isDebugEnabled()) {
FSNamesystem.LOG.debug("Edit log size is now " + fc.size() +
" written " + written + " bytes " + " at offset " + position);
}
}

public RawKeyValueIterator sort() MergeSort m = new MergeSort(this);
int count = super.count;
if (count == 0) return null;
int [] pointers = super.pointers;
int [] pointersCopy = new int[count];
System.arraycopy(pointers, 0, pointersCopy, 0, count);
m.mergeSort(pointers, pointersCopy, 0, count);
return new MRSortResultIterator(super.keyValBuffer, pointersCopy,
super.startOffsets, super.keyLengths, super.valueLengths);

public void setChannelPosition(long dataOffset, boolean startWithPartialChunk) throws IOException long channelSize = blockDataWriter.getChannelSize();
if (channelSize < dataOffset) {
String msg = "Trying to change block file offset of block "
+ block
+ "file "
+ ((blockDataFile.getFile() != null) ? blockDataFile.getFile()
: "unknown") + " to " + dataOffset
+ " but actual size of file is " + blockDataWriter.getChannelSize();
throw new IOException(msg);
}
if (dataOffset > channelSize) {
throw new IOException("Set position over the end of the data file.");
}
if (startWithPartialChunk && channelSize != dataOffset + checksumSize) {
DFSClient.LOG.warn("Inline Checksum Block " + block + " channel size "
+ channelSize + " but packet needs to start from " + dataOffset);
}
blockDataWriter.flush();
blockDataWriter.position(dataOffset);

public void setChannelPosition(long dataOffset, long ckOffset) throws IOException long channelSize = blockDataWriter.getChannelSize();
if (channelSize < dataOffset) {
String fileName;
if (datanode.data instanceof FSDataset) {
FSDataset fsDataset = (FSDataset) datanode.data;
fileName = fsDataset.getDatanodeBlockInfo(namespaceId, block)
.getBlockDataFile().getTmpFile(namespaceId, block).toString();
} else {
fileName = "unknown";
}
String msg = "Trying to change block file offset of block " + block
+ " file " + fileName + " to " + dataOffset
+ " but actual size of file is " + blockDataWriter.getChannelSize();
throw new IOException(msg);
}
if (dataOffset > channelSize) {
throw new IOException("Set position over the end of the data file.");
}
if (dataOffset % bytesPerChecksum != 0 && channelSize != dataOffset) {
DFSClient.LOG.warn("Non-inline Checksum Block " + block
+ " channel size " + channelSize + " but data starts from "
+ dataOffset);
}
blockDataWriter.position(dataOffset);
setChecksumOffset(ckOffset);

public static void readRAMFiles(DataInput in, RAMDirectory dir) throws IOException int numFiles = in.readInt();
for (int i = 0; i < numFiles; i++) {
String name = Text.readString(in);
long length = in.readLong();
if (length > 0) {
IndexOutput output = null;
try {
output = dir.createOutput(name);
int position = 0;
byte[] buffer = new byte[BUFFER_SIZE];
while (position < length) {
int len =
position + BUFFER_SIZE <= length ? BUFFER_SIZE
: (int) (length - position);
in.readFully(buffer, 0, len);
output.writeBytes(buffer, 0, len);
position += len;
}
} finally {
if (output != null) {
output.close();
}
}
}
}

