public static boolean contentEquals(Reader input1, Reader input2) throws IORuntimeException input1 = getReader(input1);
input2 = getReader(input2);
try {
int ch = input1.read();
while (EOF != ch) {
int ch2 = input2.read();
if (ch != ch2) {
return false;
}
ch = input1.read();
}
int ch2 = input2.read();
return ch2 == EOF;
} catch (IOException e) {
throw new IORuntimeException(e);
}

public static boolean contentEqualsIgnoreEOL(File file1, File file2, Charset charset) throws IORuntimeException boolean file1Exists = file1.exists();
if (file1Exists != file2.exists()) {
return false;
}
if (!file1Exists) {
return true;
}
if (file1.isDirectory() || file2.isDirectory()) {
throw new IORuntimeException("Can't compare directories, only files");
}
if (equals(file1, file2)) {
return true;
}
Reader input1 = null;
Reader input2 = null;
try {
input1 = getReader(file1, charset);
input2 = getReader(file2, charset);
return IoUtil.contentEqualsIgnoreEOL(input1, input2);
} finally {
IoUtil.close(input1);
IoUtil.close(input2);
}

public static long copy(Reader reader, Writer writer, int bufferSize, StreamProgress streamProgress) throws IORuntimeException char[] buffer = new char[bufferSize];
long size = 0;
int readSize;
if (null != streamProgress) {
streamProgress.start();
}
try {
while ((readSize = reader.read(buffer, 0, bufferSize)) != EOF) {
writer.write(buffer, 0, readSize);
size += readSize;
writer.flush();
if (null != streamProgress) {
streamProgress.progress(size);
}
}
} catch (Exception e) {
throw new IORuntimeException(e);
}
if (null != streamProgress) {
streamProgress.finish();
}
return size;

private static String stripHostname(final String originalHostname) final int index = originalHostname.indexOf(DOMAIN_SEPARATOR);
if (index == -1) {
return originalHostname;
}
final Matcher matcher = IPV4_PATTERN.matcher(originalHostname);
if (matcher.matches()) {
return originalHostname;
}
if (index == 0) {
throw new IllegalStateException("Hostname " + originalHostname + " starts with a " + DOMAIN_SEPARATOR);
}
return originalHostname.substring(0, index);

public static String regexpExtract(String str, String regex, int extractIndex) if (extractIndex < 0) {
return null;
}
try {
Matcher m = REGEXP_PATTERN_CACHE.get(regex).matcher(str);
if (m.find()) {
MatchResult mr = m.toMatchResult();
return mr.group(extractIndex);
}
return null;
} catch (Exception e) {
LOG.error(
String.format("Exception in regexpExtract('%s', '%s', '%d')", str, regex, extractIndex),
e);
return null;
}

public static String regexpReplace(String str, String regex, String replacement) if (regex.isEmpty()) {
return str;
}
try {
StringBuffer sb = new StringBuffer();
Matcher m = REGEXP_PATTERN_CACHE.get(regex).matcher(str);
while (m.find()) {
m.appendReplacement(sb, replacement);
}
m.appendTail(sb);
return sb.toString();
} catch (Exception e) {
LOG.error(
String.format("Exception in regexpReplace('%s', '%s', '%s')", str, regex, replacement),
e);
return null;
}

private String normalizePath(String path) path = path.trim();
