public boolean match(String[] requestPathTokens, Map<String, String> params) if (tokens.length == requestPathTokens.length) {
for (int i = 0; i < tokens.length; i++) {
String key = tokens[i];
String value = requestPathTokens[i];
if (key.length() > 0 && key.charAt(0) == ':') {
params.put(key.substring(1), value);
} else if (!key.equals(value)) {
return false;
}
}
return true;
}
if (tokens.length > 0 &&
tokens[tokens.length - 1].equals(":*") &&
tokens.length <= requestPathTokens.length) {
for (int i = 0; i < tokens.length - 2; i++) {
String key = tokens[i];
String value = requestPathTokens[i];
if (key.length() > 0 && key.charAt(0) == ':') {
params.put(key.substring(1), value);
} else if (!key.equals(value)) {
return false;
}
}
StringBuilder b = new StringBuilder(requestPathTokens[tokens.length - 1]);
for (int i = tokens.length; i < requestPathTokens.length; i++) {
b.append('/');
b.append(requestPathTokens[i]);
}
params.put("*", b.toString());
return true;
}
return false;

public CommandLine getCommandLine(Options commandLineOptions) throws Exception final List<String> args = new ArrayList<>();
properties.asMap().forEach((k, v) -> {
if (commandLineOptions.hasOption(k)) {
final Option o = commandLineOptions.getOption(k);
final String argument = "--" + o.getLongOpt();
if (!o.hasArg()) {
final Boolean flag = Boolean.parseBoolean(v);
if (flag) {
args.add(argument);
}
}
else if (!o.hasArgs()) {
args.add(argument);
args.add(v);
}
else {
throw new IllegalArgumentException("Option '" + o + "' is not supported yet.");
}
}
});
return CliFrontendParser.parse(commandLineOptions, args.toArray(new String[args.size()]), true);

