return ncfile;
}
miss.incrementAndGet();
if (t != null) t.miss++;
ncfile = factory.open(location, buffer_size, cancelTask, spiObject);
if (cacheLog.isDebugEnabled())
cacheLog.debug("FileCache " + name + " acquire " + hashKey + " " + ncfile.getLocation());
if (debugPrint) System.out.println("  FileCache " + name + " acquire " + hashKey + " " + ncfile.getLocation());
if ((cancelTask != null) && (cancelTask.isCancel())) {
if (ncfile != null) ncfile.close();
return null;
}
if (disabled.get()) return ncfile;
CacheElement elem;
synchronized (cache) {
elem = cache.get(hashKey);
if (elem == null) cache.put(hashKey, new CacheElement(ncfile, hashKey));
}
if (elem != null) {
synchronized (elem) {
elem.addFile(ncfile);
}
}
boolean needHard = false;
boolean needSoft = false;
synchronized (hasScheduled) {
if (!hasScheduled.get()) {
int count = files.size();
if ((count > hardLimit) && (hardLimit > 0)) {
needHard = true;
hasScheduled.getAndSet(true);
} else if ((count > softLimit) && (softLimit > 0)) {
hasScheduled.getAndSet(true);
needSoft = true;
}
}
}
if (needHard) {
if (debugCleanup)
System.out.println("CleanupTask due to hard limit time=" + new Date().getTime());
cleanup(hardLimit);
} else if (needSoft) {
schedule(new CleanupTask(), 100);
if (debugCleanup) System.out.println("CleanupTask scheduled due to soft limit time=" + new Date());
}
return ncfile;

