public static double logpdf(double val, double dof) if(val <= 0 || val == Double.POSITIVE_INFINITY) {
return Double.NEGATIVE_INFINITY;
}
final double k = dof * .5;
return (dof - 1.0) * FastMath.log(val) + (1 - k) * MathUtil.LOG2 - GammaDistribution.logGamma(k) - val * val / 2.;

public static double logpdf(double x, double dof) if(x <= 0) {
return Double.NEGATIVE_INFINITY;
}
if(dof <= 0) {
return Double.NaN;
}
final double k = dof * .5;
final double twox = x * 2.0;
return twox == Double.POSITIVE_INFINITY ? Double.NEGATIVE_INFINITY :
(k - 1.0) * FastMath.log(twox) - twox - logGamma(k) + MathUtil.LOG2;

public static double pdf(double x, double dof) if(x <= 0) {
return 0.0;
}
if(dof <= 0) {
return Double.NaN;
}
final double k = dof * .5;
return (Math.abs(k - 1.0) < Double.MIN_NORMAL) ? FastMath.exp(-x * 2.0) * 2.0 :
FastMath.exp((k - 1.0) * FastMath.log(x * 2.0) - x * 2.0 - logGamma(k)) * 2.0;

public static double quantile(double val, double k, double lambda, double theta) if(val < 0.0 || val > 1.0) {
return Double.NaN;
}
else if(val == 0) {
return 0.0;
}
else if(val == 1) {
return Double.POSITIVE_INFINITY;
}
else {
return theta + lambda * FastMath.pow(-FastMath.log(1.0 - val), 1.0 / k);
}

public static double quantile(double val, double mu, double sigma, double k) if(val < 0.0 || val > 1.0) {
return Double.NaN;
}
if(k < 0) {
return mu + sigma * Math.max((1. - FastMath.pow(-FastMath.log(val), k)) / k, 1. / k);
}
else if(k > 0) {
return mu + sigma * Math.min((1. - FastMath.pow(-FastMath.log(val), k)) / k, 1. / k);
}
else {
return mu + sigma * FastMath.log(1. / FastMath.log(1. / val));
}

public static double cdf(double val, double loc, double scale, double shape1, double shape2) val = (val - loc) / scale;
if(val == Double.NEGATIVE_INFINITY) {
return 0.;
}
if(val == Double.POSITIVE_INFINITY) {
return 1.;
}
if(val != val) {
return Double.NaN;
}
if(shape1 == 0.) {
val = FastMath.exp(-val);
}
else {
double tmp = shape1 * val;
if(tmp == Double.NEGATIVE_INFINITY) {
return shape2 == 0 ? 1 : 0.;
}
if(tmp >= 1.) {
return shape2 == 0 ? 0 : 1.;
}
val = FastMath.exp(FastMath.log1p(-tmp) / shape1);
}
if(shape2 == 0.) {
return FastMath.exp(-val);
}
final double tmp = shape2 * val;
return tmp < 1. ? FastMath.exp(FastMath.log1p(-tmp) / shape2) : 0.;

public static double cdf(double val, double mu, double sigma, double k) final double x = (val - mu) / sigma;
if(k > 0 || k < 0) {
if(k * x > 1) {
return k > 0 ? 1 : 0;
}
return FastMath.exp(-FastMath.exp(FastMath.log(1 - k * x) / k));
}
else {
return FastMath.exp(-FastMath.exp(-x));
}

public static double pdf(double val, double loc, double scale, double shape) if(!(val < Double.POSITIVE_INFINITY && val > Double.NEGATIVE_INFINITY)) {
return val == val ? 0. : Double.NaN;
}
val = (val - loc) / scale;
double e = FastMath.exp(-val);
double f = 1. + e;
return e < Double.POSITIVE_INFINITY ? shape * e / (scale * FastMath.pow(f, shape + 1.)) : 0.;

public static double logcdf(double val, double shape1, double shape2) if(val == Double.NEGATIVE_INFINITY) {
return Double.NEGATIVE_INFINITY;
}
if(val == Double.POSITIVE_INFINITY) {
return 0.;
}
if(val != val) {
return Double.NaN;
}
if(shape1 == 0.) {
val = FastMath.exp(-val);
}
else {
double tmp = shape1 * val;
if(tmp == Double.NEGATIVE_INFINITY) {
return shape2 == 0 ? 0. : Double.NEGATIVE_INFINITY;
}
if(tmp >= 1.) {
return shape2 == 0 ? Double.NEGATIVE_INFINITY : 0.;
}
val = FastMath.exp(FastMath.log1p(-tmp) / shape1);
}
if(shape2 == 0.) {
return -val;
}
final double tmp = shape2 * val;
return tmp < 1. ? FastMath.log1p(-tmp) / shape2 : Double.NEGATIVE_INFINITY;

