private void writeObject(java.io.ObjectOutputStream s) throws IOException s.defaultWriteObject();
for (int k = 0; k < segments.length; ++k) {
Segment<K, V> seg = segments[k];
seg.lock();
try {
HashEntry<K, V>[] tab = seg.table;
for (int i = 0; i < tab.length; ++i) {
for (HashEntry<K, V> e = tab[i]; e != null; e = e.next) {
K key = e.key();
if (key == null) {
continue;
}
s.writeObject(key);
s.writeObject(e.value());
}
}
} finally {
seg.unlock();
}
}
s.writeObject(null);
s.writeObject(null);

private boolean tryProcessOnOtherMembers(Operation operation, String serviceName, long timeoutNanos) final OperationService operationService = nodeEngine.getOperationService();
final Collection<Member> targets = nodeEngine.getClusterService().getMembers(DATA_MEMBER_SELECTOR);
final Member localMember = nodeEngine.getLocalMember();
for (Member target : targets) {
if (target.equals(localMember)) {
continue;
}
long start = System.nanoTime();
try {
logger.fine("Replicating " + serviceName + " to " + target);
InternalCompletableFuture<Object> future =
operationService.createInvocationBuilder(null, operation, target.getAddress())
.setTryCount(1)
.invoke();
future.get(timeoutNanos, TimeUnit.NANOSECONDS);
return true;
} catch (Exception e) {
logger.fine("Failed replication of " + serviceName + " for target " + target, e);
}
timeoutNanos -= (System.nanoTime() - start);
if (timeoutNanos < 0) {
break;
}
}
return false;

