public static void computePositions(Node node, int depth, double aoff, double awid, double radius, double radiusinc) node.x = FastMath.sin(aoff) * radius;
node.y = FastMath.cos(aoff) * radius;
double cwid = awid / node.weight;
double div = 1;
if(node.weight > 1) {
double s = FastMath.sin(awid * .5), c = FastMath.cos(awid * .5);
double dx = s * (depth + 1), dy = c * (depth + 1) - depth;
double d = FastMath.sqrt(dx * dx + dy * dy) / MathUtil.SQRT2;
div = Math.max(div, d);
}
double cang = aoff - awid * .5 / div;
final double adjwid = cwid / div;
for(Node c : node.children) {
computePositions(c, depth + 1, cang + adjwid * c.weight * .5, adjwid * c.weight, radius + radiusinc, radiusinc);
cang += adjwid * c.weight;
}

public double squaredDistanceFromCamera(double x, double y) double dx = (distance * sinZ) - x;
double dy = (distance * -cosZ) - y;
return dx * dx + dy * dy;

public static void computePositions(Node node, int depth, double aoff, double awid, int maxdepth) double r = depth / (maxdepth - 1.);
node.x = FastMath.sin(aoff + awid * .5) * r;
node.y = FastMath.cos(aoff + awid * .5) * r;
double cpos = aoff;
double cwid = awid / node.weight;
for(Node c : node.children) {
computePositions(c, depth + 1, cpos, cwid * c.weight, maxdepth);
cpos += cwid * c.weight;
}

public static double[][] computeWeightMatrix(final int quanth, final int quants, final int quantb) final int dim = quanth * quants * quantb;
final DoubleWrapper tmp = new DoubleWrapper();
assert (dim > 0);
final double[][] m = new double[dim][dim];
for(int x = 0; x < dim; x++) {
final int hx = x / (quantb * quants);
final int sx = (x / quantb) % quants;
final int bx = x % quantb;
for(int y = x; y < dim; y++) {
final int hy = y / (quantb * quants);
final int sy = (y / quantb) % quants;
final int by = y % quantb;
final double shx = FastMath.sinAndCos((hx + .5) / quanth * MathUtil.TWOPI, tmp);
final double chx = tmp.value;
final double shy = FastMath.sinAndCos((hy + .5) / quanth * MathUtil.TWOPI, tmp);
final double chy = tmp.value;
final double cos = chx * (sx + .5) / quants - chy * (sy + .5) / quants;
final double sin = shx * (sx + .5) / quants - shy * (sy + .5) / quants;
final double db = (bx - by) / (double) quantb;
final double val = 1. - FastMath.sqrt((db * db + sin * sin + cos * cos) / 5);
m[x][y] = m[y][x] = val;
}
}
return m;

