long index = entry.getKey();
if (index >= entryIndex) {
entry.getValue().setResult(new LeaderDemotedException(localMember, state.leader()));
iterator.remove();
count++;
}
}
if (count > 0) {
logger.warning("Invalidated " + count + " futures from log index: " + entryIndex);
}

