public void unpark(Notifier notifier, WaitNotifyKey key) WaitSetEntry entry = queue.peek();
while (entry != null) {
Operation op = entry.getOperation();
if (notifier == op) {
throw new IllegalStateException("Found cyclic wait-notify! -> " + notifier);
}
if (entry.isValid()) {
if (entry.isExpired()) {
entry.onExpire();
} else if (entry.isCancelled()) {
entry.onCancel();
} else {
if (entry.shouldWait()) {
return;
}
OperationService operationService = nodeEngine.getOperationService();
operationService.run(op);
}
entry.setValid(false);
}
queue.poll();
entry = queue.peek();
if (entry == null) {
waitSetMap.remove(key);
}
}

