assert ((int) (toEntryIndex - fromEntryIndex)) >= 0 : "Int overflow! From: " + fromEntryIndex + ", to: " + toEntryIndex;
LogEntry[] entries = new LogEntry[(int) (toEntryIndex - fromEntryIndex + 1)];
