@SuppressWarnings("unchecked") public static Object coerceToSAM(Closure argument, Method method, Class clazz, boolean isInterface) if (argument!=null && clazz.isAssignableFrom(argument.getClass())) {
return argument;
}
if (isInterface) {
if (Traits.isTrait(clazz)) {
Map<String,Closure> impl = Collections.singletonMap(
method.getName(),
argument
);
return ProxyGenerator.INSTANCE.instantiateAggregate(impl,Collections.singletonList(clazz));
}
return Proxy.newProxyInstance(
clazz.getClassLoader(),
new Class[]{clazz},
new ConvertedClosure(argument));
} else {
Map<String, Object> m = new HashMap<String,Object>();
m.put(method.getName(), argument);
return ProxyGenerator.INSTANCE.
instantiateAggregateFromBaseClass(m, clazz);
}

public static <T> Collection<T> dropRight(Iterable<T> self, int num) Collection<T> selfCol = self instanceof Collection ? (Collection<T>) self : toList(self);
if (selfCol.size() <= num) {
return createSimilarCollection(selfCol, 0);
}
if (num <= 0) {
Collection<T> ret = createSimilarCollection(selfCol, selfCol.size());
ret.addAll(selfCol);
return ret;
}
Collection<T> ret = createSimilarCollection(selfCol, selfCol.size() - num);
ret.addAll(asList((Iterable<T>)selfCol).subList(0, selfCol.size() - num));
return ret;

public static <T> Collection<T> tail(Iterable<T> self) if (!self.iterator().hasNext()) {
throw new NoSuchElementException("Cannot access tail() for an empty iterable");
}
Collection<T> result = createSimilarCollection(self);
addAll(result, tail(self.iterator()));
return result;

public static <T> Collection<T> init(Iterable<T> self) if (!self.iterator().hasNext()) {
throw new NoSuchElementException("Cannot access init() for an empty Iterable");
}
Collection<T> result;
if (self instanceof Collection) {
Collection<T> selfCol = (Collection<T>) self;
result = createSimilarCollection(selfCol, selfCol.size() - 1);
} else {
result = new ArrayList<T>();
}
addAll(result, init(self.iterator()));
return result;

