data.add(stereo);
}
if( !matcher.process(data) )
return false;
Se3_F64 keyToCurr = matcher.getModelParameters();
keyToCurr.invert(currToKey);
int N = matcher.getMatchSet().size();
for( int i = 0; i < N; i++ ) {
