protected void detectionCascade( FastQueue<ImageRectangle> cascadeRegions ) success = false;
ambiguous = false;
best = null;
candidateDetections.reset();
localMaximums.reset();
ambiguousRegions.clear();
storageMetric.reset();
storageIndexes.reset();
storageRect.clear();
fernRegions.clear();
fernInfo.reset();
int totalP = 0;
int totalN = 0;
TldRegionFernInfo info = fernInfo.grow();
for( int i = 0; i < cascadeRegions.size; i++ ) {
ImageRectangle region = cascadeRegions.get(i);
if( !variance.checkVariance(region)) {
continue;
}
info.r = region;
if( fern.lookupFernPN(info)) {
totalP += info.sumP;
totalN += info.sumN;
info = fernInfo.grow();
}
}
fernInfo.removeTail();
if( totalP > 0x0fffffff)
fern.renormalizeP();
if( totalN > 0x0fffffff)
fern.renormalizeN();
selectBestRegionsFern(totalP, totalN);
computeTemplateConfidence();
if( candidateDetections.size == 0 ) {
return;
}
nonmax.process(candidateDetections, localMaximums);
best = selectBest();
if( best != null ) {
ambiguous = checkAmbiguous(best);
success = true;
}

boolean orderNodes( FastQueue<Node> corners , GridInfo info ) Node seed = null;
for (int i = 0; i < corners.size; i++) {
Node n = corners.get(i);
if( n.countEdges() == 2 ) {
seed = n;
break;
}
}
if( seed == null ) {
if( verbose != null ) verbose.println("Can't find a corner with just two edges. Aborting");
return false;
}
int rowEdge = 0;
while( seed.edges[rowEdge] == null )
rowEdge = (rowEdge+1)%4;
int colEdge = (rowEdge+1)%4;
while( seed.edges[colEdge] == null )
colEdge = (colEdge+2)%4;
if( !isRightHanded(seed,rowEdge,colEdge)) {
int tmp = rowEdge;
rowEdge = colEdge;
colEdge = tmp;
}
while( seed != null ) {
int before = info.nodes.size();
Node n = seed;
do {
info.nodes.add(n);
n = n.edges[colEdge];
} while( n != null );
seed = seed.edges[rowEdge];
if( info.cols == -1 ) {
info.cols = info.nodes.size();
} else {
int columnsInRow = info.nodes.size()-before;
if( columnsInRow != info.cols ) {
if( verbose != null ) verbose.println("Number of columns in each row is variable");
return false;
}
}
}
info.rows = info.nodes.size()/info.cols;
return true;

