public CmsAccessControlEntry toAccessControlEntry(CmsObject cms, CmsUUID resID) CmsUUID id = null;
if (isRealPrinciple()) {
if (CmsRole.PRINCIPAL_ROLE.equals(m_principalType)) {
CmsRole role = CmsRole.valueOfRoleName(m_principalName);
if (role != null) {
id = role.getId();
}
} else {
try {
id = CmsPrincipal.readPrincipal(cms, m_principalName).getId();
} catch (CmsException e) {
}
}
} else {
if (m_principalName.equals(CmsAccessControlEntry.PRINCIPAL_ALL_OTHERS_NAME)) {
id = CmsAccessControlEntry.PRINCIPAL_ALL_OTHERS_ID;
}
if (m_principalName.equals(CmsAccessControlEntry.PRINCIPAL_OVERWRITE_ALL_NAME)) {
id = CmsAccessControlEntry.PRINCIPAL_OVERWRITE_ALL_ID;
}
}
if (m_permissionString == null) {
return new CmsAccessControlEntry(resID, id, m_allowed, m_denied, m_flags);
}
CmsAccessControlEntry entry = new CmsAccessControlEntry(resID, id, m_permissionString);
return entry;

private static void addGeometricConfiguration(IDoubleBondStereochemistry dbs, int flavour, GraphBuilder gb, Map<IAtom, Integer> indices) IBond db = dbs.getStereoBond();
IBond[] bs = dbs.getBonds();
if (SmiFlavor.isSet(flavour, SmiFlavor.UseAromaticSymbols) && db.getFlag(CDKConstants.ISAROMATIC)) return;
int u = indices.get(db.getBegin());
int v = indices.get(db.getEnd());
int x = indices.get(bs[0].getOther(db.getBegin()));
int y = indices.get(bs[1].getOther(db.getEnd()));
if (dbs.getStereo() == TOGETHER) {
gb.geometric(u, v).together(x, y);
} else {
gb.geometric(u, v).opposite(x, y);
}

static Atom toBeamAtom(final IAtom a, final int flavour) final boolean aromatic = SmiFlavor.isSet(flavour, SmiFlavor.UseAromaticSymbols) && a.getFlag(CDKConstants.ISAROMATIC);
final Integer charge = a.getFormalCharge();
final String symbol = checkNotNull(a.getSymbol(), "An atom had an undefined symbol");
Element element = Element.ofSymbol(symbol);
if (element == null) element = Element.Unknown;
AtomBuilder ab = aromatic ? AtomBuilder.aromatic(element) : AtomBuilder.aliphatic(element);
Integer hCount = a.getImplicitHydrogenCount();
if (element == Element.Unknown) {
ab.hydrogens(hCount != null ? hCount : 0);
} else {
ab.hydrogens(checkNotNull(hCount, "One or more atoms had an undefined number of implicit hydrogens"));
}
if (charge != null) ab.charge(charge);
if (SmiFlavor.isSet(flavour, SmiFlavor.AtomicMass | SmiFlavor.AtomicMassStrict)) {
Integer massNumber = a.getMassNumber();
if (massNumber != null) {
ab.isotope(massNumber);
}
}
Integer atomClass = a.getProperty(ATOM_ATOM_MAPPING);
if (SmiFlavor.isSet(flavour, SmiFlavor.AtomAtomMap) && atomClass != null) {
ab.atomClass(atomClass);
}
return ab.build();

private static Bond toBeamEdgeLabel(IBond b, int flavour) throws CDKException if (SmiFlavor.isSet(flavour, SmiFlavor.UseAromaticSymbols) && b.isAromatic()) {
if (!b.getBegin().isAromatic() || !b.getEnd().isAromatic())
throw new IllegalStateException("Aromatic bond connects non-aromatic atomic atoms");
return Bond.AROMATIC;
}
if (b.getOrder() == null) throw new CDKException("A bond had undefined order, possible query bond?");
IBond.Order order = b.getOrder();
switch (order) {
case SINGLE:
return Bond.SINGLE;
case DOUBLE:
return Bond.DOUBLE;
case TRIPLE:
return Bond.TRIPLE;
case QUADRUPLE:
return Bond.QUADRUPLE;
default:
if (!SmiFlavor.isSet(flavour, SmiFlavor.UseAromaticSymbols) && b.isAromatic())
throw new CDKException("Cannot write Kekulé SMILES output due to aromatic bond with unset bond order - molecule should be Kekulized");
throw new CDKException("Unsupported bond order: " + order);
}

private static void addExtendedTetrahedralConfiguration(ExtendedTetrahedral et, GraphBuilder gb, Map<IAtom, Integer> indices) IAtom[] ligands = et.peripherals();
int u = indices.get(et.focus());
int vs[] = new int[]{indices.get(ligands[0]), indices.get(ligands[1]), indices.get(ligands[2]),
indices.get(ligands[3])};
gb.extendedTetrahedral(u).lookingFrom(vs[0]).neighbors(vs[1], vs[2], vs[3])
.winding(et.winding() == CLOCKWISE ? Configuration.CLOCKWISE : Configuration.ANTI_CLOCKWISE).build();

private static void addTetrahedralConfiguration(ITetrahedralChirality tc, GraphBuilder gb, Map<IAtom, Integer> indices) IAtom[] ligands = tc.getLigands();
int u = indices.get(tc.getChiralAtom());
int vs[] = new int[]{indices.get(ligands[0]), indices.get(ligands[1]), indices.get(ligands[2]),
indices.get(ligands[3])};
gb.tetrahedral(u).lookingFrom(vs[0]).neighbors(vs[1], vs[2], vs[3])
.winding(tc.getStereo() == CLOCKWISE ? Configuration.CLOCKWISE : Configuration.ANTI_CLOCKWISE).build();

private static int[] indexElements(Map<IAtom, Integer> map, IStereoElement[] elements, Type[] types, IAtomContainer container) int[] indices = new int[container.getAtomCount()];
int nElements = 0;
for (IStereoElement element : container.stereoElements()) {
if (element instanceof ITetrahedralChirality) {
ITetrahedralChirality tc = (ITetrahedralChirality) element;
int idx = map.get(tc.getChiralAtom());
elements[idx] = element;
types[idx] = Type.Tetrahedral;
indices[nElements++] = idx;
} else if (element instanceof IDoubleBondStereochemistry) {
IDoubleBondStereochemistry dbs = (IDoubleBondStereochemistry) element;
int idx1 = map.get(dbs.getStereoBond().getBegin());
int idx2 = map.get(dbs.getStereoBond().getEnd());
elements[idx2] = elements[idx1] = element;
types[idx1] = types[idx2] = Type.Geometric;
indices[nElements++] = idx1;
}
}
return Arrays.copyOf(indices, nElements);

IAtomContainer toAtomContainer(Graph g, boolean kekule) IAtomContainer ac    = emptyContainer();
int            numAtoms = g.order();
IAtom[]        atoms = new IAtom[numAtoms];
IBond[]        bonds = new IBond[g.size()];
int j = 0;
boolean checkAtomStereo = false;
boolean checkBondStereo = false;
for (int i = 0; i < g.order(); i++) {
checkAtomStereo = checkAtomStereo || g.configurationOf(i).type() != Configuration.Type.None;
atoms[i] = toCDKAtom(g.atom(i), g.implHCount(i));
}
ac.setAtoms(atoms);
for (int i = 0; i < g.order(); i++)
atoms[i] = ac.getAtom(i);
for (Edge edge : g.edges()) {
final int u = edge.either();
final int v = edge.other(u);
IBond bond = builder.newBond();
bond.setAtoms(new IAtom[]{atoms[u], atoms[v]});
bonds[j++] = bond;
switch (edge.bond()) {
case SINGLE:
bond.setOrder(IBond.Order.SINGLE);
break;
case UP:
case DOWN:
checkBondStereo = true;
bond.setOrder(IBond.Order.SINGLE);
break;
case IMPLICIT:
bond.setOrder(IBond.Order.SINGLE);
if (!kekule && atoms[u].isAromatic() && atoms[v].isAromatic()) {
bond.setIsAromatic(true);
bond.setOrder(IBond.Order.UNSET);
atoms[u].setIsAromatic(true);
atoms[v].setIsAromatic(true);
}
break;
case IMPLICIT_AROMATIC:
case AROMATIC:
bond.setOrder(IBond.Order.SINGLE);
bond.setIsAromatic(true);
atoms[u].setIsAromatic(true);
atoms[v].setIsAromatic(true);
break;
case DOUBLE:
bond.setOrder(IBond.Order.DOUBLE);
break;
case DOUBLE_AROMATIC:
bond.setOrder(IBond.Order.DOUBLE);
bond.setIsAromatic(true);
atoms[u].setIsAromatic(true);
atoms[v].setIsAromatic(true);
break;
case TRIPLE:
bond.setOrder(IBond.Order.TRIPLE);
break;
case QUADRUPLE:
bond.setOrder(IBond.Order.QUADRUPLE);
break;
default:
throw new IllegalArgumentException("Edge label " + edge.bond()
+ "cannot be converted to a CDK bond order");
}
}
if (checkAtomStereo) {
for (int u = 0; u < g.order(); u++) {
Configuration c = g.configurationOf(u);
switch (c.type()) {
case Tetrahedral: {
IStereoElement se = newTetrahedral(u, g.neighbors(u), atoms, c);
if (se != null) ac.addStereoElement(se);
break;
}
case ExtendedTetrahedral: {
IStereoElement se = newExtendedTetrahedral(u, g, atoms);
if (se != null) ac.addStereoElement(se);
break;
}
case DoubleBond: {
checkBondStereo = true;
break;
}
case SquarePlanar: {
IStereoElement se = newSquarePlanar(u, g.neighbors(u), atoms, c);
if (se != null) ac.addStereoElement(se);
break;
}
case TrigonalBipyramidal: {
IStereoElement se = newTrigonalBipyramidal(u, g.neighbors(u), atoms, c);
if (se != null) ac.addStereoElement(se);
break;
}
case Octahedral: {
IStereoElement se = newOctahedral(u, g.neighbors(u), atoms, c);
if (se != null) ac.addStereoElement(se);
break;
}
}
}
}
ac.setBonds(bonds);
if (checkBondStereo) {
addDoubleBondStereochemistry(g, ac);
}
ac.setTitle(g.getTitle());
return ac;

@Override public StereoEncoder create(IAtomContainer container, int[][] graph) Map<IAtom, Integer> atomToIndex = null;
List<StereoEncoder> encoders = new ArrayList<StereoEncoder>();
for (IStereoElement se : container.stereoElements()) {
if (se instanceof IDoubleBondStereochemistry) {
encoders.add(encoder((IDoubleBondStereochemistry) se, atomToIndex = indexMap(atomToIndex, container),
graph));
}
}
return encoders.isEmpty() ? StereoEncoder.EMPTY : new MultiStereoEncoder(encoders);

public static IAtomContainer suppressHydrogens(IAtomContainer org) boolean anyHydrogenPresent = false;
for (IAtom atom : org.atoms()) {
if ("H".equals(atom.getSymbol())) {
anyHydrogenPresent = true;
break;
}
}
if (!anyHydrogenPresent)
return org;
Set<IAtom>         xatoms  = Collections.emptySet();
Collection<Sgroup> sgroups = org.getProperty(CDKConstants.CTAB_SGROUPS);
if (sgroups != null) {
xatoms = new HashSet<>();
for (Sgroup sgroup : sgroups) {
for (IBond bond : sgroup.getBonds()) {
xatoms.add(bond.getBegin());
xatoms.add(bond.getEnd());
}
}
}
GraphUtil.EdgeToBondMap bondmap = GraphUtil.EdgeToBondMap.withSpaceFor(org);
final int[][] graph = GraphUtil.toAdjList(org, bondmap);
final int nOrgAtoms = org.getAtomCount();
final int nOrgBonds = org.getBondCount();
int nCpyAtoms = 0;
int nCpyBonds = 0;
final Set<IAtom> hydrogens        = new HashSet<IAtom>(nOrgAtoms);
final Set<IBond> bondsToHydrogens = new HashSet<IBond>();
final IAtom[] cpyAtoms = new IAtom[nOrgAtoms];
for (int v = 0; v < nOrgAtoms; v++) {
final IAtom atom = org.getAtom(v);
if (suppressibleHydrogen(org, graph, bondmap, v) &&
!xatoms.contains(atom)) {
hydrogens.add(atom);
incrementImplHydrogenCount(org.getAtom(graph[v][0]));
} else {
cpyAtoms[nCpyAtoms++] = atom;
}
}
if (hydrogens.isEmpty()) return org;
IBond[] cpyBonds = new IBond[nOrgBonds - hydrogens.size()];
int remaining = hydrogens.size();
for (final IBond bond : org.bonds()) {
if (remaining > 0 && (hydrogens.contains(bond.getBegin()) || hydrogens.contains(bond.getEnd()))) {
bondsToHydrogens.add(bond);
remaining--;
continue;
}
cpyBonds[nCpyBonds++] = bond;
}
if (nCpyBonds != cpyBonds.length)
throw new IllegalArgumentException("number of removed bonds was less than the number of removed hydrogens");
List<IStereoElement> elements = new ArrayList<IStereoElement>();
for (IStereoElement se : org.stereoElements()) {
if (se instanceof ITetrahedralChirality) {
ITetrahedralChirality tc = (ITetrahedralChirality) se;
IAtom focus = tc.getChiralAtom();
IAtom[] neighbors = tc.getLigands();
boolean updated = false;
for (int i = 0; i < neighbors.length; i++) {
if (hydrogens.contains(neighbors[i])) {
neighbors[i] = focus;
updated = true;
}
}
if (!updated) {
elements.add(tc);
} else {
elements.add(new TetrahedralChirality(focus, neighbors, tc.getStereo()));
}
} else if (se instanceof ExtendedTetrahedral) {
ExtendedTetrahedral tc = (ExtendedTetrahedral) se;
IAtom   focus    = tc.getFocus();
IAtom[] carriers = tc.getCarriers().toArray(new IAtom[4]);
IAtom[] ends     = ExtendedTetrahedral.findTerminalAtoms(org, focus);
boolean updated = false;
for (int i = 0; i < carriers.length; i++) {
if (hydrogens.contains(carriers[i])) {
if (org.getBond(carriers[i], ends[0]) != null)
carriers[i] = ends[0];
else
carriers[i] = ends[1];
updated = true;
}
}
if (!updated) {
elements.add(tc);
} else {
elements.add(new ExtendedTetrahedral(focus, carriers, tc.getConfigOrder()));
}
} else if (se instanceof IDoubleBondStereochemistry) {
IDoubleBondStereochemistry db = (IDoubleBondStereochemistry) se;
Conformation conformation = db.getStereo();
IBond orgStereo = db.getStereoBond();
IBond orgLeft = db.getBonds()[0];
IBond orgRight = db.getBonds()[1];
IAtom u = orgStereo.getBegin();
IAtom v = orgStereo.getEnd();
IAtom x = orgLeft.getOther(u);
IAtom y = orgRight.getOther(v);
IAtom xNew = x;
IAtom yNew = y;
if (hydrogens.contains(x)) {
conformation = conformation.invert();
xNew = findSingleBond(org, u, x);
}
if (hydrogens.contains(y)) {
conformation = conformation.invert();
yNew = findSingleBond(org, v, y);
}
if (x == null || y == null ||
xNew == null || yNew == null) continue;
if (x.equals(xNew) && y.equals(yNew)) {
elements.add(db);
continue;
}
IBond cpyLeft  = !Objects.equals(xNew, x) ? org.getBond(u, xNew) : orgLeft;
IBond cpyRight = !Objects.equals(yNew, y) ? org.getBond(v, yNew) : orgRight;
elements.add(new DoubleBondStereochemistry(orgStereo,
new IBond[]{cpyLeft, cpyRight},
conformation));
} else if (se instanceof ExtendedCisTrans) {
ExtendedCisTrans db = (ExtendedCisTrans) se;
int config = db.getConfigOrder();
IBond focus     = db.getFocus();
IBond orgLeft   = db.getCarriers().get(0);
IBond orgRight  = db.getCarriers().get(1);
IAtom[] ends = ExtendedCisTrans.findTerminalAtoms(org, focus);
IAtom u = ends[0];
IAtom v = ends[1];
IAtom x = orgLeft.getOther(u);
IAtom y = orgRight.getOther(v);
IAtom xNew = x;
IAtom yNew = y;
if (hydrogens.contains(x)) {
config ^= 0x3;
xNew = findSingleBond(org, u, x);
}
if (hydrogens.contains(y)) {
config ^= 0x3;
yNew = findSingleBond(org, v, y);
}
if (x == null || y == null ||
xNew == null || yNew == null) continue;
if (x.equals(xNew) && y.equals(yNew)) {
elements.add(db);
continue;
}
IBond cpyLeft  = !Objects.equals(xNew, x) ? org.getBond(u, xNew) : orgLeft;
IBond cpyRight = !Objects.equals(yNew, y) ? org.getBond(v, yNew) : orgRight;
elements.add(new ExtendedCisTrans(focus,
new IBond[]{cpyLeft, cpyRight},
config));
} else if (se instanceof Atropisomeric) {
elements.add(se);
}
}
org.setAtoms(Arrays.copyOf(cpyAtoms, nCpyAtoms));
org.setBonds(cpyBonds);
org.setStereoElements(elements);
if (org.getSingleElectronCount() > 0) {
Set<ISingleElectron> remove = new HashSet<ISingleElectron>();
for (ISingleElectron se : org.singleElectrons()) {
if (hydrogens.contains(se.getAtom())) remove.add(se);
}
for (ISingleElectron se : remove) {
org.removeSingleElectron(se);
}
}
if (org.getLonePairCount() > 0) {
Set<ILonePair> remove = new HashSet<ILonePair>();
for (ILonePair lp : org.lonePairs()) {
if (hydrogens.contains(lp.getAtom())) remove.add(lp);
}
for (ILonePair lp : remove) {
org.removeLonePair(lp);
}
}
if (sgroups != null) {
for (Sgroup sgroup : sgroups) {
if (sgroup.getValue(SgroupKey.CtabParentAtomList) != null) {
Collection<IAtom> pal = sgroup.getValue(SgroupKey.CtabParentAtomList);
pal.removeAll(hydrogens);
}
for (IAtom hydrogen : hydrogens)
sgroup.removeAtom(hydrogen);
for (IBond bondToHydrogen : bondsToHydrogens)
sgroup.removeBond(bondToHydrogen);
}
}
return org;

public static IReaction toReaction(IAtomContainer mol) if (mol == null)
throw new IllegalArgumentException("Null molecule provided");
final IChemObjectBuilder bldr = mol.getBuilder();
final IReaction          rxn  = bldr.newInstance(IReaction.class);
rxn.setProperties(mol.getProperties());
rxn.setID(mol.getID());
Map<Integer,IAtomContainer> components = new HashMap<>();
for (IAtom atom : mol.atoms()) {
ReactionRole role   = atom.getProperty(CDKConstants.REACTION_ROLE);
Integer      grpIdx = atom.getProperty(CDKConstants.REACTION_GROUP);
if (role == null || role == ReactionRole.None)
throw new IllegalArgumentException("Atom " + mol.indexOf(atom) + " had undefined role");
if (grpIdx == null)
throw new IllegalArgumentException("Atom " + mol.indexOf(atom) + " had no reaction group id");
IAtomContainer comp = components.get(grpIdx);
if (comp == null) {
components.put(grpIdx, comp = bldr.newInstance(IAtomContainer.class, 20, 20, 0, 0));
switch (role) {
case Reactant:
rxn.addReactant(comp);
break;
case Product:
rxn.addProduct(comp);
break;
case Agent:
rxn.addAgent(comp);
break;
}
}
comp.addAtom(atom);
}
for (IBond bond : mol.bonds()) {
IAtom beg = bond.getBegin();
IAtom end = bond.getEnd();
Integer begIdx = beg.getProperty(CDKConstants.REACTION_GROUP);
Integer endIdx = end.getProperty(CDKConstants.REACTION_GROUP);
if (begIdx == null || endIdx == null)
throw new IllegalArgumentException("Bond " + mol.indexOf(bond) + " had atoms with no reaction group id");
if (!begIdx.equals(endIdx))
throw new IllegalArgumentException("Bond " + mol.indexOf(bond) + " had atoms with different reaction group id");
components.get(begIdx).addBond(bond);
}
for (IStereoElement se : mol.stereoElements()) {
IAtom focus = null;
if (se instanceof ITetrahedralChirality) {
focus = ((ITetrahedralChirality) se).getChiralAtom();
} else if (se instanceof IDoubleBondStereochemistry) {
focus = ((IDoubleBondStereochemistry) se).getStereoBond().getBegin();
} else if (se instanceof ExtendedTetrahedral) {
focus = ((ExtendedTetrahedral) se).focus();
}
if (focus == null)
throw new IllegalArgumentException("Stereochemistry had no focus");
Integer grpIdx = focus.getProperty(CDKConstants.REACTION_GROUP);
components.get(grpIdx).addStereoElement(se);
}
for (ISingleElectron se : mol.singleElectrons()) {
Integer grpIdx = se.getAtom().getProperty(CDKConstants.REACTION_GROUP);
components.get(grpIdx).addSingleElectron(se);
}
for (ILonePair lp : mol.lonePairs()) {
Integer grpIdx = lp.getAtom().getProperty(CDKConstants.REACTION_GROUP);
components.get(grpIdx).addLonePair(lp);
}
return rxn;

protected Integer getFontSizeForZoom(double zoom) double lower = -1;
for (double upper : this.zoomToFontSizeMap.keySet()) {
if (lower == -1) {
lower = upper;
if (zoom <= lower) return this.zoomToFontSizeMap.get(upper);
continue;
}
if (zoom > lower && zoom <= upper) {
return this.zoomToFontSizeMap.get(upper);
}
lower = upper;
}
return this.zoomToFontSizeMap.get(lower);

protected void setupTransformNatural(Rectangle2D modelBounds) double zoom = rendererModel.getParameter(ZoomFactor.class).getValue();
this.fontManager.setFontForZoom(zoom);
this.setup();

@Override protected void makeFonts() int size = this.minFontSize;
double scale = 0.5;
this.fontSizeToFontMap = new HashMap<Integer, Font>();
for (int i = 0; i < 20; i++) {
if (super.getFontStyle() == IFontManager.FontStyle.NORMAL) {
this.fontSizeToFontMap.put(size, new Font(super.getFontName(), Font.PLAIN, size));
} else {
this.fontSizeToFontMap.put(size, new Font(super.getFontName(), Font.BOLD, size));
}
this.registerFontSizeMapping(scale, size);
size += 1;
scale += 0.1;
}

public void setZoomToFit(double drawWidth, double drawHeight, double diagramWidth, double diagramHeight) double margin = rendererModel.getParameter(Margin.class).getValue();
double widthRatio = drawWidth / (diagramWidth + (2 * margin));
double heightRatio = drawHeight / (diagramHeight + (2 * margin));
double zoom = Math.min(widthRatio, heightRatio);
this.fontManager.setFontForZoom(zoom);
rendererModel.getParameter(ZoomFactor.class).setValue(zoom);

protected void setup() double scale = rendererModel.getParameter(Scale.class).getValue();
double zoom = rendererModel.getParameter(ZoomFactor.class).getValue();
try {
transform = new AffineTransform();
transform.translate(drawCenter.x, drawCenter.y);
transform.scale(1, -1);
transform.scale(scale, scale);
transform.scale(zoom, zoom);
transform.translate(-this.modelCenter.x, -this.modelCenter.y);
} catch (NullPointerException npe) {
String errorString = "null pointer when setting transform: "
+ "drawCenter=%s scale=%s zoom=%s modelCenter=%s";
System.err.println(String.format(errorString, drawCenter, scale, zoom, modelCenter));
}

public Rectangle calculateScreenBounds(Rectangle2D modelBounds) double scale = rendererModel.getParameter(Scale.class).getValue();
double zoom = rendererModel.getParameter(ZoomFactor.class).getValue();
double margin = rendererModel.getParameter(Margin.class).getValue();
Point2d modelScreenCenter = this.toScreenCoordinates(modelBounds.getCenterX(), modelBounds.getCenterY());
double width = (scale * zoom * modelBounds.getWidth()) + (2 * margin);
double height = (scale * zoom * modelBounds.getHeight()) + (2 * margin);
return new Rectangle((int) (modelScreenCenter.x - width / 2), (int) (modelScreenCenter.y - height / 2),
(int) width, (int) height);

@Override public int[][] fused() List<int[]> fused = new ArrayList<int[]>(cycles.size());
for (int i = 0; i < cycles.size(); i++) {
if (this.fused.get(i)) fused.add(toArray(cycles.get(i)));
}
return fused.toArray(new int[fused.size()][]);

protected Rectangle convertToDiagramBounds(Rectangle2D modelBounds) double xCenter = modelBounds.getCenterX();
double yCenter = modelBounds.getCenterY();
double modelWidth = modelBounds.getWidth();
double modelHeight = modelBounds.getHeight();
double scale = rendererModel.getParameter(Scale.class).getValue();
double zoom = rendererModel.getParameter(ZoomFactor.class).getValue();
Point2d screenCoord = this.toScreenCoordinates(xCenter, yCenter);
if (modelWidth == 0 && modelHeight == 0) {
return new Rectangle((int) screenCoord.x, (int) screenCoord.y, 0, 0);
}
double margin = rendererModel.getParameter(Margin.class).getValue();
int width = (int) ((scale * zoom * modelWidth) + (2 * margin));
int height = (int) ((scale * zoom * modelHeight) + (2 * margin));
int xCoord = (int) (screenCoord.x - width / 2);
int yCoord = (int) (screenCoord.y - height / 2);
return new Rectangle(xCoord, yCoord, width, height);

public Permutation toPermutation() Permutation p = new Permutation(this.size());
for (int i = 0; i < this.size(); i++) {
p.set(i, this.cells.get(i).first());
}
return p;

protected final void draw(IDrawVisitor visitor, double zoom, Bounds bounds, Rectangle2D viewBounds) double modelScale = zoom * model.get(BasicSceneGenerator.Scale.class);
double zoomToFit = Math.min(viewBounds.getWidth() / (bounds.width() * modelScale),
viewBounds.getHeight() / (bounds.height() * modelScale));
AffineTransform transform = new AffineTransform();
transform.translate(viewBounds.getCenterX(), viewBounds.getCenterY());
transform.scale(modelScale, -modelScale);
if (model.get(BasicSceneGenerator.FitToScreen.class) || zoomToFit < 1)
transform.scale(zoomToFit, zoomToFit);
transform.translate(-(bounds.minX + bounds.maxX) / 2,
