protected static <A> int[] sortedIndex(final NumberArrayAdapter<?, A> adapter, final A data, int len) int[] s1 = MathUtil.sequence(0, len);
IntegerArrayQuickSort.sort(s1, (x, y) -> Double.compare(adapter.getDouble(data, x), adapter.getDouble(data, y)));
return s1;

protected static <A> double[] computeNormalizedRanks(final NumberArrayAdapter<?, A> adapter, final A data, int len) int[] s1 = sortedIndex(adapter, data, len);
final double norm = .5 / (len - 1);
double[] ret = new double[len];
for(int i = 0; i < len;) {
final int start = i++;
final double val = adapter.getDouble(data, s1[start]);
while(i < len && adapter.getDouble(data, s1[i]) <= val) {
i++;
}
final double score = (start + i - 1) * norm;
for(int j = start; j < i; j++) {
ret[s1[j]] = score;
}
}
return ret;

protected static <A> int[] discretize(NumberArrayAdapter<?, A> adapter, A data, final int len, final int bins) double min = adapter.getDouble(data, 0), max = min;
for(int i = 1; i < len; i++) {
double v = adapter.getDouble(data, i);
if(v < min) {
min = v;
}
else if(v > max) {
max = v;
}
}
final double scale = (max > min) ? bins / (max - min) : 1;
int[] discData = new int[len];
for(int i = 0; i < len; i++) {
int bin = (int) Math.floor((adapter.getDouble(data, i) - min) * scale);
discData[i] = bin < 0 ? 0 : bin >= bins ? bins - 1 : bin;
}
return discData;

protected static <A> double[] ranks(final NumberArrayAdapter<?, A> adapter, final A data, int[] idx) final int len = idx.length;
double[] ret = new double[len];
for(int i = 0; i < len;) {
final int start = i++;
final double val = adapter.getDouble(data, idx[start]);
while(i < len && adapter.getDouble(data, idx[i]) <= val) {
i++;
}
final double score = (start + i - 1) * .5 + 1;
for(int j = start; j < i; j++) {
ret[idx[j]] = score;
}
}
return ret;

public static <A> double[] toPrimitiveDoubleArray(A array, NumberArrayAdapter<?, ? super A> adapter) if (adapter == DOUBLEARRAYADAPTER) {
return ((double[]) array).clone();
}
double[] ret = new double[adapter.size(array)];
for (int i = 0; i < ret.length; i++) {
ret[i] = adapter.getDouble(array, i);
}
return ret;

protected static <A> double[] computeDistances(NumberArrayAdapter<?, A> adapter, A data) final int size = adapter.size(data);
double[] dMatrix = new double[(size * (size + 1)) >> 1];
for(int i = 0, c = 0; i < size; i++) {
for(int j = 0; j < i; j++) {
double dx = adapter.getDouble(data, i) - adapter.getDouble(data, j);
dMatrix[c++] = (dx < 0) ? -dx : dx;
}
c++;
}
doubleCenterMatrix(dMatrix, size);
return dMatrix;

public static <A> double[] alphaPWM(A data, NumberArrayAdapter<?, A> adapter, final int nmom) final int n = adapter.size(data);
final double[] xmom = new double[nmom];
double weight = 1. / n;
for(int i = 0; i < n; i++) {
final double val = adapter.getDouble(data, i);
xmom[0] += weight * val;
for(int j = 1; j < nmom; j++) {
weight *= (n - i - j + 1) / (n - j + 1);
xmom[j] += weight * val;
}
}
return xmom;

public static <A> double[] alphaBetaPWM(A data, NumberArrayAdapter<?, A> adapter, final int nmom) final int n = adapter.size(data);
final double[] xmom = new double[nmom << 1];
double aweight = 1. / n, bweight = aweight;
for(int i = 0; i < n; i++) {
final double val = adapter.getDouble(data, i);
xmom[0] += aweight * val;
xmom[1] += bweight * val;
for(int j = 1, k = 2; j < nmom; j++, k += 2) {
aweight *= (n - i - j + 1) / (n - j + 1);
bweight *= (i - j + 1) / (n - j + 1);
xmom[k + 1] += aweight * val;
xmom[k + 1] += bweight * val;
}
}
return xmom;

public static <A> int getIndexOfMaximum(A array, NumberArrayAdapter<?, A> adapter) throws IndexOutOfBoundsException final int size = adapter.size(array);
int index = 0;
double max = adapter.getDouble(array, 0);
for (int i = 1; i < size; i++) {
double val = adapter.getDouble(array, i);
if (val > max) {
max = val;
index = i;
}
}
return index;

public static <T> void quickSelect(T data, Adapter<T> adapter, int start, int end, int rank) while(true) {
if(start + SMALL > end) {
insertionSort(data, adapter, start, end);
return;
}
final int len = end - start;
final int seventh = (len >> 3) + (len >> 6) + 1;
final int m3 = (start + end) >> 1;
final int m2 = m3 - seventh;
final int m1 = m2 - seventh;
final int m4 = m3 + seventh;
final int m5 = m4 + seventh;
if(adapter.compare(data, m1, m2) > 0) {
adapter.swap(data, m1, m2);
}
if(adapter.compare(data, m1, m3) > 0) {
adapter.swap(data, m1, m3);
}
if(adapter.compare(data, m2, m3) > 0) {
adapter.swap(data, m2, m3);
}
if(adapter.compare(data, m4, m5) > 0) {
adapter.swap(data, m4, m5);
}
if(adapter.compare(data, m1, m4) > 0) {
adapter.swap(data, m1, m4);
}
if(adapter.compare(data, m3, m4) > 0) {
adapter.swap(data, m3, m4);
}
if(adapter.compare(data, m2, m5) > 0) {
adapter.swap(data, m2, m5);
}
if(adapter.compare(data, m2, m3) > 0) {
adapter.swap(data, m2, m3);
}
if(adapter.compare(data, m4, m5) > 0) {
adapter.swap(data, m4, m5);
}
int best = bestPivot(rank, m1, m2, m3, m4, m5);
adapter.swap(data, best, end - 1);
int i = start, j = end - 2;
while(true) {
while(i <= j && adapter.compare(data, end - 1, i) >= 0) {
i++;
}
while(j >= i && adapter.compare(data, end - 1, j) <= 0) {
j--;
}
if(i >= j) {
break;
}
adapter.swap(data, i, j);
}
adapter.swap(data, i, end - 1);
while(rank < i && adapter.compare(data, i, i - 1) == 0) {
--i;
}
while(rank > i && adapter.compare(data, i, i + 1) == 0) {
++i;
}
if(rank < i) {
end = i;
}
else if(rank > i) {
start = i + 1;
}
else {
break;
}
}

