public void assignLabelsToPixels( GrayS32 pixelToRegions , GrowQueue_I32 regionMemberCount , FastQueue<float[]> regionColor ) regionColor.reset();
for( int i = 0; i < clusters.size(); i++ ) {
float[] r = regionColor.grow();
float[] c = clusters.get(i).color;
for( int j = 0; j < numBands; j++ ) {
r[j] = c[j];
}
}
regionMemberCount.resize(clusters.size());
regionMemberCount.fill(0);
int indexPixel = 0;
for( int y = 0; y < pixelToRegions.height; y++ ) {
int indexOutput = pixelToRegions.startIndex + y*pixelToRegions.stride;
for( int x =0; x < pixelToRegions.width; x++ , indexPixel++ , indexOutput++) {
Pixel p = pixels.data[indexPixel];
int best = -1;
float bestDistance = Float.MAX_VALUE;
for( int j = 0; j < p.clusters.size; j++ ) {
ClusterDistance d = p.clusters.data[j];
if( d.distance < bestDistance ) {
bestDistance = d.distance;
best = d.cluster.id;
}
}
if( best == -1 ) {
regionColor.grow();
best = regionMemberCount.size();
regionMemberCount.add(0);
}
pixelToRegions.data[indexOutput] = best;
regionMemberCount.data[best]++;
}
}

protected static Kernel1D_F32 derivative1D_F32(int order, double sigma, int radius, boolean normalize) Kernel1D_F32 ret = new Kernel1D_F32(radius * 2 + 1);
float[] gaussian = ret.data;
int index = 0;
switch( order ) {
case 1:
for (int i = radius; i >= -radius; i--) {
gaussian[index++] = (float) UtilGaussian.derivative1(0, sigma, i);
}
break;
case 2:
for (int i = radius; i >= -radius; i--) {
gaussian[index++] = (float) UtilGaussian.derivative2(0, sigma, i);
}
break;
case 3:
for (int i = radius; i >= -radius; i--) {
gaussian[index++] = (float) UtilGaussian.derivative3(0, sigma, i);
}
break;
case 4:
for (int i = radius; i >= -radius; i--) {
gaussian[index++] = (float) UtilGaussian.derivative4(0, sigma, i);
}
break;
default:
throw new IllegalArgumentException("Only derivatives of order 1 to 4 are supported");
}
if( normalize ) {
double sum = 0;
for (int i = radius; i >= -radius; i--) {
sum += UtilGaussian.computePDF(0, sigma, i);
}
for (int i = 0; i < gaussian.length; i++) {
gaussian[i] /= sum;
}
}
return ret;

public static void vertical( GrayF32 src , GrayF32 dst ) if( src.height < dst.height )
throw new IllegalArgumentException("src height must be >= dst height");
if( src.width != dst.width )
throw new IllegalArgumentException("src width must equal dst width");
float scale = src.height/(float)dst.height;
for (int x = 0; x < dst.width; x++) {
int indexDst = dst.startIndex + x;
for (int y = 0; y < dst.height-1; y++) {
float srcY0 = y*scale;
float srcY1 = (y+1)*scale;
int isrcY0 = (int)srcY0;
int isrcY1 = (int)srcY1;
int index = src.getIndex(x,isrcY0);
float startWeight = (1.0f-(srcY0-isrcY0));
float start = src.data[index];
index += src.stride;
float middle = 0;
for( int i = isrcY0+1; i < isrcY1; i++ ) {
middle += src.data[index];
index += src.stride;
}
float endWeight = (srcY1%1);
float end = src.data[index];
dst.data[indexDst] = (float)((start*startWeight + middle + end*endWeight)/scale );
indexDst += dst.stride;
}
int y = dst.height-1;
float srcY0 = y*scale;
int isrcY0 = (int)srcY0;
int isrcY1 = src.height-1;
int index = src.getIndex(x,isrcY0);
float startWeight = (1.0f-(srcY0-isrcY0));
float start = src.data[index];
index += src.stride;
float middle = 0;
for( int i = isrcY0+1; i < isrcY1; i++ ) {
middle += src.data[index];
index += src.stride;
}
float end = isrcY1 != isrcY0 ? src.data[index]: 0;
dst.data[indexDst] = (float)((start*startWeight + middle + end)/scale );
}

public static void horizontal( GrayF32 src , GrayF32 dst ) if( src.width < dst.width )
throw new IllegalArgumentException("src width must be >= dst width");
if( src.height != dst.height )
throw new IllegalArgumentException("src height must equal dst height");
float scale = src.width/(float)dst.width;
for (int y = 0; y < dst.height; y++) {
int indexDst = dst.startIndex + y*dst.stride;
for (int x = 0; x < dst.width-1; x++, indexDst++ ) {
float srcX0 = x*scale;
float srcX1 = (x+1)*scale;
int isrcX0 = (int)srcX0;
int isrcX1 = (int)srcX1;
int index = src.getIndex(isrcX0,y);
float startWeight = (1.0f-(srcX0-isrcX0));
float start = src.data[index++];
float middle = 0;
for( int i = isrcX0+1; i < isrcX1; i++ ) {
middle += src.data[index++];
}
float endWeight = (srcX1%1);
float end = src.data[index];
dst.data[indexDst] = (start*startWeight + middle + end*endWeight)/scale;
}
int x = dst.width-1;
float srcX0 = x*scale;
int isrcX0 = (int)srcX0;
int isrcX1 = src.width-1;
int index = src.getIndex(isrcX0,y);
float startWeight = (1.0f-(srcX0-isrcX0));
float start = src.data[index++];
float middle = 0;
for( int i = isrcX0+1; i < isrcX1; i++ ) {
middle += src.data[index++];
}
float end = isrcX1 != isrcX0 ? src.data[index] : 0;
dst.data[indexDst] = (start*startWeight + middle + end)/scale;
}

public static float[] subbandAbsVal(GrayF32 subband, float[] coef ) if( coef == null ) {
coef = new float[subband.width*subband.height];
}
int i = 0;
for( int y = 0; y < subband.height; y++ ) {
int index = subband.startIndex + subband.stride*y;
int end = index + subband.width;
for( ;index < end; index++  ) {
coef[i++] = Math.abs(subband.data[index]);
}
}
return coef;

public static void normalize(GrayF32 image , float mean , float stdev ) for (int y = 0; y < image.height; y++) {
int index = image.startIndex + y*image.stride;
int end = index + image.width;
while( index < end ) {
image.data[index] = (image.data[index]-mean)/stdev;
index++;
}
}

public boolean abandonFile(String src, String holder ) throws IOException writeLock();
try {
if (NameNode.stateChangeLog.isDebugEnabled()) {
NameNode.stateChangeLog.debug("FILE* NameSystem.abandonFile: " + src);
}
if (isInSafeMode()) {
throw new SafeModeException("Cannot abandon file " + src, safeMode);
}
checkLease(src, holder);
internalReleaseLeaseOne(leaseManager.getLease(holder), src);
if (NameNode.stateChangeLog.isDebugEnabled()) {
NameNode.stateChangeLog.debug("FILE* NameSystem.abandonFile: "
+ " has been scheduled for lease recovery");
}
return true;
} finally {
writeUnlock();
}

synchronized Lease addLease(String holder, String src, long timestamp) Lease lease = getLease(holder);
if (lease == null) {
lease = new Lease(holder);
leases.put(holder, lease);
sortedLeases.add(lease);
} else {
renewLease(lease);
}
sortedLeasesByPath.put(src, new LeaseOpenTime(lease, timestamp));
lease.paths.add(src);
return lease;

boolean recoverLease(String src, String holder, String clientMachine, boolean discardLastBlock) throws IOException byte[][] components = INodeDirectory.getPathComponents(src);
writeLock();
try {
if (isInSafeMode()) {
throw new SafeModeException(
"Cannot recover the lease of " + src, safeMode);
}
INode inode = dir.getFileINode(components);
if (inode == null) {
throw new FileNotFoundException("File not found " + src);
}
if (!inode.isUnderConstruction()) {
return true;
}
if (isPermissionEnabled) {
INode[] inodes = dir.getExistingPathINodes(src);
if (isPermissionCheckingEnabled(inodes)) {
checkPathAccess(src, inodes, FsAction.WRITE);
}
}
return recoverLeaseInternal(inode, src, holder, clientMachine,
true, discardLastBlock);
} finally {
writeUnlock();
}

public List<FileStatusExtended> getRandomFileStats(double percent) readLock();
try {
List<FileStatusExtended> stats = new LinkedList<FileStatusExtended>();
for (INodeFile file : getRandomFiles(percent)) {
