public void adjustBeforeOptimize(Polygon2D_F64 polygon, GrowQueue_B touchesBorder, boolean clockwise) int N = polygon.size();
work.vertexes.resize(N);
for (int i = 0; i < N; i++) {
work.get(i).set(0, 0);
}
for (int i = N - 1, j = 0; j < N; i = j, j++) {
int ii,jj,kk,mm;
if( clockwise ) {
mm = CircularIndex.addOffset(-1,i,N);
ii=i;jj=j;
kk = CircularIndex.addOffset(1,j,N);
} else {
mm = CircularIndex.addOffset(1,j,N);
ii=j;jj=i;
kk = CircularIndex.addOffset(-1,i,N);
}
Point2D_F64 a = polygon.get(ii), b = polygon.get(jj);
double dx = b.x - a.x;
double dy = b.y - a.y;
double l = Math.sqrt(dx * dx + dy * dy);
if( l == 0 ) {
throw new RuntimeException("Input polygon has two identical corners. You need to fix that.");
}
dx *= 1.5 / l;
dy *= 1.5 / l;
Point2D_F64 _a = work.get(ii);
Point2D_F64 _b = work.get(jj);
if( touchesBorder.size>0 && touchesBorder.get(ii) ) {
if(!touchesBorder.get(mm)) {
_a.x -= dx;
_a.y -= dy;
}
} else {
_a.x += -dy;
_a.y += dx;
}
if( touchesBorder.size>0 && touchesBorder.get(jj) ) {
if( !touchesBorder.get(kk) ) {
_b.x += dx;
_b.y += dy;
}
} else {
_b.x += -dy;
_b.y += dx;
}
}
for (int i = 0; i < N; i++) {
Point2D_F64 a = polygon.get(i);
Point2D_F64 b = work.get(i);
a.x += b.x;
a.y += b.y;
}

public void process( Polygon2D_F64 polygon, boolean clockwise) int N = polygon.size();
segments.resize(N);
for (int i = N - 1, j = 0; j < N; i = j, j++) {
int ii,jj;
if( clockwise ) {
ii = i; jj = j;
} else {
ii = j; jj = i;
}
Point2D_F64 a = polygon.get(ii), b = polygon.get(jj);
double dx = b.x - a.x;
double dy = b.y - a.y;
double l = Math.sqrt(dx * dx + dy * dy);
if( l == 0) {
throw new RuntimeException("Two identical corners!");
}
if( dx < 0 )
dx = 0;
if( dy > 0 )
dy = 0;
LineSegment2D_F64 s = segments.get(ii);
s.a.x = a.x - dy/l;
s.a.y = a.y + dx/l;
s.b.x = b.x - dy/l;
s.b.y = b.y + dx/l;
}
for (int i = N - 1, j = 0; j < N; i = j, j++) {
int ii,jj;
if( clockwise ) {
ii = i; jj = j;
} else {
ii = j; jj = i;
}
UtilLine2D_F64.convert(segments.get(ii),ga);
UtilLine2D_F64.convert(segments.get(jj),gb);
if( null != Intersection2D_F64.intersection(ga,gb,intersection)) {
if( intersection.distance2(polygon.get(jj)) < 20 ) {
polygon.get(jj).set(intersection);
}
}
}
UtilPolygons2D_F64.removeAdjacentDuplicates(polygon,1e-8);

public boolean process(EllipseRotated_F64 ellipse ) if( numContourPoints <= 0 ) {
score = 0;
return true;
}
double cphi = Math.cos(ellipse.phi);
double sphi = Math.sin(ellipse.phi);
averageInside = 0;
averageOutside = 0;
int total = 0;
for (int contourIndex = 0; contourIndex < numContourPoints; contourIndex++) {
double theta = contourIndex*Math.PI*2.0/numContourPoints;
double ct = Math.cos(theta);
double st = Math.sin(theta);
double px = ellipse.center.x + ellipse.a*ct*cphi - ellipse.b*st*sphi;
double py = ellipse.center.y + ellipse.a*ct*sphi + ellipse.b*st*cphi;
double edx = ellipse.a*ct*ellipse.b*ellipse.b;
double edy = ellipse.b*st*ellipse.a*ellipse.a;
double r = Math.sqrt(edx*edx + edy*edy);
edx /= r;
edy /= r;
double dx = edx*cphi - edy*sphi;
double dy = edx*sphi + edy*cphi;
double xin = px-dx*tangentDistance;
double yin = py-dy*tangentDistance;
double xout = px+dx*tangentDistance;
double yout = py+dy*tangentDistance;
if( integral.isInside(xin,yin) && integral.isInside(xout,yout)) {
averageInside += integral.compute(px,py, xin, yin);
averageOutside += integral.compute(px,py, xout, yout);
total++;
}
}
score = 0;
if( total > 0 ) {
score = Math.abs(averageOutside-averageInside)/(total*tangentDistance);
}
return score >= passThreshold;

static double distanceSq( Point2D_I32 a , Point2D_I32 b ) double dx = b.x-a.x;
double dy = b.y-a.y;
return dx*dx + dy*dy;

static double axisAdjustedDistanceSq(EllipseRotated_F64 a , EllipseRotated_F64 b ) double dx = b.center.x - a.center.x;
double dy = b.center.y - a.center.y;
double c = Math.cos(a.phi);
double s = Math.sin(a.phi);
double x = (dx*c + dy*s);
double y = (-dx*s + dy*c)*a.a/a.b;
return x*x + y*y;

