private void restoreInstanceDirectoryFromPath(Path source, String instanceRocksDBPath) throws IOException FileSystem fileSystem = source.getFileSystem();
final FileStatus[] fileStatuses = fileSystem.listStatus(source);
if (fileStatuses == null) {
throw new IOException("Cannot list file statues. Directory " + source + " does not exist.");
}
for (FileStatus fileStatus : fileStatuses) {
final Path filePath = fileStatus.getPath();
final String fileName = filePath.getName();
File restoreFile = new File(source.getPath(), fileName);
File targetFile = new File(instanceRocksDBPath, fileName);
if (fileName.endsWith(SST_FILE_SUFFIX)) {
Files.createLink(targetFile.toPath(), restoreFile.toPath());
} else {
Files.copy(restoreFile.toPath(), targetFile.toPath(), StandardCopyOption.REPLACE_EXISTING);
}
}

public boolean initOutPathDistFS(Path outPath, WriteMode writeMode, boolean createDirectory) throws IOException if (!isDistributedFS()) {
return false;
}
try {
OUTPUT_DIRECTORY_INIT_LOCK.lockInterruptibly();
}
catch (InterruptedException e) {
Thread.currentThread().interrupt();
throw new IOException("The thread was interrupted while trying to initialize the output directory");
}
try {
if (exists(outPath)) {
switch(writeMode) {
case NO_OVERWRITE:
throw new IOException("File or directory already exists. Existing files and directories are not overwritten in " +
WriteMode.NO_OVERWRITE.name() + " mode. Use " + WriteMode.OVERWRITE.name() +
" mode to overwrite existing files and directories.");
case OVERWRITE:
try {
delete(outPath, true);
} catch (IOException e) {
}
break;
default:
throw new IllegalArgumentException("Invalid write mode: " + writeMode);
}
}
if (createDirectory) {
try {
if (!exists(outPath)) {
mkdirs(outPath);
}
} catch (IOException ioe) {
}
return exists(outPath) && getFileStatus(outPath).isDir();
}
else {
return !exists(outPath);
}
}
finally {
OUTPUT_DIRECTORY_INIT_LOCK.unlock();
}

