public static <T> List<T> sort(Collection<T> collection, Comparator<? super T> comparator) List<T> list = new ArrayList<T>(collection);
Collections.sort(list, comparator);
return list;

public static <T> List<T> addAllIfNotContains(List<T> list, List<T> otherList) for (T t : otherList) {
if (false == list.contains(t)) {
list.add(t);
}
}
return list;

@SafeVarargs public static <T> List<T> sortPageAll(int pageNo, int pageSize, Comparator<T> comparator, Collection<T>... colls) final List<T> list = new ArrayList<>(pageNo * pageSize);
for (Collection<T> coll : colls) {
list.addAll(coll);
}
if (null != comparator) {
Collections.sort(list, comparator);
}
return page(pageNo, pageSize, list);

public static <T> List<T> setOrAppend(List<T> list, int index, T element) if (index < list.size()) {
list.set(index, element);
} else {
list.add(element);
}
return list;

public static <T> List<T> page(int pageNo, int pageSize, List<T> list) if (isEmpty(list)) {
return new ArrayList<>(0);
}
int resultSize = list.size();
if (resultSize <= pageSize) {
if (pageNo <= 1) {
return Collections.unmodifiableList(list);
} else {
return new ArrayList<>(0);
}
}
final int[] startEnd = PageUtil.transToStartEnd(pageNo, pageSize);
if (startEnd[1] > resultSize) {
startEnd[1] = resultSize;
}
return list.subList(startEnd[0], startEnd[1]);

public static <T> List<T> randomEles(List<T> list, int count) final List<T> result = new ArrayList<T>(count);
int limit = list.size();
while (result.size() < count) {
result.add(randomEle(list, limit));
}
return result;

@SafeVarargs public static <T> List<T> list(boolean isLinked, T... values) if (ArrayUtil.isEmpty(values)) {
return list(isLinked);
}
List<T> arrayList = isLinked ? new LinkedList<T>() : new ArrayList<T>(values.length);
for (T t : values) {
arrayList.add(t);
}
return arrayList;

public static <T> T[] filter(T[] array, Editor<T> editor) ArrayList<T> list = new ArrayList<T>(array.length);
T modified;
for (T t : array) {
modified = editor.edit(t);
if (null != modified) {
list.add(modified);
}
}
return list.toArray(Arrays.copyOf(array, list.size()));

public static <T> T get(Collection<T> collection, int index) if (null == collection) {
return null;
}
final int size = collection.size();
if (index < 0) {
index += size;
}
if (index >= size) {
return null;
}
if (collection instanceof List) {
final List<T> list = ((List<T>) collection);
return list.get(index);
} else {
int i = 0;
for (T t : collection) {
if (i > index) {
break;
} else if (i == index) {
return t;
}
i++;
}
}
return null;

