}

public <T extends Dict> void removeEqual(T dict, String... withoutNames) HashSet<String> withoutSet = CollectionUtil.newHashSet(withoutNames);
for (Map.Entry<String, Object> entry : dict.entrySet()) {
if (withoutSet.contains(entry.getKey())) {
continue;
}
final Object value = this.get(entry.getKey());
if (null != value && value.equals(entry.getValue())) {
this.remove(entry.getKey());
}
}

