private float iterationSor(GrayF32 image1, GrayF32 deriv1X, GrayF32 deriv1Y, int i, int ipx, int imx, int ipy, int imy) float w = SOR_RELAXATION;
float psid = psiData.data[i];
float psig = gamma*psiGradient.data[i];
float di = warpImage2.data[i] - image1.data[i];
float dx2 = warpDeriv2X.data[i];
float dy2 = warpDeriv2Y.data[i];
float dxx2 = warpDeriv2XX.data[i];
float dyy2 = warpDeriv2YY.data[i];
float dxy2 = warpDeriv2XY.data[i];
float Au = -psid*di*dx2 + alpha*divU.data[i]
- psig*((dx2 - deriv1X.data[i])*warpDeriv2XX.data[i] + (dy2 - deriv1Y.data[i])*warpDeriv2XY.data[i]);
float Av = -psid*di*dy2 + alpha*divV.data[i]
- psig*((dx2 - deriv1X.data[i])*warpDeriv2XY.data[i] + (dy2 - deriv1Y.data[i])*warpDeriv2YY.data[i]);
float Du = psid*dx2*dx2 + psig*(dxx2*dxx2 + dxy2*dxy2) + alpha*divD.data[i];
float Dv = psid*dy2*dy2 + psig*(dyy2*dyy2 + dxy2*dxy2) + alpha*divD.data[i];
float D = psid*dx2*dy2 + psig*(dxx2 + dyy2)*dxy2;
float psi_index = psiSmooth.data[i];
float coef0 = 0.5f*(psiSmooth.data[ipx] + psi_index);
float coef1 = 0.5f*(psiSmooth.data[imx] + psi_index);
float coef2 = 0.5f*(psiSmooth.data[ipy] + psi_index);
float coef3 = 0.5f*(psiSmooth.data[imy] + psi_index);
float div_du = coef0 * du.data[ipx] + coef1 * du.data[imx] + coef2 * du.data[ipy] + coef3 * du.data[imy];
float div_dv = coef0 * dv.data[ipx] + coef1 * dv.data[imx] + coef2 * dv.data[ipy] + coef3 * dv.data[imy] ;
final float dui = du.data[i];
final float dvi = dv.data[i];
du.data[i] = (1f-w)*dui + w*(Au - D*dvi + alpha*div_du)/Du;
dv.data[i] = (1f-w)*dvi + w*(Av - D*du.data[i] + alpha*div_dv)/Dv;
return (du.data[i] - dui) * (du.data[i] - dui) + (dv.data[i] - dvi) * (dv.data[i] - dvi);

public static void process_F32_sub(GrayF32 orig, GrayF32 derivX, GrayF32 derivY) final float[] data = orig.data;
final float[] imgX = derivX.data;
final float[] imgY = derivY.data;
final int width = orig.getWidth();
final int height = orig.getHeight() - 1;
final int strideSrc = orig.stride;
final int adjWidth = width - 2;
for (int y = 1; y < height; y++) {
int index = orig.startIndex + strideSrc * y + 1;
int indexX = derivX.startIndex + derivX.stride * y + 1;
int indexY = derivY.startIndex + derivY.stride * y + 1;
int endX_alt = index + (width - adjWidth % 3) - 2;
int endX = endX_alt + adjWidth % 3;
float a11, a12, a13;
float a21, a22, a23;
float a31, a32, a33;
a11 = data[index - strideSrc - 1];
a12 = data[index - strideSrc];
a21 = data[index - 1];
a22 = data[index];
a31 = data[index + strideSrc - 1];
a32 = data[index + strideSrc];
for (; index < endX_alt;) {
a13 = data[index - strideSrc + 1];
a23 = data[index + 1];
a33 = data[index + strideSrc + 1];
float v = (a33 - a11) * 0.25F;
float w = (a31 - a13) * 0.25F;
imgY[indexY++] = (a32 - a12) * 0.5F + v + w;
imgX[indexX++] = (a23 - a21) * 0.5F + v - w;
index++;
a11 = data[index - strideSrc + 1];
a21 = data[index + 1];
a31 = data[index + strideSrc + 1];
v = (a31 - a12) * 0.25F;
w = (a32 - a11) * 0.25F;
imgY[indexY++] = (a33 - a13) * 0.5F + v + w;
imgX[indexX++] = (a21 - a22) * 0.5F + v - w;
index++;
a12 = data[index - strideSrc + 1];
a22 = data[index + 1];
a32 = data[index + strideSrc + 1];
v = (a32 - a13) * 0.25F;
w = (a33 - a12) * 0.25F;
imgY[indexY++] = (a31 - a11) * 0.5F + v + w;
imgX[indexX++] = (a22 - a23) * 0.5F + v - w;
index++;
}
for (; index < endX; index++) {
float v = (data[index + strideSrc + 1] - data[index - strideSrc - 1]) * 0.25F;
float w = (data[index + strideSrc - 1] - data[index - strideSrc + 1]) * 0.25F;
imgY[indexY++] = (data[index + strideSrc] - data[index - strideSrc]) * 0.5F + v + w;
imgX[indexX++] = (data[index + 1] - data[index - 1]) * 0.5F + v - w;
}
}

public static void process(GrayU8 orig, GrayS16 deriv) final byte[] data = orig.data;
final short[] out = deriv.data;
final int width = orig.getWidth();
final int height = orig.getHeight() - 1;
final int stride = orig.stride;
BoofConcurrency.loopFor(1,height,y->{
int index = orig.startIndex + stride * y + 1;
int indexOut = deriv.startIndex + deriv.stride * y + 1;
int endX = index + width - 2;
for (; index < endX; index++) {
int v = data[index - stride] & 0xFF;
v += data[index - 1] & 0xFF;
v += -4 * (data[index] & 0xFF);
v += data[index + 1] & 0xFF;
v += data[index + stride] & 0xFF;
out[indexOut++] = (short) v;
}
});

public static void derivX_F32(GrayF32 orig, GrayF32 derivX) final float[] data = orig.data;
final float[] imgX = derivX.data;
final int width = orig.getWidth();
final int height = orig.getHeight();
for (int y = 0; y < height; y++) {
int index = width * y + 1;
int endX = index + width - 2;
int endXAlt = endX - (width - 2) % 3;
float x0 = data[index - 1];
float x1 = data[index];
for (; index < endXAlt;) {
float x2 = data[index + 1];
imgX[index++] = (x2 - x0) * 0.5f;
x0 = data[index + 1];
imgX[index++] = (x0 - x1) * 0.5f;
x1 = data[index + 1];
imgX[index++] = (x1 - x2) * 0.5f;
}
for (; index < endX; index++) {
imgX[index] = (data[index + 1] - data[index - 1]) * 0.5f;
}
}

public static void process_I8(GrayU8 orig, GrayS16 derivX, GrayS16 derivY) final byte[] data = orig.data;
final short[] imgX = derivX.data;
final short[] imgY = derivY.data;
final int width = orig.getWidth();
final int height = orig.getHeight() - 1;
final int adjWidth = width - 2;
for (int y = 1; y < height; y++) {
int endX_alt = width * y + (width - adjWidth % 3) - 1;
int endX = endX_alt + adjWidth % 3;
int a11, a12, a13;
int a21, a22, a23;
int a31, a32, a33;
int index = width * y + 1;
a11 = data[index - width - 1] & 0xFF;
a12 = data[index - width] & 0xFF;
a21 = data[index - 1] & 0xFF;
a22 = data[index] & 0xFF;
a31 = data[index + width - 1] & 0xFF;
a32 = data[index + width] & 0xFF;
for (; index < endX_alt;) {
a13 = data[index - width + 1] & 0xFF;
a23 = data[index + 1] & 0xFF;
a33 = data[index + width + 1] & 0xFF;
int v = (a33 - a11);
int w = (a31 - a13);
imgY[index] = (short) ((a32 - a12) * 2 + v + w);
imgX[index] = (short) ((a23 - a21) * 2 + v - w);
index++;
a11 = data[index - width + 1] & 0xFF;
a21 = data[index + 1] & 0xFF;
a31 = data[index + width + 1] & 0xFF;
v = (a31 - a12);
w = (a32 - a11);
imgY[index] = (short) ((a33 - a13) * 2 + v + w);
imgX[index] = (short) ((a21 - a22) * 2 + v - w);
index++;
a12 = data[index - width + 1] & 0xFF;
a22 = data[index + 1] & 0xFF;
a32 = data[index + width + 1] & 0xFF;
v = (a32 - a13);
w = (a33 - a12);
imgY[index] = (short) ((a31 - a11) * 2 + v + w);
imgX[index] = (short) ((a22 - a23) * 2 + v - w);
index++;
}
for (; index < endX; index++) {
int v = (data[index + width + 1] & 0xFF) - (data[index - width - 1] & 0xFF);
int w = (data[index + width - 1] & 0xFF) - (data[index - width + 1] & 0xFF);
imgY[index] = (short) (((data[index + width] & 0xFF) - (data[index - width] & 0xFF)) * 2 + v + w);
imgX[index] = (short) (((data[index + 1] & 0xFF) - (data[index - 1] & 0xFF)) * 2 + v - w);
}
}

public static void process(GrayU8 orig, GrayS16 derivX, GrayS16 derivY) final byte[] data = orig.data;
final short[] imgX = derivX.data;
final short[] imgY = derivY.data;
final int width = orig.getWidth();
final int height = orig.getHeight() - 1;
for (int y = 1; y < height; y++) {
int endX = width * y + width - 1;
for (int index = width * y + 1; index < endX; index++) {
int v = (data[index + width + 1] & 0xFF) - (data[index - width - 1] & 0xFF);
int w = (data[index + width - 1] & 0xFF) - (data[index - width + 1] & 0xFF);
imgY[index] = (short) (((data[index + width] & 0xFF) - (data[index - width] & 0xFF)) * 2 + v + w);
imgX[index] = (short) (((data[index + 1] & 0xFF) - (data[index - 1] & 0xFF)) * 2 + v - w);
}
}

public static void vertical( GrayF32 src , GrayF32 dst ) if( src.height < dst.height )
throw new IllegalArgumentException("src height must be >= dst height");
if( src.width != dst.width )
throw new IllegalArgumentException("src width must equal dst width");
float scale = src.height/(float)dst.height;
for (int x = 0; x < dst.width; x++) {
int indexDst = dst.startIndex + x;
for (int y = 0; y < dst.height-1; y++) {
float srcY0 = y*scale;
float srcY1 = (y+1)*scale;
int isrcY0 = (int)srcY0;
int isrcY1 = (int)srcY1;
int index = src.getIndex(x,isrcY0);
float startWeight = (1.0f-(srcY0-isrcY0));
float start = src.data[index];
index += src.stride;
float middle = 0;
for( int i = isrcY0+1; i < isrcY1; i++ ) {
middle += src.data[index];
index += src.stride;
}
float endWeight = (srcY1%1);
float end = src.data[index];
dst.data[indexDst] = (float)((start*startWeight + middle + end*endWeight)/scale );
indexDst += dst.stride;
}
int y = dst.height-1;
float srcY0 = y*scale;
int isrcY0 = (int)srcY0;
int isrcY1 = src.height-1;
int index = src.getIndex(x,isrcY0);
float startWeight = (1.0f-(srcY0-isrcY0));
float start = src.data[index];
index += src.stride;
float middle = 0;
for( int i = isrcY0+1; i < isrcY1; i++ ) {
middle += src.data[index];
index += src.stride;
}
float end = isrcY1 != isrcY0 ? src.data[index]: 0;
dst.data[indexDst] = (float)((start*startWeight + middle + end)/scale );
}

protected static void gaussianKernel(double xx , double yy , GrayF64 xy , double sigma , GrayF64 output ) double sigma2 = sigma*sigma;
double N = xy.width*xy.height;
for( int y = 0; y < xy.height; y++ ) {
int index = xy.startIndex + y*xy.stride;
for( int x = 0; x < xy.width; x++ , index++ ) {
double value = (xx + yy - 2*xy.data[index])/N;
double v = Math.exp(-Math.max(0, value) / sigma2);
output.data[index] = v;
}
}

public static void bufferedToPlanar_F32(BufferedImage src, Planar<GrayF32> dst) final int width = src.getWidth();
final int height = src.getHeight();
if (dst.getNumBands() == 3) {
final float[] band1 = dst.getBand(0).data;
final float[] band2 = dst.getBand(1).data;
final float[] band3 = dst.getBand(2).data;
for (int y = 0; y < height; y++) {
int index = dst.startIndex + y * dst.stride;
for (int x = 0; x < width; x++, index++) {
int argb = src.getRGB(x, y);
band1[index] = (argb >>> 16) & 0xFF;
band2[index] = (argb >>> 8) & 0xFF;
band3[index] = argb & 0xFF;
}
}
} else if (dst.getNumBands() == 4) {
final float[] band1 = dst.getBand(0).data;
final float[] band2 = dst.getBand(1).data;
final float[] band3 = dst.getBand(2).data;
final float[] band4 = dst.getBand(3).data;
for (int y = 0; y < height; y++) {
int index = dst.startIndex + y * dst.stride;
for (int x = 0; x < width; x++, index++) {
int argb = src.getRGB(x, y);
band1[index] = (argb >>> 24) & 0xFF;
band2[index] = (argb >>> 16) & 0xFF;
band3[index] = (argb >>> 8) & 0xFF;
band4[index] = argb & 0xFF;
}
}
} else if( dst.getNumBands() == 1 ){
bufferedToGray(src, dst.getBand(0).data, dst.startIndex, dst.stride);
} else {
throw new IllegalArgumentException("Unsupported number of input bands");
}

protected static float A( int x , int y , GrayF32 flow ) int index = flow.getIndex(x,y);
float u0 = flow.data[index-1];
float u1 = flow.data[index+1];
float u2 = flow.data[index-flow.stride];
float u3 = flow.data[index+flow.stride];
float u4 = flow.data[index-1-flow.stride];
float u5 = flow.data[index+1-flow.stride];
float u6 = flow.data[index-1+flow.stride];
float u7 = flow.data[index+1+flow.stride];
return (1.0f/6.0f)*(u0 + u1 + u2 + u3) + (1.0f/12.0f)*(u4 + u5 + u6 + u7);

@PublicEvolving public static List<Field> getAllDeclaredFields(Class<?> clazz, boolean ignoreDuplicates) List<Field> result = new ArrayList<Field>();
while (clazz != null) {
Field[] fields = clazz.getDeclaredFields();
for (Field field : fields) {
if(Modifier.isTransient(field.getModifiers()) || Modifier.isStatic(field.getModifiers())) {
continue;
}
if(hasFieldWithSameName(field.getName(), result)) {
if (ignoreDuplicates) {
continue;
} else {
throw new InvalidTypesException("The field "+field+" is already contained in the hierarchy of the "+clazz+"."
+ "Please use unique field names through your classes hierarchy");
}
}
result.add(field);
}
clazz = clazz.getSuperclass();
}
return result;

public static Type getTypeHierarchy(List<Type> typeHierarchy, Type t, Class<?> stopAtClass) while (!(isClassType(t) && typeToClass(t).equals(stopAtClass))) {
typeHierarchy.add(t);
t = typeToClass(t).getGenericSuperclass();
if (t == null) {
break;
}
}
return t;

public static Class<?> getRawClass(Type t) if (isClassType(t)) {
return typeToClass(t);
} else if (t instanceof GenericArrayType) {
Type component = ((GenericArrayType) t).getGenericComponentType();
return Array.newInstance(getRawClass(component), 0).getClass();
}
return Object.class;

private static <OUT> TypeInfoFactory<? super OUT> getClosestFactory(ArrayList<Type> typeHierarchy, Type t) TypeInfoFactory factory = null;
while (factory == null && isClassType(t) && !(typeToClass(t).equals(Object.class))) {
typeHierarchy.add(t);
factory = getTypeInfoFactory(t);
t = typeToClass(t).getGenericSuperclass();
if (t == null) {
break;
}
}
return factory;

public static void validateLambdaType(Class<?> baseClass, Type t) if (!(t instanceof Class)) {
return;
}
final Class<?> clazz = (Class<?>) t;
if (clazz.getTypeParameters().length > 0) {
throw new InvalidTypesException("The generic type parameters of '" + clazz.getSimpleName() + "' are missing. "
+ "In many cases lambda methods don't provide enough information for automatic type extraction when Java generics are involved. "
+ "An easy workaround is to use an (anonymous) class instead that implements the '" + baseClass.getName() + "' interface. "
+ "Otherwise the type has to be specified explicitly using type information.");
}

public static Class<?> typeToClass(Type t) if (t instanceof Class) {
return (Class<?>)t;
}
else if (t instanceof ParameterizedType) {
return ((Class<?>) ((ParameterizedType) t).getRawType());
}
throw new IllegalArgumentException("Cannot convert type to class");

@Internal public static <OUT> TypeInfoFactory<OUT> getTypeInfoFactory(Type t) final Class<?> factoryClass;
if (registeredTypeInfoFactories.containsKey(t)) {
factoryClass = registeredTypeInfoFactories.get(t);
}
else {
if (!isClassType(t) || !typeToClass(t).isAnnotationPresent(TypeInfo.class)) {
return null;
}
final TypeInfo typeInfoAnnotation = typeToClass(t).getAnnotation(TypeInfo.class);
factoryClass = typeInfoAnnotation.value();
if (!TypeInfoFactory.class.isAssignableFrom(factoryClass)) {
throw new InvalidTypesException("TypeInfo annotation does not specify a valid TypeInfoFactory.");
}
}
return (TypeInfoFactory<OUT>) InstantiationUtil.instantiate(factoryClass);

public static <X> TypeInformation<X> getForClass(Class<X> clazz) final ArrayList<Type> typeHierarchy = new ArrayList<>();
typeHierarchy.add(clazz);
return new TypeExtractor().privateGetForClass(clazz, typeHierarchy);

private boolean isValidPojoField(Field f, Class<?> clazz, ArrayList<Type> typeHierarchy) if(Modifier.isPublic(f.getModifiers())) {
return true;
} else {
boolean hasGetter = false, hasSetter = false;
final String fieldNameLow = f.getName().toLowerCase().replaceAll("_", "");
Type fieldType = f.getGenericType();
Class<?> fieldTypeWrapper = ClassUtils.primitiveToWrapper(f.getType());
TypeVariable<?> fieldTypeGeneric = null;
if(fieldType instanceof TypeVariable) {
fieldTypeGeneric = (TypeVariable<?>) fieldType;
fieldType = materializeTypeVariable(typeHierarchy, (TypeVariable<?>)fieldType);
}
for(Method m : clazz.getMethods()) {
final String methodNameLow = m.getName().endsWith("_$eq") ?
m.getName().toLowerCase().replaceAll("_", "").replaceFirst("\\$eq$", "_\\$eq") :
m.getName().toLowerCase().replaceAll("_", "");
if(
(methodNameLow.equals("get"+fieldNameLow) || methodNameLow.equals("is"+fieldNameLow) || methodNameLow.equals(fieldNameLow)) &&
m.getParameterTypes().length == 0 &&
(m.getGenericReturnType().equals( fieldType ) || (fieldTypeWrapper != null && m.getReturnType().equals( fieldTypeWrapper )) || (fieldTypeGeneric != null && m.getGenericReturnType().equals(fieldTypeGeneric)) )
) {
hasGetter = true;
}
if((methodNameLow.equals("set"+fieldNameLow) || methodNameLow.equals(fieldNameLow+"_$eq")) &&
m.getParameterTypes().length == 1 &&
(m.getGenericParameterTypes()[0].equals( fieldType ) || (fieldTypeWrapper != null && m.getParameterTypes()[0].equals( fieldTypeWrapper )) || (fieldTypeGeneric != null && m.getGenericParameterTypes()[0].equals(fieldTypeGeneric) ) )&&
m.getReturnType().equals(Void.TYPE)
) {
hasSetter = true;
}
}
if(hasGetter && hasSetter) {
return true;
} else {
if(!hasGetter) {
LOG.info(clazz+" does not contain a getter for field "+f.getName() );
}
if(!hasSetter) {
LOG.info(clazz+" does not contain a setter for field "+f.getName() );
}
return false;
}
}

