private JobConf localizeJob(TaskInProgress tip) throws IOException Path localJarFile = null;
Task t = tip.getTask();
JobID jobId = t.getJobID();
Path jobFile = new Path(t.getJobFile());
FileStatus status = null;
long jobFileSize = -1;
try {
status = systemFS.getFileStatus(jobFile);
jobFileSize = status.getLen();
} catch(FileNotFoundException fe) {
jobFileSize = -1;
}
Path localJobFile = lDirAlloc.getLocalPathForWrite(
getLocalJobDir(jobId.toString())
+ Path.SEPARATOR + "job.xml",
jobFileSize, fConf);
RunningJob rjob = addTaskToJob(jobId, tip);
synchronized (rjob.localizationLock) {
if (rjob.localized == false) {
FileSystem localFs = FileSystem.getLocal(fConf);
Path jobDir = localJobFile.getParent();
if (localFs.exists(jobDir)){
LOG.warn("Deleting pre-existing jobDir: " + jobDir
+ " when localizeJob for tip " + tip);
localFs.delete(jobDir, true);
boolean b = localFs.mkdirs(jobDir);
if (!b)
throw new IOException("Not able to create job directory "
+ jobDir.toString());
}
systemFS.copyToLocalFile(jobFile, localJobFile);
boolean cleanup = false;
JobConf localJobConf = null;
Path bigParamPath = null;
if (fConf.getBoolean("mapred.input.dir.cleanup", true)) {
bigParamPath = new Path(jobDir, "bigParam");
int threshold = fConf.getInt("mapred.input.dir.cleanup.threshold", 1000);
localJobConf = new JobConf(localJobFile, bigParamPath, localFs, threshold);
} else {
localJobConf = new JobConf(localJobFile);
}
Path workDir = lDirAlloc.getLocalPathForWrite(
(getLocalJobDir(jobId.toString())
+ Path.SEPARATOR + "work"), fConf);
if (!localFs.mkdirs(workDir)) {
throw new IOException("Mkdirs failed to create "
+ workDir.toString());
}
System.setProperty("job.local.dir", workDir.toString());
localJobConf.set("job.local.dir", workDir.toString());
String jarFile = localJobConf.getJar();
long jarFileSize = -1;
boolean changeLocalJobConf = jarFile != null;
if (changeLocalJobConf) {
boolean shared =
localJobConf.getBoolean("mapred.cache.shared.enabled", false);
Path jarFilePath = new Path(jarFile);
if (shared) {
try {
jarFileSize =
Long.parseLong(DistributedCache.
getSharedArchiveLength(localJobConf)[0]);
} catch (NullPointerException npe) {
jarFileSize = -1;
}
} else {
try {
status = systemFS.getFileStatus(jarFilePath);
jarFileSize = status.getLen();
} catch(FileNotFoundException fe) {
jarFileSize = -1;
}
}
localJarFile = new Path(lDirAlloc.getLocalPathForWrite(
getLocalJobDir(jobId.toString())
+ Path.SEPARATOR + "jars",
5 * jarFileSize, fConf), "job.jar");
if (!localFs.mkdirs(localJarFile.getParent())) {
throw new IOException("Mkdirs failed to create jars directory ");
}
if (!shared) {
systemFS.copyToLocalFile(jarFilePath, localJarFile);
RunJar.unJar(new File(localJarFile.toString()),
new File(localJarFile.getParent().toString()));
}
localJobConf.setJar(localJarFile.toString());
}
reconfigureLocalJobConf(localJobConf, localJobFile, tip, changeLocalJobConf);
synchronized (rjob) {
rjob.keepJobFiles = ((localJobConf.getKeepTaskFilesPattern() != null) ||
localJobConf.getKeepFailedTaskFiles());
rjob.jobConf = localJobConf;
taskController.initializeJob(jobId);
rjob.localized = true;
}
} else {
JobConf localJobConf = new JobConf(localJobFile);
reconfigureLocalJobConf(localJobConf, localJobFile, tip, false);
}
}
return new JobConf(rjob.jobConf);

public boolean checkComplete() throws IOException JobID jobID = runningJob.getID();
if (runningJob.isComplete()) {
final String jobdir = jobconf.get(JOB_DIR_LABEL);
if (jobdir != null) {
final Path jobpath = new Path(jobdir);
jobpath.getFileSystem(jobconf).delete(jobpath, true);
}
if (runningJob.isSuccessful()) {
LOG.info("Job Complete(Succeeded): " + jobID);
} else {
LOG.info("Job Complete(Failed): " + jobID);
}
raidPolicyPathPairList.clear();
Counters ctrs = runningJob.getCounters();
if (ctrs != null) {
RaidNodeMetrics metrics = RaidNodeMetrics.getInstance(RaidNodeMetrics.DEFAULT_NAMESPACE_ID);
if (ctrs.findCounter(Counter.FILES_FAILED) != null) {
long filesFailed = ctrs.findCounter(Counter.FILES_FAILED).getValue();
metrics.raidFailures.inc(filesFailed);
}
long slotSeconds = ctrs.findCounter(
JobInProgress.Counter.SLOTS_MILLIS_MAPS).getValue() / 1000;
metrics.raidSlotSeconds.inc(slotSeconds);
}
return true;
} else {
String report =  (" job " + jobID +
" map " + StringUtils.formatPercent(runningJob.mapProgress(), 0)+
" reduce " + StringUtils.formatPercent(runningJob.reduceProgress(), 0));
if (!report.equals(lastReport)) {
LOG.info(report);
lastReport = report;
}
TaskCompletionEvent[] events =
runningJob.getTaskCompletionEvents(jobEventCounter);
jobEventCounter += events.length;
for(TaskCompletionEvent event : events) {
if (event.getTaskStatus() ==  TaskCompletionEvent.Status.FAILED) {
LOG.info(" Job " + jobID + " " + event.toString());
}
}
return false;
}

