summaryStr = newSummary.toString();
}
return new Summary(keywords, summaryStr);

public void rmLittlePathByScore() int maxTo = -1;
Term temp = null;
for (int i = 0; i < terms.length; i++) {
if (terms[i] == null) {
continue;
}
Term maxTerm = null;
double maxScore = 0;
Term term = terms[i];
do {
if (maxTerm == null || maxScore > term.score()) {
maxTerm = term;
} else if (maxScore == term.score() && maxTerm.getName().length() < term.getName().length()) {
maxTerm = term;
}
} while ((term = term.next()) != null);
term = maxTerm;
do {
maxTo = term.toValue();
maxScore = term.score();
if (maxTo - i == 1 || i + 1 == terms.length)
continue;
boolean flag = true;
out: for (int j = i; j < maxTo; j++) {
temp = terms[j];
if (temp == null) {
continue;
}
do {
if (temp.toValue() > maxTo || temp.score() < maxScore) {
flag = false;
break out;
}
} while ((temp = temp.next()) != null);
}
if (flag) {
for (int j = i + 1; j < maxTo; j++) {
terms[j] = null;
}
}
} while ((term = term.next()) != null);
}

public static double dotDense(NumberVector v1, NumberVector v2) final int dim1 = v1.getDimensionality(), dim2 = v2.getDimensionality();
final int mindim = (dim1 <= dim2) ? dim1 : dim2;
double dot = 0;
for(int k = 0; k < mindim; k++) {
dot += v1.doubleValue(k) * v2.doubleValue(k);
}
return dot;

public static double angleDense(NumberVector v1, NumberVector v2) final int dim1 = v1.getDimensionality(), dim2 = v2.getDimensionality();
final int mindim = (dim1 <= dim2) ? dim1 : dim2;
double cross = 0, l1 = 0, l2 = 0;
for(int k = 0; k < mindim; k++) {
final double r1 = v1.doubleValue(k);
final double r2 = v2.doubleValue(k);
cross += r1 * r2;
l1 += r1 * r1;
l2 += r2 * r2;
}
for(int k = mindim; k < dim1; k++) {
final double r1 = v1.doubleValue(k);
l1 += r1 * r1;
}
for(int k = mindim; k < dim2; k++) {
final double r2 = v2.doubleValue(k);
l2 += r2 * r2;
}
final double a = (cross == 0.) ? 0. :
(l1 == 0. || l2 == 0.) ? 1. :
FastMath.sqrt((cross / l1) * (cross / l2));
return (a < 1.) ? a : 1.;

public double maxDist(SpatialComparable mbr1, SpatialComparable mbr2) final int dim1 = mbr1.getDimensionality(), dim2 = mbr2.getDimensionality();
final int mindim = dim1 < dim2 ? dim1 : dim2;
double agg = 0.;
for(int d = 0; d < mindim; d++) {
double d1 = mbr1.getMax(d) - mbr2.getMin(d);
double d2 = mbr2.getMax(d) - mbr1.getMin(d);
double delta = d1 > d2 ? d1 : d2;
agg += delta * delta;
}
for(int d = mindim; d < dim1; d++) {
double d1 = Math.abs(mbr1.getMin(d)), d2 = Math.abs(mbr1.getMax(d));
double delta = d1 > d2 ? d1 : d2;
agg += delta * delta;
}
for(int d = mindim; d < dim2; d++) {
double d1 = Math.abs(mbr2.getMin(d)), d2 = Math.abs(mbr2.getMax(d));
double delta = d1 > d2 ? d1 : d2;
agg += delta * delta;
}
return FastMath.sqrt(agg);

public static double angle(NumberVector v1, NumberVector v2, NumberVector o) final int dim1 = v1.getDimensionality(), dim2 = v2.getDimensionality(),
dimo = o.getDimensionality();
final int mindim = (dim1 <= dim2) ? dim1 : dim2;
double cross = 0, l1 = 0, l2 = 0;
for(int k = 0; k < mindim; k++) {
final double ok = k < dimo ? o.doubleValue(k) : 0.;
final double r1 = v1.doubleValue(k) - ok;
final double r2 = v2.doubleValue(k) - ok;
cross += r1 * r2;
l1 += r1 * r1;
l2 += r2 * r2;
}
for(int k = mindim; k < dim1; k++) {
final double ok = k < dimo ? o.doubleValue(k) : 0.;
final double r1 = v1.doubleValue(k) - ok;
l1 += r1 * r1;
}
for(int k = mindim; k < dim2; k++) {
final double ok = k < dimo ? o.doubleValue(k) : 0.;
final double r2 = v2.doubleValue(k) - ok;
l2 += r2 * r2;
}
final double a = (cross == 0.) ? 0. :
(l1 == 0. || l2 == 0.) ? 1. :
FastMath.sqrt((cross / l1) * (cross / l2));
return (a < 1.) ? a : 1.;

public static double minDot(SpatialComparable v1, SpatialComparable v2) if(v1 instanceof NumberVector && v2 instanceof NumberVector) {
return dot((NumberVector) v1, (NumberVector) v2);
}
final int dim1 = v1.getDimensionality(), dim2 = v2.getDimensionality();
final int mindim = (dim1 <= dim2) ? dim1 : dim2;
double s1 = 0, s2 = 0;
for(int k = 0; k < mindim; k++) {
final double min1 = v1.getMin(k), max1 = v1.getMax(k);
final double min2 = v2.getMin(k), max2 = v2.getMax(k);
final double p1 = min1 * min2, p2 = min1 * max2;
final double p3 = max1 * min2, p4 = max1 * max2;
s1 += Math.max(Math.max(p1, p2), Math.max(p3, p4));
s2 += Math.min(Math.min(p1, p2), Math.min(p3, p4));
}
return Math.max(Math.abs(s1), Math.abs(s2));

public static double minCosAngle(SpatialComparable v1, SpatialComparable v2) if(v1 instanceof NumberVector && v2 instanceof NumberVector) {
return cosAngle((NumberVector) v1, (NumberVector) v2);
}
final int dim1 = v1.getDimensionality(), dim2 = v2.getDimensionality();
final int mindim = (dim1 <= dim2) ? dim1 : dim2;
double s1 = 0, s2 = 0, l1 = 0, l2 = 0;
for(int k = 0; k < mindim; k++) {
final double min1 = v1.getMin(k), max1 = v1.getMax(k);
final double min2 = v2.getMin(k), max2 = v2.getMax(k);
final double p1 = min1 * min2, p2 = min1 * max2;
final double p3 = max1 * min2, p4 = max1 * max2;
s1 += Math.max(Math.max(p1, p2), Math.max(p3, p4));
s2 += Math.min(Math.min(p1, p2), Math.min(p3, p4));
if(max1 < 0) {
l1 += max1 * max1;
}
else if(min1 > 0) {
l1 += min1 * min1;
}
if(max2 < 0) {
l2 += max2 * max2;
}
else if(min2 > 0) {
l2 += min2 * min2;
}
}
for(int k = mindim; k < dim1; k++) {
final double min1 = v1.getMin(k), max1 = v1.getMax(k);
if(max1 < 0.) {
l1 += max1 * max1;
}
else if(min1 > 0.) {
l1 += min1 * min1;
}
}
for(int k = mindim; k < dim2; k++) {
final double min2 = v2.getMin(k), max2 = v2.getMax(k);
if(max2 < 0.) {
l2 += max2 * max2;
}
else if(min2 > 0.) {
l2 += min2 * min2;
}
}
final double cross = Math.max(Math.abs(s1), Math.abs(s2));
final double a = (cross == 0.) ? 0. :
(l1 == 0. || l2 == 0.) ? 1. :
FastMath.sqrt((cross / l1) * (cross / l2));
return (a < 1.) ? a : 1.;

public static double angle(double[] v1, double[] v2) final int mindim = (v1.length <= v2.length) ? v1.length : v2.length;
double s = 0, e1 = 0, e2 = 0;
for(int k = 0; k < mindim; k++) {
final double r1 = v1[k], r2 = v2[k];
s += r1 * r2;
e1 += r1 * r1;
e2 += r2 * r2;
}
for(int k = mindim; k < v1.length; k++) {
final double r1 = v1[k];
e1 += r1 * r1;
}
for(int k = mindim; k < v2.length; k++) {
final double r2 = v2[k];
e2 += r2 * r2;
}
double a = FastMath.sqrt((s / e1) * (s / e2));
return (a < 1.) ? a : 1.;

protected int effectiveBandSize(final int dim1, final int dim2) if(bandSize == Double.POSITIVE_INFINITY) {
return (dim1 > dim2) ? dim1 : dim2;
}
if(bandSize >= 1.) {
return (int) bandSize;
}
return (int) Math.ceil((dim1 >= dim2 ? dim1 : dim2) * bandSize);

public static double dotSparseDense(SparseNumberVector v1, NumberVector v2) final int dim2 = v2.getDimensionality();
double dot = 0.;
for(int i1 = v1.iter(); v1.iterValid(i1);) {
final int d1 = v1.iterDim(i1);
if(d1 >= dim2) {
break;
}
dot += v1.iterDoubleValue(i1) * v2.doubleValue(d1);
i1 = v1.iterAdvance(i1);
}
return dot;

private double preDistance(NumberVector v1, NumberVector v2, final int start, final int end) double agg = 0.;
for(int d = start; d < end; d++) {
final double xd = v1.doubleValue(d), yd = v2.doubleValue(d);
final double delta = xd >= yd ? xd - yd : yd - xd;
agg += MathUtil.powi(delta, intp);
}
return agg;

