}
return item;

public static JsonPathCursor createCursor(String attributePath) ArrayList<Triple> triples = new ArrayList<Triple>(DEFAULT_PATH_ELEMENT_COUNT);
int start = 0;
int end;
while (start < attributePath.length()) {
boolean isArray = false;
try {
while (attributePath.charAt(start) == '[' || attributePath.charAt(start) == '.') {
start++;
}
} catch (IndexOutOfBoundsException e) {
throw createIllegalArgumentException(attributePath);
}
end = start + 1;
while (end < attributePath.length()) {
char c = attributePath.charAt(end);
if ('.' == c || '[' == c) {
break;
} else if (']' == c) {
isArray = true;
break;
}
end++;
}
String part = attributePath.substring(start, end);
Triple triple = new Triple(part, part.getBytes(UTF8_CHARSET), isArray);
triples.add(triple);
start = end + 1;
}
return new JsonPathCursor(attributePath, triples);

private ByteBufferSerializer<?>[] writeHeader(BundleStreamSource source, ByteBuffer buffer, WritableByteChannel output) throws IOException final BundleMeta meta = source.getMeta();
final int nummeta = meta.size();
@SuppressWarnings("rawtypes")
final ByteBufferSerializer[] serializers = new ByteBufferSerializer[1 + nummeta];
assert (buffer.position() == 0) : "Buffer is supposed to be at 0.";
buffer.putInt(MAGIC);
if(source.hasDBIDs()) {
buffer.putInt(1 + nummeta);
ByteBufferSerializer<DBID> ser = DBIDFactory.FACTORY.getDBIDSerializer();
TypeInformationSerializer.STATIC.toByteBuffer(buffer, new SimpleTypeInformation<>(DBID.class, ser));
serializers[0] = ser;
}
else {
buffer.putInt(nummeta);
}
for(int i = 0; i < nummeta; i++) {
SimpleTypeInformation<?> type = meta.get(i);
ByteBufferSerializer<?> ser = type.getSerializer();
if(ser == null) {
throw new AbortException("Cannot serialize - no serializer found for type: " + type.toString());
}
TypeInformationSerializer.STATIC.toByteBuffer(buffer, type);
serializers[i + 1] = ser;
}
return serializers;

void readObject() for(int i = 0; i < sers.length; ++i) {
try {
data[i] = sers[i].fromByteBuffer(buffer);
}
catch(UnsupportedOperationException e) {
throw new AbortException("Deserialization failed.", e);
}
catch(IOException e) {
throw new AbortException("IO error", e);
}
}

public void writeBundleStream(BundleStreamSource source, WritableByteChannel output) throws IOException ByteBuffer buffer = ByteBuffer.allocateDirect(INITIAL_BUFFER);
DBIDVar var = DBIDUtil.newVar();
ByteBufferSerializer<?>[] serializers = null;
loop: while(true) {
BundleStreamSource.Event ev = source.nextEvent();
switch(ev){
case NEXT_OBJECT:
if(serializers == null) {
serializers = writeHeader(source, buffer, output);
}
if(serializers[0] != null) {
if(!source.assignDBID(var)) {
throw new AbortException("An object did not have an DBID assigned.");
}
DBID id = DBIDUtil.deref(var);
@SuppressWarnings("unchecked")
ByteBufferSerializer<DBID> ser = (ByteBufferSerializer<DBID>) serializers[0];
int size = ser.getByteSize(id);
buffer = ensureBuffer(size, buffer, output);
ser.toByteBuffer(buffer, id);
}
for(int i = 1, j = 0; i < serializers.length; ++i, ++j) {
@SuppressWarnings("unchecked")
ByteBufferSerializer<Object> ser = (ByteBufferSerializer<Object>) serializers[i];
int size = ser.getByteSize(source.data(j));
buffer = ensureBuffer(size, buffer, output);
ser.toByteBuffer(buffer, source.data(j));
}
break;
case META_CHANGED:
if(serializers != null) {
throw new AbortException("Meta changes are not supported, once the block header has been written.");
}
break;
case END_OF_STREAM:
break loop;
default:
LOG.warning("Unknown bundle stream event. API inconsistent? " + ev);
break;
}
}
if(buffer.position() > 0) {
flushBuffer(buffer, output);
}

private P byteArrayToPage(byte[] array) try {
ByteArrayInputStream bais = new ByteArrayInputStream(array);
ObjectInputStream ois = new ObjectInputStream(bais);
int type = ois.readInt();
if(type == EMPTY_PAGE) {
return null;
}
else if(type == FILLED_PAGE) {
P page;
try {
page = pageclass.newInstance();
page.readExternal(ois);
}
catch(InstantiationException|IllegalAccessException|ClassNotFoundException e) {
throw new AbortException("Error instanciating an index page", e);
}
return page;
}
else {
throw new IllegalArgumentException("Unknown type: " + type);
}
}
catch(IOException e) {
throw new AbortException("IO Error in page file", e);
}

@SuppressWarnings("unchecked") private P byteBufferToPage(ByteBuffer buffer) try (InputStream bais = new ByteBufferInputStream(buffer);
ObjectInputStream ois = new ObjectInputStream(bais)) {
int type = ois.readInt();
if (type == EMPTY_PAGE) {
return null;
} else if (type == FILLED_PAGE) {
return (P) ois.readObject();
} else {
throw new IllegalArgumentException("Unknown type: " + type);
}
} catch (IOException|ClassNotFoundException e) {
LoggingUtil.exception(e);
return null;
}

private void updateMeta() meta = new BundleMeta();
BundleMeta origmeta = source.getMeta();
for(int i = 0; i < origmeta.size(); i++) {
SimpleTypeInformation<?> type = origmeta.get(i);
if(column < 0) {
if(TypeUtil.NUMBER_VECTOR_VARIABLE_LENGTH.isAssignableFromType(type)) {
if(type instanceof VectorFieldTypeInformation) {
@SuppressWarnings("unchecked")
final VectorFieldTypeInformation<V> castType = (VectorFieldTypeInformation<V>) type;
if(dim != -1 && castType.mindim() > dim) {
throw new AbortException("Would filter all vectors: minimum dimensionality " + castType.mindim() + " > desired dimensionality " + dim);
}
if(dim != -1 && castType.maxdim() < dim) {
throw new AbortException("Would filter all vectors: maximum dimensionality " + castType.maxdim() + " < desired dimensionality " + dim);
}
if(dim == -1) {
dim = castType.mindim();
}
if(castType.mindim() == castType.maxdim()) {
meta.add(castType);
column = i;
continue;
}
}
@SuppressWarnings("unchecked")
final VectorTypeInformation<V> castType = (VectorTypeInformation<V>) type;
if(dim != -1) {
meta.add(new VectorFieldTypeInformation<>(FilterUtil.guessFactory(castType), dim, dim, castType.getSerializer()));
}
else {
LOG.warning("No dimensionality yet for column " + i);
meta.add(castType);
}
column = i;
continue;
}
}
meta.add(type);
}

