@Override public MultipleObjectsBundle filter(MultipleObjectsBundle objects) if(objects.dataLength() == 0) {
return objects;
}
MultipleObjectsBundle bundle = new MultipleObjectsBundle();
final Logging logger = getLogger();
for(int r = 0; r < objects.metaLength(); r++) {
@SuppressWarnings("unchecked")
SimpleTypeInformation<Object> type = (SimpleTypeInformation<Object>) objects.meta(r);
@SuppressWarnings("unchecked")
final List<Object> column = (List<Object>) objects.getColumn(r);
if(!getInputTypeRestriction().isAssignableFromType(type)) {
bundle.appendColumn(type, column);
continue;
}
@SuppressWarnings("unchecked")
final SimpleTypeInformation<I> castType = (SimpleTypeInformation<I>) type;
if(prepareStart(castType)) {
FiniteProgress pprog = logger.isVerbose() ? new FiniteProgress("Preparing normalization", objects.dataLength(), logger) : null;
for(Object o : column) {
@SuppressWarnings("unchecked")
final I obj = (I) o;
prepareProcessInstance(obj);
logger.incrementProcessed(pprog);
}
logger.ensureCompleted(pprog);
prepareComplete();
}
@SuppressWarnings("unchecked")
final List<O> castColumn = (List<O>) column;
bundle.appendColumn(convertedType(castType), castColumn);
FiniteProgress nprog = logger.isVerbose() ? new FiniteProgress("Data normalization", objects.dataLength(), logger) : null;
for(int i = 0; i < objects.dataLength(); i++) {
@SuppressWarnings("unchecked")
final I obj = (I) column.get(i);
final O normalizedObj = filterSingleObject(obj);
castColumn.set(i, normalizedObj);
logger.incrementProcessed(nprog);
}
logger.ensureCompleted(nprog);
}
return bundle;

@SuppressWarnings("unchecked") public static <C> C parameterizeOrAbort(Class<?> c, Parameterization config) try {
C ret = tryInstantiate((Class<C>) c, c, config);
if(ret == null) {
throw new AbortException("Could not instantiate class. Check parameters.");
}
return ret;
}
catch(Exception e) {
if(config.hasErrors()) {
for(ParameterException err : config.getErrors()) {
LOG.warning(err.toString());
}
}
throw e instanceof AbortException ? (AbortException) e : new AbortException("Instantiation failed", e);
}

public static int compileShader(Class<?> context, GL2 gl, int type, String name) throws ShaderCompilationException int prog = -1;
try (InputStream in = context.getResourceAsStream(name)) {
int[] error = new int[1];
String shaderdata = FileUtil.slurp(in);
prog = gl.glCreateShader(type);
gl.glShaderSource(prog, 1, new String[] { shaderdata }, null, 0);
gl.glCompileShader(prog);
gl.glGetObjectParameterivARB(prog, GL2.GL_OBJECT_INFO_LOG_LENGTH_ARB, error, 0);
if(error[0] > 1) {
byte[] info = new byte[error[0]];
gl.glGetInfoLogARB(prog, info.length, error, 0, info, 0);
String out = new String(info);
gl.glDeleteShader(prog);
throw new ShaderCompilationException("Shader compilation error in '" + name + "': " + out);
}
gl.glGetShaderiv(prog, GL2.GL_COMPILE_STATUS, error, 0);
if(error[0] > 1) {
throw new ShaderCompilationException("Shader compilation of '" + name + "' failed.");
}
}
catch(IOException e) {
throw new ShaderCompilationException("IO error loading shader: " + name, e);
}
return prog;

