protected static int compareLexicographical(Itemset a, Itemset o) int i1 = a.iter(), i2 = o.iter();
while(a.iterValid(i1) && o.iterValid(i2)) {
int v1 = a.iterDim(i1), v2 = o.iterDim(i2);
if(v1 < v2) {
return -1;
}
if(v2 < v1) {
return +1;
}
i1 = a.iterAdvance(i1);
i2 = o.iterAdvance(i2);
}
return a.iterValid(i1) ? 1 : o.iterValid(i2) ? -1 : 0;

private static void quickSort(int[] data, final int start, final int end, Comparator<? super DBIDRef> comp, IntegerDBIDVar vl, IntegerDBIDVar vk, IntegerDBIDVar vr) final int len = end - start;
if(len < INSERTION_THRESHOLD) {
for(int i = start + 1; i <= end; i++) {
for(int j = i; j > start; j--) {
vl.internalSetIndex(data[j]);
vr.internalSetIndex(data[j - 1]);
if(comp.compare(vl, vr) < 0) {
int tmp = data[j - 1];
data[j - 1] = data[j];
data[j] = tmp;
}
else {
break;
}
}
}
return;
}
final int seventh = (len >> 3) + (len >> 6) + 1;
final int m3 = (start + end) >> 1;
final int m2 = m3 - seventh;
final int m1 = m2 - seventh;
final int m4 = m3 + seventh;
final int m5 = m4 + seventh;
if(compare(vl, data[m1], vk, data[m2], comp) > 0) {
int tmp = data[m2];
data[m2] = data[m1];
data[m1] = tmp;
}
if(compare(vl, data[m1], vk, data[m3], comp) > 0) {
int tmp = data[m3];
data[m3] = data[m1];
data[m1] = tmp;
}
if(compare(vl, data[m2], vk, data[m3], comp) > 0) {
int tmp = data[m3];
data[m3] = data[m2];
data[m2] = tmp;
}
if(compare(vl, data[m4], vk, data[m5], comp) > 0) {
int tmp = data[m5];
data[m5] = data[m4];
data[m4] = tmp;
}
if(compare(vl, data[m1], vk, data[m4], comp) > 0) {
int tmp = data[m4];
data[m4] = data[m1];
data[m1] = tmp;
}
if(compare(vl, data[m3], vk, data[m4], comp) > 0) {
int tmp = data[m4];
data[m4] = data[m3];
data[m3] = tmp;
}
if(compare(vl, data[m2], vk, data[m5], comp) > 0) {
int tmp = data[m5];
data[m5] = data[m2];
data[m2] = tmp;
}
if(compare(vl, data[m2], vk, data[m3], comp) > 0) {
int tmp = data[m3];
data[m3] = data[m2];
data[m2] = tmp;
}
if(compare(vl, data[m4], vk, data[m5], comp) > 0) {
int tmp = data[m5];
data[m5] = data[m4];
data[m4] = tmp;
}
vl.internalSetIndex(data[m2]);
vr.internalSetIndex(data[m4]);
data[m2] = data[start];
data[m4] = data[end];
final boolean tied = comp.compare(vl, vr) == 0;
int left = start + 1;
int right = end - 1;
for(int k = left; k <= right; k++) {
int tmp = data[k];
vk.internalSetIndex(tmp);
final int c = comp.compare(vk, vl);
if(c == 0) {
continue;
}
else if(c < 0) {
data[k] = data[left];
data[left] = tmp;
left++;
}
else if(tied || comp.compare(vk, vr) > 0) {
while(true) {
vk.internalSetIndex(data[right]);
if(comp.compare(vk, vr) > 0 && k < right) {
right--;
}
else {
break;
}
}
data[k] = data[right];
data[right] = tmp;
right--;
vk.internalSetIndex(data[k]);
if(comp.compare(vk, vl) < 0) {
tmp = data[k];
data[k] = data[left];
data[left] = tmp;
left++;
}
}
}
data[start] = data[left - 1];
data[left - 1] = vl.internalGetIndex();
data[end] = data[right + 1];
data[right + 1] = vr.internalGetIndex();
quickSort(data, start, left - 2, comp, vl, vk, vr);
if(!tied) {
quickSort(data, left, right, comp, vl, vk, vr);
}
quickSort(data, right + 2, end, comp, vl, vk, vr);

public MeanVariance averageSymmetricGini() MeanVariance mv = new MeanVariance();
for(int i1 = 0; i1 < size1; i1++) {
double purity = 0.0;
if(contingency[i1][size2] > 0) {
final double cs = contingency[i1][size2];
for(int i2 = 0; i2 < size2; i2++) {
double rel = contingency[i1][i2] / cs;
purity += rel * rel;
}
mv.put(purity, cs);
}
}
for(int i2 = 0; i2 < size2; i2++) {
double purity = 0.0;
if(contingency[size1][i2] > 0) {
final double cs = contingency[size1][i2];
for(int i1 = 0; i1 < size1; i1++) {
double rel = contingency[i1][i2] / cs;
purity += rel * rel;
}
mv.put(purity, cs);
}
}
return mv;

public static double dotSparse(SparseNumberVector v1, SparseNumberVector v2) double dot = 0.;
int i1 = v1.iter(), i2 = v2.iter();
while(v1.iterValid(i1) && v2.iterValid(i2)) {
final int d1 = v1.iterDim(i1), d2 = v2.iterDim(i2);
if(d1 < d2) {
i1 = v1.iterAdvance(i1);
}
else if(d2 < d1) {
i2 = v2.iterAdvance(i2);
}
else {
dot += v1.iterDoubleValue(i1) * v2.iterDoubleValue(i2);
i1 = v1.iterAdvance(i1);
i2 = v2.iterAdvance(i2);
}
}
return dot;

public boolean containedIn(SparseNumberVector bv) int i1 = this.iter(), i2 = bv.iter();
while(this.iterValid(i1)) {
if(!bv.iterValid(i2)) {
return false;
}
int d1 = this.iterDim(i1), d2 = bv.iterDim(i2);
if(d1 < d2) {
return false;
}
if(d1 == d2) {
if(bv.iterDoubleValue(i2) == 0.) {
return false;
}
i1 = this.iterAdvance(i1);
}
i2 = bv.iterAdvance(i2);
}
return true;

public static double angleSparse(SparseNumberVector v1, SparseNumberVector v2) double l1 = 0., l2 = 0., cross = 0.;
int i1 = v1.iter(), i2 = v2.iter();
while(v1.iterValid(i1) && v2.iterValid(i2)) {
final int d1 = v1.iterDim(i1), d2 = v2.iterDim(i2);
if(d1 < d2) {
final double val = v1.iterDoubleValue(i1);
l1 += val * val;
i1 = v1.iterAdvance(i1);
}
else if(d2 < d1) {
final double val = v2.iterDoubleValue(i2);
l2 += val * val;
i2 = v2.iterAdvance(i2);
}
else {
final double val1 = v1.iterDoubleValue(i1);
final double val2 = v2.iterDoubleValue(i2);
l1 += val1 * val1;
l2 += val2 * val2;
cross += val1 * val2;
i1 = v1.iterAdvance(i1);
i2 = v2.iterAdvance(i2);
}
}
while(v1.iterValid(i1)) {
final double val = v1.iterDoubleValue(i1);
l1 += val * val;
i1 = v1.iterAdvance(i1);
}
while(v2.iterValid(i2)) {
final double val = v2.iterDoubleValue(i2);
l2 += val * val;
i2 = v2.iterAdvance(i2);
}
final double a = (cross == 0.) ? 0. :
(l1 == 0. || l2 == 0.) ? 1. :
FastMath.sqrt((cross / l1) * (cross / l2));
return (a < 1.) ? a : 1.;

private IntIntPair[] sortEdges(int[] dindex) IntIntPair[] edgesort = new IntIntPair[shared.layout.edges.size()];
int e = 0;
for(Layout.Edge edge : shared.layout.edges) {
int i1 = dindex[edge.dim1], i2 = dindex[edge.dim2];
edgesort[e] = new IntIntPair(Math.min(i1, i2), e);
e++;
}
Arrays.sort(edgesort);
return edgesort;

public void process(Clustering<?> result1, Clustering<?> result2) final List<? extends Cluster<?>> cs1 = result1.getAllClusters();
final List<? extends Cluster<?>> cs2 = result2.getAllClusters();
size1 = cs1.size();
size2 = cs2.size();
contingency = new int[size1 + 2][size2 + 2];
noise1 = BitsUtil.zero(size1);
noise2 = BitsUtil.zero(size2);
{
final Iterator<? extends Cluster<?>> it2 = cs2.iterator();
for(int i2 = 0; it2.hasNext(); i2++) {
final Cluster<?> c2 = it2.next();
if(c2.isNoise()) {
BitsUtil.setI(noise2, i2);
}
contingency[size1 + 1][i2] = c2.size();
contingency[size1 + 1][size2] += c2.size();
}
}
final Iterator<? extends Cluster<?>> it1 = cs1.iterator();
for(int i1 = 0; it1.hasNext(); i1++) {
