contingency[i1][size2 + 1] = c1.size();
contingency[size1][size2 + 1] += c1.size();
final Iterator<? extends Cluster<?>> it2 = cs2.iterator();
for(int i2 = 0; it2.hasNext(); i2++) {
final Cluster<?> c2 = it2.next();
int count = DBIDUtil.intersectionSize(ids, c2.getIDs());
contingency[i1][i2] = count;
contingency[i1][size2] += count;
contingency[size1][i2] += count;
contingency[size1][size2] += count;
}
}

private double pseudoRandom(final long seed, int input) final long mult = 0x5DEECE66DL;
final long add = 0xBL;
final long mask = (1L << 48) - 1;
final long i1 = (input ^ seed ^ mult) & mask;
final long i2 = (input ^ (seed >>> 16) ^ mult) & mask;
final long l1 = (i1 * mult + add) & mask;
final long l2 = (i2 * mult + add) & mask;
final int r1 = (int) (l1 >>> 22);
final int r2 = (int) (l2 >>> 21);
double random = ((((long) r1) << 27) + r2) / (double) (1L << 53);
return random;

