canLabler.canonLabel(ac);
centerCode = "";
this.atomContainer = ac;
maxSphere = noOfSpheres;
spheres = new List[noOfSpheres + 1];
for (int i = 0; i < ac.getAtomCount(); i++) {
ac.getAtom(i).setFlag(CDKConstants.VISITED, false);
}
root.setFlag(CDKConstants.VISITED, true);
rootNode = new TreeNode(root.getSymbol(), null, root, (double) 0, atomContainer.getConnectedBondsCount(root), 0);
HOSECode = new StringBuffer();
createCenterCode(root, ac, ringsize);
breadthFirstSearch(root, true);
createCode();
fillUpSphereDelimiters();
logger.debug("HOSECodeGenerator -> HOSECode: ", HOSECode);
return HOSECode.toString();

public IRingSet assignAtomTyps(IAtomContainer molecule) throws CDKException IAtom atom = null;
String hoseCode = "";
HOSECodeGenerator hcg = new HOSECodeGenerator();
int NumberOfRingAtoms = 0;
IRingSet ringSetA = null;
IRingSet ringSetMolecule = Cycles.sssr(molecule).toRingSet();
boolean isInHeteroRing = false;
try {
AtomContainerManipulator.percieveAtomTypesAndConfigureAtoms(molecule);
Aromaticity.cdkLegacy().apply(molecule);
} catch (Exception cdk1) {
throw new CDKException("AROMATICITYError: Cannot determine aromaticity due to: " + cdk1.getMessage(), cdk1);
}
for (int i = 0; i < molecule.getAtomCount(); i++) {
atom = molecule.getAtom(i);
if (ringSetMolecule.contains(atom)) {
NumberOfRingAtoms = NumberOfRingAtoms + 1;
atom.setFlag(CDKConstants.ISINRING, true);
atom.setFlag(CDKConstants.ISALIPHATIC, false);
ringSetA = ringSetMolecule.getRings(atom);
RingSetManipulator.sort(ringSetA);
IRing sring = (IRing) ringSetA.getAtomContainer(ringSetA.getAtomContainerCount() - 1);
atom.setProperty("RING_SIZE", Integer.valueOf(sring.getRingSize()));
isInHeteroRing = false;
Iterator<IAtomContainer> containers = RingSetManipulator.getAllAtomContainers(ringSetA).iterator();
while (!isInHeteroRing && containers.hasNext()) {
isInHeteroRing = isHeteroRingSystem(containers.next());
}
} else {
atom.setFlag(CDKConstants.ISALIPHATIC, true);
atom.setFlag(CDKConstants.ISINRING, false);
isInHeteroRing = false;
}
atom.setProperty("MAX_BOND_ORDER", new Double(molecule.getMaximumBondOrder(atom).numeric()));
try {
hoseCode = hcg.getHOSECode(molecule, atom, 3);
} catch (CDKException ex1) {
System.out.println("Could not build HOSECode from atom " + i + " due to " + ex1.toString());
throw new CDKException("Could not build HOSECode from atom " + i + " due to " + ex1.toString(), ex1);
}
try {
configureAtom(atom, hoseCode, isInHeteroRing);
} catch (CDKException ex2) {
System.out.println("Could not final configure atom " + i + " due to " + ex2.toString());
throw new CDKException("Could not final configure atom due to problems with force field", ex2);
}
}
String bondType;
for (IBond bond : molecule.bonds()) {
bondType = "0";
if (bond.getOrder() == IBond.Order.SINGLE) {
if ((bond.getBegin().getAtomTypeName().equals("Csp2"))
&& ((bond.getEnd().getAtomTypeName().equals("Csp2")) || (bond.getEnd().getAtomTypeName()
.equals("C=")))) {
bondType = "1";
}
if ((bond.getBegin().getAtomTypeName().equals("C="))
&& ((bond.getEnd().getAtomTypeName().equals("Csp2")) || (bond.getEnd().getAtomTypeName()
.equals("C=")))) {
bondType = "1";
}
if ((bond.getBegin().getAtomTypeName().equals("Csp"))
&& (bond.getEnd().getAtomTypeName().equals("Csp"))) {
bondType = "1";
}
}
bond.setProperty("MMFF94 bond type", bondType);
}
return ringSetMolecule;

@Override public void setParameters(Object[] params) throws CDKException if (params.length > 1) {
throw new CDKException("BondCount only expects one parameter");
}
if (!(params[0] instanceof String)) {
throw new CDKException("The parameter must be of type IBond.Order");
}
String bondType = (String) params[0];
if (bondType.length() > 1 || !"sdtq".contains(bondType)) {
throw new CDKException("The only allowed values for this parameter are 's', 'd', 't', 'q' and ''.");
}
order = bondType;

public void writeMolecule(IAtomContainer container) throws Exception final int dim = getNumberOfDimensions(container);
StringBuilder line = new StringBuilder();
Map<Integer, Integer> rgroups = null;
Map<Integer, String> aliases = null;
String title = container.getTitle();
if (title == null) title = "";
if (title.length() > 80) title = title.substring(0, 80);
writer.write(title);
writer.write('\n');
writer.write("  ");
writer.write(getProgName());
writer.write(new SimpleDateFormat("MMddyyHHmm").format(System.currentTimeMillis()));
if (dim != 0) {
writer.write(Integer.toString(dim));
writer.write('D');
}
writer.write('\n');
String comment = (String) container.getProperty(CDKConstants.REMARK);
if (comment == null) comment = "";
if (comment.length() > 80) comment = comment.substring(0, 80);
writer.write(comment);
writer.write('\n');
Map<IAtom,ITetrahedralChirality> atomstereo = new HashMap<>();
Map<IAtom,Integer> atomindex = new HashMap<>();
for (IStereoElement element : container.stereoElements())
if (element instanceof ITetrahedralChirality)
atomstereo.put(((ITetrahedralChirality) element).getChiralAtom(), (ITetrahedralChirality) element);
for (IAtom atom : container.atoms())
atomindex.put(atom, atomindex.size());
line.append(formatMDLInt(container.getAtomCount(), 3));
line.append(formatMDLInt(container.getBondCount(), 3));
line.append("  0  0");
line.append(atomstereo.isEmpty() ? "  0" : "  1");
line.append("  0  0  0  0  0999 V2000");
writer.write(line.toString());
writer.write('\n');
for (int f = 0; f < container.getAtomCount(); f++) {
IAtom atom = container.getAtom(f);
line.setLength(0);
switch (dim) {
case 0:
line.append("    0.0000    0.0000    0.0000 ");
break;
case 2:
if (atom.getPoint2d() != null) {
line.append(formatMDLFloat((float) atom.getPoint2d().x));
line.append(formatMDLFloat((float) atom.getPoint2d().y));
line.append("    0.0000 ");
} else {
line.append("    0.0000    0.0000    0.0000 ");
}
break;
case 3:
if (atom.getPoint3d() != null) {
line.append(formatMDLFloat((float) atom.getPoint3d().x));
line.append(formatMDLFloat((float) atom.getPoint3d().y));
line.append(formatMDLFloat((float) atom.getPoint3d().z)).append(" ");
} else {
line.append("    0.0000    0.0000    0.0000 ");
}
break;
}
if (container.getAtom(f) instanceof IPseudoAtom) {
IPseudoAtom pseudoAtom = (IPseudoAtom) container.getAtom(f);
String label = pseudoAtom.getLabel();
if (label == null)
label = "";
Matcher matcher = NUMERED_R_GROUP.matcher(label);
if (pseudoAtom.getSymbol().equals("R") && !label.isEmpty() && matcher.matches()) {
line.append("R# ");
if (rgroups == null) {
rgroups = new TreeMap<Integer, Integer>();
}
rgroups.put(f + 1, Integer.parseInt(matcher.group(1)));
}
else {
if (label.length() > 3) {
if (aliases == null) aliases = new TreeMap<Integer, String>();
aliases.put(f + 1, label);
line.append(formatMDLString(atom.getSymbol(), 3));
} else {
if (!label.isEmpty())
line.append(formatMDLString(label, 3));
else
line.append(formatMDLString(atom.getSymbol(), 3));
}
}
} else {
line.append(formatMDLString(container.getAtom(f).getSymbol(), 3));
}
int[] atomprops = new int[12];
atomprops[0] = determineIsotope(atom);
atomprops[1] = determineCharge(container, atom);
atomprops[2] = determineStereoParity(container, atomstereo, atomindex, atom);
atomprops[5] = determineValence(container, atom);
atomprops[9] = determineAtomMap(atom);
line.append(formatMDLInt(atomprops[0], 2));
line.append(formatMDLInt(atomprops[1], 3));
int last = atomprops.length-1;
if (!writeDefaultProps.isSet())
{
while (last >= 0) {
if (atomprops[last] != 0)
break;
last--;
}
if (last >= 2 && last < 5)
last = 5;
}
for (int i = 2; i <= last; i++)
line.append(formatMDLInt(atomprops[i], 3));
line.append('\n');
writer.write(line.toString());
}
for (IBond bond : container.bonds()) {
line.setLength(0);
if (bond.getAtomCount() != 2) {
logger.warn("Skipping bond with more/less than two atoms: " + bond);
} else {
if (bond.getStereo() == IBond.Stereo.UP_INVERTED || bond.getStereo() == IBond.Stereo.DOWN_INVERTED
|| bond.getStereo() == IBond.Stereo.UP_OR_DOWN_INVERTED) {
line.append(formatMDLInt(atomindex.get(bond.getEnd()) + 1, 3));
line.append(formatMDLInt(atomindex.get(bond.getBegin()) + 1, 3));
} else {
line.append(formatMDLInt(atomindex.get(bond.getBegin()) + 1, 3));
line.append(formatMDLInt(atomindex.get(bond.getEnd()) + 1, 3));
}
int bondType = 0;
if (bond instanceof QueryBond) {
QueryBond qbond = ((QueryBond)bond);
Expr e = qbond.getExpression();
switch (e.type()) {
case ALIPHATIC_ORDER:
case ORDER:
bondType = e.value();
break;
case IS_AROMATIC:
bondType = 4;
break;
case SINGLE_OR_DOUBLE:
bondType = 5;
break;
case SINGLE_OR_AROMATIC:
bondType = 6;
break;
case DOUBLE_OR_AROMATIC:
bondType = 7;
break;
case TRUE:
bondType = 8;
break;
case OR:
if (e.equals(new Expr(Expr.Type.ALIPHATIC_ORDER, 1).or(new Expr(Expr.Type.ALIPHATIC_ORDER, 2))) ||
e.equals(new Expr(Expr.Type.ALIPHATIC_ORDER, 2).or(new Expr(Expr.Type.ALIPHATIC_ORDER, 1))))
bondType = 5;
else if (e.equals(new Expr(Expr.Type.ALIPHATIC_ORDER, 1).or(new Expr(Expr.Type.IS_AROMATIC))) ||
e.equals(new Expr(Expr.Type.IS_AROMATIC).or(new Expr(Expr.Type.ALIPHATIC_ORDER, 1))))
bondType = 6;
else if (e.equals(new Expr(Expr.Type.ALIPHATIC_ORDER, 2).or(new Expr(Expr.Type.IS_AROMATIC))) ||
e.equals(new Expr(Expr.Type.IS_AROMATIC).or(new Expr(Expr.Type.ALIPHATIC_ORDER, 2))))
bondType = 6;
break;
default:
throw new IllegalArgumentException("Unsupported bond type!");
}
} else {
if (bond.getOrder() != null) {
switch (bond.getOrder()) {
case SINGLE:
case DOUBLE:
case TRIPLE:
if (writeAromaticBondTypes.isSet() && bond.isAromatic())
bondType = 4;
else
bondType = bond.getOrder().numeric();
break;
case UNSET:
if (bond.isAromatic()) {
if (!writeAromaticBondTypes.isSet())
throw new CDKException("Bond at idx " + container.indexOf(bond) + " was an unspecific aromatic bond which should only be used for querie in Molfiles. These can be written if desired by enabling the option 'WriteAromaticBondTypes'.");
bondType = 4;
}
break;
}
}
}
if (bondType == 0)
throw new CDKException("Bond at idx=" + container.indexOf(bond) + " is not supported by Molfile, bond=" + bond.getOrder());
line.append(formatMDLInt(bondType, 3));
line.append("  ");
switch (bond.getStereo()) {
case UP:
line.append("1");
break;
case UP_INVERTED:
line.append("1");
break;
case DOWN:
line.append("6");
break;
case DOWN_INVERTED:
line.append("6");
break;
case UP_OR_DOWN:
line.append("4");
break;
case UP_OR_DOWN_INVERTED:
line.append("4");
break;
case E_OR_Z:
line.append("3");
break;
default:
line.append("0");
}
if (writeDefaultProps.isSet())
line.append("  0  0  0 ");
line.append('\n');
writer.write(line.toString());
}
}
for (int i = 0; i < container.getAtomCount(); i++) {
IAtom atom = container.getAtom(i);
if (atom.getProperty(CDKConstants.COMMENT) != null
&& atom.getProperty(CDKConstants.COMMENT) instanceof String
&& !((String) atom.getProperty(CDKConstants.COMMENT)).trim().equals("")) {
writer.write("V  ");
writer.write(formatMDLInt(i + 1, 3));
writer.write(" ");
writer.write((String) atom.getProperty(CDKConstants.COMMENT));
writer.write('\n');
}
}
for (int i = 0; i < container.getAtomCount(); i++) {
IAtom atom = container.getAtom(i);
Integer charge = atom.getFormalCharge();
if (charge != null && charge != 0) {
writer.write("M  CHG  1 ");
writer.write(formatMDLInt(i + 1, 3));
writer.write(" ");
writer.write(formatMDLInt(charge, 3));
writer.write('\n');
}
}
if (container.getSingleElectronCount() > 0) {
Map<Integer, SPIN_MULTIPLICITY> atomIndexSpinMap = new LinkedHashMap<Integer, SPIN_MULTIPLICITY>();
for (int i = 0; i < container.getAtomCount(); i++) {
int eCount = container.getConnectedSingleElectronsCount(container.getAtom(i));
switch (eCount) {
case 0:
continue;
case 1:
atomIndexSpinMap.put(i, SPIN_MULTIPLICITY.Monovalent);
break;
case 2:
atomIndexSpinMap.put(i, SPIN_MULTIPLICITY.DivalentSinglet);
break;
default:
logger.debug("Invalid number of radicals found: " + eCount);
break;
}
}
Iterator<Map.Entry<Integer, SPIN_MULTIPLICITY>> iterator = atomIndexSpinMap.entrySet().iterator();
for (int i = 0; i < atomIndexSpinMap.size(); i += NN8) {
if (atomIndexSpinMap.size() - i <= NN8) {
writer.write("M  RAD" + formatMDLInt(atomIndexSpinMap.size() - i, WIDTH));
writeRadicalPattern(iterator, 0);
} else {
writer.write("M  RAD" + formatMDLInt(NN8, WIDTH));
writeRadicalPattern(iterator, 0);
}
writer.write('\n');
}
}
for (int i = 0; i < container.getAtomCount(); i++) {
IAtom atom = container.getAtom(i);
if (!(atom instanceof IPseudoAtom)) {
Integer atomicMass = atom.getMassNumber();
if (!writeMajorIsotopes.isSet() &&
isMajorIsotope(atom))
atomicMass = null;
if (atomicMass != null) {
writer.write("M  ISO  1 ");
writer.write(formatMDLInt(i + 1, 3));
writer.write(" ");
writer.write(formatMDLInt(atomicMass, 3));
writer.write('\n');
}
}
}
if (rgroups != null) {
StringBuilder rgpLine = new StringBuilder();
int cnt = 0;
for (Map.Entry<Integer, Integer> e : rgroups.entrySet()) {
rgpLine.append(formatMDLInt(e.getKey(), 4));
rgpLine.append(formatMDLInt(e.getValue(), 4));
cnt++;
if (cnt == 8) {
rgpLine.insert(0, "M  RGP" + formatMDLInt(cnt, 3));
writer.write(rgpLine.toString());
writer.write('\n');
rgpLine = new StringBuilder();
cnt = 0;
}
}
if (cnt != 0) {
rgpLine.insert(0, "M  RGP" + formatMDLInt(cnt, 3));
writer.write(rgpLine.toString());
writer.write('\n');
}
}
if (aliases != null) {
for (Map.Entry<Integer, String> e : aliases.entrySet()) {
writer.write("A" + formatMDLInt(e.getKey(), 5));
writer.write('\n');
String label = e.getValue();
if (label.length() > 70) label = label.substring(0, 70);
writer.write(label);
writer.write('\n');
}
}
writeSgroups(container, writer, atomindex);
writer.write("M  END");
writer.write('\n');
writer.flush();

private MacroScore bestScore(IRing macrocycle, IRingSet ringset, int wind, int[] winding) final int numAtoms = macrocycle.getAtomCount();
List<Integer> heteroIdxs = new ArrayList<>();
List<List<Integer>> ringAttachs = new ArrayList<>();
for (int i = 0; i < numAtoms; i++) {
if (macrocycle.getAtom(i).getAtomicNumber() != 6)
heteroIdxs.add(i);
}
for (IAtomContainer other : ringset.atomContainers()) {
if (other == macrocycle)
continue;
IAtomContainer shared = AtomContainerManipulator.getIntersection(macrocycle, other);
if (shared.getAtomCount() >= 2 && shared.getAtomCount() <= 4)
ringAttachs.add(getAttachedInOrder(macrocycle, shared));
}
final int convex = wind;
final int concave = -wind;
MacroScore best = null;
for (int i = 0; i < winding.length; i++) {
int nRingClick = 0;
for (List<Integer> ringAttach : ringAttachs) {
int r1, r2, r3, r4;
switch (ringAttach.size()) {
case 2:
r1 = (ringAttach.get(0) + i) % numAtoms;
r2 = (ringAttach.get(1) + i) % numAtoms;
if (winding[r1] == winding[r2]) {
if (winding[r1] == convex)
nRingClick += 5;
else
nRingClick++;
}
break;
case 3:
r1 = (ringAttach.get(0) + i) % numAtoms;
r2 = (ringAttach.get(1) + i) % numAtoms;
r3 = (ringAttach.get(2) + i) % numAtoms;
if (winding[r1] == convex &&
winding[r2] == concave &&
winding[r3] == convex)
nRingClick += 5;
else if (winding[r1] == concave &&
winding[r2] == convex &&
winding[r3] == concave)
nRingClick++;
break;
case 4:
r1 = (ringAttach.get(0) + i) % numAtoms;
r2 = (ringAttach.get(1) + i) % numAtoms;
r3 = (ringAttach.get(2) + i) % numAtoms;
r4 = (ringAttach.get(3) + i) % numAtoms;
if (winding[r1] == convex &&
winding[r2] == concave &&
winding[r3] == concave &&
winding[r4] == convex)
nRingClick++;
else if (winding[r1] == concave &&
winding[r2] == convex &&
winding[r3] == convex &&
winding[r4] == concave)
nRingClick++;
break;
}
}
int nConcaveHetero = 0;
for (int heteroIdx : heteroIdxs) {
int k = (heteroIdx + i) % numAtoms;
if (winding[k] == concave)
nConcaveHetero++;
}
int nCorrectStereo   = 0;
int nIncorrectStereo = 0;
for (IStereoElement se : macrocycle.stereoElements()) {
if (se.getConfigClass() == IStereoElement.CisTrans) {
IBond bond = (IBond) se.getFocus();
IAtom beg  = bond.getBegin();
IAtom end  = bond.getEnd();
int cfg;
if (winding[(macrocycle.indexOf(beg) + i) % numAtoms] ==
winding[(macrocycle.indexOf(end) + i) % numAtoms]) {
cfg = IStereoElement.TOGETHER;
} else {
cfg = IStereoElement.OPPOSITE;
}
if (cfg == se.getConfigOrder()) {
nCorrectStereo++;
} else {
nIncorrectStereo++;
}
}
}
MacroScore score = new MacroScore(i,
nConcaveHetero,
nCorrectStereo,
nRingClick);
if (score.compareTo(best) < 0) {
best = score;
}
}
return best;

private void writeAtomContainer(IAtomContainerSet som) throws IOException String sym;
double chrg;
for (int molnum = 0; molnum < som.getAtomContainerCount(); molnum++) {
IAtomContainer mol = som.getAtomContainer(molnum);
try {
String molname = "mol " + (molnum + 1) + " " + mol.getTitle();
writer.write(molname, 0, molname.length());
writer.write('\n');
Iterator<IAtom> atoms = mol.atoms().iterator();
int i = 0;
while (atoms.hasNext()) {
IAtom atom = atoms.next();
String line = "atom ";
sym = atom.getSymbol();
chrg = atom.getCharge();
Point3d point = atom.getPoint3d();
line = line + Integer.toString(i + 1) + " - " + sym + " ** - " + Double.toString(chrg) + " "
+ Double.toString(point.x) + " " + Double.toString(point.y) + " "
+ Double.toString(point.z) + " ";
String buf = "";
int ncon = 0;
Iterator<IBond> bonds = mol.bonds().iterator();
while (bonds.hasNext()) {
IBond bond = bonds.next();
if (bond.contains(atom)) {
IAtom connectedAtom = bond.getOther(atom);
IBond.Order bondOrder = bond.getOrder();
int serial;
String bondType = "";
serial = mol.indexOf(connectedAtom);
if (bondOrder == IBond.Order.SINGLE)
bondType = "s";
else if (bondOrder == IBond.Order.DOUBLE)
bondType = "d";
else if (bondOrder == IBond.Order.TRIPLE)
bondType = "t";
else if (bond.getFlag(CDKConstants.ISAROMATIC)) bondType = "a";
buf = buf + Integer.toString(serial + 1) + " " + bondType + " ";
ncon++;
}
}
line = line + " " + Integer.toString(ncon) + " " + buf;
writer.write(line, 0, line.length());
writer.write('\n');
i++;
}
String buf = "endmol " + (molnum + 1);
writer.write(buf, 0, buf.length());
writer.write('\n');
} catch (IOException e) {
throw e;
}
}

public static String getJournalReport(QJMStatus status) StringBuilder sb = new StringBuilder();
sb.append("<table border=1 cellpadding=1 cellspacing=0 title=\"Journals\">");
sb.append("<thead><tr><td><b>JournalId</b></td><td><b>Statistics</b></td></tr></thead>");
for (String journalId : status.getJournalIds()) {
sb.append("<tr><td>" + journalId + "</td><td>");
getHTMLTableForASingleJournal(status, journalId, sb);
sb.append("</td></tr>");
}
sb.append("</table>");
return sb.toString();

void appendHtmlReport(StringBuilder sb) sb.append("<table class=\"storage\">");
sb.append("<thead><tr><td>JN</td><td>Status</td></tr></thead>\n");
for (AsyncLogger l : loggers) {
sb.append("<tr>");
sb.append("<td>" + JspUtil.escapeXml(l.toString()) + "</td>");
sb.append("<td>");
l.appendHtmlReport(sb);
sb.append("</td></tr>\n");
}
sb.append("</table>");

public static String getNodeReport(QJMStatus status) StringBuilder sb = new StringBuilder();
sb.append("<table border=1 cellpadding=1 cellspacing=0 title=\"Journals\">");
sb.append("<thead><tr><td><b>Journal node</b></td><td><b>Alive</b></td></tr></thead>");
for (Entry<String, Boolean> e : status.getAliveMap().entrySet()) {
if (e.getValue()) {
sb.append("<tr><td>" + e.getKey()
+ "</td><td><font color=green>Active</font></td></tr>");
} else {
sb.append("<tr><td>" + e.getKey()
+ "</td><td><font color=red>Failed</font></td></tr>");
}
}
sb.append("</table>");
return sb.toString();

public static void getHTMLTableForASingleJournal(QJMStatus status, String journalName, StringBuilder sb) List<StatsDescriptor> stats = status.stats.get(journalName);
if (stats == null) {
return;
}
Set<String> statsNames = status.statNames;
sb.append("<table border=1 align=\"right\" cellpadding=1 "
+ "cellspacing=0 title=\"Journal statistics\">");
sb.append("<thead><tr><td></td>");
for (StatsDescriptor sd : stats) {
sb.append("<td><b>" + sd.journalNode + "</b></td>");
}
sb.append("</tr></thead>");
for (String st : statsNames) {
sb.append("<tr><td>" + st + "</td>");
for (StatsDescriptor sd : stats) {
sb.append("<td align=\"right\">" + getValue(sd.statsPerJournal, st)
+ "</td>");
}
sb.append("</tr>");
}
sb.append("</table>");

private int getBlockInfo(String[] argv, int i) throws IOException long blockId = Long.valueOf(argv[i++]);
LocatedBlockWithFileName locatedBlock =
getDFS().getClient().getBlockInfo(blockId);
if (null == locatedBlock) {
System.err.println("Could not find the block with id : " + blockId);
return -1;
}
StringBuilder sb = new StringBuilder();
sb.append("block: ")
.append(locatedBlock.getBlock()).append("\n")
.append("filename: ")
.append(locatedBlock.getFileName()).append("\n")
.append("locations: ");
DatanodeInfo[] locs = locatedBlock.getLocations();
for (int k=0; k<locs.length; k++) {
if (k > 0) {
sb.append(" , ");
}
sb.append(locs[k].getHostName());
}
