normalizer.getClass()));

protected void getDeviceBuffers(CudaContext context, int deviceId) NativeOps nativeOps = NativeOpsHolder.getInstance().getDeviceNativeOps();
int sizeOf = 8;
val reductionPointer = nativeOps.mallocDevice(16384 * sizeOf, deviceId, 0);
if (reductionPointer == null)
throw new IllegalStateException("Can't allocate [DEVICE] reduction buffer memory!");
nativeOps.memsetAsync(reductionPointer, 0, 16384 * sizeOf, 0, context.getOldStream());
context.syncOldStream();
val allocationPointer = nativeOps.mallocDevice(16384 * sizeOf, deviceId, 0);
if (allocationPointer == null)
throw new IllegalStateException("Can't allocate [DEVICE] allocation buffer memory!");
val scalarPointer = nativeOps.mallocHost(sizeOf, 0);
if (scalarPointer == null)
throw new IllegalStateException("Can't allocate [HOST] scalar buffer memory!");
context.setBufferScalar(scalarPointer);
context.setBufferAllocation(allocationPointer);
context.setBufferReduction(reductionPointer);
val specialPointer = nativeOps.mallocDevice(16384 * sizeOf, deviceId, 0);
if (specialPointer == null)
throw new IllegalStateException("Can't allocate [DEVICE] special buffer memory!");
nativeOps.memsetAsync(specialPointer, 0, 16384 * sizeOf, 0, context.getOldStream());
context.setBufferSpecial(specialPointer);

public void commitBlockSynchronization(Block lastblock, long newgenerationstamp, long newlength, boolean closeFile, boolean deleteblock, DatanodeID[] newtargets ) throws IOException LOG.info("commitBlockSynchronization(lastblock=" + lastblock
+ ", newgenerationstamp=" + newgenerationstamp
+ ", newlength=" + newlength
+ ", newtargets=" + Arrays.asList(newtargets)
+ ", closeFile=" + closeFile
+ ", deleteBlock=" + deleteblock
+ ")");
String src = null;
writeLock();
try {
if (isInSafeMode()) {
throw new SafeModeException("Cannot commitBlockSynchronization "
+ lastblock, safeMode);
}
Block blockWithWildcardGenstamp = new Block(lastblock.getBlockId());
final BlockInfo oldblockinfo = blocksMap.getStoredBlock(blockWithWildcardGenstamp);
if (oldblockinfo == null) {
throw new IOException("Block (=" + lastblock + ") not found");
}
if (!deleteblock
&& lastblock.getGenerationStamp() != oldblockinfo
.getGenerationStamp()
&& oldblockinfo.getGenerationStamp() >= newgenerationstamp) {
throw new IOException("Try to update block " + oldblockinfo
+ " to generation stamp " + newgenerationstamp);
}
INodeFile iFile = oldblockinfo.getINode();
if (!iFile.isUnderConstruction()) {
throw new IOException("Unexpected block (=" + lastblock
+ ") since the file (=" + iFile.getLocalName()
+ ") is not under construction");
}
INodeFileUnderConstruction pendingFile = (INodeFileUnderConstruction) iFile;
pendingFile.checkLastBlockId(lastblock.getBlockId());
blocksMap.removeBlock(oldblockinfo);
if (deleteblock) {
pendingFile.removeBlock(lastblock);
} else {
lastblock.set(lastblock.getBlockId(), newlength, newgenerationstamp);
final BlockInfo newblockinfo =
blocksMap.addINode(lastblock, pendingFile,
pendingFile.getReplication());
DatanodeDescriptor[] descriptors = null;
List<DatanodeDescriptor> descriptorsList =
new ArrayList<DatanodeDescriptor>(newtargets.length);
for(int i = 0; i < newtargets.length; i++) {
DatanodeDescriptor node =
datanodeMap.get(newtargets[i].getStorageID());
if (node != null) {
if (closeFile) {
node.addBlock(newblockinfo);
}
descriptorsList.add(node);
} else {
LOG.error("commitBlockSynchronization included a target DN " +
newtargets[i] + " which is not known to NN. Ignoring.");
}
}
if (!descriptorsList.isEmpty()) {
descriptors = descriptorsList.toArray(new DatanodeDescriptor[0]);
}
pendingFile.setLastBlock(newblockinfo, descriptors);
}
src = pendingFile.getFullPathName();
if (!closeFile) {
if (supportAppends || persistBlocks) {
dir.persistBlocks(src, pendingFile);
}
} else {
finalizeINodeFileUnderConstruction(src, pendingFile);
}
} finally {
writeUnlock();
}
if (closeFile || supportAppends) {
getEditLog().logSync();
}
LOG.info("commitBlockSynchronization(newblock=" + lastblock
+ ", file=" + src + ") successful");

public void updateBlock(int namespaceId, Block oldblock, Block newblock) throws IOException if (oldblock.getBlockId() != newblock.getBlockId()) {
throw new IOException("Cannot update oldblock (=" + oldblock
+ ") to newblock (=" + newblock + ").");
}
boolean isValidUpdate =
(newblock.getGenerationStamp() > oldblock.getGenerationStamp()) ||
(newblock.getGenerationStamp() == oldblock.getGenerationStamp() &&
newblock.getNumBytes() == oldblock.getNumBytes());
if (!isValidUpdate) {
throw new IOException(
"Cannot update oldblock=" + oldblock +
" to newblock=" + newblock + " since generation stamps must " +
"increase, or else length must not change.");
}
for(;;) {
final List<Thread> threads = tryUpdateBlock(namespaceId, oldblock, newblock);
if (threads == null) {
DataNode.LOG.info("Updated Block: namespaceid: " + namespaceId + " oldBlock: "
+ oldblock + " newBlock: " + newblock);
return;
}
DataNode.LOG.info("Waiting other threads to update block: namespaceid: "
+ namespaceId + " oldBlock: " + oldblock + " newBlock: " + newblock);
interruptAndJoinThreads(threads);
}

public BlockInfo updateINode(BlockInfo oldBlock, Block newBlock, INodeFile iNode, short replication, boolean forceUpdate) throws IOException List<DatanodeDescriptor> locations = null;
if (oldBlock != null && (!oldBlock.equals(newBlock) || forceUpdate)) {
if (oldBlock.getBlockId() != newBlock.getBlockId()) {
throw new IOException("block ids don't match : " + oldBlock + ", "
+ newBlock);
}
if (forceUpdate) {
locations = new ArrayList<DatanodeDescriptor>();
for (int i=0; i<oldBlock.numNodes(); i++) {
locations.add(oldBlock.getDatanode(i));
}
} else {
if (!iNode.isUnderConstruction()) {
throw new IOException(
"Try to update generation of a finalized block old block: "
+ oldBlock + ", new block: " + newBlock);
}
}
removeBlock(oldBlock);
}
BlockInfo info = checkBlockInfo(newBlock, replication);
info.set(newBlock.getBlockId(), newBlock.getNumBytes(), newBlock.getGenerationStamp());
info.inode = iNode;
if (locations != null) {
if (locations != null) {
for (DatanodeDescriptor d : locations) {
d.addBlock(info);
}
}
}
return info;

private List<Thread> tryUpdateBlock(int namespaceId, Block oldblock, Block newblock) throws IOException lock.writeLock().lock();
try {
ArrayList<Thread> activeThreads = getActiveThreads(namespaceId, oldblock);
if (activeThreads != null) {
return activeThreads;
}
DatanodeBlockInfo binfo = volumeMap.get(namespaceId, oldblock);
if (binfo == null) {
throw new IOException("Block " + oldblock
+ " doesn't exist or has been recovered to a new generation ");
}
File blockFile = binfo.getBlockDataFile().getFile();
long oldgs;
File oldMetaFile = null;
if (binfo.isInlineChecksum()) {
oldgs = BlockInlineChecksumReader
.getGenerationStampFromInlineChecksumFile(blockFile.getName());
} else {
oldMetaFile = BlockWithChecksumFileWriter.findMetaFile(blockFile);
oldgs = BlockWithChecksumFileReader.parseGenerationStampInMetaFile(
blockFile, oldMetaFile);
}
if (oldgs > newblock.getGenerationStamp()) {
throw new IOException("Cannot update block (id=" + newblock.getBlockId()
+ ") generation stamp from " + oldgs
+ " to " + newblock.getGenerationStamp());
}
if (newblock.getNumBytes() > oldblock.getNumBytes()) {
throw new IOException("Cannot update block file (=" + blockFile
+ ") length from " + oldblock.getNumBytes() + " to " + newblock.getNumBytes());
}
try {
volumeMap.copyOngoingCreates(namespaceId, oldblock);
} catch (CloneNotSupportedException e) {
throw new IOException("Cannot clone ActiveFile object", e);
}
File tmpMetaFile = null;
if (!binfo.isInlineChecksum()) {
tmpMetaFile = new File(oldMetaFile.getParent(),
oldMetaFile.getName() + "_tmp" + newblock.getGenerationStamp());
if (!oldMetaFile.renameTo(tmpMetaFile)) {
throw new IOException("Cannot rename block meta file to " + tmpMetaFile);
}
}
long oldBlockLength;
if (!binfo.isInlineChecksum()) {
oldBlockLength = blockFile.length();
} else {
oldBlockLength = BlockInlineChecksumReader.getBlockSizeFromFileLength(
blockFile.length(), binfo.getChecksumType(),
binfo.getBytesPerChecksum());
}
ActiveFile file = null;
if (newblock.getNumBytes() < oldBlockLength) {
if (!binfo.isInlineChecksum()) {
new BlockWithChecksumFileWriter(binfo.getBlockDataFile(), tmpMetaFile)
.truncateBlock(oldBlockLength, newblock.getNumBytes());
} else {
new BlockInlineChecksumWriter(binfo.getBlockDataFile(), binfo.getChecksumType(),
binfo.getBytesPerChecksum(), datanode.writePacketSize)
.truncateBlock(newblock.getNumBytes());
}
file = volumeMap.getOngoingCreates(namespaceId, oldblock);
if (file != null) {
file.setBytesAcked(newblock.getNumBytes());
file.setBytesOnDisk(newblock.getNumBytes());
file.setBytesReceived(newblock.getNumBytes());
} else {
binfo.syncInMemorySize();
}
}
String newDataFileName;
if (!binfo.isInlineChecksum()) {
File newMetaFile = BlockWithChecksumFileWriter.getMetaFile(blockFile, newblock);
if (!tmpMetaFile.renameTo(newMetaFile)) {
throw new IOException("Cannot rename tmp meta file to " + newMetaFile);
}
} else {
newDataFileName = BlockInlineChecksumWriter.getInlineChecksumFileName(
newblock, binfo.getChecksumType(), binfo.getBytesPerChecksum());
File newDataFile = new File(blockFile.getParent(), newDataFileName);
if (!blockFile.renameTo(newDataFile)) {
throw new IOException("Cannot rename data file to " + newDataFileName);
}
if (datanode.syncOnClose) {
NativeIO.fsyncIfPossible(newDataFile.getParent());
}
setDataFileForBlock(namespaceId, oldblock, newDataFile);
}
if(volumeMap.getOngoingCreates(namespaceId, oldblock) != null){
ActiveFile af = volumeMap.removeOngoingCreates(namespaceId, oldblock);
volumeMap.addOngoingCreates(namespaceId, newblock, af);
}
volumeMap.update(namespaceId, oldblock, newblock);
validateBlockMetadata(namespaceId, newblock);
return null;
} finally {
lock.writeLock().unlock();
}

public void updateBlock(int namespaceId, Block oldblock, Block newblock, boolean finalize) throws IOException LOG.info("namespaceId: " + namespaceId
+ ", oldblock=" + oldblock + "(length=" + oldblock.getNumBytes()
