myMetrics.blocksWritten.inc();
notifyNamenodeReceivedBlock(namespaceId, newblock, null);
LOG.info("Received block " + newblock +
" of size " + newblock.getNumBytes() +
" as part of lease recovery.");
}

private boolean setupPipelineForAppend(LocatedBlock lastBlock) throws IOException if (nodes == null || nodes.length == 0) {
String msg = "Could not get block locations. " +
"Source file \"" + src
+ "\" - Aborting...";
DFSClient.LOG.warn(msg);
setLastException(new IOException(msg));
closed = true;
if (streamer != null) streamer.close();
return false;
}
boolean success = createBlockOutputStream(nodes, dfsClient.clientName, false, true);
long oldGenerationStamp =
((LocatedBlockWithOldGS)lastBlock).getOldGenerationStamp();
if (success) {
Block newBlock = lastBlock.getBlock();
Block oldBlock = new Block(newBlock.getBlockId(), newBlock.getNumBytes(),
oldGenerationStamp);
dfsClient.namenode.updatePipeline(dfsClient.clientName,
oldBlock, newBlock, nodes);
} else {
DFSClient.LOG.warn("Fall back to block recovery process when trying" +
" to setup the append pipeline for file " + src);
block.setGenerationStamp(oldGenerationStamp);
while(processDatanodeError(true, true)) {
try {
Thread.sleep(1000);
} catch (InterruptedException  e) {
lastException = new IOException(e);
break;
}
}
}
return success;

@Override public LocatedBlock syncBlock( Block block, List<BlockRecord> syncList, boolean closeFile, List<InterDatanodeProtocol> datanodeProxies, long deadline ) throws IOException if (LOG.isDebugEnabled()) {
LOG.debug("block=" + block + ", (length=" + block.getNumBytes()
+ "), syncList=" + syncList + ", closeFile=" + closeFile);
}
if (syncList.isEmpty()) {
bsp.commitBlockSynchronization(block, 0, 0, closeFile, true,
DatanodeID.EMPTY_ARRAY);
return null;
}
List<DatanodeID> successList = new ArrayList<DatanodeID>();
throwIfAfterTime(deadline);
long generationstamp = -1;
try {
generationstamp = bsp.nextGenerationStamp(block, closeFile);
} catch (RemoteException e) {
if (e.unwrapRemoteException() instanceof BlockAlreadyCommittedException) {
throw new BlockAlreadyCommittedException(e);
} else {
throw e;
}
}
Block newblock = new Block(block.getBlockId(), block.getNumBytes(), generationstamp);
for(BlockRecord r : syncList) {
try {
throwIfAfterTime(deadline);
LOG.info("Updating block " + r + " to " + newblock);
r.datanode.updateBlock(namespaceId, r.info.getBlock(), newblock, closeFile);
successList.add(r.id);
} catch (BlockRecoveryTimeoutException e) {
throw e;
} catch (IOException e) {
InterDatanodeProtocol.LOG.warn("Failed to updateBlock (newblock="
+ newblock + ", datanode=" + r.id + ")", e);
}
}
LOG.info("Updated blocks on syncList for block " + block + " to " + newblock);
DataNode.stopAllProxies(datanodeProxies);
if (!successList.isEmpty()) {
DatanodeID[] nlist = successList.toArray(new DatanodeID[successList.size()]);
throwIfAfterTime(deadline);
bsp.commitBlockSynchronization(block,
newblock.getGenerationStamp(), newblock.getNumBytes(), closeFile, false,
nlist);
DatanodeInfo[] info = new DatanodeInfo[nlist.length];
for (int i = 0; i < nlist.length; i++) {
info[i] = new DatanodeInfo(nlist[i]);
}
return new LocatedBlock(newblock, info);
}
StringBuilder b = new StringBuilder();
for(BlockRecord r : syncList) {
b.append("\n  " + r.id);
}
throw new IOException("Cannot recover " + block + ", none of these "
+ syncList.size() + " datanodes success {" + b + "\n}");

void fsync(String src, String clientName) throws IOException NameNode.stateChangeLog.info("BLOCK* NameSystem.fsync: file "
+ src + " for " + clientName);
writeLock();
try {
if (isInSafeMode()) {
throw new SafeModeException("Cannot fsync file " + src, safeMode);
}
INodeFileUnderConstruction pendingFile = checkLease(src, clientName);
Block last = pendingFile.getLastBlock();
if (last.getNumBytes() == 0) {
last.setNumBytes(1);
}
dir.persistBlocks(src, pendingFile);
} finally {
writeUnlock();
}
getEditLog().logSync();

boolean internalReleaseLeaseOne(Lease lease, String src, INodeFileUnderConstruction pendingFile, boolean discardLastBlock) throws IOException if (discardLastBlock && discardDone(pendingFile, src)) {
return false;
}
if (pendingFile.getTargets() == null ||
pendingFile.getTargets().length == 0) {
if (pendingFile.getBlocks().length == 0) {
finalizeINodeFileUnderConstruction(src, pendingFile);
NameNode.stateChangeLog.warn("BLOCK*"
+ " internalReleaseLease: No blocks found, lease removed for " +  src);
return true;
}
Block[] blocks = pendingFile.getBlocks();
Block last = blocks[blocks.length - 1];
DatanodeDescriptor[] targets =
new DatanodeDescriptor[blocksMap.numNodes(last)];
Iterator<DatanodeDescriptor> it = blocksMap.nodeIterator(last);
for (int i = 0; it != null && it.hasNext(); i++) {
targets[i] = it.next();
}
pendingFile.setTargets(targets, last.getGenerationStamp());
}
pendingFile.assignPrimaryDatanode();
Lease reassignedLease = reassignLease(
lease, src, HdfsConstants.NN_RECOVERY_LEASEHOLDER, pendingFile
);
getEditLog().logOpenFile(src, pendingFile);
leaseManager.renewLease(reassignedLease);
return false;

private boolean discardDone(INodeFileUnderConstruction pendingFile, String src) throws IOException Block[] blocks = pendingFile.getBlocks();
if (blocks == null || blocks.length == 0) {
return false;
}
Block last = blocks[blocks.length-1];
if (last.getNumBytes() == 0) {
dir.removeBlock(src, pendingFile, last);
finalizeINodeFileUnderConstruction(src, pendingFile);
NameNode.stateChangeLog.warn("BLOCK*" +
" internalReleaseLease: discarded last block " + last +
" , lease removed for " +  src);
return true;
}
return false;

