@Override public IRenderingElement generate(IAtomContainer container, RendererModel model) final Map<IChemObject, Integer> highlight = container.getProperty(ID_MAP);
if (highlight == null) return null;
final Palette palette = model.getParameter(HighlightPalette.class).getValue();
final double radius = model.getParameter(HighlightRadius.class).getValue()
/ model.getParameter(BasicSceneGenerator.Scale.class).getValue();
final Map<Integer, Area> shapes = new HashMap<Integer, Area>();
for (IAtom atom : container.atoms()) {
Integer id = highlight.get(atom);
if (id == null) continue;
Area area = shapes.get(id);
Shape shape = createAtomHighlight(atom, radius);
if (area == null)
shapes.put(id, new Area(shape));
else
area.add(new Area(shape));
}
for (IBond bond : container.bonds()) {
Integer id = highlight.get(bond);
if (id == null) continue;
Area area = shapes.get(id);
Shape shape = createBondHighlight(bond, radius);
if (area == null)
shapes.put(id, (area = new Area(shape)));
else
area.add(new Area(shape));
IAtom   a1   = bond.getBegin(), a2 = bond.getEnd();
Integer a1Id = highlight.get(a1), a2Id = highlight.get(a2);
if (a1Id != null && !a1Id.equals(id)) area.subtract(shapes.get(a1Id));
if (a2Id != null && !a2Id.equals(id)) area.subtract(shapes.get(a2Id));
}
ElementGroup group = new ElementGroup();
for (Map.Entry<Integer, Area> e : shapes.entrySet()) {
group.add(GeneralPath.shapeOf(e.getValue(), palette.color(e.getKey())));
}
return group;

@Override public IRenderingElement generate(IAtomContainer container, RendererModel model) ElementGroup group = new ElementGroup();
final double SCREEN_RADIUS = 2.0;
final Color RADICAL_COLOR = Color.BLACK;
final double ATOM_RADIUS = ((AtomRadius) model.getParameter(AtomRadius.class)).getValue()
/ model.getParameter(Scale.class).getValue();
double modelRadius = SCREEN_RADIUS / model.getParameter(Scale.class).getValue();
double modelSpacing = modelRadius * 2.5;
Map<IAtom, Integer> singleElectronsPerAtom = new HashMap<IAtom, Integer>();
for (ISingleElectron electron : container.singleElectrons()) {
IAtom atom = electron.getAtom();
if (singleElectronsPerAtom.get(atom) == null) singleElectronsPerAtom.put(atom, 0);
Point2d point = atom.getPoint2d();
int align = GeometryUtil.getBestAlignmentForLabelXY(container, atom);
double xRadius = point.x;
double yRadius = point.y;
if (align == 1) {
xRadius += ATOM_RADIUS * 4 + singleElectronsPerAtom.get(atom) * modelSpacing;
} else if (align == -1) {
xRadius -= ATOM_RADIUS * 4 + singleElectronsPerAtom.get(atom) * modelSpacing;
} else if (align == 2) {
yRadius += ATOM_RADIUS * 4 + singleElectronsPerAtom.get(atom) * modelSpacing;
} else if (align == -2) {
yRadius -= ATOM_RADIUS * 4 + singleElectronsPerAtom.get(atom) * modelSpacing;
}
singleElectronsPerAtom.put(atom, singleElectronsPerAtom.get(atom) + 1);
group.add(new OvalElement(xRadius, yRadius, modelRadius, true, RADICAL_COLOR));
}
return group;

@Override public IRenderingElement generate(IReaction reaction, RendererModel model) Rectangle2D totalBoundsReactants = BoundsCalculator.calculateBounds(reaction.getReactants());
Rectangle2D totalBoundsProducts = BoundsCalculator.calculateBounds(reaction.getProducts());
if (totalBoundsReactants == null || totalBoundsProducts == null) return null;
double separation = model.getParameter(BondLength.class).getValue()
/ model.getParameter(Scale.class).getValue();
Color foregroundColor = model.getParameter(BasicSceneGenerator.ForegroundColor.class).getValue();
return new ArrowElement(totalBoundsReactants.getMaxX() + separation, totalBoundsReactants.getCenterY(),
totalBoundsProducts.getMinX() - separation, totalBoundsReactants.getCenterY(), 1 / model.getParameter(
Scale.class).getValue(), true, foregroundColor);

