@Override public IRenderingElement generate(IReaction reaction, RendererModel model) if (!model.getParameter(ShowReactionBoxes.class).getValue()) return null;
if (reaction.getProductCount() == 0) return new ElementGroup();
double distance = model.getParameter(BondLength.class).getValue() / model.getParameter(Scale.class).getValue()
/ 2;
Rectangle2D totalBounds = null;
for (IAtomContainer molecule : reaction.getProducts().atomContainers()) {
Rectangle2D bounds = BoundsCalculator.calculateBounds(molecule);
if (totalBounds == null) {
totalBounds = bounds;
} else {
totalBounds = totalBounds.createUnion(bounds);
}
}
if (totalBounds == null) return null;
ElementGroup diagram = new ElementGroup();
Color foregroundColor = model.getParameter(BasicSceneGenerator.ForegroundColor.class).getValue();
diagram.add(new RectangleElement(totalBounds.getMinX() - distance, totalBounds.getMinY() - distance,
totalBounds.getMaxX() + distance, totalBounds.getMaxY() + distance, foregroundColor));
diagram.add(new TextElement((totalBounds.getMinX() + totalBounds.getMaxX()) / 2, totalBounds.getMinY()
- distance, "Products", foregroundColor));
return diagram;

@Override public IRenderingElement generate(IReaction reaction, RendererModel model) if (!model.getParameter(ShowReactionBoxes.class).getValue()) return null;
double separation = model.getParameter(BondLength.class).getValue()
/ model.getParameter(Scale.class).getValue();
Rectangle2D totalBounds = BoundsCalculator.calculateBounds(reaction);
if (totalBounds == null) return null;
ElementGroup diagram = new ElementGroup();
Color foregroundColor = model.getParameter(BasicSceneGenerator.ForegroundColor.class).getValue();
diagram.add(new RectangleElement(totalBounds.getMinX() - separation, totalBounds.getMinY() - separation,
totalBounds.getMaxX() + separation, totalBounds.getMaxY() + separation, foregroundColor));
if (reaction.getID() != null) {
diagram.add(new TextElement((totalBounds.getMinX() + totalBounds.getMaxX()) / 2, totalBounds.getMinY()
- separation, reaction.getID(), foregroundColor));
}
return diagram;

@Override public IRenderingElement generate(IReaction reaction, RendererModel model) if (!model.getParameter(ShowReactionBoxes.class).getValue()) return null;
if (reaction.getReactantCount() == 0) return new ElementGroup();
double separation = model.getParameter(BondLength.class).getValue()
/ model.getParameter(Scale.class).getValue() / 2;
Rectangle2D totalBounds = BoundsCalculator.calculateBounds(reaction.getReactants());
ElementGroup diagram = new ElementGroup();
double minX = totalBounds.getMinX();
double minY = totalBounds.getMinY();
double maxX = totalBounds.getMaxX();
double maxY = totalBounds.getMaxY();
Color foregroundColor = model.getParameter(BasicSceneGenerator.ForegroundColor.class).getValue();
diagram.add(new RectangleElement(minX - separation, minY - separation, maxX + separation, maxY + separation,
foregroundColor));
diagram.add(new TextElement((minX + maxX) / 2, minY - separation, "Reactants", foregroundColor));
return diagram;

@Override public IRenderingElement generate(IAtomContainer container, RendererModel model) ElementGroup numbers = new ElementGroup();
if (!model.getParameter(WillDrawAtomNumbers.class).getValue()) return numbers;
Vector2d offset = new Vector2d(this.offset.getValue().x, -this.offset.getValue().y);
offset.scale(1 / model.getParameter(Scale.class).getValue());
int number = 1;
for (IAtom atom : container.atoms()) {
Point2d point = new Point2d(atom.getPoint2d());
point.add(offset);
numbers.add(new TextElement(point.x, point.y, String.valueOf(number), colorByType.getValue() ? atomColorer
.getValue().getAtomColor(atom) : textColor.getValue()));
number++;
}
return numbers;

