public void sortRelations(CmsObject cms, CmsResourceStatusBean resStatus) final List<CmsSite> sites = OpenCms.getSiteManager().getAvailableSites(
cms,
false,
false,
cms.getRequestContext().getOuFqn());
Collections.sort(resStatus.getOtherSiteRelationSources(), new Comparator<CmsResourceStatusRelationBean>() {
private Map<String, Integer> m_rankCache = Maps.newHashMap();
public int compare(CmsResourceStatusRelationBean o1, CmsResourceStatusRelationBean o2) {
return ComparisonChain.start().compare(rank(o1), rank(o2)).compare(
o1.getSitePath(),
o2.getSitePath()).result();
}
public int rank(CmsResourceStatusRelationBean r) {
if (m_rankCache.containsKey(r.getSiteRoot())) {
return m_rankCache.get(r.getSiteRoot()).intValue();
}
int j = 0;
int result = Integer.MAX_VALUE;
for (CmsSite site : sites) {
if (site.getSiteRoot().equals(r.getSiteRoot())) {
result = j;
break;
}
j += 1;
}
m_rankCache.put(r.getSiteRoot(), new Integer(result));
return result;
}
});
Collections.sort(resStatus.getRelationSources(), new Comparator<CmsResourceStatusRelationBean>() {
public int compare(CmsResourceStatusRelationBean arg0, CmsResourceStatusRelationBean arg1) {
if (arg0.getSitePath().matches(DETAIL_CONTAINER_PATTERN)) {
if (!arg1.getSitePath().matches(DETAIL_CONTAINER_PATTERN)) {
return 1;
}
} else if (arg1.getSitePath().matches(DETAIL_CONTAINER_PATTERN)) {
return -1;
}
return arg0.getSitePath().compareTo(arg1.getSitePath());
}
});

private List<Logger> getLoggers() List<Logger> definedLoggers = new ArrayList<Logger>();
List<Logger> packageLoggers = new ArrayList<Logger>();
LoggerContext logContext = (LoggerContext) LogManager.getContext(false);
Iterator<Logger> it_curentlogger = logContext.getLoggers().iterator();
while (it_curentlogger.hasNext()) {
Logger log = it_curentlogger.next();
String logname = log.getName();
String[] prefix = buildsufix(logname);
for (int i = 0; i < prefix.length; i++) {
String temp = log.getName().replace(prefix[i], "");
if (temp.length() > 1) {
temp = temp.substring(1);
}
if (temp.lastIndexOf(".") > 1) {
Logger temp_logger = getLoggerImpl(prefix[i] + "." + temp.substring(0, temp.indexOf(".")));
temp_logger.setAdditive(true);
if (!packageLoggers.contains(temp_logger)) {
packageLoggers.add(temp_logger);
}
}
}
definedLoggers.add(log);
}
Iterator<Logger> it_logger = packageLoggers.iterator();
while (it_logger.hasNext()) {
Logger temp = it_logger.next();
if (!definedLoggers.contains(temp)) {
definedLoggers.add(temp);
}
}
Collections.sort(definedLoggers, new Comparator<Object>() {
public int compare(Logger o1, Logger o2) {
return String.CASE_INSENSITIVE_ORDER.compare(o1.getName(), o2.getName());
}
public int compare(Object obj, Object obj1) {
return compare((Logger)obj, (Logger)obj1);
}
});
return definedLoggers;

