return new SoftReferenceMemoizeFunction<V>(cache, closure, lruProtectionStorage, queue);

protected void pushInstanceOfTypeInfo(final Expression objectOfInstanceOf, final Expression typeExpression) final Map<Object, List<ClassNode>> tempo = typeCheckingContext.temporaryIfBranchTypeInformation.peek();
Object key = extractTemporaryTypeInfoKey(objectOfInstanceOf);
List<ClassNode> potentialTypes = tempo.get(key);
if (potentialTypes == null) {
potentialTypes = new LinkedList<ClassNode>();
tempo.put(key, potentialTypes);
}
potentialTypes.add(typeExpression.getType());

@Override public void cleanUpNullReferences() List<K> keys = new LinkedList<>();
for (Map.Entry<K, V> entry : map.entrySet()) {
K key = entry.getKey();
V value = entry.getValue();
if (null == value
|| (value instanceof SoftReference && null == ((SoftReference) value).get())
|| (value instanceof WeakReference && null == ((WeakReference) value).get())) {
keys.add(key);
}
}
for (K key : keys) {
map.remove(key);
}

public static void extractPlaceholders(ClassNode node, Map<GenericsTypeName, GenericsType> map) if (node == null) return;
if (node.isArray()) {
extractPlaceholders(node.getComponentType(), map);
return;
}
if (!node.isUsingGenerics() || !node.isRedirectNode()) return;
GenericsType[] parameterized = node.getGenericsTypes();
if (parameterized == null || parameterized.length == 0) return;
GenericsType[] redirectGenericsTypes = node.redirect().getGenericsTypes();
if (redirectGenericsTypes == null ||
(node.isGenericsPlaceHolder() && redirectGenericsTypes.length != parameterized.length)  ) {
redirectGenericsTypes = parameterized;
}
if (redirectGenericsTypes.length != parameterized.length) {
throw new GroovyBugError("Expected earlier checking to detect generics parameter arity mismatch" +
"\nExpected: " + node.getName() + toGenericTypesString(redirectGenericsTypes) +
"\nSupplied: " + node.getName() + toGenericTypesString(parameterized));
}
List<GenericsType> valueList = new LinkedList<>();
for (int i = 0; i < redirectGenericsTypes.length; i++) {
GenericsType redirectType = redirectGenericsTypes[i];
if (redirectType.isPlaceholder()) {
GenericsTypeName name = new GenericsTypeName(redirectType.getName());
if (!map.containsKey(name)) {
GenericsType value = parameterized[i];
map.put(name, value);
valueList.add(value);
}
}
}
for (GenericsType value : valueList) {
if (value.isWildcard()) {
ClassNode lowerBound = value.getLowerBound();
if (lowerBound != null) {
extractPlaceholders(lowerBound, map);
}
ClassNode[] upperBounds = value.getUpperBounds();
if (upperBounds != null) {
for (ClassNode upperBound : upperBounds) {
extractPlaceholders(upperBound, map);
}
}
} else if (!value.isPlaceholder()) {
extractPlaceholders(value.getType(), map);
}
}

private Expression transformMapEntryExpression(MapEntryExpression me, ClassNode constructorCallType) Expression key = me.getKeyExpression();
Expression value = me.getValueExpression();
ModuleNode module = currentClass.getModule();
if (module != null && key instanceof ConstantExpression) {
Map<String, ImportNode> importNodes = module.getStaticImports();
if (importNodes.containsKey(key.getText())) {
ImportNode importNode = importNodes.get(key.getText());
if (importNode.getType().equals(constructorCallType)) {
String newKey = importNode.getFieldName();
return new MapEntryExpression(new ConstantExpression(newKey), value.transformExpression(this));
}
}
}
return me;

