public VectorApproximation calculateApproximation(DBID id, V dv) int[] approximation = new int[dv.getDimensionality()];
for(int d = 0; d < splitPositions.length; d++) {
final double val = dv.doubleValue(d);
final int lastBorderIndex = splitPositions[d].length - 1;
if(val < splitPositions[d][0]) {
approximation[d] = 0;
if(id != null) {
LOG.warning("Vector outside of VAFile grid!");
}
}
else if(val > splitPositions[d][lastBorderIndex]) {
approximation[d] = lastBorderIndex - 1;
if(id != null) {
LOG.warning("Vector outside of VAFile grid!");
}
}
else {
int pos = Arrays.binarySearch(splitPositions[d], val);
pos = (pos >= 0) ? pos : ((-pos) - 2);
approximation[d] = pos;
}
}
return new VectorApproximation(id, approximation);

protected static VectorApproximation calculatePartialApproximation(DBID id, NumberVector dv, List<DoubleObjPair<DAFile>> daFiles) int[] approximation = new int[dv.getDimensionality()];
for(int i = 0; i < daFiles.size(); i++) {
double val = dv.doubleValue(i);
double[] borders = daFiles.get(i).second.getSplitPositions();
assert borders != null : "borders are null";
int lastBorderIndex = borders.length - 1;
if(val < borders[0]) {
approximation[i] = 0;
}
else if(val > borders[lastBorderIndex]) {
approximation[i] = lastBorderIndex - 1;
}
else {
for(int s = 0; s < lastBorderIndex; s++) {
if(val >= borders[s] && val < borders[s + 1] && approximation[i] != -1) {
approximation[i] = s;
}
}
}
}
return new VectorApproximation(id, approximation);

public void split() if(hasChildren()) {
return;
}
final boolean issplit = (maxSplitDimension >= (getDimensionality() - 1));
final int childLevel = issplit ? level + 1 : level;
final int splitDim = issplit ? 0 : maxSplitDimension + 1;
final double splitPoint = getMin(splitDim) + (getMax(splitDim) - getMin(splitDim)) * .5;
for(int i = 0; i < 2; i++) {
double[] min = SpatialUtil.getMin(this);
double[] max = SpatialUtil.getMax(this);
if(i == 0) {
min[splitDim] = splitPoint;
}
else {
max[splitDim] = splitPoint;
}
ModifiableDBIDs childIDs = split.determineIDs(getIDs(), new HyperBoundingBox(min, max), d_min, d_max);
if(childIDs != null) {
if(i == 0) {
rightChild = new CASHInterval(min, max, split, childIDs, splitDim, childLevel, d_min, d_max);
}
else {
leftChild = new CASHInterval(min, max, split, childIDs, splitDim, childLevel, d_min, d_max);
}
}
}
if(LOG.isDebuggingFine()) {
StringBuilder msg = new StringBuilder();
msg.append("Child level ").append(childLevel).append(",  split Dim   ").append(splitDim);
if(leftChild != null) {
msg.append("\nleft   ").append(leftChild);
}
if(rightChild != null) {
msg.append("\nright   ").append(rightChild);
}
LOG.fine(msg.toString());
}

protected void zSort(List<? extends SpatialComparable> objs, int start, int end, double[] mms, int[] dims, int depth) final int numdim = (dims != null) ? dims.length : (mms.length >> 1);
final int edim = (dims != null) ? dims[depth] : depth;
final double min = mms[2 * edim], max = mms[2 * edim + 1];
double spos = (min + max) / 2.;
if(max - spos < STOPVAL || spos - min < STOPVAL) {
boolean ok = false;
for(int d = 0; d < numdim; d++) {
int d2 = ((dims != null) ? dims[d] : d) << 1;
if(mms[d2 + 1] - mms[d2] >= STOPVAL) {
ok = true;
break;
}
}
if(!ok) {
return;
}
}
int split = pivotizeList1D(objs, start, end, edim, spos, false);
assert (start <= split && split <= end);
int nextdim = (depth + 1) % numdim;
if(start < split - 1) {
mms[2 * edim] = min;
mms[2 * edim + 1] = spos;
zSort(objs, start, split, mms, dims, nextdim);
}
if(split < end - 1) {
mms[2 * edim] = spos;
mms[2 * edim + 1] = max;
zSort(objs, split, end, mms, dims, nextdim);
}
mms[2 * edim] = min;
mms[2 * edim + 1] = max;

public static final Color getColorForValue(double val) double[] pos = new double[] { 0.0, 0.6, 0.8, 1.0 };
Color[] cols = new Color[] { new Color(0.0f, 0.0f, 0.0f, 0.6f), new Color(0.0f, 0.0f, 1.0f, 0.8f), new Color(1.0f, 0.0f, 0.0f, 0.9f), new Color(1.0f, 1.0f, 0.0f, 1.0f) };
assert (pos.length == cols.length);
if(val < pos[0]) {
val = pos[0];
}
for(int i = 1; i < pos.length; i++) {
if(val <= pos[i]) {
Color prev = cols[i - 1];
Color next = cols[i];
final double mix = (val - pos[i - 1]) / (pos[i] - pos[i - 1]);
final int r = (int) ((1 - mix) * prev.getRed() + mix * next.getRed());
final int g = (int) ((1 - mix) * prev.getGreen() + mix * next.getGreen());
final int b = (int) ((1 - mix) * prev.getBlue() + mix * next.getBlue());
final int a = (int) ((1 - mix) * prev.getAlpha() + mix * next.getAlpha());
Color col = new Color(r, g, b, a);
return col;
}
}
return cols[cols.length - 1];

private Pair<DBIDVar, Double> singleIteration(Relation<V> relationx, Relation<? extends NumberVector> relationy) final int dim = RelationUtil.dimensionality(relationx);
final int dimy = RelationUtil.dimensionality(relationy);
assert (dim == 2);
KNNQuery<V> knnQuery = QueryUtil.getKNNQuery(relationx, getDistanceFunction(), k + 1);
ArrayModifiableDBIDs ids = DBIDUtil.newArray(relationx.getDBIDs());
ids.sort();
double[][] X = new double[ids.size()][6];
double[][] F = new double[ids.size()][ids.size()];
double[][] Y = new double[ids.size()][dimy];
{
int i = 0;
for(DBIDIter id = ids.iter(); id.valid(); id.advance(), i++) {
{
V vec = relationx.get(id);
double la = vec.doubleValue(0);
double lo = vec.doubleValue(1);
X[i][0] = 1.0;
X[i][1] = la;
X[i][2] = lo;
X[i][3] = la * lo;
X[i][4] = la * la;
X[i][5] = lo * lo;
}
{
final NumberVector vecy = relationy.get(id);
for(int d = 0; d < dimy; d++) {
double idy = vecy.doubleValue(d);
Y[i][d] = idy;
}
}
{
KNNList neighbors = knnQuery.getKNNForDBID(id, k + 1);
ModifiableDBIDs neighborhood = DBIDUtil.newArray(neighbors.size());
for(DBIDIter neighbor = neighbors.iter(); neighbor.valid(); neighbor.advance()) {
if(DBIDUtil.equal(id, neighbor)) {
continue;
}
neighborhood.add(neighbor);
}
F[i][i] = 1.0;
final int nweight = -1 / neighborhood.size();
for(DBIDIter iter = neighborhood.iter(); iter.valid(); iter.advance()) {
int pos = ids.binarySearch(iter);
assert (pos >= 0);
F[pos][i] = nweight;
}
}
}
}
double[][] common = times(transposeTimesTranspose(X, F), F);
double[][] b = times(inverse(times(common, X)), times(common, Y));
double[][] sigmaMat = times(F, minusEquals(times(X, b), times(F, Y)));
final double sigma_sum_square = normF(sigmaMat) / (relationx.size() - 6 - 1);
final double norm = 1 / FastMath.sqrt(sigma_sum_square);
double[][] E = timesEquals(times(F, minus(Y, times(X, b))), norm);
DBIDVar worstid = DBIDUtil.newVar();
double worstscore = Double.NEGATIVE_INFINITY;
int i = 0;
for(DBIDIter id = ids.iter(); id.valid(); id.advance(), i++) {
double err = squareSum(getRow(E, i));
if(err > worstscore) {
worstscore = err;
worstid.set(id);
}
}
return new Pair<>(worstid, FastMath.sqrt(worstscore));

private void divide(int[] idx, double[] data, ArrayList<int[]> ret, int start, int end, int depth) if(depth == 0) {
int[] a = Arrays.copyOfRange(idx, start, end);
Arrays.sort(a);
ret.add(a);
return;
}
final int count = end - start;
if(count == 0) {
for(int j = 1 << depth; j > 0; --j) {
ret.add(new int[0]);
}
return;
}
double m = 0.;
for(int i = start; i < end; i++) {
m += data[i];
}
m /= count;
int pos = Arrays.binarySearch(data, start, end, m);
if(pos >= 0) {
final int opt = (start + end) >> 1;
while(data[pos] == m) {
if(pos < opt) {
pos++;
}
else if(pos > opt) {
pos--;
}
else {
break;
}
}
}
else {
pos = (-pos - 1);
}
divide(idx, data, ret, start, pos, depth - 1);
divide(idx, data, ret, pos, end, depth - 1);

@Override protected Cluster<SubspaceModel> runDOC(Database database, Relation<V> relation, ArrayModifiableDBIDs S, int d, int n, int m, int r, int minClusterSize) long[] D = null;
DBIDVar dV = DBIDUtil.newVar();
FiniteProgress iprogress = LOG.isVerbose() ? new FiniteProgress("Iteration progress for current cluster", m * n, LOG) : null;
Random random = rnd.getSingleThreadedRandom();
DBIDArrayIter iter = S.iter();
outer: for(int i = 0; i < n; ++i) {
iter.seek(random.nextInt(S.size()));
for(int j = 0; j < m; ++j) {
DBIDs randomSet = DBIDUtil.randomSample(S, r, random);
long[] nD = BitsUtil.zero(d);
for(int k = 0; k < d; ++k) {
if(dimensionIsRelevant(k, relation, randomSet)) {
BitsUtil.setI(nD, k);
}
}
if(D == null || BitsUtil.cardinality(nD) > BitsUtil.cardinality(D)) {
D = nD;
dV.set(iter);
if(BitsUtil.cardinality(D) >= d_zero) {
if(iprogress != null) {
iprogress.setProcessed(iprogress.getTotal(), LOG);
}
break outer;
}
}
LOG.incrementProcessed(iprogress);
}
}
LOG.ensureCompleted(iprogress);
if(D == null || BitsUtil.cardinality(D) == 0) {
return null;
}
DBIDs C = findNeighbors(dV, D, S, relation);
return (C.size() >= minClusterSize) ? makeCluster(relation, C, D) : null;

private void initHeap(ObjectHeap<CASHInterval> heap, Relation<ParameterizationFunction> relation, int dim, DBIDs ids) CASHIntervalSplit split = new CASHIntervalSplit(relation, minPts);
double[] minMax = determineMinMaxDistance(relation, dim);
double d_min = minMax[0], d_max = minMax[1];
double dIntervalLength = d_max - d_min;
int numDIntervals = (int) FastMath.ceil(dIntervalLength / jitter);
double dIntervalSize = dIntervalLength / numDIntervals;
double[] d_mins = new double[numDIntervals],
d_maxs = new double[numDIntervals];
if(LOG.isVerbose()) {
LOG.verbose(new StringBuilder().append("d_min ").append(d_min)
.append("\nd_max ").append(d_max)
.append("\nnumDIntervals ").append(numDIntervals)
.append("\ndIntervalSize ").append(dIntervalSize).toString());
}
double[] alphaMin = new double[dim - 1], alphaMax = new double[dim - 1];
Arrays.fill(alphaMax, Math.PI);
for(int i = 0; i < numDIntervals; i++) {
d_mins[i] = (i == 0) ? d_min : d_maxs[i - 1];
d_maxs[i] = (i < numDIntervals - 1) ? d_mins[i] + dIntervalSize : d_max - d_mins[i];
HyperBoundingBox alphaInterval = new HyperBoundingBox(alphaMin, alphaMax);
ModifiableDBIDs intervalIDs = split.determineIDs(ids, alphaInterval, d_mins[i], d_maxs[i]);
if(intervalIDs != null && intervalIDs.size() >= minPts) {
heap.add(new CASHInterval(alphaMin, alphaMax, split, intervalIDs, -1, 0, d_mins[i], d_maxs[i]));
}
}
if(LOG.isDebuggingFiner()) {
LOG.debugFiner(new StringBuilder().append("heap.size: ").append(heap.size()).toString());
}

public OutlierResult run(Relation<V> relation) final DBIDs ids = relation.getDBIDs();
KNNQuery<V> knnQuery = QueryUtil.getKNNQuery(relation, getDistanceFunction(), k + 1);
final int dim = RelationUtil.dimensionality(relation);
if(k <= dim + 1) {
LOG.warning("PCA is underspecified with a too low k! k should be at much larger than " + dim);
}
WritableDoubleDataStore cop_score = DataStoreUtil.makeDoubleStorage(ids, DataStoreFactory.HINT_HOT | DataStoreFactory.HINT_STATIC);
WritableDataStore<double[]> cop_err_v = models ? DataStoreUtil.makeStorage(ids, DataStoreFactory.HINT_HOT | DataStoreFactory.HINT_STATIC, double[].class) : null;
WritableIntegerDataStore cop_dim = models ? DataStoreUtil.makeIntegerStorage(ids, DataStoreFactory.HINT_HOT | DataStoreFactory.HINT_STATIC, -1) : null;
FiniteProgress prog = LOG.isVerbose() ? new FiniteProgress("Correlation Outlier Probabilities", relation.size(), LOG) : null;
double[] centroid = new double[dim];
double[] scores = new double[dim];
ModifiableDBIDs nids = DBIDUtil.newHashSet(k + 10);
for(DBIDIter id = ids.iter(); id.valid(); id.advance()) {
nids.clear();
nids.addDBIDs(knnQuery.getKNNForDBID(id, k + 1));
nids.remove(id);
computeCentroid(centroid, relation, nids);
PCAResult pcares = pca.processIds(nids, relation);
double[][] tevecs = pcares.getEigenvectors();
double[] evs = pcares.getEigenvalues();
double[] projected = times(tevecs, minusEquals(relation.get(id).toArray(), centroid));
if(dist == DistanceDist.CHISQUARED) {
double sqdevs = 0;
for(int d = 0; d < dim; d++) {
double dev = projected[d];
sqdevs += dev * dev / evs[d];
scores[d] = 1 - ChiSquaredDistribution.cdf(sqdevs, d + 1);
}
}
else {
assert (dist == DistanceDist.GAMMA);
double[][] dists = new double[dim][nids.size()];
int j = 0;
double[] srel = new double[dim];
for(DBIDIter s = nids.iter(); s.valid() && j < nids.size(); s.advance(), j++) {
V vec = relation.get(s);
for(int d = 0; d < dim; d++) {
srel[d] = vec.doubleValue(d) - centroid[d];
}
double sqdist = 0.0;
for(int d = 0; d < dim; d++) {
double serrd = transposeTimes(tevecs[d], srel);
dists[d][j] = (sqdist += serrd * serrd / evs[d]);
}
}
double sqdevs = 0;
for(int d = 0; d < dim; d++) {
final double dev = projected[d];
sqdevs += dev * dev / evs[d];
Arrays.sort(dists[d]);
scores[d] = 1 - GammaChoiWetteEstimator.STATIC.estimate(dists[d], SHORTENED_ARRAY).cdf(sqdevs);
}
}
double min = Double.POSITIVE_INFINITY;
int vdim = dim - 1;
for(int d = 0; d < dim; d++) {
double v = scores[d];
if(v < min) {
min = v;
vdim = d;
}
}
final double prob = expect * (1 - min) / (expect + min);
cop_score.putDouble(id, prob);
if(models) {
Arrays.fill(projected, vdim + 1, dim, 0.);
cop_err_v.put(id, timesEquals(transposeTimes(tevecs, projected), -prob));
cop_dim.putInt(id, dim - vdim);
}
LOG.incrementProcessed(prog);
}
LOG.ensureCompleted(prog);
DoubleRelation scoreResult = new MaterializedDoubleRelation("Correlation Outlier Probabilities", COP_SCORES, cop_score, ids);
OutlierScoreMeta scoreMeta = new ProbabilisticOutlierScore();
OutlierResult result = new OutlierResult(scoreMeta, scoreResult);
if(models) {
result.addChildResult(new MaterializedRelation<>("Local Dimensionality", COP_DIM, TypeUtil.INTEGER, cop_dim, ids));
result.addChildResult(new MaterializedRelation<>("Error vectors", COP_ERRORVEC, TypeUtil.DOUBLE_ARRAY, cop_err_v, ids));
}
return result;

