public void configure() throws CoreException String path =
project.getPersistentProperty(new QualifiedName(Activator.PLUGIN_ID,
"hadoop.runtime.path"));
File dir = new File(path);
final ArrayList<File> coreJars = new ArrayList<File>();
dir.listFiles(new FileFilter() {
public boolean accept(File pathname) {
String fileName = pathname.getName();
if ((fileName.indexOf("hadoop") != -1) && (fileName.endsWith("jar"))
&& (fileName.indexOf("test") == -1)
&& (fileName.indexOf("examples") == -1)) {
coreJars.add(pathname);
}
return false;
}
});
File dir2 = new File(path + File.separatorChar + "lib");
if (dir2.exists() && dir2.isDirectory()) {
dir2.listFiles(new FileFilter() {
public boolean accept(File pathname) {
if ((!pathname.isDirectory())
&& (pathname.getName().endsWith("jar"))) {
coreJars.add(pathname);
}
return false;
}
});
}
IJavaProject javaProject = JavaCore.create(getProject());
try {
IClasspathEntry[] currentCp = javaProject.getRawClasspath();
IClasspathEntry[] newCp =
new IClasspathEntry[currentCp.length + coreJars.size()];
System.arraycopy(currentCp, 0, newCp, 0, currentCp.length);
final Iterator<File> i = coreJars.iterator();
int count = 0;
while (i.hasNext()) {
final File f = (File) i.next();
URL url = f.toURI().toURL();
log.finer("hadoop library url.getPath() = " + url.getPath());
newCp[newCp.length - 1 - count] =
JavaCore.newLibraryEntry(new Path(url.getPath()), null, null);
count++;
}
javaProject.setRawClasspath(newCp, new NullProgressMonitor());
} catch (Exception e) {
log.log(Level.SEVERE, "IOException generated in "
+ this.getClass().getCanonicalName(), e);
}

private Connection getConnection(InetSocketAddress addr, Class<?> protocol, UserGroupInformation ticket, int rpcTimeout, Call call) throws IOException if (!running.get()) {
throw new IOException("The client is stopped");
}
Connection connection;
ConnectionId remoteId = new ConnectionId(
addr, protocol, ticket, rpcTimeout);
do {
synchronized (connections) {
connection = connections.get(remoteId);
if (connection == null) {
connection = new Connection(remoteId);
connections.put(remoteId, connection);
}
}
} while (!connection.addCall(call));
boolean success = false;
try {
connection.setupIOstreams();
success = true;
} finally {
if (!success) {
try {
if (connection.closeException == null) {
connection.markClosed(new IOException(
"Unexpected error when setup IO Stream"));
}
} finally {
connection.close(true);
}
}
}
return connection;

private boolean setupPipelineForAppend(LocatedBlock lastBlock) throws IOException if (nodes == null || nodes.length == 0) {
String msg = "Could not get block locations. " +
"Source file \"" + src
+ "\" - Aborting...";
DFSClient.LOG.warn(msg);
setLastException(new IOException(msg));
closed = true;
if (streamer != null) streamer.close();
return false;
}
boolean success = createBlockOutputStream(nodes, dfsClient.clientName, false, true);
long oldGenerationStamp =
((LocatedBlockWithOldGS)lastBlock).getOldGenerationStamp();
if (success) {
Block newBlock = lastBlock.getBlock();
Block oldBlock = new Block(newBlock.getBlockId(), newBlock.getNumBytes(),
oldGenerationStamp);
dfsClient.namenode.updatePipeline(dfsClient.clientName,
oldBlock, newBlock, nodes);
} else {
DFSClient.LOG.warn("Fall back to block recovery process when trying" +
" to setup the append pipeline for file " + src);
block.setGenerationStamp(oldGenerationStamp);
while(processDatanodeError(true, true)) {
try {
Thread.sleep(1000);
} catch (InterruptedException  e) {
lastException = new IOException(e);
break;
}
}
}
return success;

public static void register(FastProtocolId id, Method m) synchronized (FastProtocolRegister.class) {
String name = id.toString();
if (name.length() != NAME_LEN) {
throw new RuntimeException("Code must be " + NAME_LEN + " bytes long");
}
if (m == null) {
throw new RuntimeException("Method cannot be null");
}
Method registeredMethod = idToMethod.get(name);
if (registeredMethod != null && registeredMethod != m) {
throw new RuntimeException(
"Trying to register different method with name: " + name);
} else if (registeredMethod == m) {
return;
}
LOG.info("FastProtocol - Registering method: " + name + " method: "
+ m.getName());
idToMethod.put(name, m);
methodToId.put(m, name);
}

public static void register(FastWritableId id, FastWritable fw) synchronized (FastWritableRegister.class) {
String name = id.toString();
if (name.length() != NAME_LEN) {
throw new RuntimeException("Code must be " + NAME_LEN + " bytes long");
}
if (fw == null) {
throw new RuntimeException("Instance cannot be null");
}
FastWritable registeredWritable = register.get(name);
if (registeredWritable != null && registeredWritable != fw) {
throw new RuntimeException(
"Trying to register different class with name: " + name);
} else if (registeredWritable == fw) {
return;
}
LOG.info("FastWritable - Registering name: " + name);
register.put(name, fw);
}

public static Method tryGetMethod(String id) if (id.length() != NAME_LEN) {
return null;
}
return idToMethod.get(id);

protected void setParameters(List<Object> params, PreparedStatement statement) throws SQLException int i = 1;
ParameterMetaData metaData = getParameterMetaDataSafe(statement);
if (metaData != null) {
if (metaData.getParameterCount() == 0 && params.size() == 1 && params.get(0) instanceof Map) {
Map paramsMap = (Map) params.get(0);
if (paramsMap.isEmpty()) return;
}
if (metaData.getParameterCount() != params.size()) {
LOG.warning("Found " + metaData.getParameterCount() + " parameter placeholders but supplied with " + params.size() + " parameters");
}
}
for (Object value : params) {
setObject(statement, i++, value);
}

