public void query(String sql, List<Object> params, @ClosureParams(value=SimpleType.class, options="java.sql.ResultSet") Closure closure) throws SQLException Connection connection = createConnection();
PreparedStatement statement = null;
ResultSet results = null;
try {
statement = getPreparedStatement(connection, sql, params);
results = statement.executeQuery();
closure.call(results);
} catch (SQLException e) {
LOG.warning("Failed to execute: " + sql + " because: " + e.getMessage());
throw e;
} finally {
closeResources(connection, statement, results);
}

public void execute(String sql, Closure processResults) throws SQLException Connection connection = createConnection();
Statement statement = null;
try {
statement = getStatement(connection, sql);
boolean isResultSet = statement.execute(sql);
int updateCount = statement.getUpdateCount();
while(isResultSet || updateCount != -1) {
if (processResults.getMaximumNumberOfParameters() != 2) {
throw new SQLException("Incorrect number of parameters for processResults Closure");
}
if (isResultSet) {
ResultSet resultSet = statement.getResultSet();
List<GroovyRowResult> rowResult = resultSet == null ? null : asList(sql, resultSet);
processResults.call(isResultSet, rowResult);
} else {
processResults.call(isResultSet, updateCount);
}
isResultSet = statement.getMoreResults();
updateCount = statement.getUpdateCount();
}
} catch (SQLException e) {
LOG.warning("Failed to execute: " + sql + " because: " + e.getMessage());
throw e;
} finally {
closeResources(connection, statement);
}

public int executeUpdate(String sql) throws SQLException Connection connection = createConnection();
Statement statement = null;
try {
statement = getStatement(connection, sql);
this.updateCount = statement.executeUpdate(sql);
return this.updateCount;
} catch (SQLException e) {
LOG.warning("Failed to execute: " + sql + " because: " + e.getMessage());
throw e;
} finally {
closeResources(connection, statement);
}

protected void closeResources(Connection connection, Statement statement, ResultSet results) if (results != null) {
try {
results.close();
} catch (SQLException e) {
LOG.finest("Caught exception closing resultSet: " + e.getMessage() + " - continuing");
}
}
closeResources(connection, statement);

public int call(String sql, List<Object> params) throws Exception Connection connection = createConnection();
CallableStatement statement = null;
try {
statement = getCallableStatement(connection, sql, params);
return statement.executeUpdate();
} catch (SQLException e) {
LOG.warning("Failed to execute: " + sql + " because: " + e.getMessage());
throw e;
} finally {
closeResources(connection, statement);
}

public int[] withBatch(int batchSize, Closure closure) throws SQLException Connection connection = createConnection();
BatchingStatementWrapper statement = null;
boolean savedWithinBatch = withinBatch;
try {
withinBatch = true;
statement = new BatchingStatementWrapper(createStatement(connection), batchSize, LOG);
closure.call(statement);
return statement.executeBatch();
} catch (SQLException e) {
LOG.warning("Error during batch execution: " + e.getMessage());
throw e;
} finally {
closeResources(statement);
closeResources(connection);
withinBatch = savedWithinBatch;
}

protected Connection createConnection() throws SQLException if ((cacheStatements || cacheConnection) && useConnection != null) {
return useConnection;
}
if (dataSource != null) {
Connection con;
try {
con = AccessController.doPrivileged(new PrivilegedExceptionAction<Connection>() {
public Connection run() throws SQLException {
return dataSource.getConnection();
}
});
} catch (PrivilegedActionException pae) {
Exception e = pae.getException();
if (e instanceof SQLException) {
throw (SQLException) e;
} else {
throw (RuntimeException) e;
}
}
if (cacheStatements || cacheConnection) {
useConnection = con;
}
return con;
}
return useConnection;

