public static org.apache.arrow.vector.types.pojo.Schema toArrowSchema(Schema schema) List<Field> fields = new ArrayList<>(schema.numColumns());
for(int i = 0; i < schema.numColumns(); i++) {
fields.add(getFieldForColumn(schema.getName(i),schema.getType(i)));
}
return new org.apache.arrow.vector.types.pojo.Schema(fields);

public static Schema fromStructType(StructType structType) Schema.Builder builder = new Schema.Builder();
StructField[] fields = structType.fields();
String[] fieldNames = structType.fieldNames();
for (int i = 0; i < fields.length; i++) {
String name = fields[i].dataType().typeName().toLowerCase();
switch (name) {
case "double":
builder.addColumnDouble(fieldNames[i]);
break;
case "float":
builder.addColumnFloat(fieldNames[i]);
break;
case "long":
builder.addColumnLong(fieldNames[i]);
break;
case "int":
case "integer":
builder.addColumnInteger(fieldNames[i]);
break;
case "string":
builder.addColumnString(fieldNames[i]);
break;
default:
throw new RuntimeException("Unknown type: " + name);
}
}
return builder.build();

