public static int chars2utf(char[] src, int sindex, byte[] dst, int dindex, int len) int j = dindex;
int limit = sindex + len;
for (int i = sindex; i < limit; i++) {
char ch = src[i];
if (1 <= ch && ch <= 0x7F) {
dst[j++] = (byte)ch;
} else if (ch <= 0x7FF) {
dst[j++] = (byte)(0xC0 | (ch >> 6));
dst[j++] = (byte)(0x80 | (ch & 0x3F));
} else {
dst[j++] = (byte)(0xE0 | (ch >> 12));
dst[j++] = (byte)(0x80 | ((ch >> 6) & 0x3F));
dst[j++] = (byte)(0x80 | (ch & 0x3F));
}
}
return j;

public static int utf2chars(byte[] src, int sindex, char[] dst, int dindex, int len) int i = sindex;
int j = dindex;
int limit = sindex + len;
while (i < limit) {
int b = src[i++] & 0xFF;
if (b >= 0xE0) {
b = (b & 0x0F) << 12;
b = b | (src[i++] & 0x3F) << 6;
b = b | (src[i++] & 0x3F);
} else if (b >= 0xC0) {
b = (b & 0x1F) << 6;
b = b | (src[i++] & 0x3F);
}
dst[j++] = (char)b;
}
return j;

