}
}

public static File searchForGroovyScriptFile(String input) String scriptFileName = input.trim();
File scriptFile = new File(scriptFileName);
String[] standardExtensions = {".groovy",".gvy",".gy",".gsh"};
int i = 0;
while (i < standardExtensions.length && !scriptFile.exists()) {
scriptFile = new File(scriptFileName + standardExtensions[i]);
i++;
}
if (!scriptFile.exists()) {
scriptFile = new File(scriptFileName);
}
return scriptFile;

@Override public void applyUpdater(INDArray gradient, int iteration, int epoch) if (msg == null || msdx == null)
throw new IllegalStateException("Updater has not been initialized with view state");
double rho = config.getRho();
double epsilon = config.getEpsilon();
msg.muli(rho).addi(gradient.mul(gradient).muli(1 - rho));
INDArray rmsdx_t1 = Transforms.sqrt(msdx.add(epsilon), false);
INDArray rmsg_t = Transforms.sqrt(msg.add(epsilon), false);
INDArray update = gradient.muli(rmsdx_t1.divi(rmsg_t));
msdx.muli(rho).addi(update.mul(update).muli(1 - rho));

@Override public void applyUpdater(INDArray gradient, int iteration, int epoch) if (v == null)
throw new IllegalStateException("Updater has not been initialized with view state");
double momentum = config.currentMomentum(iteration, epoch);
double learningRate = config.getLearningRate(iteration, epoch);
INDArray vPrev = v.dup(gradientReshapeOrder);
v.muli(momentum).subi(gradient.dup(gradientReshapeOrder).muli(learningRate));
Nd4j.getExecutioner().exec(new OldAddOp(vPrev.muli(momentum), v.mul(-momentum - 1), gradient));

public synchronized void update(Gradient gradient, int iteration, int epoch, int batchSize, LayerWorkspaceMgr workspaceMgr) boolean isExternal = gradient.gradient() != getFlattenedGradientsView();
Map<String, Gradient> layerGradients = new HashMap<>();
Trainable[] layers = getOrderedLayers();
if (layers.length == 1 && isSingleLayerUpdater()) {
layerGradients.put(layers[0].getConfig().getLayerName(), gradient);
} else {
for (Map.Entry<String, INDArray> gradientPair : gradient.gradientForVariable().entrySet()) {
String key = gradientPair.getKey();
int idx = key.lastIndexOf('_');
if (idx == -1)
throw new IllegalStateException(
"Invalid key: Gradient key does not have layer separator: \"" + key + "\"");
String layerName = key.substring(0, idx);
Gradient g = layerGradients.get(layerName);
if (g == null) {
g = new DefaultGradient();
layerGradients.put(layerName, g);
}
String newKey = key.substring(idx + 1);
g.setGradientFor(newKey, gradientPair.getValue());
}
}
if(isMiniBatch()){
divideByMinibatch(isExternal, gradient, batchSize);
}
for (Map.Entry<String, Gradient> entry : layerGradients.entrySet()) {
String layerName = entry.getKey();
Trainable layer = layersByName.get(layerName);
preApply(layer, layerGradients.get(layerName), iteration);
}
if(getClass() != LayerUpdater.class){
workspaceMgr.assertNotOpen(ArrayType.UPDATER_WORKING_MEM, "Updater working memory");
}
for (UpdaterBlock ub : updaterBlocks) {
if (ub.skipDueToPretrainConfig(this instanceof LayerUpdater)) {
continue;
}
try(MemoryWorkspace ws = workspaceMgr.notifyScopeEntered(ArrayType.UPDATER_WORKING_MEM)){
if (isExternal) {
ub.updateExternalGradient(iteration, epoch, gradient.gradient(), getParams());
} else {
ub.update(iteration, epoch);
}
}
}

@Override public INDArray computeGradient(INDArray labels, INDArray preOutput, IActivation activationFn, INDArray mask) labels = labels.castTo(preOutput.dataType());
long nSamples = labels.size(0);
INDArray output = activationFn.getActivation(preOutput.dup(), false);
MixtureDensityComponents mdc = extractComponents(output);
INDArray gradient = Nd4j.zeros(nSamples, preOutput.columns());
INDArray labelsMinusMu = labelsMinusMu(labels, mdc.mu);
INDArray labelsMinusMuSquared = labelsMinusMu.mul(labelsMinusMu).sum(2);
INDArray variance = mdc.sigma.mul(mdc.sigma);
INDArray minustwovariance = variance.mul(2).negi();
INDArray normalPart = mdc.alpha.div(Transforms.pow(mdc.sigma.mul(SQRT_TWO_PI), mLabelWidth));
INDArray exponent = labelsMinusMuSquared.div(minustwovariance);
INDArray exponentMax = exponent.max(1);
exponent.subiColumnVector(exponentMax);
INDArray pi = Transforms.exp(exponent).muli(normalPart);
INDArray piDivisor = pi.sum(true,1);
pi.diviColumnVector(piDivisor);
INDArray dLdZAlpha = mdc.alpha.sub(pi);
INDArray dLdZSigma = (labelsMinusMuSquared.div(variance).subi(mLabelWidth)).muli(-1).muli(pi);
INDArray dLdZMu = Nd4j.create(nSamples, mMixtures, mLabelWidth);
for (int k = 0; k < mLabelWidth; k++) {
dLdZMu.put(new INDArrayIndex[] {NDArrayIndex.all(), NDArrayIndex.all(), NDArrayIndex.point(k)},
labelsMinusMu.get(new INDArrayIndex[] {NDArrayIndex.all(), NDArrayIndex.all(),
NDArrayIndex.point(k)}).muli(pi).divi(variance).negi());
}
dLdZMu = dLdZMu.reshape(nSamples, mMixtures * mLabelWidth);
gradient.put(new INDArrayIndex[] {NDArrayIndex.all(), NDArrayIndex.interval(0, mMixtures)}, dLdZAlpha);
gradient.put(new INDArrayIndex[] {NDArrayIndex.all(), NDArrayIndex.interval(mMixtures, mMixtures * 2)},
dLdZSigma);
gradient.put(new INDArrayIndex[] {NDArrayIndex.all(),
NDArrayIndex.interval(mMixtures * 2, (mLabelWidth + 2) * mMixtures)}, dLdZMu);
INDArray gradients = activationFn.backprop(preOutput, gradient).getFirst();
if (mask != null) {
LossUtil.applyMask(gradients, mask);
}
return gradients;

private Pair<Gradient, INDArray> getGradientsAndDelta(INDArray preOut, LayerWorkspaceMgr workspaceMgr) ILossFunction lossFunction = layerConf().getLossFn();
INDArray labels2d = getLabels2d(workspaceMgr, ArrayType.BP_WORKING_MEM);
if (labels2d.size(1) != preOut.size(1)) {
throw new DL4JInvalidInputException(
"Labels array numColumns (size(1) = " + labels2d.size(1) + ") does not match output layer"
+ " number of outputs (nOut = " + preOut.size(1) + ") " + layerId());
}
INDArray delta = lossFunction.computeGradient(labels2d, preOut, layerConf().getActivationFn(), maskArray);
Gradient gradient = new DefaultGradient();
INDArray weightGradView = gradientViews.get(CenterLossParamInitializer.WEIGHT_KEY);
INDArray biasGradView = gradientViews.get(CenterLossParamInitializer.BIAS_KEY);
INDArray centersGradView = gradientViews.get(CenterLossParamInitializer.CENTER_KEY);
double alpha = layerConf().getAlpha();
INDArray centers = params.get(CenterLossParamInitializer.CENTER_KEY);
INDArray l = labels.castTo(centers.dataType());
INDArray centersForExamples = l.mmul(centers);
INDArray diff = centersForExamples.sub(input).muli(alpha);
INDArray numerator = l.transpose().mmul(diff);
INDArray denominator = l.sum(0).reshape(l.size(1), 1).addi(1.0);
INDArray deltaC;
if (layerConf().getGradientCheck()) {
double lambda = layerConf().getLambda();
deltaC = numerator.muli(lambda);
} else {
deltaC = numerator.diviColumnVector(denominator);
}
centersGradView.assign(deltaC);
Nd4j.gemm(input, delta, weightGradView, true, false, 1.0, 0.0);
delta.sum(biasGradView, 0);
gradient.gradientForVariable().put(CenterLossParamInitializer.WEIGHT_KEY, weightGradView);
gradient.gradientForVariable().put(CenterLossParamInitializer.BIAS_KEY, biasGradView);
gradient.gradientForVariable().put(CenterLossParamInitializer.CENTER_KEY, centersGradView);
return new Pair<>(gradient, delta);

private Pair<Gradient, INDArray> getGradientsAndDelta(INDArray preOut, LayerWorkspaceMgr workspaceMgr) ILossFunction lossFunction = layerConf().getLossFn();
INDArray labels2d = getLabels2d(workspaceMgr, ArrayType.BP_WORKING_MEM);
INDArray delta = lossFunction.computeGradient(labels2d, preOut, layerConf().getActivationFn(), maskArray);
org.deeplearning4j.nn.conf.ocnn.OCNNOutputLayer conf = ( org.deeplearning4j.nn.conf.ocnn.OCNNOutputLayer) conf().getLayer();
if(conf.getLastEpochSinceRUpdated() == 0 && epochCount == 0) {
INDArray currentR = doOutput(false,workspaceMgr);
if(window == null) {
window = Nd4j.createUninitializedDetached(conf.getWindowSize()).assign(0.0);
}
if(batchWindowSizeIndex < window.length() - currentR.length()) {
window.put(new INDArrayIndex[]{NDArrayIndex.interval(batchWindowSizeIndex,batchWindowSizeIndex + currentR.length())},currentR);
}
else if(batchWindowSizeIndex < window.length()) {
int windowIdx = (int) window.length() - batchWindowSizeIndex;
window.put(new INDArrayIndex[]{NDArrayIndex.interval(window.length() - windowIdx,window.length())},currentR.get(NDArrayIndex.interval(0,windowIdx)));
}
batchWindowSizeIndex += currentR.length();
conf.setLastEpochSinceRUpdated(epochCount);
}
else if(conf.getLastEpochSinceRUpdated()  != epochCount) {
double percentile = window.percentileNumber(100.0 * conf.getNu()).doubleValue();
getParam(R_KEY).putScalar(0,percentile);
conf.setLastEpochSinceRUpdated(epochCount);
batchWindowSizeIndex = 0;
}
else {
INDArray currentR = doOutput(false,workspaceMgr);
window.put(new INDArrayIndex[]{NDArrayIndex.interval(batchWindowSizeIndex,batchWindowSizeIndex + currentR.length())},currentR);
}
Gradient gradient = new DefaultGradient();
INDArray vGradView = gradientViews.get(V_KEY);
double oneDivNu = 1.0 / layerConf().getNu();
INDArray xTimesV = input.mmul(getParam(V_KEY));
INDArray derivW = layerConf().getActivationFn().getActivation(xTimesV.dup(),true).negi();
derivW = derivW.muliColumnVector(delta).mean(0).muli(oneDivNu).addi(getParam(W_KEY));
gradient.setGradientFor(W_KEY,gradientViews.get(W_KEY).assign(derivW));
INDArray firstVertDerivV =  layerConf().getActivationFn()
.backprop(xTimesV.dup(),Nd4j.ones(input.dataType(), xTimesV.shape()))
.getFirst().muliRowVector(getParam(W_KEY).neg());
firstVertDerivV = firstVertDerivV.muliColumnVector(delta)
.reshape('f',input.size(0),1,layerConf().getHiddenSize());
INDArray secondTermDerivV = input.reshape('f',
input.size(0),getParam(V_KEY).size(0),1);
long[]  shape = new long[firstVertDerivV.shape().length];
for(int i = 0; i < firstVertDerivV.rank(); i++) {
shape[i] = Math.max(firstVertDerivV.size(i),secondTermDerivV.size(i));
}
INDArray firstDerivVBroadcast = Nd4j.createUninitialized(input.dataType(), shape);
INDArray mulResult = firstVertDerivV.broadcast(firstDerivVBroadcast);
int[] bcDims = {0,1};
Broadcast.mul(mulResult, secondTermDerivV, mulResult, bcDims);
INDArray derivV = mulResult
.mean(0).muli(oneDivNu).addi(getParam(V_KEY));
gradient.setGradientFor(V_KEY,vGradView.assign(derivV));
INDArray derivR = Nd4j.scalar(delta.meanNumber()).muli(oneDivNu).addi(-1);
gradient.setGradientFor(R_KEY,gradientViews.get(R_KEY).assign(derivR));
clearNoiseWeightParams();
delta = backpropDropOutIfPresent(delta);
return new Pair<>(gradient, delta);

@Override public void setupSearchState(Pair<Gradient, Double> pair) INDArray gradient = pair.getFirst().gradient(conf.variables());
INDArray params = model.params().dup();
searchState.put(GRADIENT_KEY, gradient);
searchState.put(SCORE_KEY, pair.getSecond());
searchState.put(PARAMS_KEY, params);

public void preApply(Trainable layer, Gradient gradient, int iteration) if (layer.getConfig() == null || layer.numParams() == 0) {
return;
}
GradientNormalization normalization = layer.getConfig().getGradientNormalization();
if (normalization == null || normalization == GradientNormalization.None)
return;
final double threshold = layer.getConfig().getGradientNormalizationThreshold();
INDArray layerGradientView = layer.getGradientsViewArray();
switch (normalization) {
case RenormalizeL2PerLayer:
if (layerGradientView != null) {
double l2 = layerGradientView.norm2Number().doubleValue();
if (l2 == 0.0)
l2 = 1e-5;
layerGradientView.divi(l2);
}
break;
case RenormalizeL2PerParamType:
for (INDArray g : gradient.gradientForVariable().values()) {
double l2 = Nd4j.getExecutioner().execAndReturn(new Norm2(g)).getFinalResult().doubleValue();
if (l2 == 0.0)
l2 = 1e-5;
g.divi(l2);
}
break;
case ClipElementWiseAbsoluteValue:
if (layerGradientView != null) {
CustomOp op = DynamicCustomOp.builder("clipbyvalue")
.addInputs(layerGradientView)
.callInplace(true)
.addFloatingPointArguments(-threshold, threshold)
.build();
Nd4j.getExecutioner().exec(op);
}
break;
case ClipL2PerLayer:
if (layerGradientView != null) {
double layerL2 = layerGradientView.norm2Number().doubleValue();
if (layerL2 > threshold) {
double scalingFactor = threshold / layerL2;
layerGradientView.muli(scalingFactor);
}
}
break;
case ClipL2PerParamType:
for (INDArray g : gradient.gradientForVariable().values()) {
double l2 = g.norm2Number().doubleValue();
if (l2 > threshold) {
double scalingFactor = l2 / threshold;
g.divi(scalingFactor);
}
}
break;
default:
throw new RuntimeException(
"Unknown (or not implemented) gradient normalization strategy: " + normalization);
}

private Pair<Gradient, INDArray> getGradientsAndDelta(INDArray preOut, LayerWorkspaceMgr workspaceMgr) ILossFunction lossFunction = layerConf().getLossFn();
INDArray labels2d = getLabels2d(workspaceMgr, ArrayType.BP_WORKING_MEM);
INDArray delta = lossFunction.computeGradient(labels2d, preOut, layerConf().getActivationFn(), maskArray);
Gradient gradient = new DefaultGradient();
INDArray weightGradView = gradientViews.get(DefaultParamInitializer.WEIGHT_KEY);
Nd4j.gemm(input.castTo(weightGradView.dataType()), delta, weightGradView, true, false, 1.0, 0.0);
gradient.gradientForVariable().put(DefaultParamInitializer.WEIGHT_KEY, weightGradView);
if(hasBias()){
INDArray biasGradView = gradientViews.get(DefaultParamInitializer.BIAS_KEY);
delta.sum(biasGradView, 0);
gradient.gradientForVariable().put(DefaultParamInitializer.BIAS_KEY, biasGradView);
}
delta = workspaceMgr.leverageTo(ArrayType.ACTIVATION_GRAD, delta);
return new Pair<>(gradient, delta);

@Override public boolean optimize(LayerWorkspaceMgr workspaceMgr) INDArray gradient;
INDArray searchDirection;
INDArray parameters;
Pair<Gradient, Double> pair = gradientAndScore(workspaceMgr);
if (searchState.isEmpty()) {
searchState.put(GRADIENT_KEY, pair.getFirst().gradient());
try(MemoryWorkspace ws = Nd4j.getWorkspaceManager().scopeOutOfWorkspaces()) {
setupSearchState(pair);
}
} else {
searchState.put(GRADIENT_KEY, pair.getFirst().gradient());
}
try(MemoryWorkspace ws = Nd4j.getWorkspaceManager().scopeOutOfWorkspaces()) {
preProcessLine();
}
gradient = (INDArray) searchState.get(GRADIENT_KEY);
searchDirection = (INDArray) searchState.get(SEARCH_DIR);
parameters = (INDArray) searchState.get(PARAMS_KEY);
try {
step = lineMaximizer.optimize(parameters, gradient, searchDirection, workspaceMgr);
} catch (InvalidStepException e) {
log.warn("Invalid step...continuing another iteration: {}", e.getMessage());
step = 0.0;
}
if (step != 0.0) {
stepFunction.step(parameters, searchDirection, step);
model.setParams(parameters);
} else {
log.debug("Step size returned by line search is 0.0.");
}
pair = gradientAndScore(workspaceMgr);
try(MemoryWorkspace ws = Nd4j.getWorkspaceManager().scopeOutOfWorkspaces()) {
postStep(pair.getFirst().gradient());
}
int iterationCount = BaseOptimizer.getIterationCount(model);
int epochCount = BaseOptimizer.getEpochCount(model);
try (MemoryWorkspace workspace = Nd4j.getMemoryManager().scopeOutOfWorkspaces()) {
for (TrainingListener listener : trainingListeners)
listener.iterationDone(model, iterationCount, epochCount);
}
incrementIterationCount(model, 1);
applyConstraints(model);
return true;

public boolean resultSubtype(Type t, Type s, Warner warner) List<Type> tvars = t.getTypeArguments();
List<Type> svars = s.getTypeArguments();
Type tres = t.getReturnType();
Type sres = subst(s.getReturnType(), svars, tvars);
return covariantReturnType(tres, sres, warner);

public Type externalType(Types types) Type t = erasure(types);
if (name == name.table.names.init && owner.hasOuterInstance()) {
Type outerThisType = types.erasure(owner.type.getEnclosingType());
return new MethodType(t.getParameterTypes().prepend(outerThisType),
t.getReturnType(),
t.getThrownTypes(),
t.tsym);
} else {
return t;
}

public boolean notSoftSubtype(Type t, Type s) if (t == s) return false;
if (t.hasTag(TYPEVAR)) {
TypeVar tv = (TypeVar) t;
return !isCastable(tv.bound,
relaxBound(s),
noWarnings);
}
if (!s.hasTag(WILDCARD))
s = cvarUpperBound(s);
return !isSubtype(t, relaxBound(s));

public Type erasure(Types types) if (erasure_field == null)
erasure_field = types.erasure(type);
return erasure_field;

public Optional<Symbol> mergeAbstracts(List<Symbol> ambiguousInOrder, Type site, boolean sigCheck) boolean shouldErase = false;
List<Type> erasedParams = ambiguousInOrder.head.erasure(this).getParameterTypes();
for (Symbol s : ambiguousInOrder) {
if ((s.flags() & ABSTRACT) == 0 ||
(sigCheck && !isSameTypes(erasedParams, s.erasure(this).getParameterTypes()))) {
return Optional.empty();
} else if (s.type.hasTag(FORALL)) {
shouldErase = true;
}
}
for (MostSpecificReturnCheck mostSpecificReturnCheck : MostSpecificReturnCheck.values()) {
outer: for (Symbol s : ambiguousInOrder) {
Type mt = memberType(site, s);
List<Type> allThrown = mt.getThrownTypes();
for (Symbol s2 : ambiguousInOrder) {
if (s != s2) {
Type mt2 = memberType(site, s2);
if (!isSubSignature(mt, mt2) ||
!mostSpecificReturnCheck.test(mt, mt2, this)) {
continue outer;
} else {
List<Type> thrownTypes2 = mt2.getThrownTypes();
if (!mt.hasTag(FORALL) && shouldErase) {
thrownTypes2 = erasure(thrownTypes2);
} else if (mt.hasTag(FORALL)) {
Assert.check(mt2.hasTag(FORALL));
thrownTypes2 = subst(thrownTypes2, mt2.getTypeArguments(), mt.getTypeArguments());
}
allThrown = chk.intersect(allThrown, thrownTypes2);
}
}
}
return (allThrown == mt.getThrownTypes()) ?
Optional.of(s) :
Optional.of(new MethodSymbol(
s.flags(),
s.name,
createMethodTypeWithThrown(s.type, allThrown),
s.owner) {
@Override
public Symbol baseSymbol() {
return s;
}
});
}
}
return Optional.empty();

public Type instantiateFunctionalInterface(DiagnosticPosition pos, Type funcInterface, List<Type> paramTypes, Check.CheckContext checkContext) if (types.capture(funcInterface) == funcInterface) {
return funcInterface;
} else {
Type formalInterface = funcInterface.tsym.type;
InferenceContext funcInterfaceContext =
new InferenceContext(this, funcInterface.tsym.type.getTypeArguments());
Assert.check(paramTypes != null);
List<Type> descParameterTypes = types.findDescriptorType(formalInterface).getParameterTypes();
if (descParameterTypes.size() != paramTypes.size()) {
checkContext.report(pos, diags.fragment("incompatible.arg.types.in.lambda"));
return types.createErrorType(funcInterface);
}
for (Type p : descParameterTypes) {
if (!types.isSameType(funcInterfaceContext.asUndetVar(p), paramTypes.head)) {
checkContext.report(pos, diags.fragment("no.suitable.functional.intf.inst", funcInterface));
return types.createErrorType(funcInterface);
}
paramTypes = paramTypes.tail;
}
List<Type> actualTypeargs = funcInterface.getTypeArguments();
for (Type t : funcInterfaceContext.undetvars) {
UndetVar uv = (UndetVar)t;
Optional<Type> inst = uv.getBounds(InferenceBound.EQ).stream()
.filter(b -> !b.containsAny(formalInterface.getTypeArguments())).findFirst();
uv.setInst(inst.orElse(actualTypeargs.head));
actualTypeargs = actualTypeargs.tail;
}
Type owntype = funcInterfaceContext.asInstType(formalInterface);
if (!chk.checkValidGenericType(owntype)) {
checkContext.report(pos, diags.fragment("no.suitable.functional.intf.inst", funcInterface));
}
checkContext.compatible(owntype, funcInterface, types.noWarnings);
return owntype;
}

public List<Type> getBounds(TypeVar t) if (t.bound.hasTag(NONE))
return List.nil();
else if (t.bound.isErroneous() || !t.bound.isCompound())
return List.of(t.bound);
else if ((erasure(t).tsym.flags() & INTERFACE) == 0)
return interfaces(t).prepend(supertype(t));
else
return interfaces(t);

private MethodSymbol validateContainer(Type targetContainerType, Type originalAnnoType, DiagnosticPosition pos) MethodSymbol containerValueSymbol = null;
boolean fatalError = false;
Scope scope = targetContainerType.tsym.members();
int nr_value_elems = 0;
boolean error = false;
for(Symbol elm : scope.getSymbolsByName(names.value)) {
nr_value_elems++;
if (nr_value_elems == 1 &&
elm.kind == MTH) {
containerValueSymbol = (MethodSymbol)elm;
} else {
error = true;
}
}
if (error) {
log.error(pos,
"invalid.repeatable.annotation.multiple.values",
targetContainerType,
nr_value_elems);
return null;
} else if (nr_value_elems == 0) {
log.error(pos,
"invalid.repeatable.annotation.no.value",
targetContainerType);
return null;
}
if (containerValueSymbol.kind != MTH) {
log.error(pos,
"invalid.repeatable.annotation.invalid.value",
targetContainerType);
fatalError = true;
}
Type valueRetType = containerValueSymbol.type.getReturnType();
Type expectedType = types.makeArrayType(originalAnnoType);
if (!(types.isArray(valueRetType) &&
types.isSameType(expectedType, valueRetType))) {
log.error(pos,
"invalid.repeatable.annotation.value.return",
targetContainerType,
valueRetType,
expectedType);
fatalError = true;
}
return fatalError ? null : containerValueSymbol;

Env<AttrContext> methodEnv(JCMethodDecl tree, Env<AttrContext> env) Env<AttrContext> localEnv =
env.dup(tree, env.info.dup(env.info.scope.dupUnshared(tree.sym)));
localEnv.enclMethod = tree;
if (tree.sym.type != null) {
localEnv.info.returnResult = attr.new ResultInfo(KindSelector.VAL,
tree.sym.type.getReturnType());
}
if ((tree.mods.flags & STATIC) != 0) localEnv.info.staticLevel++;
return localEnv;

JCExpression retype(JCExpression tree, Type erasedType, Type target) if (!erasedType.isPrimitive()) {
if (target != null && target.isPrimitive()) {
target = erasure(tree.type);
}
tree.type = erasedType;
if (target != null) {
return coerce(tree, target);
}
}
return tree;

public synchronized void readAsynch(InvCatalogFactory factory, CatalogSetCallback caller) if (init) {
caller.setCatalog((InvCatalogImpl) getParentCatalog());
return;
}
String hrefResolved;
try {
java.net.URI uri = getParentCatalog().resolveUri(href);
hrefResolved = uri.toString();
}
catch (java.net.URISyntaxException e) {
proxy = new InvDatasetImpl(null, "HREF ERROR");
if (debug)
System.out.println("HREF ERROR =\n  " + href + " err= " + e.getMessage());
proxy.addProperty(new InvProperty("HREF ERROR", href));
datasets.add(proxy);
return;
}
try {
if (debug) System.out.println(" InvCatalogRef readXMLasynch " + getFullName() +
"  hrefResolved = " + hrefResolved);
factory.readXMLasynch(hrefResolved, new Callback(caller));
} catch (Exception e) {
proxy = new InvDatasetImpl(null, "HREF ERROR");
if (debug)
System.out.println("HREF ERROR =\n  " + href + " err= " + e.getMessage());
proxy.addProperty(new InvProperty("HREF ERROR", href));
datasets.add(proxy);
}

public void open(ucar.unidata.io.RandomAccessFile raf, ucar.nc2.NetcdfFile ncfile, ucar.nc2.util.CancelTask cancelTask) throws java.io.IOException super.open(raf, ncfile, cancelTask);
java.util.Map<String, String> hdrNames = new java.util.HashMap<String, String>();
volScan = new SigmetVolumeScan(raf, ncfile, varList);
this.varList = init(raf, ncfile, hdrNames);

public boolean finish() if (datasets.size() == 1) {
topDataset = (InvDatasetImpl) datasets.get(0);
} else {
topDataset = new InvDatasetImpl(null, name == null ? "Top Dataset" : name);
for (InvDataset dataset : datasets)
topDataset.addDataset((InvDatasetImpl) dataset);
topDataset.setServicesLocal(services);
}
topDataset.setCatalog(this);
dsHash = new HashMap<String, InvDataset>();
addDatasetIds(topDataset);
return topDataset.finish();
}
private void addDatasetIds(InvDatasetImpl ds) {
addDatasetByID(ds);
if (ds instanceof InvCatalogRef) return;
for (InvDataset invDataset : ds.getDatasets()) {
InvDatasetImpl nested = (InvDatasetImpl) invDataset;
addDatasetIds(nested);
}
}
public void addDatasetByID(InvDatasetImpl ds) {
if (ds.getID() != null)
dsHash.put(ds.getID(), ds);
}
public void removeDatasetByID(InvDatasetImpl ds) {
if (ds.getID() != null)
dsHash.remove(ds.getID());
}
public void addDataset(InvDatasetImpl ds) {
if (ds != null)
datasets.add(ds);
}
