static boolean accept(IAtom atom, List<IBond> bonds) int dbCount = 0;
if (!IAtomType.Hybridization.SP2.equals(atom.getHybridization())) return false;
if (bonds.size() == 1) return false;
for (IBond bond : bonds) {
if (DOUBLE.equals(bond.getOrder())) dbCount++;
IBond.Stereo stereo = bond.getStereo();
if (IBond.Stereo.UP_OR_DOWN.equals(stereo) || IBond.Stereo.UP_OR_DOWN_INVERTED.equals(stereo))
return false;
}
return dbCount == 1;

static int elevation(IBond bond) IBond.Stereo stereo = bond.getStereo();
if (stereo == null) return 0;
switch (stereo) {
case UP:
case DOWN_INVERTED:
return +1;
case DOWN:
case UP_INVERTED:
return -1;
default:
return 0;
}

private static int nStereoBonds(List<IBond> bonds) int count = 0;
for (IBond bond : bonds) {
IBond.Stereo stereo = bond.getStereo();
switch (stereo) {
case E_OR_Z:
case UP_OR_DOWN:
case UP_OR_DOWN_INVERTED:
return -1;
case UP:
case DOWN:
case UP_INVERTED:
case DOWN_INVERTED:
count++;
break;
}
}
return count;

private void labelUnspecified(IBond doubleBond) final IAtom aBeg = doubleBond.getBegin();
final IAtom aEnd = doubleBond.getEnd();
final int beg = atomToIndex.get(aBeg);
final int end = atomToIndex.get(aEnd);
int nAdj = 0;
final IAtom[] focus = new IAtom[4];
final IAtom[] adj = new IAtom[4];
for (int neighbor : graph[beg]) {
IBond bond = edgeToBond.get(beg, neighbor);
if (bond.getOrder() == SINGLE) {
if (nAdj == 4) return;
focus[nAdj] = aBeg;
adj[nAdj++] = container.getAtom(neighbor);
}
if (bond.getStereo() == UP_OR_DOWN || bond.getStereo() == UP_OR_DOWN_INVERTED) {
return;
}
}
for (int neighbor : graph[end]) {
IBond bond = edgeToBond.get(end, neighbor);
if (bond.getOrder() == SINGLE) {
if (nAdj == 4) return;
focus[nAdj] = aEnd;
adj[nAdj++] = container.getAtom(neighbor);
}
if (bond.getStereo() == UP_OR_DOWN || bond.getStereo() == UP_OR_DOWN_INVERTED) {
return;
}
}
int[] rank = priority(-1, adj, nAdj);
for (int i = 0; i < nAdj; i++) {
if (doubleBondElements[atomToIndex.get(adj[rank[i]])] == null &&
tetrahedralElements[atomToIndex.get(adj[rank[i]])] == null) {
edgeToBond.get(atomToIndex.get(focus[rank[i]]),
atomToIndex.get(adj[rank[i]])).setStereo(UP_OR_DOWN);
return;
}
}
doubleBond.setStereo(E_OR_Z);

public static IBond.Stereo convertStereo(int stereoValue) IBond.Stereo stereo = IBond.Stereo.NONE;
if (stereoValue == 1) {
stereo = IBond.Stereo.UP;
} else if (stereoValue == 6) {
stereo = IBond.Stereo.DOWN;
} else if (stereoValue == 0) {
stereo = IBond.Stereo.NONE;
} else if (stereoValue == 4) {
stereo = IBond.Stereo.UP_OR_DOWN;
} else if (stereoValue == 3) {
stereo = IBond.Stereo.E_OR_Z;
}
return stereo;

private boolean hasOnlyPlainBonds(int v, IBond allowedDoubleBond) int count = 0;
for (int neighbor : graph[v]) {
IBond adjBond = edgeToBond.get(v, neighbor);
if (adjBond.getOrder().numeric() > 1) {
if (!allowedDoubleBond.equals(adjBond)) {
return false;
}
}
else {
if (adjBond.getStereo() == UP_OR_DOWN || adjBond.getStereo() == UP_OR_DOWN_INVERTED) {
return false;
}
count++;
}
}
return count > 0;

public static int convertBondStereo(IBond bond) int value = 0;
switch (bond.getStereo()) {
case UP:
value = 1;
break;
case UP_INVERTED:
value = 1;
break;
case DOWN:
value = 6;
break;
case DOWN_INVERTED:
value = 6;
break;
case UP_OR_DOWN:
value = 4;
break;
case UP_OR_DOWN_INVERTED:
value = 4;
break;
case E_OR_Z:
value = 3;
break;
default:
value = 0;
}
return value;

private static void makeElevationMap(IAtom atom, List<IBond> bonds, Map<IAtom, Integer> map) map.clear();
for (IBond bond : bonds) {
int elevation = 0;
switch (bond.getStereo()) {
case UP:
case DOWN_INVERTED:
elevation = +1;
break;
case DOWN:
case UP_INVERTED:
elevation = -1;
break;
}
if (bond.getBegin().equals(atom)) {
map.put(bond.getEnd(), elevation);
} else {
map.put(bond.getBegin(), -1 * elevation);
}
}

private void label(final ExtendedTetrahedral element) final IAtom focus = element.focus();
final IAtom[] atoms = element.peripherals();
final IBond[] bonds = new IBond[4];
int p = parity(element.winding());
List<IBond> focusBonds = container.getConnectedBondsList(focus);
if (focusBonds.size() != 2) {
LoggingToolFactory.createLoggingTool(getClass()).warn(
"Non-cumulated carbon presented as the focus of extended tetrahedral stereo configuration");
return;
}
IAtom[] terminals = element.findTerminalAtoms(container);
IAtom left  = terminals[0];
IAtom right = terminals[1];
for (int i = 0; i < 4; i++)
bonds[i] = findBond(left, right, atoms[i]);
int[] rank = new int[4];
for (int i = 0; i < 4; i++)
rank[i] = i;
p *= sortClockwise(rank, focus, atoms, 4);
IBond.Stereo[] labels = new IBond.Stereo[4];
for (int i = 0; i < 4; i++) {
int v = rank[i];
p *= -1;
labels[v] = p > 0 ? UP : DOWN;
}
int[] priority = new int[]{5, 5, 5, 5};
int i = 0;
for (int v : priority(atomToIndex.get(focus), atoms, 4)) {
IBond bond = bonds[v];
if (bond == null) continue;
if (bond.getStereo() == NONE && bond.getOrder() == SINGLE) priority[v] = i++;
}
if (priority[0] + priority[1] < priority[2] + priority[3]) {
if (priority[0] < 5)
setWedge(bonds[0], atoms[0], labels[0]);
if (priority[1] < 5)
setWedge(bonds[1], atoms[1], labels[1]);
} else {
if (priority[2] < 5)
setWedge(bonds[2], atoms[2], labels[2]);
if (priority[3] < 5)
setWedge(bonds[3], atoms[3], labels[3]);
}

private void adjust(IDoubleBondStereochemistry dbs) IBond db = dbs.getStereoBond();
IBond[] bonds = dbs.getBonds();
IAtom left = db.getBegin();
IAtom right = db.getEnd();
int p = parity(dbs);
int q = parity(getAtoms(left, bonds[0].getOther(left), right))
* parity(getAtoms(right, bonds[1].getOther(right), left));
if (p == 0) {
for (IBond bond : container.getConnectedBondsList(left))
bond.setStereo(IBond.Stereo.NONE);
for (IBond bond : container.getConnectedBondsList(right))
bond.setStereo(IBond.Stereo.NONE);
bonds[0].setStereo(IBond.Stereo.UP_OR_DOWN);
return;
}
if (p == q) return;
Arrays.fill(visited, false);
visited[atomToIndex.get(left)] = true;
if (ringSearch.cyclic(atomToIndex.get(left), atomToIndex.get(right))) {
db.setStereo(IBond.Stereo.E_OR_Z);
return;
}
for (int w : graph[atomToIndex.get(right)]) {
if (!visited[w]) reflect(w, db);
}

