}
throw new MissingMethodException(name, getClass(), argsArr);

private boolean isGetter(String name, CachedClass[] args) if (name == null || name.length() == 0 || args == null) return false;
if (args.length != 0) return false;
if (name.startsWith("get")) {
name = name.substring(3);
return isPropertyName(name);
} else if (name.startsWith("is")) {
name = name.substring(2);
return isPropertyName(name);
}
return false;

public URLConnection getResourceConnection (String name) throws ResourceException name = removeNamePrefix(name).replace('\\', '/');
if (name.startsWith("WEB-INF/groovy/")) {
