public Object invokeMethod(String name, Object args) if (args != null && Object[].class.isAssignableFrom(args.getClass())) {
Object[] arr = (Object[]) args;
if (arr.length == 0) {
return setAndGetContent(name, new HashMap<String, Object>());
} else if (arr.length == 1) {
if (arr[0] instanceof Closure) {
return setAndGetContent(name, JsonDelegate.cloneDelegateAndGetContent((Closure) arr[0]));
} else if (arr[0] instanceof Map) {
return setAndGetContent(name, arr[0]);
}
} else if (arr.length == 2) {
final Object first = arr[0];
final Object second = arr[1];
if (second instanceof Closure) {
final Closure closure = (Closure)second;
if (first instanceof Map) {
Map subMap = new LinkedHashMap();
subMap.putAll((Map) first);
subMap.putAll(JsonDelegate.cloneDelegateAndGetContent(closure));
return setAndGetContent(name, subMap);
} else if (first instanceof Iterable) {
List<Map<String, Object>> list = collectContentForEachEntry((Iterable) first, closure);
return setAndGetContent(name, list);
} else if (first != null && first.getClass().isArray()) {
final Iterable coll = Arrays.asList((Object[])first);
List<Map<String, Object>> list = collectContentForEachEntry(coll, closure);
return setAndGetContent(name, list);
}
}
}
throw new JsonException("Expected no arguments, a single map, a single closure, or a map and closure as arguments.");
} else {
return setAndGetContent(name, new HashMap<String, Object>());
}

protected Object createNode(Object name, Map attributes, Object value) Object node;
Factory factory = getProxyBuilder().resolveFactory(name, attributes, value);
if (factory == null) {
LOG.log(Level.WARNING, "Could not find match for name '" + name + "'");
throw new MissingMethodExceptionNoStack((String) name, Object.class, new Object[]{attributes, value});
}
getProxyBuilder().getContext().put(CURRENT_FACTORY, factory);
getProxyBuilder().getContext().put(CURRENT_NAME, String.valueOf(name));
getProxyBuilder().preInstantiate(name, attributes, value);
try {
node = factory.newInstance(getProxyBuilder().getChildBuilder(), name, value, attributes);
if (node == null) {
LOG.log(Level.WARNING, "Factory for name '" + name + "' returned null");
return null;
}
if (LOG.isLoggable(Level.FINE)) {
LOG.fine("For name: " + name + " created node: " + node);
}
} catch (Exception e) {
throw new RuntimeException("Failed to create component for '" + name + "' reason: "
+ e, e);
}
getProxyBuilder().postInstantiate(name, attributes, node);
getProxyBuilder().handleNodeAttributes(node, attributes);
return node;

