public static boolean equal(long[] x, long[] y) if(x == null || y == null) {
return (x == null) && (y == null);
}
int p = Math.min(x.length, y.length) - 1;
for(int i = x.length - 1; i > p; i--) {
if(x[i] != 0L) {
return false;
}
}
for(int i = y.length - 1; i > p; i--) {
if(y[i] != 0L) {
return false;
}
}
for(; p >= 0; p--) {
if(x[p] != y[p]) {
return false;
}
}
return true;

public static int compare(long[] x, long[] y) if(x == null) {
return (y == null) ? 0 : -1;
}
if(y == null) {
return +1;
}
int p = Math.min(x.length, y.length) - 1;
for(int i = x.length - 1; i > p; i--) {
if(x[i] != 0) {
return +1;
}
}
for(int i = y.length - 1; i > p; i--) {
if(y[i] != 0) {
return -1;
}
}
for(; p >= 0; p--) {
final long xp = x[p], yp = y[p];
if(xp != yp) {
return xp < 0 ? (yp < 0 && yp < xp) ? -1 : +1 : (yp < 0 || xp < yp) ? -1 : +1;
}
}
return 0;

public static int intersectionSize(long[] x, long[] y) final int lx = x.length, ly = y.length;
final int min = (lx < ly) ? lx : ly;
int res = 0;
for(int i = 0; i < min; i++) {
res += Long.bitCount(x[i] & y[i]);
}
return res;

public static int unionSize(long[] x, long[] y) final int lx = x.length, ly = y.length;
final int min = (lx < ly) ? lx : ly;
int i = 0, res = 0;
for(; i < min; i++) {
res += Long.bitCount(x[i] | y[i]);
}
for(; i < lx; i++) {
res += Long.bitCount(x[i]);
}
for(; i < ly; i++) {
res += Long.bitCount(y[i]);
}
return res;

public static int hammingDistance(long[] x, long[] y) final int lx = x.length, ly = y.length;
final int min = (lx < ly) ? lx : ly;
int i = 0, h = 0;
for(; i < min; i++) {
h += Long.bitCount(x[i] ^ y[i]);
}
for(; i < lx; i++) {
h += Long.bitCount(x[i]);
}
for(; i < ly; i++) {
h += Long.bitCount(y[i]);
}
return h;

private int[][] houghTransformation(boolean[][] mat) final int xres = mat.length, yres = mat[0].length;
final double tscale = STEPS * .66 / (xres + yres);
final int[][] ret = new int[STEPS][STEPS];
for(int x = 0; x < mat.length; x++) {
final boolean[] row = mat[x];
for(int y = 0; y < mat[0].length; y++) {
if(row[y]) {
for(int i = 0; i < STEPS; i++) {
final int d = (STEPS >> 1) + (int) (tscale * (x * table.cos(i) + y * table.sin(i)));
if(d > 0 && d < STEPS) {
ret[d][i]++;
}
}
}
}
}
return ret;

private boolean checkCandidateUpdate(double[] point) final double x = point[0], y = point[1];
if(points.isEmpty()) {
leftx = rightx = x;
topy = bottomy = y;
topleft = topright = bottomleft = bottomright = point;
return true;
}
if(x <= leftx || x >= rightx || y <= bottomy || y >= topy) {
double xpy = x + y, xmy = x - y;
boolean changed = false;
if(xpy < bottomleft[0] + bottomleft[1]) {
bottomleft = point;
changed = true;
}
else if(xpy > topright[0] + topright[1]) {
topright = point;
changed = true;
}
if(xmy < topleft[0] - topleft[1]) {
topleft = point;
changed = true;
}
else if(xmy > bottomright[0] - bottomright[1]) {
bottomright = point;
changed = true;
}
if(changed) {
leftx = Math.max(bottomleft[0], topleft[0]);
rightx = Math.min(bottomright[0], topright[0]);
topy = Math.min(topleft[1], topright[1]);
bottomy = Math.max(bottomleft[1], bottomright[1]);
}
return true;
}
return false;

public static void doubleCenterSymmetric(double[][] m) final int size = m.length;
double[] means = new double[size];
for(int x = 0; x < m.length; x++) {
final double[] rowx = m[x];
double rmean = means[x] - means[x] / (x + 1);
for(int y = x + 1; y < rowx.length; y++) {
final double nv = rowx[y];
final double dx = nv - rmean, dy = nv - means[y];
rmean += dx / (y + 1);
means[y] += dy / (x + 1);
}
means[x] = rmean;
}
double mean = means[0];
for(int x = 1; x < size; x++) {
double dm = means[x] - mean;
mean += dm / (x + 1);
}
for(int x = 0; x < size; x++) {
m[x][x] = -2. * means[x] + mean;
for(int y = x + 1; y < size; y++) {
final double nv = m[x][y] - means[x] - means[y] + mean;
m[x][y] = nv;
m[y][x] = nv;
}
}

private List<DoubleIntInt> computeZijs(double[][] averageDistances, final int dim) List<DoubleIntInt> z_ijs = new ArrayList<>(averageDistances.length * dim);
for(int i = 0; i < averageDistances.length; i++) {
double[] x_i = averageDistances[i];
double y_i = 0;
for(int j = 0; j < dim; j++) {
y_i += x_i[j];
}
y_i /= dim;
double sigma_i = 0;
for(int j = 0; j < dim; j++) {
double diff = x_i[j] - y_i;
sigma_i += diff * diff;
}
sigma_i /= (dim - 1);
sigma_i = FastMath.sqrt(sigma_i);
for(int j = 0; j < dim; j++) {
z_ijs.add(new DoubleIntInt((x_i[j] - y_i) / sigma_i, i, j));
}
}
Collections.sort(z_ijs);
return z_ijs;

public static double coefficient(double[] x, double[] y) final int xdim = x.length;
final int ydim = y.length;
if(xdim != ydim) {
throw new IllegalArgumentException("Invalid arguments: arrays differ in length.");
}
if(xdim == 0) {
throw new IllegalArgumentException("Empty vector.");
}
double sumXX = 0., sumYY = 0., sumXY = 0.;
double sumX = x[0], sumY = y[0];
int i = 1;
while(i < xdim) {
final double xv = x[i], yv = y[i];
final double deltaX = xv * i - sumX;
final double deltaY = yv * i - sumY;
final double oldi = i;
++i;
final double f = 1. / (i * oldi);
sumXX += f * deltaX * deltaX;
sumYY += f * deltaY * deltaY;
sumXY += f * deltaX * deltaY;
sumX += xv;
sumY += yv;
}
if(!(sumXX > 0. && sumYY > 0.)) {
return (sumXX == sumYY) ? 1. : 0.;
}
return sumXY / FastMath.sqrt(sumXX * sumYY);

public boolean process(EllipseRotated_F64 ellipse ) if( numContourPoints <= 0 ) {
score = 0;
return true;
}
double cphi = Math.cos(ellipse.phi);
double sphi = Math.sin(ellipse.phi);
averageInside = 0;
averageOutside = 0;
int total = 0;
for (int contourIndex = 0; contourIndex < numContourPoints; contourIndex++) {
double theta = contourIndex*Math.PI*2.0/numContourPoints;
double ct = Math.cos(theta);
double st = Math.sin(theta);
double px = ellipse.center.x + ellipse.a*ct*cphi - ellipse.b*st*sphi;
double py = ellipse.center.y + ellipse.a*ct*sphi + ellipse.b*st*cphi;
double edx = ellipse.a*ct*ellipse.b*ellipse.b;
double edy = ellipse.b*st*ellipse.a*ellipse.a;
double r = Math.sqrt(edx*edx + edy*edy);
edx /= r;
edy /= r;
double dx = edx*cphi - edy*sphi;
double dy = edx*sphi + edy*cphi;
double xin = px-dx*tangentDistance;
double yin = py-dy*tangentDistance;
double xout = px+dx*tangentDistance;
double yout = py+dy*tangentDistance;
if( integral.isInside(xin,yin) && integral.isInside(xout,yout)) {
averageInside += integral.compute(px,py, xin, yin);
averageOutside += integral.compute(px,py, xout, yout);
total++;
}
}
score = 0;
if( total > 0 ) {
score = Math.abs(averageOutside-averageInside)/(total*tangentDistance);
}
return score >= passThreshold;

static double axisAdjustedDistanceSq(EllipseRotated_F64 a , EllipseRotated_F64 b ) double dx = b.center.x - a.center.x;
double dy = b.center.y - a.center.y;
double c = Math.cos(a.phi);
double s = Math.sin(a.phi);
double x = (dx*c + dy*s);
double y = (-dx*s + dy*c)*a.a/a.b;
return x*x + y*y;

