public boolean refine(Point2D_F64 a, Point2D_F64 b, LineGeneral2D_F64 found) center.x = (a.x + b.x)/2.0;
center.y = (a.y + b.y)/2.0;
localScale = a.distance(center);
double slopeX = (b.x - a.x);
double slopeY = (b.y - a.y);
double r = Math.sqrt(slopeX*slopeX + slopeY*slopeY);
double tanX = slopeY/r;
double tanY = -slopeX/r;
computePointsAndWeights(slopeX, slopeY, a.x, a.y, tanX, tanY);
if( samplePts.size() >= 4 ) {
if( null == FitLine_F64.polar(samplePts.toList(), weights.data, polar) ) {
throw new RuntimeException("All weights were zero, bug some place");
}
UtilLine2D_F64.convert(polar, found);
localToGlobal(found);
return true;
} else {
return false;
}

void addEdgesToInfo(List<Node> cluster) for (int i = 0; i < cluster.size(); i++) {
Node n = cluster.get(i);
NodeInfo infoA = listInfo.get(i);
EllipseRotated_F64 a = infoA.ellipse;
for (int j = 0; j < n.connections.size(); j++) {
NodeInfo infoB = listInfo.get( indexOf(cluster, n.connections.get(j)));
EllipseRotated_F64 b = infoB.ellipse;
Edge edge = infoA.edges.grow();
edge.target = infoB;
edge.angle = Math.atan2( b.center.y - a.center.y , b.center.x - a.center.x );
}
sorter.sort(infoA.edges.data, infoA.edges.size);
}

int addLineToGrid(SquareNode a, SquareNode b, List<SquareNode> list) int total = 2;
while( true ) {
boolean matched = false;
int side;
for( side = 0; side < 4; side++ ) {
if( b.edges[side] != null && b.edges[side].destination(b) == a ) {
matched = true;
break;
}
}
if(!matched) {
throw new RuntimeException("BUG!");
}
side = (side+2)%4;
if( b.edges[side] == null )
break;
SquareNode c = b.edges[side].destination(b);
if (c.graph == SEARCHED )
break;
total++;
c.graph = SEARCHED;
list.add(c);
a = b;
b = c;
}
return total;

